INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300002,3,'中心理解题','创建理想社会，是人类文明的伟大目标之一，但对于何为理想社会，文学艺术家的看法往往与众不同。政治家更多考虑的是制度的完善、社会秩序的稳定，科学家追求的是知识与技术，经济学家看重的是物质财富的增长，而文学艺术家所展现的社会理想中，则常常闪耀着至诚尽性、众生平等、虚静无为之类超越现实的精神之光。
这段话表达的主要观点是：','[{"label":"A","content":"不同职业，看待问题的视角不同"},{"label":"B","content":"所有人都有创建理想社会的伟大目标"},{"label":"C","content":"文学艺术家眼中的理想社会与众不同"},{"label":"D","content":"要创建理想社会，需要各行各业携手努力"}]','C','文段分析见批注。
文段先提出“文学艺术家对于理想社会的看法与众不同”,接下来依次介绍政治家、科学家、经济学家、文学艺术家的不同看法，具体介绍了文学艺术家看法的与众不同，对应C选项，当选；
A选项缺少主题词“理想社会”和主体“文学艺术家”;B选项对应的是首句转折前，出处有误且绝对化；D选项的对策无中生有，原文并无对策和问题。

花生批注：
⑤ 文学艺术家是全文论述主体。
⑥ 行文结构：总分结构。
先转折提出总观点：
对于何为理想社会，文学艺术家的看法往往与众不同 (转折前内容不重要);
而后分析论证：
展开介绍政治家、科学家、经济学家对理想社会的的认识，转折后具体说明了文学艺术家的与众不同。','2017年河北省事业单位','进阶','published','{"globalNumber":2,"setNumber":1,"localNumber":2,"sourceLabel":"2017年河北省事业单位 62%","accuracy":62,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"创建理想社会，是人类文明的伟大目标之一，但对于何为理想社会，文学艺术家的看法往往与众不同。政治家更多考虑的是制度的完善、社会秩序的稳定，科学家追求的是知识与技术，经济学家看重的是物质财富的增长，而文学艺术家所展现的社会理想中，则常常闪耀着至诚尽性、众生平等、虚静无为之类超越现实的精神之光。\n这段话表达的主要观点是："}],"optionRich":{"A":[{"text":"不同职业，看待问题的视角不同"}],"B":[{"text":"所有人都有创建理想社会的伟大目标"}],"C":[{"text":"文学艺术家眼中的理想社会与众不同"}],"D":[{"text":"要创建理想社会，需要各行各业携手努力"}]},"annotatedStemRich":[{"text":"创建理想社会，是人类文明的伟大目标之一，但对于何为理想社会，"},{"text":"文学艺术家⑨","underline":true},{"text":"的看法往往与众不同(转折提出总观点)。政治家更多考虑的是制度的完善、社会秩序的稳定，科学家追求的是知识与技术，经济学家看重的是物质财富的增长，而文学艺术家所展现的社会理想中，则常常闪耀着至诚尽性、众生平等、虚静无为之类超越现实的精神之光(分析论证)。\n这段话表达的主要观点是："}],"annotatedOptionRich":{"A":[{"text":"不同职业，看待问题的视角不同(缺主题词)"}],"B":[{"text":"所有人都有创建理想社会的伟大目标(出处有误且绝对化)"}],"C":[{"text":"文学艺术家眼中的理想社会与众不同"}],"D":[{"text":"要创建理想社会，需要各行各业携手努力(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段先提出“文学艺术家对于理想社会的看法与众不同”,接下来依次介绍政治家、科学家、经济学家、文学艺术家的不同看法，具体介绍了文学艺术家看法的与众不同，对应C选项，当选；\nA选项缺少主题词“理想社会”和主体“文学艺术家”;B选项对应的是首句转折前，出处有误且绝对化；D选项的对策无中生有，原文并无对策和问题。","notes":[{"marker":"⑤","content":"文学艺术家是全文论述主体。","matchScore":0.4978,"pairingMode":"content-similarity","order":4},{"marker":"⑥","content":"行文结构：总分结构。\n先转折提出总观点：\n对于何为理想社会，文学艺术家的看法往往与众不同 (转折前内容不重要);\n而后分析论证：\n展开介绍政治家、科学家、经济学家对理想社会的的认识，转折后具体说明了文学艺术家的与众不同。","matchScore":0.8203,"pairingMode":"content-similarity","order":5}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300003,3,'中心理解题','建筑在实用和审美功能之外的文化象征意涵，常常和特定的民族国家认同联系在一起。建筑设计建造者，在把握本土与外来关系之时，对这一点尤其需要精思熟虑，尊重建筑的“本土性”。“本土性”并不意味着一成不变，全球化时代中的各个民族，汲取外来建筑精华为我所用是顺理成章的事情。但“拿来”不是照搬照抄，不是贪大求洋。只有在继承传统文化基因基础上借鉴外来建筑优长，在洋为中用、融会中西的深度化合中发扬光大我国建筑传统，提升当代建筑的文化格调和营造水平，才能在交流融合中不断发展进步。
上述文字意在强调建筑设计建造者在进行建筑设计时要：','[{"label":"A","content":"摆脱急功近利的浮躁心态"},{"label":"B","content":"准确把握本土与外来关系"},{"label":"C","content":"既尊重规律又发挥个性"},{"label":"D","content":"延续民族风格、提升文化品位\n片段阅读60 0 (上册)"}]','B','文段分析见批注。
文段在引出话题后，直接给出对策“建筑设计者在把握本土与外来关系之时要精思熟虑”,接着介绍具体应该如何把握本土与外来的关系，最后再次重复对策。B选项是文段对策句的同义替换，当选；
A选项“浮躁心态”和C选项“尊重规律又发挥个性”原文未体现，D选项只强调了“继承传统”没体现“借鉴外来”,表述片面，均可简单排除。

花生批注：
⑦ 行文结构：前对策结构。
先引出话题：
建筑的文化意涵与民族国家认同相联系；
再提出对策：
建筑设计者在把握本土与外来关系之时要精思熟虑；
然后分析论证；
最后以关联词重复对策：
要在继承传统的基础上借鉴外来建筑的优点，在融合中进步。','2021年河南省事业单位','基础','published','{"globalNumber":3,"setNumber":1,"localNumber":3,"sourceLabel":"2021年河南省事业单位75%","accuracy":75,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"建筑在实用和审美功能之外的文化象征意涵，常常和特定的民族国家认同联系在一起。建筑设计建造者，在把握本土与外来关系之时，对这一点尤其需要精思熟虑，尊重建筑的“本土性”。“本土性”并不意味着一成不变，全球化时代中的各个民族，汲取外来建筑精华为我所用是顺理成章的事情。但“拿来”不是照搬照抄，不是贪大求洋。只有在继承传统文化基因基础上借鉴外来建筑优长，在洋为中用、融会中西的深度化合中发扬光大我国建筑传统，提升当代建筑的文化格调和营造水平，才能在交流融合中不断发展进步。\n上述文字意在强调建筑设计建造者在进行建筑设计时要："}],"optionRich":{"A":[{"text":"摆脱急功近利的浮躁心态"}],"B":[{"text":"准确把握本土与外来关系"}],"C":[{"text":"既尊重规律又发挥个性"}],"D":[{"text":"延续民族风格、提升文化品位\n片段阅读60 0 (上册)"}]},"annotatedStemRich":[{"text":"建筑在实用和审美功能之外的文化象征意涵，常常和特定的民族国家认同联系在一起(引出话题)。建筑设计建造者，在把握本土与外来关系之时，对这一点尤其需要精思熟虑，尊重建筑的“本土性”(祈使句表对策)。“本土性”并不意味着一成不变，全球化时代中的各个民族，汲取外来建筑精华为我所用是顺理成章的事情。但“拿来”不是照搬照抄，不是贪大求洋(分析论证)。\n只有在继承传统文化基因基础上借鉴外来建筑优长，在洋为中用、融会中西的深度化合中发扬光大我国建筑传统，提升当代建筑的文化格调和营造水平，才能在交流融合中不断发展进步(重复对策)。⑦\n上述文字意在强调建筑设计建造者在进行建筑设计时要："}],"annotatedOptionRich":{"A":[{"text":"摆脱急功近利的浮躁心态(无中生有)"}],"B":[{"text":"准确把握本土与外来关系"}],"C":[{"text":"既尊重规律又发挥个性(无中生有)"}],"D":[{"text":"延续民族风格、提升文化品位( 片面 )"}]},"practicalAnalysis":"文段分析见批注。\n文段在引出话题后，直接给出对策“建筑设计者在把握本土与外来关系之时要精思熟虑”,接着介绍具体应该如何把握本土与外来的关系，最后再次重复对策。B选项是文段对策句的同义替换，当选；\nA选项“浮躁心态”和C选项“尊重规律又发挥个性”原文未体现，D选项只强调了“继承传统”没体现“借鉴外来”,表述片面，均可简单排除。","notes":[{"marker":"⑦","content":"行文结构：前对策结构。\n先引出话题：\n建筑的文化意涵与民族国家认同相联系；\n再提出对策：\n建筑设计者在把握本土与外来关系之时要精思熟虑；\n然后分析论证；\n最后以关联词重复对策：\n要在继承传统的基础上借鉴外来建筑的优点，在融合中进步。","matchScore":0.8005,"pairingMode":"marker-and-content","order":6}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300004,3,'语句填入类','毫无疑问，重大事件作为城市发展动力具有无可替代的积极作用：它能集中人力、物力、财力，能够凝聚市民积极参与的热情，能够发挥连带效应拉动相关产业的发展，能够通过“非常状态”的锤炼提升城市管理和运行水平，能够快速提升城市知名度从而增强城市软实力，等等。但是，重大事件所具有的片面发展、透支未来、非常规管理等问题均不具有可持续性，尤其是不可能从根本上解决“冰冻三尺非一日之寒”的“过度城市化”“城市空心化”等“城市病”,因此
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"可持续发展是常态，重大事件是非常态"},{"label":"B","content":"可持续发展是本，重大事件为末"},{"label":"C","content":"城市发展动力不能依赖重大事件"},{"label":"D","content":"城市发展战略应寄托于新的“重大事件”的刺激"}]','C','文段分析见批注。
文段先介绍了重大事件的积极作用，转折后介绍了重大事件不具有可持续性，不能根本上解决城市发展问题；尾句“因此”后应是对上文的总结，C选项可看作禁止型对策，再分析了重大事件后，给出“城市发展动力不能依赖重大事件”的对策，符合逻辑，当选；
A选项、B选项⑨都是对“可持续发展”和“重大事件”的区别的总结，但上文并未提及可持续发展，排除；
D选项本身有误，重大事件已不能从根本上解决“城市病”,即便寄托于新的，依旧不能从根本上解决，对策有误，排除。

花生批注：
⑨ 行文结构：后对策结构。
开篇引出话题：
重大事件作为城市发展动力具有无可替代的积极作用；再转折提出问题：
重大事件不具有可持续性，不能解决“城市病”;
尾句“因此”后应是对上文的总结。
⑩ 二者均为区别比较联系类选项，即“可持续发展与重大事件”二者的区别比较，若选择A选项或B选项，文段应为科普介绍类，上文也应提及可持续发展，且二者地位、篇幅大致相当。','2020年上海公安招聘','进阶','published','{"globalNumber":4,"setNumber":1,"localNumber":4,"sourceLabel":"2020年上海公安招聘 61%","accuracy":61,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"毫无疑问，重大事件作为城市发展动力具有无可替代的积极作用：它能集中人力、物力、财力，能够凝聚市民积极参与的热情，能够发挥连带效应拉动相关产业的发展，能够通过“非常状态”的锤炼提升城市管理和运行水平，能够快速提升城市知名度从而增强城市软实力，等等。但是，重大事件所具有的片面发展、透支未来、非常规管理等问题均不具有可持续性，尤其是不可能从根本上解决“冰冻三尺非一日之寒”的“过度城市化”“城市空心化”等“城市病”,因此\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"可持续发展是常态，重大事件是非常态"}],"B":[{"text":"可持续发展是本，重大事件为末"}],"C":[{"text":"城市发展动力不能依赖重大事件"}],"D":[{"text":"城市发展战略应寄托于新的“重大事件”的刺激"}]},"annotatedStemRich":[{"text":"毫无疑问，"},{"text":"重大事件","underline":true},{"text":"⑧作为城市发展动力具有无可替代的积极作用：它能集中人力、物力、财力，能够凝聚市民积极参与的热情，能够发挥连带效应拉动相关产业的发展，能够通过“非常状态”的锤炼提升城市管理和运行水平，能够快速提升城市知名度从而增强城市软实力，等等(引出话题)。但是，重大事件所具有的片面发展、透支未来、非常规管理等问题均不具有可持续性，尤其是不可能从根本上解决“冰冻三尺非一日之寒”的“过度城市化”“城市空心化”等“城市病”(提出问题),因此 "},{"text":"                      ","underline":true},{"text":" (给出对策)。⑨\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"可持续发展是常态，重大事件是非常态(区别比较联系类)"}],"B":[{"text":"可持续发展是本，重大事件为末(区别比较联系类)"}],"C":[{"text":"城市发展动力不能依赖重大事件"}],"D":[{"text":"城市发展战略应寄托于新的“重大事件”的刺激(对策有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍了重大事件的积极作用，转折后介绍了重大事件不具有可持续性，不能根本上解决城市发展问题；尾句“因此”后应是对上文的总结，C选项可看作禁止型对策，再分析了重大事件后，给出“城市发展动力不能依赖重大事件”的对策，符合逻辑，当选；\nA选项、B选项⑨都是对“可持续发展”和“重大事件”的区别的总结，但上文并未提及可持续发展，排除；\nD选项本身有误，重大事件已不能从根本上解决“城市病”,即便寄托于新的，依旧不能从根本上解决，对策有误，排除。","notes":[{"marker":"⑨","content":"行文结构：后对策结构。\n开篇引出话题：\n重大事件作为城市发展动力具有无可替代的积极作用；再转折提出问题：\n重大事件不具有可持续性，不能解决“城市病”;\n尾句“因此”后应是对上文的总结。","matchScore":0.9444,"pairingMode":"marker-and-content","order":8},{"marker":"⑩","content":"二者均为区别比较联系类选项，即“可持续发展与重大事件”二者的区别比较，若选择A选项或B选项，文段应为科普介绍类，上文也应提及可持续发展，且二者地位、篇幅大致相当。","matchScore":0.3619,"pairingMode":"content-similarity","order":9}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300005,3,'中心理解题','截至2019年末，我国60岁及以上人口已超过2.5亿，占总人口的18.1%,也就是说，差不多5个人中，就有一位老人。当前，即便是城镇地区，非网民占比也达到了40.2%。随着老年群体规模日益庞大，在公共服务的提供上，尽最大努力照顾老年人的诉求，已显得越来越必要，它已经不能用“照拂少数人需求”来形容了。在当前这样“快进”的互联网时代，不上网的老人远比我们想象中的多。他们的正常需求，不能因为不上网就被无视。
这段文字着重强调的是：','[{"label":"A","content":"上亿不上网的老年人应该被互联网社会所接纳"},{"label":"B","content":"需为庞大的老年人群体提供更便利的公共服务"},{"label":"C","content":"帮助老年人跟上互联网时代应该提上议事日程"},{"label":"D","content":"“照顾少数人需求”应成为关爱老年人的行动"}]','B','文段分析见批注。
根据对策句“随着老年群体规模日益庞大，在公共服务的提供上，尽最大努力照顾老年人的诉求，已显得越来越必要”可知：问题为“公共服务的提供”, 对策为“照顾老年人诉求”。B选项为“问题+对策”的完美选项；
A选项、C选项的“被互联网社会接纳”、“跟上互联网时代”和“公共服务的提供”无关；
D选项逻辑混乱、本身有误⑨,且未提及“公共服务的提供”;
综上，正确答案为B选项。

花生批注：
⑫ 行文结构：前对策结构。
先介绍背景：老年人多；
再提出对策：
在公共服务上，要尽最大努力照顾老年人的诉求(用“必要”表对策);
最后分析论证，在互联网时代，虽然老年人不上网，但不能因此无视其需求。需要注意的是，“互联网时代”、“不上网”为分析论证中的内容，并非要解决的问题，
要解决的是“公共服务提供”的问题。
⑬ 原文逻辑为：老年人口多，照顾老年人已经不是“照顾少数人需求”;并不是“照顾少数人需求”应成为关爱老年人行动。','2021年江苏省考','基础','published','{"globalNumber":5,"setNumber":1,"localNumber":5,"sourceLabel":"2021年江苏省考 70%","accuracy":70,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"截至2019年末，我国60岁及以上人口已超过2.5亿，占总人口的18.1%,也就是说，差不多5个人中，就有一位老人。当前，即便是城镇地区，非网民占比也达到了40.2%。随着老年群体规模日益庞大，在公共服务的提供上，尽最大努力照顾老年人的诉求，已显得越来越必要，它已经不能用“照拂少数人需求”来形容了。在当前这样“快进”的互联网时代，不上网的老人远比我们想象中的多。他们的正常需求，不能因为不上网就被无视。\n这段文字着重强调的是："}],"optionRich":{"A":[{"text":"上亿不上网的老年人应该被互联网社会所接纳"}],"B":[{"text":"需为庞大的老年人群体提供更便利的公共服务"}],"C":[{"text":"帮助老年人跟上互联网时代应该提上议事日程"}],"D":[{"text":"“照顾少数人需求”应成为关爱老年人的行动"}]},"annotatedStemRich":[{"text":"截至2019年末，我国60岁及以上人口已超过2.5亿，占总人口的 18.1%,也就是说，差不多5个人中，就有一位老人。当前，即便是城镇地区，非网民占比也达到了40.2%(背景介绍)。随着老年群体规模日益庞大，"},{"text":"在公共服务的提供上","underline":true},{"text":"四，尽最大努力照顾老年人的诉求，已显得越来越必要(提出对策 ) ,它已经不能用“照拂少数人需求”来形容了。在当前这样“快进”的互联网时代，不上网的老人远比我们想象中的多。他们的正常需求，不能因为\n不上网就被无视(分析论证)。②\n这段文字着重强调的是："}],"annotatedOptionRich":{"A":[{"text":"上亿不上网的老年人应该被互联网社会所接纳(对策有误)"}],"B":[{"text":"需为庞大的老年人群体提供更便利的公共服务"}],"C":[{"text":"帮助老年人跟上互联网时代应该提上议事日程(对策有误)"}],"D":[{"text":"“照顾少数人需求”应成为关爱老年人的行动(本身有误)"}]},"practicalAnalysis":"文段分析见批注。\n根据对策句“随着老年群体规模日益庞大，在公共服务的提供上，尽最大努力照顾老年人的诉求，已显得越来越必要”可知：问题为“公共服务的提供”, 对策为“照顾老年人诉求”。B选项为“问题+对策”的完美选项；\nA选项、C选项的“被互联网社会接纳”、“跟上互联网时代”和“公共服务的提供”无关；\nD选项逻辑混乱、本身有误⑨,且未提及“公共服务的提供”;\n综上，正确答案为B选项。","notes":[{"marker":"⑫","content":"行文结构：前对策结构。\n先介绍背景：老年人多；\n再提出对策：\n在公共服务上，要尽最大努力照顾老年人的诉求(用“必要”表对策);\n最后分析论证，在互联网时代，虽然老年人不上网，但不能因此无视其需求。需要注意的是，“互联网时代”、“不上网”为分析论证中的内容，并非要解决的问题，\n要解决的是“公共服务提供”的问题。","matchScore":0.5783,"pairingMode":"content-similarity","order":11},{"marker":"⑬","content":"原文逻辑为：老年人口多，照顾老年人已经不是“照顾少数人需求”;并不是“照顾少数人需求”应成为关爱老年人行动。","matchScore":0.4628,"pairingMode":"content-similarity","order":12}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300006,3,'中心理解题','根据群体遗传学的研究，遗传病与人类群体的遗传多样性密切相关，一方面，遗传病在不同人群中呈现不同的易感性；另一方面，靶向性药物在不同人群中也呈现不同的治疗效果。新药上市需要严格的临床试验认证，某种药物可能只在特定遗传背景的病人身上有效，肺癌靶向药物克唑替尼就很好地说明了特定人类资源对于药物研发的重要性。我国人口基数大、民族多、疾病类型多、家系多、具有丰富的人类遗传资源，无论是为了促进科学研究，守护公众健康，还是为了维护国家安全和社会公共利益，都应珍惜人类遗传资源这一巨大的宝藏。
该段文字意在提出：','[{"label":"A","content":"人类遗传资源的特性决定药物研发的方向"},{"label":"B","content":"我国人类遗传资源能有效促进科学研究，守护公众健康"},{"label":"C","content":"应致力保护本土人类遗传资源"},{"label":"D","content":"丰富的人类遗传资源对遗传病研究大有裨益"}]','C','文段分析见批注。
本题A选项对应背景知识介绍部分，出处有误； B选项、D选项介绍人类遗传资源的意义和价值，未体现对策，均可简单排除；
C选项，“保护本土人类遗传资源”是“我国应珍惜我们丰富的人类遗传资源”的同义替换；
综上，正确答案为C选项。

花生批注：
⑮ 行文结构：后对策结构。
先介绍背景知识：遗传病和人类群体遗传多样性有关；尾句先分析最后提出对策：我国要珍惜我们丰富的人类遗传资源。主体是“我国”。
⑯ 尾句指出的①我国人类遗传资源丰富②可促进科学研究守护公众健康③可维护国家安全的社会公共利益，均是提出“我国要珍惜人类遗传资源”的理由，因为这些理由所以更要珍惜，对策“要珍惜”更重要。
33 “A 且B”类选项概括全面，是正确答案概率很高，看到此类选项，直接考虑和原文一一对应即可。','2021年广东省事业单位','挑战','published','{"globalNumber":6,"setNumber":1,"localNumber":6,"sourceLabel":"2021年广东省事业单位 43%","accuracy":43,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"根据群体遗传学的研究，遗传病与人类群体的遗传多样性密切相关，一方面，遗传病在不同人群中呈现不同的易感性；另一方面，靶向性药物在不同人群中也呈现不同的治疗效果。新药上市需要严格的临床试验认证，某种药物可能只在特定遗传背景的病人身上有效，肺癌靶向药物克唑替尼就很好地说明了特定人类资源对于药物研发的重要性。我国人口基数大、民族多、疾病类型多、家系多、具有丰富的人类遗传资源，无论是为了促进科学研究，守护公众健康，还是为了维护国家安全和社会公共利益，都应珍惜人类遗传资源这一巨大的宝藏。\n该段文字意在提出："}],"optionRich":{"A":[{"text":"人类遗传资源的特性决定药物研发的方向"}],"B":[{"text":"我国人类遗传资源能有效促进科学研究，守护公众健康"}],"C":[{"text":"应致力保护本土人类遗传资源"}],"D":[{"text":"丰富的人类遗传资源对遗传病研究大有裨益"}]},"annotatedStemRich":[{"text":"根据群体遗传学的研究，遗传病与人类群体的遗传多样性密切相关，一方面，遗传病在不同人群中呈现不同的易感性；另一方面，靶向性药物在不同人群中也呈现不同的治疗效果。新药上市需要严格的临床试验认证，某种药物可能只在特定遗传背景的病人身上有效，肺癌靶向药物克唑替尼就很好地说明了特定人类资源对于药物研发的重要性(背景知识介绍)。"},{"text":"我国⑥人口基数大、 ","underline":true},{"text":" "},{"text":"民族多、疾病类型多、家系多、具有丰富的人类遗传资源，无论是为了促进科学研究，守护公众健康，还是为了维护国家安全和社会公共利益，都应珍惜人类遗传资源这一巨大的宝藏(提出对策) ","underline":true},{"text":"⑮⑥\n该段文字意在提出："}],"annotatedOptionRich":{"A":[{"text":"人类遗传资源的特性决定药物研发的方向(中性表达且出处有误)"}],"B":[{"text":"我国人类遗传资源能有效促进科学研究，守护公众健康(中性表达)"}],"C":[{"text":"应致力保护本土人类遗传资源","bold":true}],"D":[{"text":"丰富的人类遗传资源对遗传病研究大有裨益(中性表达)"}]},"practicalAnalysis":"文段分析见批注。\n本题A选项对应背景知识介绍部分，出处有误； B选项、D选项介绍人类遗传资源的意义和价值，未体现对策，均可简单排除；\nC选项，“保护本土人类遗传资源”是“我国应珍惜我们丰富的人类遗传资源”的同义替换；\n综上，正确答案为C选项。","notes":[{"marker":"⑮","content":"行文结构：后对策结构。\n先介绍背景知识：遗传病和人类群体遗传多样性有关；尾句先分析最后提出对策：我国要珍惜我们丰富的人类遗传资源。主体是“我国”。","matchScore":0.6264,"pairingMode":"marker-and-content","order":14},{"marker":"⑯","content":"尾句指出的①我国人类遗传资源丰富②可促进科学研究守护公众健康③可维护国家安全的社会公共利益，均是提出“我国要珍惜人类遗传资源”的理由，因为这些理由所以更要珍惜，对策“要珍惜”更重要。","matchScore":0.6597,"pairingMode":"content-similarity","order":15},{"marker":"33","content":"“A 且B”类选项概括全面，是正确答案概率很高，看到此类选项，直接考虑和原文一一对应即可。","matchScore":0.1816,"pairingMode":"content-similarity","order":31}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300007,3,'细节判断类','按照马歇尔的定义，消费者剩余是指消费者通过商品交换取得的净收益。具体来讲就是消费者购买某商品的意愿价格与实际成交价格之间的差额。这就是说，消费者剩余的大小取决于两个因素：买方意愿价与实际成交价。我们知道，实际成交价就是市价，单个买家或卖家均无法左右市价，它要由市场决定。如果成交价是市价，则消费者剩余大小就要看买方的意愿价格。买方意愿价格越高，消费者剩余则会越大。
与这段文字的意思相符的一项是：','[{"label":"A","content":"消费者剩余受卖家定价行为影响"},{"label":"B","content":"消费者剩余会根据市价的变化而增减"},{"label":"C","content":"消费者剩余的大小取决于买方的意愿价格"},{"label":"D","content":"消费者剩余的大小受市场变动的影响较小"}]','B','本文段逻辑性较强，读懂原文意思即可判断选项正误；文段指出“消费者剩余的大小取决于两个因素：买方意愿价与实际成交价，而且实际成交价就是市价”,因此：消费者剩余=买方意愿价一实际成交价(市价)。①
根据总结出的公式可知：消费者剩余和卖方定价无关，排除A选项；消费者剩余会根据买方意愿价或市价的变化而变化，B选项正确；消费者剩余取决于买方意愿价和实际成交价两个变量，排除C选项；消费者剩余会受到市场变动(市价)影响，“影响较小”无中生有，排除D选项；
综上，本题答案为B选项。
片段阅读6 0 0 四(上册)

花生批注：
⑰ 消费者剩余，受到买方意愿价、实际成交价两个变量影响，不能说受某一单一因素决定。
例如：
笔试总成绩=行测+申论；
B选项：笔试总成绩会根据申论成绩变化而增减，说法正确；
C选项：笔试总成绩取决于行测成绩，说法错误。','2018年广西选调','挑战','published','{"globalNumber":7,"setNumber":1,"localNumber":7,"sourceLabel":"2018年广西选调 41%","accuracy":41,"typeAndPassage":"细节判断类","stemRich":[{"text":"按照马歇尔的定义，消费者剩余是指消费者通过商品交换取得的净收益。具体来讲就是消费者购买某商品的意愿价格与实际成交价格之间的差额。这就是说，消费者剩余的大小取决于两个因素：买方意愿价与实际成交价。我们知道，实际成交价就是市价，单个买家或卖家均无法左右市价，它要由市场决定。如果成交价是市价，则消费者剩余大小就要看买方的意愿价格。买方意愿价格越高，消费者剩余则会越大。\n与这段文字的意思相符的一项是："}],"optionRich":{"A":[{"text":"消费者剩余受卖家定价行为影响"}],"B":[{"text":"消费者剩余会根据市价的变化而增减"}],"C":[{"text":"消费者剩余的大小取决于买方的意愿价格"}],"D":[{"text":"消费者剩余的大小受市场变动的影响较小"}]},"annotatedStemRich":[{"text":"按照马歇尔的定义，消费者剩余是指消费者通过商品交换取得的净收益。具体来讲就是消费者购买某商品的意愿价格与实际成交价格之间的差额。这就是说，消费者剩余的大小取决于两个因素：买方意愿价与实际成交价。我们知道，实际成交价就是市价，单个买家或卖家均无法左右市价，它要由市场决定。如果成交价是市价，则消费者剩余大小就要看买方的意愿价格。买方意愿价格越高，消费者剩余则会越大。\n与这段文字的意思相符的一项是："}],"annotatedOptionRich":{"A":[{"text":"消费者剩余受卖家定价行为影响"}],"B":[{"text":"消费者剩余会根据市价的变化而增减"}],"C":[{"text":"消费者剩余的大小取决于买方的意愿价格"}],"D":[{"text":"消费者剩余的大小受市场变动的影响较小"}]},"practicalAnalysis":"本文段逻辑性较强，读懂原文意思即可判断选项正误；文段指出“消费者剩余的大小取决于两个因素：买方意愿价与实际成交价，而且实际成交价就是市价”,因此：消费者剩余=买方意愿价一实际成交价(市价)。①\n根据总结出的公式可知：消费者剩余和卖方定价无关，排除A选项；消费者剩余会根据买方意愿价或市价的变化而变化，B选项正确；消费者剩余取决于买方意愿价和实际成交价两个变量，排除C选项；消费者剩余会受到市场变动(市价)影响，“影响较小”无中生有，排除D选项；\n综上，本题答案为B选项。\n片段阅读6 0 0 四(上册)","notes":[{"marker":"⑰","content":"消费者剩余，受到买方意愿价、实际成交价两个变量影响，不能说受某一单一因素决定。\n例如：\n笔试总成绩=行测+申论；\nB选项：笔试总成绩会根据申论成绩变化而增减，说法正确；\nC选项：笔试总成绩取决于行测成绩，说法错误。","matchScore":0.5032,"pairingMode":"content-similarity","order":16}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300008,3,'中心理解题','成功不是衡量人生价值的最高标准，比成功更重要的是，一个人要有丰富的内在，有自己的真性情和真兴趣，有自己真正喜欢做的事。只要你有自己真正喜欢做的事，你就在任何情况下都会感到充实和踏实。那些仅仅追求外在成功的人实际上是没有真正喜欢做的事，他们真正喜欢的只是名利，一旦在名利场上受挫，内在的空虚就暴露无遗。
这段文字的主旨是：','[{"label":"A","content":"成功就是做好自己喜欢做的事"},{"label":"B","content":"人生价值的最高标准难以确定"},{"label":"C","content":"追逐名利的人是得不到成功的"},{"label":"D","content":"兴趣是人们得到幸福的源泉"}]','A','文段均在论述，逻辑结构较混乱，依次翻译即可：①比成功更重要的是有自己真正喜欢做的事；②有自己真正喜欢做的事，会充实和踏实；
③没有真正喜欢做的事只是追求外在成功，内心是空虚的。
上述三句话均在谈论“做自己喜欢做的事”,对应A选项，当选；
其他选项均未提及“做自己真正喜欢的事”,均可简单排除。

花生批注：
⑲ 全文均在论述，逻辑结构较混乱，依次翻译即可：
①比成功更重要的是有自己真正喜欢做的事；
②有自己真正喜欢做的事，会充实和踏实；
③没有真正喜欢做的事只是追求外在成功，内心是空虚的。
② 根据第③句的“外在成功”, 我们可以把成功分为外在成功和真正的成功；
即真正的成功(比外在成功更重要的是)做自己喜欢做的事，没有做自己喜欢做的事只是外在成功，不是真正成功。','2017年天津市考','进阶','published','{"globalNumber":8,"setNumber":1,"localNumber":8,"sourceLabel":"2017年天津市考 55%","accuracy":55,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"成功不是衡量人生价值的最高标准，比成功更重要的是，一个人要有丰富的内在，有自己的真性情和真兴趣，有自己真正喜欢做的事。只要你有自己真正喜欢做的事，你就在任何情况下都会感到充实和踏实。那些仅仅追求外在成功的人实际上是没有真正喜欢做的事，他们真正喜欢的只是名利，一旦在名利场上受挫，内在的空虚就暴露无遗。\n这段文字的主旨是："}],"optionRich":{"A":[{"text":"成功就是做好自己喜欢做的事"}],"B":[{"text":"人生价值的最高标准难以确定"}],"C":[{"text":"追逐名利的人是得不到成功的"}],"D":[{"text":"兴趣是人们得到幸福的源泉"}]},"annotatedStemRich":[{"text":"①成功不是衡量人生价值的最高标准，比成功更重要的是，一个人要有丰富的内在，有自己的真性情和真兴趣，"},{"text":"有自己真正喜欢做的事","underline":true},{"text":"⑥。②只要你有自己真正喜欢做的事，你就在任何情况下都会感到充实和踏实。③那些仅仅追求外在成功的人实际上是没有真正喜欢做的事，他们真正喜欢的只是名利，一旦在名利场上受挫，内在的空虚就暴露无遗。⑩\n这段文字的主旨是："}],"annotatedOptionRich":{"A":[{"text":"成功就是做好自己喜欢做的事"}],"B":[{"text":"人生价值的最高标准难以确定(无中生有)"}],"C":[{"text":"追逐名利的人是得不到成功的(杂糅)"}],"D":[{"text":"兴趣是人们得到幸福的源泉(无中生有)"}]},"practicalAnalysis":"文段均在论述，逻辑结构较混乱，依次翻译即可：①比成功更重要的是有自己真正喜欢做的事；②有自己真正喜欢做的事，会充实和踏实；\n③没有真正喜欢做的事只是追求外在成功，内心是空虚的。\n上述三句话均在谈论“做自己喜欢做的事”,对应A选项，当选；\n其他选项均未提及“做自己真正喜欢的事”,均可简单排除。","notes":[{"marker":"⑲","content":"全文均在论述，逻辑结构较混乱，依次翻译即可：\n①比成功更重要的是有自己真正喜欢做的事；\n②有自己真正喜欢做的事，会充实和踏实；\n③没有真正喜欢做的事只是追求外在成功，内心是空虚的。","matchScore":1.2643,"pairingMode":"content-similarity","order":17},{"marker":"②","content":"根据第③句的“外在成功”, 我们可以把成功分为外在成功和真正的成功；\n即真正的成功(比外在成功更重要的是)做自己喜欢做的事，没有做自己喜欢做的事只是外在成功，不是真正成功。","matchScore":0.5887,"pairingMode":"marker-and-content","order":18}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300009,3,'下文推断类','在信息流动中，个体几乎居于风险的主要位置，即要承载由不确定风险所带来的所有后果。但是就信息获得、披露与结果承受等角度而言，个体基本上处于一种消极、被动的地位，而在很大程度上能够掌控相应风险或获得更为对称信息的，却是掌握个人信息的平台或企业一方。因此，往往是有风险者无法负担风险，而风险掌控者却可能在负担风险之时“缺席”。
这段文字接下来最有可能讨论的是：','[{"label":"A","content":"如何规避个体在信息流动中产生的风险"},{"label":"B","content":"如何让信息的获益方承担风险责任"},{"label":"C","content":"信息流动中的风险究竟该如何掌控"},{"label":"D","content":"信息平台与个人之间究竟由谁承担风险"}]','B','文段分析见批注。
文段先分析介绍了平台或企业能掌控风险但不承担风险，个体承担风险却无力掌控风险；最后用“因此”给出总结：承担风险者(个体)无法负担风险，
“做自己真正喜欢做的事”是全文论述话题。

花生批注：
① 学生“混居”是全文论述话题。
⑧ 重大事件是全文论述主题。
⑪ 公共服务提供是全文论述话题。
⑭ 我国是全文论述主体。
② “风险掌控者(企业或平台) 在应该承担风险时缺席”是上文文末提出的问题。
2 行文结构：分总结构。
文段先分析了风险承担、风险掌控的不同主体：
平台或企业能掌控风险但不承担风险，个体承担风险却无力掌控风险；
最后给出总结：承担风险者无法负担风险，风险掌控者却在该承担风险时“缺席”。
③ 海水淡化是全文论述话题。
④3 “诚信”全文论述话题。','2021年江苏省考','挑战','published','{"globalNumber":9,"setNumber":1,"localNumber":9,"sourceLabel":"2021年江苏省考 43%","accuracy":43,"typeAndPassage":"下文推断类 +提出问题 → 解决问题","stemRich":[{"text":"在信息流动中，个体几乎居于风险的主要位置，即要承载由不确定风险所带来的所有后果。但是就信息获得、披露与结果承受等角度而言，个体基本上处于一种消极、被动的地位，而在很大程度上能够掌控相应风险或获得更为对称信息的，却是掌握个人信息的平台或企业一方。因此，往往是有风险者无法负担风险，而风险掌控者却可能在负担风险之时“缺席”。\n这段文字接下来最有可能讨论的是："}],"optionRich":{"A":[{"text":"如何规避个体在信息流动中产生的风险"}],"B":[{"text":"如何让信息的获益方承担风险责任"}],"C":[{"text":"信息流动中的风险究竟该如何掌控"}],"D":[{"text":"信息平台与个人之间究竟由谁承担风险"}]},"annotatedStemRich":[{"text":"在信息流动中，个体几乎居于风险的主要位置，即要承载由不确定风险所带来的所有后果。但是就信息获得、披露与结果承受等角度而言，个体基本上处于一种消极、被动的地位，而在很大程度上能够掌控相应风险或获得更为对称信息的，却是掌握个人信息的平台或企业一方。因此，往往是有风险者无法负担风险，"},{"text":"而风险掌控者却可能在负担风险之时“缺席”","underline":true},{"text":"。②\n这段文字接下来最有可能讨论的是："}],"annotatedOptionRich":{"A":[{"text":"如何规避个体在信息流动中产生的风险"}],"B":[{"text":"如何让信息的获益方承担风险责任"}],"C":[{"text":"信息流动中的风险究竟该如何掌控"}],"D":[{"text":"信息平台与个人之间究竟由谁承担风险"}]},"practicalAnalysis":"文段分析见批注。\n文段先分析介绍了平台或企业能掌控风险但不承担风险，个体承担风险却无力掌控风险；最后用“因此”给出总结：承担风险者(个体)无法负担风险，\n“做自己真正喜欢做的事”是全文论述话题。","notes":[{"marker":"①","content":"学生“混居”是全文论述话题。","matchScore":0.6373,"pairingMode":"content-similarity","order":0},{"marker":"⑧","content":"重大事件是全文论述主题。","matchScore":0.442,"pairingMode":"content-similarity","order":7},{"marker":"⑪","content":"公共服务提供是全文论述话题。","matchScore":0.5325,"pairingMode":"content-similarity","order":10},{"marker":"⑭","content":"我国是全文论述主体。","matchScore":0.5328,"pairingMode":"content-similarity","order":13},{"marker":"②","content":"“风险掌控者(企业或平台) 在应该承担风险时缺席”是上文文末提出的问题。","matchScore":0.5179,"pairingMode":"marker-and-content","order":19},{"marker":"2","content":"行文结构：分总结构。\n文段先分析了风险承担、风险掌控的不同主体：\n平台或企业能掌控风险但不承担风险，个体承担风险却无力掌控风险；\n最后给出总结：承担风险者无法负担风险，风险掌控者却在该承担风险时“缺席”。","matchScore":0.9261,"pairingMode":"marker-and-content","order":20},{"marker":"③","content":"海水淡化是全文论述话题。","matchScore":0.6326,"pairingMode":"content-similarity","order":29},{"marker":"④3","content":"“诚信”全文论述话题。","matchScore":0.7471,"pairing