INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300014,3,'中心理解题','水资源短缺一直是我国在人口增长、城市化和工业化过程中所面临的一个长期的、趋势性的问题，成为制约我国经济发展的一大瓶颈。专家认为，海水淡化是沿海及临海地区最经济、最实用、最灵活的水危机解决方案。随着技术的进步，海水淡化的成本将逐步降低，最终将达到与成本正逐步上升的城市自来水竞争的程度，从而得以大规模推广。
这段文字主要强调的是：','[{"label":"A","content":"海水淡化的必要性和可行性"},{"label":"B","content":"海水淡化的经济性和实用性"},{"label":"C","content":"制约中国经济发展的水危机"},{"label":"D","content":"解决沿海地区水危机的有效措施"}]','A','文段分析见批注。
