INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300018,3,'语句填入类','当我们仔细观察当今世界上的主流火箭时，就会发现它们用的发动机、燃料箱等都是上世纪的产物。比如要在2018年首飞的太空发射系统用的是改进过的航天飞机的火箭发动机，燃料箱用的是改进过的航天飞机的外挂燃料箱，两侧的固体燃料推进器用的也是改进过的航天飞机的固体燃料推进器。。火箭是非常复杂的东西，设计并制造火箭需要考虑的因素太多，就连火箭制造商们也只能去选择一些经受过时间考验的产物，从而确保产品的可靠性。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"这是因为新技术的推广需要一定的时间"},{"label":"B","content":"这并不意味着火箭技术没有任何新的进展"},{"label":"C","content":"事实上，制造火箭的材料并不都是前沿科技产物"},{"label":"D","content":"也就是说，在火箭这个领域内并不是最新的就是好的"}]','D','所填入语句在文段中间，可先概括前后两部分：“横线”前介绍的是“火箭多使用旧材料”,“横线”后介绍了“火箭为什么使用旧材料”, 前后均谈及“旧材料”。
观察选项：若填入 A选项，解释火箭使用旧材料的原因是新技术推广需要时间，与后文的“使用旧材料是因为要确保可靠性”矛盾，排除；
若填入B选项“这并不意味着没有新进展”,按照行文逻辑，下文应介绍新进展，而非继续解释为什么使用旧材料，排除；
若填入 C选项“事实上，制造火箭的材料并不都是前沿科技产物”,按照行文逻辑，前文应介绍制造火箭的前沿科技产物，转折后再介绍也使用了旧材料，排除；
若填入D选项， D选项起到承上启下的作用，“也就是说”是对上文的继续解释，“横线”前、“横线”中、“横线”后均在谈论旧材料，逻辑正确，当选。','2018年国家公务员考试','进阶','published','{"globalNumber":18,"setNumber":1,"localNumber":18,"sourceLabel":"2018年国家公务员考试62%","accuracy":62,"typeAndPassage":"语句填入类+科普介绍文章","stemRich":[{"text":"当我们仔细观察当今世界上的主流火箭时，就会发现它们用的发动机、燃料箱等都是上世纪的产物。比如要在2018年首飞的太空发射系统用的是改进过的航天飞机的火箭发动机，燃料箱用的是改进过的航天飞机的外挂燃料箱，两侧的固体燃料推进器用的也是改进过的航天飞机的固体燃料推进器。 "},{"text":" ","underline":true},{"text":"。火箭是非常复杂的东西，设计并制造火箭需要考虑的因素太多，就连火箭制造商们也只能去选择一些经受过时间考验的产物，从而确保产品的可靠性。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"这是因为新技术的推广需要一定的时间"}],"B":[{"text":"这并不意味着火箭技术没有任何新的进展"}],"C":[{"text":"事实上，制造火箭的材料并不都是前沿科技产物"}],"D":[{"text":"也就是说，在火箭这个领域内并不是最新的就是好的"}]},"annotatedStemRich":[{"text":"当我们仔细观察当今世界上的主流火箭时，就会发现它们用的发动机、燃料箱等都是上世纪的产物。比如要在2018年首飞的太空发射系统用的是改进过的航天飞机的火箭发动机，燃料箱用的是改进过的航天飞机的外挂燃料箱，两侧的固体燃料推进器用的也是改进过的航天飞机的固体燃料推进器(介绍制造火箭使用旧材料)。"},{"text":"                        ","underline":true},{"text":" (可考虑承上启下)。火箭是非常复杂的东西，设计并制造火箭需要考虑的因素太多，就连火箭制造商们也只能去选择一些经受过时间考验的产物，从而确保产品的可靠性(解释为什么使用旧材料)。\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"这是因为新技术的推广需要一定的时间"}],"B":[{"text":"这并不意味着火箭技术没有任何新的进展"}],"C":[{"text":"事实上，制造火箭的材料并不都是前沿科技产物"}],"D":[{"text":"也就是说，在火箭这个领域内并不是最新的就是好的\n"},{"text":"【参考答","italic":true},{"text":"案 】D"}]},"practicalAnalysis":"所填入语句在文段中间，可先概括前后两部分：“横线”前介绍的是“火箭多使用旧材料”,“横线”后介绍了“火箭为什么使用旧材料”, 前后均谈及“旧材料”。\n观察选项：若填入 A选项，解释火箭使用旧材料的原因是新技术推广需要时间，与后文的“使用旧材料是因为要确保可靠性”矛盾，排除；\n若填入B选项“这并不意味着没有新进展”,按照行文逻辑，下文应介绍新进展，而非继续解释为什么使用旧材料，排除；\n若填入 C选项“事实上，制造火箭的材料并不都是前沿科技产物”,按照行文逻辑，前文应介绍制造火箭的前沿科技产物，转折后再介绍也使用了旧材料，排除；\n若填入D选项， D选项起到承上启下的作用，“也就是说”是对上文的继续解释，“横线”前、“横线”中、“横线”后均在谈论旧材料，逻辑正确，当选。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300019,3,'细节判断类','从医学角度看，非酒精性脂肪肝是因为脂代谢紊乱等多种因素引起了肝细胞内中性脂肪(主要是甘油三酯和脂肪酸)过度堆积。脂代谢紊乱引发的多种重要组织损伤，特别是心脑血管和肝脏损害，对健康造成极大威胁，因此其机制和防治策略研究一直是国际上医学研究的前沿领域。专家指出，尽管饮食控制和改变生活方式对高脂血症及脂肪肝有明显的改善作用，但在现实生活中很难实施，患者往往由于各种因素不能严格执行医嘱。到目前为止，人类尚未研发出可以根治和阻止肝脏脂代谢紊乱的有效药物。
关于脂代谢紊乱，文中没有提及：','[{"label":"A","content":"主要危害"},{"label":"B","content":"研究状况"},{"label":"C","content":"改善途径"},{"label":"D","content":"发病机理"}]','D','原文第①句的“非酒精性脂肪肝是因为脂代谢紊乱等多种因素引起了肝细胞内中性脂肪过度堆积”可翻译为“脂代谢紊乱等多种因素会引起肝细胞内中性脂肪过度堆积，从而引起非酒精性脂肪肝”,谈论的是“非酒精性脂肪肝的发病机理”,而非“脂代谢紊乱”的发病机理，D选项未提及，当选。

花生批注：
39 填入后的行文逻辑为：
先介绍火箭多用旧材料，中间解释“也就是说，并不是最新的就是好的(旧的也很好)”,下文再解释为什么旧材料好。
①从医学角度看，非酒精性脂肪肝是因为脂代谢紊乱等多种因素引起了肝细胞内中性脂肪(主要是甘油三酯和脂肪酸)过度堆积。②脂代谢紊乱引发的多种重要组织损伤，特别是心脑血管和肝脏损害，对健康造成极大威胁，因此其机制和防治策略研究一直是国际上医学研究的前沿领域。③专家指出，尽管饮食控制和改变生活方式对高脂血症及脂肪肝有明显的改善作用⑥,但在现实生活中很难实施，患者往往由于各种因素不能严格执行医嘱。④ 到目前为止，人类尚未研发出可以根治和阻止肝脏脂代谢紊乱的有效药物②。
关于脂代谢紊乱，文中没有提及：
A. 主要危害 B. 研究状况
C. 改善途径 D. 发病机理
④0 脂代谢紊乱的主要危害。
④① 脂代谢紊乱的改善途径。
有同学可能会认为“饮食控制和改变生活方式是高脂血症和脂肪肝的改善途径”, 而非“脂代谢紊乱的改善途径”;
但D选项是一定没有提及，很可能是出题人“挖坑”设置的选项，但C选项是可能有所提及，二者择优，D选项当选。
④② 脂代谢紊乱的研究状况。','2018年国家公务员考试','进阶','published','{"globalNumber":19,"setNumber":1,"localNumber":19,"sourceLabel":"2018年国家公务员考试 48%","accuracy":48,"typeAndPassage":"细节判断类","stemRich":[{"text":"从医学角度看，非酒精性脂肪肝是因为脂代谢紊乱等多种因素引起了肝细胞内中性脂肪(主要是甘油三酯和脂肪酸)过度堆积。脂代谢紊乱引发的多种重要组织损伤，特别是心脑血管和肝脏损害，对健康造成极大威胁，因此其机制和防治策略研究一直是国际上医学研究的前沿领域。专家指出，尽管饮食控制和改变生活方式对高脂血症及脂肪肝有明显的改善作用，但在现实生活中很难实施，患者往往由于各种因素不能严格执行医嘱。到目前为止，人类尚未研发出可以根治和阻止肝脏脂代谢紊乱的有效药物。\n关于脂代谢紊乱，文中没有提及："}],"optionRich":{"A":[{"text":"主要危害"}],"B":[{"text":"研究状况"}],"C":[{"text":"改善途径"}],"D":[{"text":"发病机理"}]},"annotatedStemRich":[{"text":"39花生批注：\n填入后的行文逻辑为：\n先介绍火箭多用旧材料，中间解释“也就是说，并不是最新的就是好的(旧的也很好)”,下文再解释为什么旧材料好。\n①从医学角度看，非酒精性脂肪肝是因为脂代谢紊乱等多种因素引起了肝细胞内中性脂肪(主要是甘油三酯和脂肪酸)过度堆积。②"},{"text":"脂代谢紊乱引发的多种重要组织损伤，特别是心脑血管和肝脏损害，对健康造成极大威胁","underline":true},{"text":"，因此其机制和防治策略研究一直是国际上医学研究的前沿领域。③专家指出，尽"},{"text":"管饮食控制和改变生活方式对高脂血症及脂肪肝有明显的改善作用","underline":true},{"text":"⑥,但在现实生活中很难实施，患者往往由于各种因素不能严格执行医嘱。④ "},{"text":" 到目前为止， ","underline":true},{"text":" "},{"text":"人类尚未研发出可以根治和阻止肝脏脂代谢紊乱的有效药物","underline":true},{"text":"②。\n关于脂代谢紊乱，文中没有提及："}],"annotatedOptionRich":{"A":[{"text":"主要危害"}],"B":[{"text":"研究状况"}],"C":[{"text":"改善途径"}],"D":[{"text":"发病机理","bold":true}]},"practicalAnalysis":"原文第①句的“非酒精性脂肪肝是因为脂代谢紊乱等多种因素引起了肝细胞内中性脂肪过度堆积”可翻译为“脂代谢紊乱等多种因素会引起肝细胞内中性脂肪过度堆积，从而引起非酒精性脂肪肝”,谈论的是“非酒精性脂肪肝的发病机理”,而非“脂代谢紊乱”的发病机理，D选项未提及，当选。","notes":[{"marker":"39","content":"填入后的行文逻辑为：\n先介绍火箭多用旧材料，中间解释“也就是说，并不是最新的就是好的(旧的也很好)”,下文再解释为什么旧材料好。\n①从医学角度看，非酒精性脂肪肝是因为脂代谢紊乱等多种因素引起了肝细胞内中性脂肪(主要是甘油三酯和脂肪酸)过度堆积。②脂代谢紊乱引发的多种重要组织损伤，特别是心脑血管和肝脏损害，对健康造成极大威胁，因此其机制和防治策略研究一直是国际上医学研究的前沿领域。③专家指出，尽管饮食控制和改变生活方式对高脂血症及脂肪肝有明显的改善作用⑥,但在现实生活中很难实施，患者往往由于各种因素不能严格执行医嘱。④ 到目前为止，人类尚未研发出可以根治和阻止肝脏脂代谢紊乱的有效药物②。\n关于脂代谢紊乱，文中没有提及：\nA. 主要危害 B. 研究状况\nC. 改善途径 D. 发病机理","matchScore":1.5536,"pairingMode":"content-similarity","order":37},{"marker":"④0","content":"脂代谢紊乱的主要危害。","matchScore":0.6949,"pairingMode":"content-similarity","order":38},{"marker":"④①","content":"脂代谢紊乱的改善途径。\n有同学可能会认为“饮食控制和改变生活方式是高脂血症和脂肪肝的改善途径”, 而非“脂代谢紊乱的改善途径”;\n但D选项是