INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300020,3,'中心理解题','人们一般认为，诚信与否是个人品德问题，与他人无关。但是个人品德却不仅仅是个人问题，它还会通过外部性产生社会效果——个人道德的亏欠，最终可能会“报应”到整个社会头上。从制度经济学的角度来看，一个好的经济制度和治理机制应当能够抑制负外部性，否则经济秩序可能走向崩溃，要通过制度和机制使始作俑者承担应有的责任，而不是让他人或者整个市场为之埋单。
对这段文字的主旨概括最准确的是：','[{"label":"A","content":"个人品德缺失得由全社会埋单"},{"label":"B","content":"经济制度对经济秩序意义重大"},{"label":"C","content":"诚信既是社会问题又是经济问题"},{"label":"D","content":"需用制度抑制不诚信的负外部性"}]','D','文段分析见批注。
D选项从对策句提炼，针对“不诚信”,要通过“制度机制”解决，问题、对策均正确的完美选项，当选；
A选项、C选项均为问题表述，未体现对策， B选项为中性表达，均可简单排除。
