INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300023,3,'语句填入类','进行骨髓移植的前提条件是有配型成功的捐赠者。双胞胎配型成功几率最高，兄弟姐妹也有可能。但在中国，20世纪70年代到现在，大多数都是独生子女，有兄弟姐妹且能配型成功的概率也非常低。另外，父母和子女之间骨髓配型成功的概率非常低，几乎为零。因此，绝大多数患者都必须依赖不认识的志愿者配型。非亲缘关系骨髓配型成功的几率只有几十万至几百万分之一，
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"即使这样，骨髓移植仍是大多数血液疾病患者的唯一希望"},{"label":"B","content":"如果冒着风险使用不完美的配型，成功率自然会大为降低"},{"label":"C","content":"骨髓库里志愿者样本的多少，直接决定着病人找到合适配型的几率"},{"label":"D","content":"志愿者捐献固然很重要，国家相关政策的落实和执行也是当务之急"}]','C','文段先引出话题“骨髓移植需要配型成功的捐赠者”,接下来依次分析各种类型配型者的成功概率：双胞胎配型成功几率最高、有兄弟姐妹且配型成功的概率非常低、父母和子女配型成功概率几乎为零，再接下来应分析不认识的志愿者配型概率问题。只有C选项谈到概率问题，非亲缘关系配型成功率和志愿者样本多少，直接决定了找到合适配型的几率， ⑤逻辑正确且谈论话题一致，当选；

花生批注：
⑤ 此语句逻辑为数学问题：
非亲缘关系配型成功概率× 志愿者样本数量=能找到合适配型的数量。
A选项谈论的是“骨髓移植是唯一希望”,即“多种治疗方式中只能骨髓移植”,但文段谈论的是不同对象骨髓移植配型成功的概率问题，非治疗方式选择的问题，排除；
B选项的“冒着风险使用不完美的配型”属于无中生有，且本身有误，实际治疗中不会这样做，排除；
D选项的“国家政策落实与执行”属于无中生有，排除。','2018年国家公务员考试','挑战','published','{"globalNumber":23,"setNumber":2,"localNumber":3,"sourceLabel":"2018年国家公务员考试40%","accuracy":40,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"进行骨髓移植的前提条件是有配型成功的捐赠者。双胞胎配型成功几率最高，兄弟姐妹也有可能。但在中国，20世纪70年代到现在，大多数都是独生子女，有兄弟姐妹且能配型成功的概率也非常低。另外，父母和子女之间骨髓配型成功的概率非常低，几乎为零。因此，绝大多数患者都必须依赖不认识的志愿者配型。非亲缘关系骨髓配型成功的几率只有几十万至几百万分之一，\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"即使这样，骨髓移植仍是大多数血液疾病患者的唯一希望"}],"B":[{"text":"如果冒着风险使用不完美的配型，成功率自然会大为降低"}],"C":[{"text":"骨髓库里志愿者样本的多少，直接决定着病人找到合适配型的几率"}],"D":[{"text":"志愿者捐献固然很重要，国家相关政策的落实和执行也是当务之急"}]},"annotatedStemRich":[{"text":"进行骨髓移植的前提条件是有配型成功的捐赠者"},{"text":"(引出话题)。","bold":true},{"text":"双胞胎配型成功几率最高，兄弟姐妹也有可能。但在中国，20世纪70年代到现在，大多数都是独生子女，有兄弟姐妹且能配型成功的概率也非常低。另外，父母和子女之间骨髓配型成功的概率非常低，几乎为零。因此，绝大多数患者都必须依赖不认识的志愿者配型。非亲缘关系骨髓配型成功的几率只有几十万至几百万分之一，"},{"text":"                        ","underline":true},{"text":" o\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"即使这样，骨髓移植仍是大多数血液疾病患者的唯一希望(话题不一致)"}],"B":[{"text":"如果冒着风险使用不完美的配型，成功率自然会大为降低"}],"C":[{"text":"骨髓库里志愿者样本的多少，直接决定着病人找到合适配型的几率"}],"D":[{"text":"志愿者捐献固然很重要，国家相关政策的落实和执行也是当务之急"}]},"practicalAnalysis":"文段先引出话题“骨髓移植需要配型成功的捐赠者”,接下来依次分析各种类型配型者的成功概率：双胞胎配型成功几率最高、有兄弟姐妹且配型成功的概率非常低、父母和子女配型成功概率几乎为零，再接下来应分析不认识的志愿者配型概率问题。只有C选项谈到概率问题，非亲缘关系配型成功率和志愿者样本多少，直接决定了找到合适配型的几率， ⑤逻辑正确且谈论话题一致，当选；","notes":[{"marker":"⑤","content":"此语句逻辑为数学问题：\n非亲缘关系配型成功概率× 志愿者样本数量=能找到合适配型的数量。\nA选项谈论的是“骨髓移植是唯一希望”,即“多种治疗方式中只能骨髓移植”,但文段谈论的是不同对象骨髓移植配型成功的概率问题，非治疗方式选择的问题，排除；\nB选项的“冒着风险使用不完美的配型”属于无中生有，且本身有误，实际治疗中不会这样做，排除；\nD选项的“国家政策落实与执行”属于无中生有，排除。","matchScore":0.3923,"pairingMode":"marker-and-content","order":4}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300024,3,'标题拟定类','20世纪70年代，一些科学家提出了一种假设，即我们的宇宙只不过是许多宇宙之一，它们都有着各自的物理学定律和错综复杂的结构，生命就在其中所有条件都恰好适宜的宇宙中出现。到了80年代，现代宇宙学中的某些理论则证明，这样的“平行宇宙”的确可能存在。近年来，英国科学家发现了另一个“宇宙”在我们的宇宙中留下的痕迹，他们认为有可能证明了多元宇宙的存在。
给这段文字加个标题，最为合适的一项是：','[{"label":"A","content":"《多元的宇宙》"},{"label":"B","content":"《1/N 是地球》"},{"label":"C","content":"《宇宙是唯一的吗》"},{"label":"D","content":"《“平行宇宙”论》"}]','C','文段分析见批注。
文段通过三个不同时期的研究进展，表明或许宇宙不是唯一的，可看作历程类文段；C选项的“宇宙是唯一的吗”,既包含70年代科学家提出的假设，

花生批注：
⑦ 行文结构：大并列。
文段通过清晰的时间轴依次介绍：
①70年代提出假设：我们的宇宙是众多宇宙之一；
②80年代通过理论证明“平行宇宙”可能存在；
③近年通过发现痕迹证明“多元宇宙”可能存在。','2020年河南省事业单位','进阶','published','{"globalNumber":24,"setNumber":2,"localNumber":4,"sourceLabel":"2020年河南省事业单位 48%","accuracy":48,"typeAndPassage":"标题拟定类+科普介绍文章","stemRich":[{"text":"20世纪70年代，一些科学家提出了一种假设，即我们的宇宙只不过是许多宇宙之一，它们都有着各自的物理学定律和错综复杂的结构，生命就在其中所有条件都恰好适宜的宇宙中出现。到了80年代，现代宇宙学中的某些理论则证明，这样的“平行宇宙”的确可能存在。近年来，英国科学家发现了另一个“宇宙”在我们的宇宙中留下的痕迹，他们认为有可能证明了多元宇宙的存在。\n给这段文字加个标题，最为合适的一项是："}],"optionRich":{"A":[{"text":"《多元的宇宙》"}],"B":[{"text":"《1/N 是地球》"}],"C":[{"text":"《宇宙是唯一的吗》"}],"D":[{"text":"《“平行宇宙”论》"}]},"annotatedStemRich":[{"text":"20世纪70年代，一些科学家提出了一种假设，即我们的"},{"text":"宇宙","underline":true},{"text":"⑥只不过是许多宇宙之一，它们都有着各自的物理学定律和错综复杂的结构，生命就在其中所有条件都恰好适宜的宇宙中出现(70年代提出假设)。到了80年代，现代宇宙学中的某些理论则证明，这样的“平行宇宙”的确可能存在(80年代理论证明)。近年来，英国科学家发现了另一个“宇宙”在我们的宇宙中留下的痕迹，他们认为有可能证明了多元宇宙的存在(近年痕迹证明)。⑦\n给这段文字加个标题，最为合适的一项是："}],"annotatedOptionRich":{"A":[{"text":"《多元的宇宙》 ( 片面 )"}],"B":[{"text":"《1/N 是地球》 (缺主体)"}],"C":[{"text":"《宇宙是唯一的吗》","bold":true}],"D":[{"text":"《“平行宇宙”","bold":true},{"text":"论》( 片面 )"}]},"practicalAnalysis":"文段分析见批注。\n文段通过三个不同时期的研究进展，表明或许宇宙不是唯一的，可看作历程类文段；C选项的“宇宙是唯一的吗”,既包含70年代科学家提出的假设，","notes":[{"marker":"⑦","content":"行文结构：大并列。\n文段通过清晰的时间轴依次介绍：\n①70年代提出假设：我们的宇宙是众多宇宙之一；\n②80年代通过理论证明“平行宇宙”可能存在；\n③近年通过发现痕迹证明“多元宇宙”可能存在。","matchScore":0.7614,"pairingMode":"marker-and-content","order":6}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300025,3,'细节判断类','亚马孙雨林有着“地球之肺”的美称。科学家估算，其每年所吸收的二氧化碳量占人类燃烧化石燃料所释放的二氧化碳总量的四分之一，因而在众多的气候预测模型中，都将亚马孙雨林的碳汇作用视为重要的影响因素。而最新研究认为，这些模型基于亚马孙雨林土壤中存在足够的磷营养供应这一假设，与现实状况并不相符。研究人员指出，亚马孙雨林生态系统已有数百万年的历史，如今，在亚马孙流域，许多地方的磷已经枯竭，这对植物吸收二氧化碳的能力造成很大影响。而过去的气候预测模型研究没有充分考虑到磷贫乏问题，因而其对亚马孙雨林的碳汇作用评估并不准确。
根据这段文字，下列说法正确的是：','[{"label":"A","content":"亚马孙雨林主要靠磷来吸收二氧化碳"},{"label":"B","content":"亚马孙雨林碳汇量并没有预期的那么高"},{"label":"C","content":"近年来亚马孙雨林的磷贫乏问题越来越严重"},{"label":"D","content":"现有气候预测模型大都高估了亚马孙雨林的影响力"}]','B','A选项，根据第③句的“这些模型基于亚马孙雨林土壤中存在足够的磷营养供应这一假设”可知，亚马孙雨林碳汇需要足够的磷，但不意味着“靠磷吸收二氧化碳”,⑧排除；
B选项，根据第④句的“在亚马孙流域许多地方的磷已经枯竭，这对植物吸收二氧化碳的能力造成很大影响”可知，亚马孙雨林碳汇量没有预期的高， B 当选；
C选项的“越来越严重”、D选项的“亚马孙雨林影响力”均为无中生有，排除C选项、D选项。

花生批注：
⑧ 例如：吃饱饭需要钱，不意味着“主要靠钱来吃食物”。','2019年新疆省考','进阶','published','{"globalNumber":25,"setNumber":2,"localNumber":5,"sourceLabel":"2019年新疆省考 51%","accuracy":51,"typeAndPassage":"细节判断类","stemRich":[{"text":"亚马孙雨林有着“地球之肺”的美称。科学家估算，其每年所吸收的二氧化碳量占人类燃烧化石燃料所释放的二氧化碳总量的四分之一，因而在众多的气候预测模型中，都将亚马孙雨林的碳汇作用视为重要的影响因素。而最新研究认为，这些模型基于亚马孙雨林土壤中存在足够的磷营养供应这一假设，与现实状况并不相符。研究人员指出，亚马孙雨林生态系统已有数百万年的历史，如今，在亚马孙流域，许多地方的磷已经枯竭，这对植物吸收二氧化碳的能力造成很大影响。而过去的气候预测模型研究没有充分考虑到磷贫乏问题，因而其对亚马孙雨林的碳汇作用评估并不准确。\n根据这段文字，下列说法正确的是："}],"optionRich":{"A":[{"text":"亚马孙雨林主要靠磷来吸收二氧化碳"}],"B":[{"text":"亚马孙雨林碳汇量并没有预期的那么高"}],"C":[{"text":"近年来亚马孙雨林的磷贫乏问题越来越严重"}],"D":[{"text":"现有气候预测模型大都高估了亚马孙雨林的影响力"}]},"annotatedStemRich":[{"text":"①亚马孙雨林有着“地球之肺”的美称。②科学家估算，其每年所吸收的二氧化碳量占人类燃烧化石燃料所释放的二氧化碳总量的四分之一，因而在众多的气候预测模型中，都将亚马孙雨林的碳汇作用视为重要的影响因素。③而最新研究认为，这些模型基于亚马孙雨林土壤中存在足够的磷营养供应这一假设( A 选项 ) ,与现实状况并不相符。④研究人员指出，亚马孙雨林生态系统已有数百万年的历史，如今，在亚马孙流域，许多地方的磷已经枯竭，这对植物吸收二氧化碳的能力造成很大影响( B 选项)。⑤而过去的气候预测模型研究没有充分考虑到磷贫乏问题，因而其对亚马孙雨林的碳汇作用评估并不准确。\n根据这段文字，下列说法正确的是："}],"annotatedOptionRich":{"A":[{"text":"亚马孙雨林主要靠磷来吸收二氧化碳(偷换概念)"}],"B":[{"text":"亚马孙雨林碳汇量并没有预期的那么高"}],"C":[{"text":"近年来亚马孙雨林的磷贫乏问题越来越严重(无中生有)"}],"D":[{"text":"现有气候预测模型大都高估了亚马孙雨林的影响力(无中生有)"}]},"practicalAnalysis":"A选项，根据第③句的“这些模型基于亚马孙雨林土壤中存在足够的磷营养供应这一假设”可知，亚马孙雨林碳汇需要足够的磷，但不意味着“靠磷吸收二氧化碳”,⑧排除；\nB选项，根据第④句的“在亚马孙流域许多地方的磷已经枯竭，这对植物吸收二氧化碳的能力造成很大影响”可知，亚马孙雨林碳汇量没有预期的高， B 当选；\nC选项的“越来越严重”、D选项的“亚马孙雨林影响力”均为无中生有，排除C选项、D选项。","notes":[{"marker":"⑧","content":"例如：吃饱饭需要钱，不意味着“主要靠钱来吃食物”。","matchScore":0.2363,"pairingMode":"marker-and-content","order":7}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300026,3,'中心理解题','国家是用边界围起来的政治实体，是国家政权行使权力的区域，可以看作是一种政治区划。但是这种边界围起的政治区划，只是国家的形式，并不是国家的本质，真正的国家是指边界之内的国民已经形成了一种“凝聚力”,这种凝聚力可以称之为“国家意识”,就是大家都在内心深处认为我是“某国人”。没有形成这种意识的国家，本质上还不能称为一个国家，是很不稳固的。真正的大国不仅在于领土大，人口多，关键在于其国民是否已经形成了“国家意识”,产生了“国家认同”。
这段话主要谈的是：','[{"label":"A","content":"国家的边界意识"},{"label":"B","content":"国家的本质属性"},{"label":"C","content":"国家认同的作用"},{"label":"D","content":"国家意识的内涵"}]','B','文段分析见批注。
文段结构较混乱，可简单翻译每句话再概括重点：①边界围起的政治区划只是国家的形式，并非国家的本质；②国家的本质(真正的国家)是形成“国家意识”;③没有“国家意识”,本质上不是国家；④“真正的大国”在于形成“国家意识”,产生“国家认同”。句句不离“国家的本质”,对应B选项，当选；
A选项杂糅，把“边界”和“国家意识”杂糅成“边界意识”,排除；C选项，最后一句话说的是“真正的大国关键在于产生了‘国家认同''”,强调的是“真正的大国(即本质上是一个国家或大国)需要有什么”,而非“国家认同”有什么作用；D选项，第②句话提及国家意识的内涵是为了说明“真正的国家需要有什么样的国家意识”.重点依然是“真正的国家(即本质上是一个国家) 需要有什么”,而非“国家意识的内涵”。⑪

花生批注：
⑩ 行文结构：前观点结构。
通过转折引出观点：
边界围起的政治区划只是国家的形式，不是国家的本质；边界之内形成“国家意识”才是真正的国家(即国家的本质是形成国家意识);
之后反面、正面论证(尾句也可看作重复观点):
没有形成“国家意识”,本质上不是国家；
真正的国家(本质上成为国家)在于形成“国家意识”, 产生“国家认同”。
已经形成了“国家意识”,产生了“国家认同”(分析论证)。⑩ 这段话主要谈的是：
A. 国家的边界意识 B. 国家的本质属性
C. 国家认同的作用 D. 国家意识的内涵
⑪ 文段反复提及国家意识，是为了说明“有了国家意识才是真正的国家”,可以说谈论的是“真正的国家是什么样的(即国家的本质属性)”, 也可以说谈论的是“国家意识的作用(有了国家意识能成为国家)”,但“国家意识的内涵”指的是“国家意识是什么”,未体现“国家意识与国家的关系”,因此， B选项更合适。','2017年四川省考','进阶','published','{"globalNumber":26,"setNumber":2,"localNumber":6,"sourceLabel":"2017年四川省考 47%","accuracy":47,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"国家是用边界围起来的政治实体，是国家政权行使权力的区域，可以看作是一种政治区划。但是这种边界围起的政治区划，只是国家的形式，并不是国家的本质，真正的国家是指边界之内的国民已经形成了一种“凝聚力”,这种凝聚力可以称之为“国家意识”,就是大家都在内心深处认为我是“某国人”。没有形成这种意识的国家，本质上还不能称为一个国家，是很不稳固的。真正的大国不仅在于领土大，人口多，关键在于其国民是否已经形成了“国家意识”,产生了“国家认同”。\n这段话主要谈的是："}],"optionRich":{"A":[{"text":"国家的边界意识"}],"B":[{"text":"国家的本质属性"}],"C":[{"text":"国家认同的作用"}],"D":[{"text":"国家意识的内涵"}]},"annotatedStemRich":[{"text":"①"},{"text":" 国家","underline":true},{"text":"⑨是用边界围起来的政治实体，是国家政权行使权力的区域，可以看作是一种政治区划。但是这种边界围起的政治区划，只是国家的形式，并不是国家的本质，②真正的国家是指边界之内的国民已经形成了一种“凝聚力”, 这种凝聚力可以称之为“国家意识”,就是大家都在内心深处认为我是“某国人”\n(转折引出观点)。③没有形成这种意识的国家，本质上还不能称为一个国家，是很不稳固的。④真正的大国不仅在于领土大，人口多，关键在于其国民是否\n已经形成了“国家意识”,产生了“国家认同”(分析论证)。⑩ 这段话主要谈的是："}],"annotatedOptionRich":{"A":[{"text":"国家的边界意识"}],"B":[{"text":"国家的本质属性"}],"C":[{"text":"国家认同的作用"}],"D":[{"text":"国家意识的内涵"}]},"practicalAnalysis":"文段分析见批注。\n文段结构较混乱，可简单翻译每句话再概括重点：①边界围起的政治区划只是国家的形式，并非国家的本质；②国家的本质(真正的国家)是形成“国家意识”;③没有“国家意识”,本质上不是国家；④“真正的大国”在于形成“国家意识”,产生“国家认同”。句句不离“国家的本质”,对应B选项，当选；\nA选项杂糅，把“边界”和“国家意识”杂糅成“边界意识”,排除；C选项，最后一句话说的是“真正的大国关键在于产生了‘国家认同''”,强调的是“真正的大国(即本质上是一个国家或大国)需要有什么”,而非“国家认同”有什么作用；D选项，第②句话提及国家意识的内涵是为了说明“真正的国家需要有什么样的国家意识”.重点依然是“真正的国家(即本质上是一个国家) 需要有什么”,而非“国家意识的内涵”。⑪","notes":[{"marker":"⑩","content":"行文结构：前观点结构。\n通过转折引出观点：\n边界围起的政治区划只是国家的形式，不是国家的本质；边界之内形成“国家意识”才是真正的国家(即国家的本质是形成国家意识);\n之后反面、正面论证(尾句也可看作重复观点):\n没有形成“国家意识”,本质上不是国家；\n真正的国家(本质上成为国家)在于形成“国家意识”, 产生“国家认同”。\n已经形成了“国家意识”,产生了“国家认同”(分析论证)。⑩ 这段话主要谈的是：\nA. 国家的边界意识 B. 国家的本质属性\nC. 国家认同的作用 D. 国家意识的内涵","matchScore":0.8711,"pairingMode":"marker-and-content","order":9},{"marker":"⑪","content":"文段反复提及国家意识，是为了说明“有了国家意识才是真正的国家”,可以说谈论的是“真正的国家是什么样的(即国家的本质属性)”, 也可以说谈论的是“国家意识的作用(有了国家意识能成为国家)”,但“国家意识的内涵”指的是“国家意识是什么”,未体现“国家意识与国家的关系”,因此， B选项更合适。","matchScore":0.5738,"pairingMode":"marker-and-content","order":10}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300027,3,'中心理解题','历史表明，中国抗日战争是世界反法西斯战争的重要组成部分，中国战场是世界反法西斯战争的东方主战场。确立“十四年抗战”,更能完整地审视中国抗日战争与世界反法西斯战争的密切关联，更能完整地体现中国人民为夺取世界反法西斯战争的胜利、维护世界正义与进步事业所付出的巨大牺牲和作出的重大贡献，更能完整地讲好“中国抗战故事”。
这段文字主要介绍了：','[{"label":"A","content":"确立“十四年抗战”的重要意义"},{"label":"B","content":"中国抗日战争发挥了非凡的作用"},{"label":"C","content":"如何完整讲好“中国抗战故事”"},{"label":"D","content":"中国抗日战争在世界反法西斯战争中的重要地位"}]','A','文段分析见批注。
文段介绍确立“十四年抗战”的重要意义， A选项概括了并列部分的主要内容，当选；

花生批注：
⑫ 行文结构：大并列结构。
先介绍背景：
抗日战争是世界反法西斯战争的重要部分和主战场；
再通过三个“更能”,强调确立十四年抗战的意义：
①有助于完整审视抗日战争与世界反法西斯战争的关联；
②有助于体现中国人民为反法西斯战争的胜利付出的牺牲和贡献；
③有助于完整讲好中国抗战故事。
片段阅读6 00 (上册)','2018年贵州省考','基础','published','{"globalNumber":27,"setNumber":2,"localNumber":7,"sourceLabel":"2018年贵州省考70%","accuracy":70,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"历史表明，中国抗日战争是世界反法西斯战争的重要组成部分，中国战场是世界反法西斯战争的东方主战场。确立“十四年抗战”,更能完整地审视中国抗日战争与世界反法西斯战争的密切关联，更能完整地体现中国人民为夺取世界反法西斯战争的胜利、维护世界正义与进步事业所付出的巨大牺牲和作出的重大贡献，更能完整地讲好“中国抗战故事”。\n这段文字主要介绍了："}],"optionRich":{"A":[{"text":"确立“十四年抗战”的重要意义"}],"B":[{"text":"中国抗日战争发挥了非凡的作用"}],"C":[{"text":"如何完整讲好“中国抗战故事”"}],"D":[{"text":"中国抗日战争在世界反法西斯战争中的重要地位"}]},"annotatedStemRich":[{"text":"历史表明，中国抗日战争是世界反法西斯战争的重要组成部分，中国战场是世界反法西斯战争的东方主战场(背景介绍)。确立“十四年抗战”,更能完整地审视中国抗日战争与世界反法西斯战争的密切关联( 意义 1 ) ,更能完整地体现中国人民为夺取世界反法西斯战争的胜利、维护世界正义与进步事业所付出的巨大牺牲和作出的重大贡献(意义 2 ) ,更能完整地讲好“中国抗战故事” (意义3)。②\n这段文字主要介绍了："}],"annotatedOptionRich":{"A":[{"text":"确立“十四年抗战”的重要意义"}],"B":[{"text":"中国抗日战争发挥了非凡的作用 (出处有误)"}],"C":[{"text":"如何完整讲好“中国抗战故事”( 片面 )"}],"D":[{"text":"中国抗日战争在世界反法西斯战争中的重要地位(出处有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段介绍确立“十四年抗战”的重要意义， A选项概括了并列部分的主要内容，当选；","notes":[{"marker":"⑫","content":"行文结构：大并列结构。\n先介绍背景：\n抗日战争是世界反法西斯战争的重要部分和主战场；\n再通过三个“更能”,强调确立十四年抗战的意义：\n①有助于完整审视抗日战争与世界反法西斯战争的关联；\n②有助于体现中国人民为反法西斯战争的胜利付出的牺牲和贡献；\n③有助于完整讲好中国抗战故事。\n片段阅读6 00 (上册)","matchScore":0.8593,"pairingMode":"content-similarity","order":11}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300028,3,'细节判断类','中国民间一直存在以争讼为耻的传统思想，且官方也存在无讼和恶讼思维，故民间水务纠纷若不是很严重的话，当事双方一般并不愿意对簿公堂，而是选择依靠地方士绅等乡村精英予以协调解决，争取做到“以和为贵”。因此，从水务纠纷的处理机制来看，中国古代主要存在两种解决模式。一方面，对于一般的民间水务纠纷，往往由士绅、渠长等地方精英依据乡约自行调处另一方面，对于情节严重，关涉较大的水务纠纷，可通过国家行政法律机制解决。
关于以上文字，下列理解错误的是：','[{"label":"A","content":"以争讼为耻辱是中国古代民间的传统思想"},{"label":"B","content":"乡约民规在古代民间的地位接近国家行政法律机制"},{"label":"C","content":"国家法律机制在古代民间水务纠纷处理中运用较少"},{"label":"D","content":"地方士绅是解决古代民间水务纠纷的重要力量"}]','B','“依据乡约自行调处”和“运用国家行政法律机制解决”是解决水务纠纷的两种模式，文段未比较二者地位， B选项属无中生有；而且根据常识可知：乡约民规地位不会接近国家行政法律机制，B选项本身有误，当选。

花生批注：
⑭ 根据“一般的民间水务纠纷，由地方士绅等依据乡约自行调处”可知，地方士绅是解决水务纠纷的重要力量。
⑮ 根据常识可知：情节严重、关涉较大的水务纠纷相对较少，即国家法律机制在古代民间水务纠纷处理中运用较少。
关于以上文字，下列理解错误的是：
A. 以争讼为耻辱是中国古代民间的传统思想
B. 乡约民规在古代民间的地位接近国家行政法律机制(区别比较联系类且本身有误)
C. 国家法律机制在古代民间水务纠纷处理中运用较少
D. 地方士绅是解决古代民间水务纠纷的重要力量','2019年黑龙江省考','基础','published','{"globalNumber":28,"setNumber":2,"localNumber":8,"sourceLabel":"2019年黑龙江省考 71%","accuracy":71,"typeAndPassage":"细节判断类","stemRich":[{"text":"中国民间一直存在以争讼为耻的传统思想，且官方也存在无讼和恶讼思维，故民间水务纠纷若不是很严重的话，当事双方一般并不愿意对簿公堂，而是选择依靠地方士绅等乡村精英予以协调解决，争取做到“以和为贵”。因此，从水务纠纷的处理机制来看，中国古代主要存在两种解决模式。一方面，对于一般的民间水务纠纷，往往由士绅、渠长等地方精英依据乡约自行调处另一方面，对于情节严重，关涉较大的水务纠纷，可通过国家行政法律机制解决。\n关于以上文字，下列理解错误的是："}],"optionRich":{"A":[{"text":"以争讼为耻辱是中国古代民间的传统思想"}],"B":[{"text":"乡约民规在古代民间的地位接近国家行政法律机制"}],"C":[{"text":"国家法律机制在古代民间水务纠纷处理中运用较少"}],"D":[{"text":"地方士绅是解决古代民间水务纠纷的重要力量"}]},"annotatedStemRich":[{"text":"中国民间一直存在以争讼为耻的传统思想 ( A 选项 ) ,且官方也存在无讼和恶讼思维，故民间水务纠纷若不是很严重的话，当事双方一般并不愿意对簿公堂，而是选择依靠地方士绅等乡村精英予以协调解决，争取做到“以和为贵”。因此，从水务纠纷的处理机制来看，中国古代主要存在两种解决模式。一方面，"},{"text":"对于一般的民间水务纠纷，往往由士绅、渠长等地方精英依据乡约自行调处(D","underline":true},{"text":" "},{"text":"选项)","underline":true},{"text":"⑨; "},{"text":" 另一方面，对于情节严重，关涉较大的水务纠纷，可通过国家行政法律机制解决(C选项)","underline":true},{"text":" ⑮。\n关于以上文字，下列理解错误的是："}],"annotatedOptionRich":{"A":[{"text":"以争讼为耻辱是中国古代民间的传统思想"}],"B":[{"text":"乡约民规在古代民间的地位接近国家行政法律机制(区别比较联系类且本身有误)"}],"C":[{"text":"国家法律机制在古代民间水务纠纷处理中运用较少"}],"D":[{"text":"地方士绅是解决古代民间水务纠纷的重要力量"}]},"practicalAnalysis":"“依据乡约自行调处”和“运用国家行政法律机制解决”是解决水务纠纷的两种模式，文段未比较二者地位， B选项属无中生有；而且根据常识可知：乡约民规地位不会接近国家行政法律机制，B选项本身有误，当选。","notes":[{"marker":"⑭","content":"根据“一般的民间水务纠纷，由地方士绅等依据乡约自行调处”可知，地方士绅是解决水务纠纷的重要力量。","matchScore":0.8101,"pairingMode":"content-similarity","order":13},{"marker":"⑮","content":"根据常识可知：情节严重、关涉较大的水务纠纷相对较少，即国家法律机制在古代民间水务纠纷处理中运用较少。\n关于以上文字，下列理解错误的是：\nA. 以争讼为耻辱是中国古代民间的传统思想\nB. 乡约民规在古代民间的地位接近国家行政法律机制(区别比较联系类且本身有误)\nC. 国家法律机制在古代民间水务纠纷处理中运用较少\nD. 地方士绅是解决古代民间水务纠纷的重要力量","matchScore":0.8445,"pairingMode":"marker-and-content","order":14}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300029,3,'中心理解题','在全社会共同努力下，我国脱贫攻坚取得决定性成就：贫困人口从2012年年底的9899万人减到 2019年年底的551万人，贫困发生率由10.2%降至0.6%,区域性整体贫困基本得到解决。这一伟大成就离不开科技的力量。新一轮扶贫攻坚实施以来，全国科技部门聚焦制约贫困地区发展的科技、
人才资源短缺两大短板，实施智力扶贫，以科技特派员为代表的广大科技人员积极投身脱贫攻坚主战场，将科研成果应用于扶贫事业，走出了科技扶贫、产业脱贫的新路径，成为“把论文写在大地上”的生动实践。
这段文字主要强调：','[{"label":"A","content":"区域性整体脱贫离不开科技"},{"label":"B","content":"科研成果是科技扶贫新路径"},{"label":"C","content":"脱贫攻坚已取得决定性成就"},{"label":"D","content":"人才资源是科技扶贫的保证"}]','A','文段分析见批注。
文段开篇给出观点：区域性整体贫困的解决离不开科技； A选项的问题、对策均正确，为完美选项，当选；
文段后半段具体介绍了科技在扶贫中的应用，包括科技人员投身扶贫主战场、科研成果应用于扶贫事业，分别对应D选项、B选项，这两个选项均片面且未提及“区域性整体脱贫”; C选项未提及对策，可简单排除。

花生批注：
⑯ 区域性整体脱贫是全文论述话题。
⑰ 行文结构：前对策结构。
开篇引出话题：区域性整体贫困基本得到解决；
再以必要条件(离不开)表对策：区域性整体脱贫离不开科技；
最后具体介绍“科技扶贫”。
在全社会共同努力下，我国脱贫攻坚取得决定性成就：贫困人口从2012 年年底的9899万人减到2019年年底的551万人，贫困发生率由10.2%降至0.6%, 区域性整体贫困基本得到解决(引出话题)。这一伟大成就离不开科技的力量(必要条件表对策)。新一轮扶贫攻坚实施以来，全国科技部门聚焦制约贫困地区发展的科技、人才资源短缺两大短板，实施智力扶贫，以科技特派员为代表的广大科技人员积极投身脱贫攻坚主战场，将科研成果应用于扶贫事业，走出了科技扶贫、产业脱贫的新路径，成为“把论文写在大地上”的生动实践( 具体介绍“科技扶贫”)。①
这段文字主要强调：
A. 区域性整体脱贫离不开科技
B. 科研成果是科技扶贫新路径(片面)
C. 脱贫攻坚已取得决定性成就(中性表达)
D. 人才资源是科技扶贫的保证(片面)','2020年福建省事业单位','进阶','published','{"globalNumber":29,"setNumber":2,"localNumber":9,"sourceLabel":"2020年福建省事业单位66%","accuracy":66,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"在全社会共同努力下，我国脱贫攻坚取得决定性成就：贫困人口从2012年年底的9899万人减到 2019年年底的551万人，贫困发生率由10.2%降至0.6%,区域性整体贫困基本得到解决。这一伟大成就离不开科技的力量。新一轮扶贫攻坚实施以来，全国科技部门聚焦制约贫困地区发展的科技、\n人才资源短缺两大短板，实施智力扶贫，以科技特派员为代表的广大科技人员积极投身脱贫攻坚主战场，将科研成果应用于扶贫事业，走出了科技扶贫、产业脱贫的新路径，成为“把论文写在大地上”的生动实践。\n这段文字主要强调："}],"optionRich":{"A":[{"text":"区域性整体脱贫离不开科技"}],"B":[{"text":"科研成果是科技扶贫新路径"}],"C":[{"text":"脱贫攻坚已取得决定性成就"}],"D":[{"text":"人才资源是科技扶贫的保证"}]},"annotatedStemRich":[{"text":"在全社会共同努力下，我国脱贫攻坚取得决定性成就：贫困人口从2012 年年底的9899万人减到2019年年底的551万人，贫困发生率由10.2%降至0.6%, "},{"text":"区域性整体贫困","underline":true},{"text":"基本得到解决(引出话题)。这一伟大成就离不开科技的力量(必要条件表对策)。新一轮扶贫攻坚实施以来，全国科技部门聚焦制约贫困地区发展的科技、人才资源短缺两大短板，实施智力扶贫，以科技特派员为代表的广大科技人员积极投身脱贫攻坚主战场，将科研成果应用于扶贫事业，走出了科技扶贫、产业脱贫的新路径，成为“把论文写在大地上”的生动实践( 具体介绍“科技扶贫”)。①\n这段文字主要强调："}],"annotatedOptionRich":{"A":[{"text":"区域性整体脱贫离不开科技"}],"B":[{"text":"科研成果是科技扶贫新路径(片面)"}],"C":[{"text":"脱贫攻坚已取得决定性成就(中性表达)"}],"D":[{"text":"人才资源是科技扶贫的保证(片面)"}]},"practicalAnalysis":"文段分析见批注。\n文段开篇给出观点：区域性整体贫困的解决离不开科技； A选项的问题、对策均正确，为完美选项，当选；\n文段后半段具体介绍了科技在扶贫中的应用，包括科技人员投身扶贫主战场、科研成果应用于扶贫事业，分别对应D选项、B选项，这两个选项均片面且未提及“区域性整体脱贫”; C选项未提及对策，可简单排除。","notes":[{"marker":"⑯","content":"区域性整体脱贫是全文论述话题。","matchScore":0.571,"pairingMode":"content-similarity","order":15},{"marker":"⑰","content":"行文结构：前对策结构。\n开篇引出话题：区域性整体贫困基本得到解决；\n再以必要条件(离不开)表对策：区域性整体脱贫离不开科技；\n最后具体介绍“科技扶贫”。\n在全社会共同努力下，我国脱贫攻坚取得决定性成就：贫困人口从2012 年年底的9899万人减到2019年年底的551万人，贫困发生率由10.2%降至0.6%, 区域性整体贫困基本得到解决(引出话题)。这一伟大成就离不开科技的力量(必要条件表对策)。新一轮扶贫攻坚实施以来，全国科技部门聚焦制约贫困地区发展的科技、人才资源短缺两大短板，实施智力扶贫，以科技特派员为代表的广大科技人员积极投身脱贫攻坚主战场，将科研成果应用于扶贫事业，走出了科技扶贫、产业脱贫的新路径，成为“把论文写在大地上”的生动实践( 具体介绍“科技扶贫”)。①\n这段文字主要强调：\nA. 区域性整体脱贫离不开科技\nB. 科研成果是科技扶贫新路径(片面)\nC. 脱贫攻坚已取得决定性成就(中性表达)\nD. 人才资源是科技扶贫的保证(片面)","matchScore":1.3139,"pairingMode":"content-similarity","order":16}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300030,3,'语句填入类','。20世纪建筑材料与修建技术往往不同于古代传统技艺，必须研究和开发符合不同修建类型的专门修复手段，不仅要保存有代表性的原材料，也要重视针对20世纪材料老化的详细调查。马德里文件强调：重建一个完全消失的遗产地或者某个部分并不是保护的行为。作为历史的见证，一个遗产地的文化价值主要基于它原真的或重要的材料特征。在可持续予以重视的当下，文化价值不能因采用节能措施、智能等新技术而遭受负面冲击。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"20 世纪建筑遗产有其真实性与完整性"},{"label":"B","content":"20 世纪建筑遗产保护离不开技术层面及文化层面的综合把控"},{"label":"C","content":"保护20世纪遗产与保护古代遗产有同等重要的价值"},{"label":"D","content":"建筑遗产的价值不仅存在于物质层面还在于其文化意义"}]','B','所填入语句位于文段开端，考虑概括下文；观察选项可知，选项均为“A且B”类型.猜测文段结构为总分.所填入语句的两部分和下文要一一对应；⑱B选项的“技术层面及文化层面”与文段正一一对应，当选；
A选项的“真实性和完整性”和D选项的“物质层面”均无中生有，排除； C选项是区别比较联系类，文段并非将20世纪遗产和古代遗产进行对比，排除。

花生批注：
⑬ 另一方面，C选项是对策类选项，文段并非提出问题，也不应选择对策类选项。
B选项和D选项均出自文段背景部分，不是文段重点，均可直接排除； C选项“完整讲好中国抗战故事”仅对应文末三个并列意义中的一个，片面，排除。
⑱ 此题可从选项入手，判断能否用选项的“A 、B”两部分概括文段的两部分，比自己概括要快速、简单。
④ 四大类：
①原因类选项：大篇幅谈原因
②历程类：具有清晰时间轴
③区别比较联系类：双主语且篇幅相当
④具体类：可具体概括出“小点”','2018年广西选调','进阶','published','{"globalNumber":30,"setNumber":2,"localNumber":10,"sourceLabel":"2018年广西选调 62%","accuracy":62,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"。20世纪建筑材料与修建技术往往不同于古代传统技艺，必须研究和开发符合不同修建类型的专门修复手段，不仅要保存有代表性的原材料，也要重视针对20世纪材料老化的详细调查。马德里文件强调：重建一个完全消失的遗产地或者某个部分并不是保护的行为。作为历史的见证，一个遗产地的文化价值主要基于它原真的或重要的材料特征。在可持续予以重视的当下，文化价值不能因采用节能措施、智能等新技术而遭受负面冲击。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"20 世纪建筑遗产有其真实性与完整性"}],"B":[{"text":"20 世纪建筑遗产保护离不开技术层面及文化层面的综合把控"}],"C":[{"text":"保护20世纪遗产与保护古代遗产有同等重要的价值"}],"D":[{"text":"建筑遗产的价值不仅存在于物质层面还在于其文化意义"}]},"annotatedStemRich":[{"text":" ","underline":true},{"text":" 。20世纪建筑材料与修建技术往往不同于古代传统技艺，必须研究和开发符合不同修建类型的专门修复手段，不仅要保存有代表性的原材料，也要重视针对20世纪材料老化的详细调查。马德里文件强调：重建一个完全消失的遗产地或者某个部分并不是保护的行为(介绍20世纪建筑保护需要专门修复手段)。作为历史的见证，一个遗产地的文化价值主要基于它原真的或重要的材料特征。在可持续予以重视的当下，文化价值不能因采用节能措施、智能等新技术而遭受负面冲击(介绍遗产地的文化价值要予以保护)。\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"20 世纪建筑遗产有其真实性与完整性(无中生有)"}],"B":[{"text":"20 世纪建筑遗产保护离不开技术层面及文化层面的综合把控( A 且B 类选项)"}],"C":[{"text":"保护20世纪遗产与保护古代遗产有同等重要的价值(区别比较联系类)"}],"D":[{"text":"建筑遗产的价值不仅存在于物质层面还在于其文化意义(无中生有)"}]},"practicalAnalysis":"所填入语句位于文段开端，考虑概括下文；观察选项可知，选项均为“A且B”类型.猜测文段结构为总分.所填入语句的两部分和下文要一一对应；⑱B选项的“技术层面及文化层面”与文段正一一对应，当选；\nA选项的“真实性和完整性”和D选项的“物质层面”均无中生有，排除； C选项是区别比较联系类，文段并非将20世纪遗产和古代遗产进行对比，排除。","notes":[{"marker":"⑬","content":"另一方面，C选项是对策类选项，文段并非提出问题，也不应选择对策类选项。\nB选项和D选项均出自文段背景部分，不是文段重点，均可直接排除； C选项“完整讲好中国抗战故事”仅对应文末三个并列意义中的一个，片面，排除。","matchScore":0.3085,"pairingMode":"content-similarity","order":12},{"marker":"⑱","content":"此题可从选项入手，判断能否用选项的“A 、B”两部分概括文段的两部分，比自己概括要快速、简单。","matchScore":0.2545,"pairingMode":"marker-and-content","order":17},{"marker":"④","content":"四大类：\n①原因类选项：大篇幅谈原因\n②历程类：具有清晰时间轴\n③区别比较联系类：双主语且篇幅相当\n④具体类：可具体概括出“小点”","matchScore":0.2281,"pairingMode":"content-similarity","order":39}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300031,3,'语句填入类','与国外相比，我国景区生存经营还普遍存在“门票依赖”的情况。适时推动景区门票价格降低，虽然会在短时间内影响景区门票收入，但是从中长期来看却能带来客流量的增长。这时，如果景区把握住机会，提供更多满足游客需要的产品和服务，就会实现更大的经济收益。从这个意义上来说，
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"降低门票价格是未来景区发展的必然趋势"},{"label":"B","content":"景区门票降价有助于促进民众、景区、商家共赢"},{"label":"C","content":"配套服务业水平对旅游消费体验的影响比票价更大"},{"label":"D","content":"要在更广范围内、更大程度上降低相关景区门票价格"}]','B','所填入语句在文末，可猜测其是对上文的概括总结。
文段开门见山提出“我国景区‘门票依赖’”的问题，之后分析景区门票价格降低的好处，即“能带来客流量的增长，实现更大的经济收益”,文末应总结门票降价的意义；
A选项的“必然趋势”过于绝对且与事实不符，未来景区发展不一定要降低门票，排除；
B选项，根据上文可知从长期看门票降价有利于景区，根据常识可知门票降价有利于民众，根据逻辑可知客流量增加也有利于景区商家②;综上，景区门票降价确实有助于“三赢”,逻辑正确，当选；
C选项，原文谈论的是景区门票降价问题，而非比较“服务”与“门票”的影响大小，排除；
D选项的“要在更广范围内、更大程度上降低门票价格”无中生有，排除。

花生批注：
⑲ 若上文依次介绍了“提高配套服务水平”和“降低门票价格”带来的影响，才可以选择C选项。
② 各景区情况不同，高价景区可能需要降低门票，低价景区可能需要通过提高票价来提高服务和基础设施建设，不能说“门票降价就是景区发展的必然趋势”。
② 有同学可能认为B选项的商家是无中生有，但提到商家并不违背常识与行文逻辑，与其他选项更严重的问题相比，完全可以接受。
④3 若D 当选，对应文段应为科普介绍类文段，即介绍“发呆概念及具有的意义”。
