INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300038,3,'中心理解题','当前我国城市建设面临经济发展与产业结构调整、环境保护、社会治理模式、民生保障等多方面矛盾，建设智慧城市是大势所趋。我国在智慧城市的很多应用方面已经走在了世界前列，像网约车、共享单车等。但也存在一些问题，如顶层设计不足、缺乏体系性规划与创新等。另外，智慧城市建设有许多方面没有考虑到与市民切身相关的问题，市民的感知度并不明显。如何把城市建设和市民利益结合起来，注意群众需求，是推进智慧城市建设、解决智慧城市落地问题的关键。
这段文字意在强调：','[{"label":"A","content":"我国智慧城市建设已走在世界前列"},{"label":"B","content":"智慧城市建设面临许多综合性问题"},{"label":"C","content":"建设智慧城市可以解决城市建设诸多矛盾"},{"label":"D","content":"建设智慧城市要接地气与群众需求相联系"}]','D','文段分析见批注。
文段对策句可翻译为：推进智慧城市建设应把城市建设和市民利益结合起来，注意群众需求； D选项为原文对策的同义替换，当选。
A选项出自分析论证部分的转折之前，出处有误，排除；B选项为问题表述，原文有对策应选择对策，排除；C选项出自首句引出话题部分，出处有误，排除。

花生批注：
⑥ “宇宙”是全文论述主体。
⑨ “国家”是全文论述话题。
对这一问题的回答，也对应了后文的研究过程；并且用问题做标题更有吸引力， C选项当选；
A选项和D选项均只对应某一时期提出的理论，表述片面，未体现整个过程，而且二者为同质选项，可一起排除；B选项未体现论述主体“宇宙”,排除。
2 相对贫困问题是全文论述话题。
6 《诗经》是全文论述主体。
36 “建设智慧城市”是全文论述话题。
③ 行文结构：后对策结构。
开篇引出话题：建设智慧城市是大势所趋；
再转折提出问题；
最后通过必要条件给出对策：
建设智慧城市的关键是注意群众需求。
当前我国城市建设面临经济发展与产业结构调整、环境保护、社会治理模式、民生保障等多方面矛盾，建设智慧城市③是大势所趋 (引出话题)。我国在智慧城市的很多应用方面已经走在了世界前列，像网约车、共享单车等。但也存在一些问题，如顶层设计不足、缺乏体系性规划与创新等。另外，智慧城市建设有许多方面没有考虑到与市民切身相关的问题，市民的感知度并不明显 (转折提出问题)。如何把城市建设和市民利益结合起来，注意群众需求，是推进智慧城市建设、解决智慧城市落地问题的关键(后对策)。⑨
这段文字意在强调：
A. 我国智慧城市建设已走在世界前列(出处有误)
B. 智慧城市建设面临许多综合性问题(问题表述)
C. 建设智慧城市可以解决城市建设诸多矛盾(中性表述)
D. 建设智慧城市要接地气与群众需求相联系
④ ①“必须……”为对策表述，为原文对策句的同义替换；
② B选项问题正确，即“思绪太多有风险”对应文段提出问题部分；对策也正确，
“必须时不时发发呆”对应给出对策部分。','2018年黑龙江省考','基础','published','{"globalNumber":38,"setNumber":2,"localNumber":18,"sourceLabel":"2018年黑龙江省考 77%","accuracy":77,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"当前我国城市建设面临经济发展与产业结构调整、环境保护、社会治理模式、民生保障等多方面矛盾，建设智慧城市是大势所趋。我国在智慧城市的很多应用方面已经走在了世界前列，像网约车、共享单车等。但也存在一些问题，如顶层设计不足、缺乏体系性规划与创新等。另外，智慧城市建设有许多方面没有考虑到与市民切身相关的问题，市民的感知度并不明显。如何把城市建设和市民利益结合起来，注意群众需求，是推进智慧城市建设、解决智慧城市落地问题的关键。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"我国智慧城市建设已走在世界前列"}],"B":[{"text":"智慧城市建设面临许多综合性问题"}],"C":[{"text":"建设智慧城市可以解决城市建设诸多矛盾"}],"D":[{"text":"建设智慧城市要接地气与群众需求相联系"}]},"annotatedStemRich":[{"text":"36花生批注：\n“建设智慧城市”是全文论述话题。\n③花生批注：\n"},{"text":"行文结构：","bold":true},{"text":"后对策结构。\n开篇引出话题：建设智慧城市是大势所趋；\n"},{"text":"再转折提出问题；","bold":true},{"text":"\n最后通过必要条件给出对策：\n建设智慧城市的关键是注意群众需求。\n当前我国城市建设面临经济发展与产业结构调整、环境保护、社会治理模式、民生保障等多方面矛盾，"},{"text":"建设智慧城市","underline":true},{"text":"③是大势所趋 (引出话题)。我国在智慧城市的很多应用方面已经走在了世界前列，像网约车、共享单车等。但也存在一些问题，如顶层设计不足、缺乏体系性规划与创新等。另外，智慧城市建设有许多方面没有考虑到与市民切身相关的问题，市民的感知度并不明显 (转折提出问题)。如何把城市建设和市民利益结合起来，注意群众需求，是推进智慧城市建设、解决智慧城市落地问题的关键(后对策)。⑨\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"我国智慧城市建设已走在世界前列(出处有误)"}],"B":[{"text":"智慧城市建设面临许多综合性问题(问题表述)"}],"C":[{"text":"建设智慧城市可以解决城市建设诸多矛盾(中性表述)"}],"D":[{"text":"建设智慧城市要接地气与群众需求相联系"}]},"practicalAnalysis":"文段分析见批注。\n文段对策句可翻译为：推进智慧城市建设应把城市建设和市民利益结合起来，注意群众需求； D选项为原文对策的同义替换，当选。\nA选项出自分析论证部分的转折之前，出处有误，排除；B选项为问题表述，原文有对策应选择对策，排除；C选项出自首句引出话题部分，出处有误，排除。","notes":[{"marker":"⑥","content":"“宇宙”是全文论述主体。","matchScore":0.5188,"pairingMode":"content-similarity","order":5},{"marker":"⑨","content":"“国家”是全文论述话题。\n对这一问题的回答，也对应了后文的研究过程；并且用问题做标题更有吸引力， C选项当选；\nA选项和D选项均只对应某一时期提出的理论，表述片面，未体现整个过程，而且二者为同质选项，可一起排除；B选项未体现论述主体“宇宙”,排除。","matchScore":0.2889,"pairingMode":"marker-and-content","order":8},{"marker":"2","content":"相对贫困问题是全文论述话题。","matchScore":0.6052,"pairingMode":"content-similarity","order":21},{"marker":"6","content":"《诗经》是全文论述主体。","matchScore":0.5188,"pairingMode":"content-similarity","order":25},{"marker":"36","content":"“建设智慧城市”是全文论述话题。","matchScore":1.0406,"pairingMode":"content-similarity","order":35},{"marker":"③","content":"行文结构：后对策结构。\n开篇引出话题：建设智慧城市是大势所趋；\n再转折提出问题；\n最后通过必要条件给出对策：\n建设智慧城市的关键是注意群众需求。\n当前我国城市建设面临经济发展与产业结构调整、环境保护、社会治理模式、民生保障等多方面矛盾，建设智慧城市③是大势所趋 (引出话题)。我国在智慧城市的很多应用方面已经走在了世界前列，像网约车、共享单车等。但也存在一些问题，如顶层设计不足、缺乏体系性规划与创新等。另外，智慧城市建设有许多方面没有考虑到与市民切身相关的问题，市民的感知度并不明显 (转折提出问题)。如何把城市建设和市民利益结合起来，注意群众需求，是推进智慧城市建设、解决智慧城市落地问题的关键(后对策)。⑨\n这段文字意在强调：\nA. 我国智慧城市建设已走在世界前列(出处有误)\nB. 智慧城市建设面临许多综合性问题(问题表述)\nC. 建设智慧城市可以解决城市建设诸多矛盾(中性表述)\nD. 建设智慧城市要接地气与群众需求相联系","matchScore":1.553,"pairingMode":"marker-and-content","order":36},{"marker":"④","content":"①“必须……”为对策表述，为原文对策句的同义替换；\n② B选项问题正确，即“思绪太多有风险”对应文段提出问题部分；对策也正确，\n“必须时不时发发呆”对应给出对策部分。","matchScore":0.4388,"pairingMode":"content-similarity","order":40}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300039,3,'中心理解题','守护好儿童健康就是守护好全民健康的基础。一方面，要“破”。“有抑郁症?会不会伤害我?”尽管人们对心理健康有了越来越多的认识，但污名化的影子仍在。这不仅让一些家长对孩子的心理健康问题“讳疾忌医”,也阻碍了孩子在遭遇心理困扰时寻求帮助。因此，有必要全力消除心理健康的污名化。另一方面，要“立”。《健康中国行动——儿童青少年心理健康行动方案(2019～2022 年)》已提出，将儿童心理健康纳入家庭教育指导，这是很好的路径。要随着家庭教育指导的深入，
帮助不同年龄段儿童的家长正确认识孩子的心理发育规律，学会与孩子沟通、交流，做好源头预防。这段文字意在强调：','[{"label":"A","content":"对于儿童健康，人们容易陷入“重身体而轻心理”的误区"},{"label":"B","content":"要让全社会正确认识儿童心理健康问题，树立“身心健康同样重要”的意识"},{"label":"C","content":"要不断完善儿童心理健康问题干预体系"},{"label":"D","content":"守护儿童心理健康是一项系统工程，需要学校、家庭和社会共同的努力"}]','B','文段分析见批注。
文段引出“儿童健康”这一话题后，依次给出了两个对策，分别是“破”与“立”: “破”指的是破除家长对于儿童心理健康的错误认识，正对应B选项的“要让全社会正确认识儿童心理健康问题(破除错误认识，即要正确认识)”; “立”指的是将儿童心理健康纳入家庭教育指导，帮助家长正确认识儿童心理发育规律，即树立关注儿童心理健康的意识，正对应B选项的“树立‘身心健康同样重要’的意识”; B选项可看作“A 且 B”类选项，当选；
本题A选项为问题表述，未提及对策；C选项的“干预体系”和D选项的“学校家庭社会”均为无中生有，文段未提及相关内容，可简单排除。

花生批注：
38 行文结构：并列对策。
开篇引出话题：守护好儿童健康；
依次给出两个对策：
对策1:“破”,破除对心理健康的错误认识；
对策2:“立”,树立关注儿童心理健康的意识。','2023年福建省事业单位','进阶','published','{"globalNumber":39,"setNumber":2,"localNumber":19,"sourceLabel":"2023年福建省事业单位 50%","accuracy":50,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"守护好儿童健康就是守护好全民健康的基础。一方面，要“破”。“有抑郁症?会不会伤害我?”尽管人们对心理健康有了越来越多的认识，但污名化的影子仍在。这不仅让一些家长对孩子的心理健康问题“讳疾忌医”,也阻碍了孩子在遭遇心理困扰时寻求帮助。因此，有必要全力消除心理健康的污名化。另一方面，要“立”。《健康中国行动——儿童青少年心理健康行动方案(2019～2022 年)》已提出，将儿童心理健康纳入家庭教育指导，这是很好的路径。要随着家庭教育指导的深入，\n帮助不同年龄段儿童的家长正确认识孩子的心理发育规律，学会与孩子沟通、交流，做好源头预防。这段文字意在强调："}],"optionRich":{"A":[{"text":"对于儿童健康，人们容易陷入“重身体而轻心理”的误区"}],"B":[{"text":"要让全社会正确认识儿童心理健康问题，树立“身心健康同样重要”的意识"}],"C":[{"text":"要不断完善儿童心理健康问题干预体系"}],"D":[{"text":"守护儿童心理健康是一项系统工程，需要学校、家庭和社会共同的努力"}]},"annotatedStemRich":[{"text":"守护好儿童健康就是守护好全民健康的基础(引出话题)。一方面，要“破”。“有抑郁症?会不会伤害我?”尽管人们对心理健康有了越来越多的认识，但污名化的影子仍在。这不仅让一些家长对孩子的心理健康问题“讳疾忌医”, 也阻碍了孩子在遭遇心理困扰时寻求帮助。因此，有必要全力消除心理健康的污名化(对策1)。另一方面，要“立”。《健康中国行动——儿童青少年心理健康行动方案(2019～2022年)》已提出，将儿童心理健康纳入家庭教育指导，这是很好的路径。要随着家庭教育指导的深入，帮助不同年龄段儿童的家长正确认识孩子的心理发育规律，学会与孩子沟通、交流，做好源头预防( 对策 2 ) 。\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"对于儿童健康，人们容易陷入“重身体而轻心理”的误区(问题表述)"}],"B":[{"text":"要让全社会正确认识儿童心理健康问题，树立“身心健康同样重要”的意识"}],"C":[{"text":"要不断完善儿童心理健康问题干预体系(无中生有)"}],"D":[{"text":"守护儿童心理健康是一项系统工程，需要学校、家庭和社会共同的努力 (无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段引出“儿童健康”这一话题后，依次给出了两个对策，分别是“破”与“立”: “破”指的是破除家长对于儿童心理健康的错误认识，正对应B选项的“要让全社会正确认识儿童心理健康问题(破除错误认识，即要正确认识)”; “立”指的是将儿童心理健康纳入家庭教育指导，帮助家长正确认识儿童心理发育规律，即树立关注儿童心理健康的意识，正对应B选项的“树立‘身心健康同样重要’的意识”; B选项可看作“A 且 B”类选项，当选；\n本题A选项为问题表述，未提及对策；C选项的“干预体系”和D选项的“学校家庭社会”均为无中生有，文段未提及相关内容，可简单排除。","notes":[{"marker":"38","content":"行文结构：并列对策。\n开篇引出话题：守护好儿童健康；\n依次给出两个对策：\n对策1:“破”,破除对心理健康的错误认识；\n对策2:“立”,树立关注儿童心理健康的意识。","matchScore":0.7442,"pairingMode":"content-similarity","order":37}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300040,3,'中心理解题','发呆是跟思绪相对应的。人发呆的时候，脑子里没有思绪，是一种活在当下、沉浸在现实中的感受。而思绪关注的则是过去和未来。思绪太多，人就会逐渐失去与真实世界的联系，陷入各种情绪中。这时候，需要适时地断一断电，关掉思绪，把注意力拉回到现实，重新和这个真实世界建立联系。
这段文字意在强调：','[{"label":"A","content":"思绪是胡思乱想，发呆才是关注当下"},{"label":"B","content":"思绪太多有风险，必须时不时发发呆"},{"label":"C","content":"发呆能有效对抗那些不切实际的幻想"},{"label":"D","content":"发呆即活在当下，它具有现实的意义"}]','B','文段分析见批注。
文段为典型后对策结构，文段通过祈使句“需要……”给出对策，对策句可翻译为“当思绪过多时，需要适时发呆、关掉思绪”,B选项为完美选项，
当选。
A选项，区别比较联系类选项⑫,原文有对策优先选对策，排除；C选项的“对抗那些不切实际的幻想”,无中生有，排除； D选项为中性表述⑤,原文有对策优先选对策，排除。

花生批注：
5 例如：想要减肥，可以跑步。要解决的问题是“减肥”, 对策为“跑步”,后者是对策重点。
B选项：可以跑步；
D选项：减肥是健康的途径 (可翻译为“想健康可以减肥”)。
A选项、C选项均是对相对贫困问题进行分析，未谈及对策，可看作中性表达②排除；
B选项从对策句提炼，针对“相对贫困问题”,要形成“多层次资源支援和保障”,问题、对策均正确的完美选项，当选；
D选项⑤是强干扰项，可翻译为“扶贫需要解决相对贫困”,问题是“扶贫”, 对策是“解决相对贫困”,与文中问题、对策不一致，错误。
③⑨ 行文结构：后对策结构。
开篇引出话题：
介绍发呆与思绪的关系；
再提出问题：
思绪太多会陷入各种情绪中；
最后以祈使句给出对策：
需要适时发呆，关掉思绪。
④② 若A当选，文段类型应为科普介绍类，即介绍“思绪”与“发呆”的区别且两者篇幅相当。','2018年贵州选调','进阶','published','{"globalNumber":40,"setNumber":2,"localNumber":20,"sourceLabel":"2018年贵州选调 48%","accuracy":48,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"发呆是跟思绪相对应的。人发呆的时候，脑子里没有思绪，是一种活在当下、沉浸在现实中的感受。而思绪关注的则是过去和未来。思绪太多，人就会逐渐失去与真实世界的联系，陷入各种情绪中。这时候，需要适时地断一断电，关掉思绪，把注意力拉回到现实，重新和这个真实世界建立联系。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"思绪是胡思乱想，发呆才是关注当下"}],"B":[{"text":"思绪太多有风险，必须时不时发发呆"}],"C":[{"text":"发呆能有效对抗那些不切实际的幻想"}],"D":[{"text":"发呆即活在当下，它具有现实的意义"}]},"annotatedStemRich":[{"text":"发呆是跟思绪相对应的(引出话题)。人发呆的时候，脑子里没有思绪，是一种活在当下、沉浸在现实中的感受。而思绪关注的则是过去和未来。思绪太多，人就会逐渐失去与真实世界的联系，陷入各种情绪中(提出并分析问题)。这时候，需要适时地断一断电，关掉思绪，把注意力拉回到现实，重新和这个\n真实世界建立联系(后对策)。⑨\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"思绪是胡思乱想，发呆才是关注当下"},{"text":"(区别比较联系类选项)","underline":true}],"B":[{"text":"思绪太多有风险，必须时不时发发呆"}],"C":[{"text":"发呆能有效对抗那些不切实际的幻想(无中生有)"}],"D":[{"text":"发呆即活在当下，它具有现实的意义(中性表述)"}]},"practicalAnalysis":"文段分析见批注。\n文段为典型后对策结构，文段通过祈使句“需要……”给出对策，对策句可翻译为“当思绪过多时，需要适时发呆、关掉思绪”,B选项为完美选项，\n当选。\nA选项，区别比较联系类选项⑫,原文有对策优先选对策，排除；C选项的“对抗那些不切实际的幻想”,无中生有，排除； D选项为中性表述⑤,原文有对策优先选对策，排除。","notes":[{"marker":"5","content":"例如：想要减肥，可以跑步。要解决的问题是“减肥”, 对策为“跑步”,后者是对策重点。\nB选项：可以跑步；\nD选项：减肥是健康的途径 (可翻译为“想健康可以减肥”)。\nA选项、C选项均是对相对贫困问题进行分析，未谈及对策，可看作中性表达②排除；\nB选项从对策句提炼，针对“相对贫困问题”,要形成“多层次资源支援和保障”,问题、对策均正确的完美选项，当选；\nD选项⑤是强干扰项，可翻译为“扶贫需要解决相对贫困”,问题是“扶贫”, 对策是“解决相对贫困”,与文中问题、对策不一致，错误。","matchScore":0.2651,"pairingMode":"marker-and-content","order":24},{"marker":"③⑨","content":"行文结构：后对策结构。\n开篇引出话题：\n介绍发呆与思绪的关系；\n再提出问题：\n思绪太多会陷入各种情绪中；\n最后以祈使句给出对策：\n需要适时发呆，关掉思绪。","matchScore":0.7132,"pairingMode":"content-similarity","order":38},{"marker":"④②","content":"若A当选，文段类型应为科普介绍类，即介绍“思绪”与“发呆”的区别且两者篇幅相当。","matchScore":0.2351,"pairingMode":"content-similarity","order":41}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300041,3,'中心理解题','区块链是信息分布式存储的记账系统，其最大特色在于能够在没有信任基础的网络环境中不依赖中心平台的信任背书建立信任关系，其实际应用是从作为虚拟货币的比特币开始的。但是，区块链技术的应用又不仅仅限于虚拟货币。目前，在金融监管、数据共享、互联网等领域，在互联网金融、银行、保险、供应链金融、清结算中心等多个场景，区块链技术都有一定程度的应用。如果此时还只将区块链等同于虚拟货币并拿来炒作，不是认识上存在偏颇，就是为了炒作而故意扭曲。
这段文字意在强调：','[{"label":"A","content":"区块链有助于建立社会信用管理系统"},{"label":"B","content":"区块链技术在市场中已得到广泛应用"},{"label":"C","content":"将区块链技术等同于虚拟货币是错误的"},{"label":"D","content":"区块链技术的潜在价值有待进一步挖掘"}]','C','文段分析见批注。
文段通过转折引出观点：区块链技术的应用不仅仅限于虚拟货币；在分析论证后又重复观点：将区块链等同于虚拟货币是错误的； C选项是观点的同义替换，当选；
A选项的“社会信用管理系统”、D选项的“潜在价值”都是无中生有，可简单排除；
B选项出自文段分析论证部分，出处有误；而且介绍区块链技术已经在很多领域有所应用，是为了论证“区块链技术的应用不仅仅限于虚拟货币”,而非为了介绍其应用广泛，排除。

花生批注：
① 行文结构：前观点结构。
先转折提出观点：区块链技术的应用又不仅仅限于虚拟货币；
再对此观点进行解释说明；并在尾句强调观点：只将区块链等同于虚拟货币并拿来炒作是错误的。','2019年浙江省考','基础','published','{"globalNumber":41,"setNumber":3,"localNumber":1,"sourceLabel":"2019年浙江省考 70%","accuracy":70,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"区块链是信息分布式存储的记账系统，其最大特色在于能够在没有信任基础的网络环境中不依赖中心平台的信任背书建立信任关系，其实际应用是从作为虚拟货币的比特币开始的。但是，区块链技术的应用又不仅仅限于虚拟货币。目前，在金融监管、数据共享、互联网等领域，在互联网金融、银行、保险、供应链金融、清结算中心等多个场景，区块链技术都有一定程度的应用。如果此时还只将区块链等同于虚拟货币并拿来炒作，不是认识上存在偏颇，就是为了炒作而故意扭曲。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"区块链有助于建立社会信用管理系统"}],"B":[{"text":"区块链技术在市场中已得到广泛应用"}],"C":[{"text":"将区块链技术等同于虚拟货币是错误的"}],"D":[{"text":"区块链技术的潜在价值有待进一步挖掘"}]},"annotatedStemRich":[{"text":"区块链是信息分布式存储的记账系统，其最大特色在于能够在没有信任基础的网络环境中不依赖中心平台的信任背书建立信任关系，其实际应用是从作为虚拟货币的比特币开始的。但是，区块链技术的应用又不仅仅限于虚拟货币 (转折提出观点)。目前，在金融监管、数据共享、互联网等领域，在互联网金融、银行、保险、供应链金融、清结算中心等多个场景，区块链技术都有一定程度的应用。如果此时还只将区块链等同于虚拟货币并拿来炒作，不是认识上存在\n偏颇，就是为了炒作而故意扭曲(分析论证+重复观点)。① 这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"区块链有助于建立社会信用管理系统 (无中生有)"}],"B":[{"text":"区块链技术在市场中已得到广泛应用 (出处有误)"}],"C":[{"text":"将区块链技术等同于虚拟货币是错误的"}],"D":[{"text":"区块链技术的潜在价值有待进一步挖掘 (无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段通过转折引出观点：区块链技术的应用不仅仅限于虚拟货币；在分析论证后又重复观点：将区块链等同于虚拟货币是错误的； C选项是观点的同义替换，当选；\nA选项的“社会信用管理系统”、D选项的“潜在价值”都是无中生有，可简单排除；\nB选项出自文段分析论证部分，出处有误；而且介绍区块链技术已经在很多领域有所应用，是为了论证“区块链技术的应用不仅仅限于虚拟货币”,而非为了介绍其应用广泛，排除。","notes":[{"marker":"①","content":"行文结构：前观点结构。\n先转折提出观点：区块链技术的应用又不仅仅限于虚拟货币；\n再对此观点进行解释说明；并在尾句强调观点：只将区块链等同于虚拟货币并拿来炒作是错误的。","matchScore":0.7112,"pairingMode":"marker-and-content","order":0}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300042,3,'中心理解题','老人们承担“责任重、风险高”的带娃压力，本质是生育成本过高导致的结果，有一定的必然性。它与不少家庭不敢生二孩，其实是同一问题的一体两面。加快优化生育成本的社会分担机制，解除更多家庭在养育孩子上的后顾之忧，才是“解放”老人，缓解社会生育焦虑的要诀。
这段文字意在强调：','[{"label":"A","content":"国家和社会应承担更多的生育成本"},{"label":"B","content":"“二孩时代”的老人不堪重负，亟需“解放”"},{"label":"C","content":"生育成本过高导致“二孩”政策效用不大"},{"label":"D","content":"育儿观念的代际隔阂日益突显，代际矛盾日益突出"}]','A','文段分析见批注。
文段在提出并分析老人承担带娃压力这一问题后，给出了对策，对策可翻译为：要想解放老人、缓解社会生育焦虑需要加快优化生育成本的社会分担机制，解决养育孩子的后顾之忧。对策的重点是“加快优化生育成本的社会分担机制”,对应A选项，当选；
B选项可翻译为：老人承担的带娃压力需要解放，“解放”成了对策重点，与文末对策不一致，排除；
C选项、D选项均非对策表述，可简单排除。

花生批注：
② 行文结构：后对策结构。
文段开篇提出：“老人承担带娃压力”这一问题，并加以分析；
文末给出对策：加快优化生育成本的社会分担机制，解除更多家庭在养育孩子上的后顾之忧，才是“解放”老人，缓解社会生育焦虑的要诀。','2018年江西法检','基础','published','{"globalNumber":42,"setNumber":3,"localNumber":2,"sourceLabel":"2018年江西法检73%","accuracy":73,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"老人们承担“责任重、风险高”的带娃压力，本质是生育成本过高导致的结果，有一定的必然性。它与不少家庭不敢生二孩，其实是同一问题的一体两面。加快优化生育成本的社会分担机制，解除更多家庭在养育孩子上的后顾之忧，才是“解放”老人，缓解社会生育焦虑的要诀。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"国家和社会应承担更多的生育成本"}],"B":[{"text":"“二孩时代”的老人不堪重负，亟需“解放”"}],"C":[{"text":"生育成本过高导致“二孩”政策效用不大"}],"D":[{"text":"育儿观念的代际隔阂日益突显，代际矛盾日益突出"}]},"annotatedStemRich":[{"text":"老人们承担“责任重、风险高”的带娃压力，本质是生育成本过高导致的结果，有一定的必然性。它与不少家庭不敢生二孩，其实是同一问题的一体两面(提出并分析问题)。加快优化生育成本的社会分担机制，解除更多家庭在养育孩子上的后顾之忧，才是“解放”老人，缓解社会生育焦虑的要诀(逻辑关联词表对策)。②\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"国家和社会应承担更多的生育成本"}],"B":[{"text":"“二孩时代”的老人不堪重负，亟需“解放”(表述空泛)"}],"C":[{"text":"生育成本过高导致“二孩”政策效用不大(问题表述)"}],"D":[{"text":"育儿观念的代际隔阂日益突显，代际矛盾日益突出(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段在提出并分析老人承担带娃压力这一问题后，给出了对策，对策可翻译为：要想解放老人、缓解社会生育焦虑需要加快优化生育成本的社会分担机制，解决养育孩子的后顾之忧。对策的重点是“加快优化生育成本的社会分担机制”,对应A选项，当选；\nB选项可翻译为：老人承担的带娃压力需要解放，“解放”成了对策重点，与文末对策不一致，排除；\nC选项、D选项均非对策表述，可简单排除。","notes":[{"marker":"②","content":"行文结构：后对策结构。\n文段开篇提出：“老人承担带娃压力”这一问题，并加以分析；\n文末给出对策：加快优化生育成本的社会分担机制，解除更多家庭在养育孩子上的后顾之忧，才是“解放”老人，缓解社会生育焦虑的要诀。","matchScore":1.0125,"pairingMode":"marker-and-content","order":1}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300043,3,'语句填入类','在时空关系上，摄影和舞蹈是两种截然不同的艺术表现形式。舞蹈中的舞者并非如摄影作品中所呈现的那样，在空间中摆出某个单一、特定的造型，。舞者根据舞蹈情节及个人情绪从空间中的一个位置运动到另一个位置，而摄影能够记录的只是舞者舞动的精彩瞬间，
但这个瞬间只是舞蹈在时空中的一个切片。舞蹈如同音乐一般，本身是一个绵延的过程；欣赏舞蹈如同欣赏交响乐，欣赏者面对的是完整的旋律，而非其中的某个音符。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"而是全情投入到对舞蹈情感的诠释之中"},{"label":"B","content":"而是处于一种不断运动的舞蹈过程之中"},{"label":"C","content":"而是伴随音乐的律动做出特定舞蹈动作"},{"label":"D","content":"而是在动与静的交替中传达舞蹈的神韵"}]','B','文章分析见批注。
所填入语句为“不是…而是…”句式，注意“不是”和“而是”部分的转折关系；
舞蹈中的舞者不是如摄影中的“在空间中摆出单一、特定的造型”,则舞蹈中的舞者是“不单一、不特定的造型”,即“处于一种不断运动的舞蹈过程中”, B选项正确；
其他选项均无法体现舞蹈动作的连贯性，无法和“单一、特定造型”形成转折；而且A选项的“情感诠释”、D选项的“舞蹈神韵”均无中生有。

花生批注：
④ 此句也有提示：舞蹈是延绵的过程。
⑤ 行文结构：总分结构。
开篇给出总观点：摄影和舞蹈不同；
下文具体介绍：摄影和舞蹈的不同。
在时空关系上，摄影和舞蹈是两种截然不同的艺术表现形式(总观点)。舞蹈中的舞者并非如摄影作品中所呈现的那样，在空间中摆出某个单一、特定
。舞者根据舞蹈情节及个人情绪从空间中的一个位置运动到另一个位置，而摄影能够记录的只是舞者舞动的精彩瞬间，但这个瞬间只是舞蹈在时空中的一个切片。舞蹈如同音乐一般，本身是一个绵延的过程；欣赏舞蹈如同欣赏交响乐，欣赏者面对的是完整的旋律，而非其中的某个音符(具体分析)。
填入文中画横线部分最恰当的一项是：
A. 而是全情投入到对舞蹈情感的诠释之中
B. 而是处于一种不断运动的舞蹈过程之中
C. 而是伴随音乐的律动做出特定舞蹈动作
D. 而是在动与静的交替中传达舞蹈的神韵
