INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300044,3,'细节判断类','有研究显示，让试验对象每天摄入50克黑巧克力，15天后，这些人不仅血糖值有所下降，而且血液中的好胆固醇浓度增加了20%,坏胆固醇浓度减少了20%,摄入同样的量的白巧克力的人却未能收获同样的健康益处。有趣的是，人们常常担心巧克力受热融化后所含的抗氧化物质活性消失，但在试验中，即便是那些化掉之后重新凝固、外表看起来十分不体面的“陈年巧克力”,依然拥有强大的抗氧化能力，对试验对象的血糖和血脂控制有益。
以下无法从上述文字得知的是：','[{"label":"A","content":"黑巧克力的血糖控制效果比白巧克力更好"},{"label":"B","content":"白巧克力无法改善血液中的胆固醇浓度"},{"label":"C","content":"巧克力中抗氧化物质的活性受热后不会完全消失"},{"label":"D","content":"黑巧克力的抗氧化能力有助于血糖的控制"}]','B','根据第①句的“摄入黑巧克力的试验对象血糖值有所下降，但摄入同样量的白巧克力却未能收获同样的健康益处⑥”可知，“黑巧克力的血糖控制效果优于白巧克力”,A选项正确；但却无法得知“白巧克力对于改善胆固醇浓度毫无效果”,B选项一定无法得知，当选；
C选项，根据原文第②句的“受热后重新凝固的‘陈年巧克力’,依然拥有强大的抗氧化能力”,可以得知；
D选项，根据原文第②句可以得知“不仅是正常巧克力，即使是陈年巧克力也有抗氧化能力，对实验对象的血糖控制有益”,黑巧克力属于巧克力，黑巧克力当然也有抗氧化能力且对血糖控制有益⑦,可以得知。

花生批注：
⑥ 例如：A与B 一样努力，但却未收获同样效果。
常规思维理解应是：
A 虽然和B 一样努力，收获却小于B。
但无法推出A 的努力毫无收获。
⑦ 可能有同学质疑：
一定是抗氧化能力有助于血糖的控制吗?
二者之间关系原文确实没有明确表示，但对比B、D选项； B选项一定无法推知且违背正常逻辑；
D选项可能推知且未违背正常逻辑；
B选项更可能是正确答案。注：较难的细节判断经常存在这样的选项设置，一个选项犯了严重的、违背常规逻辑的错误，一个选项稍有“过度”推断但符合常理，此时一定“抓大放小”。
A. 黑巧克力的血糖控制效果比白巧克力更好
B. 白巧克力无法改善血液中的胆固醇浓度
C. 巧克力中抗氧化物质的活性受热后不会完全消失
D. 黑巧克力的抗氧化能力有助于血糖的控制','2019年黑龙江省考','进阶','published','{"globalNumber":44,"setNumber":3,"localNumber":4,"sourceLabel":"2019年黑龙江省考 63%","accuracy":63,"typeAndPassage":"细节判断类","stemRich":[{"text":"有研究显示，让试验对象每天摄入50克黑巧克力，15天后，这些人不仅血糖值有所下降，而且血液中的好胆固醇浓度增加了20%,坏胆固醇浓度减少了20%,摄入同样的量的白巧克力的人却未能收获同样的健康益处。有趣的是，人们常常担心巧克力受热融化后所含的抗氧化物质活性消失，但在试验中，即便是那些化掉之后重新凝固、外表看起来十分不体面的“陈年巧克力”,依然拥有强大的抗氧化能力，对试验对象的血糖和血脂控制有益。\n以下无法从上述文字得知的是："}],"optionRich":{"A":[{"text":"黑巧克力的血糖控制效果比白巧克力更好"}],"B":[{"text":"白巧克力无法改善血液中的胆固醇浓度"}],"C":[{"text":"巧克力中抗氧化物质的活性受热后不会完全消失"}],"D":[{"text":"黑巧克力的抗氧化能力有助于血糖的控制"}]},"annotatedStemRich":[{"text":"①有研究显示，让试验对象每天摄入50克黑巧克力，15天后，这些人不仅血糖值有所下降，而且血液中的好胆固醇浓度增加了20%,坏胆固醇浓度减少了20%,摄入同样的量的白巧克力的人却未能收获同样的健康益处( A 选项)。\n②有趣的是，人们常常担心巧克力受热融化后所含的抗氧化物质活性消失，但在试验中，即便是那些化掉之后重新凝固、外表看起来十分不体面的“陈年巧克力”,依然拥有强大的抗氧化能力( B 选项 ) ,对试验对象的血糖和血脂控制有益( D 选项)。\n以下无法从上述文字得知的是："}],"annotatedOptionRich":{"A":[{"text":"黑巧克力的血糖控制效果比白巧克力更好"}],"B":[{"text":"白巧克力无法改善血液中的胆固醇浓度"}],"C":[{"text":"巧克力中抗氧化物质的活性受热后不会完全消失"}],"D":[{"text":"黑巧克力的抗氧化能力有助于血糖的控制"}]},"practicalAnalysis":"根据第①句的“摄入黑巧克力的试验对象血糖值有所下降，但摄入同样量的白巧克力却未能收获同样的健康益处⑥”可知，“黑巧克力的血糖控制效果优于白巧克力”,A选项正确；但却无法得知“白巧克力对于改善胆固醇浓度毫无效果”,B选项一定无法得知，当选；\nC选项，根据原文第②句的“受热后重新凝固的‘陈年巧克力’,依然拥有强大的抗氧化能力”,可以得知；\nD选项，根据原文第②句可以得知“不仅是正常巧克力，即使是陈年巧克力也有抗氧化能力，对实验对象的血糖控制有益”,黑巧克力属于巧克力，黑巧克力当然也有抗氧化能力且对血糖控制有益⑦,可以得知。","notes":[{"marker":"⑥","content":"例如：A与B 一样努力，但却未收获同样效果。\n常规思维理解应是：\nA 虽然和B 一样努力，收获却小于B。\n但无法推出A 的努力毫无收获。","matchScore":0.2356,"pairingMode":"marker-and-content","order":5},{"marker":"⑦","content":"可能有同学质疑：\n一定是抗氧化能力有助于血糖的控制吗?\n二者之间关系原文确实没有明确表示，但对比B、D选项； B选项一定无法推知且违背正常逻辑；\nD选项可能推知且未违背正常逻辑；\nB选项更可能是正确答案。注：较难的细节判断经常存在这样的选项设置，一个选项犯了严重的、违背常规逻辑的错误，一个选项稍有“过度”推断但符合常理，此时一定“抓大放小”。\nA. 黑巧克力的血糖控制效果比白巧克力更好\nB. 白巧克力无法改善血液中的胆固醇浓度\nC. 巧克力中抗氧化物质的活性受热后不会完全消失\nD. 黑巧克力的抗氧化能力有助于血糖的控制","matchScore":0.407,"pairingMode":"marker-and-content","order":6}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300045,3,'细节判断类','随着历史的发展，人类对世界的了解越来越少。虽然看上去大多数人都明白牛顿经典力学，也多少知道爱因斯坦相对论，但是有多少人知道拉链是怎么做出来的，原材料是什么,原理是什么。别说消费者，就是工厂里的熟练工人也不清楚，因为他们只用完成好自己的那一道工序就好。反观我们的祖先，对自己周遭环境是了如指掌，对自己的午饭从哪里来也很清楚。人类群体智慧的知识错觉让人们以为自己懂得很多，不用去操心那些无知的事。这有好处，去寻找所有的真相最需要的就是时间，这势必会耽误人们工作、学习、奋斗。
根据文段内容，下列推断最准确的是：','[{"label":"A","content":"寻找真相比生存要花更多时间"},{"label":"B","content":"熟练工人更了解拉链生产过程"},{"label":"C","content":"经典力学比相对论更容易理解"},{"label":"D","content":"我们的祖先比我们更了解彼时周遭世界"}]','D','A选项，文段第⑥句提到了“寻找真相需要时间”,即了解或懂得这个世界的一些事情本质(拉链是怎么做出来的、自己的午饭是从哪里来的等等)是需要时间的，但并未将寻找真相所需时间和生存时间进行比较，二者也无法比较，排除；
B选项，文段第②③句提到“熟练工人也只知道自己的那一道工序，并不清楚拉链的原理”,本身有误；
C选项，文段第②句提到经典力学和相对论，但并无难易比较，无中生有；
D选项，根据文段第④句的“反观我们的祖先，对自己周遭环境(即身边世界)是了如指掌的”和第①句的“随着历史的发展，人类对世界的了解越来越少”可知，我们的祖先比我们更了解彼时周遭的世界，当选。

花生批注：
⑧ 根据常识可知人类群体对整个世界的了解会越来越多，再根据下文“人类群体智慧的知识错觉让人们以为自己懂得很多”,可知，这句话应理解为，现在的人们对自己身边的世界了解的越来越少。
我们的祖先熟悉周边的世界，知道如何获得午饭，知道如何建造房屋等；但现在的人们，拉链如何制作、原材料是什么等身边的事情，也不熟悉了。
⑨ 海外经典翻拍剧是全文论述主体。
⑩ 行文结构：前观点结构。
开篇直接给出观点：海外经典翻拍剧不会成为国内影视剧市场主流；
后文进行分析论证：原作品成功是因为其民族性，但各国民族性不同，因此不会在国内同样成功。
①随着历史的发展，人类对世界的了解越来越少⑧。②虽然看上去大多数人都明白牛顿经典力学，也多少知道爱因斯坦相对论( C选项 ) ,但是有多少人知道拉链是怎么做出来的，原材料是什么,原理是什么。③别说消费者，就是工厂里的熟练工人也不清楚，因为他们只用完成好自己的那一道工序就好( B选项)。④反观我们的祖先，对自己周遭环境是了如指掌，对自己的午饭从哪里来也很清楚( D选项)。⑤人类群体智慧的知识错觉让人们以为自己懂得很多，不用去操心那些无知的事。⑥这有好处，去寻找所有的真相最需要的就是时间，这势必会耽误人们工作、学习、奋斗( A选项)。
根据文段内容，下列推断最准确的是：
A. 寻找真相比生存要花更多时间
B. 熟练工人更了解拉链生产过程
C. 经典力学比相对论更容易理解
D. 我们的祖先比我们更了解彼时周遭世界
