INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300052,3,'中心理解题','目前，我国影视外译活动丰富多彩，国家赞助体系下的影视翻译将影视作品的外译和传播推到了前所未有的广度和高度。商业翻译更加注重影视作品的商业属性，主要依据供求关系对影视作品进行翻译，有助于满足需求。影迷翻译可以成为国家赞助体系下的影视外译和商业外译的有益补充。这些不同的翻译模式，共同促进中国影视的跨境传播，将更多的中国影视佳作带给世界。
这段文字重在说明的是：','[{"label":"A","content":"我国影视外译的基本模式"},{"label":"B","content":"我国影视外译的多元发展"},{"label":"C","content":"不同翻译模式对中国影视境外传播的作用"},{"label":"D","content":"不同翻译模式所对应的不同文化传播主体"}]','C','文段分析见批注。
文段依次介绍了不同翻译模式的作用：国家影视翻译将影视作品的外译和传播推到前所未有的广度和高度、商业翻译满足需求、影迷翻译是有益补充，并在文末做了概括。对应C选项，当选；
A选项、B选项、D选项，均未提及不同翻译模式的作用，均可简单排除。

花生批注：
④ 翻译模式是文段论述主体。
25 行文结构：分总结构。
文段依次介绍国家赞助体系下的影视翻译、商业翻译、影迷翻译的不同作用；
文末用“这些”概括总结。
目前，我国影视外译活动丰富多彩，国家赞助体系下的影视翻译将影视作品的外译和传播推到了前所未有的广度和高度(分 1 ) 。商业翻译更加注重影视作品的商业属性，主要依据供求关系对影视作品进行翻译，有助于满足需求 ( 分 2 ) 。影迷翻译可以成为国家赞助体系下的影视外译和商业外译的有益补充( 分 3 ) 。这些不同的翻译模式②,共同促进中国影视的跨境传播，将更多的中国影视佳作带给世界(总)。⑤
这段文字重在说明的是：
A. 我国影视外译的基本模式
B. 我国影视外译的多元发展
C. 不同翻译模式对中国影视境外传播的作用
D. 不同翻译模式所对应的不同文化传播主体
S四IHA海IGO公NGK考AO 练习题03套','2021年江苏省事业单位','进阶','published','{"globalNumber":52,"setNumber":3,"localNumber":12,"sourceLabel":"2021年江苏省事业单位 64%","accuracy":64,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"目前，我国影视外译活动丰富多彩，国家赞助体系下的影视翻译将影视作品的外译和传播推到了前所未有的广度和高度。商业翻译更加注重影视作品的商业属性，主要依据供求关系对影视作品进行翻译，有助于满足需求。影迷翻译可以成为国家赞助体系下的影视外译和商业外译的有益补充。这些不同的翻译模式，共同促进中国影视的跨境传播，将更多的中国影视佳作带给世界。\n这段文字重在说明的是："}],"optionRich":{"A":[{"text":"我国影视外译的基本模式"}],"B":[{"text":"我国影视外译的多元发展"}],"C":[{"text":"不同翻译模式对中国影视境外传播的作用"}],"D":[{"text":"不同翻译模式所对应的不同文化传播主体"}]},"annotatedStemRich":[{"text":"④花生批注：\n翻译模式是文段论述主体。\n25花生批注：\n行文结构：分总结构。\n文段依次介绍国家赞助体系下的影视翻译、商业翻译、影迷翻译的不同作用；\n文末用“这些”概括总结。\n目前，我国影视外译活动丰富多彩，国家赞助体系下的影视翻译将影视作品的外译和传播推到了前所未有的广度和高度(分 1 ) 。商业翻译更加注重影视作品的商业属性，主要依据供求关系对影视作品进行翻译，有助于满足需求 ( 分 2 ) 。影迷翻译可以成为国家赞助体系下的影视外译和商业外译的有益补充( 分 3 ) 。这些不同的"},{"text":"翻译模式","underline":true},{"text":"②,共同促进中国影视的跨境传播，将更多的中国影视佳作带给世界(总)。⑤\n这段文字重在说明的是："}],"annotatedOptionRich":{"A":[{"text":"我国影视外译的基本模式"}],"B":[{"text":"我国影视外译的多元发展"}],"C":[{"text":"不同翻译模式对中国影视境外传播的作用"}],"D":[{"text":"不同翻译模式所对应的不同文化传播主体\n"},{"text":"S四IHA海IGO公NGK考AO ","bold":true},{"text":"练习题03套"}]},"practicalAnalysis":"文段分析见批注。\n文段依次介绍了不同翻译模式的作用：国家影视翻译将影视作品的外译和传播推到前所未有的广度和高度、商业翻译满足需求、影迷翻译是有益补充，并在文末做了概括。对应C选项，当选；\nA选项、B选项、D选项，均未提及不同翻译模式的作用，均可简单排除。","notes":[{"marker":"④","content":"翻译模式是文段论述主体。","matchScore":1.0404,"pairingMode":"marker-and-content","order":23},{"marker":"25","content":"行文结构：分总结构。\n文段依次介绍国家赞助体系下的影视翻译、商业翻译、影迷翻译的不同作用；\n文末用“这些”概括总结。\n目前，我国影视外译活动丰富多彩，国家赞助体系下的影视翻译将影视作品的外译和传播推到了前所未有的广度和高度(分 1 ) 。商业翻译更加注重影视作品的商业属性，主要依据供求关系对影视作品进行翻译，有助于满足需求 ( 分 2 ) 。影迷翻译可以成为国家赞助体系下的影视外译和商业外译的有益补充( 分 3 ) 。这些不同的翻译模式②,共同促进中国影视的跨境传播，将更多的中国影视佳作带给世界(总)。⑤\n这段文字重在说明的是：\nA. 我国影视外译的基本模式\nB. 我国影视外译的多元发展\nC. 不同翻译模式对中国影视境外传播的作用\nD. 不同翻译模式所对应的不同文化传播主体\nS四IHA海IGO公NGK考AO 练习题03套","matchScore":1.5671,"pairingMode":"content-similarity","order":24}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300053,3,'语句填入类','“草原丝路”的得名显然源于对地貌特征的概括，其主要路径是从中原出发向北至漠北蒙古草原折而西行，再经欧亚草原地带直达欧洲，尽管途中也有非草原景观的荒漠和半荒漠地貌类型，但其主体为欧亚草原地带。欧亚草原东西延伸呈连续带状分布，西起多瑙河下游，向东依次为东欧平原、西西伯利亚平原、哈萨克丘陵、蒙古高原，直至中国东北松辽平原，东西绵延近110个经度，是地球上最宽广的草原带，在地形和地貌上堪称畅通无阻的天然通衢，为东西方交通提供便利。草原丝路主干线分布于北纬40～50度之间的欧亚草原地带，
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"冠以“草原”,可谓名副其实"},{"label":"B","content":"丝绸是草原丝路的重要输出品"},{"label":"C","content":"“草原丝路”是丝路概念广义化的结果"},{"label":"D","content":"地貌特征是划分不同“丝绸之路”的主要依据"}]','A','文段分析见批注。
文段开篇开门见山给出总论点：草原丝路得名来自地貌特征；之后对地貌特征做了具体介绍，文末所填入语句也应谈论相同话题；若填入A选项，构成总分总结构，首尾句呼应②,逻辑正确；
B选项的“重要输出品丝绸”、C选项的“丝路概念广义化”、D选项的“划分不同‘丝绸之路’”均属无中生有，可简单排除。

