INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300054,3,'中心理解题','从生命现象发生以来，极端微生物在地球生物圈中早已存在，只是由于生产和科学技术的局限，直到19世纪末，人们才逐渐在生活和生产实践中认识到这一特殊的生命群体。从接近沸点的温泉、海底火山口、寒冷的南北极区、盐湖、酸碱泉到高寒及高压的深海环境，无处不活跃着极端微生物的身影。上述语段所表达的主旨是：','[{"label":"A","content":"极端微生物可在极限环境中保持顽强的生命力"},{"label":"B","content":"极端微生物为人类提供了探索生命极限的线索"},{"label":"C","content":"极端微生物可能是最古老的生命类群"},{"label":"D","content":"人们对极端微生物的认识还远远不够"}]','A','文段只有两句话，简单翻译即可：①19世纪末人们才认识存在已久的极端微生物；②极端微生物可在各种极端环境生存；只有A选项体现极端微生物在极端环境生存的特点，当选②;

花生批注：
28 极端微生物为全文论述主体。
上述语段所表达的主旨是：
A. 极端微生物可在极限环境中保持顽强的生命力
B. 极端微生物为人类提供了探索生命极限的线索 (无中生有)
C. 极端微生物可能是最古老的生命类群(绝对化)
2 文段在引出极端微生物后，仅介绍了极端微生物可在极端环境生存的这一特点，为科普介绍文章，正确选项应突出极端微生物的特点。
原文仅为介绍极端微生物， B选项的“为人类提供线索”、 D选项的“人类认识远远不够”均为无中生有；C选项的“可能是最古老生命类群”无中生有，均可简单排除。','2017年福建省事业单位','挑战','published','{"globalNumber":54,"setNumber":3,"localNumber":14,"sourceLabel":"2017年福建省事业单位40%","accuracy":40,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"从生命现象发生以来，极端微生物在地球生物圈中早已存在，只是由于生产和科学技术的局限，直到19世纪末，人们才逐渐在生活和生产实践中认识到这一特殊的生命群体。从接近沸点的温泉、海底火山口、寒冷的南北极区、盐湖、酸碱泉到高寒及高压的深海环境，无处不活跃着极端微生物的身影。上述语段所表达的主旨是："}],"optionRich":{"A":[{"text":"极端微生物可在极限环境中保持顽强的生命力"}],"B":[{"text":"极端微生物为人类提供了探索生命极限的线索"}],"C":[{"text":"极端微生物可能是最古老的生命类群"}],"D":[{"text":"人们对极端微生物的认识还远远不够"}]},"annotatedStemRich":[{"text":"①从生命现象发生以来， "},{"text":" 极端微生物","underline":true},{"text":"在地球生物圈中早已存在，只是由于生产和科学技术的局限，直到19世纪末，人们才逐渐在生活和生产实践中认识到这一特殊的生命群体(引出极端微生物)。 ②从接近沸点的温泉、海底火山口、寒冷的南北极区、盐湖、酸碱泉到高寒及高压的深海环境，无处不活跃着极端微生物的身影(介绍极端微生物特征)。\n上述语段所表达的主旨是："}],"annotatedOptionRich":{"A":[{"text":"极端微生物可在极限环境中保持顽强的生命力"}],"B":[{"text":"极端微生物为人类提供了探索生命极限的线索 (无中生有)"}],"C":[{"text":"极端微生物可能是最古老的生命类群(绝对化)"}],"D":[{"text":"人们对极端微生物的认识还远远不够(无中生有)"}]},"practicalAnalysis":"文段只有两句话，简单翻译即可：①19世纪末人们才认识存在已久的极端微生物；②极端微生物可在各种极端环境生存；只有A选项体现极端微生物在极端环境生存的特点，当选②;","notes":[{"marker":"28","content":"极端微生物为全文论述主体。\n上述语段所表达的主旨是：\nA. 极端微生物可在极限环境中保持顽强的生命力\nB. 极端微生物为人类提供了探索生命极限的线索 (无中生有)\nC. 极端微生物可能是最古老的生命类群(绝对化)","matchScore":0.4884,"pairingMode":"content-similarity","order":27},{"marker":"2","content":"文段在引出极端微生物后，仅介绍了极端微生物可在极端环境生存的这一特点，为科普介绍文章，正确选项应突出极端微生物的特点。\n原文仅为介绍极端微生物， B选项的“为人类提供线索”、 D选项的“人类认识远远不够”均为无中生有；C选项的“可能是最古老生命类群”无中生有，均可简单排除。","matchScore":0.4666,"pairingMode":"marker-and-content","order":28}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300055,3,'中心理解题','田野是儿童心灵向往的世界，是符合其天性生长的土壤。在早期的学习与生长中，儿童拥有自己的“内部教师”。从生物发生律看，儿童的生活是对远古祖先生活活动的浓缩与再现。远古祖先的早期生活是对自然环境与生物秩序的认识，由此发明出一套合乎人类社会的知识价值体系。幼儿重演这个阶段，意味着他们也要经历认识自然世界这个阶段，在此基础上探究和重构人类世界的自然法则与内部秩序。
这段文字意在说明：','[{"label":"A","content":"童年是对人类认知历程的再现"},{"label":"B","content":"田野生活符合儿童的成长天性"},{"label":"C","content":"幼儿在成长过程中需要自主学习"},{"label":"D","content":"儿童的世界是与自然相通的世界"}]','B','文段分析见批注。
文段可看作前观点结构，开门见山直接给出观点：田野是符合儿童天性生长的土壤，后文是对观点的解释说明；B选项是首句观点的同义替换⑨,当选；
其他选项均未提及“田野”,且A选项的“人类认知历程”、B选项的“需要自主学习”、 D选项的“儿童世界与自然相通”均属无中生有。

花生批注：
③ 后文解释说明的逻辑如下：儿童有自己成长的规律，成长规律是对祖先生活的重现，祖先是摸索自然和生物 (即田野)构建知识体系，儿童重演“祖先摸索田野”来认识世界。
A. 童年是对人类认知历程的再现(无中生有)
B. 田野生活符合儿童的成长天性
C. 幼儿在成长过程中需要自主学习(无中生有)
D. 儿童的世界是与自然相通的世界(无中生有)
32 实战思维：
类似“户外活动可以有效预防近视的发生”一题，可通过揣测原文作者意图来确定答案，即使没看懂后文的解释，但文段首句提到“田野”,可猜测原文可能是让儿童多亲近田野(原文标题《乡村园应用好用足“田野资源”》),即文段结构为前观点结构，先给出观点再加以解释，因此选择B选项。','2019年四川选调','挑战','published','{"globalNumber":55,"setNumber":3,"localNumber":15,"sourceLabel":"2019年四川选调 35%","accuracy":35,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"田野是儿童心灵向往的世界，是符合其天性生长的土壤。在早期的学习与生长中，儿童拥有自己的“内部教师”。从生物发生律看，儿童的生活是对远古祖先生活活动的浓缩与再现。远古祖先的早期生活是对自然环境与生物秩序的认识，由此发明出一套合乎人类社会的知识价值体系。幼儿重演这个阶段，意味着他们也要经历认识自然世界这个阶段，在此基础上探究和重构人类世界的自然法则与内部秩序。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"童年是对人类认知历程的再现"}],"B":[{"text":"田野生活符合儿童的成长天性"}],"C":[{"text":"幼儿在成长过程中需要自主学习"}],"D":[{"text":"儿童的世界是与自然相通的世界"}]},"annotatedStemRich":[{"text":"田野","underline":true},{"text":"是儿童心灵向往的世界，是符合其天性生长的土壤(前观点)。在早期的学习与生长中，儿童拥有自己的“内部教师”。从生物发生律看，儿童的生活是对远古祖先生活活动的浓缩与再现。远古祖先的早期生活是对自然环境与生物秩序的认识，由此发明出一套合乎人类社会的知识价值体系。幼儿重演这个阶段，意味着他们也要经历认识自然世界这个阶段，在此基础上探究和重构人类世界的自然法则与内部秩序(解释说明)。③\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"童年是对人类认知历程的再现(无中生有)"}],"B":[{"text":"田野生活符合儿童的成长天性"}],"C":[{"text":"幼儿在成长过程中需要自主学习(无中生有)"}],"D":[{"text":"儿童的世界是与自然相通的世界(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段可看作前观点结构，开门见山直接给出观点：田野是符合儿童天性生长的土壤，后文是对观点的解释说明；B选项是首句观点的同义替换⑨,当选；\n其他选项均未提及“田野”,且A选项的“人类认知历程”、B选项的“需要自主学习”、 D选项的“儿童世界与自然相通”均属无中生有。","notes":[{"marker":"③","content":"后文解释说明的逻辑如下：儿童有自己成长的规律，成长规律是对祖先生活的重现，祖先是摸索自然和生物 (即田野)构建知识体系，儿童重演“祖先摸索田野”来认识世界。\nA. 童年是对人类认知历程的再现(无中生有)\nB. 田野生活符合儿童的成长天性\nC. 幼儿在成长过程中需要自主学习(无中生有)\nD. 儿童的世界是与自然相通的世界(无中生有)","matchScore":0.5283,"pairingMode":"marker-and-content","order":30},{"marker":"32","content":"实战思维：\n类似“户外活动可以有效预防近视的发生”一题，可通过揣测原文作者意图来确定答案，即使没看懂后文的解释，但文段首句提到“田野”,可猜测原文可能是让儿童多亲近田野(原文标题《乡村园应用好用足“田野资源”》),即文段结构为前观点结构，先给出观点再加以解释，因此选择B选项。","matchScore":0.2474,"pairingMode":"content-similarity","order":31}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300056,3,'语句排序类','①深受道家、儒家等传统思想的影响
②以“太极”命名的太极拳，是太极文化的重要载体
③太极拳不仅是一种武功，更是一种中国传统文化的符号
④太极文化是中国古代最具特色和代表性的哲学思想之一
⑤太极拳道法自然，人们习练时不仅可以强身健体，治疗疾病
⑥还可以通过生命与大自然静持交流，在喧嚣的世界里，体会一份独特的恬淡与宁静
将以上6个句子重新排序，语序正确的是：','[{"label":"A","content":"③④①②⑥⑤"},{"label":"B","content":"⑤⑥③④②①"},{"label":"C","content":"③④①②⑤⑥③"},{"label":"D","content":"⑤⑥③"}]','C','观察选项可知，或者③④开头：介绍太极拳是文化符号和介绍太极文化；或者⑤⑥开头：介绍练习太极拳的意义(⑤⑥是“不仅可以…… 还可以……”句式，可以捆绑);显然应先介绍太极拳的性质再介绍其练习意义，答案直接锁定 C选项。公考最新资料、更新进度微信SKA674

花生批注：
33 文段行文逻辑如下：
③句下定义引出太极拳是一种中国传统文化符号，再由
④①②介绍太极拳的文化意义，⑤⑥介绍练习太极拳的意义。','2020年湖北省事业单位','进阶','published','{"globalNumber":56,"setNumber":3,"localNumber":16,"sourceLabel":"2020年湖北省事业单位 69%","accuracy":69,"typeAndPassage":"语句排序类+科普介绍文章","stemRich":[{"text":"①深受道家、儒家等传统思想的影响\n②以“太极”命名的太极拳，是太极文化的重要载体\n③太极拳不仅是一种武功，更是一种中国传统文化的符号\n④太极文化是中国古代最具特色和代表性的哲学思想之一\n⑤太极拳道法自然，人们习练时不仅可以强身健体，治疗疾病\n⑥还可以通过生命与大自然静持交流，在喧嚣的世界里，体会一份独特的恬淡与宁静\n将以上6个句子重新排序，语序正确的是："}],"optionRich":{"A":[{"text":"③④①②⑥⑤"}],"B":[{"text":"⑤⑥③④②①"}],"C":[{"text":"③④①②⑤⑥③"}],"D":[{"text":"⑤⑥③"}]},"annotatedStemRich":[{"text":"①深受道家、儒家等传统思想的影响\n②以“太极”命名的太极拳，是太极文化的重要载体\n③太极拳不仅是一种武功，更是一种中国传统文化的符号\n④太极文化是中国古代最具特色和代表性的哲学思想之一\n⑤太极拳道法自然，人们习练时不仅可以强身健体，治疗疾病\n⑥还可以通过生命与大自然静持交流，在喧嚣的世界里，体会一份独特的恬淡与宁静\n将以上6个句子重新排序，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"③④①②⑥⑤"}],"B":[{"text":"⑤⑥③④②①"}],"C":[{"text":"③④①②⑤⑥③"}],"D":[{"text":"⑤⑥③④①②"}]},"practicalAnalysis":"观察选项可知，或者③④开头：介绍太极拳是文化符号和介绍太极文化；或者⑤⑥开头：介绍练习太极拳的意义(⑤⑥是“不仅可以…… 还可以……”句式，可以捆绑);显然应先介绍太极拳的性质再介绍其练习意义，答案直接锁定 C选项。公考最新资料、更新进度微信SKA674","notes":[{"marker":"33","content":"文段行文逻辑如下：\n③句下定义引出太极拳是一种中国传统文化符号，再由\n④①②介绍太极拳的文化意义，⑤⑥介绍练习太极拳的意义。","matchScore":0.6433,"pairingMode":"content-similarity","order":32}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300057,3,'语句排序类','①即使是只涉及语言、数学和创造的简单任务也跨越了半球，由整个大脑共同完成
②大脑的左右半球只有一个主要区别：右半球控制身体左侧，左半球控制身体右侧
③大脑分为左右两个半球，由称为胼胝体的结构连接
④这导致很多人推测两个半球之间存在很大差异，但是其中很多猜测并不正确
⑤如果大脑受到损伤，健康的部分有时可接管受损部分的功能，甚至是大脑另外半球区域的功能
⑥现代脑成像技术明确证实，一个健康的大脑总是通过胼胝体连接左右半球、共同工作的
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"③②④⑥①⑤"},{"label":"B","content":"⑥③④②⑤①\n3⑥"},{"label":"C","content":"⑥⑤③②①④"},{"label":"D","content":"③④⑥①②⑤"}]','D','观察选项可知，首句在③⑥中选择，③句引出“胼胝体”
⑥句介绍胼胝体的功能，显然③句在前，排除B选项、 C选项；

花生批注：
③ 需注意此类选项，看似出自对策句，但故意设下陷阱。例如，想要考上需要努力。正确对策：要努力；
错误对策：要考上。
③④ ③句为下定义，科普介绍类文段，“下定义”做首句的概率很大。
3 文段行文逻辑如下：
③④:大脑分为左右半球，导致很多人错误的认为两个半球有很大差异；
⑥①:解释说明，事实上大脑总是通过胼胝体连接左右半球，共同工作的；
②:继续反驳很多人错误推测：左右半球只有一个主要区别(即，没有很大差异); ⑤:补充说明，大脑受损时，健康大脑甚至可以接管另一半球功能(进一步说明，没有很大差异)。
片段阅读6 00 四(上册)
将以上6个句子重新排列，语序正确的是：
3⑥ “称为胼胝体的结构(告诉我们该结构叫什么)”一般在介绍“胼胝体”之前。
例如：“这位同学叫小明”一般在“小明是一位努力的同学”之前。
C.⑥⑤③②①④ D.③④⑥①②⑤
38 例如：这次分成A 、B两班，这导致很多人推测两个班级有很大差异，但事实上，两个班级只有名称不同这一主要区别。
