INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300058,3,'下文推断类','大多数人在和朋友一起闲聊、聚会时，都会感到非常放松。但也有一部分人和朋友在一起时会觉得精疲力尽，感到紧张不安，心中不免会产生这样的疑问，我是不是得了社交恐惧症?社交恐惧症，又称社交焦虑障碍，患者极力回避社交场合，当处于社交场合时则会出现脸红、出汗、四肢颤抖，不敢与人对视，更有甚者会出现昏厥。社交恐惧症是一种十分常见的精神疾病，其发生机制不甚清楚，过去一直没有令人满意的治疗方法。
根据这段文字，接下来最可能讲的是：','[{"label":"A","content":"如何正确应对和规避社交恐惧症的风险"},{"label":"B","content":"社交恐惧症的危害和对患者生活的影响"},{"label":"C","content":"当前社交恐惧症在治疗方法上取得的突破"},{"label":"D","content":"关于社交恐惧症发生机制的几种主流理论"}]','C','文段先介绍了社交恐惧症，文末指出过去没有令人满意的社交恐惧症治疗方法的问题；
典型的时间对比结构，先介绍“过去的不足”,下文补充“现在的突破”, 下文应介绍当前社交恐惧症在治疗方法上取得的突破，对应C选项；
其他选项均未提及“社交恐惧症的治疗方法”,可简单排除。

花生批注：
③ “转折引出观点”,即先说问题，再说观点，是常见的引出观点方式。
例如：传统的创新观念认为创新没有固定结构，不遵从规则和模式。想要成为创新者的人被告知要“跳出固有思维模式”, ……。我们则主张一种截然不同的方法：在众所周知的框架内思考，不要跳出它的范围。','2019年甘肃省考','基础','published','{"globalNumber":58,"setNumber":3,"localNumber":18,"sourceLabel":"2019年甘肃省考 71%","accuracy":71,"typeAndPassage":"下文推断类 +时间对比","stemRich":[{"text":"大多数人在和朋友一起闲聊、聚会时，都会感到非常放松。但也有一部分人和朋友在一起时会觉得精疲力尽，感到紧张不安，心中不免会产生这样的疑问，我是不是得了社交恐惧症?社交恐惧症，又称社交焦虑障碍，患者极力回避社交场合，当处于社交场合时则会出现脸红、出汗、四肢颤抖，不敢与人对视，更有甚者会出现昏厥。社交恐惧症是一种十分常见的精神疾病，其发生机制不甚清楚，过去一直没有令人满意的治疗方法。\n根据这段文字，接下来最可能讲的是："}],"optionRich":{"A":[{"text":"如何正确应对和规避社交恐惧症的风险"}],"B":[{"text":"社交恐惧症的危害和对患者生活的影响"}],"C":[{"text":"当前社交恐惧症在治疗方法上取得的突破"}],"D":[{"text":"关于社交恐惧症发生机制的几种主流理论"}]},"annotatedStemRich":[{"text":"大多数人在和朋友一起闲聊、聚会时，都会感到非常放松。但也有一部分人和朋友在一起时会觉得精疲力尽，感到紧张不安，心中不免会产生这样的疑问，我是不是得了社交恐惧症?社交恐惧症，又称社交焦虑障碍，患者极力回避社交场合，当处于社交场合时则会出现脸红、出汗、四肢颤抖，不敢与人对视，更有甚者会出现昏厥(提出并介绍社交恐惧症)。社交恐惧症是一种十分常见的精神疾病，其发生机制不甚清楚，过去一直没有令人满意的治疗方法( 介绍过去没有令人满意的社交恐惧症治疗方法)。\n根据这段文字，接下来最可能讲的是："}],"annotatedOptionRich":{"A":[{"text":"如何正确应对和规避社交恐惧症的风险"}],"B":[{"text":"社交恐惧症的危害和对患者生活的影响\n39花生批注：\n下文推断的常见结构：\n①上文文末提出新内容→下文解释新内容\n②上文提出问题→下文分析问题、解决问题\n③上文给出宏观对策、原因等→下文具体展开\n④时间对比：过去不行→现在有了新突破\n⑤总分：上文是总+分→下文补充另一“分”\n⑥转折"}],"C":[{"text":"当前社交恐惧症在治疗方法上取得的突破"}],"D":[{"text":"关于社交恐惧症发生机制的几种主流理论"}]},"practicalAnalysis":"文段先介绍了社交恐惧症，文末指出过去没有令人满意的社交恐惧症治疗方法的问题；\n典型的时间对比结构，先介绍“过去的不足”,下文补充“现在的突破”, 下文应介绍当前社交恐惧症在治疗方法上取得的突破，对应C选项；\n其他选项均未提及“社交恐惧症的治疗方法”,可简单排除。","notes":[{"marker":"③","content":"“转折引出观点”,即先说问题，再说观点，是常见的引出观点方式。\n例如：传统的创新观念认为创新没有固定结构，不遵从规则和模式。想要成为创新者的人被告知要“跳出固有思维模式”, ……。我们则主张一种截然不同的方法：在众所周知的框架内思考，不要跳出它的范围。","matchScore":0.137,"pairingMode":"marker-and-content","order":36}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300059,3,'中心理解题','据了解，2019年，中央财政将继续安排20亿元聚焦乡村振兴人才需求，分层分类实施农业经理人、新型农业经营主体带头人、农村实用人才和现代创业创新青年等培育计划，全年培育职业农民100 万人以上。并将启动制定职业农民总体标准，配套开展职业农民统计和监测工作，研究职业农民从业规范，继续从队伍建设、教育培养、政策支持和社会保障等方面推动建立职业农民制度框架。
