INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300063,3,'语句填入类','所谓声誉，实际上是企业利益相关者对企业过去在市场交易中的表现的评价。声誉良好的企业，意味着在与利益相关者交易的历史中，扮演着可以信赖的伙伴角色。个人或者组织选择自己的交易对象，。因此，那些有着良好信用记录的企业，将更多地获得利益相关方的青睐，而且彼此的交易更倾向于继续发展下去，而不是“一锤子买卖”。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"往往取决于企业在行业中的地位和影响力"},{"label":"B","content":"是凭借自己或者他人的交易经验来进行判断的"},{"label":"C","content":"需要考虑双方企业发展的切实需要"},{"label":"D","content":"合作对象的知名度是其首要考虑的因素"}]','B','文段分析见批注。
本题简略翻译各句话后，答案自然出现：①声誉是企业过去交易表现的评价；②声誉好的企业，意味着过去的交易表现好；③选择交易对象时，会看；
④过去交易表现好的企业更容易交易。
显然所填入语句应体现“过去交易表现好”,对应B选项。

花生批注：
⑥ 行文结构：后观点结构。
前文分析解释，尾句给出总结：过去交易表现好的企业更容易交易。
前文的分析应围绕“过去交易表现”展开。
①所谓声誉，实际上是企业利益相关者对企业过去在市场交易中的表现的评价。②声誉良好的企业，意味着在与利益相关者交易的历史中，扮演着可以信赖的伙伴角色。③个人或者组织选择自己的交易对象，。④因此，那些有着良好信用记录的企业，将更多地获得利益相关方的青睐，而且彼此的交易更倾向于继续发展下去，而不是“一锤子买卖”。⑥
填入文中画横线部分最恰当的一项是：
A. 往往取决于企业在行业中的地位和影响力(无中生有)
B. 是凭借自己或者他人的交易经验来进行判断的
C. 需要考虑双方企业发展的切实需要(无中生有)
D. 合作对象的知名度是其首要考虑的因素(无中生有)','2013年国家公务员考试','进阶','published','{"globalNumber":63,"setNumber":4,"localNumber":3,"sourceLabel":"2013年国家公务员考试 55%","accuracy":55,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"所谓声誉，实际上是企业利益相关者对企业过去在市场交易中的表现的评价。声誉良好的企业，意味着在与利益相关者交易的历史中，扮演着可以信赖的伙伴角色。个人或者组织选择自己的交易对象， "},{"text":" ","underline":true},{"text":"。因此，那些有着良好信用记录的企业，将更多地获得利益相关方的青睐，而且彼此的交易更倾向于继续发展下去，而不是“一锤子买卖”。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"往往取决于企业在行业中的地位和影响力"}],"B":[{"text":"是凭借自己或者他人的交易经验来进行判断的"}],"C":[{"text":"需要考虑双方企业发展的切实需要"}],"D":[{"text":"合作对象的知名度是其首要考虑的因素"}]},"annotatedStemRich":[{"text":"⑥花生批注：\n行文结构：后观点结构。\n前文分析解释，尾句给出总结：过去交易表现好的企业更容易交易。\n前文的分析应围绕“过去交易表现”展开。\n①所谓声誉，实际上是企业利益相关者对企业过去在市场交易中的表现的评价。②声誉良好的企业，意味着在与利益相关者交易的历史中，扮演着可以信赖的伙伴角色。③个人或者组织选择自己的交易对象， "},{"text":" ","underline":true},{"text":"。④因此，那些有着良好信用记录的企业，将更多地获得利益相关方的青睐，而且彼此的交易更倾向于继续发展下去，而不是“一锤子买卖”。⑥\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"往往取决于企业在行业中的地位和影响力(无中生有)"}],"B":[{"text":"是凭借自己或者他人的交易经验来进行判断的"}],"C":[{"text":"需要考虑双方企业发展的切实需要(无中生有)"}],"D":[{"text":"合作对象的知名度是其首要考虑的因素(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n本题简略翻译各句话后，答案自然出现：①声誉是企业过去交易表现的评价；②声誉好的企业，意味着过去的交易表现好；③选择交易对象时，会看；\n④过去交易表现好的企业更容易交易。\n显然所填入语句应体现“过去交易表现好”,对应B选项。","notes":[{"marker":"⑥","content":"行文结构：后观点结构。\n前文分析解释，尾句给出总结：过去交易表现好的企业更容易交易。\n前文的分析应围绕“过去交易表现”展开。\n①所谓声誉，实际上是企业利益相关者对企业过去在市场交易中的表现的评价。②声誉良好的企业，意味着在与利益相关者交易的历史中，扮演着可以信赖的伙伴角色。③个人或者组织选择自己的交易对象，。④因此，那些有着良好信用记录的企业，将更多地获得利益相关方的青睐，而且彼此的交易更倾向于继续发展下去，而不是“一锤子买卖”。⑥\n填入文中画横线部分最恰当的一项是：\nA. 往往取决于企业在行业中的地位和影响力(无中生有)\nB. 是凭借自己或者他人的交易经验来进行判断的\nC. 需要考虑双方企业发展的切实需要(无中生有)\nD. 合作对象的知名度是其首要考虑的因素(无中生有)","matchScore":1.4423,"pairingMode":"marker-and-content","order":5}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300064,3,'细节判断类','跳出农业社会历史的局限，放眼中国北方的辽阔大地，我们可以看到历史上人文发展的丰富性。这些人文的丰富性，是对多样地理环境适应的结果。而所谓“适应”,对人类来说绝不是消极的。人类文明中的许多重要内容，都是在能动地适应环境的过程中创造出来的。农业是一种创造，畜牧业也是一种创造。
下列选项中，对上文理解错误的是：','[{"label":"A","content":"人类积极地适应环境就是能动地改造环境"},{"label":"B","content":"人类文明中的许多重要内容，都是在适应环境的过程中创造出来的"},{"label":"C","content":"人文的丰富性是由于对多样地理环境对抗改造的结果"},{"label":"D","content":"农业和畜牧业都是人类的创造"}]','C','B选项、D选项和第④句、第⑤句表述几乎完全一致，理解正确：A选项由第②句和第④句的可知，可能正确，而且该说法符合常理，保留；⑦C选项的“对环境对抗改造的结果”和第②句的说法“对环境适应的结果”矛盾，且由常识可知人类与环境的关系并非“对抗”,C选项一定错误，当选。

花生批注：
⑦ 较难的细节判断经常存在这样的选项设置，一个选项犯了严重的、违背常规逻辑的错误，一个选项稍有“过度”推断但符合常理，此时一定“抓大放小”。','2022年成都市事业单位','进阶','published','{"globalNumber":64,"setNumber":4,"localNumber":4,"sourceLabel":"2022年成都市事业单位64%","accuracy":64,"typeAndPassage":"细节判断类","stemRich":[{"text":"跳出农业社会历史的局限，放眼中国北方的辽阔大地，我们可以看到历史上人文发展的丰富性。这些人文的丰富性，是对多样地理环境适应的结果。而所谓“适应”,对人类来说绝不是消极的。人类文明中的许多重要内容，都是在能动地适应环境的过程中创造出来的。农业是一种创造，畜牧业也是一种创造。\n下列选项中，对上文理解错误的是："}],"optionRich":{"A":[{"text":"人类积极地适应环境就是能动地改造环境"}],"B":[{"text":"人类文明中的许多重要内容，都是在适应环境的过程中创造出来的"}],"C":[{"text":"人文的丰富性是由于对多样地理环境对抗改造的结果"}],"D":[{"text":"农业和畜牧业都是人类的创造"}]},"annotatedStemRich":[{"text":"①跳出农业社会历史的局限，放眼中国北方的辽阔大地，我们可以看到历史上人文发展的丰富性。②这些人文的丰富性，是对多样地理环境适应的结果。\n③而所谓“适应”,对人类来说绝不是消极的。④人类文明中的许多重要内容，都是在能动地适应环境的过程中创造出来的。⑤农业是一种创造，畜牧业也是一种创造。\n下列选项中，对上文理解错误的是："}],"annotatedOptionRich":{"A":[{"text":"人类积极地适应环境就是能动地改造环境"}],"B":[{"text":"人类文明中的许多重要内容，都是在适应环境的过程中创造出来的"}],"C":[{"text":"人文的丰富性是由于对多样地理环境对抗改造的结果"}],"D":[{"text":"农业和畜牧业都是人类的创造"}]},"practicalAnalysis":"B选项、D选项和第④句、第⑤句表述几乎完全一致，理解正确：A选项由第②句和第④句的可知，可能正确，而且该说法符合常理，保留；⑦C选项的“对环境对抗改造的结果”和第②句的说法“对环境适应的结果”矛盾，且由常识可知人类与环境的关系并非“对抗”,C选项一定错误，当选。","notes":[{"marker":"⑦","content":"较难的细节判断经常存在这样的选项设置，一个选项犯了严重的、违背常规逻辑的错误，一个选项稍有“过度”推断但符合常理，此时一定“抓大放小”。","matchScore":0.1891,"pairingMode":"marker-and-content","order":6}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300065,3,'细节判断类','昆虫的繁殖数量受到限制是由于存在一种被生态学家们称为环境防御作用的东西，这种作用从第一个生命出现以来就一直存在着。可利用的食物数量、气候和天气情况、竞争生物或捕食性生物的存在，这一切都是极为重要的。昆虫学家罗伯特 ·麦特卡夫说：“防止昆虫破坏我们世界安宁的最重大的一个因素是昆虫在它们内部进行的自相残杀的战争。”然而，现在大部分化学药物被用来杀死一切昆虫，无论是我们的朋友还是我们的敌人都一律格杀勿论。
下列说法与原文相符的是：','[{"label":"A","content":"人类应该是控制昆虫数量的主导者"},{"label":"B","content":"人类可以通过引导昆虫内部自相残杀来控制昆虫数量"},{"label":"C","content":"化学药物能起到有效控制昆虫的目的"},{"label":"D","content":"对昆虫真正有效的调控是环境防御作用的结果"}]','D','文段转折前(前三句)介绍了一种观点：昆虫繁殖数量受到限制是环境防御作用的结果(昆虫内部自相残杀);转折后提出现在的问题：无论昆虫中的“朋友”、“敌人”化学药物都格杀勿论；
A选项无中生有，文段未提及“控制昆虫数量的主导者”,排除； B选项，根据第①句可知：从第一个生命出现就有“环境防御作用”,并非人类引导的结果，排除；C选项，根据第④句的“化学药物将我们的朋友也格杀勿论”可知：作者不认同化学药物的作用，排除；
D选项，和第①②③句表达的意思一致，当选。','2021年成都市事业单位','进阶','published','{"globalNumber":65,"setNumber":4,"localNumber":5,"sourceLabel":"2021年成都市事业单位69%","accuracy":69,"typeAndPassage":"细节判断类","stemRich":[{"text":"昆虫的繁殖数量受到限制是由于存在一种被生态学家们称为环境防御作用的东西，这种作用从第一个生命出现以来就一直存在着。可利用的食物数量、气候和天气情况、竞争生物或捕食性生物的存在，这一切都是极为重要的。昆虫学家罗伯特 ·麦特卡夫说：“防止昆虫破坏我们世界安宁的最重大的一个因素是昆虫在它们内部进行的自相残杀的战争。”然而，现在大部分化学药物被用来杀死一切昆虫，无论是我们的朋友还是我们的敌人都一律格杀勿论。\n下列说法与原文相符的是："}],"optionRich":{"A":[{"text":"人类应该是控制昆虫数量的主导者"}],"B":[{"text":"人类可以通过引导昆虫内部自相残杀来控制昆虫数量"}],"C":[{"text":"化学药物能起到有效控制昆虫的目的"}],"D":[{"text":"对昆虫真正有效的调控是环境防御作用的结果"}]},"annotatedStemRich":[{"text":"①昆虫的繁殖数量受到限制是由于存在一种被生态学家们称为环境防御作用的东西，这种作用从第一个生命出现以来就一直存在着。②可利用的食物数量、气候和天气情况、竞争生物或捕食性生物的存在，这一切都是极为重要的。\n③昆虫学家罗伯特 ·麦特卡夫说：“防止昆虫破坏我们世界安宁的最重大的一个因素是昆虫在它们内部进行的自相残杀的战争。”④然而，现在大部分化学药物被用来杀死一切昆虫，无论是我们的朋友还是我们的敌人都一律格杀勿论。\n下列说法与原文相符的是："}],"annotatedOptionRich":{"A":[{"text":"人类应该是控制昆虫数量的主导者(无中生有)"}],"B":[{"text":"人类可以通过引导昆虫内部自相残杀来控制昆虫数量(无中生有)"}],"C":[{"text":"化学药物能起到有效控制昆虫的目的(本身有误)"}],"D":[{"text":"对昆虫真正有效的调控是环境防御作用的结果"}]},"practicalAnalysis":"文段转折前(前三句)介绍了一种观点：昆虫繁殖数量受到限制是环境防御作用的结果(昆虫内部自相残杀);转折后提出现在的问题：无论昆虫中的“朋友”、“敌人”化学药物都格杀勿论；\nA选项无中生有，文段未提及“控制昆虫数量的主导者”,排除； B选项，根据第①句可知：从第一个生命出现就有“环境防御作用”,并非人类引导的结果，排除；C选项，根据第④句的“化学药物将我们的朋友也格杀勿论”可知：作者不认同化学药物的作用，排除；\nD选项，和第①②③句表达的意思一致，当选。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300066,3,'中心理解题','近年来，关爱留守者和关爱外来人员，在输入与输出两个层面都得到了倡导。不过，政策愿景与现实之间却存在着极大的落差，看似多元而系统的关爱工程，其实未能发挥应有的功能性作用。让他们感受到一座城市的温暖，是对公共责任最直接的要求，也是对执行力最现实的考验。给予出租屋里的“候鸟”们以温暖，离不开输入地所在地方的重视与努力。其实要做到这点并不难，比如以社区或者学校为单位，开展一点联谊性活动；或者与城市的孩子结成对子，进行互相体验与帮助；或者发动孩子家长所供职的单位或者企业，自发性开展一些活动，要么给父母适当放一点假，给一点经济上的补偿，让他们有时间和精力多陪陪孩子，带他们去看一看风景，既满足了形式又升华了内涵，可谓一举两得。
这段文字意在强调：','[{"label":"A","content":"呼吁社会共同关爱留守者和外来人员"},{"label":"B","content":"关爱城市“候鸟”,输入地需要作出的努力"},{"label":"C","content":"对留守者的人文关怀考验政府的执行力"},{"label":"D","content":"给予城市“候鸟”温暖需要多元而系统的关爱工程"}]','B','文段分析见批注。
文段提出问题后直接给出“输入地应给予出租屋‘候鸟''重视和努力”, 后文具体举例可以怎么做，对应B选项，当选；
A选项，出自文段首句转折前部分，出处有误，而且已经“倡导关爱留守者和关爱外来人员”,要解决的是落实的问题，而非再次“呼吁”,排除；
C选项、D选项，均为对策选项，但都是从提出问题部分提炼而得，不如 B选项直接对应对策句，并且均未提到“输入地”这一对策主体，均可排除。

花生批注：
⑧ “离不开”表必要条件，必要条件表对策是常见对策表现方式之一。
⑨ 行文结构：前对策结构。
转折引出问题：关爱留守者和关爱外来人员未能发挥应有作用；
之后给出对策：输入地所在地方应给予出租屋里的“候鸟”们重视与努力；
最后分析上文对策的具体做法。','2018年福建选调','进阶','published','{"globalNumber":66,"setNumber":4,"localNumber":6,"sourceLabel":"2018年福建选调 60%","accuracy":60,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"近年来，关爱留守者和关爱外来人员，在输入与输出两个层面都得到了倡导。不过，政策愿景与现实之间却存在着极大的落差，看似多元而系统的关爱工程，其实未能发挥应有的功能性作用。让他们感受到一座城市的温暖，是对公共责任最直接的要求，也是对执行力最现实的考验。给予出租屋里的“候鸟”们以温暖，离不开输入地所在地方的重视与努力。其实要做到这点并不难，比如以社区或者学校为单位，开展一点联谊性活动；或者与城市的孩子结成对子，进行互相体验与帮助；或者发动孩子家长所供职的单位或者企业，自发性开展一些活动，要么给父母适当放一点假，给一点经济上的补偿，让他们有时间和精力多陪陪孩子，带他们去看一看风景，既满足了形式又升华了内涵，可谓一举两得。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"呼吁社会共同关爱留守者和外来人员"}],"B":[{"text":"关爱城市“候鸟”,输入地需要作出的努力"}],"C":[{"text":"对留守者的人文关怀考验政府的执行力"}],"D":[{"text":"给予城市“候鸟”温暖需要多元而系统的关爱工程"}]},"annotatedStemRich":[{"text":"近年来，关爱留守者和关爱外来人员，在输入与输出两个层面都得到了倡导。不过，政策愿景与现实之间却存在着极大的落差，看似多元而系统的关爱工程，其实未能发挥应有的功能性作用。让他们感受到一座城市的温暖，是对公共责任最直接的要求，也是对执行力最现实的考验(转折引出问题)。给予出租屋里的“候鸟”们以温暖，"},{"text":"离不开","underline":true},{"text":"⑧输入地所在地方的重视与努力(前对策)。其实要做到这点并不难，比如以社区或者学校为单位，开展一点联谊性活动；或者与城市的孩子结成对子，进行互相体验与帮助；或者发动孩子家长所供职的单位或者企业，自发性开展一些活动，要么给父母适当放一点假，给一点经济上的补偿，让他们有时间和精力多陪陪孩子，带他们去看一看风景，既满足了形式又升华了内涵，可谓一举两得(对策具体展开)。⑨\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"呼吁社会共同关爱留守者和外来人员 (出处有误)"}],"B":[{"text":"关爱城市“候鸟”,输入地需要作出的努力"}],"C":[{"text":"对留守者的人文关怀考验政府的执行力(对策有误)"}],"D":[{"text":"给予城市“候鸟”温暖需要多元而系统的关爱工程(对策有误且杂糅)"}]},"practicalAnalysis":"文段分析见批注。\n文段提出问题后直接给出“输入地应给予出租屋‘候鸟''重视和努力”, 后文具体举例可以怎么做，对应B选项，当选；\nA选项，出自文段首句转折前部分，出处有误，而且已经“倡导关爱留守者和关爱外来人员”,要解决的是落实的问题，而非再次“呼吁”,排除；\nC选项、D选项，均为对策选项，但都是从提出问题部分提炼而得，不如 B选项直接对应对策句，并且均未提到“输入地”这一对策主体，均可排除。","notes":[{"marker":"⑧","content":"“离不开”表必要条件，必要条件表对策是常见对策表现方式之一。","matchScore":0.1705,"pairingMode":"marker-and-content","order":7},{"marker":"⑨","content":"行文结构：前对策结构。\n转折引出问题：关爱留守者和关爱外来人员未能发挥应有作用；\n之后给出对策：输入地所在地方应给予出租屋里的“候鸟”们重视与努力；\n最后分析上文对策的具体做法。","matchScore":0.7543,"pairingMode":"marker-and-content","order":8}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300067,3,'中心理解题','新业态和新职业的出现，在社会的一次分配中也具有重要意义。就业面扩大、新职业增加，可以使 GDP增长普惠至更广范围和更深层次，分散财富聚集的节点，让财富增量在更加广阔的范围内分配，减少了更多社会问题的产生。这一点已经为一些专业研究所证实。某机构新近发布的《2020年生活服务业新业态和新职业从业者报告》显示，其根据平台数据得出2021年的生活服务业五大新业态和新职业的风向标社区团购、闪购、共享电单车、轻医美、付费自习室的新业态，以及社区团购团长、电单车换电师、数字化运营师、密室设计师、套餐规划师的新职业，无不具有向社会底部延伸的特点。这样的扩展和延伸方向，对经济结构调整和社会阶层的建构具有正面意义。
对这段话概括最准确的是：','[{"label":"A","content":"新业态和新职业促进社会分配更加公平"},{"label":"B","content":"新职业将来会更多出现在社会基层底部"},{"label":"C","content":"专业研究已证实新业态和新职业的出现"},{"label":"D","content":"经济结构调整和社会阶层建构正在进行"}]','A','文段分析见批注。
文段开门见山给出观点“新业态和新职业的出现，对社会分配具有重要意义”,接着进行分析论证，并在文末重申观点“新业态和新职业的扩展和延伸具有重要意义”。只有A选项提到了新业态和新职业出现的意义.即“促进社会分配更加公平⑫”,当选；

花生批注：
⑩ 新业态和新职业是全文论述主体。
⑪ 行文结构：前观点结构。
文段开篇开门见山给出观点：新业态和新职业对社会的一次分配有重要意义，让财富增量向更广范围分配，减少社会问题产生；
接下来举例论证这一观点，并在结尾再次重申观点：新业态和新职业的扩展和延伸，对经济结构调整和社会阶层的建构具有正面意义。
对这段话概括最准确的是：
A. 新业态和新职业促进社会分配更加公平
B. 新职业将来会更多出现在社会基层底部 (缺主体且话题不一致)
C. 专业研究已证实新业态和新职业的出现(本身有误)
⑫ 新业态和新职业让GDP增长普惠至更广范围和更深层次，让更多人享受到 GDP 增长，即让社会分配更加公平。
B选项谈论的是“新职业会出现在哪”,话题不一致；C选项本身有误，专业研究证实的是新业态和新职业的意义，而非“已出现”;D选项未谈及“新业态和新职业”,均可简单排除。
片段阅读600','2021年合肥市经开区管委会','进阶','published','{"globalNumber":67,"setNumber":4,"localNumber":7,"sourceLabel":"2021年合肥市经开区管委会 65%","accuracy":65,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"新业态和新职业的出现，在社会的一次分配中也具有重要意义。就业面扩大、新职业增加，可以使 GDP增长普惠至更广范围和更深层次，分散财富聚集的节点，让财富增量在更加广阔的范围内分配，减少了更多社会问题的产生。这一点已经为一些专业研究所证实。某机构新近发布的《2020年生活服务业新业态和新职业从业者报告》显示，其根据平台数据得出2021年的生活服务业五大新业态和新职业的风向标 "},{"text":"    ","underline":true},{"text":" 社区团购、闪购、共享电单车、轻医美、付费自习室的新业态，以及社区团购团长、电单车换电师、数字化运营师、密室设计师、套餐规划师的新职业，无不具有向社会底部延伸的特点。这样的扩展和延伸方向，对经济结构调整和社会阶层的建构具有正面意义。\n对这段话概括最准确的是："}],"optionRich":{"A":[{"text":"新业态和新职业促进社会分配更加公平"}],"B":[{"text":"新职业将来会更多出现在社会基层底部"}],"C":[{"text":"专业研究已证实新业态和新职业的出现"}],"D":[{"text":"经济结构调整和社会阶层建构正在进行"}]},"annotatedStemRich":[{"text":"新业态和新职业","underline":true},{"text":"⑧的出现，在社会的一次分配中也具有重要意义。就业面扩大、新职业增加，可以使GDP增长普惠至更广范围和更深层次，分散财富聚集的节点，让财富增量在更加广阔的范围内分配，减少了更多社会问题的产生 (前观点)。这一点已经为一些专业研究所证实。某机构新近发布的《2020年生活服务业新业态和新职业从业者报告》显示，其根据平台数据得出2021年的生活服务业五大新业态和新职业的风向标——社区团购、闪购、共享电单车、轻医美、付费自习室的新业态，以及社区团购团长、电单车换电师、数字化运营师、密室设计师、套餐规划师的新职业，无不具有向社会底部延伸的特点。这样的扩展和延伸方向，对经济结构调整和社会阶层的建构具有正面意义( 分析论证+重复观点)。①\n对这段话概括最准确的是："}],"annotatedOptionRich":{"A":[{"text":"新业态和新职业促进社会分配更加公平","bold":true}],"B":[{"text":"新职业将来会更多出现在社会基层底部 (缺主体且话题不一致)"}],"C":[{"text":"专业研究已证实新业态和新职业的出现(本身有误)"}],"D":[{"text":"经济结构调整和社会阶层建构正在进行(缺主体且话题不一致)"}]},"practicalAnalysis":"文段分析见批注。\n文段开门见山给出观点“新业态和新职业的出现，对社会分配具有重要意义”,接着进行分析论证，并在文末重申观点“新业态和新职业的扩展和延伸具有重要意义”。只有A选项提到了新业态和新职业出现的意义.即“促进社会分配更加公平⑫”,当选；","notes":[{"marker":"⑩","content":"新业态和新职业是全文论述主体。","matchScore":0.4896,"pairingMode":"content-similarity","order":9},{"marker":"⑪","content":"行文结构：前观点结构。\n文段开篇开门见山给出观点：新业态和新职业对社会的一次分配有重要意义，让财富增量向更广范围分配，减少社会问题产生；\n接下来举例论证这一观点，并在结尾再次重申观点：新业态和新职业的扩展和延伸，对经济结构调整和社会阶层的建构具有正面意义。\n对这段话概括最准确的是：\nA. 新业态和新职业促进社会分配更加公平\nB. 新职业将来会更多出现在社会基层底部 (缺主体且话题不一致)\nC. 专业研究已证实新业态和新职业的出现(本身有误)","matchScore":0.8088,"pairingMode":"content-similarity","order":10},{"marker":"⑫","content":"新业态和新职业让GDP增长普惠至更广范围和更深层次，让更多人享受到 GDP 增长，即让社会分配更加公平。\nB选项谈论的是“新职业会出现在哪”,话题不一致；C选项本身有误，专业研究证实的是新业态和新职业的意义，而非“已出现”;D选项未谈及“新业态和新职业”,均可简单排除。\n片段阅读600","matchScore":0.5577,"pairingMode":"marker-and-content","order":11}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300068,3,'中心理解题','现代化是一个世界性课题。在世界多极化、经济全球化的时代背景下，各国现代化进程色彩纷呈而又相容相通，汇聚为一曲多元与共识的交响。从历史经验与价值取向上看，现代化应体现民族性与世界性、多元与共识的统一。从这个角度理解和推进现代化，须摒弃自我中心、唯我独尊的立场和心态。遗憾的是，当今西方一些思想家在这个问题上是存在偏颇的。对于他们而言，西方理性主义是理解和诠释现代化问题的基本立场。这样一种理论定位容易导致“西方中心主义”,我们应有这种文化警醒。
这段文字的主旨是：','[{"label":"A","content":"理性主义思想家排斥西方文明"},{"label":"B","content":"现代化进程应由世界各国共同推进"},{"label":"C","content":"不同国家对现代化的认识存在分歧"},{"label":"D","content":"现代化过程中应正确看待西方理性主义"}]','D','文段分析见批注。
文段文末对策可理解为：西方理性主义容易导致西方中心主义(即以自我中心、唯我独尊的立场和心态),我们要警惕西方理性主义。 D选项的“正确看待西方理性主义”可看作是“我们应警惕西方理性主义”的同义替换，且该选项的“现代化过程”对应首句，完美选项，当选；
A选项，“理性主义思想家”为杂糅、“排斥西方文明”属无中生有，排除； B选项对策未针对问题，属于对策有误⑨,排除；C选项可看作区别比较联系类，且为中性表述⑮,排除。

花生批注：
⑬ 行文结构：后对策结构。
开篇引出话题：
现代化是世界性课题；
再提出问题：
推进现代化应摒弃自我中心、唯我独尊，但西方思想家坚持的西方理性主义依然是以自我为中心；
最后给出对策：
西方理性主义容易导致西方中心主义，我们要警惕西方理性主义。
⑮ 若C选项当选，文段应为科普介绍类，即介绍“A国家、 B国家……对现代化有什么不同看法”。','2021年四川省考','基础','published','{"globalNumber":68,"setNumber":4,"localNumber":8,"sourceLabel":"2021年四川省考 70%","accuracy":70,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"现代化是一个世界性课题。在世界多极化、经济全球化的时代背景下，各国现代化进程色彩纷呈而又相容相通，汇聚为一曲多元与共识的交响。从历史经验与价值取向上看，现代化应体现民族性与世界性、多元与共识的统一。从这个角度理解和推进现代化，须摒弃自我中心、唯我独尊的立场和心态。遗憾的是，当今西方一些思想家在这个问题上是存在偏颇的。对于他们而言，西方理性主义是理解和诠释现代化问题的基本立场。这样一种理论定位容易导致“西方中心主义”,我们应有这种文化警醒。\n这段文字的主旨是："}],"optionRich":{"A":[{"text":"理性主义思想家排斥西方文明"}],"B":[{"text":"现代化进程应由世界各国共同推进"}],"C":[{"text":"不同国家对现代化的认识存在分歧"}],"D":[{"text":"现代化过程中应正确看待西方理性主义"}]},"annotatedStemRich":[{"text":"现代化是一个世界性课题。在世界多极化、经济全球化的时代背景下，各国现代化进程色彩纷呈而又相容相通，汇聚为一曲多元与共识的交响(引出话题)。从历史经验与价值取向上看，现代化应体现民族性与世界性、多元与共识的统一。从这个角度理解和推进现代化，须摒弃自我中心、唯我独尊的立场和心态。遗憾的是，当今西方一些思想家在这个问题上是存在偏颇的。对于他们而言，西方理性主义是理解和诠释现代化问题的基本立场(提出问题)。这样一种理论定位容易导致“西方中心主义”,我们应有这种文化警醒(给出对策)。①\n这段文字的主旨是："}],"annotatedOptionRich":{"A":[{"text":"理性主义思想家排斥西方文明(无中生有且非对策表述)"}],"B":[{"text":"现代化进程应由世界各国共同推进(对策有误)"}],"C":[{"text":"不同国家对现代化的认识存在分歧(区别比较联系类)"}],"D":[{"text":"现代化过程中应正确看待西方理性主义"}]},"practicalAnalysis":"文段分析见批注。\n文段文末对策可理解为：西方理性主义容易导致西方中心主义(即以自我中心、唯我独尊的立场和心态),我们要警惕西方理性主义。 D选项的“正确看待西方理性主义”可看作是“我们应警惕西方理性主义”的同义替换，且该选项的“现代化过程”对应首句，完美选项，当选；\nA选项，“理性主义思想家”为杂糅、“排斥西方文明”属无中生有，排除； B选项对策未针对问题，属于对策有误⑨,排除；C选项可看作区别比较联系类，且为中性表述⑮,排除。","notes":[{"marker":"⑬","content":"行文结构：后对策结构。\n开篇引出话题：\n现代化是世界性课题；\n再提出问题：\n推进现代化应摒弃自我中心、唯我独尊，但西方思想家坚持的西方理性主义依然是以自我为中心；\n最后给出对策：\n西方理性主义容易导致西方中心主义，我们要警惕西方理性主义。","matchScore":0.8165,"pairingMode":"content-similarity","order":12},{"marker":"⑮","content":"若C选项当选，文段应为科普介绍类，即介绍“A国家、 B国家……对现代化有什么不同看法”。","matchScore":0.2492,"pairingMode":"marker-and-content","order":14}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300069,3,'下文推断类①','伴随着消费市场的风云变幻，曾经被电商冲击得落花流水的实体商家大有“重整河山再出发”的意思。时至今日，网络开店的成本早已没有绝对优势，与之相伴的却是获取流量的难度越来越大。因为消费的欲望需要不断被刺激，而人们对电商的便捷、便宜、丰富已经司空见惯。在近年全新的经营理念中，实体店并不单纯局限于一个买卖空间，而是体验与关系的集合。毕竟人不可能永远活在虚拟世界，依靠浏览美好的图片抚慰心灵，线下细致入微的感觉和带来的愉悦是电商无法满足和替代的。
这段文字接下来最可能讲的是：','[{"label":"A","content":"体现全新理念的实体商业案例"},{"label":"B","content":"不同消费渠道的统计数据变化"},{"label":"C","content":"消费市场不断分化的发展趋势"},{"label":"D","content":"线下购物不可替代的理论依据"}]','A','文段开篇引出话题：实体商家大有重整河山再出发之势；接着先介绍了电商发展遇到的困难，再介绍全新经营理念中，实体店的新优势；
这一段话主要介绍了曾经被电商冲击得落花流水的实体商家，在全新经营理念的帮助下，重新得到消费者的青睐，下文应继续解释“这种变化”;
A选项，举例具体说明“体现全新经营理念的实体商家做法”,逻辑通顺，当选；
B选项、C选项均未体现“实体商家”,可简单排除；D选项文段中已经介绍过，下文不会再提⑨。

花生批注：
⑯ “实体商家”全文论述主体。
(上册)
⑧ "毕竟人不可能永远活在虚拟世界，依靠浏览美好的图片抚慰心灵，线下细致入微的感觉和带来的愉悦是电商无法满足和替代的。”可看作是线下购物不可替代的理论依据。','2019年四川省考','进阶','published','{"globalNumber":69,"setNumber":4,"localNumber":9,"sourceLabel":"2019年四川省考 56%","accuracy":56,"typeAndPassage":"下文推断类①+提出新内容→解释新内容","stemRich":[{"text":"伴随着消费市场的风云变幻，曾经被电商冲击得落花流水的实体商家大有“重整河山再出发”的意思。时至今日，网络开店的成本早已没有绝对优势，与之相伴的却是获取流量的难度越来越大。因为消费的欲望需要不断被刺激，而人们对电商的便捷、便宜、丰富已经司空见惯。在近年全新的经营理念中，实体店并不单纯局限于一个买卖空间，而是体验与关系的集合。毕竟人不可能永远活在虚拟世界，依靠浏览美好的图片抚慰心灵，线下细致入微的感觉和带来的愉悦是电商无法满足和替代的。\n这段文字接下来最可能讲的是："}],"optionRich":{"A":[{"text":"体现全新理念的实体商业案例"}],"B":[{"text":"不同消费渠道的统计数据变化"}],"C":[{"text":"消费市场不断分化的发展趋势"}],"D":[{"text":"线下购物不可替代的理论依据"}]},"annotatedStemRich":[{"text":"伴随着消费市场的风云变幻，曾经被电商冲击得落花流水的"},{"text":"实体商家","underline":true},{"text":"大有“重整河山再出发”的意思(引出话题)。时至今日，网络开店的成本早已没有绝对优势，与之相伴的却是获取流量的难度越来越大。因为消费的欲望需要不断被刺激，而人们对电商的便捷、便宜、丰富已经司空见惯 (从电商角度分析)。在近年全新的经营理念中，实体店并不单纯局限于一个买卖空间，而是体验与关系的集合。毕竟人不可能永远活在虚拟世界，依靠浏览美好的图片抚慰心灵，线下细致入微的感觉和带来的愉悦是电商无法满足和替代的(从实体店角度分析)。\n"},{"text":"IHA海IGON公G KO ","bold":true},{"text":"练习题04套\n这段文字接下来最可能讲的是："}],"annotatedOptionRich":{"A":[{"text":"体现全新理念的实体商业案例"}],"B":[{"text":"不同消费渠道的统计数据变化"}],"C":[{"text":"消费市场不断分化的发展趋势"}],"D":[{"text":"线下购物不可替代的理论依据"}]},"practicalAnalysis":"文段开篇引出话题：实体商家大有重整河山再出发之势；接着先介绍了电商发展遇到的困难，再介绍全新经营理念中，实体店的新优势；\n这一段话主要介绍了曾经被电商冲击得落花流水的实体商家，在全新经营理念的帮助下，重新得到消费者的青睐，下文应继续解释“这种变化”;\nA选项，举例具体说明“体现全新经营理念的实体商家做法”,逻辑通顺，当选；\nB选项、C选项均未体现“实体商家”,可简单排除；D选项文段中已经介绍过，下文不会再提⑨。","notes":[{"marker":"⑯","content":"“实体商家”全文论述主体。\n(上册)","matchScore":0.2966,"pairingMode":"content-similarity","order":15},{"marker":"⑧","content":"\"毕竟人不可能永远活在虚拟世界，依靠浏览美好的图片抚慰心灵，线下细致入微的感觉和带来的愉悦是电商无法满足和替代的。”可看作是线下购物不可替代的理论依据。","matchScore":0.9646,"pairingMode":"content-similarity","order":17}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300070,3,'语句填入类','翻供在司法实践中并不鲜见，。翻供就其本身的性质而言，仍属犯罪疑人口供的一种表现形式。翻供现象的动机是多方面的。既可能是犯罪嫌疑人因记忆原因而改变原
有供述内容，也有可能出于侥幸心理和抵赖动机而推翻原来的供述内容，还有可能是原有口供是在
刑讯逼供、诱供、指供条件下产生，而后来又加以翻供。但无论如何，其目的是一致的，即通过翻
供来否定原有对自己不利或者不是很有利的口供，并提供对自己有利或更为有利的供述。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"翻供行为本身也并没有被我国的刑事诉讼法所禁止"},{"label":"B","content":"这是由犯罪嫌疑人口供本身所具有的特征所决定的"},{"label":"C","content":"翻供的内容在特定情况下也能成为有效的定案依据"},{"label":"D","content":"司法实践中对翻供处理的关键是要看翻供的真实性"}]','B','文段分析见批注。
文段前半部分介绍翻供并不鲜见并加以解释，后半部分介绍翻供的动机和目的。前后两部分逻辑关联不紧密，只分析前半部分的行文逻辑即可；

花生批注：
⑲ 行文结构：并列结构。
先介绍翻供的常见与原因；再介绍翻供的动机与目的。
