INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300071,3,'标题拟定类','访问数据是“网络爬虫”的行为起点，也是其价值本源，一些企业或个人为了经济利益或其他特殊目的，想方设法让“网络爬虫”突破道德规则与技术障碍(网站“反爬虫”措施),爬取未经授权或超过授权范围的数据。例如2018年2月至4月间，马某通过编写“爬虫”程序，窃取手机应用及网站的用户信息约20万条，然后通过微信出售给他人，非法获利共计2.4万元，这种行为就构成了侵犯公民个人信息罪。
下列最适合做这段文字标题的是：','[{"label":"A","content":"网络爬虫突破网站“反爬虫”"},{"label":"B","content":"网络爬虫恶意侵犯知识产权"},{"label":"C","content":"网络爬虫突破网络技术障碍"},{"label":"D","content":"网络爬虫恶意抓取非授权数据"}]','D','文段分析见批注。
