INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300072,3,'中心理解题','夏商西周时期医巫并存、形成了医学的雏形。春秋战国时期，百家争鸣、百花齐放，医巫分离，医学具有更显明的科学性、实用性，中医药理论体系开始形成。秦汉时期，产生了药物学专著。中医药学理论体系初步建立。以伤寒、杂病和外科为最突出的临床医学达到了前所未有的水平。三国两晋南北朝时期，医药学在脉学、针灸学、药物方剂、伤科、养生保健等方面取得了成绩。两宋政府组织人员编纂方书和本草、设立校正医书局、铸造针灸铜人、改革医学教育、设立惠民局、安剂坊、养济院、福田院等。辽、夏、金、元与汉族文化大融合，民族医学交流频繁。到了明清时期，中医药经过几千年的积累，不断得到丰富，产生了《本草纲目》这样的药学专著。使我国中医药学达到了历史上前所未有的高度。
对这段文字理解最准确的是：','[{"label":"A","content":"中国传统医药学具有多源一体化特征"},{"label":"B","content":"中国中医药学一直在交流互鉴中发展"},{"label":"C","content":"中国具有悠久的中医药文明史"},{"label":"D","content":"中国中医药长期存在着学派争鸣"}]','C','文段分析见批注。
文段有清晰的时间轴，从夏商周到明清，依次介绍了不同时期中医药学的发展历程(春秋时期中医药理论体系开始形成，明清中医药学达到顶峰),对应C选项，当选；
A选项的“多源一体化特征”无中生有；B选项的“交流互鉴”只在两宋时期有所提及，“一直”无中生有；D选项的“学派争鸣”只在春秋时期有所提及，“长期”无中生有，均可简单排除。

