INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300074,3,'下文推断类②','好的作家像名茶一样，是岁月山川灵气之凝聚，除了后天的技艺训练，还与天赋和成长环境密不可分。中国当代文坛的中坚力量，如莫言、贾平凹、阿来、迟子建等，就鲜明体现了地域环境对其写作的深刻塑造。这些作家的出生地多是偏僻乡村，作品也主要是乡土题材，很多都以自己家乡作为“文学根据地”。这集中反映了中国当代文学的一个现象，即乡土题材作品占绝大多数。哪怕写作和阅读的群体多数都居于城市，他们之间的交集还是乡村：住在城市的作家，写关于乡土的小说，给住在城市却保有乡土记忆的读者读。
