INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300077,3,'中心理解题','产学研合作一直是我国科技体制改革的核心议题之一。政府在涉及国家安全等重大技术领域内推动产学研合作责无旁贷，然而，在很多情况下产学研合作完全可以由社会力量组织完成。科技类社会组织既不属于层级制管理下的政府，又不是追逐利润的企业，这使得它能够专注于反映创新主体的诉求，形成区域创新体系内信息反馈的节点和网络，可以填补产学研资源供给方和需求方间的信息鸿沟，以一种更加灵活有效的方式协调各方利益，促进合作达成。因此，除了把产学研合作的动力留给市场之外，“留给社会”也是解决产学研合作动力问题的一种方式。
这段文字意在说明：','[{"label":"A","content":"产学研合作动力不足源于社会力量参与度不够"},{"label":"B","content":"应鼓励科技类社会组织参与到产学研合作中来"},{"label":"C","content":"如何在科技体制改革的核心议题上获得新的突破"},{"label":"D","content":"应发挥社会组织在解决产学研合作动力中的作用"}]','D','文段分析见批注。
文段观点为：“产学研合作可以由社会力量组织完成”,D选项为原文观点的同义替换，当选；
A选项为问题表述，文段有对策一定选对策，排除；B选项，对策有误，排除；C选项未提及“产学研”这一核心话题，排除。

花生批注：
③④ 产学研是全文论述主题。
35 行文结构：前观点结构。
开篇引出话题：产学研；
再转折提出观点：产学研合作可以由社会力量组织完成；
之后分析论证，最后重复观点。
36 科技类社会组织出自分析论证部分，且该选项不针对文中“合作动力”的问题。','2019年四川省考','基础','published','{"globalNumber":77,"setNumber":4,"localNumber":17,"sourceLabel":"2019年四川省考72%","accuracy":72,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"产学研合作一直是我国科技体制改革的核心议题之一。政府在涉及国家安全等重大技术领域内推动产学研合作责无旁贷，然而，在很多情况下产学研合作完全可以由社会力量组织完成。科技类社会组织既不属于层级制管理下的政府，又不是追逐利润的企业，这使得它能够专注于反映创新主体的诉求，形成区域创新体系内信息反馈的节点和网络，可以填补产学研资源供给方和需求方间的信息鸿沟，以一种更加灵活有效的方式协调各方利益，促进合作达成。因此，除了把产学研合作的动力留给市场之外，“留给社会”也是解决产学研合作动力问题的一种方式。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"产学研合作动力不足源于社会力量参与度不够"}],"B":[{"text":"应鼓励科技类社会组织参与到产学研合作中来"}],"C":[{"text":"如何在科技体制改革的核心议题上获得新的突破"}],"D":[{"text":"应发挥社会组织在解决产学研合作动力中的作用"}]},"annotatedStemRich":[{"text":"产学研","underline":true},{"text":"合作一直是我国科技体制改革的核心议题之一 (引出话题)。政府在涉及国家安全等重大技术领域内推动产学研合作责无旁贷，然而，在很多情况下产学研合作完全可以由社会力量组织完成(转折提出观点)。科技类社会组织既不属于层级制管理下的政府，又不是追逐利润的企业，这使得它能够专注于反映创新主体的诉求，形成区域创新体系内信息反馈的节点和网络，可以填补产学研资源供给方和需求方间的信息鸿沟，以一种更加灵活有效的方式协调各方利益，促进合作达成。因此，除了把产学研合作的动力留给市场之外，“留给社会”也是解决产学研合作动力问题的一种方式(分析论证+重复观点)。③\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"产学研合作动力不足源于社会力量参与度不够(问题表述)"}],"B":[{"text":"应鼓励科技类社会组织参与到产学研合作中来(对策有误)"}],"C":[{"text":"如何在科技体制改革的核心议题上获得新的突破(缺主题词)"}],"D":[{"text":"应发挥社会组织在解决产学研合作动力中的作用"}]},"practicalAnalysis":"文段分析见批注。\n文段观点为：“产学研合作可以由社会力量组织完成”,D选项为原文观点的同义替换，当选；\nA选项为问题表述，文段有对策一定选对策，排除；B选项，对策有误，排除；C选项未提及“产学研”这一核心话题，排除。","notes":[{"marker":"③④","content":"产学研是全文论述主题。","matchScore":0.252,"pairingMode":"content-similarity","order":32},{"marker":"35","content":"行文结构：前观点结构。\n开篇引出话题：产学研；\n再转折提出观点：产学研合作可以由社会力量组织完成；\n之后分析论证，最后重复观点。","matchScore":0.6914,"pairingMode":"content-similarity","order":33},{"marker":"36","content":"科技类社会组织出自分析论证部分，且该选项不针对文中“合作动力”的问题。","matchScore":0.5338,"pairingMode":"content-similarity","order":34}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300078,3,'中心理解题','美国经济学家罗伯特 ·卢卡斯曾经说过：“人们一旦开始思考经济增长这个问题，就再也不会去想其他事情。”百年间，在经济学家的不断努力下，增长模型对于现实经济的拟合能力越来越强，但无论是索洛模型还是无限期模型，抑或是内生增长模型，其增长路径以及最终稳态形式都强调了人口增长的重要性。尤其是按照索洛模型，最终经济增长率完全收敛于人口增长率，这意味着，一个国家或地区经济增长取决于人口的增长。
通过这段文字，作者最想表达的是：','[{"label":"A","content":"经济增长是经济学家关注的重要问题"},{"label":"B","content":"增长模型对于现实经济的拟合能力越来越强"},{"label":"C","content":"要促进经济增长，就要重视人口增长"},{"label":"D","content":"一个国家或地区经济增长取决于人口的增长"}]','C','文段分析见批注。
文段转折后介绍了各种经济模型都强调了人口增长对于经济增长的重要性，C选项为此观点的同义替换，当选；
D选项出自尾句，“一个国家或地区经济增长取决于人口的增长”是索洛模型的观点，片面，排除；A选项、B选项，均出自转折前内容，出处有误，排除。

花生批注：
③ 经济增长是全文论述话题。
