INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300080,3,'语句排序类','①但均在情感层面宣示了时间过去一极之于人精神生活的意义
②乡愁是传统农耕文明的产物
③在中国，作为“城中村”存在的园林，正是源于这种被诗化的原乡意象。以此为背景，中国文化宽泛地使用了乡愁这一概念，它既奠基于个体记忆，也散布为民族记忆
④既指向乡村，也指向城市
⑤土地的不可移动性，使中国人的原乡观念根深蒂固，也使相关情感表达成为文学艺术的母题
⑥但是，乡愁的产生毕竟以人对故乡的远离为前提，这意味着它具有追忆和回望的性质，更多指向异乡人关于故乡的想象，而不是乡村的实存
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"②③④⑤⑥①"},{"label":"B","content":"⑤⑥②③④①"},{"label":"C","content":"②⑤④③⑥①\n片段阅读600 ( 上册)"},{"label":"D","content":"②⑤⑥③④①"}]','D','观察选项可知，首句在②⑤中选择，②是下定义引出乡愁， ⑤句介绍为什么原乡相关情感(即乡愁)根深蒂固且成为文学母题，显然②句在前，排除B选项；
剩余选项尾句均为①句，可再分析①句位置：①句中的“均在情感层面……"”,“均”表明上文应有两个或以上被指代对象，④句正有“乡村”和“城市”(⑥句没有两个被指代对象),④①捆绑；此时可发现④句无主语，恰好可和③句末尾共用主语“它”,且句式一致，④答案可确定为D选项。
