INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300094,3,'语句排序类','①外生菌根真菌还可以减缓森林土壤中的碳返回到大气中的自然过程，增强森林固碳的能力
②树木与许多不同的菌根真菌形成共生关系，通过这些与树木同步生长的微生物，牢牢将碳固定在土壤中
③科学家们已经了解到，一种叫做外生菌根真菌的特殊菌根真菌正在帮助树木更快地吸收二氧化碳
④只要将这些碳元素留在森林、不进入大气，就能减少对全球变暖的影响
⑤但树木并不能独立完成这一固碳过程，每一片森林中都有一个微生物群
⑥目前全球森林大概吸收了三分之一的人类排放的二氧化碳
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"③①②⑤④⑥\n③①⑤④"},{"label":"B","content":""},{"label":"C","content":""},{"label":"D","content":"⑥④⑤②③①\n片段阅读600"}]','D','本题首句不好判断，可从有转折、指代的⑤句入手：⑤句前半句指代前文的“树木固碳”.后半句引出“微生物群的作用”. 可猜测前文介绍的是树木对固碳的作用，下文介绍微生物群对固碳的作用：⑩
⑥句介绍森林能吸收二氧化碳、④句介绍森林吸收二氧化碳的意义；
①②③句均介绍微生物，即⑥④在⑤前，①②③在⑤后，答案确定D选项。

花生批注：
7 由此句可知：菌根真菌也属于微生物。
28 实战思维：
看到⑤句的“除树木固碳，还有微生物群”,要立刻想到并列结构，⑤句在中间起到承上启下作用；
上文讲树木固碳，下文讲微生物固碳，直接根据内容分堆即可。
9 行文结构：并列结构。
⑥④介绍森林固碳及意义； ⑤承上启下，引出微生物群， ②③①介绍微生物对于固碳的作用。
③0 而且符合从宏观(森林、树木)到微观(微生物群)的常见表达逻辑。','2022年浙江省事业单位','进阶','published','{"globalNumber":94,"setNumber":5,"localNumber":14,"sourceLabel":"2022年浙江省事业单位52%","accuracy":52,"typeAndPassage":"语句排序类+科普介绍文章","stemRich":[{"text":"①外生菌根真菌还可以减缓森林土壤中的碳返回到大气中的自然过程，增强森林固碳的能力\n②树木与许多不同的菌根真菌形成共生关系，通过这些与树木同步生长的微生物，牢牢将碳固定在土壤中\n③科学家们已经了解到，一种叫做外生菌根真菌的特殊菌根真菌正在帮助树木更快地吸收二氧化碳\n④只要将这些碳元素留在森林、不进入大气，就能减少对全球变暖的影响\n⑤但树木并不能独立完成这一固碳过程，每一片森林中都有一个微生物群\n⑥目前全球森林大概吸收了三分之一的人类排放的二氧化碳\n将以上6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"③①②⑤④⑥\n③①⑤④"}],"B":[{"text":""}],"C":[{"text":""}],"D":[{"text":"⑥④⑤②③①\n片段阅读600"}]},"annotatedStemRich":[{"text":"①外生菌根真菌还可以减缓森林土壤中的碳返回到大气中的自然过程，增强森林固碳的能力\n②"},{"text":"树木与许多不同的菌根真菌形成共生关系，通过这些与树木同步生长的微生物，","underline":true},{"text":"②牢牢将碳固定在土壤中\n③科学家们已经了解到，一种叫做外生菌根真菌的特殊菌根真菌正在帮助树木更快地吸收二氧化碳\n④只要将这些碳元素留在森林、不进入大气，就能减少对全球变暖的影响\n"},{"text":"⑤但树木并不能独立完成这一固碳过程，每一片森林中都有一个微生物群","underline":true},{"text":"②\n⑥目前全球森林大概吸收了三分之一的人类排放的二氧化碳将以上6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"③①②⑤④⑥\n③①⑤④ 【参考答案】D\n【题型与文段类型】语句排序类+科普介绍文章\n【实战解析】本题首句不好判断，可从有转折、指代的⑤句入手：⑤句前半句指代前文的“树木固碳”.后半句引出“微生物群的作用”. "},{"text":" 可猜测前文介绍的是树木对固碳的作用，下文介绍微生物群对固碳的作用：","underline":true},{"text":"⑩\n⑥句介绍森林能吸收二氧化碳、④句介绍森林吸收二氧化碳的意义；\n①②③句均介绍微生物，即⑥④在⑤前，①②③在⑤后，答案确定D 选项。"}]},"practicalAnalysis":"本题首句不好判断，可从有转折、指代的⑤句入手：⑤句前半句指代前文的“树木固碳”.后半句引出“微生物群的作用”. 可猜测前文介绍的是树木对固碳的作用，下文介绍微生物群对固碳的作用：⑩\n⑥句介绍森林能吸收二氧化碳、④句介绍森林吸收二氧化碳的意义；\n①②③句均介绍微生物，即⑥④在⑤前，①②③在⑤后，答案确定D选项。","notes":[{"marker":"7","content":"由此句可知：菌根真菌也属于微生物。","matchScore":0.3808,"pairingMode":"content-similarity","order":26},{"marker":"28","content":"实战思维：\n看到⑤句的“除树木固碳，还有微生物群”,要立刻想到并列结构，⑤句在中间起到承上启下作用；\n上文讲树木固碳，下文讲微生物固碳，直接根据内容分堆即可。","matchScore":0.2245,"pairingMode":"content-similarity","order":27},{"marker":"9","content":"行文结构：并列结构。\n⑥④介绍森林固碳及意义； ⑤承上启下，引出微生物群， ②③①介绍微生物对于固碳的作用。","matchScore":0.526,"pairingMode":"content-similarity","order":28},{"marker":"③0","content":"而且符合从宏观(森林、树木)到微观(微生物群)的常见表达逻辑。","matchScore":0.2865,"pairingMode":"content-similarity","order":29}],"pai