INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300095,3,'中心理解题','围棋和中国古老的哲学应该同出一源，尤其和中国太极文化相辅相成。太极是通过黑白的交融和互补，展现了世界的矛盾统一，而围棋的黑子和白子构成的奇特图景也是流动的太极图，而中国古代哲学的朴素辩证法，阴阳、盛衰、盈亏、优劣、虚实、有无，都辩证地融合在一起。
这段文字主要讲的是：','[{"label":"A","content":"中国古代哲学的朴素辩证法"},{"label":"B","content":"围棋和中国太极文化的渊源"},{"label":"C","content":"以世界矛盾统一辩证法的发现"},{"label":"D","content":"围棋的起源与发展"}]','B','文段分析见批注。
文段开篇引出围棋和中国古老哲学(尤其是中国太极文化)这一对论述主体，下文具体展开介绍围棋和中国古代哲学(包括太极文化)之间的关系，是典型的区别比较联系类文段，包括围棋、中国古代哲学(太极文化)这一双主体，对应B选项，当选；
A选项、C选项未提及“围棋”,D选项属历程类选项，但原文并非介绍围棋的发展过程，排除。

花生批注：
