INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300096,3,'标题拟定类','真正的通俗应该是从最简单的、众所周知的材料出发，用简单的推论和恰当的例子来说明从这些材料中得出的主要结论，启发肯动脑筋的读者不断去思考更深一层的问题。把读者当成不动脑筋或不会动脑筋的人，试图通过一种畸形简化的充满玩笑和俏皮话的形式，把某一种学说的全部结论现成地奉献给读者，读者连咀嚼都用不着，只要囫囵吞下去就行了的做法，是十足的庸俗之举。
