INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300097,3,'中心理解题','我国科普工作虽然取得了很大进步，可是科普读物，无论数量还是质量，与发达国家还有着数量级的差距。在一些社会关注的重大问题上，科学家更应该主动站出来讲话。要把科学语言转化为老百姓听得懂的语言，实事求是讲真话。如果连科学家都不愿意、不敢讲话，任由真相缺失、谣言扩散，那么势必会引起公众的恐慌和困惑。
上述文字意在强调：','[{"label":"A","content":"科普工作应该通俗化，接地气"},{"label":"B","content":"我国科普读物数量少，质量差"},{"label":"C","content":"科学家负有做科普工作的义务"},{"label":"D","content":"科学家应坚持求真务实的原则"}]','C','文段分析见批注。
文段开篇提出问题：我国科普工作依然存在问题；之后直接给出对策“科学家要主动做好科普工作，要讲老百姓听得懂的语言，要实事求是讲真话”, C选项是对对策的概括，当选；
B选项非对策表述，可直接排除；A选项虽然是对策，但只对应“说老百姓听得懂的语言”且未提及主体“科学家”,排除； D选项未提及“科普”, 排除。

