INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300098,3,'语句填入类','职业病的机理和发生规律的基础研究是许多工作推进的基础。当前对职业病的认定仍然停留在2013
年制定的《职业病分类和目录》,10大类132种，以呼吸系统、皮肤、眼睛、耳鼻喉口腔等为主。
但随着我国经济转型升级，新技术、新材料的广泛应用，新业态的产生，新的职业危害因素不断出现。
与工作相关的肌肉骨骼系统疾病和心理健康等职业健康问题已引起广大劳动者和社会各界的广泛关
,如何认定、如何核查、如何治疗都是我们不得不面对的问题。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"新的职业危害引发的安全与健康问题"},{"label":"B","content":"新的经济形势下职业病的分类和目录"},{"label":"C","content":"经济转型期职业病的机理和发生规律"},{"label":"D","content":"职业病的出现与新业态新技术的关系"}]','A','文段分析见批注。
文段在引出“职业病”这一话题后，分析介绍了当前职业病的认定标准及现在新的职业危害因素与职业健康问题，文末给出总观点：即对于( )的认定、核查、治疗都是我们要面对的问题；
A选项，安全与健康问题的认定、核查、治疗，搭配得当，且和前文的分析介绍(现在新的职业危害因素与职业健康问题)衔接极其紧密，保留；
B选项(如何治疗职业病的分类与目录)、 C选项(如何治疗职业病的机理和规律)、 D选项(如何治疗职业病与新业态的关系),均与“治疗”搭配不当，均可简单排除；
综上，A选项是正确答案。

花生批注：
③ 行文结构：后观点结构。
文段开门见山引出话题：职业病，分析介绍了当前职业病的认定标准及现在新的职业危害因素与职业健康问题；
文末给出总观点，对于( ) 的认定、核查、治疗都是我们要面对的问题。
填入文中画横线部分最恰当的一项是：
A. 新的职业危害引发的安全与健康问题
B. 新的经济形势下职业病的分类和目录
C. 经济转型期职业病的机理和发生规律
D. 职业病的出现与新业态新技术的关系
38 实战思维：
文末观点句中存在“认定、核查、治疗”三个动词，要找到合适宾语与三个动词构成合适的动宾关系；
