INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300099,3,'中心理解题','作为发展中国家，为引进外商直接投资提供一定的优惠政策是必要的，但我国目前在这方面给予各级地方政府自主权过大，直接导致恶性竞争。从保障国民经济长期稳定的需要出发，中央政府应当对招商引资的优惠政策实行高度的集中统一，使各地政府把注意力转移到创造公平竞争的市场环境上去，从全局上形成协调引进外商直接投资与国内经济发展关系的氛围。
这段话的主旨是：','[{"label":"A","content":"引资优惠政策要集中授权"},{"label":"B","content":"地方政府的竞争要公平"},{"label":"C","content":"发展中国家引进外资意义重大"},{"label":"D","content":"提供引资优惠政策的必要性"}]','A','文段分析见批注。
文段在提出问题后直接给出对策：中央政府应当对招商引资的优惠政策实行高度的集中统一，正对应A选项，当选；
B选项未提及“引资优惠政策”且出处有误(出自文末分析论证部分),排 ④C选项、D选项均非对策表述，可简单排除。

花生批注：
④ 行文结构：前对策结构。
文段开篇通过转折引出问题：各级地方政府制定吸引外商直接投资的优惠政策的自主权过大；
接着给出对策：中央政府应对优惠政策实行集中统一；文末对这一做法进行意义分析。
④① “各地政府把注意力转移到创造公平竞争的市场环境上去”是“引资优惠政策要集中授权”的意义，非对策重点。
