INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300101,3,'词句理解题','人口激增，让地球的粮食供应面临严峻的考验，有科学家预计，到2050年，需要增加70%的耕地，人类才能养活自己。但地球上根本没有这么多可增加的耕地。于是，科学家转向海洋求助，在远离海岸的开阔海域中养鱼，这样就可以给人类提供足够的营养。我们可以大胆地预测，人类食物的蓝色革命即将拉开序幕。
这段文字用“人类食物的蓝色革命”来说明：','[{"label":"A","content":"对海域的深度开发，可以弥补地球上耕地的不足"},{"label":"B","content":"海洋鱼类资源将在人类食物结构中占较大比重"},{"label":"C","content":"加大深海养殖的力度，可以解决食物供给不足的现象"},{"label":"D","content":"海水养殖业将成为第一产业，在国民经济中占主导地位"}]','B','文段开篇提出问题：人口激增让地球粮食面临考验；接着通过转折给出解决方法：无法增加耕地但可以在远离海岸的开阔海域中养鱼来给人类提供足够营养；文末给出预测：人类食物的蓝色革命即将拉开序幕；
“人类食物的蓝色革命”,“革命”指的是“人类食物结构发生变化”, 通俗的说就是“吃什么发生改变”;“蓝色”,蓝色代指海洋，根据上文对策可知：
这种变化指的是“食物里增加海洋鱼类”,即人类食物里会增大海洋鱼类比重，对应B选项；
A选项的“对海域的深度开发”,未提及“养鱼”,排除；C选项的“加大深海养殖力度”无中生有，原文是“在远离海岸的开阔海域中养鱼”,未说明是“深海养殖”,排除；D选项的“海水养殖业将成为第一产业”无中生有且本身有误(第一产业是农业),排除。

花生批注：
① 简单的说：食物的革命，必须谈及吃的食物的改变，A选项、C选项、D选项，均未提及“吃什么”,均可简单排除。
片段阅读6 0 0 四(上册)','2017年辽宁省考','挑战','published','{"globalNumber":101,"setNumber":6,"localNumber":1,"sourceLabel":"2017年辽宁省考32%","accuracy":32,"typeAndPassage":"词句理解题","stemRich":[{"text":"人口激增，让地球的粮食供应面临严峻的考验，有科学家预计，到2050年，需要增加70%的耕地，人类才能养活自己。但地球上根本没有这么多可增加的耕地。于是，科学家转向海洋求助，在远离海岸的开阔海域中养鱼，这样就可以给人类提供足够的营养。我们可以大胆地预测，人类食物的蓝色革命即将拉开序幕。\n这段文字用“人类食物的蓝色革命”来说明："}],"optionRich":{"A":[{"text":"对海域的深度开发，可以弥补地球上耕地的不足"}],"B":[{"text":"海洋鱼类资源将在人类食物结构中占较大比重"}],"C":[{"text":"加大深海养殖的力度，可以解决食物供给不足的现象"}],"D":[{"text":"海水养殖业将成为第一产业，在国民经济中占主导地位"}]},"annotatedStemRich":[{"text":"人口激增，让地球的粮食供应面临严峻的考验，有科学家预计，到2050年，需要增加70%的耕地，人类才能养活自己。但地球上根本没有这么多可增加的耕地。于是，科学家转向海洋求助，在远离海岸的开阔海域中养鱼，这样就可以给人类提供足够的营养。我们可以大胆地预测，人类食物的蓝色革命即将拉开序幕。\n这段文字用“人类食物的蓝色革命”来说明："}],"annotatedOptionRich":{"A":[{"text":"对海域的深度开发，可以弥补地球上耕地的不足"}],"B":[{"text":"海洋鱼类资源将在人类食物结构中占较大比重"}],"C":[{"text":"加大深海养殖的力度，可以解决食物供给不足的现象"}],"D":[{"text":"海水养殖业将成为第一产业，在国民经济中占主导地位"}]},"practicalAnalysis":"文段开篇提出问题：人口激增让地球粮食面临考验；接着通过转折给出解决方法：无法增加耕地但可以在远离海岸的开阔海域中养鱼来给人类提供足够营养；文末给出预测：人类食物的蓝色革命即将拉开序幕；\n“人类食物的蓝色革命”,“革命”指的是“人类食物结构发生变化”, 通俗的说就是“吃什么发生改变”;“蓝色”,蓝色代指海洋，根据上文对策可知：\n这种变化指的是“食物里增加海洋鱼类”,即人类食物里会增大海洋鱼类比重，对应B选项；\nA选项的“对海域的深度开发”,未提及“养鱼”,排除；C选项的“加大深海养殖力度”无中生有，原文是“在远离海岸的开阔海域中养鱼”,未说明是“深海养殖”,排除；D选项的“海水养殖业将成为第一产业”无中生有且本身有误(第一产业是农业),排除。","notes":[{"marker":"①","content":"简单的说：食物的革命，必须谈及吃的食物的改变，A选项、C选项、D选项，均未提及“吃什么”,均可简单排除。\n片段阅读6 0 0 四(上册)","matchScore":0.3857,"pairingMode":"content-similarity","order":0}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300102,3,'语句填入类','针对外来入侵物种问题，我国管理制度在不断完善，《外来入侵物种管理办法》已于2022年8月1 日起施行。办法明确，农业农村部会同有关部门建立外来入侵物种普查制度，每十年组织开展一次全国普查；建立外来入侵物种监测制度，构建全国外来入侵物种监测网络；建立外来入侵物种信息发布制度。 ,防范外来物种入侵，人人有责。《中华人民共和国生物安全法》规定：任何单位和个人未经批准，不得擅自引进、释放或者丢弃外来物种。千万不要觉得外来物种和自己没有多大关系。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"外来入侵物种可能会对生态环境造成严重破坏"},{"label":"B","content":"生物安全防线是总体国家安全观的重要环节"},{"label":"C","content":"这一问题的解决也要依靠社会和个人的努力"},{"label":"D","content":"每位公民的心中更应该保有对自然和法律的敬畏"}]','C','文段分析见批注。
文段在介绍《外来入侵物种管理办法》的施行与重点内容后，之后给出针对个人的对策：( ),防范外来物种入侵，人人有责(即人人都要防范外来物种入侵);填入语句应和“个人”有关，对应C选项的“社会和个人的努力”; 并且C选项的“这一问题”指代前文首句的“外来入侵物种问题”,指代正确；此外，针对外来物种入侵问题，“管理制度不断完善”和“也要依靠社会和个人努力”,构成并列，当选③:
A选项的“破坏生态环境”、 B选项的“生物安全防线”、 D选项的“敬畏自然和法律”既无法总结上文，也无法和下文构成衔接，均可简单排除。

花生批注：
② 行文结构：前对策结构；
文段先介绍了《外来入侵物种管理办法》的施行与重点内容；
之后给出针对个人的对策： (),防范外来物种入侵，人人有责(即人人都要防范外来物种入侵);
最后用《生物安全法》规定内容给出论证。
③ 有的同学可能会有疑惑：“依靠个人的努力”和之后的“人人有责”不重复吗?
只要不是词句的反复使用，意思相似或一致是可以的；反复表达相同意思表达强调，并无不可；
例如：自然环境和每个人息息相关，保护环境，人人有责。
填入文中画横线部分最恰当的一项是：
A. 外来入侵物种可能会对生态环境造成严重破坏(无中生有)
B. 生物安全防线是总体国家安全观的重要环节(无中生有)
C. 这一问题的解决也要依靠社会和个人的努力
② 原文仅指出问题没有对策，可概括问题，也可给出有针对性对策，本题无问题概括选项，B选项为针对性对策，可选。
A选项和D选项缺少文段论述主体“大学生”,简单排除； C选项中性表
达，没体现问题也没体现对策，排除。','2023年重庆市事业单位','进阶','published','{"globalNumber":102,"setNumber":6,"localNumber":2,"sourceLabel":"2023年重庆市事业单位51%","accuracy":51,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"针对外来入侵物种问题，我国管理制度在不断完善，《外来入侵物种管理办法》已于2022年8月1 日起施行。办法明确，农业农村部会同有关部门建立外来入侵物种普查制度，每十年组织开展一次全国普查；建立外来入侵物种监测制度，构建全国外来入侵物种监测网络；建立外来入侵物种信息发布制度。"},{"text":"                        ","underline":true},{"text":" ,防范外来物种入侵，人人有责。《中华人民共和国生物安全法》规定：任何单位和个人未经批准，不得擅自引进、释放或者丢弃外来物种。千万不要觉得外来物种和自己没有多大关系。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"外来入侵物种可能会对生态环境造成严重破坏"}],"B":[{"text":"生物安全防线是总体国家安全观的重要环节"}],"C":[{"text":"这一问题的解决也要依靠社会和个人的努力"}],"D":[{"text":"每位公民的心中更应该保有对自然和法律的敬畏"}]},"annotatedStemRich":[{"text":"针对外来入侵物种问题，我国管理制度在不断完善，《外来入侵物种管理办法》已于2022年8月1日起施行。办法明确，农业农村部会同有关部门建立外来入侵物种普查制度，每十年组织开展一次全国普查；建立外来入侵物种监测制度，构建全国外来入侵物种监测网络；建立外来入侵物种信息发布制度 (引出问题并介绍相关制度)。"},{"text":"                       ","underline":true},{"text":",防范外来物种入侵，人人有责(针对个人给出对策)。《中华人民共和国生物安全法》规定：任何单位和个人未经批准，不得擅自引进、释放或者丢弃外来物种。千万不要觉得\n外来物种和自己没有多大关系(论证)。②\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"外来入侵物种可能会对生态环境造成严重破坏(无中生有)"}],"B":[{"text":"生物安全防线是总体国家安全观的重要环节(无中生有)"}],"C":[{"text":"这一问题的解决也要依靠社会和个人的努力"}],"D":[{"text":"每位公民的心中更应该保有对自然和法律的敬畏(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段在介绍《外来入侵物种管理办法》的施行与重点内容后，之后给出针对个人的对策：( ),防范外来物种入侵，人人有责(即人人都要防范外来物种入侵);填入语句应和“个人”有关，对应C选项的“社会和个人的努力”; 并且C选项的“这一问题”指代前文首句的“外来入侵物种问题”,指代正确；此外，针对外来物种入侵问题，“管理制度不断完善”和“也要依靠社会和个人努力”,构成并列，当选③:\nA选项的“破坏生态环境”、 B选项的“生物安全防线”、 D选项的“敬畏自然和法律”既无法总结上文，也无法和下文构成衔接，均可简单排除。","notes":[{"marker":"②","content":"行文结构：前对策结构；\n文段先介绍了《外来入侵物种管理办法》的施行与重点内容；\n之后给出针对个人的对策： (),防范外来物种入侵，人人有责(即人人都要防范外来物种入侵);\n最后用《生物安全法》规定内容给出论证。","matchScore":0.9077,"pairingMode":"marker-and-content","order":1},{"marker":"③","content":"有的同学可能会有疑惑：“依靠个人的努力”和之后的“人人有责”不重复吗?\n只要不是词句的反复使用，意思相似或一致是可以的；反复表达相同意思表达强调，并无不可；\n例如：自然环境和每个人息息相关，保护环境，人人有责。\n填入文中画横线部分最恰当的一项是：\nA. 外来入侵物种可能会对生态环境造成严重破坏(无中生有)\nB. 生物安全防线是总体国家安全观的重要环节(无中生有)\nC. 这一问题的解决也要依靠社会和个人的努力","matchScore":0.4452,"pairingMod