INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300103,3,'中心理解题','在亚利桑那大学的一项研究中，研究人员将参与者对自己习惯的看法跟他们丢弃垃圾所提供的记录进行了对比，结果发现：人们常常声称自己省吃俭用，但实际并非如此；人们常常吃垃圾食品，但自己并不承认。在牛羊肉的消费上，富裕家庭报告的消费量比实际消费量少，或许为了显示他们的饮食健康；而贫困家庭所报告的消费量比实际的多，也许为满足他们多吃的愿望。
这段文字意在说明：','[{"label":"A","content":"垃圾记录比本人陈述更能真实反映行为习惯"},{"label":"B","content":"人们往往无法正确评估自己丢弃垃圾的行为"},{"label":"C","content":"经济状况可能对人们的消费主张产生一定影响"},{"label":"D","content":"消费观念会在一定程度上影响人们的饮食习惯"}]','A','文段分析见批注。
B选项，原文讨论的是“人们对自己行为习惯的评估”,不是对“丢弃垃圾”这一行为的评估，排除；C选项和D选项缺少主题词“垃圾”排除。

花生批注：
④ 亚利桑那大学做了一项研究：将参与者对自己习惯的看法和他们丢弃垃圾所提供的记录进行对比；
研究结果如下：
①人们声称省吃俭用，但垃圾记录并非如此；
②人们不承认吃了垃圾食品，但垃圾记录显示常吃垃圾食品；
③富裕家庭报告的牛羊肉消费量，比垃圾记录的少；
④贫困家庭报告的牛羊肉消费量，比垃圾记录的多。
在亚利桑那大学的一项研究中，研究人员将参与者对自己习惯的看法跟他们丢弃垃圾所提供的记录进行了对比(实验内容 ) ,结果发现：人们常常声称自己省吃俭用，但实际并非如此；人们常常吃垃圾食品，但自己并不承认。在牛羊肉的消费上，富裕家庭报告的消费量比实际消费量少，或许为了显示他们的饮食健康；而贫困家庭所报告的消费量比实际的多，也许为满足他们多吃的愿望(实验结果)。④
这段文字意在说明：
⑤ A. 垃圾记录比本人陈述更能真实反映行为习惯
B. 人们往往无法正确评估自己丢弃垃圾的行为(杂糅)
C. 经济状况可能对人们的消费主张产生一定影响(缺主题词)
D. 消费观念会在一定程度上影响人们的饮食习惯(缺主题词)','2018年黑龙江省考','进阶','published','{"globalNumber":103,"setNumber":6,"localNumber":3,"sourceLabel":"2018年黑龙江省考 56%","accuracy":56,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"在亚利桑那大学的一项研究中，研究人员将参与者对自己习惯的看法跟他们丢弃垃圾所提供的记录进行了对比，结果发现：人们常常声称自己省吃俭用，但实际并非如此；人们常常吃垃圾食品，但自己并不承认。在牛羊肉的消费上，富裕家庭报告的消费量比实际消费量少，或许为了显示他们的饮食健康；而贫困家庭所报告的消费量比实际的多，也许为满足他们多吃的愿望。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"垃圾记录比本人陈述更能真实反映行为习惯"}],"B":[{"text":"人们往往无法正确评估自己丢弃垃圾的行为"}],"C":[{"text":"经济状况可能对人们的消费主张产生一定影响"}],"D":[{"text":"消费观念会在一定程度上影响人们的饮食习惯"}]},"annotatedStemRich":[{"text":"在亚利桑那大学的一项研究中，研究人员将参与者对自己习惯的看法跟他们丢弃垃圾所提供的记录进行了对比(实验内容 ) ,结果发现：人们常常声称自己省吃俭用，但实际并非如此；人们常常吃垃圾食品，但自己并不承认。在牛羊肉的消费上，富裕家庭报告的消费量比实际消费量少，或许为了显示他们的饮食健康；而贫困家庭所报告的消费量比实际的多，也许为满足他们多吃的愿望(实验结果)。④\n这段文字意在说明：\n文段和A 选项均可看作区别比较联系类，将“声称”和“垃圾记录”进行比较，得出“垃圾记录更真实”的结论。\n【参考答案】A\n【题型与文段类型】中心理解题+说理类文章\n文段介绍了一项对比“人们对自身行为习惯的看法”和“垃圾丢弃记录”的实验；并得出结论：人们声称的行为习惯与垃圾记录的实际情况不符，他们丢弃的垃圾反而体现了实际情况；"},{"text":"对应A选项，当选；  ","underline":true}],"annotatedOptionRich":{"B":[{"text":"选项，原文讨论的是“人们对自己行为习惯的评估”,不是对“丢弃垃圾”这一行为的评估，排除；C 选项和D 选项缺少主题词“垃圾”排除。"}]},"practicalAnalysis":"文段分析见批注。\nB选项，原文讨论的是“人们对自己行为习惯的评估”,不是对“丢弃垃圾”这一行为的评估，排除；C选项和D选项缺少主题词“垃圾”排除。","notes":[{"marker":"④","content":"亚利桑那大学做了一项研究：将参与者对自己习惯的看法和他们丢弃垃圾所提供的记录进行对比；\n研究结果如下：\n①人们声称省吃俭用，但垃圾记录并非如此；\n②人们不承认吃了垃圾食品，但垃圾记录显示常吃垃圾食品；\n③富裕家庭报告的牛羊肉消费量，比垃圾记录的少；\n④贫困家庭报告的牛羊肉消费量，比垃圾记录的多。\n在亚利桑那大学的一项研究中，研究人员将参与者对自己习惯的看法跟他们丢弃垃圾所提供的记录进行了对比(实验内容 ) ,结果发现：人们常常声称自己省吃俭用，但实际并非如此；人们常常吃垃圾食品，但自己并不承认。在牛羊肉的消费上，富裕家庭报告的消费量比实际消费量少，或许为了显示他们的饮食健康；而贫困家庭所报告的消费量比实际的多，也许为满足他们多吃的愿望(实验结果)。④\n这段文字意在说明：","matchScore":1.0935,"pairingMode":"marker-and-content","order":3},{"marker":"⑤","content":"A. 垃圾记录比本人陈述更能真实反映行为习惯\nB. 人们往往无法正确评估自己丢弃垃圾的行为(杂糅)\nC. 经济状况可能对人们的消费主张产生一定影响(缺主题词)\nD. 消费观念会在一定程度上影响人们的饮食习惯(缺主题词)","matchScore":0.3697,"pairingMode":"content-similarity","order":4}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300104,3,'中心理解题','时代是出题者，马克思曾说过：“问题就是公开的、无畏的、左右一切个人的时代声音。”新发展理念不是跨越现实距离的纯主观精神设计，而是对新的发展问题的积极回应。新中国成立特别是改革开放以来，我们用70多年时间走完了发达国家几百年的发展历程，创造了举世瞩目的“两大奇迹”。但高速发展的同时，传统增长动能减弱、资源环境透支严重、国内外联动性不足、发展成果共享度不高等突出问题随之而来。
上述文字意在强调：','[{"label":"A","content":"厘清问题是通达新发展理念的认识支点"},{"label":"B","content":"直面问题是树立新发展理念的逻辑起点"},{"label":"C","content":"破解难题是贯彻新发展理念的实践落点"},{"label":"D","content":"发现问题是把握新发展理念的最初原点"}]','B','文段分析见批注。
文段在用名言引出“问题”这一话题后，直接给出观点：新发展理念是对新的发展问题的积极回应；“直面问题”是“对新发展问题的积极回应”的同义替换，B选项正确；
A选项的“厘清问题”、C选项的“破解难题⑧”、D选项的“发现问题”均无法体现作者观点，排除。
原文如下：新中国成立特别是改革开放以来，我们用70 多年时间走完了发达国家几百年的发展历程，创造了举世瞩目的“两大奇迹”。但高速发展的同时，传统增长动能减弱、发展参差不齐、资源环境透支严重、国内外联动性不足、发展成果共享度不高等突出问题随之而来。以习近平同志为核心的党中央审时度势，立足“三期叠加”的现实，主动把握和引领经济新常态，适时提出创新、协调、绿色、开放、共享的新发展理念，以此破解新时代发展的上述新问题。

花生批注：
⑦ 行文结构：前观点结构。
文段在用名言引出“问题”这一话题后，直接给出观点：新发展理念是对新发展问题的积极回应；
下文介绍我国目前面对的问题。
⑧ 直面问题指的是面对新问题不逃避的态度；破解难题(是实践落点)是对棘手问题的做法。
