INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300105,3,'中心理解题','研究人员目前正在研发一种可用眼部动作来控制的“眼神”机器人系统。使用这种系统，有行动障碍的人只需注视所需的物体，机器人就会自动帮助取来。该研究采用的是一种基于模式的系统，参照了眨眼频率、瞳孔放大程度等明确反映人类行动意图的眼部特征。
上述文字旨在说明：','[{"label":"A","content":"“眼神”系统控制机器人的前景可观"},{"label":"B","content":"机器人“眼神”系统研发取得了新的突破"},{"label":"C","content":"“眼神”识别技术可助力机器人帮人取物"},{"label":"D","content":"“眼神”机器人依赖人眼的动作运行"}]','C','文段分析见批注。
