INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300106,3,'中心理解题','“微时代”的媒介技术革新与融合，改变和重塑着人们的审美感知方式，传统艺术审美活动的固有流程与秩序几乎被颠覆。艺术的鉴赏只需通过手指在智能手机上的简单点击或滑动即可实现，艺术接受的场所不再局限于美术馆、博物馆、剧院或影院等传统艺术空间，而是扩大至移动网络信号覆盖的所有区域；艺术创造不再为少数精英们独占，数字媒介技术带来的专业门槛和诸种成本的降低，使越来越多的人实现了由单纯的艺术接受者向艺术创作者的身份转变。
这段文字意在说明：','[{"label":"A","content":"数字技术条件下艺术鉴赏有哪些实现途径"},{"label":"B","content":"“微时代”艺术审美的大众化程度愈来愈高"},{"label":"C","content":"智能手机已成为人们艺术创造和欣赏的重要媒介"},{"label":"D","content":"“微时代”的媒介技术对审美活动产生颠覆性影响"}]','D','文段分析见批注。
文段介绍的是“微时代”的媒介技术颠覆了传统艺术审美活动，分述部分的“艺术鉴赏方式、艺术接受场所及艺术创造接受者”的变化均由“媒介技术”引起；D选项为总观点的同义替换，当选；

花生批注：
⑫ 行文结构：总分结构。
开篇给出总观点：“微时代”的媒介技术颠覆传统艺术审美活动；
后文分别从艺术鉴赏、艺术接受场所及艺术创造三方面进行分述如何颠覆。','2018年黑龙江省考','基础','published','{"globalNumber":106,"setNumber":6,"localNumber":6,"sourceLabel":"2018年黑龙江省考73%","accuracy":73,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"“微时代”的媒介技术革新与融合，改变和重塑着人们的审美感知方式，传统艺术审美活动的固有流程与秩序几乎被颠覆。艺术的鉴赏只需通过手指在智能手机上的简单点击或滑动即可实现，艺术接受的场所不再局限于美术馆、博物馆、剧院或影院等传统艺术空间，而是扩大至移动网络信号覆盖的所有区域；艺术创造不再为少数精英们独占，数字媒介技术带来的专业门槛和诸种成本的降低，使越来越多的人实现了由单纯的艺术接受者向艺术创作者的身份转变。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"数字技术条件下艺术鉴赏有哪些实现途径"}],"B":[{"text":"“微时代”艺术审美的大众化程度愈来愈高"}],"C":[{"text":"智能手机已成为人们艺术创造和欣赏的重要媒介"}],"D":[{"text":"“微时代”的媒介技术对审美活动产生颠覆性影响"}]},"annotatedStemRich":[{"text":"“微时代”的"},{"text":"媒介技术革新与融合","underline":true},{"text":"，改变和重塑着人们的审美感知方式，传统艺术审美活动的固有流程与秩序几乎被颠覆 ( 总 ) 。艺术的鉴赏只需通过手指在智能手机上的简单点击或滑动即可实现(分 1 ) ,艺术接受的场所不再局限于美术馆、博物馆、剧院或影院等传统艺术空间，而是扩大至移动网络信号覆盖的所有区域( 分 2 ) ; 艺术创造不再为少数精英们独占，数字媒介技术带来的专业门槛和诸种成本的降低，使越来越多的人实现了由单纯的艺术接受者向艺术创作者的身份转变(分3)。②\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"数字技术条件下艺术鉴赏有哪些实现途径(具体类选项)"}],"B":[{"text":"“微时代”艺术审美的大众化程度愈来愈高(片面)"}],"C":[{"text":"智能手机已成为人们艺术创造和欣赏的重要媒介(片面)"}],"D":[{"text":"“微时代”的媒介技术对审美活动产生颠覆性影响"}]},"practicalAnalysis":"文段分析见批注。\n文段介绍的是“微时代”的媒介技术颠覆了传统艺术审美活动，分述部分的“艺术鉴赏方式、艺术接受场所及艺术创造接受者”的变化均由“媒介技术”引起；D选项为总观点的同义替换，当选；","notes":[{"marker":"⑫","content":"行文结构：总分结构。\n开篇给出总观点：“微时代”的媒介技术颠覆传统艺术审美活动；\n后文分别从艺术鉴赏、艺术接受场所及艺术创造三方面进行分述如何颠覆。","matchScore":0.6388,"pairingMode":"content-similarity","order":11}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300107,3,'语句填入类','达尔文注意到，自然选择理论无法解释雄孔雀的尾巴、雄鹿的鹿角，以及为什么对有的物种来说其雄性比雌性要大得多等问题。于是他提出：物种会对能增加其获得交配和繁殖机会的性状进行性选择。他认为，性选择性状可以通过性比的不平衡来解释，当一个物种的雄性可选择的雌性数量较少时，它们将不得不更加努力地从这些少量的异性中去锁定一个作为配偶，
后来的研究发现，性选择和性比之间的确存在一种联系，但性选择最为明显的时候并不发生在潜在配偶数量稀少时，而是在潜在配偶数量充足时。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"而这种竞争推动了性选择"},{"label":"B","content":"不过它们的选择非常有限"},{"label":"C","content":"它们的种群中普遍存在性比不平衡"},{"label":"D","content":"拥有配偶意味着能够获得更多繁殖机会"}]','A','此题只需关注填入语句一句即可：“性选择性状可以通过性比的不平衡来解释”即用性比的不平衡解释性状的性选择；“当一个物种的雄性可选择的雌性数量较少时，它们将不得不更加努力地从这些少量的异性中去锁定一个作为配偶”介绍的是性比的不平衡，下文应填入的是“性状的性选择”, 只有A选项提到了性选择，当选。

花生批注：
⑮ 例如：成绩的高低可以用努力程度来解释，当一个同学非常努力时，这种努力带来了成绩的提高。
⑯ 后文继续对性比和性选择之间关系进行说明。
片段阅读6 00 (上册)','2022年事业单位联考','进阶','published','{"globalNumber":107,"setNumber":6,"localNumber":7,"sourceLabel":"2022年事业单位联考63%","accuracy":63,"typeAndPassage":"语句填入类+科普介绍文章","stemRich":[{"text":"达尔文注意到，自然选择理论无法解释雄孔雀的尾巴、雄鹿的鹿角，以及为什么对有的物种来说其雄性比雌性要大得多等问题。于是他提出：物种会对能增加其获得交配和繁殖机会的性状进行性选择。他认为，性选择性状可以通过性比的不平衡来解释，当一个物种的雄性可选择的雌性数量较少时，它们将不得不更加努力地从这些少量的异性中去锁定一个作为配偶，"},{"text":"                        ","underline":true},{"text":"\n后来的研究发现，性选择和性比之间的确存在一种联系，但性选择最为明显的时候并不发生在潜在配偶数量稀少时，而是在潜在配偶数量充足时。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"而这种竞争推动了性选择"}],"B":[{"text":"不过它们的选择非常有限"}],"C":[{"text":"它们的种群中普遍存在性比不平衡"}],"D":[{"text":"拥有配偶意味着能够获得更多繁殖机会"}]},"annotatedStemRich":[{"text":"达尔文注意到，自然选择理论无法解释雄孔雀的尾巴、雄鹿的鹿角，以及为什么对有的物种来说其雄性比雌性要大得多等问题。于是他提出：物种会对\n能增加其获得交配和繁殖机会的性状进行"},{"text":"性选择","underline":true},{"text":"⑨。"},{"text":"他认为，性选择性状可以通过性比的不平衡来解释(用性比不平衡解释性状的性选择),当一个物种的雄性可选择的雌性数量较少时，它们将不得不更加努力地从这些少量的异性中去锁定一个作为配偶(性比不平衡),","underline":true},{"text":" ( 带来性状"},{"text":"的性选择)。后来的研究发现，性选择和性比之间的确存在一种联系，","underline":true},{"text":"但性选择最为明显的时候并不发生在潜在配偶数量稀少时，而是在潜在配偶数量充足时。\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"而这种竞争推动了性选择"}],"B":[{"text":"不过它们的选择非常有限(未提及性选择)"}],"C":[{"text":"它们的种群中普遍存在性比不平衡(未提及性选择)"}],"D":[{"text":"拥有配偶意味着能够获得更多繁殖机会(未提及性选择)"}]},"practicalAnalysis":"此题只需关注填入语句一句即可：“性选择性状可以通过性比的不平衡来解释”即用性比的不平衡解释性状的性选择；“当一个物种的雄性可选择的雌性数量较少时，它们将不得不更加努力地从这些少量的异性中去锁定一个作为配偶”介绍的是性比的不平衡，下文应填入的是“性状的性选择”, 只有A选项提到了性选择，当选。","notes":[{"marker":"⑮","content":"例如：成绩的高低可以用努力程度来解释，当一个同学非常努力时，这种努力带来了成绩的提高。","matchScore":0.2836,"pairingMode":"content-similarity","order":14},{"marker":"⑯","content":"后文继续对性比和性选择之间关系进行说明。\n片段阅读6 00 (上册)","matchScore":0.2652,"pairingMode":"content-similarity","order":15}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300108,3,'语句填入类','将不能量化的诗歌(以及纯文学)评价标准和人工智能的算法标准拼接在一起，本来就是一件不伦不类的事。人工智能在科学研究、生产劳动等方面的贡献，足以证明其本领之强，。人类也完全没必要拿自己的优势去跟人工智能的缺点比较，即使科技再发达，想必在未来很长的一段时间内，诗歌与文学的世界依然是人类情感和灵魂最佳的栖息地，守卫好我们的心灵家园，依然要靠人类自身的智慧与创造力。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"却不能弥补人类智慧在诗歌创作上的缺陷"},{"label":"B","content":"完全可以取代人类智慧自主开展诗歌创作"},{"label":"C","content":"没必要和人类智慧在诗歌创作上一决高下"},{"label":"D","content":"毫无疑问将能够实现诗歌评价标准的量化"}]','C','文段分析见批注。

花生批注：
⑮ 评价体系是全文论述话题。
填入文中画横线部分最恰当的一项是：
A. 却不能弥补人类智慧在诗歌创作上的缺陷(本身有误)
B. 完全可以取代人类智慧自主开展诗歌创作(本身有误)
C. 没必要和人类智慧在诗歌创作上一决高下
⑰ C选项与上文衔接也非常恰当；人工智能有自己的优势，没必要在自己的缺点(诗歌与文学)上和人类一决高下。
⑱ B选项与尾句“诗歌与文学要靠人类自身的智慧与创造力”相悖；
D选项与首句提到的“诗歌不能量化”相悖。
文段首句引出“将诗歌和人工智能拼接是不伦不类的”这一话题，下文分别从人工智能角度、人类角度分析论证；
本题可从横线后的“人类也完全没必要拿自己的优势(诗歌与文学)去跟人工智能的缺点比较”入手，“也”表并列，前文意思应为“人工智能没必要用自己的缺点(诗歌与文学)去和人类比较”,正对应C选项，①当选；
B选项、D选项均与原文意思相悖，⑧直接排除；A选项，本身有误，原文说“诗歌与文学的世界依然是人类情感和灵魂最佳的栖息地”,诗歌与文学是人类的优势，并未提及存在缺陷，排除。','2019年黑龙江省考','进阶','published','{"globalNumber":108,"setNumber":6,"localNumber":8,"sourceLabel":"2019年黑龙江省考69%","accuracy":69,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"将不能量化的诗歌(以及纯文学)评价标准和人工智能的算法标准拼接在一起，本来就是一件不伦不类的事。人工智能在科学研究、生产劳动等方面的贡献，足以证明其本领之强， "},{"text":" ","underline":true},{"text":"。人类也完全没必要拿自己的优势去跟人工智能的缺点比较，即使科技再发达，想必在未来很长的一段时间内，诗歌与文学的世界依然是人类情感和灵魂最佳的栖息地，守卫好我们的心灵家园，依然要靠人类自身的智慧与创造力。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"却不能弥补人类智慧在诗歌创作上的缺陷"}],"B":[{"text":"完全可以取代人类智慧自主开展诗歌创作"}],"C":[{"text":"没必要和人类智慧在诗歌创作上一决高下"}],"D":[{"text":"毫无疑问将能够实现诗歌评价标准的量化"}]},"annotatedStemRich":[{"text":"将不能量化的诗歌(以及纯文学)评价标准和人工智能的算法标准拼接在一起，本来就是一件不伦不类的事(引出话题)。人工智能在科学研究、生产劳动等方面的贡献，足以证明其本领之强，"},{"text":"                       ","underline":true},{"text":"。人类也完全没必要拿自己的优势去跟人工智能的缺点比较，即使科技再发达，想必在未来很长的一段时间内，诗歌与文学的世界依然是人类情感和灵魂最佳的栖息地，守卫好我们的心灵家园，依然要靠人类自身的智慧与创造力。\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"却不能弥补人类智慧在诗歌创作上的缺陷(本身有误)"}],"B":[{"text":"完全可以取代人类智慧自主开展诗歌创作(本身有误)"}],"C":[{"text":"没必要和人类智慧在诗歌创作上一决高下"}],"D":[{"text":"毫无疑问将能够实现诗歌评价标准的量化(本身有误)"}]},"practicalAnalysis":"文段分析见批注。","notes":[{"marker":"⑮","content":"评价体系是全文论述话题。\n填入文中画横线部分最恰当的一项是：\nA. 却不能弥补人类智慧在诗歌创作上的缺陷(本身有误)\nB. 完全可以取代人类智慧自主开展诗歌创作(本身有误)\nC. 没必要和人类智慧在诗歌创作上一决高下","matchScore":0.5071,"pairingMode":"content-similarity","order":16},{"marker":"⑰","content":"C选项与上文衔接也非常恰当；人工智能有自己的优势，没必要在自己的缺点(诗歌与文学)上和人类一决高下。","matchScore":0.5309,"pairingMode":"content-similarity","order":17},{"marker":"⑱","content":"B选项与尾句“诗歌与文学要靠人类自身的智慧与创造力”相悖；\nD选项与首句提到的“诗歌不能量化”相悖。\n文段首句引出“将诗歌和人工智能拼接是不伦不类的”这一话题，下文分别从人工智能角度、人类角度分析论证；\n本题可从横线后的“人类也完全没必要拿自己的优势(诗歌与文学)去跟人工智能的缺点比较”入手，“也”表并列，前文意思应为“人工智能没必要用自己的缺点(诗歌与文学)去和人类比较”,正对应C选项，①当选；\nB选项、D选项均与原文意思相悖，⑧直接排除；A选项，本身有误，原文说“诗歌与文学的世界依然是人类情感和灵魂最佳的栖息地”,诗歌与文学是人类的优势，并未提及存在缺陷，排除。","matchScore":0.675,"pairingMode":"content-similarity","order":18}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300109,3,'中心理解题','调查发现，“花呗”“借呗”“京东白条”等便捷的小额借贷平台，迎合甚至刺激了部分大学生“先消费，再分期还贷”的理念，一些大学生通过负债借贷维持超前消费。与此相应，炫富、挥霍等消费行为在大学生中时有发生，“名媛”“土豪”等词语风行网络，成为个别大学生羡慕不劳而获生活的“幻想目标”。
这段话中作者意在说明的是：','[{"label":"A","content":"消费主义网络渗透力增强"},{"label":"B","content":"大学生要理性消费"},{"label":"C","content":"大学生更依赖网络消费"},{"label":"D","content":"新模式下的超前消费"}]','B','文段分析见批注。
文段依次指出问题：①大学生目前存在负债借贷维持超前消费的行为，② 炫富、挥霍暴露大学生错误消费行为和消费观念，B选项“理性消费”的对策针对问题且主体正确，②当选；

花生批注：
②0 行文结构：并列结构。
文段并列给出两个问题：
①大学生目前存在负债借贷维持超前消费的行为；
②炫富、挥霍暴露大学生错误消费行为和消费观念。
这段话中作者意在说明的是：
A. 消费主义网络渗透力增强( 缺主体 )
B. 大学生要理性消费
C. 大学生更依赖网络消费(中性表达)
