INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300112,3,'中心理解题','很长一段时间，中国文学海外传播主要依赖有规模有体系的经典作品译介，这些译介在推动中国文学走出去的过程中发挥了重要作用，但有时也会出现译介书目和目标读者的喜好、接受度之间有差距的情况，从而影响译介和推广的效果。而如今，类型文学海外传播则更注重市场需求，有时候甚至表现出从“译出”到“译入”的变化，即不是先译好了再推送，而是对方主动译入。据称，中国网络小说的许多海外读者因为等不及人工翻译，便通过机器翻译来实时阅读中文更新内容，这种如饥似渴的阅读需求是中国文学走出去的根本动力。
这段文字意在说明：','[{"label":"A","content":"中国文学走出去首先需要满足市场需求"},{"label":"B","content":"类型文学在国外读者中拥有很高的人气"},{"label":"C","content":"中国文学的传播方式会直接影响到效果"},{"label":"D","content":"中国文学海外传播的路径需要与时俱进"}]','A','文段分析见批注。

花生批注：
25 “中国文学海外传播”为全文论述话题。
26 行文结构：二层结构之对比 (古今对比)。
前一半介绍了：过去中国文学海外传播的方式和该模式的问题；
后一半介绍了：现在“更注重市场需求”的海外传播方式和该模式的成功。
②7 过去的传播方式“效果不好”,现在的传播方式“受到欢迎”,通过过去和现在对比，突出现在的“好”, 即中国文学海外传播要继续满足市场需求。
文段先后介绍了过去、现在的中国文学海外传播方式，并且介绍了过去的问题和现在的受欢迎，二者对比，重点突出现在“更注重市场需求”传播方式的优势，A选项以对策的形式突出现在的传播方式，当选②;
B选项未提及“传播方式”、C选项未突出现在传播方式的“好”、D选项的对策“与时俱进”无中生有，均可简单排除。','2020年事业单位联考','进阶','published','{"globalNumber":112,"setNumber":6,"localNumber":12,"sourceLabel":"2020年事业单位联考 60%","accuracy":60,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"很长一段时间，中国文学海外传播主要依赖有规模有体系的经典作品译介，这些译介在推动中国文学走出去的过程中发挥了重要作用，但有时也会出现译介书目和目标读者的喜好、接受度之间有差距的情况，从而影响译介和推广的效果。而如今，类型文学海外传播则更注重市场需求，有时候甚至表现出从“译出”到“译入”的变化，即不是先译好了再推送，而是对方主动译入。据称，中国网络小说的许多海外读者因为等不及人工翻译，便通过机器翻译来实时阅读中文更新内容，这种如饥似渴的阅读需求是中国文学走出去的根本动力。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"中国文学走出去首先需要满足市场需求"}],"B":[{"text":"类型文学在国外读者中拥有很高的人气"}],"C":[{"text":"中国文学的传播方式会直接影响到效果"}],"D":[{"text":"中国文学海外传播的路径需要与时俱进"}]},"annotatedStemRich":[{"text":"很长一段时间，"},{"text":"中国文学海外传播","underline":true},{"text":"⑤主要依赖有规模有体系的经典作品译介，这些译介在推动中国文学走出去的过程中发挥了重要作用，但有时也会出现译介书目和目标读者的喜好、接受度之间有差距的情况，从而影响译介和推广的效果(以前的传播方式和问题)。而如今，类型文学海外传播则更注重市场需求，有时候甚至表现出从“译出”到“译入”的变化，即不是先译好了再推送，而是对方主动译入。据称，中国网络小说的许多海外读者因为等不及人工翻译，便通过机器翻译来实时阅读中文更新内容，这种如饥似渴的阅读需求是中国文学走出去的根本动力(现在的传播方式和成功)。②\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"中国文学走出去首先需要满足市场需求"}],"B":[{"text":"类型文学在国外读者中拥有很高的人气(缺主题词)"}],"C":[{"text":"中国文学的传播方式会直接影响到效果(中性表达)"}],"D":[{"text":"中国文学海外传播的路径需要与时俱进(无中生有)"}]},"practicalAnalysis":"文段分析见批注。","notes":[{"marker":"25","content":"“中国文学海外传播”为全文论述话题。","matchScore":0.5437,"pairingMode":"content-similarity","order":25},{"marker":"26","content":"行文结构：二层结构之对比 (古今对比)。\n前一半介绍了：过去中国文学海外传播的方式和该模式的问题；\n后一半介绍了：现在“更注重市场需求”的海外传播方式和该模式的成功。","matchScore":0.4663,"pairingMode":"content-similarity","order":26},{"marker":"②7","content":"过去的传播方式“效果不好”,现在的传播方式“受到欢迎”,通过过去和现在对比，突出现在的“好”, 即中国文学海外传播要继续满足市场需求。\n文段先后介绍了过去、现在的中国文学海外传播方式，并且介绍了过去的问题和现在的受欢迎，二者对比，重点突出现在“更注重市场需求”传播方式的优势，A选项以对策的形式突出现在的传播方式，当选②;\nB选项未提及“传播方式”、C选项未突出现在传播方式的“好”、D选项的对策“与时俱进”无中生有，均可简单排除。","matchScore":0.3393,"pairingMode":"content-similarity","order":27}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300113,3,'标题拟定类','纵观世界，新的垃圾处理时代正在到来。前不久，俄罗斯科学家已经可以利用等离子技术来处理垃圾焚烧过程中产生的有害气体，并对城市生活制造的“污泥浊水”进行无害化处理，使其转为腐殖酸肥料。德国科学家造出“风拣技术”,令世界看到了垃圾处理的广阔未来。该技术终结了垃圾的人工分拣，让风代替人去对垃圾中的塑料、玻璃、纸张等进行分拣，从而将垃圾处理工艺提高到了一个前所未有的新阶段。
最适合做这段文字标题的是：','[{"label":"A","content":"垃圾：放错地方的资源"},{"label":"B","content":"科技：垃圾处理的关键"},{"label":"C","content":"风力：新时代的“机器人”"},{"label":"D","content":"无害化：垃圾处理的未来"}]','B','文段分析见批注。
