INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300114,3,'标题拟定类','据“上海发布”最新消息，“数字人民币五五欢乐购”活动正式启动，总计发放35万份红包。根据通知，符合条件的所有手机定位在上海市的公众均可参与报名。6月11日9时起，可在活动报名页面自行查询抽签结果。数字人民币支付率先在南京路、淮海中路——新天地、豫园、小陆家嘴、徐家汇、北外滩等“两街四圈”和虹桥国际开放枢纽核心商圈落地。
