INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300115,3,'下文推断类','飞行表演由各种基础动作组成，如横滚、筋斗以及著名的眼镜蛇动作等。此时，飞机发动机会遭受进气畸变，发动机稳定裕度衰减，即航空发动机进口流场参数与其设计的假设不一致。进气畸变是航空发动机失稳的主要诱因，易造成压气机稳定性丧失，此时涡轮负荷和热应力增加，压气机叶片发生强迫振动，极有可能对发动机造成不可逆的损害，影响飞机飞行安全，因此有必要发展及时可靠的压气机失稳预报技术，确保在进气畸变条件下航空发动机安全稳定运行。
