INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300116,3,'下文推断类','立秋后，自然界的阳气开始收敛、沉降，人们应当开始做好保养阳气的准备。在起居上应做到“早睡早起”,因为早睡可以顺应阳气收敛，早起可使肺气得以舒展。秋应于肺，在志为忧，这个时期是抑郁症的高发期。因而对于有抑郁症或抑郁情绪的人来说，要注意情绪的调整和把控。
