INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300117,3,'词句理解题','俄罗斯科学家在人造聚合材料的基础上加入从蛋壳中提取的羟基磷灰石，开发出一种新型黏合剂。目前，牙科医生修复受损牙齿用的是人造材料，普通的修复物在这种材料基础上制成。这种复合材料和固定修复物所使用的胶，在性能和化学组成方面与天然牙组织——牙质有很大不同。因此，它们与真牙结合得很不好，有时修复体会脱落。天然羟基磷灰石存在于各种固体组织中，包括牙齿、骨骼和蛋壳等，在其基础上制作的黏合剂可以很好地模拟牙质的特性和结构。
根据文意，新型黏合剂用来固定牙齿修复效果好的原因是：','[{"label":"A","content":"新型黏合剂的化学组成和结构非常接近于真牙"},{"label":"B","content":"天然羟基磷灰石能广泛存在于各种固体组织中"},{"label":"C","content":"新型黏合剂提高了牙科修复物和胶的稳固性"},{"label":"D","content":"普通的牙科修复材料和胶不能存在于固体组织"}]','A','文段中介绍了过去粘合剂的问题和新型粘合剂的优势，将二者对比即可看出新型粘合剂固定牙齿修复效果好的原因是什么。

花生批注：
36 天然羟基磷灰石存在于牙齿、骨骼和蛋壳等组织中，因为本身就存在于生物组织，所以可以更好的模拟牙质的特性与结构；
B选项是新型粘合剂和天然牙组织接近的原因，而非用来固定牙齿修复效果好的原因。
③ 新型粘合剂提高了粘合稳定性，和固定牙齿修复效果好，是一回事，都是结果，而非结果的原因。
俄罗斯科学家在人造聚合材料的基础上加入从蛋壳中提取的羟基磷灰石，开发出一种新型黏合剂。目前，牙科医生修复受损牙齿用的是人造材料，普通的修复物在这种材料基础上制成。这种复合材料和固定修复物所使用的胶，在性能和化学组成方面与天然牙组织——牙质有很大不同。因此，它们与真牙结合得很不好，有时修复体会脱落(过去粘合剂)。天然羟基磷灰石存在于各种固体组织中，包括牙齿、骨骼和蛋壳等，在其基础上制作的黏合剂可以很好地模拟牙质的特性和结构(新型粘合剂)。
根据文意，新型黏合剂用来固定牙齿修复效果好的原因是：
A. 新型黏合剂的化学组成和结构非常接近于真牙
B. 天然羟基磷灰石能广泛存在于各种固体组织中③
C. 新型黏合剂提高了牙科修复物和胶的稳固性③
D. 普通的牙科修复材料和胶不能存在于固体组织
38 类似B选项，解释的是为什么旧粘合剂和天然牙组织的牙质有很大不同。
过去粘合剂
新型粘合剂
性能和化学组成与天然牙组织不同
能很好模拟牙质的特性和结构
因此旧粘合剂
与真牙结合的不好
因此新型粘合剂与真牙结合的更好
对比即可看出，新型粘合剂修复效果更好的原因是能很好模拟牙质的特性和结构(也是因为性能和化学组成与天然牙组织相同),对应A选项，当选。','2022年成都市事业单位','进阶','published','{"globalNumber":117,"setNumber":6,"localNumber":17,"sourceLabel":"2022年成都市事业单位57%","accuracy":57,"typeAndPassage":"词句理解题","stemRich":[{"text":"俄罗斯科学家在人造聚合材料的基础上加入从蛋壳中提取的羟基磷灰石，开发出一种新型黏合剂。目前，牙科医生修复受损牙齿用的是人造材料，普通的修复物在这种材料基础上制成。这种复合材料和固定修复物所使用的胶，在性能和化学组成方面与天然牙组织——牙质有很大不同。因此，它们与真牙结合得很不好，有时修复体会脱落。天然羟基磷灰石存在于各种固体组织中，包括牙齿、骨骼和蛋壳等，在其基础上制作的黏合剂可以很好地模拟牙质的特性和结构。\n根据文意，新型黏合剂用来固定牙齿修复效果好的原因是："}],"optionRich":{"A":[{"text":"新型黏合剂的化学组成和结构非常接近于真牙"}],"B":[{"text":"天然羟基磷灰石能广泛存在于各种固体组织中"}],"C":[{"text":"新型黏合剂提高了牙科修复物和胶的稳固性"}],"D":[{"text":"普通的牙科修复材料和胶不能存在于固体组织"}]},"annotatedStemRich":[{"text":"36花生批注：\n天然羟基磷灰石存在于牙齿、骨骼和蛋壳等组织中，因为本身就存在于生物组织，所以可以更好的模拟牙质的特性与结构；\nB 选项是新型粘合剂和天然牙组织接近的原因，而非用来固定牙齿修复效果好的原因。\n③花生批注：\n新型粘合剂提高了粘合稳定性，和固定牙齿修复效果好，是一回事，都是结果，而非结果的原因。\n俄罗斯科学家在人造聚合材料的基础上加入从蛋壳中提取的羟基磷灰石，开发出一种新型黏合剂。目前，牙科医生修复受损牙齿用的是人造材料，普通的修复物在这种材料基础上制成。这种复合材料和固定修复物所使用的胶，在性能和化学组成方面与天然牙组织——牙质有很大不同。因此，它们与真牙结合得很不好，有时修复体会脱落(过去粘合剂)。天然羟基磷灰石存在于各种固体组织中，包括牙齿、骨骼和蛋壳等，在其基础上制作的黏合剂可以很好地模拟牙质的特性和结构(新型粘合剂)。\n根据文意，新型黏合剂用来固定牙齿修复效果好的原因是："}],"annotatedOptionRich":{"A":[{"text":"新型黏合剂的化学组成和结构非常接近于真牙"}],"B":[{"text":"天然羟基磷灰石能广泛存在于各种固体组织中③"}],"C":[{"text":"新型黏合剂提高了牙科修复物和胶的稳固性③"}],"D":[{"text":"普通的牙科修复材料和胶不能存在于固体组织"}]},"practicalAnalysis":"文段中介绍了过去粘合剂的问题和新型粘合剂的优势，将二者对比即可看出新型粘合剂固定牙齿修复效果好的原因是什么。","notes":[{"marker":"36","content":"天然羟基磷灰石存在于牙齿、骨骼和蛋壳等组织中，因为本身就存在于生物组织，所以可以更好的模拟牙质的特性与结构；\nB选项是新型粘合剂和天然牙组织接近的原因，而非用来固定牙齿修复效果好的原因。","matchScore":1.2406,"pairingMode":"content-similarity","order":36},{"marker":"③","content":"新型粘合剂提高了粘合稳定性，和固定牙齿修复效果好，是一回事，都是结果，而非结果的原因。\n俄罗斯科学家在人造聚合材料的基础上加入从蛋壳中提取的羟基磷灰石，开发出一种新型黏合剂。目前，牙科医生修复受损牙齿用的是人造材料，普通的修复物在这种材料基础上制成。这种复合材料和固定修复物所使用的胶，在性能和化学组成方面与天然牙组织——牙质有很大不同。因此，它们与真牙结合得很不好，有时修复体会脱落(过去粘合剂)。天然羟基磷灰石存在于各种固体组织中，包括牙齿、骨骼和蛋壳等，在其基础上制作的黏合剂可以很好地模拟牙质的特性和结构(新型粘合剂)。\n根据文意，新型黏合剂用来固定牙齿修复效果好的原因是：\nA. 新型黏合剂的化学组成和结构非常接近于真牙\nB. 天然羟基磷灰石能广泛存在于各种固体组织中③\nC. 新型黏合剂提高了牙科修复物和胶的稳固性③\nD. 普通的牙科修复材料和胶不能存在于固体组织","matchScore":1.5524,"pairingMode":"marker-and-content","order":37},{"marker":"38","content":"类似B选项，解释的是为什么旧粘合剂和天然牙组织的牙质有很大不同。\n过去粘合剂\n新型粘合剂\n性能和化学组成与天然牙组织不同\n能很好模拟牙质的特性和结构\n因此旧粘合剂\n与真牙结合的不好\n因此新型粘合剂与真牙结合的更好\n对比即可看出，新型粘合剂修复效果更好的原因是能很好模拟牙质的特性和结构(也是因为性能和化学组成与天然牙组织相同),对应A选项，当选。","matchScore":0.7871,"pairingMode":"content-similarity","order":38}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300118,3,'语句排序类','①有了静，全部构建会组合成一种古筝独奏般的淡雅清丽
②在摩肩接踵的拥挤中游古典园林是很叫人伤心的事
③中国古典园林不管依傍何种建筑流派，都要以静作为自己的韵律
④而失去了静，它内在的整体风致也就不可寻找
⑤你有幸走在这样的园林中就会觉得走进了一种境界，虚虚浮浮而又满目生气，几乎不相信自己往常曾多次来过
⑥如有一个偶然的机会，或许是大雨刚歇，游客未至，或许是时值黄昏，庭院冷落
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"③①④②⑥⑤"},{"label":"B","content":"⑥⑤②③①④"},{"label":"C","content":"②⑥⑤③①④"},{"label":"D","content":"②⑤⑥③①④"}]','A','观察选项，③①④均在一起，可先分析剩余三句的顺序：② 介绍了“人多游园体验不好”,⑥⑤(为一句话)介绍了“如果幸运的遇到人少，游园体验极佳”,先介绍在嘈杂拥挤中游园体验不佳，再介绍若偶然遇到在“静”的环境下游园，体验极佳，符合逻辑，②⑥⑤捆绑；
③①④介绍的是中国古典园林的“静”,先介绍“静”的意义，再介绍“静”时的游园体验，符合逻辑，并且③引出“中国古典园林”,可看作是“下定义”做首句，④ A选项当选。

花生批注：
⑥ 有同学可能有疑惑：介绍我国目前面对的问题，和“积极回应问题”有什么关系? 下文为什么成了“积极回应问题”的论证?
查找原文后可知，文段删掉了最后一句话，若补充完整，后文介绍的是“我国就是积极面对这些新发展问题”。
③⑨ 文段首句引出话题“中国古典园林以静为旋律”;①④ 正反论证“静”对园林的意义；②⑥⑤介绍“静”时的游园体验。
①有了静，全部构建会组合成一种古筝独奏般的淡雅清丽
②在摩肩接踵的拥挤中游古典园林是很叫人伤心的事
③中国古典园林不管依傍何种建筑流派，都要以静作为自己的韵律
④而失去了静，它内在的整体风致也就不可寻找
⑤你有幸走在这样的园林中就会觉得走进了一种境界，虚虚浮浮而又满目生气，几乎不相信自己往常曾多次来过
⑥如有一个偶然的机会，或许是大雨刚歇，游客未至，或许是时值黄昏，庭院冷落
将以上6个句子重新排列，语序正确的是：
A.③①④②⑥⑤ B.⑥⑤②③①④
C.②⑥⑤③①④ D.②⑤⑥③①④
