INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300119,3,'语句排序类','①“适度距离”不单是居住空间上的物理距离，也是心理上的“代际距离”
②个性解放、知识快速更新和年轻一代的经济独立不断冲击着传统家长权威
③当年轻人与父辈的价值观念和行为方式难以快速趋同时，保持适度距离是确保良性代际互动的前提
④在社会转型进程中，中国的家庭结构经历着革命式变迁
⑤有学者提出，两代人的居住格局应保持“一碗汤的距离”,既要让子代和父代有各自的独立空间，又要维系家庭成员之间的亲密关系
⑥不同价值观念和行为方式在同一时空并存的环境下，代际之间的适度空间和社会距离是彼此有效沟通与和谐共处的基本条件之一
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"⑤①③④②⑥"},{"label":"B","content":"②⑥③④①⑤"},{"label":"C","content":"④②⑥③⑤①"},{"label":"D","content":"⑥③⑤④①②"}]','C','观察选项可知，首句在②④⑤⑥中选择，②④在介绍背景与问题，⑤⑥均提及“适度距离”,可猜测先介绍背景，再介绍对策；
再分析②④,④是背景介绍(社会转型中中国家庭结构发生变化),②介绍转型带来的问题(年轻一代冲击传统家长权威),④在②前，基本锁定C选项；
⑥③⑤①都在介绍“适度距离”,全文行文逻辑可理解为：先介绍社会转型中中国家庭结构的变迁，这种变迁带来年轻一代与传统家长权威的冲突，“适度距离”是解决这种冲突的对策，符合逻辑， C选项正确。','2020年湖南省考','基础','published','{"globalNumber":119,"setNumber":6,"localNumber":19,"sourceLabel":"2020年湖南省考 72%","accuracy":72,"typeAndPassage":"语句排序类+说理类文章","stemRich":[{"text":"①“适度距离”不单是居住空间上的物理距离，也是心理上的“代际距离”\n②个性解放、知识快速更新和年轻一代的经济独立不断冲击着传统家长权威\n③当年轻人与父辈的价值观念和行为方式难以快速趋同时，保持适度距离是确保良性代际互动的前提\n④在社会转型进程中，中国的家庭结构经历着革命式变迁\n⑤有学者提出，两代人的居住格局应保持“一碗汤的距离”,既要让子代和父代有各自的独立空间，又要维系家庭成员之间的亲密关系\n⑥不同价值观念和行为方式在同一时空并存的环境下，代际之间的适度空间和社会距离是彼此有效沟通与和谐共处的基本条件之一\n将以上6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"⑤①③④②⑥"}],"B":[{"text":"②⑥③④①⑤"}],"C":[{"text":"④②⑥③⑤①"}],"D":[{"text":"⑥③⑤④①②"}]},"annotatedStemRich":[{"text":"①“适度距离”不单是居住空间上的物理距离，也是心理上的“代际距离”\n②个性解放、知识快速更新和年轻一代的经济独立不断冲击着传统家长权威\n③当年轻人与父辈的价值观念和行为方式难以快速趋同时，保持适度距离是确保良性代际互动的前提\n④在社会转型进程中，中国的家庭结构经历着革命式变迁\n⑤有学者提出，两代人的居住格局应保持“一碗汤的距离”,既要让子代和父代有各自的独立空间，又要维系家庭成员之间的亲密关系\n⑥不同价值观念和行为方式在同一时空并存的环境下，代际之间的适度空间和社会距离是彼此有效沟通与和谐共处的基本条件之一\n将以上6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"⑤①③④②⑥"}],"B":[{"text":"②⑥③④①⑤"}],"C":[{"text":"④②⑥③⑤①"}],"D":[{"text":"⑥③⑤④①②"}]},"practicalAnalysis":"观察选项可知，首句在②④⑤⑥中选择，②④在介绍背景与问题，⑤⑥均提及“适度距离”,可猜测先介绍背景，再介绍对策；\n再分析②④,④是背景介绍(社会转型中中国家庭结构发生变化),②介绍转型带来的问题(年轻一代冲击传统家长权威),④在②前，基本锁定C选项；\n⑥③⑤①都在介绍“适度距离”,全文行文逻辑可理解为：先介绍社会转型中中国家庭结构的变迁，这种变迁带来年轻一代与传统家长权威的冲突，“适度距离”是解决这种冲突的对策，符合逻辑， C选项正确。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300120,3,'细节判断类','谈及诺贝尔奖提名的历史，不得不提爱因斯坦。1905年，爱因斯坦发表了5篇论文，提出光电效应、狭义相对论、质能等效方程，并对统计力学作出了巨大贡献。1910年，奥斯特瓦尔德便向瑞典科学院提名爱因斯坦获奖。尽管那个时代的瑞典科学院更加青睐实验物理学工作，对以思想实验为主的相对论持保留意见，但爱因斯坦仍先后被提名62次，终于在1922年荣膺诺贝尔物理学奖，可以说物理学的半壁江山都站在爱因斯坦的身后。
由以上材料不能推知：','[{"label":"A","content":"爱因斯坦的狭义相对论代表了思想实验的最高成就"},{"label":"B","content":"爱因斯坦在物理学方面的贡献不属于实验物理学领域"},{"label":"C","content":"爱因斯坦对统计力学作出了巨大贡献"},{"label":"D","content":"1905 年发表的论文是爱因斯坦获诺贝尔奖的基础"}]','A','本题为选非题， A选项的“思想实验的最高成就”为绝对化表述，原文中未提及，选项无法推出，当选。
