INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300121,3,'中心理解题','现代生物制造已经成为全球性的战略性新兴产业，在化工、材料、医药、食品、农业等诸多重大工业领域得到了广泛的应用。据经合组织预测，到2030年约有35%的化学品和其他工业产品来自生物制造。欧、美、日等主要发达国家都将绿色生物制造确立为战略发展重点，并分别制定了相应的国家规划。我国正处于建设创新型国家与加快生态文明体制改革的决定性阶段，紧随并引领世界科技前沿，发展新型绿色生物制造技术，支撑传统产业升级变革，关乎资源、环境、健康，符合国家重大战略需求。
这段文字意在说明：','[{"label":"A","content":"现代生物制造的应用领域日益广泛"},{"label":"B","content":"发展现代绿色生物制造乃大势所趋"},{"label":"C","content":"发展现代生物制造符合我国重大战略需求"},{"label":"D","content":"我国正处于传统产业升级变革的关键时期"}]','C','文段分析见批注。
文段可看作他国、我国的对比结构，也可看作是“背景+我国”的结构；先介绍现代生物制造和他国的策略，引出我国发展绿色生物制造技术符合国家重大战略需求；他国和我国对比，“我国”更重要，对应 C选项，当选；
A选项、B选项未提及我国、 D选项未提及现代生物制造技术，均可简单排除。
片段阅读60 0 (上册)

