INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300122,3,'中心理解题','古代先哲对爱因斯坦等有颠覆性创新的科学家具体如何产生影响?表面上看，这些古人对物理学和整个科学领域的认知天真而充满错误，对科学几乎什么都不懂。但是，他们问了很多根本性问题，并进行了严肃讨论。如果当代科学家想摆脱常规思维的束缚，这些古代先哲将会是灵感的源泉：在追寻知识最前沿时，他们颠覆性同时又充满孩子气的问题，将会指引人们进入新疆域。
这段文字意在说明：','[{"label":"A","content":"古代先哲对科学本质的认识至今仍具有启迪性"},{"label":"B","content":"当代科学研究是在前人成就基础上的大胆探索"},{"label":"C","content":"科学要在扬弃古代先哲思想的基础上继续前进"},{"label":"D","content":"古代哲学思想为科学的创新性研究提供了助力"}]','A','文段分析见批注。
文段设问引出话题“古代先哲对现代科学家有何影响”,⑤下文简单分析后，给出观点：当代科学家在想摆脱常规思维束缚时，古代先哲可提供灵感；即古代先哲可为现代科学研究提供灵感，A选项是此意思的同义替换，⑥当选；
B选项未提到“古代先哲”,可简单排除；C选项的“扬弃⑦”指的是发扬与抛弃，“抛弃”无中生有，排除；D选项意思和A选项相近，但主体错误，古代哲学思想不等于古代先哲，排除。

花生批注：
④ 行文结构：后观点结构。
文段开篇用设问引出话题：
“古代先哲对现代科学家有何影响”;
中间进行分析介绍；
文末给出观点：当代科学家在想摆脱常规思维束缚时，古代先哲可提供灵感。
⑤ 实战思维：
设问引出话题的题目，读文段时要时刻牢记问题，即古代先哲有什么影响，只要抓住“古代先哲”,答案只能选A选项。
⑥ A选项可翻译为：在进行科学本质研究时，古代先哲依然有启迪性；
与原文尾句意思一致：在当代科学家想摆脱思维束缚时，古代先哲可以是灵感的来源。
⑦ 扬弃是发扬与抛弃的统一，是在保留精华的基础上剔除糟粕。
⑨ 有同学可能会困惑：“这一大变革”指的是前文的“生产关系变革”,和下文“生产工具变革”连接稍显突兀；原因在于文段删掉了一句话，若补充上，逻辑就更加紧密合理，主要介绍当前的生产工具变革；
原文如下：当今世界正处在生产工具大变革的前夜。这一大变革主要表现在互联网的诞生和发展。从生产工具的角度看，全球已开始进入“互联网+”时代。
古代先哲③对爱因斯坦等有颠覆性创新的科学家具体如何产生影响(设问引出话题)? 表面上看，这些古人对物理学和整个科学领域的认知天真而充满错误，对科学几乎什么都不懂。但是，他们问了很多根本性问题，并进行了严肃讨论(分析介绍)。如果当代科学家想摆脱常规思维的束缚，这些古代先哲将会是灵感的源泉：在追寻知识最前沿时，他们颠覆性同时又充满孩子气的问题，将会指引人们进入新疆域(后观点)。④
这段文字意在说明：
A. 古代先哲对科学本质的认识至今仍具有启迪性
B. 当代科学研究是在前人成就基础上的大胆探索(主体有误)
C. 科学要在扬弃古代先哲思想的基础上继续前进(无中生有)','2018年浙江选调','进阶','published','{"globalNumber":122,"setNumber":7,"localNumber":2,"sourceLabel":"2018年浙江选调 57%","accuracy":57,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"古代先哲对爱因斯坦等有颠覆性创新的科学家具体如何产生影响?表面上看，这些古人对物理学和整个科学领域的认知天真而充满错误，对科学几乎什么都不懂。但是，他们问了很多根本性问题，并进行了严肃讨论。如果当代科学家想摆脱常规思维的束缚，这些古代先哲将会是灵感的源泉：在追寻知识最前沿时，他们颠覆性同时又充满孩子气的问题，将会指引人们进入新疆域。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"古代先哲对科学本质的认识至今仍具有启迪性"}],"B":[{"text":"当代科学研究是在前人成就基础上的大胆探索"}],"C":[{"text":"科学要在扬弃古代先哲思想的基础上继续前进"}],"D":[{"text":"古代哲学思想为科学的创新性研究提供了助力"}]},"annotatedStemRich":[{"text":"古代先哲","underline":true},{"text":"③对爱因斯坦等有颠覆性创新的科学家具体如何产生影响(设问引出话题)? 表面上看，这些古人对物理学和整个科学领域的认知天真而充满错误，对科学几乎什么都不懂。但是，他们问了很多根本性问题，并进行了严肃讨论(分析介绍)。如果当代科学家想摆脱常规思维的束缚，这些古代先哲将会是灵感的源泉：在追寻知识最前沿时，他们颠覆性同时又充满孩子气的问题，将会指引人们进入新疆域(后观点)。④\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"古代先哲对科学本质的认识至今仍具有启迪性"}],"B":[{"text":"当代科学研究是在前人成就基础上的大胆探索(主体有误)"}],"C":[{"text":"科学要在扬弃古代先哲思想的基础上继续前进(无中生有)"}],"D":[{"text":"古代哲学思想为科学的创新性研究提供了助力(主体有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段设问引出话题“古代先哲对现代科学家有何影响”,⑤下文简单分析后，给出观点：当代科学家在想摆脱常规思维束缚时，古代先哲可提供灵感；即古代先哲可为现代科学研究提供灵感，A选项是此意思的同义替换，⑥当选；\nB选项未提到“古代先哲”,可简单排除；C选项的“扬弃⑦”指的是发扬与抛弃，“抛弃”无中生有，排除；D选项意思和A选项相近，但主体错误，古代哲学思想不等于古代先哲，排除。","notes":[{"marker":"④","content":"行文结构：后观点结构。\n文段开篇用设问引出话题：\n“古代先哲对现代科学家有何影响”;\n中间进行分析介绍；\n文末给出观点：当代科学家在想摆脱常规思维束缚时，古代先哲可提供灵感。","matchScore":0.9289,"pairingMode":"marker-and-content","order":3},{"marker":"⑤","content":"实战思维：\n设问引出话题的题目，读文段时要时刻牢记问题，即古代先哲有什么影响，只要抓住“古代先哲”,答案只能选A选项。","matchScore":0.4331,"pairingMode":"marker-and-content","order":4},{"marker":"⑥","content":"A选项可翻译为：在进行科学本质研究时，古代先哲依然有启迪性；\n与原文尾句意思一致：在当代科学家想摆脱思维束缚时，古代先哲可以是灵感的来源。","matchScore":0.5294,"pairingMode":"marker-and-content","order":5},{"marker":"⑦","content":"扬弃是发扬与抛弃的统一，是在保留精华的基础上剔除糟粕。","matchScore":0.2946,"pairingMode":"marker-and-content","order":6},{"marker":"⑨","content":"有同学可能会困惑：“这一大变革”指的是前文的“生产关系变革”,和下文“生产工具变革”连接稍显突兀；原因在于文段删掉了一句话，若补充上，逻辑就更加紧密合理，主要介绍当前的生产工具变革；\n原文如下：当今世界正处在生产工具大变革的