INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300123,3,'中心理解题','从一定意义上讲，任何社会的发展变化，往往是从生产工具的发展变化开始的；生产工具的大变革必然引发生产力的大发展；生产力决定生产关系，生产力的大发展最终必然要求变革现存的生产关系。这一大变革主要表现在互联网的诞生和发展。从生产工具的角度看，全球已开始进入“互联网+”时代。在工业领域，主要是互联网加机器人、3D 打印技术、新能源、新材料、太空技术、传统制造业等；在农业领域，是互联网加智能农业、生物工程等；在第三产业，是互联网加金融、商务、教育、医疗、媒体、各种新兴服务业等。
这段文字意在强调：','[{"label":"A","content":"生产力是社会前进的决定力量"},{"label":"B","content":"生产工具对社会的发展变化具有不可替代的作用"},{"label":"C","content":"当今世界处于“互联网+”领衔的生产工具大变革时代"},{"label":"D","content":"三大产业只有与“互联网+”相结合才能长效发展\n四海公考练习题07套"}]','C','文段分析见批注。
文段开篇介绍了社会发展变化的一般过程，接着给出前观点：当前变革主要表现在互联网的诞生与发展，从生产工具角度看，已开始进入互联网+时代；后文列举互联网+时代的新生产工具，论证前文观点；显然，被论证的观点更重要，即“生产工具已进入互联网+时代”,对应C选项，当选；
A选项、B选项未提到关键词“互联网+”,D选项“三大产业”和对策均无中生有，可简单排除。

花生批注：
⑧ 背景知识用于帮助理解，一般不重要。
⑩ 行文结构：前观点结构。
开篇介绍：社会变化的一般过程，即社会发展变化由生产工具开始，生产工具变化引起生产力大发展，生产力大发展最终导致生产关系的变革；
接着给出观点：现在的变革表现在互联网，生产工具已进入互联网+时代；
最后：列举互联网+时代的新生产工具。','2019年合肥市事业单位','进阶','published','{"globalNumber":123,"setNumber":7,"localNumber":3,"sourceLabel":"2019年合肥市事业单位63%","accuracy":63,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"从一定意义上讲，任何社会的发展变化，往往是从生产工具的发展变化开始的；生产工具的大变革必然引发生产力的大发展；生产力决定生产关系，生产力的大发展最终必然要求变革现存的生产关系。这一大变革主要表现在互联网的诞生和发展。从生产工具的角度看，全球已开始进入“互联网+”时代。在工业领域，主要是互联网加机器人、3D 打印技术、新能源、新材料、太空技术、传统制造业等；在农业领域，是互联网加智能农业、生物工程等；在第三产业，是互联网加金融、商务、教育、医疗、媒体、各种新兴服务业等。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"生产力是社会前进的决定力量"}],"B":[{"text":"生产工具对社会的发展变化具有不可替代的作用"}],"C":[{"text":"当今世界处于“互联网+”领衔的生产工具大变革时代"}],"D":[{"text":"三大产业只有与“互联网+”相结合才能长效发展\n四海公考练习题07套"}]},"annotatedStemRich":[{"text":"从一定意义上讲，任何社会的发展变化，往往是从生产工具的发展变化开始的；生产工具的大变革必然引发生产力的大发展；生产力决定生产关系，生产力的大发展最终必然要求变革现存的生产关系( "},{"text":"背景知识引出","underline":true},{"text":"⑧)。"},{"text":"这一大变革主要表现在互联网的诞生和发展。从生产工具的角度看，全球已开始进入","underline":true},{"text":" "},{"text":" “互联网+”时代","underline":true},{"text":"⑨(前观点)。在工业领域，主要是互联网加机器人、3D 打印技术、新能源、新材料、太空技术、传统制造业等；在农业领域，是互联网加智能农业、生物工程等；在第三产业，是互联网加金融、商务、教育、医疗、媒体、各种新兴服务业等(举例论证)。⑩\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"生产力是社会前进的决定力量(无主题词)"}],"B":[{"text":"生产工具对社会的发展变化具有不可替代的作用(无主题词)"}],"C":[{"text":"当今世界处于“互联网+”领衔的生产工具大变革时代"}],"D":[{"text":"三大产业只有与“互联网+”相结合才能长效发展(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段开篇介绍了社会发展变化的一般过程，接着给出前观点：当前变革主要表现在互联网的诞生与发展，从生产工具角度看，已开始进入互联网+时代；后文列举互联网+时代的新生产工具，论证前文观点；显然，被论证的观点更重要，即“生产工具已进入互联网+时代”,对应C选项，当选；\nA选项、B选项未提到关键词“互联网+”,D选项“三大产业”和对策均无中生有，可简单排除。","notes":[{"marker":"⑧","content":"背景知识用于帮助理解，一般不重要。","matchScore":0.4479,"pairingMode":"marker-and-content","order":7},{"marker":"⑩","content":"行文结构：前观点结构。\n开篇介绍：社会变化的一般过程，即社会发展变化由生产工具开始，生产工具变化引起生产力大发展，生产力大发展最终导致生产关系的变革；\n接着给出观点：现在的变革表现在互联网，生产工具已进入互联网+时代；\n最后：列举互联网+时代的新生产工具。","matchScore":0.7385,"pairingMode":"marker-and-content","order":9}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300124,3,'词句理解题','“微创新”,这个概念正在成为中国企业尝试的新方向。今天的技术革新在很多时候已经不再是颠覆性的更新换代，任何针对用户体验的微小改变，都可能引爆整个市场。微博就可以看作是在博客基础上的微创新，用140个字拉低了用户门槛，迅速引发了全民微博潮。对于习惯了模仿的企业来说，如何不让微创新成为“山寨”的代名词，是问题的关键，特别是在互联网领域，像团购这样的一窝蜂现象屡见不鲜，然而其中很难看到“微创新”在发挥作用。
这段文字用“团购”来说明：','[{"label":"A","content":"盲目从众的现象"},{"label":"B","content":"更新换代的趋势"},{"label":"C","content":"复制与模仿的做法"},{"label":"D","content":"集体相约采购的行为"}]','C','文段分析见批注。
文段在介绍了微创新的概念与功能后，给出了对策：不要让微创新成为山寨和模仿；后文用团购说明已存在的“山寨和模仿”现象，对应C选项，当选。

花生批注：
⑪ 行文结构：前对策结构。
文段开篇：介绍了“微创新”的概念和作用；
接着给出禁止型对策：对于习惯模仿的企业，不要让“微创新”成为“山寨”,即不要让“微创新”成为山寨、模仿；
后文：举了团购的例子支持观点。','2015年国家公务员考试','进阶','published','{"globalNumber":124,"setNumber":7,"localNumber":4,"sourceLabel":"2015年国家公务员考试 65%","accuracy":65,"typeAndPassage":"词句理解题","stemRich":[{"text":"“微创新”,这个概念正在成为中国企业尝试的新方向。今天的技术革新在很多时候已经不再是颠覆性的更新换代，任何针对用户体验的微小改变，都可能引爆整个市场。微博就可以看作是在博客基础上的微创新，用140个字拉低了用户门槛，迅速引发了全民微博潮。对于习惯了模仿的企业来说，如何不让微创新成为“山寨”的代名词，是问题的关键，特别是在互联网领域，像"},{"text":"团购","underline":true},{"text":"这样的一窝蜂现象屡见不鲜，然而其中很难看到“微创新”在发挥作用。\n这段文字用“团购”来说明："}],"optionRich":{"A":[{"text":"盲目从众的现象"}],"B":[{"text":"更新换代的趋势"}],"C":[{"text":"复制与模仿的做法"}],"D":[{"text":"集体相约采购的行为"}]},"annotatedStemRich":[{"text":"“微创新”,这个概念正在成为中国企业尝试的新方向。今天的技术革新在很多时候已经不再是颠覆性的更新换代，任何针对用户体验的微小改变，都可能引爆整个市场。微博就可以看作是在博客基础上的微创新，用140个字拉低了用户门槛，迅速引发了全民微博潮(背景知识介绍)。对于习惯了模仿的企业来说，如何不让微创新成为“山寨”的代名词，是问题的关键(前对策), 特别是在互联网领域，像团购这样的一窝蜂现象屡见不鲜，然而其中很难看到\n“微创新”在发挥作用(举例论证)。①\n这段文字用“团购”来说明："}],"annotatedOptionRich":{"A":[{"text":"盲目从众的现象②"}],"B":[{"text":"更新换代的趋势"}],"C":[{"text":"复制与模仿的做法"}],"D":[{"text":"集体相约采购的行为"}]},"practicalAnalysis":"文段分析见批注。\n文段在介绍了微创新的概念与功能后，给出了对策：不要让微创新成为山寨和模仿；后文用团购说明已存在的“山寨和模仿”现象，对应C选项，当选。","notes":[{"marker":"⑪","content":"行文结构：前对策结构。\n文段开篇：介绍了“微创新”的概念和作用；\n接着给出禁止型对策：对于习惯模仿的企业，不要让“微创新”成为“山寨”,即不要让“微创新”成为山寨、模仿；\n后文：举了团购的例子支持观点。","matchScore":0.615,"pairingMode":"content-similarity","order":10}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300125,3,'下文推断类','当人们下意识地模仿同伴表情时，通过感受每分每秒的情感回应，他们能够在同伴的情绪中感受到自己也产生了相似的情绪体验，这一过程被称为“情绪感染”。这种体验被他人所激发，并最终会使情绪的接受者产生与最初激发者趋于一致的情绪，这也就是所谓的“看到别人笑我也会开心，看到别人哭我也会难过”。
这段文字接下来最不可能讲述的是：','[{"label":"A","content":"为什么情绪会传染"},{"label":"B","content":"什么是情绪感染"},{"label":"C","content":"哪种人更易被情绪感染"},{"label":"D","content":"如何提升自身的情绪感染力"}]','B','本题是选非题，文段首句已经明确介绍了什么是“情绪感染”, 后文一般不会再介绍，对应B选项，当选。

花生批注：
⑫ 从众指的是个人的观念与行为由于群体的引导或压力，而向与多数人相一致的方向变化的现象。
例如：老师在课堂上说“认可我讲课方式的请举手”, 小明看到大家都举手了，即使他不认可，也举起了手；
而很多公司都开展团购业务，显然不是“盲目从众” (看到其他公司开展团购业务，即使自己不想或不适合，也随大流开展),而是看到这一做法前景好，可能打着“微创新”的名义，行模仿与山寨之实。
片段阅读6 00 四(上册)
⑬ 上文已经较详细介绍的内容，下文一般不会再介绍。','2023年福建省事业单位','进阶','published','{"globalNumber":125,"setNumber":7,"localNumber":5,"sourceLabel":"2023年福建省事业单位63%","accuracy":63,"typeAndPassage":"下文推断类","stemRich":[{"text":"当人们下意识地模仿同伴表情时，通过感受每分每秒的情感回应，他们能够在同伴的情绪中感受到自己也产生了相似的情绪体验，这一过程被称为“情绪感染”。这种体验被他人所激发，并最终会使情绪的接受者产生与最初激发者趋于一致的情绪，这也就是所谓的“看到别人笑我也会开心，看到别人哭我也会难过”。\n这段文字接下来最不可能讲述的是："}],"optionRich":{"A":[{"text":"为什么情绪会传染"}],"B":[{"text":"什么是情绪感染"}],"C":[{"text":"哪种人更易被情绪感染"}],"D":[{"text":"如何提升自身的情绪感染力"}]},"annotatedStemRich":[{"text":"当人们下意识地模仿同伴表情时，通过感受每分每秒的情感回应，他们能够在同伴的情绪中感受到自己也产生了相似的情绪体验，这一过程被称为“情绪感染”。这种体验被他人所激发，并最终会使情绪的接受者产生与最初激发者趋于一致的情绪，这也就是所谓的“看到别人笑我也会开心，看到别人哭我也会难过”。\n这段文字接下来最不可能讲述的是："}],"annotatedOptionRich":{"A":[{"text":"为什么情绪会传染"}],"B":[{"text":"什么是情绪感染"}],"C":[{"text":"哪种人更易被情绪感染"}],"D":[{"text":"如何提升自身的情绪感染力"}]},"practicalAnalysis":"本题是选非题，文段首句已经明确介绍了什么是“情绪感染”, 后文一般不会再介绍，对应B选项，当选。","notes":[{"marker":"⑫","content":"从众指的是个人的观念与行为由于群体的引导或压力，而向与多数人相一致的方向变化的现象。\n例如：老师在课堂上说“认可我讲课方式的请举手”, 小明看到大家都举手了，即使他不认可，也举起了手；\n而很多公司都开展团购业务，显然不是“盲目从众” (看到其他公司开展团购业务，即使自己不想或不适合，也随大流开展),而是看到这一做法前景好，可能打着“微创新”的名义，行模仿与山寨之实。\n片段阅读6 00 四(上册)","matchScore":0.1562,"pairingMode":"content-similarity","order":11},{"marker":"⑬","content":"上文已经较详细介绍的内容，下文一般不会再介绍。","matchScore":0.5475,"pairingMode":"content-similarity","order":12}],"pairingMode":"validated-sequence-fallback"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300126,3,'词句理解题','造纸术是中国四大发明之一，也是人类文明史上一项杰出的发明创造。中国是世界上最早养蚕织丝的国家。中国古代劳动人民以上等蚕茧抽丝织绸，剩下的恶茧、病茧等则用漂絮法制取丝绵。漂絮完毕，篾席上会遗留一些残絮。当漂絮的次数多了，篾席上的残絮便积成一层纤维薄片，经晾干之后剥离下来，可用于书写。这种漂絮的副产物数量不多，在古书上称它为赫踬或方絮。这表明了中国造纸术的起源同丝絮有着渊源关系。
文中的“它”所指的是：','[{"label":"A","content":"漂絮完毕，篾席上遗留的残絮"},{"label":"B","content":"漂絮的副产物"},{"label":"C","content":"篾席上的纤维薄片"},{"label":"D","content":"篾席上的副产物"}]','C','根据文段可知，飘絮完毕 →篾席遗留残絮→残絮积累成纤维薄片，经晾干后剥离下来的纤维薄片可用于书写。文段中“它”指代的是前文的“这种飘絮的副产物”,“这种飘絮的副产物”是对上文“纤维薄片”的指代，因此题干中的“它”实质上就是用来书写的纤维薄片，答案为C选项。

花生批注：
⑭ 原文中“这种飘絮的副产物”本身就是指代词，并非“它”所指代的实际对象；
另外，飘絮的副产物可能有很多种，原文中“这种飘絮的副产物”是特指“纤维薄片”这种飘絮的副产物，而并非所有飘絮副产物。','2019年江西省法检','进阶','published','{"globalNumber":126,"setNumber":7,"localNumber":6,"sourceLabel":"2019年江西省法检50%","accuracy":50,"typeAndPassage":"词句理解题","stemRich":[{"text":"造纸术是中国四大发明之一，也是人类文明史上一项杰出的发明创造。中国是世界上最早养蚕织丝的国家。中国古代劳动人民以上等蚕茧抽丝织绸，剩下的恶茧、病茧等则用漂絮法制取丝绵。漂絮完毕，篾席上会遗留一些残絮。当漂絮的次数多了，篾席上的残絮便积成一层纤维薄片，经晾干之后剥离下来，可用于书写。这种漂絮的副产物数量不多，在古书上称它为赫踬或方絮。这表明了中国造纸术的起源同丝絮有着渊源关系。\n文中的“它”所指的是："}],"optionRich":{"A":[{"text":"漂絮完毕，篾席上遗留的残絮"}],"B":[{"text":"漂絮的副产物"}],"C":[{"text":"篾席上的纤维薄片"}],"D":[{"text":"篾席上的副产物"}]},"annotatedStemRich":[{"text":"造纸术是中国四大发明之一，也是人类文明史上一项杰出的发明创造。中国是世界上最早养蚕织丝的国家。中国古代劳动人民以上等蚕茧抽丝织绸，剩下的恶茧、病茧等则用漂絮法制取丝绵。漂絮完毕，篾席上会遗留一些残絮( A 选项)。当漂絮的次数多了，篾席上的残絮便积成一层纤维薄片( C 选项), 经晾干之后剥离下来，可用于书写。这种漂絮的副产物数量不多( B 选项), 在古书上称它为赫或方絮。这表明了中国造纸术的起源同丝絮有着渊源关系。\n文中的“它”所指的是："}],"annotatedOptionRich":{"A":[{"text":"漂絮完毕，篾席上遗留的残絮"}],"B":[{"text":"漂絮的副产物"}],"C":[{"text":"篾席上的纤维薄片"}],"D":[{"text":"篾席上的副产物"}]},"practicalAnalysis":"根据文段可知，飘絮完毕 →篾席遗留残絮→残絮积累成纤维薄片，经晾干后剥离下来的纤维薄片可用于书写。文段中“它”指代的是前文的“这种飘絮的副产物”,“这种飘絮的副产物”是对上文“纤维薄片”的指代，因此题干中的“它”实质上就是用来书写的纤维薄片，答案为C选项。","notes":[{"marker":"⑭","content":"原文中“这种飘絮的副产物”本身就是指代词，并非“它”所指代的实际对象；\n另外，飘絮的副产物可能有很多种，原文中“这种飘絮的副产物”是特指“纤维薄片”这种飘絮的副产物，而并非所有飘絮副产物。","matchScore":0.4433,"pairingMode":"content-similarity","order":13}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300127,3,'中心理解题','当下的家庭教育中，“教育超量”与教育不足同时存在。有些家长唯恐自己的孩子“输在起跑线上”, 为孩子报了多个辅导班、兴趣班，给孩子造成很重的负担。也有家长认为孩子还小，不必学什么, 让孩子自由成长就行。这种自然教育的观念，与西方教育思想的影响有关。卢梭在《爱弥儿》中就讲，“要放任无为，才能一切有为”“你开头什么都不教，结果反而会创造一切教育奇迹”,卢梭的这些说法有一定的启发性，但其片面性也是显而易见的。事实上，卢梭本人也不是“按照”他的教育观念成长的。
这段文字意在说明：','[{"label":"A","content":"家庭教育不应偏信、执着于某一具体理论"},{"label":"B","content":"如何把握家庭教育的尺度始终是一道难题"},{"label":"C","content":"片面强调教育“超量”“减量”都不可取"},{"label":"D","content":"“教育超量”与教育不足都有其生存的土壤"}]','C','文段分析见批注。
文段开篇直接指出当前家庭教育存在教育超量与教育不足两个问题，之后再依次介绍两个问题。总分结构“总”更重要，C选项即是对两个问题的概括，当选；
A选项对策有误，原文问题并非“家长偏信或执着于某一具体理论”,排除；B选项表述过于宽泛，“把握家庭教育尺度是难题”不如“教育超量”、“教育不足”具体，排除；D选项的“有其生存土壤”无中生有且未体现问题，排除。

花生批注：
⑮ 行文结构：总分结构。
文段开篇直接指出当前家庭教育存在教育超量与教育不足两个问题；
之后依次分析介绍教育超量、教育不足问题。
这段文字接下来最不可能讲述的是：⑬
A. 为什么情绪会传染 B. 什么是情绪感染
C. 哪种人更易被情绪感染 D. 如何提升自身的情绪感染力
⑯ 虽然C选项未提到“家庭教育”,但“教育超量”与“教育减量”和题干中的问题一一对应；与A选项的对策有误相比，C选项缺少“家庭”二字，问题相对较轻。','2020年事业单位联考','进阶','published','{"globalNumber":127,"setNumber":7,"localNumber":7,"sourceLabel":"2020年事业单位联考 58%","accuracy":58,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"当下的家庭教育中，“教育超量”与教育不足同时存在。有些家长唯恐自己的孩子“输在起跑线上”, 为孩子报了多个辅导班、兴趣班，给孩子造成很重的负担。也有家长认为孩子还小，不必学什么, 让孩子自由成长就行。这种自然教育的观念，与西方教育思想的影响有关。卢梭在《爱弥儿》中就讲，“要放任无为，才能一切有为”“你开头什么都不教，结果反而会创造一切教育奇迹”,卢梭的这些说法有一定的启发性，但其片面性也是显而易见的。事实上，卢梭本人也不是“按照”他的教育观念成长的。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"家庭教育不应偏信、执着于某一具体理论"}],"B":[{"text":"如何把握家庭教育的尺度始终是一道难题"}],"C":[{"text":"片面强调教育“超量”“减量”都不可取"}],"D":[{"text":"“教育超量”与教育不足都有其生存的土壤"}]},"annotatedStemRich":[{"text":"当下的家庭教育中，“教育超量”与教育不足同时存在(提出两方面问题)。有些家长唯恐自己的孩子“输在起跑线上”,为孩子报了多个辅导班、兴趣班，给孩子造成很重的负担(分析教育超量问题)。也有家长认为孩子还小，不必学什么,让孩子自由成长就行。这种自然教育的观念，与西方教育思想的影响有关。卢梭在《爱弥儿》中就讲，“要放任无为，才能一切有为”“你开头什么都不教，结果反而会创造一切教育奇迹”,卢梭的这些说法有一定的启发性，但其片面性也是显而易见的。事实上，卢梭本人也不是“按照”他的教育观念成长的(分析教育不足问题)。⑤\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"家庭教育不应偏信、执着于某一具体理论(对策有误)"}],"B":[{"text":"如何把握家庭教育的尺度始终是一道难题(宽泛不具体)"}],"C":[{"text":"片面强调教育“超量”“减量”都不可取"}],"D":[{"text":"“教育超量”与教育不足都有其生存的土壤(中性表达且无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段开篇直接指出当前家庭教育存在教育超量与教育不足两个问题，之后再依次介绍两个问题。总分结构“总”更重要，C选项即是对两个问题的概括，当选；\nA选项对策有误，原文问题并非“家长偏信或执着于某一具体理论”,排除；B选项表述过于宽泛，“把握家庭教育尺度是难题”不如“教育超量”、“教育不足”具体，排除；D选项的“有其生存土壤”无中生有且未体现问题，排除。","notes":[{"marker":"⑮","content":"行文结构：总分结构。\n文段开篇直接指出当前家庭教育存在教育超量与教育不足两个问题；\n之后依次分析介绍教育超量、教育不足问题。\n这段文字接下来最不可能讲述的是：⑬\nA. 为什么情绪会传染 B. 什么是情绪感染\nC. 哪种人更易被情绪感染 D. 如何提升自身的情绪感染力","matchScore":0.6045,"pairingMode":"content-similarity","order":14},{"marker":"⑯","content":"虽然C选项未提到“家庭教育”,但“教育超量”与“教育减量”和题干中的问题一一对应；与A选项的对策有误相比，C选项缺少“家庭”二字，问题相对较轻。","matchScore":0.3832,"pairingMode":"content-similarity","order":15}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300128,3,'中心理解题','如今的互联网，已远非一个工具，它渗透并影响着深层的社会关系。曾经，浓浓的年味是一句问候、一副春联、一顿年夜饭。而在互联网时代，这些历史悠久的年俗也发生了变化，网络红包已成为过年的新标配。互联网改变的不仅仅是传统民俗，它对政府管理理念、社会治理体系，都产生了积极的促进作用。网络问政越来越被普通群众所接受，微信公众号已成为政务新媒体的重要平台。
上述语段旨在论述：','[{"label":"A","content":"网络红包成为过年的新标配"},{"label":"B","content":"网络促进政务管理与创新"},{"label":"C","content":"互联网深层次影响社会关系"},{"label":"D","content":"网络问政被普通大众接受"}]','C','文段分析见批注。
文段开头直接点出“互联网渗透并影响着深层的社会关系”,后文依次介绍了互联网对传统民俗、政府管理、社会治理的影响，对应C选项，当选；
A选项，B选项，D选项均出自分析介绍部分，且只对应一个方面，可简单排除。

花生批注：
⑱ 行文结构：总分结构。
先提出总观点：
互联网渗透并影响着深层的社会关系；
再从两个角度分析：
①互联网改变传统民俗；
②互联网促进政府管理和社会治理。','2020年福建省事业单位','进阶','published','{"globalNumber":128,"setNumber":7,"localNumber":8,"sourceLabel":"2020年福建省事业单位 66%","accuracy":66,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"如今的互联网，已远非一个工具，它渗透并影响着深层的社会关系。曾经，浓浓的年味是一句问候、一副春联、一顿年夜饭。而在互联网时代，这些历史悠久的年俗也发生了变化，网络红包已成为过年的新标配。互联网改变的不仅仅是传统民俗，它对政府管理理念、社会治理体系，都产生了积极的促进作用。网络问政越来越被普通群众所接受，微信公众号已成为政务新媒体的重要平台。\n上述语段旨在论述："}],"optionRich":{"A":[{"text":"网络红包成为过年的新标配"}],"B":[{"text":"网络促进政务管理与创新"}],"C":[{"text":"互联网深层次影响社会关系"}],"D":[{"text":"网络问政被普通大众接受"}]},"annotatedStemRich":[{"text":"如今的"},{"text":"互联网","underline":true},{"text":"①,已远非一个工具，它渗透并影响着深层的社会关系( 提出观点)。曾经，浓浓的年味是一句问候、一副春联、一顿年夜饭。而在互联网时代，这些历史悠久的年俗也发生了变化，网络红包已成为过年的新标配(互联网改变传统民俗)。互联网改变的不仅仅是传统民俗，它对政府管理理念、社会治理体系，都产生了积极的促进作用。网络问政越来越被普通群众所接受，微信公众号已成为政务新媒体的重要平台(互联网促进政府管理和社会治理)。\n上述语段旨在论述："}],"annotatedOptionRich":{"A":[{"text":"网络红包成为过年的新标配( 片面 )"}],"B":[{"text":"网络促进政务管理与创新( 片面 )"}],"C":[{"text":"互联网深层次影响社会关系"}],"D":[{"text":"网络问政被普通大众接受(片面)"}]},"practicalAnalysis":"文段分析见批注。\n文段开头直接点出“互联网渗透并影响着深层的社会关系”,后文依次介绍了互联网对传统民俗、政府管理、社会治理的影响，对应C选项，当选；\nA选项，B选项，D选项均出自分析介绍部分，且只对应一个方面，可简单排除。","notes":[{"marker":"⑱","content":"行文结构：总分结构。\n先提出总观点：\n互联网渗透并影响着深层的社会关系；\n再从两个角度分析：\n①互联网改变传统民俗；\n②互联网促进政府管理和社会治理。","matchScore":0.7984,"pairingMode":"content-similarity","order":17}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300129,3,'中心理解题','在任何以创新驱动经济增长的国家里，政府从来都没有成为私营企业的掣肘，相反，它一直是私营企业最重要的合作伙伴，因为只有政府才能让创新企业获得更好的发展，才能让创新成为企业的唯一选项。在关系到国家战略和未来竞争力的关键领域，政府经常表现得比企业更为大胆，有时甚至堪称激进。正是政府与企业合作奠定了技术基础，才能不断出现经济结构的转变和升级。
这段文字主要说明了：','[{"label":"A","content":"创新能力是企业发展的核心竞争力"},{"label":"B","content":"经济结构转型能释放企业的创新力"},{"label":"C","content":"企业是政府实现创新的载体"},{"label":"D","content":"政府应为企业创新保驾护航"}]','D','文段只有两句话，分别介绍了政府可以帮助私营企业创新和政府和企业合作可为经济结构转型升级奠定技术基础，谈论主体均为“政府”;
A选项、B选项未提及“政府”,可简单排除；C选项的论述主体为“企业”, 排除；
文段可理解为“政府有助于企业创新”,即政府应帮助企业创新，对应D选项，当选。

花生批注：
⑲ 政府是全文论述主体。
这段文字主要说明了：
A. 创新能力是企业发展的核心竞争力(无中生有且缺少关键词)
B. 经济结构转型能释放企业的创新力(出处有误)
C. 企业是政府实现创新的载体(中性表述)
D. 政府应为企业创新保驾护航
③ “用碳纳米管做月球乘人电梯”并非碳纳米管功用，而是用这种夸张的例子突出碳纳米管比重轻强度高的特点。
例如：这块木板就算站上十头大象，也压不断；不是在介绍“能乘大象”的功用，而是突出它的质量好。
文段通篇围绕“碳纳米管”开展介绍，碳纳米管为全文论述主体，C选项、 D选项未提及“碳纳米管”,可简单排除；
B选项只对应中间一句：碳纳米管适合做防弹背心，但未体现碳纳米管的特点；③
A选项，“奇妙”一词可对应碳纳米管与众不同的特点，并且“奇妙”一词做标题可吸引人阅读，当选。','2016年黑龙江省考','基础','published','{"globalNumber":129,"setNumber":7,"localNumber":9,"sourceLabel":"2016年黑龙江省考 75%","accuracy":75,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"在任何以创新驱动经济增长的国家里，政府从来都没有成为私营企业的掣肘，相反，它一直是私营企业最重要的合作伙伴，因为只有政府才能让创新企业获得更好的发展，才能让创新成为企业的唯一选项。在关系到国家战略和未来竞争力的关键领域，政府经常表现得比企业更为大胆，有时甚至堪称激进。正是政府与企业合作奠定了技术基础，才能不断出现经济结构的转变和升级。\n这段文字主要说明了："}],"optionRich":{"A":[{"text":"创新能力是企业发展的核心竞争力"}],"B":[{"text":"经济结构转型能释放企业的创新力"}],"C":[{"text":"企业是政府实现创新的载体"}],"D":[{"text":"政府应为企业创新保驾护航"}]},"annotatedStemRich":[{"text":"在任何以创新驱动经济增长的国家里，"},{"text":"政府","underline":true},{"text":"③从来都没有成为私营企业的掣肘，相反，它一直是私营企业最重要的合作伙伴，因为只有政府才能让创新企业获得更好的发展，才能让创新成为企业的唯一选项(政府可以帮助私营企业创新)。在关系到国家战略和未来竞争力的关键领域，政府经常表现得比企业更为大胆，有时甚至堪称激进。正是政府与企业合作奠定了技术基础，才能不断出现经济结构的转变和升级(政府和企业合作可为经济结构转型升级奠定技术基础)。\n这段文字主要说明了："}],"annotatedOptionRich":{"A":[{"text":"创新能力是企业发展的核心竞争力(无中生有且缺少关键词)"}],"B":[{"text":"经济结构转型能释放企业的创新力(出处有误)"}],"C":[{"text":"企业是政府实现创新的载体(中性表述)"}],"D":[{"text":"政府应为企业创新保驾护航"}]},"practicalAnalysis":"文段只有两句话，分别介绍了政府可以帮助私营企业创新和政府和企业合作可为经济结构转型升级奠定技术基础，谈论主体均为“政府”;\nA选项、B选项未提及“政府”,可简单排除；C选项的论述主体为“企业”, 排除；\n文段可理解为“政府有助于企业创新”,即政府应帮助企业创新，对应D选项，当选。","notes":[{"marker":"⑲","content":"政府是全文论述主体。\n这段文字主要说明了：\nA. 创新能力是企业发展的核心竞争力(无中生有且缺少关键词)\nB. 经济结构转型能释放企业的创新力(出处有误)\nC. 企业是政府实现创新的载体(中性表述)\nD. 政府应为企业创新保驾护航","matchScore":0.4315,"pairingMode":"content-similarity","order":18},{"marker":"③","content":"“用碳纳米管做月球乘人电梯”并非碳纳米管功用，而是用这种夸张的例子突出碳纳米管比重轻强度高的特点。\n例如：这块木板就算站上十头大象，也压不断；不是在介绍“能乘大象”的功用，而是突出它的质量好。\n文段通篇围绕“碳纳米管”开展介绍，碳纳米管为全文论述主体，C选项、 D选项未提及“碳纳米管”,可简单排除；\nB选项只对应中间一句：碳纳米管适合做防弹背心，但未体现碳纳米管的特点；③\nA选项，“奇妙”一词可对应碳纳米管与众不同的特点，并且“奇妙”一词做标题可吸引人阅读，当选。","matchScore":0.2217,"pairingMode":"marker-and-content","order":29}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300130,3,'语句填入类','如今，人工智能已经度过了最初的萌芽阶段，正在迅速渗透进生活的方方面面，它的边界也在不断变化和扩展。比如，人们最初会为计算器的计算速度惊诧，将其视作智能，但现在它不过是小学生都能使用的辅助工具。正如《2030年全球人工智能的发展前景》报告中所说，人工智能正在形成一种“人工智能效应”,它“总会将一种新技术带入人们的生活，而一旦人们习惯了这种技术，它便不再被认为是人工智能”。或许，人工智能并不是“忽如一夜春风来”,而是以一种“润物细无声”的姿态存在。从这一层面上来说，
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"人工智能的边界正日益扩展"},{"label":"B","content":"人工智能具有一定的时效性"},{"label":"C","content":"人工智能时代早已来临"},{"label":"D","content":"新技术才是人工智能时代的标志"}]','C','文段分析见批注。
文段开篇介绍人工智能已度过萌芽阶段，正在迅速渗透进生活的方方面面；中间分析解释；文末继续分析人工智能所处阶段(即人工智能不是突然间到来，而是不知不觉来到我们身边),可猜测文段为总分总结构，尾句应对人工智能所处阶段加以总结，且注意要呼应首句；
C选项是对人工智能现在所处阶段的总结，承接上句，与首句呼应，逻辑正确，当选；
A选项，虽然首句提到“人工智能的边界在不断变化和扩展”,但下文重点谈论的是人工智能“什么时候来的”,而非它的边界范围，排除；
B选项的“时效性②”和D选项的“新技术是标志”均为无中生有，排除。

花生批注：
② 行文结构：总分总结构。
文段开篇介绍人工智能已度过萌芽阶段，正在迅速渗透进生活的方方面面；
中间分析解释；
文末继续分析人工智能所处阶段(人工智能不是突然间到来，而是不知不觉来到我们身边);
尾句应对人工智能所处阶段加以总结，且注意要呼应首句。
填入文中画横线部分最恰当的一项是：
A. 人工智能的边界正日益扩展(片面)
B. 人工智能具有一定的时效性(无中生有)
C. 人工智能时代早已来临
D. 新技术才是人工智能时代的标志(无中生有)
② 时效性是指同一件事物在不同的时间具有很大的性质上的差异，我们管这个差异性叫时效性。时效性影响着决策的生效时间，时效性决定了决策在特定时间内是否有效。
例如：比如报纸、新闻节目，今天听了是新闻，明天听了就是旧闻，我们就说报纸、新闻节目具有时效性；比如冬天雪糕不好卖，夏天雪糕可能脱销，我们就说雪糕这个商品具有时效性。','2018年新疆省考','进阶','published','{"globalNumber":130,"setNumber":7,"localNumber":10,"sourceLabel":"2018年新疆省考65%","accuracy":65,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"如今，人工智能已经度过了最初的萌芽阶段，正在迅速渗透进生活的方方面面，它的边界也在不断变化和扩展。比如，人们最初会为计算器的计算速度惊诧，将其视作智能，但现在它不过是小学生都能使用的辅助工具。正如《2030年全球人工智能的发展前景》报告中所说，人工智能正在形成一种“人工智能效应”,它“总会将一种新技术带入人们的生活，而一旦人们习惯了这种技术，它便不再被认为是人工智能”。或许，人工智能并不是“忽如一夜春风来”,而是以一种“润物细无声”的姿态存在。从这一层面上来说，"},{"text":"                          ","underline":true},{"text":"\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"人工智能的边界正日益扩展"}],"B":[{"text":"人工智能具有一定的时效性"}],"C":[{"text":"人工智能时代早已来临"}],"D":[{"text":"新技术才是人工智能时代的标志"}]},"annotatedStemRich":[{"text":"如今，人工智能已经度过了最初的萌芽阶段，正在迅速渗透进生活的方方面面，它的边界也在不断变化和扩展(总 ) 。比如，人们最初会为计算器的计算速度惊诧，将其视作智能，但现在它不过是小学生都能使用的辅助工具。正如《2030年全球人工智能的发展前景》报告中所说，人工智能正在形成一种“人工智能效应”,它“总会将一种新技术带入人们的生活，而一旦人们习惯了这种技术，它便不再被认为是人工智能”(分)。或许，人工智能并不是“忽如一夜春风来”,而是以一种“润物细无声”的姿态存在。从这一层面上来说， "},{"text":" ","underline":true},{"text":" ( 总 ) 。②\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"人工智能的边界正日益扩展(片面)"}],"B":[{"text":"人工智能具有一定的时效性(无中生有)"}],"C":[{"text":"人工智能时代早已来临"}],"D":[{"text":"新技术才是人工智能时代的标志(无中生有)\n3花生批注：\n有同学可能会有疑惑：不是只有生态修复方面才提到“新科技”吗?\n文段为大并列结构，四个方面均突出“低碳环保”,正确选项一定要包含，C 选项、 D 选项可直接排除，B选项又过于片面，答案只能为A 选项；\nA 选项的“新科技”可以这样理解：虽然并非每个方面都提及科技，但根据常识可知：“推动场馆节能改造，打造低碳场馆”、“规模化应用清洁能源车辆、智能化管理”、\"建立绿色电力交易机制、实现100%绿电供应”中应涉及“新科技”, A 选项的“新科技”问题远较其他选项轻微且符合常识，要"}]},"practicalAnalysis":"文段分析见批注。\n文段开篇介绍人工智能已度过萌芽阶段，正在迅速渗透进生活的方方面面；中间分析解释；文末继续分析人工智能所处阶段(即人工智能不是突然间到来，而是不知不觉来到我们身边),可猜测文段为总分总结构，尾句应对人工智能所处阶段加以总结，且注意要呼应首句；\nC选项是对人工智能现在所处阶段的总结，承接上句，与首句呼应，逻辑正确，当选；\nA选项，虽然首句提到“人工智能的边界在不断变化和扩展”,但下文重点谈论的是人工智能“什么时候来的”,而非它的边界范围，排除；\nB选项的“时效性②”和D选项的“新技术是标志”均为无中生有，排除。","notes":[{"marker":"②","content":"行文结构：总分总结构。\n文段开篇介绍人工智能已度过萌芽阶段，正在迅速渗透进生活的方方面面；\n中间分析解释；\n文末继续分析人工智能所处阶段(人工智能不是突然间到来，而是不知不觉来到我们身边);\n尾句应对人工智能所处阶段加以总结，且注意要呼应首句。\n填入文中画横线部分最恰当的一项是：\nA. 人工智能的边界正日益扩展(片面)\nB. 人工智能具有一定的时效性(无中生有)\nC. 人工智能时代早已来临\nD. 新技术才是人工智能时代的标志(无中生有)","matchScore":1.0197,"pairingMode":"marker-and-content","order":19},{"marker":"②","content":"时效性是指同一件事物在不同的时间具有很大的性质上的差异，我们管这个差异性叫时效性。时效性影响着决策的生效时间，时效性决定了决策在特定时间内是否有效。\n例如：比如报纸、新闻节目，今天听了是新闻，明天听了就是旧闻，我们就说报纸、新闻节目具有时效性；比如冬天雪糕不好卖，夏天雪糕可能脱销，我们就说雪糕这个商品具有时效性。","matchScore":0.1041,"pairingMode":"marker-and-content","order":20}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300131,3,'中心理解题','与东京奥运会相比，北京2022年冬奥会在这些方面下了大功夫：在场馆筹建方面，不仅最大限度地利用现有场馆和设施，而且制定了更严格的绿色建筑标准，推动场馆节能改造，打造冬奥低碳场馆；在交通方面，规模化应用清洁能源车辆，通过智能化管理提升交通运行效率，构建冬奥低碳交通体系；在可再生能源利用方面，建立跨区域绿色电力交易机制，实现冬奥场馆100%绿电供应；在生态修复方面，尽可能减少人工建筑和人为活动对生态环境的干扰，应用技术创新促进生态修复，为赛事实现碳中和奠定坚实基础。
这段文字意在说明，北京2022年冬奥会：','[{"label":"A","content":"重视发挥新科技实现碳中和的作用"},{"label":"B","content":"为赛事构建低碳交通体系奠定基础"},{"label":"C","content":"在场馆、交通、能源和生态方面狠下功夫"},{"label":"D","content":"重视新科技在场馆、交通、能源和生态方面的作用"}]','A','文段分析见批注。
文段为大并列结构，依次介绍北京冬奥会在场馆筹建、交通、可再生能源利用及生态修复方面所下的“大功夫”:绿色标准、节能改造、低碳场馆、清洁能源车辆、低碳交通体系、绿电供应、实现碳中和等；正确选项应体现贯穿全文的“低碳环保”;
观察选项：B选项只对应“交通方面”,片面；C选项“狠下功夫”过于宽泛，未体现“低碳环保”,可简单排除；

花生批注：
2 行文结构：大并列结构。
首句引出话题：
北京冬奥会下了大功夫；
通过并列结构依次介绍：
①场馆方面：制定绿色建筑标准，推动节能改造；
②交通方面：应用清洁能源车辆，构建低碳交通体系；
③可再生能源利用方面：建立绿色电力交易机制；
④生态修复方面：应用技术创新促进生态修复，为碳中和奠定基础。
A选项提到“新科技”和“碳中和”②,D选项只提到“新科技”,二者对比， A选项更为全面，当选。','2022年重庆市事业单位','挑战','published','{"globalNumber":131,"setNumber":7,"localNumber":11,"sourceLabel":"2022年重庆市事业单位34%","accuracy":34,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"与东京奥运会相比，北京2022年冬奥会在这些方面下了大功夫：在场馆筹建方面，不仅最大限度地利用现有场馆和设施，而且制定了更严格的绿色建筑标准，推动场馆节能改造，打造冬奥低碳场馆；在交通方面，规模化应用清洁能源车辆，通过智能化管理提升交通运行效率，构建冬奥低碳交通体系；在可再生能源利用方面，建立跨区域绿色电力交易机制，实现冬奥场馆100%绿电供应；在生态修复方面，尽可能减少人工建筑和人为活动对生态环境的干扰，应用技术创新促进生态修复，为赛事实现碳中和奠定坚实基础。\n这段文字意在说明，北京2022年冬奥会："}],"optionRich":{"A":[{"text":"重视发挥新科技实现碳中和的作用"}],"B":[{"text":"为赛事构建低碳交通体系奠定基础"}],"C":[{"text":"在场馆、交通、能源和生态方面狠下功夫"}],"D":[{"text":"重视新科技在场馆、交通、能源和生态方面的作用"}]},"annotatedStemRich":[{"text":"与东京奥运会相比，北京2022年冬奥会在这些方面下了大功夫(引出话题) 在场馆筹建方面，不仅最大限度地利用现有场馆和设施，而且制定了更严格的绿色建筑标准，推动场馆节能改造，打造冬奥低碳场馆(场馆方面); 在交通方面，规模化应用清洁能源车辆，通过智能化管理提升交通运行效率，构建冬奥低碳交通体系(交通方面);在可再生能源利用方面，建立跨区域绿色电力交易机制，实现冬奥场馆100%绿电供应(可再生能源利用方面); 在生态修复方面，尽可能减少人工建筑和人为活动对生态环境的干扰，应用技术创新促\n进生态修复，为赛事实现碳中和奠定坚实基础(生态修复方面)。② 这段文字意在说明，北京2022年冬奥会："}],"annotatedOptionRich":{"A":[{"text":"重视发挥新科技实现碳中和的作用"}],"B":[{"text":"为赛事构建低碳交通体系奠定基础(片面)"}],"C":[{"text":"在场馆、交通、能源和生态方面狠下功夫(缺少关键词)"}],"D":[{"text":"重视新科技在场馆、交通、能源和生态方面的作用(缺少关键词)"}]},"practicalAnalysis":"文段分析见批注。\n文段为大并列结构，依次介绍北京冬奥会在场馆筹建、交通、可再生能源利用及生态修复方面所下的“大功夫”:绿色标准、节能改造、低碳场馆、清洁能源车辆、低碳交通体系、绿电供应、实现碳中和等；正确选项应体现贯穿全文的“低碳环保”;\n观察选项：B选项只对应“交通方面”,片面；C选项“狠下功夫”过于宽泛，未体现“低碳环保”,可简单排除；","notes":[{"marker":"2","content":"行文结构：大并列结构。\n首句引出话题：\n北京冬奥会下了大功夫；\n通过并列结构依次介绍：\n①场馆方面：制定绿色建筑标准，推动节能改造；\n②交通方面：应用清洁能源车辆，构建低碳交通体系；\n③可再生能源利用方面：建立绿色电力交易机制；\n④生态修复方面：应用技术创新促进生态修复，为碳中和奠定基础。\nA选项提到“新科技”和“碳中和”②,D选项只提到“新科技”,二者对比， A选项更为全面，当选。","matchScore":0.8998,"pairingMode":"marker-and-content","order":21}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300132,3,'语句填入类','人口向城市迁移并不一定会推动经济增长和生产率的提高。如果人口流入城市，却没有优质的就业作为依托，就会导致城市的贫民窟化。只有经济结构根据经济发展阶段进行转换，经济才会增长，并创造良好的就业机会，收入才会随之增加，人口才会向城市迁移。所以，。填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"人口向城市迁移是经济发展的必然趋势"},{"label":"B","content":"人口迁移率是衡量经济发展水平的重要指标"},{"label":"C","content":"只有调整经济结构，才能增加城市中的就业机会"},{"label":"D","content":"城镇化其实是经济发展的结果，而非前提"}]','D','所填入语句在文末，可猜测其是对上文的概括总结。上文依次介绍：①人口向城市迁移不一定会带来经济发展；②经济发展才会带来人口向城市迁移；
观察选项，D选项为“A 且B”类选项，可验证是否一一对应：①“人口向城市迁移不一定会带来经济发展”,即“城镇化不是经济发展的前提”;② “只有经济发展才会带来人口向城市迁移”,即“城镇化是经济发展的结果”, 完美对应，当选；
A选项的“必然趋势”无中生有，也过于绝对，排除；B选项的观点与原文“人口迁移不一定会推动经济增长”相悖，排除；C选项与前文“只有经济结构根据经济发展阶段进行转换，经济才会增长并创造良好的就业机会”重复，排除。','2019年国家公务员考试','进阶','published','{"globalNumber":132,"setNumber":7,"localNumber":12,"sourceLabel":"2019年国家公务员考试50%","accuracy":50,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"人口向城市迁移并不一定会推动经济增长和生产率的提高。如果人口流入城市，却没有优质的就业作为依托，就会导致城市的贫民窟化。只有经济结构根据经济发展阶段进行转换，经济才会增长，并创造良好的就业机会，收入才会随之增加，人口才会向城市迁移。所以，"},{"text":"                         ","underline":true},{"text":" 。填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"人口向城市迁移是经济发展的必然趋势"}],"B":[{"text":"人口迁移率是衡量经济发展水平的重要指标"}],"C":[{"text":"只有调整经济结构，才能增加城市中的就业机会"}],"D":[{"text":"城镇化其实是经济发展的结果，而非前提"}]},"annotatedStemRich":[{"text":"人口向城市迁移并不一定会推动经济增长和生产率的提高。如果人口流入城市，却没有优质的就业作为依托，就会导致城市的贫民窟化(人口向城市迁移不一定会带来经济发展)。只有经济结构根据经济发展阶段进行转换，经济才会增长，并创造良好的就业机会，收入才会随之增加，人口才会向城市迁移(只有经济发展才会带来人口向城市迁移)。所以，"},{"text":"                         ","underline":true},{"text":"\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"人口向城市迁移是经济发展的必然趋势(绝对化)"}],"B":[{"text":"人口迁移率是衡量经济发展水平的重要指标"},{"text":"(本身有误)","bold":true}],"C":[{"text":"只有调整经济结构，才能增加城市中的就业机会(语义重复)"}],"D":[{"text":"城镇化其实是经济发展的结果，而非前提( A 且B 类 )"}]},"practicalAnalysis":"所填入语句在文末，可猜测其是对上文的概括总结。上文依次介绍：①人口向城市迁移不一定会带来经济发展；②经济发展才会带来人口向城市迁移；\n观察选项，D选项为“A 且B”类选项，可验证是否一一对应：①“人口向城市迁移不一定会带来经济发展”,即“城镇化不是经济发展的前提”;② “只有经济发展才会带来人口向城市迁移”,即“城镇化是经济发展的结果”, 完美对应，当选；\nA选项的“必然趋势”无中生有，也过于绝对，排除；B选项的观点与原文“人口迁移不一定会推动经济增长”相悖，排除；C选项与前文“只有经济结构根据经济发展阶段进行转换，经济才会增长并创造良好的就业机会”重复，排除。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300133,3,'中心理解题','目前许多农业电子商务网站的前身是农业信息服务网站，本身并不具备商业目的性，因而在转变为电子商务网站之初，将首要目标定位在吸引更多人关注和增加网站流量而非如何发挥商业价值上。在这种思路指导下，大多数农业电子商务网站往往重视网站的“新、全、奇”特点，打出“中国最大”“全国第一”的口号，以期获得更多的点击率和流量，但这并不能让市场和网民对这些网站有全面的了解，因此其中大量的信息资源并不被人所知，其商业价值也无法发挥出来。
这段文字的主要意思是：','[{"label":"A","content":"农业电子商务网站过多地侧重信息服务功能"},{"label":"B","content":"农业电子商务网站在实现商业目的上做得不够"},{"label":"C","content":"农业电子商务网站成功地获得网站流量和关注"},{"label":"D","content":"农业电子商务网站应注重宣传的真实性和创新性"}]','B','文段分析见批注。
文段转折前分析介绍了农业电子商务网站为何制定并实施了现有的发展思路，转折后指出问题：现有的发展思路让网站的信息资源不被人所知，商业价值无法发挥，B选项概括了这一问题，当选；
A选项本身有误，文段说“网站侧重点击率和人气”、“大量信息资源不被人所知”,并非“过多侧重信息服务功能”,错误； C选项未体现问题且“成功地获得了流量和关注”无中生有，排除；D选项对策有误，“注重宣传的真实性与创新性”无法解决“商业价值无法发挥”这一问题，排除。

花生批注：
25 转折后指出这样的发展思路并不能发挥商业价值。
26 实战秒杀：
首句介绍该网站本身不具备“商业目的性”,下文介绍现有的做法也无法发挥“商业价值”,直接锁定B选项。
这段文字的主要意思是：
A. 农业电子商务网站过多地侧重信息服务功能(本身有误)
B. 农业电子商务网站在实现商业目的上做得不够
C. 农业电子商务网站成功地获得网站流量和关注(中性表达且无中生有)','2019年黑龙江省考','进阶','published','{"globalNumber":133,"setNumber":7,"localNumber":13,"sourceLabel":"2019年黑龙江省考 57%","accuracy":57,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"目前许多农业电子商务网站的前身是农业信息服务网站，本身并不具备商业目的性，因而在转变为电子商务网站之初，将首要目标定位在吸引更多人关注和增加网站流量而非如何发挥商业价值上。在这种思路指导下，大多数农业电子商务网站往往重视网站的“新、全、奇”特点，打出“中国最大”“全国第一”的口号，以期获得更多的点击率和流量，但这并不能让市场和网民对这些网站有全面的了解，因此其中大量的信息资源并不被人所知，其商业价值也无法发挥出来。\n这段文字的主要意思是："}],"optionRich":{"A":[{"text":"农业电子商务网站过多地侧重信息服务功能"}],"B":[{"text":"农业电子商务网站在实现商业目的上做得不够"}],"C":[{"text":"农业电子商务网站成功地获得网站流量和关注"}],"D":[{"text":"农业电子商务网站应注重宣传的真实性和创新性"}]},"annotatedStemRich":[{"text":"目前许多农业电子商务网站的前身是农业信息服务网站，本身并不具备商业目的性，因而在转变为电子商务网站之初，将首要目标定位在吸引更多人关注和增加网站流量而非如何发挥商业价值上。在这种思路指导下，大多数农业电子商务网站往往重视网站的“新、全、奇”特点，打出“中国最大”“全国第一”的口号，以期获得更多的点击率和流量(介绍农业电子商务网站的现状), 但这并不能让市场和网民对这些网站有全面的了解，因此其中大量的信息资源并不被人所知，其商业价值也无法发挥出来(转折提出问题)。\n只有经济发展才会带来人口向城市迁移；\n即先有经济发展，再有城镇化；\n即城镇化是经济发展的结果。\n25花生批注：\n转折后指出这样的发展思路并不能发挥商业价值。\n26花生批注：\n实战秒杀：\n首句介绍该网站本身不具备“商业目的性”,下文介绍现有的做法也无法发挥“商业价值”,直接锁定B 选项。\n这段文字的主要意思是："}],"annotatedOptionRich":{"A":[{"text":"农业电子商务网站过多地侧重信息服务功能(本身有误)"}],"B":[{"text":"农业电子商务网站在实现商业目的上做得不够"}],"C":[{"text":"农业电子商务网站成功地获得网站流量和关注(中性表达且无中生有)"}],"D":[{"text":"农业电子商务网站应注重宣传的真实性和创新性(对策不针对问题)"}]},"practicalAnalysis":"文段分析见批注。\n文段转折前分析介绍了农业电子商务网站为何制定并实施了现有的发展思路，转折后指出问题：现有的发展思路让网站的信息资源不被人所知，商业价值无法发挥，B选项概括了这一问题，当选；\nA选项本身有误，文段说“网站侧重点击率和人气”、“大量信息资源不被人所知”,并非“过多侧重信息服务功能”,错误； C选项未体现问题且“成功地获得了流量和关注”无中生有，排除；D选项对策有误，“注重宣传的真实性与创新性”无法解决“商业价值无法发挥”这一问题，排除。","notes":[{"marker":"25","content":"转折后指出这样的发展思路并不能发挥商业价值。","matchScore":1.0549,"pairingMode":"content-similarity","order":23},{"marker":"26","content":"实战秒杀：\n首句介绍该网站本身不具备“商业目的性”,下文介绍现有的做法也无法发挥“商业价值”,直接锁定B选项。\n这段文字的主要意思是：\nA. 农业电子商务网站过多地侧重信息服务功能(本身有误)\nB. 农业电子商务网站在实现商业目的上做得不够\nC. 农业电子商务网站成功地获得网站流量和关注(中性表达且无中生有)","matchScore":0.9854,"pairingMode":"content-similarity","order":24}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300134,3,'标题拟定类','企业“上云”不止提升自身竞争力，也可为智慧城市贡献一份力量。最近杭州市政府和阿里云、富士康共同发布的“杭州城市数据大脑”,运用人工智能技术对城市进行全局实时分析，自动调配公共资源，解决城市治理中的棘手问题。开放的算法平台使城市大脑可以广泛吸取智慧，从互联网+ 信号灯到智能物流配送，任何优良算法都可以放入城市大脑的插槽中。同时，智慧城市建设不能仅靠一家企业单打独斗，政府需要提供引导平台，把碎片化产品加以整合。走上云端的浙企，让浙江乃至中国看到了下一代社会治理结构的美好未来。
