INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300135,3,'标题拟定类','碳纳米管是由石墨中一层或若干层碳原子卷曲而成的笼状“纤维”,内部是空的，外部直径只是几到几十纳米，比重只有钢的六分之一，而强度却是钢的100倍。轻而柔软又非常结实的材料，是做防弹背心的最佳选择。如果用碳纳米管做绳索，是从月球上挂到地球表面，而唯一不被自身重量所拉断的绳索。如果用它做成地球一月球乘人的电梯，人们在月球定居就很容易了。
