INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300136,3,'语句填入类','这些年西汉纸不断出土，从材料上看，西汉纸大多夹带许多未被捣碎的纤维团，这种纸制作粗糙，组织松散，纸浆分布不匀，透眼较多，不太适于落笔着墨，书写起来也不顺畅。西汉纸大多不平整，像被揉搓过一样。出土的很多纸上都没有字，即便有字，也是写在纸的右下角，常见的字有“付子”“细辛”等。经考证它们基本都是汉代的药名。于是有学者推论，如果这类纸用于包装药材，那些写在纸角的字，恰好就会露在药包的表面。这样看来，
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"原来早在蔡伦之前纸就已经被发明出来了"},{"label":"B","content":"纸张成为主要书写工具经历了漫长过程"},{"label":"C","content":"西汉的古纸极有可能主要用来包装东西"},{"label":"D","content":"我国古代造纸起源与中药学发展不无关系"}]','C','文段解析见批注。
所填入语句为尾句且由“这样看来”可知：填入语句应为对前文的总结；
前文依次介绍了西汉纸的三个特点：①西汉纸书写起来不顺畅；②西汉纸大多不平整；③西汉纸右下角有药名，可能用于包装药材；
根据上述特点，可猜测西汉纸极有可能主要用来包装东西，对应 C选项，当选；
其他选项均未提及西汉纸，而且A选项的“发明时间”无中生有；B选项为历程类，原文非介绍整个发展过程；D选项的“造纸起源”无中生有，而且和“中医药发展有关”片面，均排除。

花生批注：
33 行文结构：分总结构。
分1:西汉纸纸质决定书写起来不顺畅；
分2:西汉纸大多不平整，像被揉搓过；
分3:西汉纸右下角有药名，可能用于包装药材；
最后一句应根据上文总结。
这样看来， ( 总 ) 。③
填入文中画横线部分最恰当的一项是：
A. 原来早在蔡伦之前纸就已经被发明出来了(无中生有)
B. 纸张成为主要书写工具经历了漫长过程 (历程类)
C. 西汉的古纸极有可能主要用来包装东西','2020年山东省考','进阶','published','{"globalNumber":136,"setNumber":7,"localNumber":16,"sourceLabel":"2020年山东省考 69%","accuracy":69,"typeAndPassage":"语句填入类+科普介绍文章","stemRich":[{"text":"这些年西汉纸不断出土，从材料上看，西汉纸大多夹带许多未被捣碎的纤维团，这种纸制作粗糙，组织松散，纸浆分布不匀，透眼较多，不太适于落笔着墨，书写起来也不顺畅。西汉纸大多不平整，像被揉搓过一样。出土的很多纸上都没有字，即便有字，也是写在纸的右下角，常见的字有“付子”“细辛”等。经考证它们基本都是汉代的药名。于是有学者推论，如果这类纸用于包装药材，那些写在纸角的字，恰好就会露在药包的表面。这样看来，"},{"text":"                         ","underline":true},{"text":"\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"原来早在蔡伦之前纸就已经被发明出来了"}],"B":[{"text":"纸张成为主要书写工具经历了漫长过程"}],"C":[{"text":"西汉的古纸极有可能主要用来包装东西"}],"D":[{"text":"我国古代造纸起源与中药学发展不无关系"}]},"annotatedStemRich":[{"text":"这些年"},{"text":"西汉纸","underline":true},{"text":"③不断出土，从材料上看，西汉纸大多夹带许多未被捣碎的纤维团，这种纸制作粗糙，组织松散，纸浆分布不匀，透眼较多，不太适于落笔着墨，书写起来也不顺畅"},{"text":"(分1)。","bold":true},{"text":"西汉纸大多不平整，像被揉搓过一样(分2)。出土的很多纸上都没有字，即便有字，也是写在纸的右下角，常见的字有“付子”“细辛”等。经考证它们基本都是汉代的药名。于是有学者推论，如果这类纸用于包装药材，那些写在纸角的字，恰好就会露在药包的表面( 分 3 ) 。\n这样看来，"},{"text":"                       ","underline":true},{"text":" ( 总 ) 。③\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"原来早在蔡伦之前纸就已经被发明出来了(无中生有)"}],"B":[{"text":"纸张成为主要书写工具经历了漫长过程 (历程类)"}],"C":[{"text":"西汉的古纸极有可能主要用来包装东西"}],"D":[{"text":"我国古代造纸起源与中药学发展不无关系(无中生有且片面)"}]},"practicalAnalysis":"文段解析见批注。\n所填入语句为尾句且由“这样看来”可知：填入语句应为对前文的总结；\n前文依次介绍了西汉纸的三个特点：①西汉纸书写起来不顺畅；②西汉纸大多不平整；③西汉纸右下角有药名，可能用于包装药材；\n根据上述特点，可猜测西汉纸极有可能主要用来包装东西，对应 C选项，当选；\n其他选项均未提及西汉纸，而且A选项的“发明时间”无中生有；B选项为历程类，原文非介绍整个发展过程；D选项的“造纸起源”无中生有，而且和“中医药发展有关”片面，均排除。","notes":[{"marker":"33","content":"行文结构：分总结构。\n分1:西汉纸纸质决定书写起来不顺畅；\n分2:西汉纸大多不平整，像被揉搓过；\n分3:西汉纸右下角有药名，可能用于包装药材；\n最后一句应根据上文总结。\n这样看来， ( 总 ) 。③\n填入文中画横线部分最恰当的一项是：\nA. 原来早在蔡伦之前纸就已经被发明出来了(无中生有)\nB. 纸张成为主要书写工具经历了漫长过程 (历程类)\nC. 西汉的古纸极有可能主要用来包装东西","matchScore":0.7891,"pairingMode":"content-similarity","order":31}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300137,3,'语句排序类','①有一种奇特的感觉，肺腑之间最后一缕从城市带来的污浊空气在这里被替换
②那些我能想到的与绿有关的词，都能在这里找到其现实所在
③沿林中石路，走进树荫遮蔽却非常明亮的林中空地，呼吸春茶般的清新
④天地之间，被绿色点缀、绞缠、流绕、覆盖。嫩绿、黛绿、葱绿、碧绿、水绿、豆绿、墨绿 ……
⑤小河的这片水杉林有上千株之多，枝繁叶茂，顶天立地，横成行，竖成队，斜成线，像迎接检阅的威武方阵
⑥通直向上的树干，铺伸空中的枝条，摇曳对生的细叶，天光穿过缝隙，它们像是点燃的一团团蓬松的绿火
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"⑥②④⑤③①"},{"label":"B","content":"③⑥④②①⑤"},{"label":"C","content":"⑤③①⑥④②⑤"},{"label":"D","content":"④⑥②⑤③①"}]','C','观察首句，⑤句引出“水杉林”,③句介绍的是“走进林中”、 ④句介绍的是“林间绿色”、⑥句介绍的是“树干、枝条”,应由⑤引出这片水杉林，再介绍林中景色，⑤做首句的可能性最大；
而且，②句的指示代词“那些”指代④句的“嫩绿、黛绿、葱绿、碧绿、水绿、豆绿、墨绿……“”,④②捆绑，排除A选项、D选项；
另外，只有③①句谈论的是林间的空气，③①话题一致，排除B选项；
综上，正确答案是C选项。

花生批注：
35 行文逻辑如下：
⑤句引出“水杉林”;③① 两句介绍这里的空气很清新，能够替换从城市带来的污浊空气；⑥④②均介绍“林中绿色”。
