INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300138,3,'语句排序类','①如果作家们不想放弃由自己直接来描写对象的权利和责任，就一定要躲避
②例如，一个真正的作家在描写时间时几乎不会用“光阴似箭”“日月如梭”之类的成语
③同样的道理，现代生活中那些互相模仿的四字句现代骈体，听起来整齐而顺口
④成语是人们作一般表述时的拐杖，对文学表述者来说，它很可能变成“类型化”障碍
⑤实际上却造成了接受上的惰性疲倦，又败坏了中国语文的生动风姿
⑥因为那太偷懒了，无论是成语还是定型的形容词，都是经过太多人手的“语言硬块”将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"④②①⑥③⑤"},{"label":"B","content":"④②⑥⑤③①"},{"label":"C","content":""},{"label":"D","content":"④①⑥②③⑤"}]','C','本题首句已确定，可以先从第⑥句的指示代词“那”入手，“那”指代的应是一种偷懒的做法；①的做法为“作家不想放弃自己直接描写对象的权利，要躲避成语”,②的做法可以理解为“描写时使用‘光阴似箭’‘日月如梭’之类的成语”,前者是正确做法，后者是偷懒做法，⑨⑥②捆绑，排除 A选项、D选项；
再辨析尾句，③“听起来整齐顺口”与⑤“实际上却造成了接受上的惰性疲倦”构成了转折关系，③⑤也构成一组论证，C选项逻辑正确，当选。

花生批注：
③④ “那些”指代的是描写绿色的词，②一定在④之后。
36 “那”指代的是一种“偷懒”的做法。
③ 行文结构：前对策结构。
④提出问题：成语会变成“类型化”障碍；
②⑥分析问题：作者使用成语太偷懒了；
①提出对策：作者要避免使用这些成语；
最后③⑤进一步论证：生活中使用四字句现代骈体会造成接受上的惰性疲倦。
38 例如：真正的学习不能直接背诵别人总结的笔记，因为那太偷懒了；
“那”指的是“直接背诵别人总结的笔记”。','2019年新疆事业单位','进阶','published','{"globalNumber":138,"setNumber":7,"localNumber":18,"sourceLabel":"2019年新疆事业单位 66%","accuracy":66,"typeAndPassage":"语句排序类+说理类文章","stemRich":[{"text":"①如果作家们不想放弃由自己直接来描写对象的权利和责任，就一定要躲避\n②例如，一个真正的作家在描写时间时几乎不会用“光阴似箭”“日月如梭”之类的成语\n③同样的道理，现代生活中那些互相模仿的四字句现代骈体，听起来整齐而顺口\n④成语是人们作一般表述时的拐杖，对文学表述者来说，它很可能变成“类型化”障碍\n⑤实际上却造成了接受上的惰性疲倦，又败坏了中国语文的生动风姿\n⑥因为那太偷懒了，无论是成语还是定型的形容词，都是经过太多人手的“语言硬块”将以上6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"④②①⑥③⑤"}],"B":[{"text":"④②⑥⑤③①"}],"C":[{"text":""}],"D":[{"text":"④①⑥②③⑤"}]},"annotatedStemRich":[{"text":"①如果作家们不想放弃由自己直接来描写对象的权利和责任，就一定要躲避\n②例如，一个真正的作家在描写时间时几乎不会用“光阴似箭”“日月如梭”之类的成语\n③同样的道理，现代生活中那些互相模仿的四字句现代骈体，听起来整齐而顺口\n④成语是人们作一般表述时的拐杖，对文学表述者来说，它很可能变成“类型化”障碍\n⑤实际上却造成了接受上的惰性疲倦，又败坏了中国语文的生动风姿\n⑥因为"},{"text":"那太偷懒了","underline":true},{"text":"，无论是成语还是定型的形容词，都是经过太多人手的“语言硬块”\n将以上6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"④②①⑥③⑤"}],"B":[{"text":"④②⑥⑤③①"}],"D":[{"text":"④①⑥②③⑤\n【参考答案】C\n【题型与文段类型】语句排序类+说理类文章\n【实战解析】本题首句已确定，可以先从第⑥句的指示代词“那”入手，“那”指代的应是一种偷懒的做法；①的做法为“作家不想放弃自己直接描写对象的权利，要躲避成语”,"},{"text":"②的做法可以理解为“描写时使用‘光阴似箭’‘日月如梭’之类的成语”,前者是正确做法，后者是偷懒做法，","underline":true},{"text":"⑨⑥②捆绑，排除 A 选项、D 选项；\n再辨析尾句，③“听起来整齐顺口”与⑤“实际上却造成了接受上的惰性疲倦”构成了转折关系，③⑤也构成一组论证，C 选项逻辑正确，当选。"}]},"practicalAnalysis":"本题首句已确定，可以先从第⑥句的指示代词“那”入手，“那”指代的应是一种偷懒的做法；①的做法为“作家不想放弃自己直接描写对象的权利，要躲避成语”,②的做法可以理解为“描写时使用‘光阴似箭’‘日月如梭’之类的成语”,前者是正确做法，后者是偷懒做法，⑨⑥②捆绑，排除 A选项、D选项；\n再辨析尾句，③“听起来整齐顺口”与⑤“实际上却造成了接受上的惰性疲倦”构成了转折关系，③⑤也构成一组论证，C选项逻辑正确，当选。","notes":[{"marker":"③④","content":"“那些”指代的是描写绿色的词，②一定在④之后。","matchScore":0.4182,"pairingMode":"content-similarity","order":32},{"marker":"36","content":"“那”指代的是一种“偷懒”的做法。","matchScore":1.0402,"pairingMode":"content-similarity","order":34},{"marker":"③","content":"行文结构：前对策结构。\n④提出问题：成语会变成“类型化”障碍；\n②⑥分析问题：作者使用成语太偷懒了；\n①提出对策：作者要避免使用这些成语；\n最后③⑤进一步论证：生活中使用四字句现代骈体会造成接受上的惰性疲倦。","matchScore":0.4489,"pairingMode":"marker-and-content","order":35},{"marker":"38","content":"例如：真正的学习不能直接背诵别人总结的笔记，因为那太偷懒了；\n“那”指的是“直接背诵别人总