INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300139,3,'语句填入类','。正如游戏要求团队协作，真正让一款游戏成为广受追捧且健康向上的产品，也需要协同的力量。如果开发团队只考虑市场效益，对游戏内容和形式放任自流，纵使在短时间内能取得佳绩，也会因过度消费用户而败下阵来。如果政府部门只在一些节点上把一把、管一管，纵使出台了一些政策文件，也不过是形式大于效力。如果家长对孩子不管不问或一封到底，纵使气急败坏也无济于事，与其关上游戏的门还不如打开疏导陪伴的窗。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"国产游戏行业的有序发展需要多方的共同努力"},{"label":"B","content":"游戏监管不该只堵不疏而应树立“大监管”理念"},{"label":"C","content":"各方力量紧密合作才能让游戏成为生活的有益补充"},{"label":"D","content":"游戏监管需制作方、政府部门、家长三方形成合力"}]','D','文段分析见批注。

花生批注：
③⑨ 行文结构：总分结构。
开门见山提出观点：(空); 之后举例论证：需要协同的力量；
再从三个角度反面论证：
①开发团队不能对游戏内容和形式放任自流(即要监管);
②政府部门的监管不能流于形式(即要有效监管);
③家长不能不管也不能粗暴的一封到底(即要科学的监管);
从三个角度论述对游戏进行监管的必要性。
(上册)
④ A选项存在两个问题：
①后文的关键词“监管”, A选项没有体现，不如D选项直观具体；
若选择A选项，下文应从“有序发展”角度给出对策，而非从“监管”角度；
② A选项本身也存在问题：文段谈论的是“游戏的监管”,监管和游戏开发团队、政府部门、家长有关，但游戏的有序发展和开发团队、政府部门有关，和家长关系不大。
根据横线后的句子的“正如”可知，下文是举例说明所填入语句，根据下文的“也需要协同的力量”可推知所填入语句也应体现“协同”;
再分析下文，下文是从三个角度进行反面论证：①开发团队不能对游戏内容和形式放任自流(即要监管);②政府部门的监管不能流于形式(即要有效监管);③家长不能不管也不能粗暴的一封到底(即要科学的监管);
综上可知，所填入语句应体现“协同”和“监管”,正对应D选项，且D选项的三个主体与下文一一对应(顺序也正确),完美选项；
A选项、 C选项谈到“协同”但未体现“监管”; B选项谈到“监管”
但未体现“协同”且“大监管理念”无中生有。','2019年四川省考','进阶','published','{"globalNumber":139,"setNumber":7,"localNumber":19,"sourceLabel":"2019年四川省考 56%","accuracy":56,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"。正如游戏要求团队协作，真正让一款游戏成为广受追捧且健康向上的产品，也需要协同的力量。如果开发团队只考虑市场效益，对游戏内容和形式放任自流，纵使在短时间内能取得佳绩，也会因过度消费用户而败下阵来。如果政府部门只在一些节点上把一把、管一管，纵使出台了一些政策文件，也不过是形式大于效力。如果家长对孩子不管不问或一封到底，纵使气急败坏也无济于事，与其关上游戏的门还不如打开疏导陪伴的窗。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"国产游戏行业的有序发展需要多方的共同努力"}],"B":[{"text":"游戏监管不该只堵不疏而应树立“大监管”理念"}],"C":[{"text":"各方力量紧密合作才能让游戏成为生活的有益补充"}],"D":[{"text":"游戏监管需制作方、政府部门、家长三方形成合力"}]},"annotatedStemRich":[{"text":" ","underline":true},{"text":"。正如游戏要求团队协作，真正让一款游戏成为广受追捧且健康向上的产品，也需要协同的力量"},{"text":"(","bold":true},{"text":" "},{"text":"总","bold":true},{"text":" "},{"text":")","bold":true},{"text":" "},{"text":"。","bold":true},{"text":"如果开发团队只考虑市场效益，对游戏内容和形式放任自流，纵使在短时间内能取得佳绩，也会因过度消费用户而败下阵来。如果政府部门只在一些节点上把一把、管一管，纵使出台了一些政策文件，也不过是形式大于效力。如果家长对孩子不管不问或一封到底，纵使气急败坏也无济于事，与其关上游戏的门还不如打开疏导陪伴的窗(从三个角度分析论证)。⑨\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"国产游戏行业的有序发展需要多方的共同努力(片面)"}],"B":[{"text":"游戏监管不该只堵不疏而应树立“大监管”理念(片面且无中生有)"}],"C":[{"text":"各方力量紧密合作才能让游戏成为生活的有益补充(片面)"}],"D":[{"text":"游戏监管需制作方、政府部门、家长三方形成合力"}]},"practicalAnalysis":"文段分析见批注。","notes":[{"marker":"③⑨","content":"行文结构：总分结构。\n开门见山提出观点：(空); 之后举例论证：需要协同的力量；\n再从三个角度反面论证：\n①开发团队不能对游戏内容和形式放任自流(即要监管);\n②政府部门的监管不能流于形式(即要有效监管);\n③家长不能不管也不能粗暴的一封到底(即要科学的监管);\n从三个角度论述对游戏进行监管的必要性。\n(上册)","matchScore":0.5144,"pairingMode":"content-similarity","order":37},{"marker":"④","content":"A选项存在两个问题：\n①后文的关键词“监管”, A选项没有体现，不如D选项直观具体；\n若选择A选项，下文应从“有序发展”角度给出对策，而非从“监管”角度；\n② A选项本身也存在问题：文段谈论的是“游戏的监管”,监管和游戏开发团队、政府部门、家长有关，但游戏的有序发展和开发团队、政府部门有关，和家长关系不大。\n根据横线后的句子的“正如”可知，下文是举例说明所填入语句，根据下文的“也需要协同的力量”可推知所填入语句也应体现“协同”;\n再分析下文，下文是从三个角度进行反面论证：①开发团队不能对游戏内容和形式放任自流(即要监管);②政府部门的监管不能流于形式(即要有效监管);③家长不能不管也不能粗暴的一封到底(即要科学的监管);\n综上可知，所填入语句应体现“协同”和“监管”,正对应D选项，且D选项的三个主体与下文一一对应(顺序也正确),完美选项；\nA选项、 C选项谈到“协同”但未体现“监管”; B选项谈到“监管”\n但未体现“协同”且“大监管理念”无中生有。","matchScore":0.34