INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300142,3,'下文推断类⑥','北京西北郊区的圆明园，曾是中国有史以来最宏伟的皇家园林。在清室150余年的创建和经营下，曾以其宏大的地域规模、杰出的营造技艺、精美的建筑景群、丰富的文化收藏和博大精深的民族文化内涵而享誉于世，被誉为“一切造园艺术的典范”,被法国作家雨果称誉为“理想与艺术的典范”。但先后经英法联军、八国联军洗劫后，终变成一片废墟。也正是因为这样一个由辉煌到衰败的过程，圆明园成为人们旅游的热点景区。
这段话是一篇文章的引言，文章接下来最可能讲的是：','[{"label":"A","content":"圆明园的毁灭过程"},{"label":"B","content":"圆明园的文化遗产"},{"label":"C","content":"圆明园的兴衰历程"},{"label":"D","content":"清王室的生活状况"}]','B','文段先介绍了圆明园的历史，在文末提出当今圆明园成为热点景区，后文很可能介绍圆明园景区的相关情况，对应B选项，圆明园的文化遗产指的是圆明园不可再生、不可替代的宝贵资源，符合逻辑，当选；
A选项和C选项在文段背景介绍部分均已介绍，下文不会重复出现，排除； D选项清王室生活状况无中生有，可以简单排除。

