INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300143,3,'词句理解题','随着权健、无限极等一个个保健品神话的破灭，很多使用保健品的人陷入了恐慌和焦虑中，他们从昔日对保健品的盲目“迷信、依赖”,一下子反转到“怀疑、一棍子打死”,保健品在某些地区甚至成了“骗局”的代名词，成为过街老鼠。但是，一些有识之士在保健品市场冰与火的两极之间，保持了难得的冷静，他们认为，封杀保健品不是目的，管理才是王道。
关于“很多使用保健品的人”对待保健品的表现，以下概括最准确的是：','[{"label":"A","content":"不置可否"},{"label":"B","content":"心有余悸"},{"label":"C","content":"草木皆兵"},{"label":"D","content":"矫枉过正"}]','D','根据首句可知，很多使用保健品的人对待保健品的表现从昔日的盲目“迷信、依赖”,一下子反转到“怀疑、一棍子打死、骗局”;从极度相信到极度不相信，这些人的态度转变超过了正常的限度，正对应“矫枉过正”,D选项正确。

花生批注：
⑦ 不置可否：不说行，也不说不行。指不表明态度。
心有余悸：危险之事虽然已经过去了，回想起来仍感到害怕。
草木皆兵：形容人极度惊慌时疑神疑鬼。
矫枉过正：比喻纠正错误或偏差超过了应有的限度。','2019年吉林省考','进阶','published','{"globalNumber":143,"setNumber":8,"localNumber":3,"sourceLabel":"2019年吉林省考 57%","accuracy":57,"typeAndPassage":"词句理解题","stemRich":[{"text":"随着权健、无限极等一个个保健品神话的破灭，很多使用保健品的人陷入了恐慌和焦虑中，他们从昔日对保健品的盲目“迷信、依赖”,一下子反转到“怀疑、一棍子打死”,保健品在某些地区甚至成了“骗局”的代名词，成为过街老鼠。但是，一些有识之士在保健品市场冰与火的两极之间，保持了难得的冷静，他们认为，封杀保健品不是目的，管理才是王道。\n关于“很多使用保健品的人”对待保健品的表现，以下概括最准确的是："}],"optionRich":{"A":[{"text":"不置可否"}],"B":[{"text":"心有余悸"}],"C":[{"text":"草木皆兵"}],"D":[{"text":"矫枉过正"}]},"annotatedStemRich":[{"text":"随着权健、无限极等一个个保健品神话的破灭，很多使用保健品的人陷入了恐慌和焦虑中，他们从昔日对保健品的盲目“迷信、依赖”,一下子反转到“怀疑、一棍子打死”,保健品在某些地区甚至成了“骗局”的代名词，成为过街老鼠(很多使用保健品的人的态度转变)。但是，一些有识之士在保健品市场冰与火的两极之间，保持了难得的冷静，他们认为，封杀保健品不是目的，管理才是王道 (有识之士对保健品态度很冷静)。\n关于“很多使用保健品的人”对待保健品的表现，以下概括最准确的是："}],"annotatedOptionRich":{"A":[{"text":"不置可否"}],"B":[{"text":"心有余悸"}],"C":[{"text":"草木皆兵"}],"D":[{"text":"矫枉过正","bold":true},{"text":"②"}]},"practicalAnalysis":"根据首句可知，很多使用保健品的人对待保健品的表现从昔日的盲目“迷信、依赖”,一下子反转到“怀疑、一棍子打死、骗局”;从极度相信到极度不相信，这些人的态度转变超过了正常的限度，正对应“矫枉过正”,D选项正确。","notes":[{"marker":"⑦","content":"不置可否：不说行，也不说不行。指不表明态度。\n心有余悸：危险之事虽然已经过去了，回想起来仍感到害怕。\n草木皆兵：形容人极度惊慌时疑神疑鬼。\n矫枉过正：比喻纠正错误或偏差超过了应有的限度。","matchScore":0.177,"pairingMode":"content-similarity","order":6}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300144,3,'细节判断类','广告、点击量变现和会员付费，是现阶段视频平台的三大主要收入来源。从国内近几年的发展态势来看，L 视频平台公司的会员付费模式备受国内同行的青睐和追捧。从2009年到2018年，该公司的市值增长了约60倍，目前高达1293亿美元，在众多科技股中表现抢眼。但即使这样的“巨无霸”, 现在也面临着会员增长的压力，这部分收入未来恐怕难以填补其在原创内容领域巨额投入的缺口。
根据这段文字，下列说法正确的是：','[{"label":"A","content":"L 公司的广告收入没有会员付费收入高"},{"label":"B","content":"L 公司的会员付费模式优于国内视频网站"},{"label":"C","content":"L 公司的市值增长主要依靠会员付费收入"},{"label":"D","content":"L 公司的点击量变现收入比不上国内其他视频网站"}]','B','A选项、D选项原文均没有相关对比表述，均为无中生有，可简单排除；
B选项，第②句"L 视频平台公司的会员付费模式备受国内同行的青睐和追捧”,“备受国内同行青睐和追捧”说明L 公司的会员付费模式可能有优势， B选项可能正确⑧:

花生批注：
⑧ 较难的细节判断经常存在这样的选项设置，一个选项犯了严重的、违背常规逻辑的错误，一个选项稍有“过度”推断但符合常理，此时一定“抓大放小”。
C选项，虽然第②句、第③句有“L 视频平台公司的会员付费模式备受国内同行的青睐和追捧”和“该公司的市值增长了约60倍”的表述，但无法确定L 公司的市值增长主要依靠会员付费收入，属于强加因果；另外根据常识可知：公司的市值增长主要和未来的良好前景有关，市值并非等于当前的实际收入，综上，C选项犯了强加因果和本身有误的错误，排除。','2020年陕西省考','进阶','published','{"globalNumber":144,"setNumber":8,"localNumber":4,"sourceLabel":"2020年陕西省考54%","accuracy":54,"typeAndPassage":"细节判断类","stemRich":[{"text":"广告、点击量变现和会员付费，是现阶段视频平台的三大主要收入来源。从国内近几年的发展态势来看，L 视频平台公司的会员付费模式备受国内同行的青睐和追捧。从2009年到2018年，该公司的市值增长了约60倍，目前高达1293亿美元，在众多科技股中表现抢眼。但即使这样的“巨无霸”, 现在也面临着会员增长的压力，这部分收入未来恐怕难以填补其在原创内容领域巨额投入的缺口。\n根据这段文字，下列说法正确的是："}],"optionRich":{"A":[{"text":"L 公司的广告收入没有会员付费收入高"}],"B":[{"text":"L 公司的会员付费模式优于国内视频网站"}],"C":[{"text":"L 公司的市值增长主要依靠会员付费收入"}],"D":[{"text":"L 公司的点击量变现收入比不上国内其他视频网站"}]},"annotatedStemRich":[{"text":"①广告、点击量变现和会员付费，是现阶段视频平台的三大主要收入来源。\n②从国内近几年的发展态势来看，L 视频平台公司的会员付费模式备受国内同行的青睐和追捧。③从2009年到2018年，该公司的市值增长了约60倍，目前高达1293亿美元，在众多科技股中表现抢眼。④但即使这样的“巨无霸”, 现在也面临着会员增长的压力，这部分收入未来恐怕难以填补其在原创内容领域巨额投入的缺口。\n根据这段文字，下列说法正确的是："}],"annotatedOptionRich":{"A":[{"text":"L 公司的广告收入没有会员付费收入高(无中生有)"}],"B":[{"text":"L 公司的会员付费模式优于国内视频网站"}],"C":[{"text":"L 公司的市值增长主要依靠会员付费收入(强加因果、本身有误)"}],"D":[{"text":"L 公司的点击量变现收入比不上国内其他视频网站(无中生有)"}]},"practicalAnalysis":"A选项、D选项原文均没有相关对比表述，均为无中生有，可简单排除；\nB选项，第②句\"L 视频平台公司的会员付费模式备受国内同行的青睐和追捧”,“备受国内同行青睐和追捧”说明L 公司的会员付费模式可能有优势， B选项可能正确⑧:","notes":[{"marker":"⑧","content":"较难的细节判断经常存在这样的选项设置，一个选项犯了严重的、违背常规逻辑的错误，一个选项稍有“过度”推断但符合常理，此时一定“抓大放小”。\nC选项，虽然第②句、第③句有“L 视频平台公司的会员付费模式备受国内同行的青睐和追捧”和“该公司的市值增长了约60倍”的表述，但无法确定L 公司的市值增长主要依靠会员付费收入，属于强加因果；另外根据常识可知：公司的市值增长主要和未来的良好前景有关，市值并非等于当前的实际收入，综上，C选项犯了强加因果和本身有误的错误，排除。","matchScore":0.4821,"pairingMode":"marker-and-content","order":7}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300145,3,'词句理解题','某市交通管理局曾经推出一个创意很巧妙的公益宣传片：电视画面中，现代都市的交通变成了按照丛林法则任意穿行的“动物世界”,满是超载、不走斑马线、翻越护栏等交通乱象。这很巧妙地回答了上面的问题，如果没有汽车文明，我们的城市表面上是现代文明和高科技的产物，实则无异于丛林法则下的弱肉强食和混乱无序。
下列哪一项不是画横线部分“上面的问题”所指：','[{"label":"A","content":"如果没有汽车文明的话，汽车社会将是怎样的场景"},{"label":"B","content":"如何杜绝“路怒”现象以及汽车“违法变道”现象"},{"label":"C","content":"汽车文明滞后于汽车时代，汽车社会将是何等境况"},{"label":"D","content":"汽车文明没有发育成熟，汽车社会将是怎样的场景"}]','B','画线句子的“这”指代上文的乱象：现代都市的交通变成了按照丛林法则任意穿行的“动物世界”,满是超载、不走斑马线、翻越护栏等交通乱象；再根据下文可知：这种乱象是“没有汽车文明”的表现；
所以“上面的问题”应是“没有汽车文明我们的城市会如何”, A选项、 C选项、D选项意思符合，均是“上面的问题”⑨,选非题，排除；
“这”所指代部分并未介绍杜绝路怒和违法变道的具体措施，无法回答B选项所提问题，所以 B选项不是上述横线“上面的问题”所指，当选。

花生批注：
⑨ 实战思维：
四个选项中，A选项、C选项、 D选项意思相近，B选项意思特殊，其中只有一个不是“上面问题”所指，只能选择B选项。','2016年重庆市考','进阶','published','{"globalNumber":145,"setNumber":8,"localNumber":5,"sourceLabel":"2016年重庆市考49%","accuracy":49,"typeAndPassage":"词句理解题","stemRich":[{"text":"某市交通管理局曾经推出一个创意很巧妙的公益宣传片：电视画面中，现代都市的交通变成了按照丛林法则任意穿行的“动物世界”,满是超载、不走斑马线、翻越护栏等交通乱象。"},{"text":"这很巧妙地回答了上面的问题","underline":true},{"text":"，如果没有汽车文明，我们的城市表面上是现代文明和高科技的产物，实则无异于丛林法则下的弱肉强食和混乱无序。\n下列哪一项不是画横线部分“上面的问题”所指："}],"optionRich":{"A":[{"text":"如果没有汽车文明的话，汽车社会将是怎样的场景"}],"B":[{"text":"如何杜绝“路怒”现象以及汽车“违法变道”现象"}],"C":[{"text":"汽车文明滞后于汽车时代，汽车社会将是何等境况"}],"D":[{"text":"汽车文明没有发育成熟，汽车社会将是怎样的场景"}]},"annotatedStemRich":[{"text":"某市交通管理局曾经推出一个创意很巧妙的公益宣传片：电视画面中，现代都市的交通变成了按照丛林法则任意穿行的“动物世界”,满是超载、不走斑马线、翻越护栏等交通乱象。"},{"text":"这很巧妙地回答了上面的问题","underline":true},{"text":"，如果没有汽车文明，我们的城市表面上是现代文明和高科技的产物，实则无异于丛林法则下的弱肉强食和混乱无序。\n下列哪一项不是画横线部分“上面的问题”所指："}],"annotatedOptionRich":{"A":[{"text":"如果没有汽车文明的话，汽车社会将是怎样的场景"}],"B":[{"text":"如何杜绝“路怒”现象以及汽车“违法变道”现象"}],"C":[{"text":"汽车文明滞后于汽车时代，汽车社会将是何等境况"}],"D":[{"text":"汽车文明没有发育成熟，汽车社会将是怎样的场景\n片段阅读600\n"},{"text":"四","bold":true},{"text":"(上册)"}]},"practicalAnalysis":"画线句子的“这”指代上文的乱象：现代都市的交通变成了按照丛林法则任意穿行的“动物世界”,满是超载、不走斑马线、翻越护栏等交通乱象；再根据下文可知：这种乱象是“没有汽车文明”的表现；\n所以“上面的问题”应是“没有汽车文明我们的城市会如何”, A选项、 C选项、D选项意思符合，均是“上面的问题”⑨,选非题，排除；\n“这”所指代部分并未介绍杜绝路怒和违法变道的具体措施，无法回答B选项所提问题，所以 B选项不是上述横线“上面的问题”所指，当选。","notes":[{"marker":"⑨","content":"实战思维：\n四个选项中，A选项、C选项、 D选项意思相近，B选项意思特殊，其中只有一个不是“上面问题”所指，只能选择B选项。","matchScore":0.4867,"pairingMode":"marker-and-content","order":8}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300146,3,'中心理解题','习近平总书记指出，当前意识形态工作的根本任务没有变，也不能变，那就是要巩固马克思主义在意识形态领域的指导地位、巩固全党全国人民团结奋斗的共同思想基础。要加强重大理论学习，认真落实党委中心组理论学习制度，扎实开展“两学一做”学习教育，用中国特色社会主义理论体系和习近平总书记系列重要讲话精神统一思想、凝聚共识，确保在“举什么旗、走什么路”这一根本问题上绝不含糊、绝无偏差。要强化思想政治引导，密切关注社会思潮动态动向，严守政治纪律和政治规矩，坚决维护中央权威，对一些错误言论、思潮和主张，旗帜鲜明、及时有力地予以批驳和修正，始终站稳政治立场、保持政治定力、把准政治方向，为加快发展奠定坚实的思想政治基础。
这段文字意在强调：','[{"label":"A","content":"当前意识形态工作根本任务没有变"},{"label":"B","content":"加强思想意识形态领域的工作力度"},{"label":"C","content":"全国人民团结奋斗的共同思想基础"},{"label":"D","content":"全党全国人民思想政治引导的方向"}]','A','文段分析见批注。
文段总观点为“当前意识形态工作的根本任务(两个巩固)没有变，也不能变”,对应A选项，当选；
B选项、C选项①分别对应“两个巩固”,且表述与原文有较大差别，D选项对应“分2”,均片面，可简单排除。

花生批注：
⑩ 行文结构：总分结构。
开篇开门见山给出总观点：
当前意识形态工作的根本任务(巩固马克思主义在意识形态领域的指导地位和巩固全党全国人民团结奋斗的共同思想基础)没有变，也不能变；
后文分别从两个角度论证：
①要加强理论学习；
②要强化思想政治引导。
⑪ “加强思想意识形态领域的工作力度”源自“要巩固马克思主义在意识形态领域的指导地位”;
“全国人民团结奋斗的共同思想基础”源自“巩固全党全国人民团结奋斗的共同思想基础”。','2019年河南省考','挑战','published','{"globalNumber":146,"setNumber":8,"localNumber":6,"sourceLabel":"2019年河南省考40%","accuracy":40,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"习近平总书记指出，当前意识形态工作的根本任务没有变，也不能变，那就是要巩固马克思主义在意识形态领域的指导地位、巩固全党全国人民团结奋斗的共同思想基础。要加强重大理论学习，认真落实党委中心组理论学习制度，扎实开展“两学一做”学习教育，用中国特色社会主义理论体系和习近平总书记系列重要讲话精神统一思想、凝聚共识，确保在“举什么旗、走什么路”这一根本问题上绝不含糊、绝无偏差。要强化思想政治引导，密切关注社会思潮动态动向，严守政治纪律和政治规矩，坚决维护中央权威，对一些错误言论、思潮和主张，旗帜鲜明、及时有力地予以批驳和修正，始终站稳政治立场、保持政治定力、把准政治方向，为加快发展奠定坚实的思想政治基础。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"当前意识形态工作根本任务没有变"}],"B":[{"text":"加强思想意识形态领域的工作力度"}],"C":[{"text":"全国人民团结奋斗的共同思想基础"}],"D":[{"text":"全党全国人民思想政治引导的方向"}]},"annotatedStemRich":[{"text":"习近平总书记指出，当前意识形态工作的根本任务没有变，也不能变，那就是要巩固马克思主义在意识形态领域的指导地位、巩固全党全国人民团结奋斗的共同思想基础( 总 ) 。要加强重大理论学习，认真落实党委中心组理论学习制度，扎实开展“两学一做”学习教育，用中国特色社会主义理论体系和习近平总书记系列重要讲话精神统一思想、凝聚共识，确保在“举什么旗、走什么路”这一根本问题上绝不含糊、绝无偏差( 分 1 ) 。要强化思想政治引导，密切关注社会思潮动态动向，严守政治纪律和政治规矩，坚决维护中央权威，对一些错误言论、思潮和主张，旗帜鲜明、及时有力地予以批驳和修正，始终站稳政治立场、保持政治定力、把准政治方向，为加快发展奠定坚实的思想政治基础(分2)。⑩\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"当前意识形态工作根本任务没有变"}],"B":[{"text":"加强思想意识形态领域的工作力度(片面)"}],"C":[{"text":"全国人民团结奋斗的共同思想基础(片面)"}],"D":[{"text":"全党全国人民思想政治引导的方向( 片面 )"}]},"practicalAnalysis":"文段分析见批注。\n文段总观点为“当前意识形态工作的根本任务(两个巩固)没有变，也不能变”,对应A选项，当选；\nB选项、C选项①分别对应“两个巩固”,且表述与原文有较大差别，D选项对应“分2”,均片面，可简单排除。","notes":[{"marker":"⑩","content":"行文结构：总分结构。\n开篇开门见山给出总观点：\n当前意识形态工作的根本任务(巩固马克思主义在意识形态领域的指导地位和巩固全党全国人民团结奋斗的共同思想基础)没有变，也不能变；\n后文分别从两个角度论证：\n①要加强理论学习；\n②要强化思想政治引导。","matchScore":0.8541,"pairingMode":"marker-and-content","order":9},{"marker":"⑪","content":"“加强思想意识形态领域的工作力度”源自“要巩固马克思主义在意识形态领域的指导地位”;\n“全国人民团结奋斗的共同思想基础”源自“巩固全党全国人民团结奋斗的共同思想基础”。","matchScore":0.8985,"pairingMode":"content-similarity","order":10}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300147,3,'语句填入类','人类历史上，从“地理大发现”一直到今天，真正推动全球化往前演化的，是底层的经济过程，而不是上层的政治意志。政治意志有可能导致全球化出现一个短期的逆转，但这是走不远的，比如两次世界大战，全球化都出现了短期的逆转，但大战之后全球化反而往更深层次走了。所以， ,尤其是今天的全球化跟过去相比，到达的深度已经完全不可同日而语了。填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"现在全球化已经发展得非常深入"},{"label":"B","content":"经济层面的全球化仍然是大势所趋"},{"label":"C","content":"未来经济全球化面临巨大的不确定性"},{"label":"D","content":"这次新冠疫情使全球化遭遇了新的挑战"}]','B','文段分析见批注。
文段开篇指出：历史上推动全球化的是底层经济过程(A),而非上层的政治意志(B);接着分析了推动全球化的确实不是政治意志(B),下文应谈论经济对全球化的推动(A)⑬, 所填入语句应包含关键词“经济”;

花生批注：
⑫ 行文结构：前观点结构。
文段开篇开门见山给出观点：介绍了历史上推动全球化的是底层经济过程，而非上层的政治意志；
中间分析确实非政治意志；文末应谈论经济对全球化的推动。
填入文中画横线部分最恰当的一项是：
A. 现在全球化已经发展得非常深入(缺少关键词)
B. 经济层面的全球化仍然是大势所趋
