INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300149,3,'中心理解题','哲学思维是一种高度抽象化和理性化的思维。哲学思维的这种特点并不表明哲学与生活无关，也不表明它所讨论的只能是一些纯粹思辨的、冷冰冰的问题。其实，哲学的抽象性主要是指论证方式，而非哲学问题。哲学中的问题来自生活和科学，都是确实且普遍存在的。当这些问题上升为哲学问题时，就抽象化了，因为哲学是以普遍性的概念和范畴形式来表述和论证这些问题的。如存在和意识的相互关系、必然性和偶然性的问题等，这些问题在没有上升为哲学问题前，都以具体问题的形式出现。可以说，所有哲学问题在生活和科学中都有类似的特点。
这段文字主要说明：','[{"label":"A","content":"哲学思维的思辨性特点"},{"label":"B","content":"哲学与现实生活的关系"},{"label":"C","content":"哲学研究问题的普遍性"},{"label":"D","content":"哲学论证方式的抽象性"}]','C','文段分析见批注。
文段前三句介绍：哲学问题并非是抽象的；后四句介绍：哲学问题是确实且普遍存在的；这个文段可看作是“哲学问题不是 ·……而是……”结构，主要介绍的是哲学问题的性质，主体是“哲学问题”,对应C选项，当选；
A选项、D选项侧重“抽象性”,但文段介绍的是“哲学问题并非抽象的”, 抽象性并非重点；B选项为区别比较联系类，但哲学与现实生活并非文段的“双主体”,主要谈论的为“哲学问题”,排除。

花生批注：
⑥ 下文推断的常见结构：
①上文文末提出新内容→下文解释新内容
②上文提出问题→下文分析问题、解决问题
③上文给出宏观对策、原因等→下文具体展开
④时间对比：过去不行→现在有了新突破
⑤总分：上文是总+分→下文补充另一“分”
⑥转折
⑯ 哲学问题是文段论述主体。
⑰ 文段可简略翻译如下：
①哲学思维是抽象性思维； ②③哲学思维的抽象不代表哲学与生活无关，其实，哲学的抽象性指的是论证方式，而非哲学问题；
即：哲学问题并非是抽象的； ④哲学问题来自生活与科学，是确实且普遍存在的； ⑤⑥解释说明；
⑦再做总结：所有哲学问题都有类似特点(来自生活与科学，是确实且普遍存在的 ) ;
即：哲学问题是确实且普遍存在的。
A. 哲学思维的思辨性特点(缺主体)
B. 哲学与现实生活的关系(区别比较联系类)
C. 哲学研究问题的普遍性','2019年四川省考','挑战','published','{"globalNumber":149,"setNumber":8,"localNumber":9,"sourceLabel":"2019年四川省考 30%","accuracy":30,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"哲学思维是一种高度抽象化和理性化的思维。哲学思维的这种特点并不表明哲学与生活无关，也不表明它所讨论的只能是一些纯粹思辨的、冷冰冰的问题。其实，哲学的抽象性主要是指论证方式，而非哲学问题。哲学中的问题来自生活和科学，都是确实且普遍存在的。当这些问题上升为哲学问题时，就抽象化了，因为哲学是以普遍性的概念和范畴形式来表述和论证这些问题的。如存在和意识的相互关系、必然性和偶然性的问题等，这些问题在没有上升为哲学问题前，都以具体问题的形式出现。可以说，所有哲学问题在生活和科学中都有类似的特点。\n这段文字主要说明："}],"optionRich":{"A":[{"text":"哲学思维的思辨性特点"}],"B":[{"text":"哲学与现实生活的关系"}],"C":[{"text":"哲学研究问题的普遍性"}],"D":[{"text":"哲学论证方式的抽象性"}]},"annotatedStemRich":[{"text":"①哲学思维是一种高度抽象化和理性化的思维。②哲学思维的这种特点并不表明哲学与生活无关，也不表明它所讨论的只能是一些纯粹思辨的、冷冰冰的问题。③其实，哲学的抽象性主要是指论证方式，而非哲学问题。④"},{"text":"哲学中的问题","underline":true},{"text":"⑯来自生活和科学，都是确实且普遍存在的。⑤当这些问题上升为哲学问题时，就抽象化了，因为哲学是以普遍性的概念和范畴形式来表述和论证这些问题的。⑥如存在和意识的相互关系、必然性和偶然性的问题等，这些问题在没有上升为哲学问题前，都以具体问题的形式出现。⑦可以说，所有哲学问题在生活和科学中都有类似的特点。⑫\n⑰花生批注：\n这段文字主要说明："}],"annotatedOptionRich":{"A":[{"text":"哲学思维的思辨性特点(缺主体)"}],"B":[{"text":"哲学与现实生活的关系(区别比较联系类)"}],"C":[{"text":"哲学研究问题的普遍性"}],"D":[{"text":"哲学论证方式的抽象性( 缺主体 )"}]},"practicalAnalysis":"文段分析见批注。\n文段前三句介绍：哲学问题并非是抽象的；后四句介绍：哲学问题是确实且普遍存在的；这个文段可看作是“哲学问题不是 ·……而是……”结构，主要介绍的是哲学问题的性质，主体是“哲学问题”,对应C选项，当选；\nA选项、D选项侧重“抽象性”,但文段介绍的是“哲学问题并非抽象的”, 抽象性并非重点；B选项为区别比较联系类，但哲学与现实生活并非文段的“双主体”,主要谈论的为“哲学问题”,排除。","notes":[{"marker":"⑥","content":"下文推断的常见结构：\n①上文文末提出新内容→下文解释新内容\n②上文提出问题→下文分析问题、解决问题\n③上文给出宏观对策、原因等→下文具体展开\n④时间对比：过去不行→现在有了新突破\n⑤总分：上文是总+分→下文补充另一“分”\n⑥转折","matchScore":0.1158,"pairingMode":"marker-and-content","order":5},{"marker":"⑯","content":"哲学问题是文段论述主体。","matchScore":0.6275,"pairingMode":"marker-and-content","order":15},{"marker":"⑰","content":"文段可简略翻译如下：\n①哲学思维是抽象性思维； ②③哲学思维的抽象不代表哲学与生活无关，其实，哲学的抽象性指的是论证方式，而非哲学问题；\n即：哲学问题并非是抽象的； ④哲学问题来自生活与科学，是确实且普遍存在的； ⑤⑥解释说明；\n⑦再做总结：所有哲学问题都有类似特点(来自生活与科学，是确实且普遍存在的 ) ;\n即：哲学问题是确实且普遍存在的。\nA. 哲学思维的思辨性特点(缺主体)\nB. 哲学与现实生活的关系(区别比较联系类)\nC. 哲学研究问题的普遍性","matchScore":0.791,"pairingMode":"marker-and-content","order":16}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300150,3,'中心理解题','审慎原则并不是不尊重科学，而是对科学应用的务实态度。科研成果的取得及其社会认可，往往代表着巨大的经济利益甚或科学家的终身成就，这就很难保证科学家不会放松科学原则要求而违规；科研成果的社会化往往与企业利益相连，企业逐利时难免会刻意隐瞒危害。由于科研的未知性因素和危险的发现难度及时间跨度过大，即使科学家和企业都秉承道德原则，也很难保证能发现科研成果的潜在危害。
这段文字意在强调：','[{"label":"A","content":"对科学成果的应用应当秉承谨慎态度"},{"label":"B","content":"科研成果应用的潜在危险无法被预测"},{"label":"C","content":"科学附带的经济效益腐化了科学精神"},{"label":"D","content":"道德原则是科学研究首要遵循的原则"}]','A','文段分析见批注。
文段先介绍审慎原则是科学应用的务实态度，再从多个角度展开论述：因为可能存在这些问题，更应该对科学应用秉承审慎态度； A选项的“谨慎态度”是“审慎态度”的同义替换，当选；
B选项和C选项分别对应“分3”和“分2”的内容，均为片面，排除； D选项的“道德原则是首要……”无中生有，排除。

花生批注：
⑧ 行文结构：总分结构。
首句直接给出观点：
审慎原则是对科学应用的务实态度；
随后从三个角度分析论证：
①科研成果牵扯科学家终生成就和经济利益，科学家可能会放松原则；
②科研成果与企业利益相连，企业可能隐瞒危害；
③即使科学家、企业都秉承道德原则，科研成果潜在危害不一定能发现。
因为可能存在上述问题，更应该对科学应用秉持审慎态度。
这段文字意在强调：
A. 对科学成果的应用应当秉承谨慎态度
B. 科研成果应用的潜在危险无法被预测(片面)
C. 科学附带的经济效益腐化了科学精神 ( 片面 )','2013年辽宁省考','基础','published','{"globalNumber":150,"setNumber":8,"localNumber":10,"sourceLabel":"2013年辽宁省考 70%","accuracy":70,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"审慎原则并不是不尊重科学，而是对科学应用的务实态度。科研成果的取得及其社会认可，往往代表着巨大的经济利益甚或科学家的终身成就，这就很难保证科学家不会放松科学原则要求而违规；科研成果的社会化往往与企业利益相连，企业逐利时难免会刻意隐瞒危害。由于科研的未知性因素和危险的发现难度及时间跨度过大，即使科学家和企业都秉承道德原则，也很难保证能发现科研成果的潜在危害。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"对科学成果的应用应当秉承谨慎态度"}],"B":[{"text":"科研成果应用的潜在危险无法被预测"}],"C":[{"text":"科学附带的经济效益腐化了科学精神"}],"D":[{"text":"道德原则是科学研究首要遵循的原则"}]},"annotatedStemRich":[{"text":"审慎原则并不是不尊重科学，而是对科学应用的务实态度(总)。科研成果的取得及其社会认可，往往代表着巨大的经济利益甚或科学家的终身成就，这就很难保证科学家不会放松科学原则要求而违规( 分 1 ) ; 科研成果的社会化往往与企业利益相连，企业逐利时难免会刻意隐瞒危害( 分 2 ) 。由于科研的未知性因素和危险的发现难度及时间跨度过大，即使科学家和企业都秉承道德原则，也很难保证能发现科研成果的潜在危害 (分3)。⑥\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"对科学成果的应用应当秉承谨慎态度"}],"B":[{"text":"科研成果应用的潜在危险无法被预测(片面)"}],"C":[{"text":"科学附带的经济效益腐化了科学精神 ( 片面 )"}],"D":[{"text":"道德原则是科学研究首要遵循的原则(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍审慎原则是科学应用的务实态度，再从多个角度展开论述：因为可能存在这些问题，更应该对科学应用秉承审慎态度； A选项的“谨慎态度”是“审慎态度”的同义替换，当选；\nB选项和C选项分别对应“分3”和“分2”的内容，均为片面，排除； D选项的“道德原则是首要……”无中生有，排除。","notes":[{"marker":"⑧","content":"行文结构：总分结构。\n首句直接给出观点：\n审慎原则是对科学应用的务实态度；\n随后从三个角度分析论证：\n①科研成果牵扯科学家终生成就和经济利益，科学家可能会放松原则；\n②科研成果与企业利益相连，企业可能隐瞒危害；\n③即使科学家、企业都秉承道德原则，科研成果潜在危害不一定能发现。\n因为可能存在上述问题，更应该对科学应用秉持审慎态度。\n这段文字意在强调：\nA. 对科学成果的应用应当秉承谨慎态度\nB. 科研成果应用的潜在危险无法被预测(片面)\nC. 科学附带的经济效益腐化了科学精神 ( 片面 )","matchScore":0.7524,"pairingMode":"content-similarity","order":17}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300151,3,'中心理解题','在21世纪，新能源必将取得快速发展正逐渐成为人们的共识。然而，从长远来看，解决人类能源需求的清洁技术路线不一定是现在占主导地位的这几种模式，新能源的研发与新型技术的进步仍然需要充分的资金支持。近年来，一些新能源技术路线受成本因素影响而被压制发展。因此，需要政府补贴来支持其初始阶段的发展。
这段文字最可能讨论的是：','[{"label":"A","content":"是否应探索新能源技术路线"},{"label":"B","content":"新能源技术路线是否需要调整"},{"label":"C","content":"现阶段是否应取消新能源补贴"},{"label":"D","content":"是否应加强对新能源市场的管理"}]','C','文段分析见批注。

花生批注：
⑲ 行文结构：后对策结构。
先转折提出并分析问题：
新能源研发需要资金支持且新能源技术路线受成本因素影响而被压制发展；
文末提出对策：
需要政府补贴来支持新能源研发初始阶段的发展。','2019年浙江省考','进阶','published','{"globalNumber":151,"setNumber":8,"localNumber":11,"sourceLabel":"2019年浙江省考 68%","accuracy":68,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"在21世纪，新能源必将取得快速发展正逐渐成为人们的共识。然而，从长远来看，解决人类能源需求的清洁技术路线不一定是现在占主导地位的这几种模式，新能源的研发与新型技术的进步仍然需要充分的资金支持。近年来，一些新能源技术路线受成本因素影响而被压制发展。因此，需要政府补贴来支持其初始阶段的发展。\n这段文字最可能讨论的是："}],"optionRich":{"A":[{"text":"是否应探索新能源技术路线"}],"B":[{"text":"新能源技术路线是否需要调整"}],"C":[{"text":"现阶段是否应取消新能源补贴"}],"D":[{"text":"是否应加强对新能源市场的管理"}]},"annotatedStemRich":[{"text":"在21世纪，新能源必将取得快速发展正逐渐成为人们的共识。然而，从长远来看，解决人类能源需求的清洁技术路线不一定是现在占主导地位的这几种模式，新能源的研发与新型技术的进步仍然需要充分的资金支持。近年来，一些新能源技术路线受成本因素影响而被压制发展(提出并分析问题)。因此，需要政府补贴来支持其初始阶段的发展(后对策)。⑨\n"},{"text":"这段文字最可能讨论的是： ","underline":true},{"text":"20"}],"annotatedOptionRich":{"A":[{"text":"是否应探索新能源技术路线 (无主题词)"}],"B":[{"text":"新能源技术路线是否需要调整(无主题词)"}],"C":[{"text":"现阶段是否应取消新能源补贴"}],"D":[{"text":"是否应加强对新能源市场的管理(无主题词)"}]},"practicalAnalysis":"文段分析见批注。","notes":[{"marker":"⑲","content":"行文结构：后对策结构。\n先转折提出并分析问题：\n新能源研发需要资金支持且新能源技术路线受成本因素影响而被压制发展；\n文末提出对策：\n需要政府补贴来支持新能源研发初始阶段的发展。","matchScore":0.9084,"pairingMode":"content-similarity","order":18}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300152,3,'中心理解题','瓦特发明的蒸汽机将人类带入工业社会，从此，以消耗自然资源为基础的社会经济发展模式向各领域逐渐渗透，开始主导人类社会的方方面面。这种模式如同做蛋糕一样，被做得越来越大，已经不只局限在“突飞猛进”的工业生产领域，在城市规划与建设等领域更为突出。这种模式的确为社会创造出了巨大财富，人们也从中或多或少得到了实惠，但其弊端正在逐渐显现。
根据这段文字，可以看出作者的意图是：','[{"label":"A","content":"倡导转变社会经济发展模式"},{"label":"B","content":"批判工业社会的经济增长方式"},{"label":"C","content":"揭示工业社会经济发展模式的实质"},{"label":"D","content":"呼吁人们降低对自然资源的消耗水平"}]','A','文段分析见批注。
文段先介绍了工业社会后的社会经济发展模式，尾句指出该模式的弊端正在显现，正确答案应体现出“弊端正在显现”这一问题；
C选项，对应首句，工业社会经济发展模式的实质是“以消耗自然资源为基础”,未体现出该模式的问题，排除；

花生批注：
② 社会经济发展模式是全文论述主体。
2 行文结构：二层结构之转折。前两句介绍工业社会后的社会经济发展模式；
尾句指出这种社会经济发展模式的弊端正在逐渐显现。文段也可看作背景知识+正文的二层结构。
根据这段文字，可以看出作者的意图是：
A. 倡导转变社会经济发展模式
B. 批判工业社会的经济增长方式(无主题词)
C. 揭示工业社会经济发展模式的实质(中性表述)
23 该社会经济发展模式弊端正在显现，所以要转变该社会经济发展模式。','2012年国家公务员考试','进阶','published','{"globalNumber":152,"setNumber":8,"localNumber":12,"sourceLabel":"2012年国家公务员考试51%","accuracy":51,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"瓦特发明的蒸汽机将人类带入工业社会，从此，以消耗自然资源为基础的社会经济发展模式向各领域逐渐渗透，开始主导人类社会的方方面面。这种模式如同做蛋糕一样，被做得越来越大，已经不只局限在“突飞猛进”的工业生产领域，在城市规划与建设等领域更为突出。这种模式的确为社会创造出了巨大财富，人们也从中或多或少得到了实惠，但其弊端正在逐渐显现。\n根据这段文字，可以看出作者的意图是："}],"optionRich":{"A":[{"text":"倡导转变社会经济发展模式"}],"B":[{"text":"批判工业社会的经济增长方式"}],"C":[{"text":"揭示工业社会经济发展模式的实质"}],"D":[{"text":"呼吁人们降低对自然资源的消耗水平"}]},"annotatedStemRich":[{"text":"瓦特发明的蒸汽机将人类带入工业社会，从此，以消耗自然资源为基础的"},{"text":"社会经济发展模式","underline":true},{"text":"②向各领域逐渐渗透，开始主导人类社会的方方面面。这种模式如同做蛋糕一样，被做得越来越大，已经不只局限在“突飞猛进”的工业生产领域，在城市规划与建设等领域更为突出(引出并介绍话题)。这种模式的确为社会创造出了巨大财富，人们也从中或多或少得到了实惠，但其弊端正在逐渐显现(转折提出问题)。②\n根据这段文字，可以看出作者的意图是："}],"annotatedOptionRich":{"A":[{"text":"倡导转变社会经济发展模式"}],"B":[{"text":"批判工业社会的经济增长方式(无主题词)"}],"C":[{"text":"揭示工业社会经济发展模式的实质(中性表述)"}],"D":[{"text":"呼吁人们降低对自然资源的消耗水平(无主题词)"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍了工业社会后的社会经济发展模式，尾句指出该模式的弊端正在显现，正确答案应体现出“弊端正在显现”这一问题；\nC选项，对应首句，工业社会经济发展模式的实质是“以消耗自然资源为基础”,未体现出该模式的问题，排除；","notes":[{"marker":"②","content":"社会经济发展模式是全文论述主体。","matchScore":0.5464,"pairingMode":"marker-and-content","order":20},{"marker":"2","content":"行文结构：二层结构之转折。前两句介绍工业社会后的社会经济发展模式；\n尾句指出这种社会经济发展模式的弊端正在逐渐显现。文段也可看作背景知识+正文的二层结构。\n根据这段文字，可以看出作者的意图是：\nA. 倡导转变社会经济发展模式\nB. 批判工业社会的经济增长方式(无主题词)\nC. 揭示工业社会经济发展模式的实质(中性表述)","matchScore":0.6573,"pairingMode":"marker-and-content","order":21},{"marker":"23","content":"该社会经济发展模式弊端正在显现，所以要转变该社会经济发展模式。","matchScore":0.6943,"pairingMode":"content-similarity","order":22}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300153,3,'标题拟定类','每当寒暑假期来临，大量的少儿节目开始在荧屏上活跃，力图充实孩子们的假期。近年来，文化类节目的大热渲染了良好的荧屏氛围，文物、汉字、诗词等优秀传统文化搭载综艺节目的外壳在镜头中大放异彩。而如何将少儿节目与文化类节目联结，如何在少年儿童的休闲娱乐时光中潜移默化地为他们树立文化自觉、弘扬中华优秀传统文化，则是电视行业践行“将最好的留给孩子”这一信念的必经之路。
下列适合作为文段标题的是：','[{"label":"A","content":"创新是少儿节目的生命力所在"},{"label":"B","content":"给少儿节目浸润点文化底色"},{"label":"C","content":"给少年儿童多些文化熏陶"},{"label":"D","content":"电视行业要“将最好的留给孩子”"}]','B','文段分析见批注。
文段先介绍了少儿节目和文化类节目的大热，文末给出对策：少儿节目应和文化类节目联结，要让少年儿童在少儿节目中受到传统文化的熏陶。主体是“少儿节目”,对策的重点是“传统文化”,B选项是对策的同义替换，当选；
A选项的“创新”无中生有，且未提到“传统文化”,排除； C选项、D选项均未提及少儿节目，排除。

花生批注：
25 行文结构：后对策结构。
开门见山引出话题：少儿节目；
接下来介绍文化类节目的“大热”;
文末通过“必经之路”语义表对策：要将少儿节目与文化类节目联结、要让儿童在少儿节目中学习传统文化。
⑥ 完美选项：
①对策的同义替换，浸润文化即加入传统文化；②包含主题词“少儿节目”;
③“浸润”作为热词做标题可增强吸引力。
②7 原文对策可翻译为：电视行业践行“将最好的留给孩子”的信念，应将少儿节目与文化类节目联结，在节目中加入传统文化；
此选项把“将最好的留给孩子”当成对策，属于对策错误。','2019年沈阳市事业单位','进阶','published','{"globalNumber":153,"setNumber":8,"localNumber":13,"sourceLabel":"2019年沈阳市事业单位66%","accuracy":66,"typeAndPassage":"标题拟定类+说理类文章","stemRich":[{"text":"每当寒暑假期来临，大量的少儿节目开始在荧屏上活跃，力图充实孩子们的假期。近年来，文化类节目的大热渲染了良好的荧屏氛围，文物、汉字、诗词等优秀传统文化搭载综艺节目的外壳在镜头中大放异彩。而如何将少儿节目与文化类节目联结，如何在少年儿童的休闲娱乐时光中潜移默化地为他们树立文化自觉、弘扬中华优秀传统文化，则是电视行业践行“将最好的留给孩子”这一信念的必经之路。\n下列适合作为文段标题的是："}],"optionRich":{"A":[{"text":"创新是少儿节目的生命力所在"}],"B":[{"text":"给少儿节目浸润点文化底色"}],"C":[{"text":"给少年儿童多些文化熏陶"}],"D":[{"text":"电视行业要“将最好的留给孩子”"}]},"annotatedStemRich":[{"text":"每当寒暑假期来临，大量的"},{"text":"少儿节目","underline":true},{"text":"②开始在荧屏上活跃，力图充实孩子们的假期(引出话题)。近年来，文化类节目的大热渲染了良好的荧屏氛围，文物、汉字、诗词等优秀传统文化搭载综艺节目的外壳在镜头中大放异彩( 分析介绍)。而如何将少儿节目与文化类节目联结，如何在少年儿童的休闲娱乐时光中潜移默化地为他们树立文化自觉、弘扬中华优秀传统文化，则是电视行业践行“将最好的留给孩子”这一信念的必经之路(语义表对策)。⑤\n1 06\n下列适合作为文段标题的是："}],"annotatedOptionRich":{"A":[{"text":"创新是少儿节目的生命力所在(无中生有)"}],"B":[{"text":"给少儿节目浸润点文化底色"}],"C":[{"text":"给少年儿童多些文化熏陶( 缺主语 )"}],"D":[{"text":"电视行业要“将最好的留给孩子”(缺主语且"},{"text":"对策错误","underline":true},{"text":"②)"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍了少儿节目和文化类节目的大热，文末给出对策：少儿节目应和文化类节目联结，要让少年儿童在少儿节目中受到传统文化的熏陶。主体是“少儿节目”,对策的重点是“传统文化”,B选项是对策的同义替换，当选；\nA选项的“创新”无中生有，且未提到“传统文化”,排除； C选项、D选项均未提及少儿节目，排除。","notes":[{"marker":"25","content":"行文结构：后对策结构。\n开门见山引出话题：少儿节目；\n接下来介绍文化类节目的“大热”;\n文末通过“必经之路”语义表对策：要将少儿节目与文化类节目联结、要让儿童在少儿节目中学习传统文化。","matchScore":0.7237,"pairingMode":"content-similarity","order":24},{"marker":"⑥","content":"完美选项：\n①对策的同义替换，浸润文化即加入传统文化；②包含主题词“少儿节目”;\n③“浸润”作为热词做标题可增强吸引力。","matchScore":0.4244,"pairingMode":"content-similarity","order":25},{"marker":"②7","content":"原文对策可翻译为：电视行业践行“将最好的留给孩子”的信念，应将少儿节目与文化类节目联结，在节目中加入传统文化；\n此选项把“将最好的留给孩子”当成对策，属于对策错误。","matchScore":0.6756,"pairingMode":"content-similarity","order":26}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300154,3,'语句填入类','农民是乡村振兴的主体，也是受益者，必须要把亿万农民群众的积极性、主动性、创造性调动起来。在过去长期的农业生产中，我们或多或少存在重物轻人的现象。这表现在只注重农产品的数量增长，不重视务农队伍的素质提高和职业化。相应的是，农村教育、科技、卫生、文化等公共资源投入少，导致农村人口素质偏低、人才缺乏。而乡村发展的本质是人的健康发展，只有农民自身素质和能力不断提升，才能有效推进乡村的可持续发展。因此， o
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"乡村振兴必须加大对农村公共资源的投入"},{"label":"B","content":"要提升农民科学素养，提高农业农村现代化水平"},{"label":"C","content":"乡村振兴在注重硬件建设的同时也要大力提高人口素质"},{"label":"D","content":"乡村基础教育、职业教育、就业培训等才是乡村建设的根本"}]','C','文段分析见批注。
横线位于尾句，尾句应针对前文问题(“重物轻人”)提出对策，即乡村振兴要重视农民、提升农民素质，对应C选项， C选项问题、对策均正确，当选；

花生批注：
9 行文结构：后对策结构。
首先引入话题：乡村振兴中农民的重要性；
再提出问题并分析：在过去的农业生产中存在重物轻人现象；
尾句应针对问题给出对策。
③ 有同学可能会疑惑：C选项的“注重硬件建设的同时”不无中生有吗?
C选项的对策虽然是并列的，但要注意原文重点突出的是什么,有时会有“附带”的不重要对策，原文中的问题是“重物轻人”,所以给出对策是继续重视“物”的同时重视“人的素质培养”, 完全合情合理；
例如：花生老师想要求大家在考前更要努力学习，可以说：考前的复习是非常重要高效的，所以考试前一周要在保证身体健康的情况下，更加努力学习；
对策重点是努力学习，附带出“保证健康”可以接受。
A选项，虽然针对“农村教育、科技、卫生、文化等公共资源投入少”但未提及全文重点“农民(即人)”,③排除；
B选项的“科学素养”和“农业农村现代化水平”均无中生有，“科学素养”指对科学的了解，而文段的问题是农民素质问题，对策无法解决问题，排除；
D选项的“基础教育、职业教育、就业培训”过度推断③,并且问题是“乡村振兴”而非“乡村建设”,排除。','2020年四川省考','进阶','published','{"globalNumber":154,"setNumber":8,"localNumber":14,"sourceLabel":"2020年四川省考 61%","accuracy":61,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"农民是乡村振兴的主体，也是受益者，必须要把亿万农民群众的积极性、主动性、创造性调动起来。在过去长期的农业生产中，我们或多或少存在重物轻人的现象。这表现在只注重农产品的数量增长，不重视务农队伍的素质提高和职业化。相应的是，农村教育、科技、卫生、文化等公共资源投入少，导致农村人口素质偏低、人才缺乏。而乡村发展的本质是人的健康发展，只有农民自身素质和能力不断提升，才能有效推进乡村的可持续发展。因此，"},{"text":"                        ","underline":true},{"text":" o\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"乡村振兴必须加大对农村公共资源的投入"}],"B":[{"text":"要提升农民科学素养，提高农业农村现代化水平"}],"C":[{"text":"乡村振兴在注重硬件建设的同时也要大力提高人口素质"}],"D":[{"text":"乡村基础教育、职业教育、就业培训等才是乡村建设的根本"}]},"annotatedStemRich":[{"text":"农民","underline":true},{"text":"②是乡村振兴的主体，也是受益者，必须要把亿万农民群众的积极性、主动性、创造性调动起来(引入话题)。在过去长期的农业生产中，我们或多或少存在重物轻人的现象。这表现在只注重农产品的数量增长，不重视务农队伍的素质提高和职业化。相应的是，农村教育、科技、卫生、文化等公共资源投入少，导致农村人口素质偏低、人才缺乏。而乡村发展的本质是人的健康发展，只有农民自身素质和能力不断提升，才能有效推进乡村的可持续发展 (提出并分析问题)。因此，"},{"text":"                         ","underline":true},{"text":" (后对策)。②\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"乡村振兴必须加大对农村公共资源的投入(对策不针对问题)"}],"B":[{"text":"要提升农民科学素养，提高农业农村现代化水平"},{"text":"(偷换概念且无中生有)","bold":true}],"C":[{"text":"乡村振兴在注重硬件建设的同时也要大力提高人口素质"}],"D":[{"text":"乡村基础教育、职业教育、就业培训等才是乡村建设的根本(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n横线位于尾句，尾句应针对前文问题(“重物轻人”)提出对策，即乡村振兴要重视农民、提升农民素质，对应C选项， C选项问题、对策均正确，当选；","notes":[{"marker":"9","content":"行文结构：后对策结构。\n首先引入话题：乡村振兴中农民的重要性；\n再提出问题并分析：在过去的农业生产中存在重物轻人现象；\n尾句应针对问题给出对策。","matchScore":0.6497,"pairingMode":"content-similarity","order":28},{"marker":"③","content":"有同学可能会疑惑：C选项的“注重硬件建设的同时”不无中生有吗?\nC选项的对策虽然是并列的，但要注意原文重点突出的是什么,有时会有“附带”的不重要对策，原文中的问题是“重物轻人”,所以给出对策是继续重视“物”的同时重视“人的素质培养”, 完全合情合理；\n例如：花生老师想要求大家在考前更要努力学习，可以说：考前的复习是非常重要高效的，所以考试前一周要在保证身体健康的情况下，更加努力学习；\n对策重点是努力学习，附带出“保证健康”可以接受。\nA选项，虽然针对“农村教育、科技、卫生、文化等公共资源投入少”但未提及全文重点“农民(即人)”,③排除；\nB选项的“科学素养”和“农业农村现代化水平”均无中生有，“科学素养”指对科学的了解，而文段的问题是农民素质问题，对策无法解决问题，排除；\nD选项的“基础教育、职业教育、就业培训”过度推断③,并且问题是“乡村振兴”而非“乡村建设”,排除。"