INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300175,3,'标题拟定类','当前，我国科技事业实现了重大发展，重大创新成果竞相涌现。但也应看到，我国科技领域仍存在一些亟待解决的问题，关键核心技术受制于人的局面没有得到根本性改变。现在，我们迎来了世界新一轮科技革命和产业变革同我国转变发展方式的历史性交汇期，科技创新角逐空前激烈，只有努力实现关键核心技术自主可控，才能抓住千载难逢的历史机遇，真正发挥创新引领发展的第一动力作用。
最适合做这段文字标题的是：','[{"label":"A","content":"从关键核心技术到创新动力"},{"label":"B","content":"关键技术核心—— “大国重器”"},{"label":"C","content":"把关键核心技术握在手中"},{"label":"D","content":"掌握关键核心技术岂能只争朝夕"}]','C','文段分析见批注。
文段先通过转折引出问题：我国关键核心技术受制于人，分析后通过“只有才”逻辑关联词给对策：我国要努力实现关键核心技术自主可控。C选项的“握在手中”是对策“自主可控”的同义替换，当选；
A选项、B选项均非对策表述，未体现对策重点“关键核心技术自主可控”, 排除；D选项可看作禁止型对策“掌握关键核心技术不能只争朝夕”,未体现“自主可控”,排除。

花生批注：
29 先介绍“好处”,再转折引出“问题”,是非常常见的引出问题方式。
6 行文结构：后对策结构。
文段先通过转折引出问题：我国关键核心技术受制于人；
文末通过“只有才”逻辑关联词给对策：
我国要努力实现关键核心技术自主可控。
最适合做这段文字标题的是：
A. 从关键核心技术到创新动力(中性表达)
B. 关键技术核心——“大国重器”(中性表达)
C. 把关键核心技术握在手中
D. 掌握关键核心技术岂能只争朝夕(对策有误)','2020年广东选调','基础','published','{"globalNumber":175,"setNumber":9,"localNumber":15,"sourceLabel":"2020年广东选调 75%","accuracy":75,"typeAndPassage":"标题拟定类+说理类文章","stemRich":[{"text":"当前，我国科技事业实现了重大发展，重大创新成果竞相涌现。但也应看到，我国科技领域仍存在一些亟待解决的问题，关键核心技术受制于人的局面没有得到根本性改变。现在，我们迎来了世界新一轮科技革命和产业变革同我国转变发展方式的历史性交汇期，科技创新角逐空前激烈，只有努力实现关键核心技术自主可控，才能抓住千载难逢的历史机遇，真正发挥创新引领发展的第一动力作用。\n最适合做这段文字标题的是："}],"optionRich":{"A":[{"text":"从关键核心技术到创新动力"}],"B":[{"text":"关键技术核心—— “大国重器”"}],"C":[{"text":"把关键核心技术握在手中"}],"D":[{"text":"掌握关键核心技术岂能只争朝夕"}]},"annotatedStemRich":[{"text":"当前，我国科技事业实现了重大发展，重大创新成果竞相涌现。但也应看到，我国科技领域仍存在一些亟待解决的问题，关键核心技术受制于人的局面没有得到根本性改变(转折引出问题)。现在，我们迎来了世界新一轮科技革命和产业变革同我国转变发展方式的历史性交汇期，科技创新角逐空前激烈，只有努力实现关键核心技术自主可控，才能抓住千载难逢的历史机遇，真正发挥创新引领发展的第一动力作用(后对策)。\n最适合做这段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"从关键核心技术到创新动力(中性表达)"}],"B":[{"text":"关键技术核心——“大国重器”(中性表达)"}],"C":[{"text":"把关键核心技术握在手中","bold":true}],"D":[{"text":"掌握关键核心技术岂能只争朝夕(对策有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段先通过转折引出问题：我国关键核心技术受制于人，分析后通过“只有才”逻辑关联词给对策：我国要努力实现关键核心技术自主可控。C选项的“握在手中”是对策“自主可控”的同义替换，当选；\nA选项、B选项均非对策表述，未体现对策重点“关键核心技术自主可控”, 排除；D选项可看作禁止型对策“掌握关键核心技术不能只争朝夕”,未体现“自主可控”,排除。","notes":[{"marker":"29","content":"先介绍“好处”,再转折引出“问题”,是非常常见的引出问题方式。","matchScore":0.3516,"pairingMode":"content-similarity","order":27},{"marker":"6","content":"行文结构：后对策结构。\n文段先通过转折引出问题：我国关键核心技术受制于人；\n文末通过“只有才”逻辑关联词给对策：\n我国要努力实现关键核心技术自主可控。\n最适合做这段文字标题的是：\nA. 从关键核心技术到创新动力(中性表达)\nB. 关键技术核心——“大国重器”(中性表达)\nC. 把关键核心技术握在手中\nD. 掌握关键核心技术岂能只争朝夕(对策有误)","matchScore":0.8329,"pairingMode":"content-similarity","order":34}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300176,3,'中心理解题','自美国F-117 隐形战斗轰炸机首次亮相巴拿马上空后，隐形武器成为世界武器发展的一大趋势。有的军事专家曾预言，未来战争或为隐形武器唱主角的战争。中国武器装备发展也将隐形化作为第三代武器的一个重要指标，新列装的武器装备基本上皆具有隐形的功能。这些隐形武器，其光学特征可以隐形于地理背景之中，其电磁特征也可以湮没于电子信号频谱之内，使对手无法对其识别。
这段文字主要介绍：','[{"label":"A","content":"未来世界武器发展的主要趋势"},{"label":"B","content":"军事专家对未来战争模式的预测"},{"label":"C","content":"隐形武器具备隐形性能的原因"},{"label":"D","content":"中国发展隐形武器的背景及成就"}]','D','文段分析见批注。
文段先介绍隐形武器在世界上的发展(背景),接着介绍中国也在发展隐形武器及取得的成就，为典型的“背景+我国”结构，“我国”是重点， D选项为典型的A且B类选项，概括全面且主语为“我国”,为完美选项；
其他选项皆未提及“我国”,且A选项、B选项出自背景介绍部分，C选项出自后文解释部分，均犯了片面的错误，排除。

花生批注：
③ 行文结构：二层结构之“背景+我国”。
开篇介绍背景引出话题：
隐形武器成为发展趋势；
后文介绍我国现状及成就：中国也大力发展隐形武器且新列装的武器装备基本上皆具有隐形的功能；
后文介绍我国，我国是重点。
38 一正确：指概括全面是正确选项概率非常高。','2017年四川省考','进阶','published','{"globalNumber":176,"setNumber":9,"localNumber":16,"sourceLabel":"2017年四川省考 59%","accuracy":59,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"自美国F-117 隐形战斗轰炸机首次亮相巴拿马上空后，隐形武器成为世界武器发展的一大趋势。有的军事专家曾预言，未来战争或为隐形武器唱主角的战争。中国武器装备发展也将隐形化作为第三代武器的一个重要指标，新列装的武器装备基本上皆具有隐形的功能。这些隐形武器，其光学特征可以隐形于地理背景之中，其电磁特征也可以湮没于电子信号频谱之内，使对手无法对其识别。\n这段文字主要介绍："}],"optionRich":{"A":[{"text":"未来世界武器发展的主要趋势"}],"B":[{"text":"军事专家对未来战争模式的预测"}],"C":[{"text":"隐形武器具备隐形性能的原因"}],"D":[{"text":"中国发展隐形武器的背景及成就"}]},"annotatedStemRich":[{"text":"自美国F-117 隐形战斗轰炸机首次亮相巴拿马上空后，隐形武器成为世界武器发展的一大趋势。有的军事专家曾预言，未来战争或为隐形武器唱主角的战争(背景介绍)。中国武器装备发展也将隐形化作为第三代武器的一个重要指标，新列装的武器装备基本上皆具有隐形的功能。这些隐形武器，其光学特征可以隐形于地理背景之中，其电磁特征也可以湮没于电子信号频谱之内，使对手无法对其识别(我国现状)。⑦\n这段文字主要介绍："}],"annotatedOptionRich":{"A":[{"text":"未来世界武器发展的主要趋势(片面)"}],"B":[{"text":"军事专家对未来战争模式的预测 ( 片面 )"}],"C":[{"text":"隐形武器具备隐形性能的原因 ( 片面 )"}],"D":[{"text":"中国发展隐形武器的背景及成就"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍隐形武器在世界上的发展(背景),接着介绍中国也在发展隐形武器及取得的成就，为典型的“背景+我国”结构，“我国”是重点， D选项为典型的A且B类选项，概括全面且主语为“我国”,为完美选项；\n其他选项皆未提及“我国”,且A选项、B选项出自背景介绍部分，C选项出自后文解释部分，均犯了片面的错误，排除。","notes":[{"marker":"③","content":"行文结构：二层结构之“背景+我国”。\n开篇介绍背景引出话题：\n隐形武器成为发展趋势；\n后文介绍我国现状及成就：中国也大力发展隐形武器且新列装的武器装备基本上皆具有隐形的功能；\n后文介绍我国，我国是重点。","matchScore":0.7027,"pairingMode":"content-similarity","order":35},{"marker":"38","content":"一正确：指概括全面是正确选项概率非常高。","matchScore":0.3438,"pairingMode":"content-similarity","order":36}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300177,3,'中心理解题','书院是中国历史上一种独具特色的文化教育形式，在书院发展的一千多年历史进程中，它不仅是中国文化的象征，更是中国文化向域外传播的窗口。书院之名起于唐代，由最早的修书、藏书的机构，逐步演变为具有教学、研究功能的场所。书院制度在宋代不断发展、壮大、成熟，清代是书院发展的鼎盛时期，无论是穷乡僻壤，还是边陲小镇都可见到书院。不仅如此，书院还随儒学走出国门，在朝鲜半岛生根、萌芽、兴盛起来，对中国文化传播起着不可替代的作用。
这段文字主要说明：','[{"label":"A","content":"书院的发展经历了漫长的历史过程"},{"label":"B","content":"书院所承载的教育及文化传播功能"},{"label":"C","content":"书院与文明传承之间有着密切关系"},{"label":"D","content":"书院制度的影响遍布我国以及域外"}]','B','文段分析见批注。
文段首句直接给出总观点，根据下文分述内容可将其理解为“书院既是我国独具特色的文化教育形式，也是中国文化的象征和向外传播的窗口”,强调书院包含了“教育”和“文化传播”这两项功能，只有B选项同时提到了书院的这两个特征④,完美选项，当选；
A选项是历程类选项⑧,且只对应分析论证的第一部分，表述片面，排除； D选项只强调了书院制度的文化传播属性，忽略了其教育属性，表述片面，排除；
C选项“文明传承”无中生有，排除；综上，正确答案是B选项。

花生批注：
39 “书院”为全文论述主体。
④ 行文结构：总分结构。
首句给出总观点：
书院是我国独具特色的文化教育形式；
还是中国文化象征，是中国文化向外传播的窗口；
后文从两方面介绍：
“不仅如此”前：介绍书院的教育功能；
“不仅如此”后：介绍书院的文化传播功能。
④ 1、A 且B 类选项，满足一正确；
2 、概括首句作者观点，同时体现书院的“教育”和“文化传播”功能。
④ 文段只在分析论证的第一部分体现了书院的发展(且不是“分1”的全部内容), 不是文段论述的重点。
书院③是中国历史上一种独具特色的文化教育形式，在书院发展的一千多年历史进程中，它不仅是中国文化的象征，更是中国文化向域外传播的窗口(开门见山提出观点)。书院之名起于唐代，由最早的修书、藏书的机构，逐步演变为具有教学、研究功能的场所。书院制度在宋代不断发展、壮大、成熟，清代是书院发展的鼎盛时期，无论是穷乡僻壤，还是边陲小镇都可见到书院(分 1)。不仅如此，书院还随儒学走出国门，在朝鲜半岛生根、萌芽、兴盛起来，对中国文化传播起着不可替代的作用(分2)。@
这段文字主要说明：
A. 书院的发展经历了漫长的历史过程(历程类)
B. 书院所承载的教育及文化传播功能
C. 书院与文明传承之间有着密切关系(无中生有)','2020江苏省考','基础','published','{"globalNumber":177,"setNumber":9,"localNumber":17,"sourceLabel":"2020江苏省考 74%","accuracy":74,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"书院是中国历史上一种独具特色的文化教育形式，在书院发展的一千多年历史进程中，它不仅是中国文化的象征，更是中国文化向域外传播的窗口。书院之名起于唐代，由最早的修书、藏书的机构，逐步演变为具有教学、研究功能的场所。书院制度在宋代不断发展、壮大、成熟，清代是书院发展的鼎盛时期，无论是穷乡僻壤，还是边陲小镇都可见到书院。不仅如此，书院还随儒学走出国门，在朝鲜半岛生根、萌芽、兴盛起来，对中国文化传播起着不可替代的作用。\n这段文字主要说明："}],"optionRich":{"A":[{"text":"书院的发展经历了漫长的历史过程"}],"B":[{"text":"书院所承载的教育及文化传播功能"}],"C":[{"text":"书院与文明传承之间有着密切关系"}],"D":[{"text":"书院制度的影响遍布我国以及域外"}]},"annotatedStemRich":[{"text":"39花生批注：\n“书院”为全文论述主体。\n④花生批注：\n行文结构：总分结构。\n首句给出总观点：\n书院是我国独具特色的文化教育形式；\n还是中国文化象征，是中国文化向外传播的窗口；\n后文从两方面介绍：\n“不仅如此”前：介绍书院的教育功能；\n“不仅如此”后：介绍书院的文化传播功能。\n④花生批注：\n1、A 且B 类选项，满足一正确；\n2 、概括首句作者观点，同时体现书院的“教育”和“文化传播”功能。\n④花生批注：\n文段只在分析论证的第一部分体现了书院的发展(且不是“分1”的全部内容), 不是文段论述的重点。\n"},{"text":"书院","underline":true},{"text":"③是中国历史上一种独具特色的文化教育形式，在书院发展的一千多年历史进程中，它不仅是中国文化的象征，更是中国文化向域外传播的窗口(开门见山提出观点)。书院之名起于唐代，由最早的修书、藏书的机构，逐步演变为具有教学、研究功能的场所。书院制度在宋代不断发展、壮大、成熟，清代是书院发展的鼎盛时期，无论是穷乡僻壤，还是边陲小镇都可见到书院(分 1)。不仅如此，书院还随儒学走出国门，在朝鲜半岛生根、萌芽、兴盛起来，对中国文化传播起着不可替代的作用(分2)。@\n这段文字主要说明："}],"annotatedOptionRich":{"A":[{"text":"书院的发展经历了漫长的历史过程(历程类)"}],"B":[{"text":"书院所承载的教育及文化传播功能"}],"C":[{"text":"书院与文明传承之间有着密切关系(无中生有)"}],"D":[{"text":"书院制度的影响遍布我国以及域外( 片面 )"}]},"practicalAnalysis":"文段分析见批注。\n文段首句直接给出总观点，根据下文分述内容可将其理解为“书院既是我国独具特色的文化教育形式，也是中国文化的象征和向外传播的窗口”,强调书院包含了“教育”和“文化传播”这两项功能，只有B选项同时提到了书院的这两个特征④,完美选项，当选；\nA选项是历程类选项⑧,且只对应分析论证的第一部分，表述片面，排除； D选项只强调了书院制度的文化传播属性，忽略了其教育属性，表述片面，排除；\nC选项“文明传承”无中生有，排除；综上，正确答案是B选项。","notes":[{"marker":"39","content":"“书院”为全文论述主体。","matchScore":1.0224,"pairingMode":"content-similarity","order":37},{"marker":"④","content":"行文结构：总分结构。\n首句给出总观点：\n书院是我国独具特色的文化教育形式；\n还是中国文化象征，是中国文化向外传播的窗口；\n后文从两方面介绍：\n“不仅如此”前：介绍书院的教育功能；\n“不仅如此”后：介绍书院的文化传播功能。","matchScore":1.2016,"pairingMode":"marker-and-content","order":38},{"marker":"④","content":"1、A 且B 类选项，满足一正确；\n2 、概括首句作者观点，同时体现书院的“教育”和“文化传播”功能。","matchScore":1.089,"pairingMode":"marker-and-content","order":39},{"marker":"④","content":"文段只在分析论证的第一部分体现了书院的发展(且不是“分1”的全部内容), 不是文段论述的重点。\n书院③是中国历史上一种独具特色的文化教育形式，在书院发展的一千多年历史进程中，它不仅是中国文化的象征，更是中国文化向域外传播的窗口(开门见山提出观点)。书院之名起于唐代，由最早的修书、藏书的机构，逐步演变为具有教学、研究功能的场所。书院制度在宋代不断发展、壮大、成熟，清代是书院发展的鼎盛时期，无论是穷乡僻壤，还是边陲小镇都可见到书院(分 1)。不仅如此，书院还随儒学走出国门，在朝鲜半岛生根、萌芽、兴盛起来，对中国文化传播起着不可替代的作用(分2)。@\n这段文字主要说明：\nA. 书院的发展经历了漫长的历史过程(历程类)\nB. 书院所承载的教育及文化传播功能\nC. 书院与文明传承之间有着密切关系(无中生有)","matchScore":1.4642,"pairingMode":"marker-and-content","order":40}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300178,3,'标题拟定类','我国地域广阔，各地经济社会发展的类型和水平差异显著,不同区域、层次、类型的教育发展的历史传统、现实模式和未来图景也各有特点。高质量教育体系由充满活力、因地制宜和各具特色的子系统组成，这需要将教育发展的普遍性和特殊性统一起来，既为各地、各校教育改革发展提出硬性底线要求以确保改革创新方向不动摇，也为不同地区、学校发展提供更多弹性和广阔空间以促进更丰富多样的特色发展。
最适合做这段文字标题的是：','[{"label":"A","content":"建设高质量教育体系，需要实施分类指导"},{"label":"B","content":"建设高质量教育体系，需要突出制度引领"},{"label":"C","content":"建设高质量教育体系，需要持续改革创新"},{"label":"D","content":"建设高质量教育体系，需要夯实资源保障"}]','A','文段分析见批注。
文段首先介绍我国各地情况不同，之后用“需要”给出对策：高质量教育体系既需要有硬性底线要求保证创新方向不动摇(普遍性),又要为不同地区提供更多弹性与空间以促进特色发展(特殊性)。
A选项的对策重点“实施分类指导”既对应原文对策后一半(提供弹性与空间以促进特色发展)也对应前文介绍的我国现状(各地情况不同),当选；
B选项的“突出制度引领”、C选项的“持续改革创新”⑥、D选项的“夯实资源保障”均属无中生有，排除。

花生批注：
④③ 行文结构：后对策结构。
文段首先介绍了我国各地情况不同；
之后直接给出对策：高质量教育体系既需要有硬性底线要求保证创新方向不动摇 (普遍性),又要为不同地区提供更多弹性与空间以促进特色发展(特殊性)。
我国地域广阔，各地经济社会发展的类型和水平差异显著,不同区域、层次、类型的教育发展的历史传统、现实模式和未来图景也各有特点(引出话题)。高质量教育体系由充满活力、因地制宜和各具特色的子系统组成，这需要将教育发展的普遍性和特殊性统一起来，既为各地、各校教育改革发展提出硬性底线要求以确保改革创新方向不动摇，也为不同地区、学校发展提供更多弹性和广阔空间以促进更丰富多样的特色发展 ( 后对策 ) 。
最适合做这段文字标题的是：
A. 建设高质量教育体系，需要实施分类指导
B. 建设高质量教育体系，需要突出制度引领(无中生有)
C. 建设高质量教育体系，需要持续改革创新 (无中生有)
④ 有同学可能会疑惑：A选项只说到对策的后一半，不片面吗?
对策虽然是并列的，但要注意原文重点突出的是什么, 有时会有“附带”的不重要对策，原文首先介绍的是我国各地情况不同，针对这一现状，提出了“提供弹性与空间以促进特色发展”的对策，该对策相对更重要。
例如：考前的复习是非常重要高效的，所以考试前一周要在保证身体健康的情况下，更加努力学习；
在没有更全面选项的情况下，对策重点是努力学习，单说努力学习而未提保证健康也可以接受。
45 原文为“既为各地、各校教育改革发展提出硬性底线要求以确保改革创新方向不动摇”,“确保改革创新方向不动摇”是对策“提出硬性底线要求”的效果，且重点是“方向不动摇”,而非“持续改革创新”。','2021年事业单位联考','进阶','published','{"globalNumber":178,"setNumber":9,"localNumber":18,"sourceLabel":"2021年事业单位联考 62%","accuracy":62,"typeAndPassage":"标题拟定类+说理类文章","stemRich":[{"text":"我国地域广阔，各地经济社会发展的类型和水平差异显著,不同区域、层次、类型的教育发展的历史传统、现实模式和未来图景也各有特点。高质量教育体系由充满活力、因地制宜和各具特色的子系统组成，这需要将教育发展的普遍性和特殊性统一起来，既为各地、各校教育改革发展提出硬性底线要求以确保改革创新方向不动摇，也为不同地区、学校发展提供更多弹性和广阔空间以促进更丰富多样的特色发展。\n最适合做这段文字标题的是："}],"optionRich":{"A":[{"text":"建设高质量教育体系，需要实施分类指导"}],"B":[{"text":"建设高质量教育体系，需要突出制度引领"}],"C":[{"text":"建设高质量教育体系，需要持续改革创新"}],"D":[{"text":"建设高质量教育体系，需要夯实资源保障"}]},"annotatedStemRich":[{"text":"④③花生批注：\n行文结构：后对策结构。\n文段首先介绍了我国各地情况不同；\n之后直接给出对策：高质量教育体系既需要有硬性底线要求保证创新方向不动摇 (普遍性),又要为不同地区提供更多弹性与空间以促进特色发展(特殊性)。\n我国地域广阔，各地经济社会发展的类型和水平差异显著,不同区域、层次、类型的教育发展的历史传统、现实模式和未来图景也各有特点(引出话题)。高质量教育体系由充满活力、因地制宜和各具特色的子系统组成，这需要将教育发展的普遍性和特殊性统一起来，既为各地、各校教育改革发展提出硬性底线要求以确保改革创新方向不动摇，也为不同地区、学校发展提供更多弹性和广阔空间以促进更丰富多样的特色发展 ( 后对策 ) 。\n最适合做这段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"建设高质量教育体系，需要实施分类指导"}],"B":[{"text":"建设高质量教育体系，需要突出制度引领(无中生有)"}],"C":[{"text":"建设高质量教育体系，需要持续改革创新 (无中生有)"}],"D":[{"text":"建设高质量教育体系，需要夯实资源保障(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段首先介绍我国各地情况不同，之后用“需要”给出对策：高质量教育体系既需要有硬性底线要求保证创新方向不动摇(普遍性),又要为不同地区提供更多弹性与空间以促进特色发展(特殊性)。\nA选项的对策重点“实施分类指导”既对应原文对策后一半(提供弹性与空间以促进特色发展)也对应前文介绍的我国现状(各地情况不同),当选；\nB选项的“突出制度引领”、C选项的“持续改革创新”⑥、D选项的“夯实资源保障”均属无中生有，排除。","notes":[{"marker":"④③","content":"行文结构：后对策结构。\n文段首先介绍了我国各地情况不同；\n之后直接给出对策：高质量教育体系既需要有硬性底线要求保证创新方向不动摇 (普遍性),又要为不同地区提供更多弹性与空间以促进特色发展(特殊性)。\n我国地域广阔，各地经济社会发展的类型和水平差异显著,不同区域、层次、类型的教育发展的历史传统、现实模式和未来图景也各有特点(引出话题)。高质量教育体系由充满活力、因地制宜和各具特色的子系统组成，这需要将教育发展的普遍性和特殊性统一起来，既为各地、各校教育改革发展提出硬性底线要求以确保改革创新方向不动摇，也为不同地区、学校发展提供更多弹性和广阔空间以促进更丰富多样的特色发展 ( 后对策 ) 。\n最适合做这段文字标题的是：\nA. 建设高质量教育体系，需要实施分类指导\nB. 建设高质量教育体系，需要突出制度引领(无中生有)\nC. 建设高质量教育体系，需要持续改革创新 (无中生有)","matchScore":1.5387,"pairingMode":"content-similarity","order":41},{"marker":"④","content":"有同学可能会疑惑：A选项只说到对策的后一半，不片面吗?\n对策虽然是并列的，但要注意原文重点突出的