INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300179,3,'中心理解题','水熊被认为是世界上最顽强的动物，其显著特征是能在各种极端环境中存活下来。科学家曾经将水熊冰冻在冰层之中，暴露在放射线之下，甚至将它们发送至太空，但令人惊奇的是，水熊仍能从假死状态中复活。最近，科学家揭示了水熊复活的秘密，其DNA 兼具动物和细菌成分，使其成为“弗兰肯斯坦”混合体。此外，科学家们在研究水熊复活过程中哪些基因会被激活时，还发现了一组特殊蛋白质。这组蛋白质能够快速替换体内损耗的水分，并修复受损细胞，致使这种动物接近于不可毁灭状态。
这段文字旨在说明：','[{"label":"A","content":"水熊的显著特征是能在各种极端环境中存活"},{"label":"B","content":"水熊是一种能复活的“弗兰肯斯坦”混合体"},{"label":"C","content":"水熊拥有神秘DNA 使它接近于不可毁灭"},{"label":"D","content":"水熊拥有的特殊蛋白质能修复受损的细胞"}]','C','文段分析见批注。
文段为“背景+新”结构(也可看作果因结构),首先介绍水熊生存能力强这一特点，接着重点介绍科学家关于水熊生命力顽强的新发现(即水熊生命力顽强的原因),全文主要讲的是水熊生命力顽强和其DNA 、特殊蛋白质有关。

花生批注：
④⑦ 行文结构：二层结构之背景 +新(也可看作果因)。
文段先介绍了水熊生命力顽强这一特点；
之后揭示了水熊生命力顽强的原因：DNA 和特殊蛋白质。
A选项、B选项只介绍了水熊生命力顽强的特点，未提及原因，可简单排除；
C选项只谈及神秘DNA 、D选项只谈及特殊蛋白质，均稍显片面；但二者对比，C选项谈及了水熊“不可毁灭”的特点，D选项只谈及“修复受损细胞”; 另外，DNA 出自“科学家揭示秘密”一句，特殊蛋白质出自“此外”一句，为补充部分，显然神秘DNA 更是水熊生命力顽强的主要原因；
综上，答案为C选项。','2020年海南省考','挑战','published','{"globalNumber":179,"setNumber":9,"localNumber":19,"sourceLabel":"2020年海南省考 35%","accuracy":35,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"水熊被认为是世界上最顽强的动物，其显著特征是能在各种极端环境中存活下来。科学家曾经将水熊冰冻在冰层之中，暴露在放射线之下，甚至将它们发送至太空，但令人惊奇的是，水熊仍能从假死状态中复活。最近，科学家揭示了水熊复活的秘密，其DNA 兼具动物和细菌成分，使其成为“弗兰肯斯坦”混合体。此外，科学家们在研究水熊复活过程中哪些基因会被激活时，还发现了一组特殊蛋白质。这组蛋白质能够快速替换体内损耗的水分，并修复受损细胞，致使这种动物接近于不可毁灭状态。\n这段文字旨在说明："}],"optionRich":{"A":[{"text":"水熊的显著特征是能在各种极端环境中存活"}],"B":[{"text":"水熊是一种能复活的“弗兰肯斯坦”混合体"}],"C":[{"text":"水熊拥有神秘DNA 使它接近于不可毁灭"}],"D":[{"text":"水熊拥有的特殊蛋白质能修复受损的细胞"}]},"annotatedStemRich":[{"text":"水熊被认为是世界上最顽强的动物，其显著特征是能在各种极端环境中存活下来。科学家曾经将水熊冰冻在冰层之中，暴露在放射线之下，甚至将它们发送至太空，但令人惊奇的是，水熊仍能从假死状态中复活(介绍水熊生命力顽强)。"},{"text":"最近，科学家揭示了水熊复活的秘密，其DNA兼具动物和细菌成分， ","underline":true},{"text":" "},{"text":"使其成为“弗兰肯斯坦”混合体。此外，科学家们在研究水熊复活过程中哪些基因会被激活时，还发现了一组特殊蛋白质。这组蛋白质能够快速替换体内损耗的水分，并修复受损细胞，致使这种动物接近于不可毁灭状态","underline":true},{"text":" (揭示水熊复活的秘密)。④\n这段文字旨在说明："}],"annotatedOptionRich":{"A":[{"text":"水熊的显著特征是能在各种极端环境中存活(未谈及“新发现”)"}],"B":[{"text":"水熊是一种能复活的“弗兰肯斯坦”混合体(未谈及“新发现”)"}],"C":[{"text":"水熊拥有神秘DNA 使它接近于不可毁灭"}],"D":[{"text":"水熊拥有的特殊蛋白质能修复受损的细胞 (片面且非重点)"}]},"practicalAnalysis":"文段分析见批注。\n文段为“背景+新”结构(也可看作果因结构),首先介绍水熊生存能力强这一特点，接着重点介绍科学家关于水熊生命力顽强的新发现(即水熊生命力顽强的原因),全文主要讲的是水熊生命力顽强和其DNA 、特殊蛋白质有关。","notes":[{"marker":"④⑦","content":"行文结构：二层结构之背景 +新(也可看作果因)。\n文段先介绍了水熊生命力顽强这一特点；\n之后揭示了水熊生命力顽强的原因：DNA 和特殊蛋白质。\nA选项、B选项只介绍了水熊生命力顽强的特点，未提及原因，可简单排除；\nC选项只谈及神秘DNA 、D选项只谈及特殊蛋白质，均稍显片面；但二者对比，C选项谈及了水熊“不可毁灭”的特点，D选项只谈及“修复受损细胞”; 另外，DNA 出自“科学家揭示秘密”一句，特殊蛋白质出自“此外”一句，为补充部分，显然神秘DNA 更是水熊生命力顽强的主要原因；\n综上，答案为C选项。","matchScore":0.4382,"pairingMode":"content-similarity","order":45}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300180,3,'语句排序类','①中国企业若想出口稀土产品，必须向行业巨头缴纳高额的专利许可费，否则产品无法出口
②稀土永磁材料领域的研发重点包括提高材料性能、扩大高端领域应用等；稀土发光材料领域的技术创新点集中在光电材料、反光材料等
③经历了被人“扼住咽喉”的切肤之痛后，我国稀土企业的创新脚步愈加快速
④然而在很长一段时间内，我国的稀土企业在国际市场处于受制于人的局面
⑤多年来，在与世界各国的“稀土大战”中，我国凭借世界第一的稀土储量，逐步在开采、分离技术领域确立了全球领先的地位
⑥目前，我国稀土领域的创新主要集中于产业链上游的稀土材料领域，多家企业重点发展具有超高性能的稀土永磁材料、稀土发光材料等
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"⑥④①③⑤②"},{"label":"B","content":"⑤④①③⑥②"},{"label":"C","content":"⑤⑥②①④③"},{"label":"D","content":"⑥②⑤④①③"}]','B','对首句⑤、⑥进行分析时，无法确定谁做首句，寻找其他切入点；
④句出现转折词“然而”,转折后强调我国稀土企业曾在国际市场受制于人，根据转折前后语义相反可知，④句前应提到我国稀土企业在国际市场上处于优势地位。因此，⑤应在④前，排除A选项；
③和⑥具有相同词“创新”,⑥具体说明的是我国在稀土领域的创新方向，应当置于③“我国稀土企业的创新脚步愈加快速”之后，作为对③的解释说明和具体展开，排除C选项、D选项；
综上，B选项当选。
