INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300181,3,'中心理解题','现在经常听到一种说法，智商不敌情商。一个人能走到哪里，取得什么成就，关键在于情商，这种“情商决定论”甚嚣尘上，令人生疑。在我们身边，无论是生活中，还是工作中，只要一个人的事情没做好，都会跟情商不高挂起钩来。事实上，我们都夸大了情商的作用，忽视了智商、实力、勤奋，以为只要玩转情商就能步步高升，其实不然。人在职场，情商固然重要，但决定性因素还是智商和才华，玩情商可以让你八面玲珑，但毕竟玩不出实际业绩，也玩不出科研成果来。一个人有真才实学，本领过硬，工作勤奋，那么情商其实就是锦上添花的事情了。
这段文字，作者意在说明：','[{"label":"A","content":"在职场中，智商比情商更加重要"},{"label":"B","content":"情商只是锦上添花，智商方能决定成败"},{"label":"C","content":"“情商决定论”并不正确，情商的作用不应夸大"},{"label":"D","content":"成功靠的是真才实学，过硬本领，而不是玩转情商"}]','C','文段分析见批注。
文段开篇指出问题：情商决定论甚嚣尘上；之后给出作者观点：情商决定论夸大了情商的作用；
C选项既针对问题“情商决定论甚嚣尘上”也符合观点“情商的作用不应夸大”,完美选项，当选；
A选项是区别比较联系类选项，文章重点谈论的是“情商”,不是“智商”与“情商”二者的比较，排除；B选项、D选项出自文段分析论证部分，出处有误且未提及“情商决定论”,排除。

花生批注：
① 情商决定论是全文论述话题。
② 行文结构：前观点结构。
开篇引出问题：
“情商决定论”甚嚣尘上；
再通过转折提出观点：
我们其实夸大了情商的作用，忽视了智商、实力、勤奋；最后分析论证。
③ 原文是“职场中的决定性因素是智商和才华”,不意味着“只有智商才能决定成败”,过于绝对化；
另，原文有“一个人有真才实学，本领过硬，工作勤奋，那么情商就是锦上添花”, 是在上述前提下，情商是锦上添花，单说“情商只是锦上添花”也过于绝对；
但是，考场上只要分析清楚结构，重点抓问题和对策/ 观点，论证中的“车轱辘话”并不重要。
