"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300182,3,'中心理解题','推动义务教育均衡发展，也要做到“精准灌溉”。地区、学校、学生不同，存在的教育发展问题也是千差万别。一位教育领域的干部坦言，西部农村地区教学点多、小规模学校多，学校撤并往往面临两难：撤了容易造成上学远、上学难，甚至引起辍学；不撤又无法解决学校规模小、师资差、质量低的窘况。如果没有经过事先周密调研，政策上搞“一刀切”,盲目调整学校布局，无疑给农家孩子上学平添了不少负担。从这个角度来看，有了普惠性的政策，还需因地制宜、因人而异，更加注重改革的系统性、整体性、协同性，兼顾教育发展需求与群众便利需要，确保教育公平稳步推进。这段文字意在说明：','[{"label":"A","content":"普及义务教育需要经过精准调研"},{"label":"B","content":"西部农村地区教育发展的两难选择"},{"label":"C","content":"普惠性政策对教育均衡发展的重要性"},{"label":"D","content":"义务教育均衡发展需要统筹兼顾"}]','D','文段分析见批注。
文段开篇给出对策：义务教育均衡发展要做到精准灌溉；后文解释了“精准灌溉”的原因：条件不同，教育发展问题也千差万别；文末又重复对策：要因地制宜、因人而异，注重系统性、整体性和协同性，兼顾教育发展需求与群众需求。D选项的“统筹兼顾⑥”可看作是对策的同义替换，且该选项问题正确，当选；
A选项的“普及义务教育”属偷换概念，“精准调研”属杂糅，排除； B选项属问题表述，未体现对策，排除；C选项，原文说的是“有了普惠性政策，还需……”,“还需”后的做法更重要，而且未提及普惠性政策的意义，排除。

花生批注：
⑤ 行文结构：前对策结构。
文段开篇给出对策：
义务教育均衡发展要做到精准灌溉；
再分析论证：
因为条件不同，存在的教育发展问题千差万别；
最后重复对策：
要因地制宜、因人而异，注重系统性、整体性和协同性，兼顾教育发展需求与群众需求。
⑥ 统筹兼顾指的是统一筹划，全面照顾；
统筹对应原文文末的“因地制宜、因人而异，注重改革的系统性、整体性和协同性”;
兼顾对应原文文末的“兼顾教育发展需求和群众便利需要”。','2018年福建选调','基础','published','{"globalNumber":182,"setNumber":10,"localNumber":2,"sourceLabel":"2018年福建选调 76%","accuracy":76,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"推动义务教育均衡发展，也要做到“精准灌溉”。地区、学校、学生不同，存在的教育发展问题也是千差万别。一位教育领域的干部坦言，西部农村地区教学点多、小规模学校多，学校撤并往往面临两难：撤了容易造成上学远、上学难，甚至引起辍学；不撤又无法解决学校规模小、师资差、质量低的窘况。如果没有经过事先周密调研，政策上搞“一刀切”,盲目调整学校布局，无疑给农家孩子上学平添了不少负担。从这个角度来看，有了普惠性的政策，还需因地制宜、因人而异，更加注重改革的系统性、整体性、协同性，兼顾教育发展需求与群众便利需要，确保教育公平稳步推进。这段文字意在说明："}],"optionRich":{"A":[{"text":"普及义务教育需要经过精准调研"}],"B":[{"text":"西部农村地区教育发展的两难选择"}],"C":[{"text":"普惠性政策对教育均衡发展的重要性"}],"D":[{"text":"义务教育均衡发展需要统筹兼顾"}]},"annotatedStemRich":[{"text":"推动"},{"text":"义务教育均衡发展","underline":true},{"text":"④,也要做到“精准灌溉”(前对策)。地区、学校、学生不同，存在的教育发展问题也是千差万别。一位教育领域的干部坦言，西部农村地区教学点多、小规模学校多，学校撤并往往面临两难：撤了容易造成上学远、上学难，甚至引起辍学；不撤又无法解决学校规模小、师资差、质量低的窘况。如果没有经过事先周密调研，政策上搞“一刀切”,盲目调整学校布局，无疑给农家孩子上学平添了不少负担(解释说明)。从这个角度来看，有了普惠性的政策，还需因地制宜、因人而异，更加注重改革的系统性、整体性、协同性，兼顾教育发展需求与群众便利需要，确保教育公平稳步推进 (重复对策 ) 。⑤\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"普及义务教育需要经过精准调研(对策问题均有误)"}],"B":[{"text":"西部农村地区教育发展的两难选择(问题表述)"}],"C":[{"text":"普惠性政策对教育均衡发展的重要性(无中生有)"}],"D":[{"text":"义务教育均衡发展需要统筹兼顾"}]},"practicalAnalysis":"文段分析见批注。\n文段开篇给出对策：义务教育均衡发展要做到精准灌溉；后文解释了“精准灌溉”的原因：条件不同，教育发展问题也千差万别；文末又重复对策：要因地制宜、因人而异，注重系统性、整体性和协同性，兼顾教育发展需求与群众需求。D选项的“统筹兼顾⑥”可看作是对策的同义替换，且该选项问题正确，当选；\nA选项的“普及义务教育”属偷换概念，“精准调研”属杂糅，排除； B选项属问题表述，未体现对策，排除；C选项，原文说的是“有了普惠性政策，还需……”,“还需”后的做法更重要，而且未提及普惠性政策的意义，排除。","notes":[{"marker":"⑤","content":"行文结构：前对策结构。\n文段开篇给出对策：\n义务教育均衡发展要做到精准灌溉；\n再分析论证：\n因为条件不同，存在的教育发展问题千差万别；\n最后重复对策：\n要因地制宜、因人而异，注重系统性、整体性和协同性，兼顾教育发展需求与群众需求。","matchScore":1.0018,"pairingMode":"marker-and-content","order":3},{"marker":"⑥","content":"统筹兼顾指的是统一筹划，全面照顾；\n统筹对应原文文末的“因地制宜、因人而异，注重改革的系统性、整体性和协同性”;\n兼顾对应原文文末的“兼顾教育发展需求和群众便利需要”。","matchScore":0.7783,"pairingMode":"marker-and-content","order":4}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300183,3,'中心理解题','古人云：“道不同而不相悖，万物并育而不相害。”建设文化强国，必不能抛弃传统文化，更不能盲目沉溺在对外来事物迷离含混的幻想之中。相反，我们首先要坚守自己的长处，同时要懂得交流、借鉴、分殊和辨别异质文明和他者文化的“表象”与“根质”。只有这样，我们才能最终实现中华民族伟大复兴的“中国梦”。
这段文字的主旨是：','[{"label":"A","content":"对待传统的旧有文化，我们应该去粗取精"},{"label":"B","content":"对待异质文明和他者文化，我们应该兼容并包"},{"label":"C","content":"我国建设文化强国，应吸收和借鉴中外文明成果"},{"label":"D","content":"建设文化强国有助于实现中华民族伟大复兴"}]','C','文段分析见批注。
文段全文均为对策表述，提出建设文化强国既要坚守自己长处(我国传统文化)也要吸收借鉴外来文化。 C选项问题、对策均正确，为完美选项，当选；
A选项、B选项，未提及“建设文化强国”这一问题，且分别只谈及传统文化、外来文化一方面，均片面，排除；
D选项可翻译为“实现中华民族伟大复兴需要建设文化强国”,“建设文化强国”成了“伟大复兴”的对策，但文段谈的是“建设文化强国”的具体措施，排除。

花生批注：
⑦ 尾句可翻译为“只有在建设文化强国时，借鉴吸收中外文化，才能实现中华民族伟大复兴的‘中国梦’”,问题是“建设文化强国”,对策是“借鉴吸收中外文化”, 最终目的是“实现中华民族的伟大复兴”。
例如：只有复习时更加努力，才能最终考上公务员；重点是“复习时要更加努力”, 最终的目的是“考上公务员”。
⑧ 行文结构：后对策结构。
全文引出话题后均为提出对策，对策从正反两方向提出。反面对策：建设文化强国，不能抛弃传统文化也不能盲目沉溺于外国文化；
正面对策：建设文化强国，要坚守自己长处也要吸收外来文化。
这段文字的主旨是：
A. 对待传统的旧有文化，我们应该去粗取精(片面)
B. 对待异质文明和他者文化，我们应该兼容并包(片面)
C. 我国建设文化强国，应吸收和借鉴中外文明成果','2021年广东选调','基础','published','{"globalNumber":183,"setNumber":10,"localNumber":3,"sourceLabel":"2021年广东选调 73%","accuracy":73,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"古人云：“道不同而不相悖，万物并育而不相害。”建设文化强国，必不能抛弃传统文化，更不能盲目沉溺在对外来事物迷离含混的幻想之中。相反，我们首先要坚守自己的长处，同时要懂得交流、借鉴、分殊和辨别异质文明和他者文化的“表象”与“根质”。只有这样，我们才能最终实现中华民族伟大复兴的“中国梦”。\n这段文字的主旨是："}],"optionRich":{"A":[{"text":"对待传统的旧有文化，我们应该去粗取精"}],"B":[{"text":"对待异质文明和他者文化，我们应该兼容并包"}],"C":[{"text":"我国建设文化强国，应吸收和借鉴中外文明成果"}],"D":[{"text":"建设文化强国有助于实现中华民族伟大复兴"}]},"annotatedStemRich":[{"text":"古人云：“道不同而不相悖，万物并育而不相害。”建设文化强国，必不能抛弃传统文化，更不能盲目沉溺在对外来事物迷离含混的幻想之中。相反，我们首先要坚守自己的长处，同时要懂得交流、借鉴、分殊和辨别异质文明和他者文化的“表象”与“根质”。只有这样，我们才能最终实现中华民族伟大复兴的“中国梦”。\n这段文字的主旨是："}],"annotatedOptionRich":{"A":[{"text":"对待传统的旧有文化，我们应该去粗取精"}],"B":[{"text":"对待异质文明和他者文化，我们应该兼容并包"}],"C":[{"text":"我国建设文化强国，应吸收和借鉴中外文明成果"}],"D":[{"text":"建设文化强国有助于实现中华民族伟大复兴"}]},"practicalAnalysis":"文段分析见批注。\n文段全文均为对策表述，提出建设文化强国既要坚守自己长处(我国传统文化)也要吸收借鉴外来文化。 C选项问题、对策均正确，为完美选项，当选；\nA选项、B选项，未提及“建设文化强国”这一问题，且分别只谈及传统文化、外来文化一方面，均片面，排除；\nD选项可翻译为“实现中华民族伟大复兴需要建设文化强国”,“建设文化强国”成了“伟大复兴”的对策，但文段谈的是“建设文化强国”的具体措施，排除。","notes":[{"marker":"⑦","content":"尾句可翻译为“只有在建设文化强国时，借鉴吸收中外文化，才能实现中华民族伟大复兴的‘中国梦’”,问题是“建设文化强国”,对策是“借鉴吸收中外文化”, 最终目的是“实现中华民族的伟大复兴”。\n例如：只有复习时更加努力，才能最终考上公务员；重点是“复习时要更加努力”, 最终的目的是“考上公务员”。","matchScore":0.59,"pairingMode":"content-similarity","order":5},{"marker":"⑧","content":"行文结构：后对策结构。\n全文引出话题后均为提出对策，对策从正反两方向提出。反面对策：建设文化强国，不能抛弃传统文化也不能盲目沉溺于外国文化；\n正面对策：建设文化强国，要坚守自己长处也要吸收外来文化。\n这段文字的主旨是：\nA. 对待传统的旧有文化，我们应该去粗取精(片面)\nB. 对待异质文明和他者文化，我们应该兼容并包(片面)\nC. 我国建设文化强国，应吸收和借鉴中外文明成果","matchScore":0.5817,"pairingMode":"content-similarity","order":6}],"pairingMode":"validated-sequence-fallback"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300184,3,'细节判断类','美国犹他州立大学和韩国建国大学的最新研究认为，人们对社交媒体上的新闻或信息是否存在偏见，除了信息本身的原因外，与分享者也有关系。尤其是对立场较为公正、中立的新闻而言，分享者的身份更能够影响人们的判断。以美国为例，62%的成年人通过社交媒体来获取新闻资讯，但社交媒体上的新闻资讯更多是个人用户分享的信息，人际关系往往会影响人们对新闻信息的判断。
根据上述文字，下列陈述正确的是：','[{"label":"A","content":"人们对社交媒体上信息是否可靠的判断和信息本身可靠性没有什么关联"},{"label":"B","content":"社交媒体上信息分享者的身份和人际关系决定人们对信息可靠性的判断"},{"label":"C","content":"社交媒体上新闻或信息的可靠性和信息本身、信息分享者等因素都相关"},{"label":"D","content":"人们根据社交媒体上分享者的社会影响力判断其分享的新闻资讯可靠性"}]','C','文段分析见批注。
A选项，根据第一句可知，人们的判断和信息本身有关，错误；

花生批注：
⑨ 第一句：对社交媒体上的新闻或信息是否有偏见，和信息本身、分享者有关；
第二句：尤其对于公正中立的新闻，分享者身份更影响判断；
第三句：社交媒体上分享信息，人际关系更影响判断。
片段阅读600 四(上册)
B选项，“决定”为绝对化表述，原文表述为“分享者的身份影响人们的判断”、
⑩ “人际关系影响人们的判断”,“影响”不代表“决定”,错误；
“社交媒体上新闻或信息的可靠性”是“人们对社交媒体上的新闻或信息是否存在偏见”的同义替换。
C选项，是首句的同义替换，正确； ⑩
D选项，“社会影响力影响新闻可靠性”无中生有，错误；综上，正确答案是C选项。','2021年贵州省事业单位','进阶','published','{"globalNumber":184,"setNumber":10,"localNumber":4,"sourceLabel":"2021年贵州省事业单位67%","accuracy":67,"typeAndPassage":"细节判断类","stemRich":[{"text":"美国犹他州立大学和韩国建国大学的最新研究认为，人们对社交媒体上的新闻或信息是否存在偏见，除了信息本身的原因外，与分享者也有关系。尤其是对立场较为公正、中立的新闻而言，分享者的身份更能够影响人们的判断。以美国为例，62%的成年人通过社交媒体来获取新闻资讯，但社交媒体上的新闻资讯更多是个人用户分享的信息，人际关系往往会影响人们对新闻信息的判断。\n根据上述文字，下列陈述正确的是："}],"optionRich":{"A":[{"text":"人们对社交媒体上信息是否可靠的判断和信息本身可靠性没有什么关联"}],"B":[{"text":"社交媒体上信息分享者的身份和人际关系决定人们对信息可靠性的判断"}],"C":[{"text":"社交媒体上新闻或信息的可靠性和信息本身、信息分享者等因素都相关"}],"D":[{"text":"人们根据社交媒体上分享者的社会影响力判断其分享的新闻资讯可靠性"}]},"annotatedStemRich":[{"text":"美国犹他州立大学和韩国建国大学的最新研究认为，人们对社交媒体上的新闻或信息是否存在偏见，除了信息本身的原因外，与分享者也有关系。尤其是对立场较为公正、中立的新闻而言，分享者的身份更能够影响人们的判断。以美国为例，62%的成年人通过社交媒体来获取新闻资讯，但社交媒体上的新闻资讯更多是个人用户分享的信息，人际关系往往会影响人们对新闻信息的判断。⑨\n根据上述文字，下列陈述正确的是："}],"annotatedOptionRich":{"A":[{"text":"人们对社交媒体上信息是否可靠的判断和信息本身可靠性没有什么关联 (本身有误)"}],"B":[{"text":"社交媒体上信息分享者的身份和人际关系决定人们对信息可靠性的判断 (绝对化)"}],"C":[{"text":"社交媒体上新闻或信息的可靠性和信息本身、信息分享者等因素都相关"}],"D":[{"text":"人们根据社交媒体上分享者的社会影响力判断其分享的新闻资讯可靠性 (无中生有)"}]},"practicalAnalysis":"文段分析见批注。\nA选项，根据第一句可知，人们的判断和信息本身有关，错误；","notes":[{"marker":"⑨","content":"第一句：对社交媒体上的新闻或信息是否有偏见，和信息本身、分享者有关；\n第二句：尤其对于公正中立的新闻，分享者身份更影响判断；\n第三句：社交媒体上分享信息，人际关系更影响判断。\n片段阅读600 四(上册)\nB选项，“决定”为绝对化表述，原文表述为“分享者的身份影响人们的判断”、","matchScore":0.6501,"pairingMode":"marker-and-content","order":7},{"marker":"⑩","content":"“人际关系影响人们的判断”,“影响”不代表“决定”,错误；\n“社交媒体上新闻或信息的可靠性”是“人们对社交媒体上的新闻或信息是否存在偏见”的同义替换。\nC选项，是首句的同义替换，正确； ⑩\nD选项，“社会影响力影响新闻可靠性”无中生有，错误；综上，正确答案是C选项。","matchScore":0.5573,"pairingMode":"content-similarity","order":8}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300185,3,'词句理解题','个人认为，电动汽车的部件品种应该由企业选择，市场来裁判。电池、电机、电控等部件的品种都很多，都应该由企业根据总体设计和市场进行选择，没有必要由标准来越俎代庖。欧、美、日法规当中低速电动车标准里面都没有限定电池，未排斥铅酸电池，而装有铅酸电池的中国品牌低速电动车畅销国外。因此，中国的低速电动车标准不应该限制铅酸电池。
文中“越俎代庖”的“庖”指的是：','[{"label":"A","content":"装有铅酸电池的中国品牌低速电动车畅销国外的事实"},{"label":"B","content":"欧、美、日法规里的中低速电动车标准"},{"label":"C","content":"市场以及企业的总体设计"},{"label":"D","content":"国内对低速电动车的限定"}]','C','首先明确“越俎代庖”这一成语的意思，原指主持祭礼的人跨过礼器(指不尽自己的职责)去代替厨师下厨房做饭，后比喻越权办事或包办代替。其中“俎”为主持祭祀的人，“庖”为厨师，即本应该做此事的主体；
根据原文“电池、电机、电控等部件的品种都很多，都应该由企业根据总体设计和市场进行选择，没有必要由标准来越俎代庖。”可知，作者认为应由“企业和市场”来选择电动汽车的部件品种，即“企业和市场”为“庖”①,“标准”为“俎”,对应C选项。

花生批注：
⑪ 即没必要由“标准(俎)”代替“企业和市场(庖)”去选择电动汽车的部件品种。
⑫ 前四句话介绍了第一个原因：身体中积蓄起的“具有很强抗寒能力”的盐类和能变为糖的淀粉让细小植物枝叶和娇嫩蔬菜等不易冻死。
⑬ ⑤⑥句话介绍了第二个原因：植物体内能“避免细胞内部结冰”的不饱和脂肪酸或抗冻蛋白让细小植物枝叶和娇嫩蔬菜等不易冻死。
个人认为，电动汽车的部件品种应该由企业选择，市场来裁判。电池、电机、电控等部件的品种都很多，都应该由企业根据总体设计和市场进行选择，没有必要由标准来越俎代庖。欧、美、日法规当中低速电动车标准里面都没有限定电池，未排斥铅酸电池，而装有铅酸电池的中国品牌低速电动车畅销国外。因此，中国的低速电动车标准不应该限制铅酸电池。
文中“越俎代庖”的“庖”指的是：
A. 装有铅酸电池的中国品牌低速电动车畅销国外的事实
B. 欧、美、日法规里的中低速电动车标准
C. 市场以及企业的总体设计
D. 国内对低速电动车的限定','2017年河南选调','进阶','published','{"globalNumber":185,"setNumber":10,"localNumber":5,"sourceLabel":"2017年河南选调 54%","accuracy":54,"typeAndPassage":"词句理解题","stemRich":[{"text":"个人认为，电动汽车的部件品种应该由企业选择，市场来裁判。电池、电机、电控等部件的品种都很多，都应该由企业根据总体设计和市场进行选择，没有必要由标准来"},{"text":"越俎代庖","underline":true},{"text":"。欧、美、日法规当中低速电动车标准里面都没有限定电池，未排斥铅酸电池，而装有铅酸电池的中国品牌低速电动车畅销国外。因此，中国的低速电动车标准不应该限制铅酸电池。\n文中“越俎代庖”的“庖”指的是："}],"optionRich":{"A":[{"text":"装有铅酸电池的中国品牌低速电动车畅销国外的事实"}],"B":[{"text":"欧、美、日法规里的中低速电动车标准"}],"C":[{"text":"市场以及企业的总体设计"}],"D":[{"text":"国内对低速电动车的限定"}]},"annotatedStemRich":[{"text":"⑪花生批注：\n即没必要由“标准(俎)”代替“企业和市场(庖)”去选择电动汽车的部件品种。\n⑫花生批注：\n前四句话介绍了第一个原因：身体中积蓄起的“具有很强抗寒能力”的盐类和能变为糖的淀粉让细小植物枝叶和娇嫩蔬菜等不易冻死。\n⑬花生批注：\n⑤⑥句话介绍了第二个原因：植物体内能“避免细胞内部结冰”的不饱和脂肪酸或抗冻蛋白让细小植物枝叶和娇嫩蔬菜等不易冻死。\n个人认为，电动汽车的部件品种应该由企业选择，市场来裁判。电池、电机、电控等部件的品种都很多，都应该由企业根据总体设计和市场进行选择，没有必要由标准来越俎代庖。欧、美、日法规当中低速电动车标准里面都没有限定电池，未排斥铅酸电池，而装有铅酸电池的中国品牌低速电动车畅销国外。因此，中国的低速电动车标准不应该限制铅酸电池。\n文中“越俎代庖”的“庖”指的是："}],"annotatedOptionRich":{"A":[{"text":"装有铅酸电池的中国品牌低速电动车畅销国外的事实"}],"B":[{"text":"欧、美、日法规里的中低速电动车标准"}],"C":[{"text":"市场以及企业的总体设计"}],"D":[{"text":"国内对低速电动车的限定"}]},"practicalAnalysis":"首先明确“越俎代庖”这一成语的意思，原指主持祭礼的人跨过礼器(指不尽自己的职责)去代替厨师下厨房做饭，后比喻越权办事或包办代替。其中“俎”为主持祭祀的人，“庖”为厨师，即本应该做此事的主体；\n根据原文“电池、电机、电控等部件的品种都很多，都应该由企业根据总体设计和市场进行选择，没有必要由标准来越俎代庖。”可知，作者认为应由“企业和市场”来选择电动汽车的部件品种，即“企业和市场”为“庖”①,“标准”为“俎”,对应C选项。","notes":[{"marker":"⑪","content":"即没必要由“标准(俎)”代替“企业和市场(庖)”去选择电动汽车的部件品种。","matchScore":1.0847,"pairingMode":"marker-and-content","order":9},{"marker":"⑫","content":"前四句话介绍了第一个原因：身体中积蓄起的“具有很强抗寒能力”的盐类和能变为糖的淀粉让细小植物枝叶和娇嫩蔬菜等不易冻死。","matchScore":1.1599,"pairingMode":"marker-and-content","order":10},{"marker":"⑬","content":"⑤⑥句话介绍了第二个原因：植物体内能“避免细胞内部结冰”的不饱和脂肪酸或抗冻蛋白让细小植物枝叶和娇嫩蔬菜等不易冻死。\n个人认为，电动汽车的部件品种应该由企业选择，市场来裁判。电池、电机、电控等部件的品种都很多，都应该由企业根据总体设计和市场进行选择，没有必要由标准来越俎代庖。欧、美、日法规当中低速电动车标准里面都没有限定电池，未排斥铅酸电池，而装有铅酸电池的中国品牌低速电动车畅销国外。因此，中国的低速电动车标准不应该限制铅酸电池。\n文中“越俎代庖”的“庖”指的是：\nA. 装有铅酸电池的中国品牌低速电动车畅销国外的事实\nB. 欧、美、日法规里的中低速电动车标准\nC. 市场以及企业的总体设计\nD. 国内对低速电动车的限定","matchScore":1.4721,"pairingMode":"marker-and-content","order":11}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300186,3,'词句理解题','多年生植物进入休眠期后，①体内的生理代谢活动并未停止。②其营养物质、酶的活性和内源激素都在发生变化。③它们会在身体中积蓄起盐类物质和能变为糖的淀粉。④而盐类和含糖溶液有很强的抗寒能力。⑤有的植物还能增加体内不饱和脂肪酸或抗冻蛋白等。⑥它们能避免细胞内部结冰。
⑦不同植物不同命。粗大的树木不怕冻可以用寒气不易侵入来解释；那么,细小的植物枝叶、娇嫩的蔬菜等不易冻死的主要原因就在于此。
在上述文字最后一句中标粗的“此”指代的是：','[{"label":"A","content":"①⑦"},{"label":"B","content":"②④"},{"label":"C","content":"③⑤"},{"label":"D","content":"④⑥"}]','C','文末“此”指的是细小的植物枝叶、娇嫩的蔬菜不易冻死的原因，故需要分析选项哪两句的组合能解释为何不易冻死；
根据“批注”可知：植物体内积蓄的盐类物质和可变为糖的淀粉、体内不饱和脂肪酸或抗冻蛋白是让自己“不被冻死”的原因，即“此”指代③⑤句， C选项正确。
④⑥句是解释“盐类物质和可变为糖的淀粉、体内不饱和脂肪酸或抗冻蛋白”的抗寒属性，并非细小的植物枝叶、娇嫩的蔬菜不易冻死的原因；
例如：下雨时我打了伞，伞能防雨；
我没被雨淋的原因是“伞”, 而不是“伞能防雨”;“伞能防雨”是解释，“伞”是我没被雨淋的原因。','2019年河南省考','进阶','published','{"globalNumber":186,"setNumber":10,"localNumber":6,"sourceLabel":"2019年河南省考 55%","accuracy":55,"typeAndPassage":"词句理解题","stemRich":[{"text":"多年生植物进入休眠期后，①体内的生理代谢活动并未停止。②其营养物质、酶的活性和内源激素都在发生变化。③它们会在身体中积蓄起盐类物质和能变为糖的淀粉。④而盐类和含糖溶液有很强的抗寒能力。⑤有的植物还能增加体内不饱和脂肪酸或抗冻蛋白等。⑥它们能避免细胞内部结冰。\n⑦不同植物不同命。粗大的树木不怕冻可以用寒气不易侵入来解释；那么,细小的植物枝叶、娇嫩的蔬菜等不易冻死的主要原因就在于此。\n在上述文字最后一句中标粗的“此”指代的是："}],"optionRich":{"A":[{"text":"①⑦"}],"B":[{"text":"②④"}],"C":[{"text":"③⑤"}],"D":[{"text":"④⑥"}]},"annotatedStemRich":[{"text":"多年生植物进入休眠期后，"},{"text":"①体内的生理代谢活动并未停止。②其营养物质、酶的活性和内源激素都在发生变化。③它们会在身体中积蓄起盐类物质和能变为糖的淀粉。④而盐类和含糖溶液有很强的抗寒能力","underline":true},{"text":"②。"},{"text":"⑤有的植物还能增加体内不饱和脂肪酸或抗冻蛋白等。⑥它们能避免细胞内部结冰","underline":true},{"text":"。 ⑦不同植物不同命。粗大的树木不怕冻可以用寒气不易侵入来解释；那么,细小的植物枝叶、娇嫩的蔬菜等不易冻死的主要原因就在于此。\n"},{"text":"四海公考","bold":true},{"text":"练习题10套\n在上述文字最后一句中标粗的“此”指代的是："}],"annotatedOptionRich":{"A":[{"text":"①⑦"}],"B":[{"text":"②④"}],"C":[{"text":"③⑤"}],"D":[{"text":"④"},{"text":"⑥","underline":true}]},"practicalAnalysis":"文末“此”指的是细小的植物枝叶、娇嫩的蔬菜不易冻死的原因，故需要分析选项哪两句的组合能解释为何不易冻死；\n根据“批注”可知：植物体内积蓄的盐类物质和可变为糖的淀粉、体内不饱和脂肪酸或抗冻蛋白是让自己“不被冻死”的原因，即“此”指代③⑤句， C选项正确。\n④⑥句是解释“盐类物质和可变为糖的淀粉、体内不饱和脂肪酸或抗冻蛋白”的抗寒属性，并非细小的植物枝叶、娇嫩的蔬菜不易冻死的原因；\n例如：下雨时我打了伞，伞能防雨；\n我没被雨淋的原因是“伞”, 而不是“伞能防雨”;“伞能防雨”是解释，“伞”是我没被雨淋的原因。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300187,3,'中心理解题','早在先秦时期，我国就逐渐形成了以炎黄华夏为凝聚核心、“五方之民”共天下的交融格局。秦国“书同文，车同轨，量同衡，行同伦”,开启了中国统一的多民族国家发展的历程。此后，无论哪个民族入主中原，都以统一天下为己任，都以中华文化的正统自居。分立如南北朝，都自诩中华正统；对峙如宋辽夏金，都被称为“桃花石”;统一如秦汉、隋唐、元明清，更是“六合同风，九州共贯”。秦汉雄风、大唐气象、康乾盛世，都是各民族共同铸就的历史。今天，我们实现中国梦，就要紧紧依靠各族人民的力量。
这段文字意在说明：','[{"label":"A","content":"我们悠久的历史是各民族共同书写的"},{"label":"B","content":"我们辽阔的疆域是各民族共同开拓的"},{"label":"C","content":"我们灿烂的文化是各民族共同创造的"},{"label":"D","content":"我们伟大的精神是各民族共同培育的"}]','A','文段分析见批注。
本题选项较为相似，只需比较谈论的是历史或疆域或文化或精神；文段(除最后一句话)可看作大并列结构，有“先秦、秦、南北朝、宋辽夏金、秦汉、隋唐、元明清”的清晰时间⑩轴，介绍了多民族共同铸就的历史；并且原文有“秦汉雄风、大唐气象、康乾盛世，都是各民族共同铸就的历史”的提示句；有上述可知，文段主要介绍的是“各民族共同书写历史”,对应A选项，当选①。

花生批注：
⑮ 行文结构：大并列结构。
文段存在清晰的时间轴：
①早在先秦时期就是交融格局；
②秦国开启了多民族国家发展历程；
③分立如南北朝，对峙如宋辽夏金，统一如秦汉隋唐元明清，都追求统一；
④秦汉雄风、大唐气象、康乾盛世，都是各民族共同铸就的历史。
⑯ 时间，由古至今，即是历史。
⑪ “疆域、文化、精神”均未提及。
反推选项：
①若谈论疆域，文段应分别介绍某个民族开拓了某个地方的领土；
②若谈论文化，文段应分别介绍某个民族创造了什么文化；
③若谈论精神，文段应分别介绍某个民族创造了什么精神。','2 0 2 1 年 国 家 公 务 员 考 试 5','挑战','published','{"globalNumber":187,"setNumber":10,"localNumber":7,"sourceLabel":"2 0 2 1 年 国 家 公 务 员 考 试 5 8 %","accuracy":8,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"早在先秦时期，我国就逐渐形成了以炎黄华夏为凝聚核心、“五方之民”共天下的交融格局。秦国“书同文，车同轨，量同衡，行同伦”,开启了中国统一的多民族国家发展的历程。此后，无论哪个民族入主中原，都以统一天下为己任，都以中华文化的正统自居。分立如南北朝，都自诩中华正统；对峙如宋辽夏金，都被称为“桃花石”;统一如秦汉、隋唐、元明清，更是“六合同风，九州共贯”。秦汉雄风、大唐气象、康乾盛世，都是各民族共同铸就的历史。今天，我们实现中国梦，就要紧紧依靠各族人民的力量。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"我们悠久的历史是各民族共同书写的"}],"B":[{"text":"我们辽阔的疆域是各民族共同开拓的"}],"C":[{"text":"我们灿烂的文化是各民族共同创造的"}],"D":[{"text":"我们伟大的精神是各民族共同培育的"}]},"annotatedStemRich":[{"text":"早在先秦时期，我国就逐渐形成了以炎黄华夏为凝聚核心、“五方之民”共天下的交融格局。秦国“书同文，车同轨，量同衡，行同伦”,开启了中国统 一 的多民族国家发展的历程。此后，无论哪个民族入主中原，都以统 一 天下为己任，都以中华文化的正统自居。分立如南北朝，都自诩中华正统；对峙如宋辽夏金，都被称为“桃花石”;统 一 如秦汉、隋唐、元明清，更是“六合同风，九州共贯”。秦汉雄风、大唐气象、康乾盛世，都是各民族共同铸就的历史。 ","underline":true},{"text":"⑮ 今天，我们实现中国梦，就要紧紧依靠各族人民的力量。\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"我们悠久的历史是各民族共同书写的"}],"B":[{"text":"我们辽阔的疆域是各民族共同开拓的 (无中生有)"}],"C":[{"text":"我们灿烂的文化是各民族共同创造的(无中生有)"}],"D":[{"text":"我们伟大的精神是各民族共同培育的 (无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n本题选项较为相似，只需比较谈论的是历史或疆域或文化或精神；文段(除最后一句话)可看作大并列结构，有“先秦、秦、南北朝、宋辽夏金、秦汉、隋唐、元明清”的清晰时间⑩轴，介绍了多民族共同铸就的历史；并且原文有“秦汉雄风、大唐气象、康乾盛世，都是各民族共同铸就的历史”的提示句；有上述可知，文段主要介绍的是“各民族共同书写历史”,对应A选项，当选①。","notes":[{"marker":"⑮","content":"行文结构：大并列结构。\n文段存在清晰的时间轴：\n①早在先秦时期就是交融格局；\n②秦国开启了多民族国家发展历程；\n③分立如南北朝，对峙如宋辽夏金，统一如秦汉隋唐元明清，都追求统一；\n④秦汉雄风、大唐气象、康乾盛世，都是各民族共同铸就的历史。","matchScore":0.9688,"pairingMode":"marker-and-content","order":12},{"marker":"⑯","content":"时间，由古至今，即是历史。","matchScore":0.3508,"pairingMode":"content-similarity","order":13},{"marker":"⑪","content":"“疆域、文化、精神”均未提及。\n反推选项：\n①若谈论疆域，文段应分别介绍某个民族开拓了某个地方的领土；\n②若谈论文化，文段应分别介绍某个民族创造了什么文化；\n③若谈论精神，文段应分别介绍某个民族创造了什么精神。","matchScore":0.2628,"pairingMode":"content-similarity","order":14}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300188,3,'细节判断类','古典经济学认为，劳动是一种被迫性的活动，是让人感到痛苦和不快乐的活动，亚当 ·斯密更是把劳动视为“诅咒”和“牺牲”。但马克思认为，人类之所以会对劳动产生厌恶感，是因为随着人类社会的发展，劳动发生了异化，人类真正逃避的是异化的劳动，而不是劳动本身。在马克思看来，劳动是人类区别于动物的类属性，正因为人类有意识的劳动行为才塑造了人类本身以及人类社会，异化劳动只是劳动的一个历史形态。
根据以上材料可知：','[{"label":"A","content":"厌恶并逃避劳动是人类的共性"},{"label":"B","content":"劳动是人类谋生的工具"},{"label":"C","content":"异化劳动将被社会发展所抛弃"},{"label":"D","content":"被迫性的劳动就是异化劳动"}]','C','文段简化翻译见批注。
A选项，根据②可知，人类厌恶并逃避的是异化的劳动，而非劳动，错误； B选项的“谋生的工具”无中生有，错误；
C选项，根据③可知，异化劳动只是劳动的一个历史形态，异化劳动终究会成为过去、被时代所抛弃，正确；
D选项，把古典经济学和马克思的观点杂糅到一起，错误。

花生批注：
⑱ 可简化翻译为：
①古典经济学(亚当斯密) 认为：劳动是被迫性活动，让人痛苦；
②马克思认为：人类厌恶的、逃避的是异化的劳动，而非劳动本身；
③马克思认为：劳动是人类的本能，人类有意识的劳动推动了发展，异化的劳动只是劳动的一个历史形态。','2021年福建省事业单位','进阶','published','{"globalNumber":188,"setNumber":10,"localNumber":8,"sourceLabel":"2021年福建省事业单位57%","accuracy":57,"typeAndPassage":"细节判断类","stemRich":[{"text":"古典经济学认为，劳动是一种被迫性的活动，是让人感到痛苦和不快乐的活动，亚当 ·斯密更是把劳动视为“诅咒”和“牺牲”。但马克思认为，人类之所以会对劳动产生厌恶感，是因为随着人类社会的发展，劳动发生了异化，人类真正逃避的是异化的劳动，而不是劳动本身。在马克思看来，劳动是人类区别于动物的类属性，正因为人类有意识的劳动行为才塑造了人类本身以及人类社会，异化劳动只是劳动的一个历史形态。\n根据以上材料可知："}],"optionRich":{"A":[{"text":"厌恶并逃避劳动是人类的共性"}],"B":[{"text":"劳动是人类谋生的工具"}],"C":[{"text":"异化劳动将被社会发展所抛弃"}],"D":[{"text":"被迫性的劳动就是异化劳动"}]},"annotatedStemRich":[{"text":"①古典经济学认为，劳动是一种被迫性的活动，是让人感到痛苦和不快乐的活动，亚当 ·斯密更是把劳动视为“诅咒”和“牺牲”。②但马克思认为，人类之所以会对劳动产生厌恶感，是因为随着人类社会的发展，劳动发生了异化，人类真正逃避的是异化的劳动，而不是劳动本身。③在马克思看来，劳动是人类区别于动物的类属性，正因为人类有意识的劳动行为才塑造了人类本身以及人类社会，异化劳动只是劳动的一个历史形态。⑤\n根据以上材料可知："}],"annotatedOptionRich":{"A":[{"text":"厌恶并逃避劳动是人类的共性(本身有误)"}],"B":[{"text":"劳动是人类谋生的工具(无中生有)"}],"C":[{"text":"异化劳动将被社会发展所抛弃"}],"D":[{"text":"被迫性的劳动就是异化劳动( 杂糅 )"}]},"practicalAnalysis":"文段简化翻译见批注。\nA选项，根据②可知，人类厌恶并逃避的是异化的劳动，而非劳动，错误； B选项的“谋生的工具”无中生有，错误；\nC选项，根据③可知，异化劳动只是劳动的一个历史形态，异化劳动终究会成为过去、被时代所抛弃，正确；\nD选项，把古典经济学和马克思的观点杂糅到一起，错误。","notes":[{"marker":"⑱","content":"可简化翻译为：\n①古典经济学(亚当斯密) 认为：劳动是被迫性活动，让人痛苦；\n②马克思认为：人类厌恶的、逃避的是异化的劳动，而非劳动本身；\n③马克思认为：劳动是人类的本能，人类有意识的劳动推动了发展，异化的劳动只是劳动的一个历史形态。","matchScore":0.9175,"pairingMode":"content-similarity","order":15}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300189,3,'中心理解题','思考是创新的第一步，是一座掘之不尽的能力宝库，没有思考能力就缺乏行动能力，就谈不到创新，谈不到创造性工作。只有努力养成善于思考的良好习惯，形成人人思考、自觉思考、终生思考的好风气，我们为人民服务的本领才能提高，为人民执政的能力才能增强，建设创新型国家才有深厚的群众基础和社会基础。
这段文字主要表达的是：','[{"label":"A","content":"创新离不开思考"},{"label":"B","content":"思考是为了创新"},{"label":"C","content":"没有创新就没有思考"},{"label":"D","content":"没有良好的思考习惯就没有创新"}]','A','文段两句话均为对策，直接翻译对策即可。
第一句对策可翻译为：创新需要思考；第二句对策可翻译为：想要提高为人民服务本领、增强为人民执政能力、夯实建设创新型国家基础需要养成善于思考的良好习惯、形成思考的好风气；
A选项是首句对策的同义替换；C选项可翻译为：思考需要创新，逻辑错误；B选项非对策选项，且“思考的目的是创新”为无中生有；D选项可翻译为：创新需要良好的思考习惯，杂糅了两个对策，均不如A选项；
综上，答案为 A选项。

花生批注：
⑲ 没有思考就谈不上创新，即谈创新就要思考，等价于创新离不开思考。
思考是创新的第一步，是一座掘之不尽的能力宝库，没有思考能力就缺乏行动能力，就谈不到创新，谈不到创造性工作。⑨只有努力养成善于思考的良好习惯，形成人人思考、自觉思考、终生思考的好风气，我们为人民服务的本领才能提高，为人民执政的能力才能增强，建设创新型国家才有深厚的群众基础和社会基础。
这段文字主要表达的是：
A. 创新离不开思考
B. 思考是为了创新(无中生有)
C. 没有创新就没有思考(本身有误)
D. 没有良好的思考习惯就没有创新(杂糅)','2019年广东省事业单位','进阶','published','{"globalNumber":189,"setNumber":10,"localNumber":9,"sourceLabel":"2019年广东省事业单位 65%","accuracy":65,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"思考是创新的第一步，是一座掘之不尽的能力宝库，没有思考能力就缺乏行动能力，就谈不到创新，谈不到创造性工作。只有努力养成善于思考的良好习惯，形成人人思考、自觉思考、终生思考的好风气，我们为人民服务的本领才能提高，为人民执政的能力才能增强，建设创新型国家才有深厚的群众基础和社会基础。\n这段文字主要表达的是："}],"optionRich":{"A":[{"text":"创新离不开思考"}],"B":[{"text":"思考是为了创新"}],"C":[{"text":"没有创新就没有思考"}],"D":[{"text":"没有良好的思考习惯就没有创新"}]},"annotatedStemRich":[{"text":"⑲花生批注：\n没有思考就谈不上创新，即谈创新就要思考，等价于创新离不开思考。\n"},{"text":"思考是创新的第一步，是一座掘之不尽的能力宝库，没有思考能力就缺乏行动能力，就谈不到创新，谈不到创造性工作。","underline":true},{"text":"⑨只有努力养成善于思考的良好习惯，形成人人思考、自觉思考、终生思考的好风气，我们为人民服务的本领才能提高，为人民执政的能力才能增强，建设创新型国家才有深厚的群众基础和社会基础。\n这段文字主要表达的是："}],"annotatedOptionRich":{"A":[{"text":"创新离不开思考"}],"B":[{"text":"思考是为了创新(无中生有)"}],"C":[{"text":"没有创新就没有思考(本身有误)"}],"D":[{"text":"没有良好的思考习惯就没有创新(杂糅)"}]},"practicalAnalysis":"文段两句话均为对策，直接翻译对策即可。\n第一句对策可翻译为：创新需要思考；第二句对策可翻译为：想要提高为人民服务本领、增强为人民执政能力、夯实建设创新型国家基础需要养成善于思考的良好习惯、形成思考的好风气；\nA选项是首句对策的同义替换；C选项可翻译为：思考需要创新，逻辑错误；B选项非对策选项，且“思考的目的是创新”为无中生有；D选项可翻译为：创新需要良好的思考习惯，杂糅了两个对策，均不如A选项；\n综上，答案为 A选项。","notes":[{"marker":"⑲","content":"没有思考就谈不上创新，即谈创新就要思考，等价于创新离不开思考。\n思考是创新的第一步，是一座掘之不尽的能力宝库，没有思考能力就缺乏行动能力，就谈不到创新，谈不到创造性工作。⑨只有努力养成善于思考的良好习惯，形成人人思考、自觉思考、终生思考的好风气，我们为人民服务的本领才能提高，为人民执政的能力才能增强，建设创新型国家才有深厚的群众基础和社会基础。\n这段文字主要表达的是：\nA. 创新离不开思考\nB. 思考是为了创新(无中生有)\nC. 没有创新就没有思考(本身有误)\nD. 没有良好的思考习惯就没有创新(杂糅)","matchScore":1.408,"pairingMode":"marker-and-content","order":16}],"pairingMode":"text-and-sequence"}');
