INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300191,3,'中心理解题','在整个宇宙中，氢是最常见的元素，现今太阳中大约75%是氢。据此可以推测，太阳系在形成的时候，主要成分也应该是氢元素。随着太阳的形成，太阳系绝大部分物质都集中到了太阳，而在太阳之外，元素发生了分层：靠近太阳的地方，温度很高，只留下了硅、铁、氧等相对较重的元素，这些元素聚集在一起，就形成了水星、金星、地球等岩质行星；在逐渐远离太阳的地方，温度降低，这些元素的比例也逐渐降低，行星的大气成分就以氢为主了，还有一些氦，如木星、土星等；而在太阳系边缘，星体中的重元素已经很少，大多以水冰、甲烷等为主。
这段文字主要介绍：','[{"label":"A","content":"温度对太阳系物质构成的影响"},{"label":"B","content":"氢元素对于太阳系形成的意义"},{"label":"C","content":"太阳系中不同元素的分布情况"},{"label":"D","content":"太阳系各行星的元素构成情况"}]','C','文段分析见批注。
太阳系由太阳和太阳外组成：文段先介绍太阳75%元素是氢；再介绍太阳系外：靠近太阳的地方只有重元素；在逐渐远离部分，这些重元素比例降低；
太阳系边缘，主要是水冰、甲烷。文段主要介绍太阳系中不同元素的分布情况， C选项正确：
A选项未提及元素，B选项的“氢元素的意义”无中生有，可简单排除；
D选项为易错选项，需注意文段谈论的是太阳系中各元素(硅铁氧氢氦等) 的分布，并非介绍“太阳系各行星都有什么元素”②,排除。

花生批注：
② “顿悟”是全文论述话题。
2 元素是全文论述话题。
3 行文结构：二层结构之“A 且B”。
太阳系由太阳和太阳外组成：
先介绍太阳75%元素是氢；再介绍太阳系外：靠近太阳的地方只有重元素；在逐渐远离部分，这些重元素比例降低；太阳系边缘，重元素已经很少，主要是水冰、甲烷。
④ 实战思维：
读完文段脑海中浮现出下图，可秒选C选项。
25 若选择D选项，原文应该介绍太阳有什么元素、水星有什么元素，金星有什么元素等等，太阳、水星、金星等星体为主体。
26 “翻译理论”为全文论述话题。
7 行文结构：二层结构之对比。先介绍以前的翻译理论以忠实为基本标准；
再介绍现在的翻译理论强调译者根据自己的理解对原文进行翻译创作。
这段文字主要介绍：
A. 温度对太阳系物质构成的影响(缺主题词)
B. 氢元素对于太阳系形成的意义(无中生有)
C. 太阳系中不同元素的分布情况
D. 太阳系各行星的元素构成情况(无中生有)
