INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300192,3,'中心理解题','翻译是文化交流的重要媒介，传统翻译理论认为原文与译文应该相互等同，因此，“忠实”是翻译的基本标准。20世纪70年代兴起的翻译研究理论，受到后现代主义哲学思潮的影响，反对本质主义，反对“译文的本质是原文”这一传统思想。这种翻译研究的新思潮，强调翻译过程中的“创造性叛逆”,即认为不忠实于原文是正常甚至必然的。在阅读原文的基础上，翻译者根据自己对原文的理解，进行独特的翻译创作，翻译者被认为是文本的另一个作者。
这段文字主要介绍：','[{"label":"A","content":"新兴翻译理论与后现代主义哲学的关系"},{"label":"B","content":"翻译者对翻译文本的创造性贡献"},{"label":"C","content":"新兴翻译理论与传统理论的区别"},{"label":"D","content":"翻译工作应该遵循的基本标准"}]','C','文段分析见批注。
本文先介绍以前的翻译理论再介绍现在的翻译理论，文段是区别比较联系类的文段，要匹配区别比较联系类的选项，直接定位到C选项；
A选项也是区别比较联系类选项，但后现代主义哲学并非主体之一，排除； B选项未体现以前的翻译理论，表述片面，排除；D选项首先是具体类选项，原文并未具体介绍翻译工作应遵循的标准，无中生有，排除；
综上，正确答案是C选项。','2021年新疆省考','基础','published','{"globalNumber":192,"setNumber":10,"localNumber":12,"sourceLabel":"2021年新疆省考 75%","accuracy":75,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"翻译是文化交流的重要媒介，传统翻译理论认为原文与译文应该相互等同，因此，“忠实”是翻译的基本标准。20世纪70年代兴起的翻译研究理论，受到后现代主义哲学思潮的影响，反对本质主义，反对“译文的本质是原文”这一传统思想。这种翻译研究的新思潮，强调翻译过程中的“创造性叛逆”,即认为不忠实于原文是正常甚至必然的。在阅读原文的基础上，翻译者根据自己对原文的理解，进行独特的翻译创作，翻译者被认为是文本的另一个作者。\n这段文字主要介绍："}],"optionRich":{"A":[{"text":"新兴翻译理论与后现代主义哲学的关系"}],"B":[{"text":"翻译者对翻译文本的创造性贡献"}],"C":[{"text":"新兴翻译理论与传统理论的区别"}],"D":[{"text":"翻译工作应该遵循的基本标准"}]},"annotatedStemRich":[{"text":"翻译是文化交流的重要媒介，传统"},{"text":"翻译理论","underline":true},{"text":"认为原文与译文应该相互等同，因此，“忠实”是翻译的基本标准(以前的翻译理论)。 20世纪70年代兴起的翻译研究理论，受到后现代主义哲学思潮的影响，反对本质主义，反对“译文的本质是原文”这一传统思想。这种翻译研究的新思潮，强调翻译过程中的“创造性叛逆”,即认为不忠实于原文是正常甚至必然的。在阅读原文的基础上，翻译者根据自己对原文的理解，进行独特的翻译创作，翻译者被认为是文本的另一个作者(现在的翻译理论)。②\n这段文字主要介绍："}],"annotatedOptionRich":{"A":[{"text":"新兴翻译理论与后现代主义哲学的关系(区别比较联系类)"}],"B":[{"text":"翻译者对翻译文本的创造性贡献( 片面 )"}],"C":[{"text":"新兴翻译理论与传统理论的区别(区别比较联系类)"}],"D":[{"text":"翻译工作应该遵循的基本标准(具体类且无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n本文先介绍以前的翻译理论再介绍现在的翻译理论，文段是区别比较联系类的文段，要匹配区别比较联系类的选项，直接定位到C选项；\nA选项也是区别比较联系类选项，但后现代主义哲学并非主体之一，排除； B选项未体现以前的翻译理论，表述片面，排除；D选项首先是具体类选项，原文并未具体介绍翻译工作应遵循的标准，无中生有，排除；\n综上，正确答案是C选项。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300193,3,'语句填入类','文学名篇精粹光润、千锤百炼、声情并茂、朗朗上口，具有久传远播的生命功能。一些属于上上品的短小篇章，比如李白的《静夜思》、王之涣的《登鹳雀楼》、孟浩然的《春晓》、李绅的《悯农》、杜牧的《清明》,几乎在某种意义上来说可用家喻户晓来形容。从屈原到鲁迅，二千余年间的不少名篇是蕴含着国魂的要素的，屈原的“路漫漫其修远兮，吾将上下而求索”一类的名句，长久激励着人们追求真理的意志。鲁迅的《阿 Q正传》揭示的阿Q 相也在暴露国民精神弱点上广为人知。由于文学名篇具有文化精神聚焦的特征和久传广播、深入人心的功能，不妨这样认为，
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"它们是可以审视、可以触摸、可以呼吸、可以体味的"},{"label":"B","content":"它们是国魂与国民的一种极佳的精神契合点"},{"label":"C","content":"它们对人的主体精神世界的滋润，是多层次的"},{"label":"D","content":"它们表明的精神文化价值是难以估量的"}]','B','文段分析见批注。
文段先指出文学名篇具有久传远播的生命功能，又介绍文学名篇蕴含国魂要素且揭露国民精神上的弱点；尾句进行总结：因为文学名篇能聚焦文化精神 (即蕴含国魂)且久传远播深入人心，所以可利用文学名篇向民众传播“国魂”;
B选项的“文学名篇是国魂和国民的精神契合点”,即通过文学名篇将国魂传递给国民，因果逻辑恰当，当选； 30

花生批注：
9 行文结构：分总结构。
开篇分述部分：
①文学名篇具有久传远播的功能；
②文学名篇蕴含国魂，激励人们；
③文学名篇也揭露国民精神上的弱点；
后文总结：文学名篇蕴含国魂并且广为人知，所以……。
填入文中画横线部分最恰当的一项是：
A. 它们是可以审视、可以触摸、可以呼吸、可以体味的(无中生有)
B. 它们是国魂与国民的一种极佳的精神契合点
C. 它们对人的主体精神世界的滋润，是多层次的(无中生有)
③0 文学名篇蕴含国魂，文学名篇由家喻户晓(被国民知晓),所以文学名篇可联结“国魂”与“国民”,即国民通过文学名篇了解其蕴含的“国魂”。
其他选项均未体现文学名篇的作用，且内容无中生有，均可排除。','2021年黑龙江省考','进阶','published','{"globalNumber":193,"setNumber":10,"localNumber":13,"sourceLabel":"2021年黑龙江省考49%","accuracy":49,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"文学名篇精粹光润、千锤百炼、声情并茂、朗朗上口，具有久传远播的生命功能。一些属于上上品的短小篇章，比如李白的《静夜思》、王之涣的《登鹳雀楼》、孟浩然的《春晓》、李绅的《悯农》、杜牧的《清明》,几乎在某种意义上来说可用家喻户晓来形容。从屈原到鲁迅，二千余年间的不少名篇是蕴含着国魂的要素的，屈原的“路漫漫其修远兮，吾将上下而求索”一类的名句，长久激励着人们追求真理的意志。鲁迅的《阿 Q正传》揭示的阿Q 相也在暴露国民精神弱点上广为人知。由于文学名篇具有文化精神聚焦的特征和久传广播、深入人心的功能，不妨这样认为，\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"它们是可以审视、可以触摸、可以呼吸、可以体味的"}],"B":[{"text":"它们是国魂与国民的一种极佳的精神契合点"}],"C":[{"text":"它们对人的主体精神世界的滋润，是多层次的"}],"D":[{"text":"它们表明的精神文化价值是难以估量的"}]},"annotatedStemRich":[{"text":"文学名篇","underline":true},{"text":"②精粹光润、千锤百炼、声情并茂、朗朗上口，具有久传远播的生命功能。一些属于上上品的短小篇章，比如李白的《静夜思》、王之涣的《登鹳雀楼》、孟浩然的《春晓》、李绅的《悯农》、杜牧的《清明》,几乎在某种意义上来说可用家喻户晓来形容。从屈原到鲁迅，二千余年间的不少名篇是蕴含着国魂的要素的，屈原的“路漫漫其修远兮，吾将上下而求索”一类的名句，长久激励着人们追求真理的意志。鲁迅的《阿Q正传》揭示的阿Q相也在暴露国民精神弱点上广为人知( 分 ) 。由于文学名篇具有文化精神聚焦的特征和久传广播、深入人心的功能，不妨这样认为，"},{"text":"                          ","underline":true},{"text":" ( 总 ) 。②\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"它们是可以审视、可以触摸、可以呼吸、可以体味的(无中生有)"}],"B":[{"text":"它们是国魂与国民的一种极佳的精神契合点"}],"C":[{"text":"它们对人的主体精神世界的滋润，是多层次的(无中生有)"}],"D":[{"text":"它们表明的精神文化价值是难以估量的(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段先指出文学名篇具有久传远播的生命功能，又介绍文学名篇蕴含国魂要素且揭露国民精神上的弱点；尾句进行总结：因为文学名篇能聚焦文化精神 (即蕴含国魂)且久传远播深入人心，所以可利用文学名篇向民众传播“国魂”;\nB选项的“文学名篇是国魂和国民的精神契合点”,即通过文学名篇将国魂传递给国民，因果逻辑恰当，当选； 30","notes":[{"marker":"9","content":"行文结构：分总结构。\n开篇分述部分：\n①文学名篇具有久传远播的功能；\n②文学名篇蕴含国魂，激励人们；\n③文学名篇也揭露国民精神上的弱点；\n后文总结：文学名篇蕴含国魂并且广为人知，所以……。\n填入文中画横线部分最恰当的一项是：\nA. 它们是可以审视、可以触摸、可以呼吸、可以体味的(无中生有)\nB. 它们是国魂与国民的一种极佳的精神契合点\nC. 它们对人的主体精神世界的滋润，是多层次的(无中生有)","matchScore":0.6005,"pairingMode":"content-similarity","order":26},{"marker":"③0","content":"文学名篇蕴含国魂，文学名篇由家喻户晓(被国民知晓),所以文学名篇可联结“国魂”与“国民”,即国民通过文学名篇了解其蕴含的“国魂”。\n其他选项均未体现文学名篇的作用，且内容无中生有，均可排除。","matchScore":0.362,"pairingMode":"content-similarity","order":27}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300194,3,'下文推断类','近来，多家情商教育机构针对不同年龄段推出相应套餐，“情商班”火爆家长圈。情商是控制和驾驭情绪的能力，对人的生活和工作有重要的作用。可是，在很多人的心里，情商的内涵已经被异化，最早的情商概念和如今流行的情商观念大相径庭。许多人对情商的理解，是圆滑世故、阿谀奉承的另一种说法。实际上，情商的核心既是对自身情绪的认识和控制能力，也包括与人交往、融入集体的能力。这两种能力的培养，需要在日常生活中实践。孩子能否培养出良好的情绪控制能力和社交能力，很大程度上取决于家长，任何情商培训都无法取代日常生活中的情商培养。
接下来最可能讲述的是：','[{"label":"A","content":"情商补习应当引起家长高度关注"},{"label":"B","content":"家长在家庭教育中的身体力行"},{"label":"C","content":"家长要理性地看待情商培训班"},{"label":"D","content":"需要培养和提高家长的情商"}]','B','文段分析见批注。
文段通过“情商班火爆”引出情商这一话题后，通过转折指出情商的本质是两种能力，文末提出对策：情商能力的培养需要家长在日常生活中实践，任何情商培训都无法替代。
前文给出宏观对策，后文应接具体对策，即“家长应当在日常生活中如何培养孩子的情商”,对应B选项，当选；
A选项的对策“家长要重视情商补习”、C选项的对策“家长要理性看待情商培训班”,依然是在谈论“情商培训”,与文末宏观对策“取决于家长，任何情商培训都无法取代生活中的情商培养”相矛盾③,排除；
D选项对策是“要提高家长情商”,无中生有，排除。

花生批注：
② A选项：想象到千年之前的生活，看见了万里之外的情景；
C选项：要透彻地认识学习知识这件事还必须亲自实践；
D选项：指书要熟读才能真正领会；
均与文段主题无关。
③ 行文结构：前对策结构。
开篇用“情商班火爆”引出情商这一话题；
接下来通过转折引出情商的本质是两种能力；
文末给出培养这两种能力的对策：
情商能力的培养需要家长在日常生活中实践，任何情商培训都无法替代。
③ 原文如下：
如果父母能在日常生活中管理好自己的情绪，并且在孩子有情绪时及时介入，告诉孩子正确处理方式，孩子自然会养成优良的情绪控制能力。反之，如果父母总是乱发脾气，自己都控制不了自己的情绪，孩子当然会被带偏。而在交际能力上，孩子与人交流的方式，很大程度上就是模仿父母与人交流的方式。
与其送孩子培训情商，不如父母先负起教育的责任，因为家庭教育在孩子成长过程中的重要地位是基础性的，更是不可替代的。搞好家庭教育，情商培训可有可无，而如果搞不好家庭教育，再昂贵的情商培训，也无助于孩子的成长和发展。
33 下文推断的常见结构：
①上文文末提出新内容→下文解释新内容
②上文提出问题→下文分析问题、解决问题
③上文给出宏观对策、原因等→下文具体展开
④时间对比：过去不行→现在有了新突破
⑤总分：上文是总+分→下文补充另一“分”
⑥转折
③④ 文段谈论的是“家长要在日常生活中做好孩子的情商培训，而不是情商培训班一报了之”,A选项、C选项与作者观点恰好相反。','2020年云南省考','挑战','published','{"globalNumber":194,"setNumber":10,"localNumber":14,"sourceLabel":"2020年云南省考35%","accuracy":35,"typeAndPassage":"下文推断类 +宏观对策 → 具体对策","stemRich":[{"text":"近来，多家情商教育机构针对不同年龄段推出相应套餐，“情商班”火爆家长圈。情商是控制和驾驭情绪的能力，对人的生活和工作有重要的作用。可是，在很多人的心里，情商的内涵已经被异化，最早的情商概念和如今流行的情商观念大相径庭。许多人对情商的理解，是圆滑世故、阿谀奉承的另一种说法。实际上，情商的核心既是对自身情绪的认识和控制能力，也包括与人交往、融入集体的能力。这两种能力的培养，需要在日常生活中实践。孩子能否培养出良好的情绪控制能力和社交能力，很大程度上取决于家长，任何情商培训都无法取代日常生活中的情商培养。\n接下来最可能讲述的是："}],"optionRich":{"A":[{"text":"情商补习应当引起家长高度关注"}],"B":[{"text":"家长在家庭教育中的身体力行"}],"C":[{"text":"家长要理性地看待情商培训班"}],"D":[{"text":"需要培养和提高家长的情商"}]},"annotatedStemRich":[{"text":"近来，多家情商教育机构针对不同年龄段推出相应套餐，“情商班”火爆家长圈(引出话题)。情商是控制和驾驭情绪的能力，对人的生活和工作有重要的作用。可是，在很多人的心里，情商的内涵已经被异化，最早的情商概念和如今流行的情商观念大相径庭。许多人对情商的理解，是圆滑世故、阿谀奉承的另一种说法。实际上，情商的核心既是对自身情绪的认识和控制能力，也包括与人交往、融入集体的能力(转折引出情商的本质)。这两种能力的培养，需要在日常生活中实践。孩子能否培养出良好的情绪控制能力和社交能力，很大程度上取决于家长，任何情商培训都无法取代日常生活中的情商培养(宏观对策)。③\n接下来最可能讲述的是："}],"annotatedOptionRich":{"A":[{"text":"情商补习应当引起家长高度关注"}],"B":[{"text":"家长在家庭教育中的身体力行②"}],"C":[{"text":"家长要理性地看待情商培训班"}],"D":[{"text":"需要培养和提高家长的情商"}]},"practicalAnalysis":"文段分析见批注。\n文段通过“情商班火爆”引出情商这一话题后，通过转折指出情商的本质是两种能力，文末提出对策：情商能力的培养需要家长在日常生活中实践，任何情商培训都无法替代。\n前文给出宏观对策，后文应接具体对策，即“家长应当在日常生活中如何培养孩子的情商”,对应B选项，当选；\nA选项的对策“家长要重视情商补习”、C选项的对策“家长要理性看待情商培训班”,依然是在谈论“情商培训”,与文末宏观对策“取决于家长，任何情商培训都无法取代生活中的情商培养”相矛盾③,排除；\nD选项对策是“要提高家长情商”,无中生有，排除。","notes":[{"marker":"②","content":"A选项：想象到千年之前的生活，看见了万里之外的情景；\nC选项：要透彻地认识学习知识这件事还必须亲自实践；\nD选项：指书要熟读才能真正领会；\n均与文段主题无关。","matchScore":0.2121,"pairingMode":"marker-and-content","order":18},{"marker":"③","content":"行文结构：前对策结构。\n开篇用“情商班火爆”引出情商这一话题；\n接下来通过转折引出情商的本质是两种能力；\n文末给出培养这两种能力的对策：\n情商能力的培养需要家长在日常生活中实践，任何情商培训都无法替代。","matchScore":0.9567,"pairingMode":"marker-and-content","order":28},{"marker":"③","content":"原文如下：\n如果父母能在日常生活中管理好自己的情绪，并且在孩子有情绪时及时介入，告诉孩子正确处理方式，孩子自然会养成优良的情绪控制能力。反之，如果父母总是乱发脾气，自己都控制不了自己的情绪，孩子当然会被带偏。而在交际能力上，孩子与人交流的方式，很大程度上就是模仿父母与人交流的方式。\n与其送孩子培训情商，不如父母先负起教育的责任，因为家庭教育在孩子成长过程中的重要地位是基础性的，更是不可替代的。搞好家庭教育，情商培训可有可无，而如果搞不好家庭教育，再昂贵的情商培训，也无助于孩子的成长和发展。","matchScore":0.2404,"pairingMode":"marker-and-content","order":29},{"marker":"33","content":"下文推断的常见结构：\n①上文文末提出新内容→下文解释新内容\n②上文提出问题→下文分析问题、解决问题\n③上文给出宏观对策、原因等→下文具体展开\n④时间对比：过去不行→现在有了新突破\n⑤总分：上文是总+分→下文补充另一“分”\n⑥转折","matchScore":0.26,"pairingMode":"content-similarity","order":30},{"marker":"③④","content":"文段谈论的是“家长要在日常生活中做好孩子的情商培训，而不是情商培训班一报了之”,A选项、C选项与作者观点恰好相反。","matchScore":0.5209,"pairingMode":"content-similarity","order":31}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300195,3,'中心理解题','新中国成立初期的30年间，中国在国际期刊上发表的论文主要研究方向大部分为基础性自然科学学科。1980年以来，众多学科快速发展，取得了举世瞩目的成就：材料科学论文产出总量位居全球第一；农业科学、化学、计算机科学、工程学、环境与生态学、地球科学、数学、物理学的论文产出位居全球第二；分子生物学与遗传学、药理学与毒理学的论文产出位居全球第三。数据同时表明，中国内地学科布局与发展逐步均衡、全面，各个学科的影响力持续增长，逐步接近全球领先水平。
这段文字意在说明：','[{"label":"A","content":"中国基础科学的进步是综合国力提升的直观体现"},{"label":"B","content":"整体而言中国各学科的发展已居于全球领先水平"},{"label":"C","content":"论文产出数据表明中国在基础科研方面进步明显"},{"label":"D","content":"我国不同时期自然科学领域的学科布局差异显著"}]','C','文段分析见批注。
文段将“新中国成立初期的前30年”和“自1980年以来”的论文产出情况进行对比，看到我国内地学科布局与发展更加均衡全面，进步明显，对应C选项，当选；
其他选项均未提及“论文”,并且还有其他问题： A选项的“体现综合国力提升”无中生有；B选项本身有误，“逐步接近全球领先水平”不等于“已居于全球领先水平”;D选项为区别比较联系类，文段并未重点体现不同时期我国学科布局的差异，因此，均可排除。

花生批注：
36 行文结构：二层结构之对比。先介绍新中国成立初期的30 年间，中国国际期刊发表的论文主要研究方向为基础自然科学学科；
再介绍1980年以来众多学科论文发表取得的成绩和这些数据表明现在我国的进步。
③ “进步明显”提示文段可能为过去和现在的对比，而且是由论文产出数据的不同表明了进步。','2021年事业单位联考','进阶','published','{"globalNumber":195,"setNumber":10,"localNumber":15,"sourceLabel":"2021年事业单位联考68%","accuracy":68,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"新中国成立初期的30年间，中国在国际期刊上发表的论文主要研究方向大部分为基础性自然科学学科。1980年以来，众多学科快速发展，取得了举世瞩目的成就：材料科学论文产出总量位居全球第一；农业科学、化学、计算机科学、工程学、环境与生态学、地球科学、数学、物理学的论文产出位居全球第二；分子生物学与遗传学、药理学与毒理学的论文产出位居全球第三。数据同时表明，中国内地学科布局与发展逐步均衡、全面，各个学科的影响力持续增长，逐步接近全球领先水平。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"中国基础科学的进步是综合国力提升的直观体现"}],"B":[{"text":"整体而言中国各学科的发展已居于全球领先水平"}],"C":[{"text":"论文产出数据表明中国在基础科研方面进步明显"}],"D":[{"text":"我国不同时期自然科学领域的学科布局差异显著"}]},"annotatedStemRich":[{"text":"新中国成立初期的30年间，中国在国际期刊上发表的"},{"text":"论文","underline":true},{"text":"主要研究方向大部分为基础性自然科学学科(前30年我国论文方向)。 1980年以来，众多学科快速发展，取得了举世瞩目的成就：材料科学论文产出总量位居全球第一；农业科学、化学、计算机科学、工程学、环境与生态学、地球科学、数学、物理学的论文产出位居全球第二；分子生物学与遗传学、药理学与毒理学的论文产出位居全球第三。数据同时表明，中国内地学科布局与发展逐步均衡、全面，各个学科的影响力持续增长，逐步接近全球领先水平(1980年以来论文产出数\n据及中国内地学科发展与进步)。6 这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"中国基础科学的进步是综合国力提升的直观体现(缺主体词且无中生有)"}],"B":[{"text":"整体而言中国各学科的发展已居于全球领先水平(缺主体词且本身有误)"}],"C":[{"text":"论文产出数据表明中国在基础科研方面进步明显"}],"D":[{"text":"我国不同时期自然科学领域的学科布局差异显著 (缺主体词且区别比较联系类)"}]},"practicalAnalysis":"文段分析见批注。\n文段将“新中国成立初期的前30年”和“自1980年以来”的论文产出情况进行对比，看到我国内地学科布局与发展更加均衡全面，进步明显，对应C选项，当选；\n其他选项均未提及“论文”,并且还有其他问题： A选项的“体现综合国力提升”无中生有；B选项本身有误，“逐步接近全球领先水平”不等于“已居于全球领先水平”;D选项为区别比较联系类，文段并未重点体现不同时期我国学科布局的差异，因此，均可排除。","notes":[{"marker":"36","content":"行文结构：二层结构之对比。先介绍新中国成立初期的30 年间，中国国际期刊发表的论文主要研究方向为基础自然科学学科；\n再介绍1980年以来众多学科论文发表取得的成绩和这些数据表明现在我国的进步。","matchScore":0.7651,"pairingMode":"content-similarity","order":33},{"marker":"③","content":"“进步明显”提示文段可能为过去和现在的对比，而且是由论文产出数据的不同表明了进步。","matchScore":0.3848,"pairingMode":"content-similarity","order":34}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300196,3,'中心理解题','伽马射线是人们认识原子核的“探针”。不同于传统的离线伽马谱学测量，在束伽马谱学测量是在大科学装置的加速器上，利用多探头多角度的伽马探测器组成的高分辨伽马探测阵列开展在束伽马谱学测量，并进行相关核科学的前沿课题研究，是目前世界上各大核物理实验室均采用的重要研究手段。我国在在束伽马谱学研究平台整合与升级方面已迈出关键一步。通过多方合作，共建的新探测阵列探测器单元数量由15个提高到50个，将进一步提升整个实验终端探测能力，预计将会在核结构研究领域取得更丰富更高水平的研究成果，同时该探测阵列也将应用于核反应、核天体、核技术应用等领域。
这段文字主要讲的是：','[{"label":"A","content":"在束伽马谱学测量的应用领域非常广泛"},{"label":"B","content":"我国开始布局建设新一代伽马探测阵列"},{"label":"C","content":"在束伽马谱学测量对于核物理研究意义重大"},{"label":"D","content":"伽马射线在用于原子核研究方面又有新进展"}]','B','文段分析见批注。
文段介绍背景知识是为了引出我国在这一领域的成就，重点为“我国成就”, 即“我国在束伽马谱学研究平台整合与升级方面已迈出关键一步”,对应B选项，当选；
其他选项均未体现我国的成就，可简单排除。

花生批注：
⑤ 我国是全文论述主体，论文是全文论述话题。
38 在束伽马谱学是全文论述话题。
39 行文结构：二层结构之“背景知识+我国”。
前半部分背景知识：介绍在束伽马谱学测量的重要价值；
后半部分介绍我国成就：在束伽马谱学研究平台整合与升级方面已迈出关键一步。
这段文字主要讲的是：
A. 在束伽马谱学测量的应用领域非常广泛(无主体)
B. 我国开始布局建设新一代伽马探测阵列
