INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300197,3,'标题填入类','如今，写论文、投稿、出书，常有一个字数的下限要求。这固然有一定合理性，但另一方面，也是一种奇怪心理在作祟：仿佛字数多了才显得有学问，篇幅长了才能体现思考的深度，长篇大论才会把问题分析透彻。很多时候，文章字数的多少，并不能代表理论修养和学识储备。洋洋洒洒的长篇大论，如果缺乏独创性的理论贡献，只能算是文字的堆砌和知识的罗列。而许多有影响力的著作，就很短小精悍、简明扼要。《共产党宣言》仅仅一万多字，比现在一篇硕士生的论文字数都少，但这一万多字，却成为世界无产阶级的锐利思想武器。
最适合做这段文字标题的是：','[{"label":"A","content":"莫以字数论长短"},{"label":"B","content":"浓缩的往往是精华"},{"label":"C","content":"文章贵在少而精、简而深"},{"label":"D","content":"归纳和总结，写作的两大利器"}]','A','文段分析见批注。
文段提出问题后给出了“文章字数多少不能代表水平”的观点，后文加以论证；
B选项、D选项，均未提及“文章字数”,可简单排除；
C选项的观点“文章贵在少、简”,与文段不符，文段的观点是“不要用文章字数多少来衡量水平”,不代表“一定是‘少’的好”,排除；

花生批注：
④ 文章字数是全文论述话题。
④ 行文结构：前观点结构。
先转折提出问题：有人认为文章字数多、篇幅长才好；接着提出作者观点：文章字数的多少，并不能代表理论修养和学识储备；
最后对观点进行分析论证。
如今，写论文、投稿、出书，常有一个字数的下限要求。这固然有一定合理性，但另一方面，也是一种奇怪心理在作祟：仿佛字数多了才显得有学问，篇幅长了才能体现思考的深度，长篇大论才会把问题分析透彻(转折提出问题)。很多时候，文章字数的多少，并不能代表理论修养和学识储备(提出观点)。洋洋洒洒的长篇大论，如果缺乏独创性的理论贡献，只能算是文字的堆砌和知识的罗列。而许多有影响力的著作，就很短小精悍、简明扼要。《共产党宣言》仅仅一万多字，比现在一篇硕士生的论文字数都少，但这一万多字，却成为世
界无产阶级的锐利思想武器(分析论证)。④ 最适合做这段文字标题的是：
A. 莫以字数论长短
B. 浓缩的往往是精华(缺主题词且本身有误)
C. 文章贵在少而精、简而深(本身有误)','2019年四川选调','进阶','published','{"globalNumber":197,"setNumber":10,"localNumber":17,"sourceLabel":"2019年四川选调 67%","accuracy":67,"typeAndPassage":"标题填入类+说理类文章","stemRich":[{"text":"如今，写论文、投稿、出书，常有一个字数的下限要求。这固然有一定合理性，但另一方面，也是一种奇怪心理在作祟：仿佛字数多了才显得有学问，篇幅长了才能体现思考的深度，长篇大论才会把问题分析透彻。很多时候，文章字数的多少，并不能代表理论修养和学识储备。洋洋洒洒的长篇大论，如果缺乏独创性的理论贡献，只能算是文字的堆砌和知识的罗列。而许多有影响力的著作，就很短小精悍、简明扼要。《共产党宣言》仅仅一万多字，比现在一篇硕士生的论文字数都少，但这一万多字，却成为世界无产阶级的锐利思想武器。\n最适合做这段文字标题的是："}],"optionRich":{"A":[{"text":"莫以字数论长短"}],"B":[{"text":"浓缩的往往是精华"}],"C":[{"text":"文章贵在少而精、简而深"}],"D":[{"text":"归纳和总结，写作的两大利器"}]},"annotatedStemRich":[{"text":"④花生批注：\n文章字数是全文论述话题。\n④花生批注：\n行文结构：前观点结构。\n先转折提出问题：有人认为文章字数多、篇幅长才好；接着提出作者观点：文章字数的多少，并不能代表理论修养和学识储备；\n最后对观点进行分析论证。\n如今，写论文、投稿、出书，常有一个"},{"text":"字数","underline":true},{"text":"的下限要求。这固然有一定合理性，但另一方面，也是一种奇怪心理在作祟：仿佛字数多了才显得有学问，篇幅长了才能体现思考的深度，长篇大论才会把问题分析透彻(转折提出问题)。很多时候，文章字数的多少，并不能代表理论修养和学识储备(提出观点)。洋洋洒洒的长篇大论，如果缺乏独创性的理论贡献，只能算是文字的堆砌和知识的罗列。而许多有影响力的著作，就很短小精悍、简明扼要。《共产党宣言》仅仅一万多字，比现在一篇硕士生的论文字数都少，但这一万多字，却成为世\n界无产阶级的锐利思想武器(分析论证)。④ 最适合做这段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"莫以字数论长短"}],"B":[{"text":"浓缩的往往是精华(缺主题词且本身有误)"}],"C":[{"text":"文章贵在少而精、简而深(本身有误)"}],"D":[{"text":"归纳和总结，写作的两大利器(缺主题词且无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段提出问题后给出了“文章字数多少不能代表水平”的观点，后文加以论证；\nB选项、D选项，均未提及“文章字数”,可简单排除；\nC选项的观点“文章贵在少、简”,与文段不符，文段的观点是“不要用文章字数多少来衡量水平”,不代表“一定是‘少’的好”,排除；","notes":[{"marker":"④","content":"文章字数是全文论述话题。","matchScore":1.0325,"pairingMode":"marker-and-content","order":37},{"marker":"④","content":"行文结构：前观点结构。\n先转折提出问题：有人认为文章字数多、篇幅长才好；接着提出作者观点：文章字数的多少，并不能代表理论修养和学识储备；\n最后对观点进行分析论证。\n如今，写论文、投稿、出书，常有一个字数的下限要求。这固然有一定合理性，但另一方面，也是一种奇怪心理在作祟：仿佛字数多了才显得有学问，篇幅长了才能体现思考的深度，长篇大论才会把问题分析透彻(转折提出问题)。很多时候，文章字数的多少，并不能代表理论修养和学识储备(提出观点)。洋洋洒洒的长篇大论，如果缺乏独创性的理论贡献，只能算是文字的堆砌和知识的罗列。而许多有影响力的著作，就很短小精悍、简明扼要。《共产党宣言》仅仅一万多字，比现在一篇硕士生的论文字数都少，但这一万多字，却成为世\n界无产阶级的锐利思想武器(分析论证)。④ 最适合做这段文字标题的是：\nA. 莫以字数论长短\nB. 浓缩的往往是精华(缺主题词且本身有误)\nC. 文章贵在少而精、简而深(本身有误)","matchScore":1.5298,"pairingMode":"marker-and-content","order":38}],"p