INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300198,3,'标题拟定类','更清洁的空气、更干净的水、更安全的食物、更公平可及的体育设施、更普惠的医疗服务……人们在这些方面的更高诉求，莫不与健康有关。“要倡导健康的生活方式，树立大卫生、大健康的观念，把以治病为中心转变为以人民健康为中心”,习近平总书记的这一要求，既顺应了人民群众的美好生活需要，更为我国卫生与健康事业发展指明了前进方向。所谓大健康，应该是对生命实施全程、全面、全要素的呵护，不仅追求身体健康，也追求心理健康、精神健康；不仅要求疾病治愈，更追求远离“亚健康”的强健体魄，锻造抵御疾病的强大身体素质。
如果给这段话加一个标题，最合适的是：','[{"label":"A","content":"美好生活需要“大健康”"},{"label":"B","content":"“大健康”内涵丰富"},{"label":"C","content":"心理健康与身体健康同等重要"},{"label":"D","content":"公众期盼远离“亚健康”"}]','A','文段分析见批注。
