INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300199,3,'语句排序类','①学界一般认为美学是以美、美的本质为主要研究对象的学问
②尤其应该辩证综合地研究主客体之间即人与世界之间的审美关系，并以此作为美学研究的主要对象
③但对于美学研究对象问题，历来存在多种不同看法，迄今并无定论
④其实，我们关于美学研究对象的认识可以更加宽泛一些
⑤同所有学科一样，美学的研究对象在某种程度上决定着它的学科性质
⑥不仅要研究作为审美客体的美，同时要研究审美主体的美感
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"①⑤③④②⑥"},{"label":"B","content":"①③④②⑤⑥"},{"label":"C","content":"⑤①④②③⑥"},{"label":"D","content":"⑤③①④⑥②⑥"}]','D','观察选项发现，首句可能为①⑤, ⑤为对比其他学科引出美学⑧,①为介绍美学的研究对象，⑤在①前更符合逻辑，排除A选项、B选项；
观察 C选项、D选项，第二句可能为①③,③介绍关于美学研究对象问题历来有多种不同看法，①介绍关于美学研究对象问题学界的一般看法；先介绍有很多不同看法，再介绍“一般认为”较符合逻辑，定位D选项；
验证D选项，④⑥②均为对策表述，⑤③①可看作引出话题，逻辑清晰，当选。

花生批注：
④ 考场秒杀：
④是宽泛对策：建议我们关于美学研究对象的认识应更宽泛；
⑥②为具体对策(如何更宽泛):不仅要研究审美客体的美，也要研究审美主体的美，尤其应辩证地研究主客体之间的审美关系，以此作为研究对象。
根据逻辑词“不仅，同时，尤其”可知，⑥在②前，只能选择D选项。
片段阅读
④⑥ 行文结构：后对策结构。
⑤对比其他学科，引出美学； ③转折引出美学研究对象问题尚无定论；
①接着介绍关于美学研究对象学界普遍的看法；
④⑥②给出作者关于美学研究对象的建议。
④⑦ 可看作对比引出话题。
④⑧ ①提出“NLR”这一定义， ④②中均包含NLR, 则① 一定在④②之前。
9 ④引出MODIS的地表温度 IST,② 介绍MODIS的夜间地表温度LST与站点观测的气温有很好的一致性，二者可考虑捆绑。
