INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300202,3,'语句填入类','科学管理是认识管理对象的动态过程。管理活动特别是现代管理活动，可以根据具体需要，已有知识的指导、前人的管理经验和科学的管理预判有序安排。然而，与按既定规程运作的物质生产过程不同， ,因而难以完全按预定的目的和计划进行，有其不确定性和强烈的探索性。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"管理活动面对的经常是极为复杂的管理对象"},{"label":"B","content":"管理活动则是以精神生产为直接目的的活动"},{"label":"C","content":"管理活动的具体形式比预想的更加多种多样"},{"label":"D","content":"管理活动往往需要各级管理者不断推陈出新"}]','A','文段开篇介绍管理活动，末尾转折引出问题，所填入语句应满足三点要求：①应体现与“按既定规程运作”的不同，②与“难以按照预定的目的和计划进行”构成因果关系，③与上文呼应；
观察选项，只有A选项符合：①管理活动面向的是复杂③的管理对象，与按既定规程运作的物质生产过程不同，②因为面向的是复杂的管理对象，所以难以按预定的目的和计划进行，③与首句“科学管理是认识管理对象的动态过程”呼应④,完美选项，当选。

花生批注：
③ 复杂可理解为多样、多变，物质生产面向对象单一、固定。
④ 较难的语句填入题要注意首句的提示信息。','2019年湖北选调','进阶','published','{"globalNumber":202,"setNumber":11,"localNumber":2,"sourceLabel":"2019年湖北选调52%","accuracy":52,"typeAndPassage":"语句填入类+科普介绍文章","stemRich":[{"text":"科学管理是认识管理对象的动态过程。管理活动特别是现代管理活动，可以根据具体需要，已有知识的指导、前人的管理经验和科学的管理预判有序安排。然而，与按既定规程运作的物质生产过程不同，"},{"text":"                        ","underline":true},{"text":" ,因而难以完全按预定的目的和计划进行，有其不确定性和强烈的探索性。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"管理活动面对的经常是极为复杂的管理对象"}],"B":[{"text":"管理活动则是以精神生产为直接目的的活动"}],"C":[{"text":"管理活动的具体形式比预想的更加多种多样"}],"D":[{"text":"管理活动往往需要各级管理者不断推陈出新"}]},"annotatedStemRich":[{"text":"科学管理是认识管理对象的动态过程(引出话题)。管理活动特别是现代管理活动，可以根据具体需要，已有知识的指导、前人的管理经验和科学的管理预判有序安排。然而，与按既定规程运作的物质生产过程不同，\n"},{"text":" ","underline":true},{"text":"_,因而难以完全按预定的目的和计划进行，有其不确定性和强烈的探索性(转折引出问题)。\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"管理活动面对的经常是极为复杂的管理对象"}],"B":[{"text":"管理活动则是以精神生产为直接目的的活动"}],"C":[{"text":"管理活动的具体形式比预想的更加多种多样"}],"D":[{"text":"管理活动往往需要各级管理者不断推陈出新"}]},"practicalAnalysis":"文段开篇介绍管理活动，末尾转折引出问题，所填入语句应满足三点要求：①应体现与“按既定规程运作”的不同，②与“难以按照预定的目的和计划进行”构成因果关系，③与上文呼应；\n观察选项，只有A选项符合：①管理活动面向的是复杂③的管理对象，与按既定规程运作的物质生产过程不同，②因为面向的是复杂的管理对象，所以难以按预定的目的和计划进行，③与首句“科学管理是认识管理对象的动态过程”呼应④,完美选项，当选。","notes":[{"marker":"③","content":"复杂可理解为多样、多变，物质生产面向对象单一、固定。","matchScore":0.3328,"pairingMode":"marker-and-content","order":2},{"marker":"④","content":"较难的语句填入题要注意首句的提示信息。","matchScore":0.2612,"pairingMode":"marker-and-content","order":3}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300203,3,'中心理解题','“万物并育而不相害，道并行而不相悖。”从“和而不同”“协和万邦”的交往理念到“和为贵”“和气生财”的和谐目标；从“一带一路”的倡议，到构建“人类命运共同体”的倡导，中国一直都在推动着新型世界交往方式的形成、促成着平等交流的文明共识。人类历史告诉我们，任何企图建立单一文明的一统天下，都只是一种不切实际的幻想。只有让不同文明在和而不同中生生不息，实现“各美其美，美人之美，美美与共，天下大同”,才能更好推动本国本民族的文明发展，共同书写人类文明发展的华丽篇章。
这段文字意在强调：','[{"label":"A","content":"不同文明间是可以和而不同的"},{"label":"B","content":"各国应共同构建人类命运共同体"},{"label":"C","content":"中国传统和合思想在当代的发展"},{"label":"D","content":"不同文明都有其自身存在的意义与价值"}]','A','文段分析见批注。
文段对策可翻译为：要更好推动本民族发展、人类文明发展需要让不同文明在和而不同中生生不息。对策的核心是“不同文明在和而不同中发展”,对应A选项⑥,当选；
B选项的“人类命运共同体”出自引出话题部分，且并非对策重点；C选项、 D选项均未体现对策，可简单排除。

花生批注：
⑤ 行文结构：后对策结构。
文段引出“世界各国交往”这一话题后，做了简单分析“单一文明一统天下是幻想”;
文末用逻辑关联词表对策：想要本民族更好发展、人类文明更好发展需要让不同文明在和而不同中生生不息。
⑥ “可以”是一种“建议型”的对策表述；A选项可翻译为：不同文明可以在和而不同中发展；
例如：想减肥是可以运动的，即减肥可以通过运动达成。
②㉑ “有助于”类选项可看作对策，是一种常见的对策表述。例如：增进了解有助于改善中美关系大气候，可理解为“中美关系大气候的改善需要增进了解”。
A选项出自分析论证部分，出处有误且未提及创新；C选项、D选项均为问题表述，原文有对策要选对策，可简单排除。','2020年天津市事业单位','进阶','published','{"globalNumber":203,"setNumber":11,"localNumber":3,"sourceLabel":"2020年天津市事业单位49%","accuracy":49,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"“万物并育而不相害，道并行而不相悖。”从“和而不同”“协和万邦”的交往理念到“和为贵”“和气生财”的和谐目标；从“一带一路”的倡议，到构建“人类命运共同体”的倡导，中国一直都在推动着新型世界交往方式的形成、促成着平等交流的文明共识。人类历史告诉我们，任何企图建立单一文明的一统天下，都只是一种不切实际的幻想。只有让不同文明在和而不同中生生不息，实现“各美其美，美人之美，美美与共，天下大同”,才能更好推动本国本民族的文明发展，共同书写人类文明发展的华丽篇章。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"不同文明间是可以和而不同的"}],"B":[{"text":"各国应共同构建人类命运共同体"}],"C":[{"text":"中国传统和合思想在当代的发展"}],"D":[{"text":"不同文明都有其自身存在的意义与价值"}]},"annotatedStemRich":[{"text":"“万物并育而不相害，道并行而不相悖。”从“和而不同”“协和万邦”的交往理念到“和为贵”“和气生财”的和谐目标；从“一带一路”的倡议，到构建“人类命运共同体”的倡导，中国一直都在推动着新型世界交往方式的形成、促成着平等交流的文明共识(引出话题)。人类历史告诉我们，任何企图建立单一文明的一统天下，都只是一种不切实际的幻想(分析论证)。只有让不同文明在和而不同中生生不息，实现“各美其美，美人之美，美美与共，天下大同”,才能更好推动本国本民族的文明发展，共同书写人类文明发展的\n华丽篇章(逻辑关联词表对策)。⑤ 这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"不同文明间是可以和而不同的"}],"B":[{"text":"各国应共同构建人类命运共同体(出处有误且对策有误)"}],"C":[{"text":"中国传统和合思想在当代的发展(非对策选项)"}],"D":[{"text":"不同文明都有其自身存在的意义与价值(非对策选项)"}]},"practicalAnalysis":"文段分析见批注。\n文段对策可翻译为：要更好推动本民族发展、人类文明发展需要让不同文明在和而不同中生生不息。对策的核心是“不同文明在和而不同中发展”,对应A选项⑥,当选；\nB选项的“人类命运共同体”出自引出话题部分，且并非对策重点；C选项、 D选项均未体现对策，可简单排除。","notes":[{"marker":"⑤","content":"行文结构：后对策结构。\n文段引出“世界各国交往”这一话题后，做了简单分析“单一文明一统天下是幻想”;\n文末用逻辑关联词表对策：想要本民族更好发展、人类文明更好发展需要让不同文明在和而不同中生生不息。","matchScore":0.7314,"pairingMode":"marker-and-content","order":4},{"marker":"⑥","content":"“可以”是一种“建议型”的对策表述；A选项可翻译为：不同文明可以在和而不同中发展；\n例如：想减肥是可以运动的，即减肥可以通过运动达成。","matchScore":0.4294,"pairingMode":"marker-and-content","order":5},{"marker":"②㉑","content":"“有助于”类选项可看作对策，是一种常见的对策表述。例如：增进了解有助于改善中美关系大气候，可理解为“中美关系大气候的改善需要增进了解”。\nA选项出自分析论证部分，出处有误且未提及创新；C选项、D选项均为问题表述，原文有对策要选对策，可简单排除。","matchScore":0.3235,"pairingMode":"content-similarity","order":20}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300204,3,'中心理解题','科学界一向认为，行星本身是没有能源的，虽然在夜间我们能看到行星，但行星发光只不过是反射了太阳光的结果。然而，最近报道，木星放射出来的能量明显多于它从太阳吸收的能量。因此让人产生疑问：木星有热核能源吗?这种能源是在大气层里还是在它的内部?经过进一步的研究，人们已经探明木星大气层的成分，并得出在那里不可能产生热核能量的结论。
这段话主要表明了这样一个观点，即：','[{"label":"A","content":"木星发光是反射太阳光的结果"},{"label":"B","content":"木星内部有可能产生热核能源"},{"label":"C","content":"木星不可能产生热核能源"},{"label":"D","content":"木星靠外部能源散发热量"}]','B','文段分析见批注。
文段先提出新发现：木星放射出来的能量多于它吸收的能量，即木星产生了热核能量(否则木星不会放射多于吸收的能量);再介绍相关研究：木星大气层不可能产生能量，即木星内部产生了热核能量(不是大气层，就是内部)。
综上，对应B选项，当选。

花生批注：
⑦ 行文结构：二层结构之“A 且B”。
文段先通过转折提出新发现：
木星放射出来的能量多于它吸收的能量(原来认为行星本身没有能源，但最新报道，木星放射出来的能量多于它吸收的能量，即说明行星是有能源的);
再介绍相关研究：
木星大气层不可能产生能量 (木星由内部和大气层组成，大气层不可能产生能量，那木星多出的能量只能是内部产生，可理解为“否一推一” ) 。','2017年天津市考','进阶','published','{"globalNumber":204,"setNumber":11,"localNumber":4,"sourceLabel":"2017年天津市考 49%","accuracy":49,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"科学界一向认为，行星本身是没有能源的，虽然在夜间我们能看到行星，但行星发光只不过是反射了太阳光的结果。然而，最近报道，木星放射出来的能量明显多于它从太阳吸收的能量。因此让人产生疑问：木星有热核能源吗?这种能源是在大气层里还是在它的内部?经过进一步的研究，人们已经探明木星大气层的成分，并得出在那里不可能产生热核能量的结论。\n这段话主要表明了这样一个观点，即："}],"optionRich":{"A":[{"text":"木星发光是反射太阳光的结果"}],"B":[{"text":"木星内部有可能产生热核能源"}],"C":[{"text":"木星不可能产生热核能源"}],"D":[{"text":"木星靠外部能源散发热量"}]},"annotatedStemRich":[{"text":"科学界一向认为，行星本身是没有能源的，虽然在夜间我们能看到行星，但行星发光只不过是反射了太阳光的结果。然而，最近报道，木星放射出来的能量明显多于它从太阳吸收的能量(转折提出新发现)。因此让人产生疑问：木星有热核能源吗?这种能源是在大气层里还是在它的内部?经过进一步的研究，人们已经探明木星大气层的成分，并得出在那里不可能产生热核能量的结论(介绍相关研究)。②\n这段话主要表明了这样一个观点，即："}],"annotatedOptionRich":{"A":[{"text":"木星发光是反射太阳光的结果"}],"B":[{"text":"木星内部有可能产生热核能源"}],"C":[{"text":"木星不可能产生热核能源"}],"D":[{"text":"木星靠外部能源散发热量"}]},"practicalAnalysis":"文段分析见批注。\n文段先提出新发现：木星放射出来的能量多于它吸收的能量，即木星产生了热核能量(否则木星不会放射多于吸收的能量);再介绍相关研究：木星大气层不可能产生能量，即木星内部产生了热核能量(不是大气层，就是内部)。\n综上，对应B选项，当选。","notes":[{"marker":"⑦","content":"行文结构：二层结构之“A 且B”。\n文段先通过转折提出新发现：\n木星放射出来的能量多于它吸收的能量(原来认为行星本身没有能源，但最新报道，木星放射出来的能量多于它吸收的能量，即说明行星是有能源的);\n再介绍相关研究：\n木星大气层不可能产生能量 (木星由内部和大气层组成，大气层不可能产生能量，那木星多出的能量只能是内部产生，可理解为“否一推一” ) 。","matchScore":0.7738,"pairingMode":"content-similarity","order":6}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300205,3,'中心理解题','如果仅从文物价值来看，纸质版的古籍文献的确不适宜大规模地向读者开放，否则，因为频繁翻阅以及由此带来的细菌侵入，必定会在很大程度上影响它们的保存。但如果从史料价值来看，它却本应该向社会开放，因为只有这样，古籍的文献价值才能得到充分实现，学术研究也才可能取得长足的进步。
这段文字重在说明古籍文献：','[{"label":"A","content":"需要民众参与研究"},{"label":"B","content":"保护技术有待提高"},{"label":"C","content":"是否开放是一个难题"},{"label":"D","content":"文物属性更应受到重视"}]','C','文段分析见批注。
文段分别从“文物价值”和“史料价值”两个角度来谈古籍文献是否应该开放这一问题，需注意文段虽有“转折”,但对于“是否应该开放”这一问题，文段并没有给出答案，仅为从两个不同角度看待，对应C选项，当选；
A选项、B选项、D选项均为无中生有，可简单排除。

花生批注：
⑧ 行文结构：二层结构之并列。先指出从文物价值来看，纸质版的古籍文献的确不适宜大规模地向读者开放；
再指出从史料价值来看，它却本应该向社会开放。
这段文字重在说明古籍文献：
A. 需要民众参与研究(无中生有且本身有误)
B. 保护技术有待提高(无中生有)
C. 是否开放是一个难题
D. 文物属性更应受到重视(无中生有)','2020年四川省事业单位','基础','published','{"globalNumber":205,"setNumber":11,"localNumber":5,"sourceLabel":"2020年四川省事业单位 71%","accuracy":71,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"如果仅从文物价值来看，纸质版的古籍文献的确不适宜大规模地向读者开放，否则，因为频繁翻阅以及由此带来的细菌侵入，必定会在很大程度上影响它们的保存。但如果从史料价值来看，它却本应该向社会开放，因为只有这样，古籍的文献价值才能得到充分实现，学术研究也才可能取得长足的进步。\n这段文字重在说明古籍文献："}],"optionRich":{"A":[{"text":"需要民众参与研究"}],"B":[{"text":"保护技术有待提高"}],"C":[{"text":"是否开放是一个难题"}],"D":[{"text":"文物属性更应受到重视"}]},"annotatedStemRich":[{"text":"如果仅从文物价值来看，纸质版的古籍文献的确不适宜大规模地向读者开放，否则，因为频繁翻阅以及由此带来的细菌侵入，必定会在很大程度上影响它们的保存。但如果从史料价值来看，它却本应该向社会开放，因为只有这样，古籍的文献价值才能得到充分实现，学术研究也才可能取得长足的进步。⑨\n⑧花生批注：\n行文结构：二层结构之并列。先指出从文物价值来看，纸质版的古籍文献的确不适宜大规模地向读者开放；\n再指出从史料价值来看，它却本应该向社会开放。\n这段文字重在说明古籍文献："}],"annotatedOptionRich":{"A":[{"text":"需要民众参与研究(无中生有且本身有误)"}],"B":[{"text":"保护技术有待提高(无中生有)"}],"C":[{"text":"是否开放是一个难题","bold":true}],"D":[{"text":"文物属性更应受到重视(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段分别从“文物价值”和“史料价值”两个角度来谈古籍文献是否应该开放这一问题，需注意文段虽有“转折”,但对于“是否应该开放”这一问题，文段并没有给出答案，仅为从两个不同角度看待，对应C选项，当选；\nA选项、B选项、D选项均为无中生有，可简单排除。","notes":[{"marker":"⑧","content":"行文结构：二层结构之并列。先指出从文物价值来看，纸质版的古籍文献的确不适宜大规模地向读者开放；\n再指出从史料价值来看，它却本应该向社会开放。\n这段文字重在说明古籍文献：\nA. 需要民众参与研究(无中生有且本身有误)\nB. 保护技术有待提高(无中生有)\nC. 是否开放是一个难题\nD. 文物属性更应受到重视(无中生有)","matchScore":0.9018,"pairingMode":"marker-and-content","order":7}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300206,3,'中心理解题','要素禀赋理论认为，不同国家之间商品相对价格的不同是发生贸易的基础，这个差价源于各国生产要素比率差异。在解释当代服务贸易时，这一理论有严格的假设条件，包括两国之间要素特别是劳动力不流动这个假设，这是理论的“核”。因为要素流动会改变贸易双方要素禀赋的差异，从而动摇贸易的基础。进入网络时代，虽然劳动力仍然不能大规模流动，但其提供的劳务却可以无障碍地大规模远距离提供，迅速缩小了不同国家的服务差价。
这段文字意在说明：','[{"label":"A","content":"网络的无差别共享功能改变了当代服务贸易的基础"},{"label":"B","content":"要素禀赋理论在网络时代的服务贸易格局下面临挑战"},{"label":"C","content":"传统贸易理论过于严格的假设条件需要与时俱进地调整"},{"label":"D","content":"网络时代的服务全球化使不同国家消费者可享受同等服务"}]','B','文段分析见批注。
文段前半段介绍要素禀赋理论中劳动力不流动是严格的假设条件，后文指出在网络时代劳务可以远距离提供，即网络时代生产要素发生了流动，破坏了该理论的假设条件，故该理论可能面临挑战，定位到B选项，当选；
其他选项均未提及要素禀赋理论，且包含其他问题：A选项的“网络的无差别共享功能”无中生有且“改变基础”本身有误(原文为动摇基础),排除； C选项“需要与时俱进地调整”、D选项的“服务全球化、享受同等服务”均为无中生有，均可简单排除。

花生批注：
⑨ “要素禀赋理论”是全文论述主体。
⑩ 行文结构：二层结构之“背景+新变化”。
先介绍要素禀赋理论：
要素禀赋理论解释当代服务贸易时假设劳动力不流动；再介绍网络时代的新变化：网络时代，劳动力虽然不能大规模流动，但劳务可以大规模远距离提供(即破坏了要素禀赋理论的假设条件)。','2020年事业单位联考','进阶','published','{"globalNumber":206,"setNumber":11,"localNumber":6,"sourceLabel":"2020年事业单位联考49%","accuracy":49,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"要素禀赋理论认为，不同国家之间商品相对价格的不同是发生贸易的基础，这个差价源于各国生产要素比率差异。在解释当代服务贸易时，这一理论有严格的假设条件，包括两国之间要素特别是劳动力不流动这个假设，这是理论的“核”。因为要素流动会改变贸易双方要素禀赋的差异，从而动摇贸易的基础。进入网络时代，虽然劳动力仍然不能大规模流动，但其提供的劳务却可以无障碍地大规模远距离提供，迅速缩小了不同国家的服务差价。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"网络的无差别共享功能改变了当代服务贸易的基础"}],"B":[{"text":"要素禀赋理论在网络时代的服务贸易格局下面临挑战"}],"C":[{"text":"传统贸易理论过于严格的假设条件需要与时俱进地调整"}],"D":[{"text":"网络时代的服务全球化使不同国家消费者可享受同等服务"}]},"annotatedStemRich":[{"text":"要素禀赋理论","underline":true},{"text":"⑨认为，不同国家之间商品相对价格的不同是发生贸易的基础，这个差价源于各国生产要素比率差异。在解释当代服务贸易时，这一理论有严格的假设条件，包括两国之间要素特别是劳动力不流动这个假设，这是理论的“核”。因为要素流动会改变贸易双方要素禀赋的差异，从而动摇贸易的基础(背景介绍)。进入网络时代，虽然劳动力仍然不能大规模流动，但其提供的劳务却可以无障碍地大规模远距离提供，迅速缩小了不同国家的服务差价\n(网络时代的变化)。四\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"网络的无差别共享功能改变了当代服务贸易的基础(本身有误)"}],"B":[{"text":"要素禀赋理论在网络时代的服务贸易格局下面临挑战"}],"C":[{"text":"传统贸易理论过于严格的假设条件需要与时俱进地调整(无中生有)"}],"D":[{"text":"网络时代的服务全球化使不同国家消费者可享受同等服务(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段前半段介绍要素禀赋理论中劳动力不流动是严格的假设条件，后文指出在网络时代劳务可以远距离提供，即网络时代生产要素发生了流动，破坏了该理论的假设条件，故该理论可能面临挑战，定位到B选项，当选；\n其他选项均未提及要素禀赋理论，且包含其他问题：A选项的“网络的无差别共享功能”无中生有且“改变基础”本身有误(原文为动摇基础),排除； C选项“需要与时俱进地调整”、D选项的“服务全球化、享受同等服务”均为无中生有，均可简单排除。","notes":[{"marker":"⑨","content":"“要素禀赋理论”是全文论述主体。","matchScore":0.4464,"pairingMode":"marker-and-content","order":8},{"marker":"⑩","content":"行文结构：二层结构之“背景+新变化”。\n先介绍要素禀赋理论：\n要素禀赋理论解释当代服务贸易时假设劳动力不流动；再介绍网络时代的新变化：网络时代，劳动力虽然不能大规模流动，但劳务可以大规模远距离提供(即破坏了要素禀赋理论的假设条件)。","matchScore":0.8554,"pairingMode":"content-similarity","order":9}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300207,3,'标题拟定题','不要小看了买菜、做饭、刷锅、洗碗这些琐碎家务，调查结果显示，夫妻在家务分工上的分歧是导致家庭关系紧张的重要原因。随着女性年龄增长，因家务分配不公而产生的心理压力会逐渐增加，而男性则相对保持稳定，研究者还发现，未能在家务分工上达成共识常常会令女性觉得在两性关系中处于劣势，从而情绪紧张。而对于男性来说，更重要的不是做多少家务，而是自己的经济社会地位是否高出配偶。当收入低于女方时做家务常常会触发男性的羞耻及抵触心理。
最适合做这段文字标题的是：','[{"label":"A","content":"家务无小事"},{"label":"B","content":"分工的学问"},{"label":"C","content":"生活的调节剂——家务"},{"label":"D","content":"多做家务益处多\n四海公考练习题11套"}]','A','文段分析见批注。
文段开篇给出禁止型对策：不要小看家务，后文具体分析论证，A选项是对策的同义替换(不要小看家务，即家务很重要、无小事),当选；
B选项未提及家务、C选项提到家务但未体现对策、D选项无中生有(原文未提及多做家务的益处),均可简单排除。

花生批注：
⑪ 家务是全文论述话题。
⑫ 行文结构：前对策结构。
文段开篇给出禁止型对策：不要小看家务；
后文先给出对策原因：家务分工分歧是家庭关系紧张重要原因；
接着分别从女性、男性角度分析为什么家务很重要。
最适合做这段文字标题的是：
A. 家务无小事
B. 分工的学问(无主题词)
C. 生活的调节剂——家务(中性表达)
