INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300208,3,'标题拟定类','我国是国际标准化组织成员。政府应该鼓励农产品生产、加工企业和学术团体积极参加国际标准化活动，从中获取发达国家大公司的标准信息，了解他们的技术动态和运作诀窍，并争取使国内的意见和建议能为即将制定或修订的国际标准所采纳，这对减少技术性贸易壁垒影响，是十分有利的。
适合本段文字的小标题是：','[{"label":"A","content":"获取标准化信息"},{"label":"B","content":"减少技术性贸易壁垒"},{"label":"C","content":"积极参加国际标准化活动"},{"label":"D","content":"制定或修订国际标准"}]','C','文段分析见批注。

花生批注：
⑬ 行文结构：前对策结构。
文段在介绍背景后直接给出对策：
政府要鼓励各主体积极参加国际标准化活动；
之后分析参加该活动的积极意义(可获取发达国家大公司的标准信息、了解其技术动态和运作诀窍、可争取国内意见建议能被国际标准采纳、可减少技术性贸易壁垒影响)。','2018年石家庄市事业单位','进阶','published','{"globalNumber":208,"setNumber":11,"localNumber":8,"sourceLabel":"2018年石家庄市事业单位65%","accuracy":65,"typeAndPassage":"标题拟定类+说理类文章","stemRich":[{"text":"我国是国际标准化组织成员。政府应该鼓励农产品生产、加工企业和学术团体积极参加国际标准化活动，从中获取发达国家大公司的标准信息，了解他们的技术动态和运作诀窍，并争取使国内的意见和建议能为即将制定或修订的国际标准所采纳，这对减少技术性贸易壁垒影响，是十分有利的。\n适合本段文字的小标题是："}],"optionRich":{"A":[{"text":"获取标准化信息"}],"B":[{"text":"减少技术性贸易壁垒"}],"C":[{"text":"积极参加国际标准化活动"}],"D":[{"text":"制定或修订国际标准"}]},"annotatedStemRich":[{"text":"我国是国际标准化组织成员 "},{"text":"(背景介绍)。","bold":true},{"text":"政府应该鼓励农产品生产、加工企业和学术团体积极参加国际标准化活动(提出对策),从中获取发达国家大公司的标准信息，了解他们的技术动态和运作诀窍，并争取使国内的意见和建议能为即将制定或修订的国际标准所采纳，这对减少技术性贸易壁垒影响，是十分有利的 (分析论证)。 ⑮\n适合本段文字的小标题是："}],"annotatedOptionRich":{"A":[{"text":"获取标准化信息(非对策且片面)"}],"B":[{"text":"减少技术性贸易壁垒(非对策且片面)"}],"C":[{"text":"积极参加国际标准化活动","bold":true}],"D":[{"text":"制定或修订国际标准(非对策且片面)"}]},"practicalAnalysis":"文段分析见批注。","notes":[{"marker":"⑬","content":"行文结构：前对策结构。\n文段在介绍背景后直接给出对策：\n政府要鼓励各主体积极参加国际标准化活动；\n之后分析参加该活动的积极意义(可获取发达国家大公司的标准信息、了解其技术动态和运作诀窍、可争取国内意见建议能被国际标准采纳、可减少技术性贸易壁垒影响)。","matchScore":0.8952,"pairingMode":"content-similarity","order":12}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300209,3,'细节判断类','劳动教育自身的复杂性与实践的条件性，决定了劳动教育的有效推进不是学校自身就能够独立实现的。在很大程度上，劳动教育对象的获得、目标的落实、实践的路径等方面均需得到社会物质层面、文化层面和制度层面的大力支持。目前，在劳动教育的社会物质支持、文化支持和制度支持方面存在着不容忽视的教育性不足、价值观念冲突和制度不够健全等诸多现实问题，严重影响了劳动教育效果的取得。为此，需要在劳动教育的物质支持方面强化教育的专业性和公共性，在文化支持方面突出价值取向的一致性、在制度支持方面则强化制度自身的公正性。
下列对文意理解错误的是：','[{"label":"A","content":"学校不能独立完成劳动教育"},{"label":"B","content":"社会对劳动教育支持还不够"},{"label":"C","content":"价值观念影响劳动教育的效果"},{"label":"D","content":"物质支持体现劳动教育的专业性"}]','D','D选项存在偷换概念的错误，将“需要在劳动教育的物质支持方面强化教育的专业性”变成“物质支持体现劳动教育的专业性”,错误，当选。','2022年成都市事业单位','进阶','published','{"globalNumber":209,"setNumber":11,"localNumber":9,"sourceLabel":"2022年成都市事业单位60%","accuracy":60,"typeAndPassage":"细节判断类","stemRich":[{"text":"劳动教育自身的复杂性与实践的条件性，决定了劳动教育的有效推进不是学校自身就能够独立实现的。在很大程度上，劳动教育对象的获得、目标的落实、实践的路径等方面均需得到社会物质层面、文化层面和制度层面的大力支持。目前，在劳动教育的社会物质支持、文化支持和制度支持方面存在着不容忽视的教育性不足、价值观念冲突和制度不够健全等诸多现实问题，严重影响了劳动教育效果的取得。为此，需要在劳动教育的物质支持方面强化教育的专业性和公共性，在文化支持方面突出价值取向的一致性、在制度支持方面则强化制度自身的公正性。\n下列对文意理解错误的是："}],"optionRich":{"A":[{"text":"学校不能独立完成劳动教育"}],"B":[{"text":"社会对劳动教育支持还不够"}],"C":[{"text":"价值观念影响劳动教育的效果"}],"D":[{"text":"物质支持体现劳动教育的专业性"}]},"annotatedStemRich":[{"text":"劳动教育自身的复杂性与实践的条件性，决定了劳动教育的有效推进不是学校自身就能够独立实现的( A选项 ) 。在很大程度上，劳动教育对象的获得、目标的落实、实践的路径等方面均需得到社会物质层面、文化层面和制度层面的大力支持。目前，在劳动教育的社会物质支持、文化支持和制度支持方面存在着不容忽视的教育性不足、价值观念冲突和制度不够健全等诸多现实问题( B 选项 ) ,严重影响了劳动教育效果的取得( C 选项)。为此，需要在劳动教育的物质支持方面强化教育的专业性和公共性( D 选项 ) ,在文化支持方面突出价值取向的一致性、在制度支持方面则强化制度自身的公正性。\n下列对文意理解错误的是："}],"annotatedOptionRich":{"A":[{"text":"学校不能独立完成劳动教育"}],"B":[{"text":"社会对劳动教育支持还不够"}],"C":[{"text":"价值观念影响劳动教育的效果"}],"D":[{"text":"物质支持体现劳动教育的专业性(偷换概念)"}]},"practicalAnalysis":"D选项存在偷换概念的错误，将“需要在劳动教育的物质支持方面强化教育的专业性”变成“物质支持体现劳动教育的专业性”,错误，当选。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300210,3,'中心理解题','从能源看，自煤炭时代进入石油时代后，石油成为维系文明社会不可或缺的资源，随着老油田一个个衰落、新油田的发现越来越困难，人们不禁担心，这种不可再生的化石能源势必会枯竭，但事实却不是这样。特别是近十年，科技大发展促进了勘探开发，曾经的技术瓶颈一个个被突破了，许多过去没有经济储量的地区也发现了大油田，剩余可采储量不仅没有降低，反而越来越多了。
这段文字意在说明：','[{"label":"A","content":"勘探技术的发展是提高石油产量的突破口"},{"label":"B","content":"对化石能源枯竭的忧虑是杞人忧天"},{"label":"C","content":"科技发展使石油开采焕发新的生机"},{"label":"D","content":"石油可采储量近十年来呈现爆发式增长"}]','C','文段分析见批注。
文段转折前介绍过去人们对石油枯竭的担忧，转折后介绍事实不像人们所担忧的，科技发展促进勘探开发，发现更多石油，剩余可采储量增多；
C选项“焕发新的生机”既隐含表达了以前人们对石油枯竭的担忧，又能表达现在科技发展对石油开采的促进作用，完美选项，当选；
A选项，科技大发展增加的是石油可采储量，不是石油产量，且选项未提及“科技”,排除；B选项、D选项均未体现“科技发展”,可直接排除。

花生批注：
⑭ 行文结构：二层结构之转折。转折前介绍过去人们对石油枯竭的担忧；
转折之后介绍新情况：
事实不像人们所担忧的，科技发展促进勘探开发，发现更多石油，剩余可采储量增多。
“科技发展”是转折后内容的重点。
文段开篇给出对策：政府应鼓励企业、学术团体积极参加国际标准化活动；后文介绍该对策的积极意义。正确答案应体现对策，对应C选项，当选；
A选项、B选项和D选项均是该对策的积极意义的一个方面，可简单排除。','2017年四川省考','进阶','published','{"globalNumber":210,"setNumber":11,"localNumber":10,"sourceLabel":"2017年四川省考64%","accuracy":64,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"从能源看，自煤炭时代进入石油时代后，石油成为维系文明社会不可或缺的资源，随着老油田一个个衰落、新油田的发现越来越困难，人们不禁担心，这种不可再生的化石能源势必会枯竭，但事实却不是这样。特别是近十年，科技大发展促进了勘探开发，曾经的技术瓶颈一个个被突破了，许多过去没有经济储量的地区也发现了大油田，剩余可采储量不仅没有降低，反而越来越多了。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"勘探技术的发展是提高石油产量的突破口"}],"B":[{"text":"对化石能源枯竭的忧虑是杞人忧天"}],"C":[{"text":"科技发展使石油开采焕发新的生机"}],"D":[{"text":"石油可采储量近十年来呈现爆发式增长"}]},"annotatedStemRich":[{"text":"从能源看，自煤炭时代进入石油时代后，石油成为维系文明社会不可或缺的资源，随着老油田一个个衰落、新油田的发现越来越困难，人们不禁担心，这种不可再生的化石能源势必会枯竭，"},{"text":"但事实却不是这样(转折前)。特别是近十年，科技大发展促进了勘探开发，曾经的技术瓶颈一个个被突破了，许多过去没有经济储量的地区也发现了大油田，剩余可采储量不仅没有降低，反而越来越多了(转折后)。","underline":true},{"text":"⑭\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"勘探技术的发展是提高石油产量的突破口(无中生有)"}],"B":[{"text":"对化石能源枯竭的忧虑是杞人忧天(缺少主题词)"}],"C":[{"text":"科技发展使石油开采焕发新的生机"}],"D":[{"text":"石油可采储量近十年来呈现爆发式增长(缺少主题词)"}]},"practicalAnalysis":"文段分析见批注。\n文段转折前介绍过去人们对石油枯竭的担忧，转折后介绍事实不像人们所担忧的，科技发展促进勘探开发，发现更多石油，剩余可采储量增多；\nC选项“焕发新的生机”既隐含表达了以前人们对石油枯竭的担忧，又能表达现在科技发展对石油开采的促进作用，完美选项，当选；\nA选项，科技大发展增加的是石油可采储量，不是石油产量，且选项未提及“科技”,排除；B选项、D选项均未体现“科技发展”,可直接排除。","notes":[{"marker":"⑭","content":"行文结构：二层结构之转折。转折前介绍过去人们对石油枯竭的担忧；\n转折之后介绍新情况：\n事实不像人们所担忧的，科技发展促进勘探开发，发现更多石油，剩余可采储量增多。\n“科技发展”是转折后内容的重点。\n文段开篇给出对策：政府应鼓励企业、学术团体积极参加国际标准化活动；后文介绍该对策的积极意义。正确答案应体现对策，对应C选项，当选；\nA选项、B选项和D选项均是该对策的积极意义的一个方面，可简单排除。","matchScore":0.6637,"pairingMode":"marker-and-content","order":13}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300211,3,'语句排序题','①由于各个作者对所描绘植物和绘画手法有不同的认识，所以诸多本草著作中就出现了风格各异的插图，但准确性欠佳
②植物科学画在中国有过辉煌时期，中国最早对植物的了解来自农业生产和本草医药的需要
③本草学家把社会实践中积累的植物学知识用文字记录下来，并配以形象图画，使人们更容易识别和利用植物，其中最著名的是李时珍的《本草纲目》
④为了能在最鲜活的状态下记录物种的模样，探险队伍中增加了专业画师，这就有了植物科学画的雏形
⑤那个时期的绘图工具是毛笔，技法是中国画中的白描
⑥现代意义的植物科学画源自西方，地理大发现时期，欧洲贵族、商人和科学家组成的舰队探索世界，同时收集动植物标本
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"⑥④②①⑤③⑩"},{"label":"B","content":"②③⑤①⑥④①"},{"label":"C","content":"②⑤①③④⑥"},{"label":"D","content":"⑥②③①④⑤"}]','B','观察选项发现，首句可能为②⑥,②介绍植物科学画在中国的早期情况(古代植物科学画),⑥介绍现代意义的植物科学画来源(现代植物科学画),根据时间顺序，②在⑥前更符合逻辑，排除A选项、D选项；
观察B选项、C选项，⑥④顺序不同，④提及“探险队伍”,显然应在“西方舰队探索世界”之后，即④在⑥之后，答案锁定B选项。

花生批注：
⑮ ④提到画师加入了探险队
伍，⑥提出各种人员组成舰队“探索世界”;
按照逻辑，应先由各种人员组成舰队，画师再加入队伍，即⑥④绑定一起，排除C 、 D选项。
⑯ ③介绍本草学家给植物学知识配以形象图画；
①介绍因各个作者手法不同，所以形象各异，准确性欠佳；
应先介绍何人做画，再介绍插画特点与问题；
所以即使有同学认为也可能先介绍现代植物科学画，再介绍古代科学植物画，也无法选择A选项。
⑪ 行文结构：二层结构之并列。先介绍中国最初的植物科学画做法及其局限性；
再说明现代意义的植物科学画的画法。
③本草学家把社会实践中积累的植物学知识用文字记录下来，并配以形象图画，使人们更容易识别和利用植物，其中最著名的是李时珍的《本草纲目》
④为了能在最鲜活的状态下记录物种的模样，探险队伍⑮中增加了专业画师，这就有了植物科学画的雏形
⑤那个时期的绘图工具是毛笔，技法是中国画中的白描
⑥现代意义的植物科学画源自西方，地理大发现时期，欧洲贵族、商人和科学家组成的舰队探索世界，同时收集动植物标本
将以上6个句子重新排列，语序正确的是：
A.⑥④②①⑤③⑩ B.②③⑤①⑥④①
C.②⑤①③④⑥ D.⑥②③①④⑤','2019年国家公务员考试','挑战','published','{"globalNumber":211,"setNumber":11,"localNumber":11,"sourceLabel":"2019年国家公务员考试44%","accuracy":44,"typeAndPassage":"语句排序题+科普介绍文章","stemRich":[{"text":"①由于各个作者对所描绘植物和绘画手法有不同的认识，所以诸多本草著作中就出现了风格各异的插图，但准确性欠佳\n②植物科学画在中国有过辉煌时期，中国最早对植物的了解来自农业生产和本草医药的需要\n③本草学家把社会实践中积累的植物学知识用文字记录下来，并配以形象图画，使人们更容易识别和利用植物，其中最著名的是李时珍的《本草纲目》\n④为了能在最鲜活的状态下记录物种的模样，探险队伍中增加了专业画师，这就有了植物科学画的雏形\n⑤那个时期的绘图工具是毛笔，技法是中国画中的白描\n⑥现代意义的植物科学画源自西方，地理大发现时期，欧洲贵族、商人和科学家组成的舰队探索世界，同时收集动植物标本\n将以上6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"⑥④②①⑤③⑩"}],"B":[{"text":"②③⑤①⑥④①"}],"C":[{"text":"②⑤①③④⑥"}],"D":[{"text":"⑥②③①④⑤"}]},"annotatedStemRich":[{"text":"①由于各个作者对所描绘植物和绘画手法有不同的认识，所以诸多本草著作中就出现了风格各异的插图，但准确性欠佳\n②植物科学画在中国有过辉煌时期，中国最早对植物的了解来自农业生产和本草医药的需要\n③本草学家把社会实践中积累的植物学知识用文字记录下来，并配以形象图画，使人们更容易识别和利用植物，其中最著名的是李时珍的《本草纲目》\n④为了能在最鲜活的状态下记录物种的模样，"},{"text":"探险队伍","underline":true},{"text":"⑮中增加了专业画师，这就有了植物科学画的雏形\n⑤那个时期的绘图工具是毛笔，技法是中国画中的白描\n⑥现代意义的植物科学画源自西方，地理大发现时期，欧洲贵族、商人和科学家组成的舰队探索世界，同时收集动植物标本\n将以上6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"⑥④②①⑤③⑩"}],"B":[{"text":"②③⑤①⑥④①"}],"C":[{"text":"②⑤①③④⑥"}],"D":[{"text":"⑥②③①④⑤"}]},"practicalAnalysis":"观察选项发现，首句可能为②⑥,②介绍植物科学画在中国的早期情况(古代植物科学画),⑥介绍现代意义的植物科学画来源(现代植物科学画),根据时间顺序，②在⑥前更符合逻辑，排除A选项、D选项；\n观察B选项、C选项，⑥④顺序不同，④提及“探险队伍”,显然应在“西方舰队探索世界”之后，即④在⑥之后，答案锁定B选项。","notes":[{"marker":"⑮","content":"④提到画师加入了探险队\n伍，⑥提出各种人员组成舰队“探索世界”;\n按照逻辑，应先由各种人员组成舰队，画师再加入队伍，即⑥④绑定一起，排除C 、 D选项。","matchScore":0.3573,"pairingMode":"marker-and-content","order":14},{"marker":"⑯","content":"③介绍本草学家给植物学知识配以形象图画；\n①介绍因各个作者手法不同，所以形象各异，准确性欠佳；\n应先介绍何人做画，再介绍插画特点与问题；\n所以即使有同学认为也可能先介绍现代植物科学画，再介绍古代科学植物画，也无法选择A选项。","matchScore":0.4985,"pairingMode":"content-similarity","order":15},{"marker":"⑪","content":"行文结构：二层结构之并列。先介绍中国最初的植物科学画做法及其局限性；\n再说明现代意义的植物科学画的画法。\n③本草学家把社会实践中积累的植物学知识用文字记录下来，并配以形象图画，使人们更容易识别和利用植物，其中最著名的是李时珍的《本草纲目》\n④为了能在最鲜活的状态下记录物种的模样，探险队伍⑮中增加了专业画师，这就有了植物科学画的雏形\n⑤那个时期的绘图工具是毛笔，技法是中国画中的白描\n⑥现代意义的植物科学画源自西方，地理大发现时期，欧洲贵族、商人和科学家组成的舰队探索世界，同时收集动植物标本\n将以上6个句子重新排列，语序正确的是：\nA.⑥④②①⑤③⑩ B.②③⑤①⑥④①\nC.②⑤①③④⑥ D.⑥②③①④⑤","matchScore":1.2908,"pairingMode":"content-similarity","order":16}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300212,3,'语句排序类','①这不仅表明了工业社会对于文化生产的接管、改造和重新规划，而且，技术的意义开始占据前所未有的份额
②电影的诞生是技术介入艺术的里程碑事件
③技术始终是文化生产的组成部分
④尽管如此，技术从未扮演艺术的主角
⑤庄子、杜甫、苏东坡，《窦娥冤》《红楼梦》,这些经典令人敬重的原因是深刻的思想和洞察力，而不是由于书写于竹简，上演于舞台，或者印刷在书本里
⑥从青铜铸鼎、笔墨纸砚到瓦舍勾栏的兴盛、印刷时代的降临，艺术符号的制作及其传播从来没有离开技术的支持
将上述6个句子重新排列，语序正确的是：','[{"label":"A","content":"③⑤④⑥②①"},{"label":"B","content":"⑥⑤④②①③"},{"label":"C","content":"③⑥④⑤②①"},{"label":"D","content":"⑥④⑤③②①"}]','C','由于本题③⑥不好判断首句，可从①的“这”或者④的“尽管如此”入手；
观察选项，④句前只能是⑤或⑥,若⑤④相连，先说“经典令人敬重是因为思想和洞察力，而非‘技术’”,接着说“技术从未是主角”,前后无法构成转折；若⑥④相连，先说“艺术从未离开技术的支持”,转折后引出“技术从未是主角”,逻辑恰当，⑧排除A 、B 两项；
C 、D 两项的差别只有③的位置：③若做首句，③⑥介绍“技术一直是艺术/文化的组成部分”,转折后④⑤介绍“但技术一直不是主角”,在之后 ②①介绍“电影诞生后，技术开始占据前所未有的份额”,逻辑正确；
③若在中间，无法承上启下，且先介绍“技术从来不是艺术主角”,再介绍“技术是文化的组成部分”,逻辑混乱，排除；
综上，答案为C选项。

花生批注：
⑱ ⑤④可理解为：
尽管经典不是因为技术，但技术从未是主角；
⑥④可理解为：
尽管艺术从未离开技术支持，但是技术从未是主角。','2018年黑龙江省考','进阶','published','{"globalNumber":212,"setNumber":11,"localNumber":12,"sourceLabel":"2018年黑龙江省考64%","accuracy":64,"typeAndPassage":"语句排序类+科普介绍文章","stemRich":[{"text":"①这不仅表明了工业社会对于文化生产的接管、改造和重新规划，而且，技术的意义开始占据前所未有的份额\n②电影的诞生是技术介入艺术的里程碑事件\n③技术始终是文化生产的组成部分\n④尽管如此，技术从未扮演艺术的主角\n⑤庄子、杜甫、苏东坡，《窦娥冤》《红楼梦》,这些经典令人敬重的原因是深刻的思想和洞察力，而不是由于书写于竹简，上演于舞台，或者印刷在书本里\n⑥从青铜铸鼎、笔墨纸砚到瓦舍勾栏的兴盛、印刷时代的降临，艺术符号的制作及其传播从来没有离开技术的支持\n将上述6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"③⑤④⑥②①"}],"B":[{"text":"⑥⑤④②①③"}],"C":[{"text":"③⑥④⑤②①"}],"D":[{"text":"⑥④⑤③②①"}]},"annotatedStemRich":[{"text":"①这不仅表明了工业社会对于文化生产的接管、改造和重新规划，而且，技术的意义开始占据前所未有的份额\n②电影的诞生是技术介入艺术的里程碑事件\n③技术始终是文化生产的组成部分\n④尽管如此，技术从未扮演艺术的主角\n⑤庄子、杜甫、苏东坡，《窦娥冤》《红楼梦》,这些经典令人敬重的原因是深刻的思想和洞察力，而不是由于书写于竹简，上演于舞台，或者印刷在书本里\n⑥从青铜铸鼎、笔墨纸砚到瓦舍勾栏的兴盛、印刷时代的降临，艺术符号的制作及其传播从来没有离开技术的支持\n将上述6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"③⑤④⑥②①"}],"B":[{"text":"⑥⑤④②①③"}],"C":[{"text":"③⑥④⑤②①"}],"D":[{"text":"⑥④⑤③②①"}]},"practicalAnalysis":"由于本题③⑥不好判断首句，可从①的“这”或者④的“尽管如此”入手；\n观察选项，④句前只能是⑤或⑥,若⑤④相连，先说“经典令人敬重是因为思想和洞察力，而非‘技术’”,接着说“技术从未是主角”,前后无法构成转折；若⑥④相连，先说“艺术从未离开技术的支持”,转折后引出“技术从未是主角”,逻辑恰当，⑧排除A 、B 两项；\nC 、D 两项的差别只有③的位置：③若做首句，③⑥介绍“技术一直是艺术/文化的组成部分”,转折后④⑤介绍“但技术一直不是主角”,在之后 ②①介绍“电影诞生后，技术开始占据前所未有的份额”,逻辑正确；\n③若在中间，无法承上启下，且先介绍“技术从来不是艺术主角”,再介绍“技术是文化的组成部分”,逻辑混乱，排除；\n综上，答案为C选项。","notes":[{"marker":"⑱","content":"⑤④可理解为：\n尽管经典不是因为技术，但技术从未是主角；\n⑥④可理解为：\n尽管艺术从未离开技术支持，但是技术从未是主角。","matchScore":0.6755,"pairingMode":"content-similarity","order":17}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300213,3,'中心理解题','传统的创新观念认为创新没有固定结构，不遵从规则和模式。想要成为创新者的人被告知要“跳出固有思维模式”,“尽情拓展思路，用与你的产品和服务毫不相关的东西做类比”。我们则主张一种截然不同的方法：在众所周知的框架内思考，不要跳出它的范围。人在专注于某个状况或问题的内部因素时，创造力才是最强的，通过对某个特定的创新任务进行界定，之后对其外延加以封闭，由此，我们大多数人才可能会更具持久的创造力。
这段文字意在说明：','[{"label":"A","content":"专注是提升创造力的重要影响因素"},{"label":"B","content":"框架内的思维往往会更有助于创新"},{"label":"C","content":"忽视规则和模式的观念不利于激发创造力"},{"label":"D","content":"没有固定结构的创新会限制创新者的思维"}]','B','文段分析见批注。
文段通过对比引出作者的对策：创新要在框架内思考，不要跳出它的范围。 B选项可翻译为“创新可以在框架内思考”②,是文中观点的同义替换，当选；

花生批注：
⑲ 创新观念是全文论述话题。
②0 行文结构：前对策结构。
通过和传统的创新观念对比，给出作者的对策：创新要在框架内思考；
最后分析论证。','2015年国家公务员考试','基础','published','{"globalNumber":213,"setNumber":11,"localNumber":13,"sourceLabel":"2015年国家公务员考试75%","accuracy":75,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"传统的创新观念认为创新没有固定结构，不遵从规则和模式。想要成为创新者的人被告知要“跳出固有思维模式”,“尽情拓展思路，用与你的产品和服务毫不相关的东西做类比”。我们则主张一种截然不同的方法：在众所周知的框架内思考，不要跳出它的范围。人在专注于某个状况或问题的内部因素时，创造力才是最强的，通过对某个特定的创新任务进行界定，之后对其外延加以封闭，由此，我们大多数人才可能会更具持久的创造力。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"专注是提升创造力的重要影响因素"}],"B":[{"text":"框架内的思维往往会更有助于创新"}],"C":[{"text":"忽视规则和模式的观念不利于激发创造力"}],"D":[{"text":"没有固定结构的创新会限制创新者的思维"}]},"annotatedStemRich":[{"text":"传统的"},{"text":"创新观念","underline":true},{"text":"⑨认为创新没有固定结构，不遵从规则和模式。想要成为创新者的人被告知要“跳出固有思维模式”,“尽情拓展思路，用与你的产品和服务毫不相关的东西做类比”(介绍传统创新观念)。我们则主张一种截然不同的方法：在众所周知的框架内思考，不要跳出它的范围(对比引出对策)。人在专注于某个状况或问题的内部因素时，创造力才是最强的( "},{"text":"A 选项),通","bold":true},{"text":"过对某个特定的创新任务进行界定，之后对其外延加以封闭，由此，我们大多数人才可能会更具持久的创造力(解释说明)。②\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"专注是提升创造力的重要影响因素(出处有误且无主题词)"}],"B":[{"text":"框架内的思维往往会更有助于创新"}],"C":[{"text":"忽视规则和模式的观念不利于激发创造力"},{"text":"(问题表述)","bold":true}],"D":[{"text":"没有固定结构的创新会限制创新者的思维(问题表述)"}]},"practicalAnalysis":"文段分析见批注。\n文段通过对比引出作者的对策：创新要在框架内思考，不要跳出它的范围。 B选项可翻译为“创新可以在框架内思考”②,是文中观点的同义替换，当选；","notes":[{"marker":"⑲","content":"创新观念是全文论述话题。","matchScore":0.3294,"pairingMode":"content-similarity","order":18},{"marker":"②0","content":"行文结构：前对策结构。\n通过和传统的创新观念对比，给出作者的对策：创新要在框架内思考；\n最后分析论证。","matchScore":0.6921,"pairingMode":"content-similarity","order":19}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300214,3,'语句填入类','除了一些特殊的年份，在江淮一带生活的人每年都要经历梅雨，习以为常。它通常在6月上中旬到7 月上旬末之间，因为正值江南特产梅子成熟之际，这段时间的降雨被称为梅雨。不过梅雨还有个别名，叫“霉雨”,那是因为这段时间阴雨连绵，湿度大，气温高，衣物和食品容易霉烂。梅雨区里生活的人大概都有衣服许久不穿，过段时间拿出来后上面已经长了毛的经历。填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"这就是梅雨形成的过程"},{"label":"B","content":"这就是梅雨给人的“教训”"},{"label":"C","content":"这就是梅雨遭人厌弃的原因"},{"label":"D","content":"这就是梅雨给南方人留下的记号"}]','D','根据选项可知，尾句是对上文的解释，可依次分析选项：
A选项的“形成过程”,前文并没有介绍，无法填入； C选项的“遭人厌弃”太过消极，原文感情色彩较中性②,无法填入；
若填入B选项，可将梅雨季衣服和食品容易霉烂看作“教训”,提醒人们注意梅雨季防发霉，逻辑正确；
2

花生批注：
2 “人们对梅雨习以为常”、“大概都有衣服许久不穿，过段时间拿出来后上面已经长了毛的经历”,表达都较中性，无法看出“厌恶”; 另外，可联系常识，梅雨只是一种天气类型，客观存在，个别人可能对其“厌恶”, 但民众均对其“厌恶”的说法显然不符合实际情况。
23 类似“军人身上的伤疤就是
最好的军功章”,“衣服上的毛就是梅雨留下的记号”。
25 例如：不努力考不上，不代表考不上。
若填入D选项，可将衣服上长出的“毛”看作是梅雨给人留下的“记号”②, 对应完美，且与B选项相比，D选项更形象生动，这一时期衣服上长出的“毛”是梅雨给人留下的“记号”,所以人们称梅雨为“霉雨”,“霉(毛)”就是梅雨给人的印象(记号);
综上，答案为D选项。','2020年贵州省事业单位','进阶','published','{"globalNumber":214,"setNumber":11,"localNumber":14,"sourceLabel":"2020年贵州省事业单位61%","accuracy":61,"typeAndPassage":"语句填入类+科普介绍文章","stemRich":[{"text":"除了一些特殊的年份，在江淮一带生活的人每年都要经历梅雨，习以为常。它通常在6月上中旬到7 月上旬末之间，因为正值江南特产梅子成熟之际，这段时间的降雨被称为梅雨。不过梅雨还有个别名，叫“霉雨”,那是因为这段时间阴雨连绵，湿度大，气温高，衣物和食品容易霉烂。梅雨区里生活的人大概都有衣服许久不穿，过段时间拿出来后上面已经长了毛的经历。"},{"text":"                         ","underline":true},{"text":" 填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"这就是梅雨形成的过程"}],"B":[{"text":"这就是梅雨给人的“教训”"}],"C":[{"text":"这就是梅雨遭人厌弃的原因"}],"D":[{"text":"这就是梅雨给南方人留下的记号"}]},"annotatedStemRich":[{"text":"除了一些特殊的年份，在江淮一带生活的人每年都要经历梅雨，习以为常。它通常在6月上中旬到7月上旬末之间，因为正值江南特产梅子成熟之际，这段时间的降雨被称为梅雨(背景介绍)。不过梅雨还有个别名，叫“霉雨”, 那是因为这段时间阴雨连绵，湿度大，气温高，衣物和食品容易霉烂。梅雨区里生活的人大概都有衣服许久不穿，过段时间拿出来后上面已经长了毛的经历 (梅雨期东西容易发霉)。 "},{"text":"                        ","underline":true},{"text":"\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"这就是梅雨形成的过程(无中生有)"}],"B":[{"text":"这就是梅雨给人的“教训”"}],"C":[{"text":"这就是梅雨遭人厌弃的原因"}],"D":[{"text":"这就是梅雨给南方人留下的记号"}]},"practicalAnalysis":"根据选项可知，尾句是对上文的解释，可依次分析选项：\nA选项的“形成过程”,前文并没有介绍，无法填入； C选项的“遭人厌弃”太过消极，原文感情色彩较中性②,无法填入；\n若填入B选项，可将梅雨季衣服和食品容易霉烂看作“教训”,提醒人们注意梅雨季防发霉，逻辑正确；\n2","notes":[{"marker":"2","content":"“人们对梅雨习以为常”、“大概都有衣服许久不穿，过段时间拿出来后上面已经长了毛的经历”,表达都较中性，无法看出“厌恶”; 另外，可联系常识，梅雨只是一种天气类型，客观存在，个别人可能对其“厌恶”, 但民众均对其“厌恶”的说法显然不符合实际情况。","matchScore":0.5842,"pairingMode":"marker-and-content","order":21},{"marker":"23","content":"类似“军人身上的伤疤就是\n最好的军功章”,“衣服上的毛就是梅雨留下的记号”。","matchScore":0.1204,"pairingMode":"content-similarity","order":22},{"marker":"25","content":"例如：不努力考不上，不代表考不上。\n若填入D选项，可将衣服上长出的“毛”看作是梅雨给人留下的“记号”②, 对应完美，且与B选项相比，D选项更形象生动，这一时期衣服上长出的“毛”是梅雨给人留下的“记号”,所以人们称梅雨为“霉雨”,“霉(毛)”就是梅雨给人的印象(记号);\n综上，答案为D选项。","matchScore":0.2236,"pairingMode":"content-similarity","order":24}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300215,3,'中心理解题','由于星辰间的距离太过漫长，单凭肉眼观测，我们绝不可能对宇宙的大小形成一个明晰的概念，并且很难想象出我们与这些天体的实际距离。假若我们能一望而知星辰的远近，假若我们的眼睛又锐利得足以看出恒星和行星表面上的微小的形貌，那么,宇宙的真实构造便会在人类开始研究星空的那一天就真相大白了。古人却不曾想到这一点，因此他们便认为那些天体都如他们所看到的那样，
和地球是绝不相似的东西。即使到了现代，我们自己仰望天空的时候，也很难想象这些恒星比那些行星要远出千百万倍。
这段话的核心含义是：','[{"label":"A","content":"宇宙的真实构造难以明晰"},{"label":"B","content":"肉眼观测天体是不可靠的"},{"label":"C","content":"古人对天体的认识不完善"},{"label":"D","content":"人类对天体的感知有缺陷"}]','B','文段分析见批注。
文段开篇给出总观点：单凭肉眼观测不能明晰宇宙大小和与天体的距离，后文展开论述； B选项是观点的同义替换，当选；
A选项本身有误，肉眼观测难以明晰宇宙真实构造，不代表宇宙真实构造难以明晰，排除；C选项出自后文分析部分，出处有误，排除；D选项的“缺陷”一词属无中生有，文段仅表明肉眼无法观测到，并非感知缺陷，排除。

花生批注：
④ 行文结构：前观点结构。
文段开篇提出观点：
单凭肉眼观测不能明晰宇宙大小和与天体的距离；
接着进行分析论证：
若肉眼能看出远近且能看清天体，宇宙的真实构造早就明晰了(即肉眼看不出); 古人误以为他们看清了天体；
现代人也对天体距离有误解。','2022年安徽省事业单位','进阶','published','{"globalNumber":215,"setNumber":11,"localNumber":15,"sourceLabel":"2022年安徽省事业单位46%","accuracy":46,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"由于星辰间的距离太过漫长，单凭肉眼观测，我们绝不可能对宇宙的大小形成一个明晰的概念，并且很难想象出我们与这些天体的实际距离。假若我们能一望而知星辰的远近，假若我们的眼睛又锐利得足以看出恒星和行星表面上的微小的形貌，那么,宇宙的真实构造便会在人类开始研究星空的那一天就真相大白了。古人却不曾想到这一点，因此他们便认为那些天体都如他们所看到的那样，\n和地球是绝不相似的东西。即使到了现代，我们自己仰望天空的时候，也很难想象这些恒星比那些行星要远出千百万倍。\n这段话的核心含义是："}],"optionRich":{"A":[{"text":"宇宙的真实构造难以明晰"}],"B":[{"text":"肉眼观测天体是不可靠的"}],"C":[{"text":"古人对天体的认识不完善"}],"D":[{"text":"人类对天体的感知有缺陷"}]},"annotatedStemRich":[{"text":"由于星辰间的距离太过漫长，单凭肉眼观测，我们绝不可能对宇宙的大小形成一个明晰的概念，并且很难想象出我们与这些天体的实际距离(前观点)。假若我们能一望而知星辰的远近，假若我们的眼睛又锐利得足以看出恒星和行星表面上的微小的形貌，那么,宇宙的真实构造便会在人类开始研究星空的那一天就真相大白了。古人却不曾想到这一点，因此他们便认为那些天体都如他们所看到的那样，和地球是绝不相似的东西。即使到了现代，我们自己仰望天空的时候，也很难想象这些恒星比那些行星要远出千百万倍(分析论证)。②\n这段话的核心含义是："}],"annotatedOptionRich":{"A":[{"text":"宇宙的真实构造难以明晰(本身有误)"}],"B":[{"text":"肉眼观测天体是不可靠的"}],"C":[{"text":"古人对天体的认识不完善(出处有误)"}],"D":[{"text":"人类对天体的感知有缺陷(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段开篇给出总观点：单凭肉眼观测不能明晰宇宙大小和与天体的距离，后文展开论述； B选项是观点的同义替换，当选；\nA选项本身有误，肉眼观测难以明晰宇宙真实构造，不代表宇宙真实构造难以明晰，排除；C选项出自后文分析部分，出处有误，排除；D选项的“缺陷”一词属无中生有，文段仅表明肉眼无法观测到，并非感知缺陷，排除。","notes":[{"marker":"④","content":"行文结构：前观点结构。\n文段开篇提出观点：\n单凭肉眼观测不能明晰宇宙大小和与天体的距离；\n接着进行分析论证：\n若肉眼能看出远近且能看清天体，宇宙的真实构造早就明晰了(即肉眼看不出); 古人误以为他们看清了天体；\n现代人也对天体距离有误解。","matchScore":0.6149,"pairingMode":"content-similarity","order":23}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300216,3,'细节判断类','顶端优势是指植物的顶芽优先生长，对侧芽萌发、侧枝生长的抑制作用，也包括对侧枝、叶子生长角度的影响。顶端优势强的植物，几乎不生分枝，如长日照植物向日葵，棉花等。番茄等植物顶端优势弱，能长出许多分枝。灌木顶端优势极弱，几乎没有主茎与分枝的区别。多数植物属中间类型，
如稻、麦、泡桐等。顶端优势的强弱随植株年龄而变化，同时受营养和环境条件的影响，幼龄植物顶端优势强，老龄时减弱。顶端对侧芽的抑制程度，随距离增加而减弱，因此对下部侧芽的抑制比对上部侧芽的轻。许多树木因此形成宝塔形树冠。
由此我们可以推出：','[{"label":"A","content":"距离根系越近，则顶端对侧芽的抑制程度会越高"},{"label":"B","content":"宝塔形树冠是顶端优势弱的植株的典型外部形态"},{"label":"C","content":"顶端优势现象的表现形式和程度因植物种类而异"},{"label":"D","content":"生存在恶劣环境下的植物，其顶端优势较为明显"}]','C','A选项，与第⑦句的“顶端对侧芽的抑制程度，随距离增加而减弱(即距离根系越近，抑制程度越弱)”相悖，排除；
B选项的“顶端优势弱的植株的典型外部形态”无中生有，排除；
C选项，根据第②③④⑤句提到的“向日葵、棉花顶端优势强并且几乎不生分枝，番茄顶端优势弱并且有许多枝，灌木顶端优势极弱并且几乎无主茎与分枝，稻、麦、泡桐顶端优势处于中间”可知，不同植物种类的顶端优势现象的表现形式和程度②不同，正确，当选；

花生批注：
6 “有无分枝”可理解为表现形式；
“强弱”可理解为顶端优势的程度。
D选项，第⑥句只提到顶端优势受到环境条件影响，但条件好坏与顶端优势的关系并未提及，无中生有，排除。','2021年新疆省考','进阶','published','{"globalNumber":216,"setNumber":11,"localNumber":16,"sourceLabel":"2021年新疆省考64%","accuracy":64,"typeAndPassage":"细节判断类","stemRich":[{"text":"顶端优势是指植物的顶芽优先生长，对侧芽萌发、侧枝生长的抑制作用，也包括对侧枝、叶子生长角度的影响。顶端优势强的植物，几乎不生分枝，如长日照植物向日葵，棉花等。番茄等植物顶端优势弱，能长出许多分枝。灌木顶端优势极弱，几乎没有主茎与分枝的区别。多数植物属中间类型，\n如稻、麦、泡桐等。顶端优势的强弱随植株年龄而变化，同时受营养和环境条件的影响，幼龄植物顶端优势强，老龄时减弱。顶端对侧芽的抑制程度，随距离增加而减弱，因此对下部侧芽的抑制比对上部侧芽的轻。许多树木因此形成宝塔形树冠。\n由此我们可以推出："}],"optionRich":{"A":[{"text":"距离根系越近，则顶端对侧芽的抑制程度会越高"}],"B":[{"text":"宝塔形树冠是顶端优势弱的植株的典型外部形态"}],"C":[{"text":"顶端优势现象的表现形式和程度因植物种类而异"}],"D":[{"text":"生存在恶劣环境下的植物，其顶端优势较为明显"}]},"annotatedStemRich":[{"text":"①顶端优势是指植物的顶芽优先生长，对侧芽萌发、侧枝生长的抑制作用，也包括对侧枝、叶子生长角度的影响。②顶端优势强的植物，几乎不生分枝，如长日照植物向日葵，棉花等。③番茄等植物顶端优势弱，能长出许多分枝。\n④灌木顶端优势极弱，几乎没有主茎与分枝的区别。⑤多数植物属中间类型，如稻、麦、泡桐等。⑥顶端优势的强弱随植株年龄而变化，同时受营养和环境条件的影响，幼龄植物顶端优势强，老龄时减弱。⑦顶端对侧芽的抑制程度，随距离增加而减弱，因此对下部侧芽的抑制比对上部侧芽的轻( A 选项)。⑧ 许多树木因此形成宝塔形树冠。\n由此我们可以推出："}],"annotatedOptionRich":{"A":[{"text":"距离根系越近，则顶端对侧芽的抑制程度会越高(本身有误)"}],"B":[{"text":"宝塔形树冠是顶端优势弱的植株的典型外部形态(无中生有)"}],"C":[{"text":"顶端优势现象的表现形式和程度因植物种类而异"}],"D":[{"text":"生存在恶劣环境下的植物，其顶端优势较为明显(无中生有)"}]},"practicalAnalysis":"A选项，与第⑦句的“顶端对侧芽的抑制程度，随距离增加而减弱(即距离根系越近，抑制程度越弱)”相悖，排除；\nB选项的“顶端优势弱的植株的典型外部形态”无中生有，排除；\nC选项，根据第②③④⑤句提到的“向日葵、棉花顶端优势强并且几乎不生分枝，番茄顶端优势弱并且有许多枝，灌木顶端优势极弱并且几乎无主茎与分枝，稻、麦、泡桐顶端优势处于中间”可知，不同植物种类的顶端优势现象的表现形式和程度②不同，正确，当选；","notes":[{"marker":"6","content":"“有无分枝”可理解为表现形式；\n“强弱”可理解为顶端优势的程度。\nD选项，第⑥句只提到顶端优势受到环境条件影响，但条件好坏与顶端优势的关系并未提及，无中生有，排除。","matchScore":0.4629,"pairingMode":"marker-and-content","order":25}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300217,3,'下文推断类⑨','生物大分子药物(如蛋白质或核酸药物)的分子量非常大，很难进入细胞里面发挥作用。然而令人惊奇的是，病毒尺寸远远大于蛋白质，却可以轻而易举地进入细胞内，它是利用什么“秘密武器”呢? 科学家在研究HIV时，发现病毒表面有一段氨基酸序列在入侵细胞时起着关键作用，于是他们把这段有用的序列克隆出来，发现只要连接上这段多肽序列，无论是生物大分子还是几百纳米大小的颗粒，都能畅通无阻地穿过细胞膜进入细胞内，于是科学家将这种神奇的多肽称为穿膜肽。
接下来作者最有可能讲述的是：','[{"label":"A","content":"穿膜肽技术的特征"},{"label":"B","content":"穿膜肽技术的概念"},{"label":"C","content":"穿膜肽的具体应用"},{"label":"D","content":"穿膜肽存在的缺陷"}]','C','文段分析见批注。
文段末尾引出新内容“穿膜肽”,下文应具体展开介绍。 C选项的穿膜肽的具体应用在下文介绍符合逻辑，当选。
A选项、B选项均为偷换概念②,排除；D选项的“缺陷”与上文衔接不当排除。

花生批注：
② “穿膜肽”为全文论述主体。
28 行文结构：二层结构之背景 +新。
前文为背景介绍：生物大分子借助多肽序列也能同病毒一样穿过细胞膜进入细胞内；
再引出新内容：将该多肽序列命名为“穿膜肽”。
生物大分子药物(如蛋白质或核酸药物)的分子量非常大，很难进入细胞里面发挥作用。然而令人惊奇的是，病毒尺寸远远大于蛋白质，却可以轻而易举地进入细胞内，它是利用什么“秘密武器”呢?科学家在研究HIV时，发现病毒表面有一段氨基酸序列在入侵细胞时起着关键作用，于是他们把这段有用的序列克隆出来，发现只要连接上这段多肽序列，无论是生物大分子还是几百纳米大小的颗粒，都能畅通无阻地穿过细胞膜进入细胞内(背景介绍),于是科学家将这种神奇的多肽称为穿膜肽②(提出新内容)。②
片段阅读600 0 (上册)
接下来作者最有可能讲述的是：
⑨ 原文主语为“穿膜肽”;选项主语为“穿膜肽技术”;
二者概念不同，“穿膜肽”为多肽本身，“穿膜肽技术”则为对这一多肽的运用。
③0 若D选项当选，前文应当先介绍穿膜肽有问题，后文才能具体分析存在哪些问题。
