INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300218,3,'下文推断类③','迄今为止，在地面实验中，量子密钥分发的点对点距离可达500千米星级，而量子隐形传态可达100 千米，那么如何在此基础上继续增加量子通信的距离呢?一个阶段性的解决方案是可信中继传输，
我国建设的光纤总长超过2000千米的“京沪干线”是采用了这一方案，在可信中继方案中，需要人为保障中继站点的安全，而中继之间的线路则是安全的。这比传统通信手段中整条线路处处都是面临着信息泄露的风险而言，大幅提高了安全性。
这段文字接下来最可能讲述：','[{"label":"A","content":"目前国外量子通信研究前沿情况"},{"label":"B","content":"中继通讯的缺点"},{"label":"C","content":"更为长远的方案，如使用量子中继器"},{"label":"D","content":"解决的方案还要留给后人去研究解决"}]','C','文段先提出问题：如何继续增加量子通信距离?之后提出了一个阶段性的解决方案，但阶段性方法不能长远解决问题，下文介绍更为长远方案，逻辑恰当；
文段和下文可看作总分结构，先引出“如何继续增加量子通信距离”这一总观点，之后分别介绍阶段性方案和长远性方案， C选项当选。','2019年浙江省台州事业单位','进阶','published','{"globalNumber":218,"setNumber":11,"localNumber":18,"sourceLabel":"2019年浙江省台州事业单位61%","accuracy":61,"typeAndPassage":"下文推断类③+上文是总+分→下文补充另一“分” 【实战解析】","stemRich":[{"text":"迄今为止，在地面实验中，量子密钥分发的点对点距离可达500千米星级，而量子隐形传态可达100 千米，那么如何在此基础上继续增加量子通信的距离呢?一个阶段性的解决方案是可信中继传输，\n我国建设的光纤总长超过2000千米的“京沪干线”是采用了这一方案，在可信中继方案中，需要人为保障中继站点的安全，而中继之间的线路则是安全的。这比传统通信手段中整条线路处处都是面临着信息泄露的风险而言，大幅提高了安全性。\n这段文字接下来最可能讲述："}],"optionRich":{"A":[{"text":"目前国外量子通信研究前沿情况"}],"B":[{"text":"中继通讯的缺点"}],"C":[{"text":"更为长远的方案，如使用量子中继器"}],"D":[{"text":"解决的方案还要留给后人去研究解决"}]},"annotatedStemRich":[{"text":"迄今为止，在地面实验中，量子密钥分发的点对点距离可达500千米星级，而量子隐形传态可达100千米，那么如何在此基础上继续增加量子通信的距离呢 (设问引出话"},{"text":"题","bold":true},{"text":" "},{"text":")","bold":true},{"text":"?一个阶段性的解决方案是可信中继传输，我国建设的光纤总长超过2000千米的“京沪干线”是采用了这一方案，在可信中继方案中，需要人为保障中继站点的安全，而中继之间的线路则是安全的。这比传统通信手段中整条线路处处都是面临着信息泄露的风险而言，大幅提高了安全性。\n这段文字接下来最可能讲述："}],"annotatedOptionRich":{"A":[{"text":"目前国外量子通信研究前沿情况"}],"B":[{"text":"中继通讯的缺点"}],"C":[{"text":"更为长远的方案，","bold":true},{"text":"如使用量子中继器"}],"D":[{"text":"解决的方案还要留给后人去研究解决"}]},"practicalAnalysis":"文段先提出问题：如何继续增加量子通信距离?之后提出了一个阶段性的解决方案，但阶段性方法不能长远解决问题，下文介绍更为长远方案，逻辑恰当；\n文段和下文可看作总分结构，先引出“如何继续增加量子通信距离”这一总观点，之后分别介绍阶段性方案和长远性方案， C选项当选。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300219,3,'中心理解题','艺术创作世界没有“安慰奖”,作品自身的水准远比空谈“磨剑”的口头功夫来得重要。更何况有些标榜的“年数”,还未必真实。所以套用一句当下的流行语：少一些磨剑，多一些真诚。当然，这绝对不是说文艺作品不需要反复打磨；恰恰相反，正是因为文艺作品需要真诚与耐心的打磨，我们才更应该对那些放卫星般的“数年磨一剑”说不，因为它将真正打磨作品的心血廉价化了如果一个人用几个月把自己十年前想到的点子写出来就算是十年磨一剑的话，那些真正在三千多个日日夜夜里一遍遍呕心沥血、钻研雕琢的人，我们又该如何赞扬他们呢?
这段文字意在说明：','[{"label":"A","content":"文艺作品不需要长时间打磨"},{"label":"B","content":"标榜数年磨一剑都缺少真诚"},{"label":"C","content":"作品耗时与创意起始点无关"},{"label":"D","content":"作品价值无需强调创作艰辛"}]','D','文段分析见批注。
文段开篇给出观点：艺术创作的作品自身水准最重要，创作者不要总标榜数年磨一剑(即强调自己的辛苦),之后解释说明； D选项可翻译为：作品本身的价值无需通过强调创作时间的长短来体现，是观点的同义替换，当选；
其他选项均出自解释说明部分，出处有误。并且还有其他问题： A选项本身有误，原文明确指出“作品需要真诚与耐心的打磨”,排除； B选项是明显的绝对化表述③,排除；C选项是中性表达，谈论作品耗时如何计算，未体现作者态度，排除。

花生批注：
33 通俗的说：
艺术创作作品水平更重要，不要空谈创作艰辛；
这不是说艺术创作不需要艰苦付出，而是一些人说的艰辛不真实(动不动就说自己辛苦了几年十几年),他们把真正艰辛付出的心血廉价化了(不管真假都在说“艰辛”,对真正艰辛创作的人不公平)。
③④ 行文结构：前观点结构。
开篇提出观点：
艺术创作的作品自身水准最重要，创作者不要总标榜数年磨一剑(即强调自己的辛苦 ) ;
再解释原因：
①标榜的时间未必真实；
②将真正打磨作品的心血廉价化。
35 原文明确给出了一些作者“在三千多个日日夜夜里一遍遍呕心沥血、钻研雕琢”, 这样的作家即使强调“十年磨一剑”也是真诚的。
片段阅读600
③ 观点态度题也是中心理解题的变形。
