INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300222,3,'中心理解题','与线下教学相比，由于时空差异，线上教学更加依赖于教师的指导和帮助，对资源的需求更大。然而，在知识经济时代，教师早已不再是知识垄断者，网络社会中的个体都有可能成为兼具知识消费者和生产者的双重角色。因此，推动社会力量参与在线教育资源供给，需要改变学校“单打独斗”的传统教育格局，以开放的态度接纳企业在线教育服务。例如，学校可适当采取外包的形式，向那些通过资质审核的教育机构、企业购买网络课程服务，提供“智能+真人”的双引擎驱动教学服务。此外，双方还可在资源支持、学情监测、评价反馈等方面加强协同创新，促进在线教育的健康发展。
这段文字意在说明：','[{"label":"A","content":"“智能+真人”是教育服务的发展趋势"},{"label":"B","content":"教育资源供给来源不再局限于学校内部"},{"label":"C","content":"共享经济时代在线教育将成为一种常态"},{"label":"D","content":"在线教育的健康发展需要引入社会力量"}]','D','文段分析见批注。
文段先介绍背景，再直接给出“要推动社会力量参与在线教育资源供给，接纳企业在线教育服务”的对策，后文加以论证；D选项是对策的同义替换，当选；
A选项、C选项均非对策表述，属中性表达，排除；B选项未提及在线教育且没有对策重点“社会力量”,排除。

花生批注：
④ 与线下教学相比，由于时空差异，线上教学④更加依赖于教师的指导和帮助，对资源的需求更大。然而，在知识经济时代，教师早已不再是知识垄断者，网络社会中的个体都有可能成为兼具知识消费者和生产者的双重角色(背景引出话题)。因此，推动社会力量参与在线教育资源供给，需要改变学校“单打独斗”的传统教育格局，以开放的态度接纳企业在线教育服务(祈使句表对策)。例如，学校可适当采取外包的形式，向那些通过资质审核的教育机构、企业购买网络课程服务，提供“智能+真人”的双引擎驱动教学服务。此外，双方还可在资源支持、学情监测、评价反馈等方面加强协同创新，促进在线教育的健康发展(分析论证)。 ⑤
这段文字意在说明：
A. “智能+真人”是教育服务的发展趋势(中性表达)
B. 教育资源供给来源不再局限于学校内部(无主题词)
C. 共享经济时代在线教育将成为一种常态(中性表达)
D. 在线教育的健康发展需要引入社会力量
⑤ 行文结构：前对策结构。
先引出话题：
虽然线上教学对教育资源需求更大，但是网络社会每个个体都可能成为教师；
再提出对策：
要推动社会力量参与在线教育资源供给，接纳企业在线教育服务；
最后分析论证。','2021年国家公务员考试','基础','published','{"globalNumber":222,"setNumber":12,"localNumber":2,"sourceLabel":"2021年国家公务员考试 74%","accuracy":74,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"与线下教学相比，由于时空差异，线上教学更加依赖于教师的指导和帮助，对资源的需求更大。然而，在知识经济时代，教师早已不再是知识垄断者，网络社会中的个体都有可能成为兼具知识消费者和生产者的双重角色。因此，推动社会力量参与在线教育资源供给，需要改变学校“单打独斗”的传统教育格局，以开放的态度接纳企业在线教育服务。例如，学校可适当采取外包的形式，向那些通过资质审核的教育机构、企业购买网络课程服务，提供“智能+真人”的双引擎驱动教学服务。此外，双方还可在资源支持、学情监测、评价反馈等方面加强协同创新，促进在线教育的健康发展。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"“智能+真人”是教育服务的发展趋势"}],"B":[{"text":"教育资源供给来源不再局限于学校内部"}],"C":[{"text":"共享经济时代在线教育将成为一种常态"}],"D":[{"text":"在线教育的健康发展需要引入社会力量"}]},"annotatedStemRich":[{"text":"④花生批注：\n与线下教学相比，由于时空差异，"},{"text":"线上教学","underline":true},{"text":"④更加依赖于教师的指导和帮助，对资源的需求更大。然而，在知识经济时代，教师早已不再是知识垄断者，网络社会中的个体都有可能成为兼具知识消费者和生产者的双重角色(背景引出话题)。因此，推动社会力量参与在线教育资源供给，需要改变学校“单打独斗”的传统教育格局，以开放的态度接纳企业在线教育服务(祈使句表对策)。例如，学校可适当采取外包的形式，向那些通过资质审核的教育机构、企业购买网络课程服务，提供“智能+真人”的双引擎驱动教学服务。此外，双方还可在资源支持、学情监测、评价反馈等方面加强协同创新，促进在线教育的健康发展(分析论证)。 ⑤\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"“智能+真人”是教育服务的发展趋势(中性表达)"}],"B":[{"text":"教育资源供给来源不再局限于学校内部(无主题词)"}],"C":[{"text":"共享经济时代在线教育将成为一种常态(中性表达)"}],"D":[{"text":"在线教育的健康发展需要引入社会力量"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍背景，再直接给出“要推动社会力量参与在线教育资源供给，接纳企业在线教育服务”的对策，后文加以论证；D选项是对策的同义替换，当选；\nA选项、C选项均非对策表述，属中性表达，排除；B选项未提及在线教育且没有对策重点“社会力量”,排除。","notes":[{"marker":"④","content":"与线下教学相比，由于时空差异，线上教学④更加依赖于教师的指导和帮助，对资源的需求更大。然而，在知识经济时代，教师早已不再是知识垄断者，网络社会中的个体都有可能成为兼具知识消费者和生产者的双重角色(背景引出话题)。因此，推动社会力量参与在线教育资源供给，需要改变学校“单打独斗”的传统教育格局，以开放的态度接纳企业在线教育服务(祈使句表对策)。例如，学校可适当采取外包的形式，向那些通过资质审核的教育机构、企业购买网络课程服务，提供“智能+真人”的双引擎驱动教学服务。此外，双方还可在资源支持、学情监测、评价反馈等方面加强协同创新，促进在线教育的健康发展(分析论证)。 ⑤\n这段文字意在说明：\nA. “智能+真人”是教育服务的发展趋势(中性表达)\nB. 教育资源供给来源不再局限于学校内部(无主题词)\nC. 共享经济时代在线教育将成为一种常态(中性表达)\nD. 在线教育的健康发展需要引入社会力量","matchScore":1.5568,"pairingMode":"marker-and-content","order":3},{"marker":"⑤","content":"行文结构：前对策结构。\n先引出话题：\n虽然线上教学对教育资源需求更大，但是网络社会每个个体都可能成为教师；\n再提出对策：\n要推动社会力量参与在线教育资源供给，接纳企业在线教育服务；\n最后分析论证。","matchScore":0.7277,"pairingMode":"marker-and-content","order":4}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300223,3,'中心理解题','中华文化有足够的智慧与气度消化外来文化，佛教被成功消化吸收就是一个例子。在数千年的发展中，中华文化之所以能广泛吸纳各种文化养料而始终具有自身鲜明特色，就因为它对外来文化并不是简单地拿来或拒斥，而是始终保持自己的主体性，坚持以我为主、为我所用。然而，近现代以来，一些人对文化的认识存在两个显著的不平衡：一是中西文化比重的不平衡；二是人文文化和科学文化的不平衡。这种不平衡体现在教育中，就是中华文化受到的关注不够，而西方文化却占极大比重，这是有失偏颇的。
这段文字意在强调：','[{"label":"A","content":"近现代对文化的认识存在误区"},{"label":"B","content":"当代教育应关注中华文化因素"},{"label":"C","content":"中华文化应在教育中发挥主体作用"},{"label":"D","content":"文化交流中应保持中华文化的主体性"}]','C','文段分析见批注。
文段转折前介绍了中华文化能消化外来文化而始终具有自身鲜明特色的成功经验：保持自己的主体性；转折后引出当今教育存在的“不平衡”问题：中华文化受到关注不够，而西方文化却占极大比重；
我们可根据过去的成功经验(即保持中华文化主体性)来解决当今教育中存在的“不平衡”问题(即西方文化占比过多，中华文化占比不够);
A选项、D选项均未提及“教育”,可简单排除；
B选项为“当代教育应关注中华文化”②,C选项可翻译为“当代教育应发挥中华文化的主体作用”,显然，C选项的“发挥中华文化主体作用”既对应了转折前的成功做法，也对应了转折后“不平衡”的问题，更贴合文段，当选。

花生批注：
⑥ 行文结构：二层结构之转折。转折前介绍中华文化成功经验：
中华文化能消化外来文化而保持自身特色的原因是能够保持自己的主体性；
转折后指出现在问题：
在教育中，中华文化受到关注不够，西方文化占比过重。
这段文字意在强调：
A. 近现代对文化的认识存在误区(无主题词)
B. 当代教育应关注中华文化因素
四海公考练习题12套
C. 中华文化应在教育中发挥主体作用
⑦ B选项只谈及关注中华文化，但未提及是否要保持中华文化的主体性，是否提升中华文化的占比，让中华文化占据主体位置。','2017年四川省考','进阶','published','{"globalNumber":223,"setNumber":12,"localNumber":3,"sourceLabel":"2017年四川省考 46%","accuracy":46,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"中华文化有足够的智慧与气度消化外来文化，佛教被成功消化吸收就是一个例子。在数千年的发展中，中华文化之所以能广泛吸纳各种文化养料而始终具有自身鲜明特色，就因为它对外来文化并不是简单地拿来或拒斥，而是始终保持自己的主体性，坚持以我为主、为我所用。然而，近现代以来，一些人对文化的认识存在两个显著的不平衡：一是中西文化比重的不平衡；二是人文文化和科学文化的不平衡。这种不平衡体现在教育中，就是中华文化受到的关注不够，而西方文化却占极大比重，这是有失偏颇的。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"近现代对文化的认识存在误区"}],"B":[{"text":"当代教育应关注中华文化因素"}],"C":[{"text":"中华文化应在教育中发挥主体作用"}],"D":[{"text":"文化交流中应保持中华文化的主体性"}]},"annotatedStemRich":[{"text":"中华文化有足够的智慧与气度消化外来文化，佛教被成功消化吸收就是一个例子。在数千年的发展中，中华文化之所以能广泛吸纳各种文化养料而始终具有自身鲜明特色，就因为它对外来文化并不是简单地拿来或拒斥，而是始终保持自己的主体性，坚持以我为主、为我所用(转折前)。然而，近现代以来，一些人对文化的认识存在两个显著的不平衡：一是中西文化比重的不平衡；二是人文文化和科学文化的不平衡。这种不平衡体现在教育中，就是中华文化受到的关注不够，而西方文化却占极大比重，这是有失偏颇的(转折引出问题)。⑥\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"近现代对文化的认识存在误区(无主题词)"}],"B":[{"text":"当代教育应关注中华文化因素\n"},{"text":"四海公考","bold":true},{"text":"练习题12套"}],"C":[{"text":"中华文化应在教育中发挥主体作用"}],"D":[{"text":"文化交流中应保持中华文化的主体性(无主题词)"}]},"practicalAnalysis":"文段分析见批注。\n文段转折前介绍了中华文化能消化外来文化而始终具有自身鲜明特色的成功经验：保持自己的主体性；转折后引出当今教育存在的“不平衡”问题：中华文化受到关注不够，而西方文化却占极大比重；\n我们可根据过去的成功经验(即保持中华文化主体性)来解决当今教育中存在的“不平衡”问题(即西方文化占比过多，中华文化占比不够);\nA选项、D选项均未提及“教育”,可简单排除；\nB选项为“当代教育应关注中华文化”②,C选项可翻译为“当代教育应发挥中华文化的主体作用”,显然，C选项的“发挥中华文化主体作用”既对应了转折前的成功做法，也对应了转折后“不平衡”的问题，更贴合文段，当选。","notes":[{"marker":"⑥","content":"行文结构：二层结构之转折。转折前介绍中华文化成功经验：\n中华文化能消化外来文化而保持自身特色的原因是能够保持自己的主体性；\n转折后指出现在问题：\n在教育中，中华文化受到关注不够，西方文化占比过重。\n这段文字意在强调：\nA. 近现代对文化的认识存在误区(无主题词)\nB. 当代教育应关注中华文化因素\n四海公考练习题12套\nC. 中华文化应在教育中发挥主体作用","matchScore":0.7485,"pairingMode":"marker-and-content","order":5},{"marker":"⑦","content":"B选项只谈及关注中华文化，但未提及是否要保持中华文化的主体性，是否提升中华文化的占比，让中华文化占据主体位置。","matchScore":0.5196,"pairingMode":"content-similarity","order":6}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300224,3,'中心理解题','一些非遗，如传统技艺与传统美术，不仅具有历史性、文化性、艺术性，亦具有生产性，即其文化内涵和技艺价值要靠人的手工创造来体现，只有在生产实践中，其传统工艺流程、关键技艺等才能实现保护、传承和弘扬。因此，“生产性保护”理念在我国非遗保护工作中应运而生，100个国家级非遗生产性保护示范基地挂牌亮相。“生产性保护”不仅可以使非遗得到活态传承和保护，还在改善和提升人民生活水平等方面发挥着积极作用。
这段话主要阐明了：','[{"label":"A","content":"非遗具有的特性中，生产性是尤为重要的一个"},{"label":"B","content":"“生产性保护”的出现及应用对非遗保护有益"},{"label":"C","content":"“生产性保护”是在非遗的保护工作中产生的"},{"label":"D","content":"实现非遗的保护和传承需要靠生产实践去体现"}]','B','文段分析见批注。
文段先介绍非遗需要在生产实践中保护；后文重点介绍我国在这一原则的基础上提出了“生产性保护”这一理念，并取得了一系列成就，因此选项一定要体现“生产性保护”,可简单排除A选项和D选项；

花生批注：
⑨ 行文结构：二层结构之“背景+我国的新成就”。
先介绍背景：
非遗的工艺流程和技艺需要在生产实践中保护；
再介绍我国的新成就：
“生产性保护”应运而生，不仅非遗得到活态传承和保护，还改善了人民生活水平；背景+我国结构中，“我国”的做法和成就尤其要重视。
C选项仅介绍了“生产性保护”的产生，未提及其积极作用，排除；
B选项为“A 且 B”类选项，“生产性保护的出现及应用”对应“‘生产性保护’理念在我国非遗保护工作中应运而生，100个国家级非遗生产性保护示范基地挂牌亮相”,“对非遗保护有益”对应“‘生产性保护’不仅可以使非遗得到活态传承和保护，还在改善和提升人民生活水平等方面发挥着积极作用”,一一对应，概括全面，为完美选项；
综上，正确答案是B选项。','2021年安徽省事业单位','基础','published','{"globalNumber":224,"setNumber":12,"localNumber":4,"sourceLabel":"2021年安徽省事业单位71%","accuracy":71,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"一些非遗，如传统技艺与传统美术，不仅具有历史性、文化性、艺术性，亦具有生产性，即其文化内涵和技艺价值要靠人的手工创造来体现，只有在生产实践中，其传统工艺流程、关键技艺等才能实现保护、传承和弘扬。因此，“生产性保护”理念在我国非遗保护工作中应运而生，100个国家级非遗生产性保护示范基地挂牌亮相。“生产性保护”不仅可以使非遗得到活态传承和保护，还在改善和提升人民生活水平等方面发挥着积极作用。\n这段话主要阐明了："}],"optionRich":{"A":[{"text":"非遗具有的特性中，生产性是尤为重要的一个"}],"B":[{"text":"“生产性保护”的出现及应用对非遗保护有益"}],"C":[{"text":"“生产性保护”是在非遗的保护工作中产生的"}],"D":[{"text":"实现非遗的保护和传承需要靠生产实践去体现"}]},"annotatedStemRich":[{"text":"一些非遗，如传统技艺与传统美术，不仅具有历史性、文化性、艺术性，亦具有生产性，即其文化内涵和技艺价值要靠人的手工创造来体现，只有在生产实践中，其传统工艺流程、关键技艺等才能实现保护、传承和弘扬"},{"text":"(背景介绍)。","bold":true},{"text":"因此，"},{"text":" “生产性保护”","underline":true},{"text":"⑤理念在我国非遗保护工作中应运而生，100个国家级非遗生产性保护示范基地挂牌亮相。“生产性保护”不仅可以使非遗得到活态传承和保护，还在改善和提升人民生活水平等方面发挥着积极作用 (我国的新成就)。⑨\n这段话主要阐明了："}],"annotatedOptionRich":{"A":[{"text":"非遗具有的特性中，生产性是尤为重要的一个(缺少核心词)"}],"B":[{"text":"“生产性保护”的出现及应用对非遗保护有益"}],"C":[{"text":"“生产性保护”是在非遗的保护工作中产生的 (片面)"}],"D":[{"text":"实现非遗的保护和传承需要靠生产实践去体现(缺少核心词)"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍非遗需要在生产实践中保护；后文重点介绍我国在这一原则的基础上提出了“生产性保护”这一理念，并取得了一系列成就，因此选项一定要体现“生产性保护”,可简单排除A选项和D选项；","notes":[{"marker":"⑨","content":"行文结构：二层结构之“背景+我国的新成就”。\n先介绍背景：\n非遗的工艺流程和技艺需要在生产实践中保护；\n再介绍我国的新成就：\n“生产性保护”应运而生，不仅非遗得到活态传承和保护，还改善了人民生活水平；背景+我国结构中，“我国”的做法和成就尤其要重视。\nC选项仅介绍了“生产性保护”的产生，未提及其积极作用，排除；\nB选项为“A 且 B”类选项，“生产性保护的出现及应用”对应“‘生产性保护’理念在我国非遗保护工作中应运而生，100个国家级非遗生产性保护示范基地挂牌亮相”,“对非遗保护有益”对应“‘生产性保护’不仅可以使非遗得到活态传承和保护，还在改善和提升人民生活水平等方面发挥着积极作用”,一一对应，概括全面，为完美选项；\n综上，正确答案是B选项。","matchScore":0.8395,"pairingMode":"marker-and-content","order":8}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300225,3,'语句填入类','人类的平均寿命越来越长，但是人类所观察到的癌症发生率也越来越高。在分析这种趋势的时候，很多人会把它归结为现代食物的品质越来越差，于是时不时有人发出“某某食物致癌”的言论，总
能吸引一堆眼球；如果指出这种“致癌的食物”跟现代技术有关，填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"那就更容易得到公众的普遍认同"},{"label":"B","content":"那就应该分析其关联性到底有多大"},{"label":"C","content":"那也不能作为反对现代技术的理由"},{"label":"D","content":"那么据此得出的结论就往往只是初步的"}]','A','所填入语句所在的句子前为“;”,可猜想后两句排比，考虑句式一致：
于是时不时有人发出“某某食物致癌”的言论，总能吸引一堆眼球；
如果指出这种“致癌的食物”跟现代技术有关，
所填入语句对应“总能吸引一堆眼球”,表达“大家关注”或“大家认同”之意，对应A选项，当选。

花生批注：
