INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300226,3,'语句填入类','翻译工作，是一种成果供他人消费的智力劳动，作为劳动者的翻译工作者必须同一切劳动者一样，具备严谨的工匠精神，力求一丝不苟、精益求精，由于市场需要和数字技术发展，当今翻译市场上出现了快餐式翻译和人工智能翻译。这是翻译在传播领域中出现的新事物，有它的特点和特定环境的需要。市场既有需要，就应允许存在，让不同要求的翻译各行其道，由消费者各取所需。但这种翻译新形态，绝不能替代严谨的学术翻译，尤其是替代不了富含艺术想象力的文艺翻译。所以
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"学术和文艺翻译仍然是翻译工作的灵魂"},{"label":"B","content":"市场和技术发展有将翻译工作带入歧途的风险"},{"label":"C","content":"在翻译界倡导工匠精神仍然是十分必要的"},{"label":"D","content":"不同类型的翻译产品满足了市场的不同需求"}]','C','文段分析见批注。

