INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300227,3,'中心理解题','“阅”与“读”两个字，前者代表目光的注视，后者则是声音的萌生。在理想的儿童教育蓝图中，阅读过程除了要有经典的文本、明亮的光线，还应该在老师的带领下发出明朗读书声。但在中国广袤的乡村地区，随着青壮年劳动力走出村庄，声音逐渐消散了。除了花鸟鱼虫带来的有限声响，被留守在乡村的老人儿童，无力再发出更多关于知识的共鸣。除了课堂上的40分钟，孩子真正能够亲近书本的机会非常有限，当语文课上的读书声结束，乡村儿童的阅读渠道往往也随之关闭。“凋敝—一成年人出走——更凋敝”,在最需要声音哺育的童年，乡村儿童无法摆脱这样的怪圈，最终被带进了更加沉默的螺旋。
这段文字意在强调：','[{"label":"A","content":"理想的阅读过程与现实的差距"},{"label":"B","content":"乡村青壮年劳动力的重要性"},{"label":"C","content":"乡村儿童阅读中的声音缺乏"},{"label":"D","content":"乡村儿童教育严重落后"}]','C','文段分析见批注。
文段转折前强调儿童教育阅读过程中声音的重要性，转折后引出问题：乡村儿童阅读过程缺少声音，对应C选项，当选；
其他选项均未提及“声音”,可简单排除。

花生批注：
⑯ 行文结构：二层结构之转折。转折前介绍儿童教育的阅读过程是需要有读书声的；
转折后引出问题：
乡村儿童的阅读缺少声音。','2021年陕西省事业单位','进阶','published','{"globalNumber":227,"setNumber":12,"localNumber":7,"sourceLabel":"2021年陕西省事业单位69%","accuracy":69,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"“阅”与“读”两个字，前者代表目光的注视，后者则是声音的萌生。在理想的儿童教育蓝图中，阅读过程除了要有经典的文本、明亮的光线，还应该在老师的带领下发出明朗读书声。但在中国广袤的乡村地区，随着青壮年劳动力走出村庄，声音逐渐消散了。除了花鸟鱼虫带来的有限声响，被留守在乡村的老人儿童，无力再发出更多关于知识的共鸣。除了课堂上的40分钟，孩子真正能够亲近书本的机会非常有限，当语文课上的读书声结束，乡村儿童的阅读渠道往往也随之关闭。“凋敝—一成年人出走——更凋敝”,在最需要声音哺育的童年，乡村儿童无法摆脱这样的怪圈，最终被带进了更加沉默的螺旋。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"理想的阅读过程与现实的差距"}],"B":[{"text":"乡村青壮年劳动力的重要性"}],"C":[{"text":"乡村儿童阅读中的声音缺乏"}],"D":[{"text":"乡村儿童教育严重落后"}]},"annotatedStemRich":[{"text":" “阅”与“读”","underline":true},{"text":"⑥两个字，前者代表目光的注视，后者则是声音的萌生。在理想的儿童教育蓝图中，阅读过程除了要有经典的文本、明亮的光线，还应该在老师的带领下发出明朗读书声(转折前)。但在中国广袤的乡村地区，随着青壮年劳动力走出村庄，声音逐渐消散了。除了花鸟鱼虫带来的有限声响，被留守在乡村的老人儿童，无力再发出更多关于知识的共鸣。除了课堂上的40 分钟，孩子真正能够亲近书本的机会非常有限，当语文课上的读书声结束，乡"},{"text":"村儿童","underline":true},{"text":"⑮的阅读渠道往往也随之关闭。“凋敝——成年人出走——更凋敝”, 在最需要声音哺育的童年，乡村儿童无法摆脱这样的怪圈，最终被带进了更加\n沉默的螺旋(转折引出问题)。⑥\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"理想的阅读过程与现实的差距(缺主体)"}],"B":[{"text":"乡村青壮年劳动力的重要性(缺主体)"}],"C":[{"text":"乡村儿童阅读中的声音缺乏"}],"D":[{"text":"乡村儿童教育严重落后(主题不一致)"}]},"practicalAnalysis":"文段分析见批注。\n文段转折前强调儿童教育阅读过程中声音的重要性，转折后引出问题：乡村儿童阅读过程缺少声音，对应C选项，当选；\n其他选项均未提及“声音”,可简单排除。","notes":[{"marker":"⑯","content":"行文结构：二层结构之转折。转折前介绍儿童教育的阅读过程是需要有读书声的；\n转折后引出问题：\n乡村儿童的阅读缺少声音。","matchScore":0.6917,"pairingMode":"content-similarity","order":15}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300228,3,'中心理解题','成功基因的突出特点就是它们的自私性。有些基因为了尽快扩展自己的版图，会采用“曲线”策略，也即在一定条件下表现出有限的利他主义。但这些基因的本质仍然是利己的，它们只想尽快复制自身以挤走其他的基因；不然的话，它们终有一天会淹没在演化的河流中。由于基因的自私性决定了个体的自私性，因此道金斯认为，生物的利他性只不过是“自私”的另一种表象。
这段文字作者表达的观点是：','[{"label":"A","content":"基因在一定的条件下会表现出有限的利他性"},{"label":"B","content":"生物的利他性本质还是出于利己动机"},{"label":"C","content":"基因的利他性本质仍然是利己"},{"label":"D","content":"成功基因的突出特点就是它们的自私性"}]','B','文段分析见批注。
文段先介绍了基因的自私性和利他本质也是利己，再由此得出结论：基因自私性决定了个体自私性且生物的利他也是“自私”的一种表象；前文是背景知识介绍，为最终的观点服务， B选项对应文末观点，当选；
其他选项均出自背景知识部分，是得出观点的原因，非重点内容，均可简单排除。

花生批注：
⑰ 有同学可能疑惑：道金斯的观点就是作者观点吗?
其实这个问题并不重要，文段是在分析介绍后引出道金斯的观点，前文是在分析介绍道金斯得出最终观点的论据，重要性相对次要，无论是谁的观点，都是最终观点更重要。
⑱ 行文结构：后观点结构。
文段首先介绍了成功基因的自私性和表现出的有限利他主义本质也是利己的；
文末给出观点：个体是自私的，利他也是“自私”的另一种表象。
成功基因的突出特点就是它们的自私性。有些基因为了尽快扩展自己的版图，会采用“曲线”策略，也即在一定条件下表现出有限的利他主义。但这些基因的本质仍然是利己的，它们只想尽快复制自身以挤走其他的基因；不然的话，它们终有一天会淹没在演化的河流中(背景知识介绍)。由于基因的自私性决定了个体的自私性，因此道金斯认为，生物的利他性只不过是“自私”的另一种表象①(后观点)。 ⑱
这段文字作者表达的观点是：
A. 基因在一定的条件下会表现出有限的利他性(出处有误)
B. 生物的利他性本质还是出于利己动机
C. 基因的利他性本质仍然是利己(出处有误)','2021年成都市事业单位','进阶','published','{"globalNumber":228,"setNumber":12,"localNumber":8,"sourceLabel":"2021年成都市事业单位52%","accuracy":52,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"成功基因的突出特点就是它们的自私性。有些基因为了尽快扩展自己的版图，会采用“曲线”策略，也即在一定条件下表现出有限的利他主义。但这些基因的本质仍然是利己的，它们只想尽快复制自身以挤走其他的基因；不然的话，它们终有一天会淹没在演化的河流中。由于基因的自私性决定了个体的自私性，因此道金斯认为，生物的利他性只不过是“自私”的另一种表象。\n这段文字作者表达的观点是："}],"optionRich":{"A":[{"text":"基因在一定的条件下会表现出有限的利他性"}],"B":[{"text":"生物的利他性本质还是出于利己动机"}],"C":[{"text":"基因的利他性本质仍然是利己"}],"D":[{"text":"成功基因的突出特点就是它们的自私性"}]},"annotatedStemRich":[{"text":"⑰花生批注：\n有同学可能疑惑：道金斯的观点就是作者观点吗?\n其实这个问题并不重要，文段是在分析介绍后引出道金斯的观点，前文是在分析介绍道金斯得出最终观点的论据，重要性相对次要，无论是谁的观点，都是最终观点更重要。\n⑱花生批注：\n行文结构：后观点结构。\n文段首先介绍了成功基因的自私性和表现出的有限利他主义本质也是利己的；\n文末给出观点：个体是自私的，利他也是“自私”的另一种表象。\n成功基因的突出特点就是它们的自私性。有些基因为了尽快扩展自己的版图，会采用“曲线”策略，也即在一定条件下表现出有限的利他主义。但这些基因的本质仍然是利己的，它们只想尽快复制自身以挤走其他的基因；不然的话，它们终有一天会淹没在演化的河流中(背景知识介绍)。 "},{"text":" 由于基因的自私性决定了个体的自私性，因此道金斯认为，生物的利他性只不过是“自私”的另一种表象","underline":true},{"text":"①(后观点)。 ⑱\n这段文字作者表达的观点是："}],"annotatedOptionRich":{"A":[{"text":"基因在一定的条件下会表现出有限的利他性(出处有误)"}],"B":[{"text":"生物的利他性本质还是出于利己动机"}],"C":[{"text":"基因的利他性本质仍然是利己(出处有误)"}],"D":[{"text":"成功基因的突出特点就是它们的自私性(出处有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍了基因的自私性和利他本质也是利己，再由此得出结论：基因自私性决定了个体自私性且生物的利他也是“自私”的一种表象；前文是背景知识介绍，为最终的观点服务， B选项对应文末观点，当选；\n其他选项均出自背景知识部分，是得出观点的原因，非重点内容，均可简单排除。","notes":[{"marker":"⑰","content":"有同学可能疑惑：道金斯的观点就是作者观点吗?\n其实这个问题并不重要，文段是在分析介绍后引出道金斯的观点，前文是在分析介绍道金斯得出最终观点的论据，重要性相对次要，无论是谁的观点，都是最终观点更重要。","matchScore":1.2493,"pairingMode":"marker-and-content","order":16},{"marker":"⑱","content":"行文结构：后观点结构。\n文段首先介绍了成功基因的自私性和表现出的有限利他主义本质也是利己的；\n文末给出观点：个体是自私的，利他也是“自私”的另一种表象。\n成功基因的突出特点就是它们的自私性。有些基因为了尽快扩展自己的版图，会采用“曲线”策略，也即在一定条件下表现出有限的利他主义。但这些基因的本质仍然是利己的，它们只想尽快复制自身以挤走其他的基因；不然的话，它们终有一天会淹没在演化的河流中(背景知识介绍)。由于基因的自私性决定了个体的自私性，因此道金斯认为，生物的利他性只不过是“自私”的另一种表象①(后观点)。 ⑱\n这段文字作者表达的观点是：\nA. 基因在一定的条件下会表现出有限的利他性(出处有误)\nB. 生物的利他性本质还是出于利己动机\nC. 基因的利他性本质仍然是利己(出处有误)","matchScore":1.5371,"pairingMode":"marker-and-content","order":17}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300229,3,'细节判断类','汉代“爱国”的观念开始大量出现，标志着中华民族爱国主义的确定与形成。虽然这一时期的“爱国如家”观念主要针对官员，但这一命题本身就含有普遍的意义。到了晋代，“忠贞爱国”作为一种政治道德，明确把先秦的忠贞思想与“爱国”结合在一起，显示出“爱国”的观念已深入人心。近代以来，
有人说中国古代只知道忠君，不知道爱国，这是不符合历史事实的。
根据这段文字可以得出：','[{"label":"A","content":"在汉代，“爱国”的观念已经深入人心"},{"label":"B","content":"“爱国”观念是忠贞思想的进一步升华"},{"label":"C","content":"在中国古代，爱国是先于且重于忠君的"},{"label":"D","content":"在汉代和晋代，对官员都有爱国的要求"}]','D','A选项，根据第③句“到了晋代，……,显示出‘爱国’的观念已深入人心”可知，“爱国”观念深入人心是在晋代，而非“汉代”,排除；
B选项，根据第③句“‘忠贞爱国’作为一种政治道德，明确把先秦的忠贞思想与‘爱国’结合在一起”可知，忠贞与爱国是并列关系，未体现后者是前者升华，排除；
C选项，文段并未介绍“忠君”思想的出现时间⑨,无中生有，排除；
D选项，根据第②句的“汉代‘爱国如家’观念主要针对官员”和第③句的“晋代‘忠贞爱国’是一种政治道德②”可知，在汉代和晋代，对官员都有爱国要求，正确，当选。

花生批注：
⑲ 根据常识可知，春秋时期的儒家思想就有忠君的说法，该选项本身有误。
20 政治道德是对官员的要求。','2021年四川省考','进阶','published','{"globalNumber":229,"setNumber":12,"localNumber":9,"sourceLabel":"2021年四川省考54%","accuracy":54,"typeAndPassage":"细节判断类","stemRich":[{"text":"汉代“爱国”的观念开始大量出现，标志着中华民族爱国主义的确定与形成。虽然这一时期的“爱国如家”观念主要针对官员，但这一命题本身就含有普遍的意义。到了晋代，“忠贞爱国”作为一种政治道德，明确把先秦的忠贞思想与“爱国”结合在一起，显示出“爱国”的观念已深入人心。近代以来，\n有人说中国古代只知道忠君，不知道爱国，这是不符合历史事实的。\n根据这段文字可以得出："}],"optionRich":{"A":[{"text":"在汉代，“爱国”的观念已经深入人心"}],"B":[{"text":"“爱国”观念是忠贞思想的进一步升华"}],"C":[{"text":"在中国古代，爱国是先于且重于忠君的"}],"D":[{"text":"在汉代和晋代，对官员都有爱国的要求"}]},"annotatedStemRich":[{"text":"①汉代“爱国”的观念开始大量出现，标志着中华民族爱国主义的确定与形成。②虽然这一时期的“爱国如家”观念主要针对官员，但这一命题本身就含有普遍的意义。③到了晋代，“忠贞爱国”作为一种政治道德，明确把先秦的忠贞思想与“爱国”结合在一起，显示出“爱国”的观念已深入人心。④近代以来，有人说中国古代只知道忠君，不知道爱国，这是不符合历史事实的。\n根据这段文字可以得出："}],"annotatedOptionRich":{"A":[{"text":"在汉代，“爱国”的观念已经深入人心(本身有误)"}],"B":[{"text":"“爱国”观念是忠贞思想的进一步升华(无中生有)"}],"C":[{"text":"在中国古代，爱国是先于且重于忠君的(无中生有)"}],"D":[{"text":"在汉代和晋代，对官员都有爱国的要求"}]},"practicalAnalysis":"A选项，根据第③句“到了晋代，……,显示出‘爱国’的观念已深入人心”可知，“爱国”观念深入人心是在晋代，而非“汉代”,排除；\nB选项，根据第③句“‘忠贞爱国’作为一种政治道德，明确把先秦的忠贞思想与‘爱国’结合在一起”可知，忠贞与爱国是并列关系，未体现后者是前者升华，排除；\nC选项，文段并未介绍“忠君”思想的出现时间⑨,无中生有，排除；\nD选项，根据第②句的“汉代‘爱国如家’观念主要针对官员”和第③句的“晋代‘忠贞爱国’是一种政治道德②”可知，在汉代和晋代，对官员都有爱国要求，正确，当选。","notes":[{"marker":"⑲","content":"根据常识可知，春秋时期的儒家思想就有忠君的说法，该选项本身有误。","matchScore":0.3426,"pairingMode":"content-similarity","order":18},{"marker":"20","content":"政治道德是对官员的要求。","matchScore":0.6432,"pairingMode":"content-similarity","order":19}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300230,3,'中心理解题','近日一位全国人大代表建议无条件为非婚生育孩子上户口引起极大关注。不论是对女性生育权的进一步保障，亦或是对非婚生子女合法权益的保障，在依法治国的语境里，都理应是不断完善的领域。争论之中，问题凸显。一方面，“丧偶式教育”被普遍诟病，加重女性独立抚养孩子意愿，这再次提醒父母双方重拾教育责任；另一方面，未婚生子，“单亲家庭”式的生活环境不利孩子成长，尊重生育权和未婚生子间要在全面考量的基础上寻求平衡。问题千万条，保障第一条。时代在前进，社会在发展，保障好各方权益是法治社会应有之义。
这段话想要表达的观点是：','[{"label":"A","content":"女性的权利在逐渐完善，女性的社会地位逐渐提高"},{"label":"B","content":"保障好非婚生子女权益是法治社会应有之义"},{"label":"C","content":"无论婚生或者非婚生子女都应享受一样的权力"},{"label":"D","content":"我国立法上应确立儿童最大利益原则"}]','B','文段分析见批注。
文段在提出话题并分析背后问题后，文末给出对策：针对非婚生育子女，保障好各方权益是法治社会应有之义，对应B选项，当选；
A选项、D选项均未提及“非婚生育子女”这一话题，排除；C选项对策无中生有，文段未提及“权力”是否一致问题，排除。

花生批注：
② 非婚生育孩子是全文谈论话题。
2 行文结构：后对策结构。
文段开篇引出话题：无条件为非婚生育孩子上户口的提议引发热议；
文段中间对此话题背后的问题加以分析介绍；
文末给出用语义表对策：法治社会应保障非婚生育子女的权益。','2019年天津市事业单位','基础','published','{"globalNumber":230,"setNumber":12,"localNumber":10,"sourceLabel":"2019年天津市事业单位70%","accuracy":70,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"近日一位全国人大代表建议无条件为非婚生育孩子上户口引起极大关注。不论是对女性生育权的进一步保障，亦或是对非婚生子女合法权益的保障，在依法治国的语境里，都理应是不断完善的领域。争论之中，问题凸显。一方面，“丧偶式教育”被普遍诟病，加重女性独立抚养孩子意愿，这再次提醒父母双方重拾教育责任；另一方面，未婚生子，“单亲家庭”式的生活环境不利孩子成长，尊重生育权和未婚生子间要在全面考量的基础上寻求平衡。问题千万条，保障第一条。时代在前进，社会在发展，保障好各方权益是法治社会应有之义。\n这段话想要表达的观点是："}],"optionRich":{"A":[{"text":"女性的权利在逐渐完善，女性的社会地位逐渐提高"}],"B":[{"text":"保障好非婚生子女权益是法治社会应有之义"}],"C":[{"text":"无论婚生或者非婚生子女都应享受一样的权力"}],"D":[{"text":"我国立法上应确立儿童最大利益原则"}]},"annotatedStemRich":[{"text":"近日一位全国人大代表建议无条件为"},{"text":"非婚生育孩子","underline":true},{"text":"②上户口引起极大关注 (引出话题)。不论是对女性生育权的进一步保障，亦或是对非婚生子女合法权益的保障，在依法治国的语境里，都理应是不断完善的领域。争论之中，问题凸显。一方面，“丧偶式教育”被普遍诟病，加重女性独立抚养孩子意愿，这再次提醒父母双方重拾教育责任；另一方面，未婚生子，“单亲家庭”式的生活环境不利孩子成长，尊重生育权和未婚生子间要在全面考量的基础上寻求平衡(分析问题)。问题千万条，保障第一条。时代在前进，社会在发展，保障好各方权益是法治社会应有之义(后对策)。②\n这段话想要表达的观点是："}],"annotatedOptionRich":{"A":[{"text":"女性的权利在逐渐完善，女性的社会地位逐渐提高 (话题不一致)"}],"B":[{"text":"保障好非婚生子女权益是法治社会应有之义"}],"C":[{"text":"无论婚生或者非婚生子女都应享受一样的权力(无中生有)"}],"D":[{"text":"我国立法上应确立儿童最大利益原则(话题不一致)"}]},"practicalAnalysis":"文段分析见批注。\n文段在提出话题并分析背后问题后，文末给出对策：针对非婚生育子女，保障好各方权益是法治社会应有之义，对应B选项，当选；\nA选项、D选项均未提及“非婚生育子女”这一话题，排除；C选项对策无中生有，文段未提及“权力”是否一致问题，排除。","notes":[{"marker":"②","content":"非婚生育孩子是全文谈论话题。","matchScore":0.5271,"pairingMode":"marker-and-content","order":20},{"marker":"2","content":"行文结构：后对策结构。\n文段开篇引出话题：无条件为非婚生育孩子上户口的提议引发热议；\n文段中间对此话题背后的问题加以分析介绍；\n文末给出用语义表对策：法治社会应保障非婚生育子女的权益。","matchScore":0.5385,"pairingMode":"marker-and-content","order":21}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300231,3,'细节判断类','当一个人专注于一项喜欢的事业时，他自然也就沉浸在一种愉悦的情绪中，全力以赴地去做，尽心尽力地去做，心平气和地去做。他在全情投入的过程中，很自然地处在一种宁静致远、物我两忘的至高境界。这种境界可以使人乐以忘忧，可以增强人体的免疫功能。书法家仅仅是易于专注的一个群体，其他能够专注于工作的人士，同样也可获得长寿，如作家、科学家等，他们中都不乏活了八九十岁甚至年过百岁的长寿老人。
下列说法与原文相符的是：','[{"label":"A","content":"书法家的平均寿命高于普通人"},{"label":"B","content":"长寿者多是善于集中注意力的人"},{"label":"C","content":"写作和科研对人的专注度要求更高"},{"label":"D","content":"精神状态在一定程度上影响人的生理功能"}]','D','结合第②句的“在全情投入的过程中，很自然地处在一种宁静致远、物我两忘的至高境界”和第③句的“这种境界可以使人乐以忘忧，可以增强人体的免疫功能”可知，精神状态(宁静致远物我两忘的境界)可以影响人的生理功能(增强人体免疫功能),D选项正确，当选；
A选项、C选项均为区别比较联系类选项，但原文中并未比较书法家和普通人的寿命，也未比较写作科研和其他工作的专注度要求，排除； B选项逻辑错误，原文表述为“专注可获得长寿”,但无法反推出“长寿者多是善于集中注意力之人”,排除。','2021年四川省考','进阶','published','{"globalNumber":231,"setNumber":12,"localNumber":11,"sourceLabel":"2021年四川省考 53%","accuracy":53,"typeAndPassage":"细节判断类","stemRich":[{"text":"当一个人专注于一项喜欢的事业时，他自然也就沉浸在一种愉悦的情绪中，全力以赴地去做，尽心尽力地去做，心平气和地去做。他在全情投入的过程中，很自然地处在一种宁静致远、物我两忘的至高境界。这种境界可以使人乐以忘忧，可以增强人体的免疫功能。书法家仅仅是易于专注的一个群体，其他能够专注于工作的人士，同样也可获得长寿，如作家、科学家等，他们中都不乏活了八九十岁甚至年过百岁的长寿老人。\n下列说法与原文相符的是："}],"optionRich":{"A":[{"text":"书法家的平均寿命高于普通人"}],"B":[{"text":"长寿者多是善于集中注意力的人"}],"C":[{"text":"写作和科研对人的专注度要求更高"}],"D":[{"text":"精神状态在一定程度上影响人的生理功能"}]},"annotatedStemRich":[{"text":"①当一个人专注于一项喜欢的事业时，他自然也就沉浸在一种愉悦的情绪中，全力以赴地去做，尽心尽力地去做，心平气和地去做。②他在全情投入的过程中，很自然地处在一种宁静致远、物我两忘的至高境界。③这种境界可以使人乐以忘忧，可以增强人体的免疫功能。④书法家仅仅是易于专注的一个群体，其他能够专注于工作的人士，同样也可获得长寿，如作家、科学家等，他们中都不乏活了八九十岁甚至年过百岁的长寿老人。\n下列说法与原文相符的是："}],"annotatedOptionRich":{"A":[{"text":"书法家的平均寿命高于普通人(无中生有)"}],"B":[{"text":"长寿者多是善于集中注意力的人(本身有误)"}],"C":[{"text":"写作和科研对人的专注度要求更高(无中生有)"}],"D":[{"text":"精神状态在一定程度上影响人的生理功能","bold":true}]},"practicalAnalysis":"结合第②句的“在全情投入的过程中，很自然地处在一种宁静致远、物我两忘的至高境界”和第③句的“这种境界可以使人乐以忘忧，可以增强人体的免疫功能”可知，精神状态(宁静致远物我两忘的境界)可以影响人的生理功能(增强人体免疫功能),D选项正确，当选；\nA选项、C选项均为区别比较联系类选项，但原文中并未比较书法家和普通人的寿命，也未比较写作科研和其他工作的专注度要求，排除； B选项逻辑错误，原文表述为“专注可获得长寿”,但无法反推出“长寿者多是善于集中注意力之人”,排除。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300232,3,'中心理解题','国际妇女节，好莱坞女星安妮 ·海瑟薇以联合国亲善大使的身份，站上联合国纽约总部讲台发表演说，为女性也为男性发声。她指出，妇女应该待在家里照顾小孩的人设是一种顽固的刻板印象，不仅歧视女性，加重了母亲的负担，也低估了父亲的角色，限制了男性在家庭和社会中的参与度。这种角色定位给孩子的成长带来了巨大的影响，她从亲身体验出发，呼吁全球政府、企业和机构，调整现有的产假制度，给予两性平等的带薪产假和育婴假，“创造一个女性和男性都不会因为想当父母，而受到经济惩罚的世界。”
这段文字意在强调：','[{"label":"A","content":"妇女待在家里照顾小孩的人设是错误的"},{"label":"B","content":"男性在家庭和社会中的参与度应该加强"},{"label":"C","content":"除了女性，男性也要拥有育婴权利"},{"label":"D","content":"男女平等制度的设想"}]','C','文段分析见批注。
文段在引出话题后介绍了海瑟薇指出的问题：妇女应该在家照顾小孩是刻板印象且有不利影响；文末给出海瑟薇提出的建议型对策：呼吁调整现有产假制度，给予男性女性平等的带薪产假和育婴假。
B选项、D选项未提及全文论述话题“育婴”,可直接排除； A选项是问题表述，排除； C选项对应文末对策④,当选。

花生批注：
⑭ 阅读是全文论述话题。
3 行文结构：后对策结构。
文段引出话题后，介绍了海瑟薇指出的问题：妇女应该在家照顾小孩是刻板印象且有不利影响；
文末给出海瑟薇提出的建议型对策：呼吁调整现有产假制度，给予男性女性平等的带薪产假和育婴假。
④ C选项可理解为“女性、男性都应拥有育婴权利”。
另外，有同学可能会有疑惑：育婴不应该是义务吗，为什么是权利?
原文海瑟薇所呼吁的是：调整现有产假制度，给予两性平等的带薪产假和育婴假，创造一个不会因为当父母而受到经济惩罚的世界；
意思是：现在不是男性不想带娃，而是因为没有育婴相应假期，照顾孩子会无工资，而不能育婴，所以其呼吁：给男性同样的假期以带娃。所以有假期育婴就是一种权利。
B. 男性在家庭和社会中的参与度应该加强(无主题词)
C. 除了女性，男性也要拥有育婴权利
D. 男女平等制度的设想(无主题词)
25 农村衰败是全文论述话题。
③ 高空坠物是全文论述话题。','2019年辽宁省考','挑战','published','{"globalNumber":232,"setNumber":12,"localNumber":12,"sourceLabel":"2019年辽宁省考 41%","accuracy":41,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"国际妇女节，好莱坞女星安妮 ·海瑟薇以联合国亲善大使的身份，站上联合国纽约总部讲台发表演说，为女性也为男性发声。她指出，妇女应该待在家里照顾小孩的人设是一种顽固的刻板印象，不仅歧视女性，加重了母亲的负担，也低估了父亲的角色，限制了男性在家庭和社会中的参与度。这种角色定位给孩子的成长带来了巨大的影响，她从亲身体验出发，呼吁全球政府、企业和机构，调整现有的产假制度，给予两性平等的带薪产假和育婴假，“创造一个女性和男性都不会因为想当父母，而受到经济惩罚的世界。”\n这段文字意在强调："}],"optionRich":{"A":[{"text":"妇女待在家里照顾小孩的人设是错误的"}],"B":[{"text":"男性在家庭和社会中的参与度应该加强"}],"C":[{"text":"除了女性，男性也要拥有育婴权利"}],"D":[{"text":"男女平等制度的设想"}]},"annotatedStemRich":[{"text":"国际妇女节，好莱坞女星安妮 ·海瑟薇以联合国亲善大使的身份，站上联合国纽约总部讲台发表演说，为女性也为男性发声(引出话题)。她指出，妇女应该待在家里照顾小孩的人设是一种顽固的刻板印象，不仅歧视女性，加重了母亲的负担，也低估了父亲的角色，限制了男性在家庭和社会中的参与度( 提出问题)。这种角色定位给孩子的成长带来了巨大的影响，她从亲身体验出发，呼吁全球政府、企业和机构，调整现有的产假制度，给予两性平等的带薪产假和育婴假，“创造一个女性和男性都不会因为想当父母，而受到经济惩罚的世界 (后对策)。”②\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"妇女待在家里照顾小孩的人设是错误的(问题表述)\n④花生批注：\nC 选项可理解为“女性、男性都应拥有育婴权利”。\n另外，有同学可能会有疑惑：育婴不应该是义务吗，为什么是权利?\n原文海瑟薇所呼吁的是：调整现有产假制度，给予两性平等的带薪产假和育婴假，创造一个不会因为当父母而受到经济惩罚的世界；\n意思是：现在不是男性不想带娃，而是因为没有育婴相应假期，照顾孩子会无工资，而不能育婴，所以其呼吁：给男性同样的假期以带娃。所以有假期育婴就是一种权利。"}],"B":[{"text":"男性在家庭和社会中的参与度应该加强(无主题词)"}],"C":[{"text":"除了女性，男性也要拥有育婴权利"}],"D":[{"text":"男女平等制度的设想(无主题词)"}]},"practicalAnalysis":"文段分析见批注。\n文段在引出话题后介绍了海瑟薇指出的问题：妇女应该在家照顾小孩是刻板印象且有不利影响；文末给出海瑟薇提出的建议型对策：呼吁调整现有产假制度，给予男性女性平等的带薪产假和育婴假。\nB选项、D选项未提及全文论述话题“育婴”,可直接排除； A选项是问题表述，排除； C选项对应文末对策④,当选。","notes":[{"marker":"⑭","content":"阅读是全文论述话题。","matchScore":0.6486,"pairingMode":"content-similarity","order":13},{"marker":"3","content":"行文结构：后对策结构。\n文段引出话题后，介绍了海瑟薇指出的问题：妇女应该在家照顾小孩是刻板印象且有不利影响；\n文末给出海瑟薇提出的建议型对策：呼吁调整现有产假制度，给予男性女性平等的带薪产假和育婴假。","matchScore":1.1675,"pairingMode":"content-similarity","order":22},{"marker":"④","content":"C选项可理解为“女性、男性都应拥有育婴权利”。\n另外，有同学可能会有疑惑：育婴不应该是义务吗，为什么是权利?\n原文海瑟薇所呼吁的是：调整现有产假制度，给予两性平等的带薪产假和育婴假，创造一个不会因为当父母而受到经济惩罚的世界；\n意思是：现在不是男性不想带娃，而是因为没有育婴相应假期，照顾孩子会无工资，而不能育婴，所以其呼吁：给男性同样的假期以带娃。所以有假期育婴就是一种权利。\nB. 男性在家庭和社会中的参与度应该加强(无主题词)\nC. 除了女性，男性也要拥有育婴权利\nD. 男女平等制度的设想(无主题词)","matchScore":0.5886,"pairingMode":"marker-and-content","order":23},{"marker":"25","content":"农村衰败是全文论述话题。","matchScore":0.5235,"pairingMode":"content-similarity","order":24},{"marker":"③","content":"高空坠物是全文论述话题。","matchScore":0.5235,"pairingMode":"content-similarity","order":36}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300233,3,'中心理解题','农村衰败，故乡消失，这是近些年媒体人提出的议题。学者的观察，时评人的关注，使得正在发生巨变的农村，被搬入舆论平台的焦点地带，农村话题时常与娱乐话题一起，成为社交媒体上的热搜词。但在这个长达十年的农村话题讨论期内，作家是缺席的。虽然有一种观点认为，作家面向社会发言最好的方式是作品，但也有不少人认为，作家不能仅仅通过写作虚构作品承担社会责任，巴尔扎克、雨果、托尔斯泰等国外作家，往往会通过行动以及公开演讲等方式，对公共事务和社会问题发表意见。最适合做本段文字标题的是：','[{"label":"A","content":"农村题材在今天缘何不再吃香"},{"label":"B","content":"现代舆论话题中作家的边缘化"},{"label":"C","content":"作家在农村衰败议题中的失语"},{"label":"D","content":"中外作家应对社会事务的不同"}]','C','文段分析见批注。
文段转折后引出观点：农村衰败这一话题中，作家是缺席的； C选项的“失语”是“缺席”的同义替换，当选；

花生批注：
⑥ 行文结构：前观点结构。
文段开门见山引出话题：农村衰败；
之后通过转折给出观点：在农村话题中作家是缺席的；后文为分析论证观点。
A. 农村题材在今天缘何不再吃香(本身有误)
B. 现代舆论话题中作家的边缘化(无中生有)
C. 作家在农村衰败议题中的失语','2017年河北省事业单位','基础','published','{"globalNumber":233,"setNumber":12,"localNumber":13,"sourceLabel":"2017年河北省事业单位74%","accuracy":74,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"农村衰败，故乡消失，这是近些年媒体人提出的议题。学者的观察，时评人的关注，使得正在发生巨变的农村，被搬入舆论平台的焦点地带，农村话题时常与娱乐话题一起，成为社交媒体上的热搜词。但在这个长达十年的农村话题讨论期内，作家是缺席的。虽然有一种观点认为，作家面向社会发言最好的方式是作品，但也有不少人认为，作家不能仅仅通过写作虚构作品承担社会责任，巴尔扎克、雨果、托尔斯泰等国外作家，往往会通过行动以及公开演讲等方式，对公共事务和社会问题发表意见。最适合做本段文字标题的是："}],"optionRich":{"A":[{"text":"农村题材在今天缘何不再吃香"}],"B":[{"text":"现代舆论话题中作家的边缘化"}],"C":[{"text":"作家在农村衰败议题中的失语"}],"D":[{"text":"中外作家应对社会事务的不同"}]},"annotatedStemRich":[{"text":"农村衰败","underline":true},{"text":"⑥,故乡消失，这是近些年媒体人提出的议题(引出话题)。学者的观察，时评人的关注，使得正在发生巨变的农村，被搬入舆论平台的焦点地带，农村话题时常与娱乐话题一起，成为社交媒体上的热搜词。但在这个长达十年的农村话题讨论期内，作家是缺席的(转折引出观点)。虽然有一种观点认为，作家面向社会发言最好的方式是作品，但也有不少人认为，作家不能仅仅通过写作虚构作品承担社会责任，巴尔扎克、雨果、托尔斯泰等国外作家，往往会通过行动以及公开演讲等方式，对公共事务和社会问题发表意见(分析论证 ) 。\n行文结构：前观点结构。\n最适合做本段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"农村题材在今天缘何不再吃香(本身有误)"}],"B":[{"text":"现代舆论话题中作家的边缘化(无中生有)"}],"C":[{"text":"作家在农村衰败议题中的失语"}],"D":[{"text":"中外作家应对社会事务的不同(区别比较联系类)"}]},"practicalAnalysis":"文段分析见批注。\n文段转折后引出观点：农村衰败这一话题中，作家是缺席的； C选项的“失语”是“缺席”的同义替换，当选；","notes":[{"marker":"⑥","content":"行文结构：前观点结构。\n文段开门见山引出话题：农村衰败；\n之后通过转折给出观点：在农村话题中作家是缺席的；后文为分析论证观点。\nA. 农村题材在今天缘何不再吃香(本身有误)\nB. 现代舆论话题中作家的边缘化(无中生有)\nC. 作家在农村衰败议题中的失语","matchScore":0.4829,"pairingMode":"marker-and-content","order":25}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300234,3,'标题拟定类','科学和艺术如同硬币的两面，共同的基础是人类的创造力，追求的是真理的普遍性。科学传播也是一种创造性活动，它由从业者将科学以各种手段和途径转化成公众易于理解的内容，从而实现传播，激发人们对科学的意识和欣赏，形成对科学客观理性的态度，在这个过程中也需要把科学与艺术结合起来。从学术同行传播的角度来说，很多著名学术期刊都会有艺术性的封面，这些封面就是科学与艺术结合的结果。面向普通公众的科学传播更加需要寓教于乐，其意义无外乎强调信息的传播要嫁接到艺术的手段上来，这样才能触动公众的神经，引起他们的共鸣。
最适合做这段文字标题的是：','[{"label":"A","content":"科学传播，也是一门艺术"},{"label":"B","content":"科学与艺术，硬币的两面"},{"label":"C","content":"嫁接艺术，科学成为大众文化"},{"label":"D","content":"艺术封面，科学艺术的跨界组合"}]','A','文段分析见批注。
文段对策为：科学传播中需要把科学与艺术结合起来，科学传播本身传播的就是科学知识，该对策可理解为：科学传播要有艺术性，对应A选项，当选；
其他选项均无主题词“科学传播”,可简单排除；另外，C选项出自论证部分的“面向普通公众的科学传播”,D选项出自论证部分的“从学术同行传播的角度来说”,二者均出处有误，片面且同质选项，均可简单排除。

花生批注：
9 行文结构：前对策结构。
开篇引出话题：
“科学传播”也是一种创造性活动；
再通过祈使句给出对策：
