INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300243,3,'中心理解题','合乎人类更高层次需求的社会救助，“皆有所养”是不够的，因为人类还有尊严，人的尊严是统领个人权利的核心价值。体面的、合乎人类尊严的基本生活，不仅体现在物质需求，还有精神需要。通俗地说，人不仅要“肚皮”,还要“脸皮”。反窥现实，不论是企业赞助、单位捐赠、政府慰问，都喜欢大张旗鼓地搞捐赠仪式，让领导、捐赠者与受赠人合照、录像，再大肆宣传，不太顾及受赠人的颜面。为了杜绝不合条件者申请救助款，主办单位往往采取将受助人张榜公示、接受举报的办法，让受助者的尊严荡然无存。一些贫困中学生、大学生怕打上贫穷烙印后被人瞧不起，干脆放弃申请救助。
这段文字，作者意在强调：','[{"label":"A","content":"目前社会上一些救助行为没有顾及受助人的尊严"},{"label":"B","content":"不顾及受助人颜面的救助行为可能会起到反作用"},{"label":"C","content":"救助，应该满足受助人的物质需求和精神需要"},{"label":"D","content":"社会救助中，受助人的尊严应该得到更多考虑"}]','D','文段分析见批注。
文段开门见山给出对策：社会救助要考虑被救助人的尊严，后文进行正反两方面论证，直接对应到D选项，当选；
A选项、B选项均为问题表述，并且均出自反面论证，排除； C选项的“精神需要”不明确，可以是文化需求，也可以是娱乐需求，无法对应文段重点“尊严需求”,排除。

花生批注：
⑤ 行文结构：前对策结构。
首句开门见山给出对策：
社会救助要考虑被救助人的尊严；
之后进行正反论证：
正面论证：人不仅要“肚皮”, 还要“脸皮”;
反面论证：现实中的捐赠大张旗鼓，让受助者尊严荡然无存，一些贫困者因此放弃申请救助。
这段文字，作者意在强调：
A. 目前社会上一些救助行为没有顾及受助人的尊严(问题表述)
B. 不顾及受助人颜面的救助行为可能会起到反作用(出处有误)
C. 救助，应该满足受助人的物质需求和精神需要
D. 社会救助中，受助人的尊严应该得到更多考虑','2019年河南选调','进阶','published','{"globalNumber":243,"setNumber":13,"localNumber":3,"sourceLabel":"2019年河南选调 65%","accuracy":65,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"合乎人类更高层次需求的社会救助，“皆有所养”是不够的，因为人类还有尊严，人的尊严是统领个人权利的核心价值。体面的、合乎人类尊严的基本生活，不仅体现在物质需求，还有精神需要。通俗地说，人不仅要“肚皮”,还要“脸皮”。反窥现实，不论是企业赞助、单位捐赠、政府慰问，都喜欢大张旗鼓地搞捐赠仪式，让领导、捐赠者与受赠人合照、录像，再大肆宣传，不太顾及受赠人的颜面。为了杜绝不合条件者申请救助款，主办单位往往采取将受助人张榜公示、接受举报的办法，让受助者的尊严荡然无存。一些贫困中学生、大学生怕打上贫穷烙印后被人瞧不起，干脆放弃申请救助。\n这段文字，作者意在强调："}],"optionRich":{"A":[{"text":"目前社会上一些救助行为没有顾及受助人的尊严"}],"B":[{"text":"不顾及受助人颜面的救助行为可能会起到反作用"}],"C":[{"text":"救助，应该满足受助人的物质需求和精神需要"}],"D":[{"text":"社会救助中，受助人的尊严应该得到更多考虑"}]},"annotatedStemRich":[{"text":"合乎人类更高层次需求的社会救助，“皆有所养”是不够的，因为人类还有尊严，人的尊严是统领个人权利的核心价值(前对策)。体面的、合乎人类尊严的基本生活，不仅体现在物质需求，还有精神需要。通俗地说，人不仅要“肚皮”, 还要“脸皮”(正面论证)。反窥现实，不论是企业赞助、单位捐赠、政府慰问，都喜欢大张旗鼓地搞捐赠仪式，让领导、捐赠者与受赠人合照、录像，再大肆宣传，不太顾及受赠人的颜面。为了杜绝不合条件者申请救助款，主办单位往往采取将受助人张榜公示、接受举报的办法，让受助者的尊严荡然无存。一些贫困中学生、大学生怕打上贫穷烙印后被人瞧不起，干脆放弃申请救助(反面论证)。⑤\n这段文字，作者意在强调："}],"annotatedOptionRich":{"A":[{"text":"目前社会上一些救助行为没有顾及受助人的尊严(问题表述)"}],"B":[{"text":"不顾及受助人颜面的救助行为可能会起到反作用(出处有误)"}],"C":[{"text":"救助，应该满足受助人的物质需求和精神需要"}],"D":[{"text":"社会救助中，","bold":true},{"text":"受助人的尊严应该得到更多考虑"}]},"practicalAnalysis":"文段分析见批注。\n文段开门见山给出对策：社会救助要考虑被救助人的尊严，后文进行正反两方面论证，直接对应到D选项，当选；\nA选项、B选项均为问题表述，并且均出自反面论证，排除； C选项的“精神需要”不明确，可以是文化需求，也可以是娱乐需求，无法对应文段重点“尊严需求”,排除。","notes":[{"marker":"⑤","content":"行文结构：前对策结构。\n首句开门见山给出对策：\n社会救助要考虑被救助人的尊严；\n之后进行正反论证：\n正面论证：人不仅要“肚皮”, 还要“脸皮”;\n反面论证：现实中的捐赠大张旗鼓，让受助者尊严荡然无存，一些贫困者因此放弃申请救助。\n这段文字，作者意在强调：\nA. 目前社会上一些救助行为没有顾及受助人的尊严(问题表述)\nB. 不顾及受助人颜面的救助行为可能会起到反作用(出处有误)\nC. 救助，应该满足受助人的物质需求和精神需要\nD. 社会救助中，受助人的尊严应该得到更多考虑","matchScore":0.7242,"pairingMode":"marker-and-content","order":4}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300244,3,'中心理解题','如果让一个幼童置身于污秽的环境中长大，由于人生观尚未形成，他必将被恶习所沾染。所以古代著名哲学家孟子的母亲得知周围邻居品行不端后，怕年幼的孟子受到影响，搬了三次家。由此可知，若要让孩子健康成长，向好的方面发展，必须远离恶劣的环境，摒弃那些不好的影响。
这段文字主要介绍了：','[{"label":"A","content":"环境对人的成长尤为重要"},{"label":"B","content":"幼童人生观易被恶习所染"},{"label":"C","content":"幼童成长必须远离恶劣环境"},{"label":"D","content":"污秽环境致幼童人生观扭曲"}]','C','文段分析见批注。
文段文末给出对策：孩子健康成长要远离恶劣环境，摒弃不好影响，对应 C选项，当选；
B选项、D选项为问题表述， A选项中性表达且未提及“幼童”,均未体现对策，可简单排除。

花生批注：
⑦ 行文结构：后对策结构。
先提出问题：
幼童在污秽环境长大会沾染恶习；
再举例分析问题；
文末给出对策：
孩子健康成长要远离恶劣环境，摒弃不好影响。
