INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300245,3,'中心理解题','云南是“生物王国”,而且地处大江大河的上游，是江河下游地区的“生态屏障”。曾有一段时间，云南想通过发展旅游等第三产业绕过工业化来发展，最大限度地保护生态环境和民族文化。现在看来，如果工业或者相关产业发展不到位，第三产业就没有服务对象，不仅经济社会发展受到制约，生态环境保护往往也因缺乏社会经济资源，难以持久维持。
作者通过这段文字意在强调：','[{"label":"A","content":"云南经验证明发展工业与保护环境两者并举不悖"},{"label":"B","content":"在云南单纯发展第三产业，保护环境的作用不大"},{"label":"C","content":"在云南兼顾经济发展与环境保护有较多困难"},{"label":"D","content":"在云南发展工业是保护生态环境的必要条件"}]','D','文段分析见批注。
文段先介绍云南之前的想法：通过发展第三产业绕过工业化来发展，最大限度保护生态环境和民族文化，再给出禁止型对策，可翻译为：发展经济、保护生态环境需要发展工业相关产业；根据前文和对策句可知，要解决的重点问题是“保护生态环境”,对策的重点是“发展工业”, 正对应D选项⑩,当选；

花生批注：
⑨ 行文结构：后对策结构。
文段先提出问题：
云南想通过发展第三产业绕过工业化来发展，最大限度的保护生态环境和民族文化；
接着给出禁止型对策：
发展经济、保护生态环境需要发展工业或相关产业。
作者通过这段文字意在强调：
A. 云南经验证明发展工业与保护环境两者并举不悖(表述不明确)
B. 在云南单纯发展第三产业，保护环境的作用不大(问题表述)
C. 在云南兼顾经济发展与环境保护有较多困难(问题表述且问题有误)
D. 在云南发展工业是保护生态环境的必要条件
⑩ D选项是必要条件表对策，可翻译为：云南保护生态环境需要发展工业。
A选项表述不明确，只说发展工业与保护环境两者并举不悖(可同时发展), 未指出二者之间关系(即云南保护生态环境不能脱离工业),排除；
B选项为问题表述，未给出对策；C选项也是问题表述且问题有误，均排除。','2012年国家公务员考试','进阶','published','{"globalNumber":245,"setNumber":13,"localNumber":5,"sourceLabel":"2012年国家公务员考试63%","accuracy":63,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"云南是“生物王国”,而且地处大江大河的上游，是江河下游地区的“生态屏障”。曾有一段时间，云南想通过发展旅游等第三产业绕过工业化来发展，最大限度地保护生态环境和民族文化。现在看来，如果工业或者相关产业发展不到位，第三产业就没有服务对象，不仅经济社会发展受到制约，生态环境保护往往也因缺乏社会经济资源，难以持久维持。\n作者通过这段文字意在强调："}],"optionRich":{"A":[{"text":"云南经验证明发展工业与保护环境两者并举不悖"}],"B":[{"text":"在云南单纯发展第三产业，保护环境的作用不大"}],"C":[{"text":"在云南兼顾经济发展与环境保护有较多困难"}],"D":[{"text":"在云南发展工业是保护生态环境的必要条件"}]},"annotatedStemRich":[{"text":"云 南","underline":true},{"text":"⑧是“生物王国”,而且地处大江大河的上游，是江河下游地区的“生态屏障” (引出话题)。曾有一段时间，云南想通过发展旅游等第三产业绕过工业化来发展，最大限度地保护生态环境和民族文化(提出问题)。现在看来，如果工业或者相关产业发展不到位，第三产业就没有服务对象，不仅经济社会发展受到制约，\n生态环境保护往往也因缺乏社会经济资源，难以持久维持(禁止型对策)。⑨\n作者通过这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"云南经验证明发展工业与保护环境两者并举不悖(表述不明确)"}],"B":[{"text":"在云南单纯发展第三产业，保护环境的作用不大(问题表述)"}],"C":[{"text":"在云南兼顾经济发展与环境保护有较多困难(问题表述且问题有误)"}],"D":[{"text":"在云南发展工业是保护生态环境的必要条件","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍云南之前的想法：通过发展第三产业绕过工业化来发展，最大限度保护生态环境和民族文化，再给出禁止型对策，可翻译为：发展经济、保护生态环境需要发展工业相关产业；根据前文和对策句可知，要解决的重点问题是“保护生态环境”,对策的重点是“发展工业”, 正对应D选项⑩,当选；","notes":[{"marker":"⑨","content":"行文结构：后对策结构。\n文段先提出问题：\n云南想通过发展第三产业绕过工业化来发展，最大限度的保护生态环境和民族文化；\n接着给出禁止型对策：\n发展经济、保护生态环境需要发展工业或相关产业。\n作者通过这段文字意在强调：\nA. 云南经验证明发展工业与保护环境两者并举不悖(表述不明确)\nB. 在云南单纯发展第三产业，保护环境的作用不大(问题表述)\nC. 在云南兼顾经济发展与环境保护有较多困难(问题表述且问题有误)\nD. 在云南发展工业是保护生态环境的必要条件","matchScore":0.6953,"pairingMode":"marker-and-content","order":8},{"marker":"⑩","content":"D选项是必要条件表对策，可翻译为：云南保护生态环境需要发展工业。\nA选项表述不明确，只说发展工业与保护环境两者并举不悖(可同时发展), 未指出二者之间关系(即云南保护生态环境不能脱离工业),排除；\nB选项为问题表述，未给出对策；C选项也是问题表述且问题有误，均排除。","matchScore":0.3462,"pairingMode":"marker-and-content","order":9}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300246,3,'中心理解题','在传统金融体系中，长期以来对“三农”的金融支持服务还不够，农村、农业、农民的金融服务获得感不明显。传统金融体系受“短期绩效”“资本至上”以及“规模偏好”等观念的影响，对规模小抗风险能力差的中小企业、创业者的金融服务相对不足。另外，风险控制与监管、市场之间还存在一定失衡情况。这些难点和痛点，在一定程度上影响了实体经济高质量发展，影响了广大人民群众对美好生活向往的满足。基于此，面对和解决传统金融体系无法解决的难点、痛点和服务障碍正是新金融崛起的出发点。
这段文字主要介绍了：','[{"label":"A","content":"市场对金融服务的新需求"},{"label":"B","content":"建设新金融的现实背景"},{"label":"C","content":"农村金融体系面临的问题"},{"label":"D","content":"传统金融体系的新发展"}]','B','文段分析见批注。
文段提出并分析传统金融的问题后，给出观点：新金融崛起的出发点是面对和解决传统金融的难点、痛点和服务障碍，即新金融崛起要面对的问题，B选项的“现实背景”是“要面对问题”的同义替换⑫,B选项当选；
其他选项均未提及“新金融”,可简单排除。

花生批注：
⑪ 行文结构：后观点结构。
文段开篇指出问题：传统金融体系对“三农”的支持服务不够；
接着分析这一问题；
文末给出观点：
新金融崛起的出发点是面对和解决传统金融的难点、痛点和服务障碍。
总观点可理解为概括新金融要面对的问题。
这段文字主要介绍了：
A. 市场对金融服务的新需求(未提及新金融)
B. 建设新金融的现实背景
C. 农村金融体系面临的问题(未提及新金融)
D. 传统金融体系的新发展(未提及新金融)
⑫ 例如：新领导班子要面对和解决原来无法解决的难点、痛点；
即新领导班子要面对的问题；
即新领导班子工作的现实背景。','2020年北京市考','进阶','published','{"globalNumber":246,"setNumber":13,"localNumber":6,"sourceLabel":"2020年北京市考 66%","accuracy":66,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"在传统金融体系中，长期以来对“三农”的金融支持服务还不够，农村、农业、农民的金融服务获得感不明显。传统金融体系受“短期绩效”“资本至上”以及“规模偏好”等观念的影响，对规模小抗风险能力差的中小企业、创业者的金融服务相对不足。另外，风险控制与监管、市场之间还存在一定失衡情况。这些难点和痛点，在一定程度上影响了实体经济高质量发展，影响了广大人民群众对美好生活向往的满足。基于此，面对和解决传统金融体系无法解决的难点、痛点和服务障碍正是新金融崛起的出发点。\n这段文字主要介绍了："}],"optionRich":{"A":[{"text":"市场对金融服务的新需求"}],"B":[{"text":"建设新金融的现实背景"}],"C":[{"text":"农村金融体系面临的问题"}],"D":[{"text":"传统金融体系的新发展"}]},"annotatedStemRich":[{"text":"在传统金融体系中，长期以来对“三农”的金融支持服务还不够，农村、农业、农民的金融服务获得感不明显(提出问题)。传统金融体系受“短期绩效”“资本至上”以及“规模偏好”等观念的影响，对规模小抗风险能力差的中小企业、创业者的金融服务相对不足。另外，风险控制与监管、市场之间还存在一定失衡情况。这些难点和痛点，在一定程度上影响了实体经济高质量发展，影响了广大人民群众对美好生活向往的满足(分析问题)。基于此，面对和解决传统金融体系无法解决的难点、痛点和服务障碍正是新金融崛起的出发点(后观点)。①\n这段文字主要介绍了："}],"annotatedOptionRich":{"A":[{"text":"市场对金融服务的新需求(未提及新金融)"}],"B":[{"text":"建设新金融的现实背景","bold":true}],"C":[{"text":"农村金融体系面临的问题(未提及新金融)"}],"D":[{"text":"传统金融体系的新发展(未提及新金融)"}]},"practicalAnalysis":"文段分析见批注。\n文段提出并分析传统金融的问题后，给出观点：新金融崛起的出发点是面对和解决传统金融的难点、痛点和服务障碍，即新金融崛起要面对的问题，B选项的“现实背景”是“要面对问题”的同义替换⑫,B选项当选；\n其他选项均未提及“新金融”,可简单排除。","notes":[{"marker":"⑪","content":"行文结构：后观点结构。\n文段开篇指出问题：传统金融体系对“三农”的支持服务不够；\n接着分析这一问题；\n文末给出观点：\n新金融崛起的出发点是面对和解决传统金融的难点、痛点和服务障碍。\n总观点可理解为概括新金融要面对的问题。\n这段文字主要介绍了：\nA. 市场对金融服务的新需求(未提及新金融)\nB. 建设新金融的现实背景\nC. 农村金融体系面临的问题(未提及新金融)\nD. 传统金融体系的新发展(未提及新金融)","matchScore":0.7426,"pairingMode":"content-similarity","order":10},{"marker":"⑫","content":"例如：新领导班子要面对和解决原来无法解决的难点、痛点；\n即新领导班子要面对的问题；\n即新领导班子工作的现实背景。","matchScore":0.6619,"pairingMode":"marker-and-content","order":11}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300247,3,'语句填入类','城市不仅是一个国家或者地区的政治、经济、文化、科技和教育中心，而且已经成为经济增长的强大引擎。美国的纽约、芝加哥和洛杉矶三个城市群，日本的东京、阪神和名古屋三大城市群，以及中国的长三角、珠三角和环渤海三大城市群等对本国经济的贡献率都在一半以上。
承接上述文字最恰当的一句是：','[{"label":"A","content":"可以说，一个国家的经济发展主要依赖于城市群的经济发展"},{"label":"B","content":"可以说，任何国家或者地区都应该重点关注大城市的发展"},{"label":"C","content":"可以说，城市的兴衰关乎国家的兴衰，城市的发展关乎国家的发展"},{"label":"D","content":"可以说，城市的发展离不开国家的支持，国家的发展离不开城市的支撑"}]','A','文段分析见批注。
开篇总起：城市已经成为经济增长的强大引擎；后文进行举例论证：美国、日本、中国城市群对本国经济贡献率都在一半以上；文末应总结“城市群对于经济增长”的重要作用，与首句呼应，构成总分总结构。
只有A选项提及城市群与经济，当选。

花生批注：
⑬ 填入文末后文段为总分总结构。
开篇总起：城市是经济增长的强大引擎；
中间举例论证：
美国、日本、中国城市群对本国经济贡献率都在一半以上；
文末总结：国家经济发展依赖于城市群的经济发展。','2014年广东省考','进阶','published','{"globalNumber":247,"setNumber":13,"localNumber":7,"sourceLabel":"2014年广东省考60%","accuracy":60,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"城市不仅是一个国家或者地区的政治、经济、文化、科技和教育中心，而且已经成为经济增长的强大引擎。美国的纽约、芝加哥和洛杉矶三个城市群，日本的东京、阪神和名古屋三大城市群，以及中国的长三角、珠三角和环渤海三大城市群等对本国经济的贡献率都在一半以上。\n承接上述文字最恰当的一句是："}],"optionRich":{"A":[{"text":"可以说，一个国家的经济发展主要依赖于城市群的经济发展"}],"B":[{"text":"可以说，任何国家或者地区都应该重点关注大城市的发展"}],"C":[{"text":"可以说，城市的兴衰关乎国家的兴衰，城市的发展关乎国家的发展"}],"D":[{"text":"可以说，城市的发展离不开国家的支持，国家的发展离不开城市的支撑"}]},"annotatedStemRich":[{"text":"城市不仅是一个国家或者地区的政治、经济、文化、科技和教育中心，而且已经成为经济增长的强大引擎。美国的纽约、芝加哥和洛杉矶三个城市群，日本的东京、阪神和名古屋三大城市群，以及中国的长三角、珠三角和环渤海三大城市群等对本国经济的贡献率都在一半以上。\n承接上述文字最恰当的一句是："}],"annotatedOptionRich":{"A":[{"text":"可以说，一个国家的经济发展主要依赖于城市群的经济发展⑨"}],"B":[{"text":"可以说，任何国家或者地区都应该重点关注大城市的发展(绝对化)"}],"C":[{"text":"可以说，城市的兴衰关乎国家的兴衰，城市的发展关乎国家的发展"}],"D":[{"text":"可以说，城市的发展离不开国家的支持，国家的发展离不开城市的支撑"}]},"practicalAnalysis":"文段分析见批注。\n开篇总起：城市已经成为经济增长的强大引擎；后文进行举例论证：美国、日本、中国城市群对本国经济贡献率都在一半以上；文末应总结“城市群对于经济增长”的重要作用，与首句呼应，构成总分总结构。\n只有A选项提及城市群与经济，当选。","notes":[{"marker":"⑬","content":"填入文末后文段为总分总结构。\n开篇总起：城市是经济增长的强大引擎；\n中间举例论证：\n美国、日本、中国城市群对本国经济贡献率都在一半以上；\n文末总结：国家经济发展依赖于城市群的经济发展。","matchScore":0.9139,"pairingMode":"content-similarity","order":12}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300248,3,'中心理解题','有事好商量，众人的事情由众人商量，是人民民主的真谛。协商民主是实现党的领导的重要方式，是我国社会主义民主政治的特有形式和独特优势。要推动协商民主广泛、多层、制度化发展，统筹推进政党协商、人大协商、政府协商、政协协商、人民团体协商、基层协商以及社会组织协商。加强协商民主制度建设，形成完整的制度程序和参与实践，保证人民在日常政治生活中有广泛持续深入参与的权利。
这段话反映出：','[{"label":"A","content":"要充分发挥社会主义协商民主重要作用"},{"label":"B","content":"社会主义协商民主是中国特有的制度形式"},{"label":"C","content":"社会主义协商民主具有西方选举民主没有的制度优势"},{"label":"D","content":"社会主义协商民主是保障人民群众当家作主的制度"}]','A','文段分析见批注。
文段在引出并介绍协商民主后，直接给出多个对策：①要推动协商民主广泛、多层、制度化发展；②统筹推进政党协商、人大协商……等；③加强协商民主制度建设。对策均包含“协商民主”,A选项为对策表述且包含“协商民主”, 可翻译为：要加强推进社会主义协商民主建设⑤,当选；
其他选项均为非对策表述，根据“原文有对策要选对策”的原则，均可简单排除。

花生批注：
⑭ 行文结构：后对策结构。
开门见山先引出话题“协商民主”并介绍；
再直接给出多个对策：要推动协商民主发展；统筹推进各种协商；加强协商民主制度建设。
⑮ 例如：考前复习要充分发挥“真题套卷”的重要作用；即考前复习要刷套卷。
这段话反映出：
A. 要充分发挥社会主义协商民主重要作用
B. 社会主义协商民主是中国特有的制度形式(非对策选项)
C. 社会主义协商民主具有西方选举民主没有的制度优势(区别比较联系类)','2021年山西省大学毕业生到乡镇','进阶','published','{"globalNumber":248,"setNumber":13,"localNumber":8,"sourceLabel":"2021年山西省大学毕业生到乡镇 58%","accuracy":58,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"有事好商量，众人的事情由众人商量，是人民民主的真谛。协商民主是实现党的领导的重要方式，是我国社会主义民主政治的特有形式和独特优势。要推动协商民主广泛、多层、制度化发展，统筹推进政党协商、人大协商、政府协商、政协协商、人民团体协商、基层协商以及社会组织协商。加强协商民主制度建设，形成完整的制度程序和参与实践，保证人民在日常政治生活中有广泛持续深入参与的权利。\n这段话反映出："}],"optionRich":{"A":[{"text":"要充分发挥社会主义协商民主重要作用"}],"B":[{"text":"社会主义协商民主是中国特有的制度形式"}],"C":[{"text":"社会主义协商民主具有西方选举民主没有的制度优势"}],"D":[{"text":"社会主义协商民主是保障人民群众当家作主的制度"}]},"annotatedStemRich":[{"text":"有事好商量，众人的事情由众人商量，是人民民主的真谛。协商民主是实现党的领导的重要方式，是我国社会主义民主政治的特有形式和独特优势( 引出话题)。要推动协商民主广泛、多层、制度化发展，统筹推进政党协商、人大协商、政府协商、政协协商、人民团体协商、基层协商以及社会组织协商。加强协商民主制度建设，形成完整的制度程序和参与实践，保证人民在日常政治生活中有广泛持续深入参与的权利(后对策)。④\n⑭花生批注：\n行文结构：后对策结构。\n开门见山先引出话题“协商民主”并介绍；\n再直接给出多个对策：要推动协商民主发展；统筹推进各种协商；加强协商民主制度建设。\n⑮花生批注：\n例如：考前复习要充分发挥“真题套卷”的重要作用；即考前复习要刷套卷。\n这段话反映出："}],"annotatedOptionRich":{"A":[{"text":"要充分发挥社会主义协商民主重要作用"}],"B":[{"text":"社会主义协商民主是中国特有的制度形式(非对策选项)"}],"C":[{"text":"社会主义协商民主具有西方选举民主没有的制度优势(区别比较联系类)"}],"D":[{"text":"社会主义协商民主是保障人民群众当家作主的制度(非对策选项)"}]},"practicalAnalysis":"文段分析见批注。\n文段在引出并介绍协商民主后，直接给出多个对策：①要推动协商民主广泛、多层、制度化发展；②统筹推进政党协商、人大协商……等；③加强协商民主制度建设。对策均包含“协商民主”,A选项为对策表述且包含“协商民主”, 可翻译为：要加强推进社会主义协商民主建设⑤,当选；\n其他选项均为非对策表述，根据“原文有对策要选对策”的原则，均可简单排除。","notes":[{"marker":"⑭","content":"行文结构：后对策结构。\n开门见山先引出话题“协商民主”并介绍；\n再直接给出多个对策：要推动协商民主发展；统筹推进各种协商；加强协商民主制度建设。","matchScore":1.1863,"pairingMode":"marker-and-content","order":13},{"marker":"⑮","content":"例如：考前复习要充分发挥“真题套卷”的重要作用；即考前复习要刷套卷。\n这段话反映出：\nA. 要充分发挥社会主义协商民主重要作用\nB. 社会主义协商民主是中国特有的制度形式(非对策选项)\nC. 社会主义协商民主具有西方选举民主没有的制度优势(区别比较联系类)","matchScore":0.7753,"pairingMode":"marker-and-content","order":14}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300249,3,'中心理解题','由于历史和现实众多因素的作用，每种语言发挥的功能并不相同，因此可以根据功能的强弱将语言分为不同类别，呈现特定的世界语言格局。语言的功能主要可分为工具功能和文化功能两大范畴，根据这两大功能的若干外显特征，形成具有可操作性的功能分类参项体系。通过功能分类，可以加深对语言功能及其特征的认识，促进世界范围内各种语言的相关数据的收集、分析及利用，同时在语言生活的实践上，可以为语言教育、语言保护和中华语言的国际传播提供参考。
这段文字主要介绍：','[{"label":"A","content":"语言功能分类对语言传播的影响"},{"label":"B","content":"语言功能强弱决定世界语言格局"},{"label":"C","content":"历史和现实等因素影响语言功能"},{"label":"D","content":"语言功能分类的理论和实践意义"}]','D','文段分析见批注。
本题可略读后从选项入手分析，D选项为典型的“A 且 B”类选项，可反推文段；文段先介绍语言可根据功能进行分类，再介绍功能分类的意义，为二层结构“A 且 B”, 正对应D选项，当选；
A选项只对应第③种意义中的一部分，属于“片面中的片面”;B选项的“决定”为绝对化表述且原文说法为“呈现”; C选项出自首句“因此”之前，出处有误，均可简单排除。

花生批注：
⑯ 功能分类的意义为：
①可以加深对语言功能的认识；
②促进语言相关数据收集、分析及利用；
③可以为语言教育、保护、传播提供参考。
①由于历史和现实众多因素的作用，每种语言发挥的功能并不相同，因此可以根据功能的强弱将语言分为不同类别，呈现特定的世界语言格局。②语言的功能主要可分为工具功能和文化功能两大范畴，根据这两大功能的若干外显特征，形成具有可操作性的功能分类参项体系(语言功能分类的理论)。通过功能分类，可以加深对语言功能及其特征的认识，促进世界范围内各种语言的相关数据的收集、分析及利用，同时在语言生活的实践上，可以为语言教育、语言保护和中华语言的国际传播提供参考⑥(语言功能分类的实践意义)。
这段文字主要介绍：
A. 语言功能分类对语言传播的影响 ( 片面 )
B. 语言功能强弱决定世界语言格局(绝对化)
C. 历史和现实等因素影响语言功能(出处有误)
D. 语言功能分类的理论和实践意义','2019年事业单位联考','基础','published','{"globalNumber":249,"setNumber":13,"localNumber":9,"sourceLabel":"2019年事业单位联考 79%","accuracy":79,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"由于历史和现实众多因素的作用，每种语言发挥的功能并不相同，因此可以根据功能的强弱将语言分为不同类别，呈现特定的世界语言格局。语言的功能主要可分为工具功能和文化功能两大范畴，根据这两大功能的若干外显特征，形成具有可操作性的功能分类参项体系。通过功能分类，可以加深对语言功能及其特征的认识，促进世界范围内各种语言的相关数据的收集、分析及利用，同时在语言生活的实践上，可以为语言教育、语言保护和中华语言的国际传播提供参考。\n这段文字主要介绍："}],"optionRich":{"A":[{"text":"语言功能分类对语言传播的影响"}],"B":[{"text":"语言功能强弱决定世界语言格局"}],"C":[{"text":"历史和现实等因素影响语言功能"}],"D":[{"text":"语言功能分类的理论和实践意义"}]},"annotatedStemRich":[{"text":"⑯花生批注：\n功能分类的意义为：\n①可以加深对语言功能的认识；\n②促进语言相关数据收集、分析及利用；\n③可以为语言教育、保护、传播提供参考。\n①由于历史和现实众多因素的作用，每种语言发挥的功能并不相同，因此可以根据功能的强弱将语言分为不同类别，呈现特定的世界语言格局。②语言的功能主要可分为工具功能和文化功能两大范畴，根据这两大功能的若干外显特征，形成具有可操作性的功能分类参项体系(语言功能分类的理论)。通过功能分类，"},{"text":"可以加深对语言功能及其特征的认识，促进世界范围内各种语言的相关数据的收集、分析及利用，同时在语言生活的实践上，可以为语言教育、 ","underline":true},{"text":" "},{"text":"语言保护和中华语言的国际传播提供参考","underline":true},{"text":"⑥(语言功能分类的实践意义)。\n这段文字主要介绍："}],"annotatedOptionRich":{"A":[{"text":"语言功能分类对语言传播的影响 ( 片面 )"}],"B":[{"text":"语言功能强弱决定世界语言格局(绝对化)"}],"C":[{"text":"历史和现实等因素影响语言功能(出处有误)"}],"D":[{"text":"语言功能分类的理论和实践意义"}]},"practicalAnalysis":"文段分析见批注。\n本题可略读后从选项入手分析，D选项为典型的“A 且 B”类选项，可反推文段；文段先介绍语言可根据功能进行分类，再介绍功能分类的意义，为二层结构“A 且 B”, 正对应D选项，当选；\nA选项只对应第③种意义中的一部分，属于“片面中的片面”;B选项的“决定”为绝对化表述且原文说法为“呈现”; C选项出自首句“因此”之前，出处有误，均可简单排除。","notes":[{"marker":"⑯","content":"功能分类的意义为：\n①可以加深对语言功能的认识；\n②促进语言相关数据收集、分析及利用；\n③可以为语言教育、保护、传播提供参考。\n①由于历史和现实众多因素的作用，每种语言发挥的功能并不相同，因此可以根据功能的强弱将语言分为不同类别，呈现特定的世界语言格局。②语言的功能主要可分为工具功能和文化功能两大范畴，根据这两大功能的若干外显特征，形成具有可操作性的功能分类参项体系(语言功能分类的理论)。通过功能分类，可以加深对语言功能及其特征的认识，促进世界范围内各种语言的相关数据的收集、分析及利用，同时在语言生活的实践上，可以为语言教育、语言保护和中华语言的国际传播提供参考⑥(语言功能分类的实践意义)。\n这段文字主要介绍：\nA. 语言功能分类对语言传播的影响 ( 片面 )\nB. 语言功能强弱决定世界语言格局(绝对化)\nC. 历史和现实等因素影响语言功能(出处有误)\nD. 语言功能分类的理论和实践意义","matchScore":1.5498,"pairingMode":"marker-and-content","order":15}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300250,3,'标题拟定类','当前，我国科技事业实现了历史性、整体性、格局性重大变化，重大创新成果竞相涌现，一些前沿方向开始进入并行、领跑阶段。但也应看到，我国科技领域仍然存在一些亟待解决的问题，关键核心技术受制于人的局面没有得到根本性改变。现在，我们迎来了世界新一轮科技革命和产业变革同我国转变发展方式的历史性交汇期，科技创新角逐空前激烈，只有努力实现关键核心技术自主可控，才能抓住千载难逢的历史机遇，有力支撑世界科技强国建设，真正发挥创新引领发展的第一动力作用。最适合做这段文字标题的是：','[{"label":"A","content":"努力拼搏，获取关键核心技术"},{"label":"B","content":"把关键核心技术掌握在自己手中"},{"label":"C","content":"重视激励原始创新和核心技术研发"},{"label":"D","content":"发挥创新引领作用，掌握关键核心技术"}]','B','文段分析见批注。
文段文末通过逻辑关联词表对策：想要抓住历史机遇、有力支撑科技强国建设、发挥创新引领作用，要实现关键核心技术自主可控；其中“实现关键核心技术的自主可控”是对策核心，“抓住历史机遇、有力支撑科技强国建设、发挥创新引领作用”是要达到的目标或对策带来的积极影响；B选项的“掌握在自己手中”是“自主可控”的同义替换，B选项对策与原文一致，当选；
A选项可翻译为：获取关键核心技术要努力拼搏，对策有误； C选项无中生有，对策有误，均排除；
D选项的“发挥创新引领作用”和“掌握关键核心技术”是并列关系，即“创新”与“掌握”同等重要，但原文中的对策重点为“实现关键核心技术自主可控”, “发挥创新引领作用”是对策能带来的积极影响之一，逻辑有误，排除。

花生批注：
⑪ 行文结构：后对策结构。
开门见山引出“我国科技事业实现了重大进步”这一话题；
之后转折提出问题：
我国科技领域仍然存在问题，关键核心技术依然受制于人；
最后逻辑关联词表对策：
只有努力实现关键核心技术自主可控，才能抓住千载难逢的历史机遇，有力支撑世界科技强国建设，真正发挥创新引领发展的第一动力作用。
最适合做这段文字标题的是：
A. 努力拼搏，获取关键核心技术(对策有误)
B. 把关键核心技术掌握在自己手中
C. 重视激励原始创新和核心技术研发(对策有误)','2019年联考','挑战','published','{"globalNumber":250,"setNumber":13,"localNumber":10,"sourceLabel":"2019年联考37%","accuracy":37,"typeAndPassage":"标题拟定类+说理类文章","stemRich":[{"text":"当前，我国科技事业实现了历史性、整体性、格局性重大变化，重大创新成果竞相涌现，一些前沿方向开始进入并行、领跑阶段。但也应看到，我国科技领域仍然存在一些亟待解决的问题，关键核心技术受制于人的局面没有得到根本性改变。现在，我们迎来了世界新一轮科技革命和产业变革同我国转变发展方式的历史性交汇期，科技创新角逐空前激烈，只有努力实现关键核心技术自主可控，才能抓住千载难逢的历史机遇，有力支撑世界科技强国建设，真正发挥创新引领发展的第一动力作用。最适合做这段文字标题的是："}],"optionRich":{"A":[{"text":"努力拼搏，获取关键核心技术"}],"B":[{"text":"把关键核心技术掌握在自己手中"}],"C":[{"text":"重视激励原始创新和核心技术研发"}],"D":[{"text":"发挥创新引领作用，掌握关键核心技术"}]},"annotatedStemRich":[{"text":"当前，我国科技事业实现了历史性、整体性、格局性重大变化，重大创新成果竞相涌现，一些前沿方向开始进入并行、领跑阶段(引出话题)。但也应看到，我国科技领域仍然存在一些亟待解决的问题，关键核心技术受制于人的局面没有得到根本性改变(转折提出问题)。现在，我们迎来了世界新一轮科技革命和产业变革同我国转变发展方式的历史性交汇期，科技创新角逐空前激烈，只有努力实现关键核心技术自主可控，才能抓住千载难逢的历史机遇，有力支撑世界科技强国建设，真正发挥创新引领发展的第一动力作用(后对策)。①\n最适合做这段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"努力拼搏，获取关键核心技术(对策有误)"}],"B":[{"text":"把关键核心技术掌握在自己手中"}],"C":[{"text":"重视激励原始创新和核心技术研发(对策有误)"}],"D":[{"text":"发挥创新引领作用，掌握关键核心技术(对策有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段文末通过逻辑关联词表对策：想要抓住历史机遇、有力支撑科技强国建设、发挥创新引领作用，要实现关键核心技术自主可控；其中“实现关键核心技术的自主可控”是对策核心，“抓住历史机遇、有力支撑科技强国建设、发挥创新引领作用”是要达到的目标或对策带来的积极影响；B选项的“掌握在自己手中”是“自主可控”的同义替换，B选项对策与原文一致，当选；\nA选项可翻译为：获取关键核心技术要努力拼搏，对策有误； C选项无中生有，对策有误，均排除；\nD选项的“发挥创新引领作用”和“掌握关键核心技术”是并列关系，即“创新”与“掌握”同等重要，但原文中的对策重点为“实现关键核心技术自主可控”, “发挥创新引领作用”是对策能带来的积极影响之一，逻辑有误，排除。","notes":[{"marker":"⑪","content":"行文结构：后对策结构。\n开门见山引出“我国科技事业实现了重大进步”这一话题；\n之后转折提出问题：\n我国科技领域仍然存在问题，关键核心技术依然受制于人；\n最后逻辑关联词表对策：\n只有努力实现关键核心技术自主可控，才能抓住千载难逢的历史机遇，有力支撑世界科技强国建设，真正发挥创新引领发展的第一动力作用。\n最适合做这段文字标题的是：\nA. 努力拼搏，获取关键核心技术(对策有误)\nB. 把关键核心技术掌握在自己手中\nC. 重视激励原始创新和核心技术研发(对策有误)","matchScore":0.9427,"pairingMode":"content-similarity","order":16}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300251,3,'下文推断类','研究人员长期以来都设想干细胞能够用来修复或替换受损组织，该研究领域被冠名为再生医学。“多能的”胚胎干细胞被再生医学家们寄予厚望，所谓“多能”就意味着这些干细胞可以分化出多种其他类型的细胞。现在的技术已经可以在非胚胎细胞中诱导细胞的多能性，这样就可以绕过直接使用胚胎细胞时所引发的伦理争议。
作者接下来最不可能讲述的是：','[{"label":"A","content":"细胞多能性研究的意义"},{"label":"B","content":"再生医学的得名由来"},{"label":"C","content":"细胞多能性研究的新成果"},{"label":"D","content":"再生医学领域的伦理争议"}]','B','文段由“再生医学得名由来”引出话题，接着介绍“多能的”胚胎干细胞在研究中的重要地位，并在文段末尾提出技术研发的新内容；
B选项“再生医学的得名由来”为首句介绍过的内容，不会重复介绍，选非题，当选；
根据尾句，下文内容应与“细胞多能性”、“伦理争议”相关，其他选项后文都可能进行阐述，均可简单排除。

