INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300253,3,'中心理解题','任何事物的发展都是一个不断完善的过程，国家的发展也是如此。在发展的道路上不存在没有问题的国家。如果仅仅因为问题没有爆发，就不采取任何有针对性的防范措施，那么矛盾就会越积越多，问题的“能量储备”也会越来越大，一旦爆发就是灾难性的。
这段文字意在强调：','[{"label":"A","content":"没有一个国家的发展能避免出现问题"},{"label":"B","content":"采取有效的防范措施以防止问题的爆发"},{"label":"C","content":"国家发展是不断发现和解决问题的过程"},{"label":"D","content":"加强对群众心理情绪的积极疏导和化解"}]','B','文段分析见批注。
文段在提出问题后，直接通过逻辑关联词“如果…就”给出对策②:要在问题没有爆发前就采取有针对性的防范措施，对应B选项当选；
A选项、C选项均未体现对策，原文有对策要选对策，D选项的“群众心理情绪”无中生有，均可简单排除。

花生批注：
②0 行文结构：后对策结构。
开篇引出话题：
国家的发展道路一定会产生问题；
再通过逻辑关联词给出对策：
要在问题没有爆发前就采取有针对性的防范措施。
② 对策句可简化成：如果不采取任何有针对性的防范措施，那么矛盾就会越积越多，一旦爆发就是灾难性的；
即：避免矛盾的爆发要采取针对性防范措施。','2021年江苏省事业单位','进阶','published','{"globalNumber":253,"setNumber":13,"localNumber":13,"sourceLabel":"2021年江苏省事业单位63%","accuracy":63,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"任何事物的发展都是一个不断完善的过程，国家的发展也是如此。在发展的道路上不存在没有问题的国家。如果仅仅因为问题没有爆发，就不采取任何有针对性的防范措施，那么矛盾就会越积越多，问题的“能量储备”也会越来越大，一旦爆发就是灾难性的。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"没有一个国家的发展能避免出现问题"}],"B":[{"text":"采取有效的防范措施以防止问题的爆发"}],"C":[{"text":"国家发展是不断发现和解决问题的过程"}],"D":[{"text":"加强对群众心理情绪的积极疏导和化解"}]},"annotatedStemRich":[{"text":"任何事物的发展都是一个不断完善的过程，国家的发展也是如此。在发展的道路上不存在没有问题的国家(提出问题)。如果仅仅因为问题没有爆发，\n就不采取任何有针对性的防范措施，那么矛盾就会越积越多，问题的“能量储备”\n也会越来越大，一旦爆发就是灾难性的(后对策)。② 这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"没有一个国家的发展能避免出现问题 (问题类表述)"}],"B":[{"text":"采取有效的防范措施以防止问题的爆发"}],"C":[{"text":"国家发展是不断发现和解决问题的过程(中性表达)"}],"D":[{"text":"加强对群众心理情绪的积极疏导和化解(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段在提出问题后，直接通过逻辑关联词“如果…就”给出对策②:要在问题没有爆发前就采取有针对性的防范措施，对应B选项当选；\nA选项、C选项均未体现对策，原文有对策要选对策，D选项的“群众心理情绪”无中生有，均可简单排除。","notes":[{"marker":"②0","content":"行文结构：后对策结构。\n开篇引出话题：\n国家的发展道路一定会产生问题；\n再通过逻辑关联词给出对策：\n要在问题没有爆发前就采取有针对性的防范措施。","matchScore":0.8242,"pairingMode":"content-similarity","order":19},{"marker":"②","content":"对策句可简化成：如果不采取任何有针对性的防范措施，那么矛盾就会越积越多，一旦爆发就是灾难性的；\n即：避免矛盾的爆发要采取针对性防范措施。","matchScore":0.9005,"pairingMode":"marker-and-content","order":20}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300254,3,'中心理解题','眼睛通过调节晶状体的弯曲程度来改变晶状体焦距获得倒立的、缩小的实像。分布在视网膜上的视神经细胞受到光的刺激，把这个信号传输给大脑，人就可以看到这个物体了，这就是眼睛成像的基本原理。眼睛所能看到的最远的点叫远点，正视眼所能看到的远点在极远处；眼睛所能看到的最近的点叫近点，正常眼睛的近点在距离眼睛约10厘米处。长时间用眼可发生眼疲劳现象，眼疲劳的症状表现为：眼睛发胀、头疼、眼花，眼睛酸涩、眼睛发干等。
这段话主要讲述：','[{"label":"A","content":"眼睛的器官部位"},{"label":"B","content":"长时间用眼导致眼疲劳"},{"label":"C","content":"眼睛的成像原理"},{"label":"D","content":"眼疲劳的症状表现"}]','B','文段分析见批注。
文段先介绍了眼睛成像的基本原理和远点、近点相关知识；再指出长时间用眼可发生眼疲劳，并且介绍眼疲劳的症状。
相较而言，背景知识作用相对次要. “长时间用眼可发生眼疲劳”是作者更想表达的内容③, B选项当选；
A选项无中生有，C选项为背景知识，D选项为补充说明，均不如B选项。

花生批注：
2 行文结构：二层结构之背景 +正文。
文段先介绍了眼睛成像的基本原理和远点、近点相关知识；
之后指出长时间用眼可发生眼疲劳，并且介绍眼疲劳的症状。
3 实战思维：
