INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300255,3,'中心理解题','客观地说，要实现自动驾驶，单靠汽车本身升级是远远不够的，还需要城市道路升级为智能化管理，达到汽车和城市交通系统的联动，汽车才能有更多的“眼睛”观察到周围的路况，发现潜在的危险。但在目前技术与环境没有完善的情况下，无人驾驶的汽车还不能像人脑一样做到精准判断，不可贸然上路。这也是无人驾驶研发者应该注意的，研发应当考虑周全而不能激进，毕竟自动驾驶能否应对复杂的道路环境，必须经历“路考”的检验。
这段文字意在强调：','[{"label":"A","content":"自动驾驶技术的应用需稳步前行"},{"label":"B","content":"安全是自动驾驶技术应用的首要原则"},{"label":"C","content":"实现自动驾驶离不开各种配套设施的升级"},{"label":"D","content":"能否通过“路考”检验是自动驾驶技术的关键"}]','A','文段分析见批注。
文段转折前介绍了自动驾驶汽车上路的要求，转折后给出并列对策：目前自动驾驶汽车不可贸然上路，无人驾驶研发者也应考虑周全，上路前必须经历路考，总结起来为“自动驾驶汽车还不能贸然上路”;A选项的“自动驾驶技术的应用需稳步前行”是此意思的同义替换，当选；
B选项的“首要原则”和 C选项的“配套设施的升级”无中生有，排除； D选项只对应转折后的第二句话，片面，排除。

花生批注：
④ 行文结构：二层结构之转折。转折前介绍自动驾驶汽车上路的要求；
转折后给出并列对策：
①目前技术与环境没有完善情况下，自动驾驶汽车不可贸然上路；
②无人驾驶研发者也应考虑周全，上路前必须经历路考的检验。
客观地说，要实现自动驾驶，单靠汽车本身升级是远远不够的，还需要城市道路升级为智能化管理，达到汽车和城市交通系统的联动，汽车才能有更多的“眼睛”观察到周围的路况，发现潜在的危险(引出话题)。但在目前技术与环境没有完善的情况下，无人驾驶的汽车还不能像人脑一样做到精准判断，不可贸然上路( 提出对策)。这也是无人驾驶研发者应该注意的，研发应当考虑周全而不能激进，毕竟自动驾驶能否应对复杂的道路环境，必须经历“路考”的检验(提出对策)。④
这段文字意在强调：
A. 自动驾驶技术的应用需稳步前行
B. 安全是自动驾驶技术应用的首要原则 (无中生有)
C. 实现自动驾驶离不开各种配套设施的升级(无中生有)','2020年四川省考','进阶','published','{"globalNumber":255,"setNumber":13,"localNumber":15,"sourceLabel":"2020年四川省考 46%","accuracy":46,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"客观地说，要实现自动驾驶，单靠汽车本身升级是远远不够的，还需要城市道路升级为智能化管理，达到汽车和城市交通系统的联动，汽车才能有更多的“眼睛”观察到周围的路况，发现潜在的危险。但在目前技术与环境没有完善的情况下，无人驾驶的汽车还不能像人脑一样做到精准判断，不可贸然上路。这也是无人驾驶研发者应该注意的，研发应当考虑周全而不能激进，毕竟自动驾驶能否应对复杂的道路环境，必须经历“路考”的检验。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"自动驾驶技术的应用需稳步前行"}],"B":[{"text":"安全是自动驾驶技术应用的首要原则"}],"C":[{"text":"实现自动驾驶离不开各种配套设施的升级"}],"D":[{"text":"能否通过“路考”检验是自动驾驶技术的关键"}]},"annotatedStemRich":[{"text":"④花生批注：\n行文结构：二层结构之转折。转折前介绍自动驾驶汽车上路的要求；\n转折后给出并列对策：\n①目前技术与环境没有完善情况下，自动驾驶汽车不可贸然上路；\n②无人驾驶研发者也应考虑周全，上路前必须经历路考的检验。\n客观地说，要实现自动驾驶，单靠汽车本身升级是远远不够的，还需要城市道路升级为智能化管理，达到汽车和城市交通系统的联动，汽车才能有更多的“眼睛”观察到周围的路况，发现潜在的危险(引出话题)。但在目前技术与环境没有完善的情况下，无人驾驶的汽车还不能像人脑一样做到精准判断，不可贸然上路( 提出对策)。这也是无人驾驶研发者应该注意的，研发应当考虑周全而不能激进，毕竟自动驾驶能否应对复杂的道路环境，必须经历“路考”的检验(提出对策)。④\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"自动驾驶技术的应用需稳步前行"}],"B":[{"text":"安全是自动驾驶技术应用的首要原则 (无中生有)"}],"C":[{"text":"实现自动驾驶离不开各种配套设施的升级(无中生有)"}],"D":[{"text":"能否通过“路考”检验是自动驾驶技术的关键(片面)"}]},"practicalAnalysis":"文段分析见批注。\n文段转折前介绍了自动驾驶汽车上路的要求，转折后给出并列对策：目前自动驾驶汽车不可贸然上路，无人驾驶研发者也应考虑周全，上路前必须经历路考，总结起来为“自动驾驶汽车还不能贸然上路”;A选项的“自动驾驶技术的应用需稳步前行”是此意思的同义替换，当选；\nB选项的“首要原则”和 C选项的“配套设施的升级”无中生有，排除； D选项只对应转折后的第二句话，片面，排除。","notes":[{"marker":"④","content":"行文结构：二层结构之转折。转折前介绍自动驾驶汽车上路的要求；\n转折后给出并列对策：\n①目前技术与环境没有完善情况下，自动驾驶汽车不可贸然上路；\n②无人驾驶研发者也应考虑周全，上路前必须经历路考的检验。\n客观地说，要实现自动驾驶，单靠汽车本身升级是远远不够的，还需要城市道路升级为智能化管理，达到汽车和城市交通系统的联动，汽车才能有更多的“眼睛”观察到周围的路况，发现潜在的危险(引出话题)。但在目前技术与环境没有完善的情况下，无人驾驶的汽车还不能像人脑一样做到精准判断，不可贸然上路( 提出对策)。这也是无人驾驶研发者应该注意的，研发应当考虑周全而不能激进，毕竟自动驾驶能否应对复杂的道路环境，必须经历“路考”的检验(提出对策)。④\n这段文字意在强调：\nA. 自动驾驶技术的应用需稳步前行\nB. 安全是自动驾驶技术应用的首要原则 (无中生有)\nC. 实现自动驾驶离不开各种配套设施的升级(无中生有)","matchScore":1.5424,"pairingMode":"marker-and-content","order":23}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300256,3,'中心理解题','发展与问题总是相伴而生。近代中国面对民族存亡的问题，新中国面对巩固并保住人民胜利成果的问题，改革开放过程中面对姓“资”姓“社”问题，每个阶段都是在“破题生长”。如今，踏平坎坷迈入新时代，改革发展的种种问题仍是复杂多样的，这不意味着遇到问题就可以躲着走，没看见，而是要有看待问题的眼光，分析问题的理性，解决问题的能力，预判问题的机制，防范问题的警觉，归根结底就是要以问题为导向。我们说发扬斗争精神，增强斗争本领，何尝不是敢于，勇于，善于向一系列问题开刀。
对上述文段概括准确的是：','[{"label":"A","content":"推动发展需要坚持问题导向"},{"label":"B","content":"发展过程就是解决问题的过程"},{"label":"C","content":"发展的不同阶段面对的问题也不同"},{"label":"D","content":"面对问题的态度决定了发展的方向"}]','A','文段分析见批注。
文段开门见山引出“发展与问题”的话题，接着加以分析说明，文末给出对策：新时代改革发展要以问题为导向，对应A选项，当选；
其他选项虽然都提到发展与问题，但均为中性表达，谈论二者关系，未体现对策，可简单排除。

花生批注：
25 “归根结底”是对前文分述对策的总结，即新时代改革发展要以问题为导向。
6 行文结构：后对策结构。
先开门见山引出“发展与问题”这一话题；
后针对改革发展的问题进行分析说明并提出对策：
