INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300257,3,'中心理解题','中国接入国际互联网以来，互联网信息技术得到迅猛发展，在网络技术、移动芯片、智能终端、云计算、大数据、卫星导航等多个领域实现了重大突破，取得了一批显著的成就，网络技术自主创新能力显著增强、智能终端制造业加快赶超、不断培育新技术新应用形成新业态。但应该看到，与世界先进水平相比，我们还存在一定差距。目前世界局势波诡云谲，中国必须掌握核心技术，在新时代才能避免受制于人，掌握我国互联网发展的主动权。
这段文字意在说明：','[{"label":"A","content":"核心技术突破才是一个国家科技实力的彰显"},{"label":"B","content":"我们与世界先进水平之间依然存在一定差距"},{"label":"C","content":"互联网发展的主动权应掌握在我们自己手里"},{"label":"D","content":"新时代更需突破互联网核心技术这个“命门”"}]','D','文段分析见批注。
文段先通过转折引出问题：我国与世界先进水平相比，互联网核心技术存在差距，再通过“必须才”逻辑关联词给对策：新时代我国要掌握互联网发展的主动权，必须掌握核心技术，对策重点是“掌握核心技术”。 D选项的“需突破互联网核心技术这个‘命门’”是对策“必须掌握核心技术”的同义替换，当选；
A选项中性表达，介绍什么能彰显国家科技实力，排除；B选项为问题表述，未体现对策重点“掌握核心技术”,排除；
C选项为强干扰项，文段对策句是“必须(只有)才”句式，一般“必须”之后为对策，“才”之后为目的⑧。因此，本题对策核心为“必须掌握核心技术”, 而非“避免受制于人，掌握我国互联网发展主动权”。

花生批注：
② 行文结构：后对策结构。
先转折引出问题：我国与世界先进水平相比，互联网核心技术存在差距(转折前内容非重点);
最后通过“必须才”提出对策：新时代我国要掌握互联网发展的主动权，必须掌握核心技术。
这段文字意在说明：
A. 核心技术突破才是一个国家科技实力的彰显(中性表达)
B. 我们与世界先进水平之间依然存在一定差距(问题表述)
C. 互联网发展的主动权应掌握在我们自己手里
D. 新时代更需突破互联网核心技术这个“命门”
28 对策句可翻译为：
要想在新时代避免受制于人，掌握互联网发展主动权，中国就必须掌握核心技术；重点在做法：必须掌握核心技术。','2019年四川选调','进阶','published','{"globalNumber":257,"setNumber":13,"localNumber":17,"sourceLabel":"2019年四川选调 67%","accuracy":67,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"中国接入国际互联网以来，互联网信息技术得到迅猛发展，在网络技术、移动芯片、智能终端、云计算、大数据、卫星导航等多个领域实现了重大突破，取得了一批显著的成就，网络技术自主创新能力显著增强、智能终端制造业加快赶超、不断培育新技术新应用形成新业态。但应该看到，与世界先进水平相比，我们还存在一定差距。目前世界局势波诡云谲，中国必须掌握核心技术，在新时代才能避免受制于人，掌握我国互联网发展的主动权。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"核心技术突破才是一个国家科技实力的彰显"}],"B":[{"text":"我们与世界先进水平之间依然存在一定差距"}],"C":[{"text":"互联网发展的主动权应掌握在我们自己手里"}],"D":[{"text":"新时代更需突破互联网核心技术这个“命门”"}]},"annotatedStemRich":[{"text":"中国接入国际互联网以来，互联网信息技术得到迅猛发展，在网络技术、移动芯片、智能终端、云计算、大数据、卫星导航等多个领域实现了重大突破，取得了一批显著的成就，网络技术自主创新能力显著增强、智能终端制造业加快赶超、不断培育新技术新应用形成新业态。但应该看到，与世界先进水平相比，我们还存在一定差距(转折引出问题)。目前世界局势波诡云谲，中国必须掌握核心技术，在新时代才能避免受制于人，掌握我国互联网发展的主动权( 逻辑关联词表对策)。②\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"核心技术突破才是一个国家科技实力的彰显(中性表达)"}],"B":[{"text":"我们与世界先进水平之间依然存在一定差距(问题表述)"}],"C":[{"text":"互联网发展的主动权应掌握在我们自己手里"}],"D":[{"text":"新时代更需突破互联网核心技术这个“命门”"}]},"practicalAnalysis":"文段分析见批注。\n文段先通过转折引出问题：我国与世界先进水平相比，互联网核心技术存在差距，再通过“必须才”逻辑关联词给对策：新时代我国要掌握互联网发展的主动权，必须掌握核心技术，对策重点是“掌握核心技术”。 D选项的“需突破互联网核心技术这个‘命门’”是对策“必须掌握核心技术”的同义替换，当选；\nA选项中性表达，介绍什么能彰显国家科技实力，排除；B选项为问题表述，未体现对策重点“掌握核心技术”,排除；\nC选项为强干扰项，文段对策句是“必须(只有)才”句式，一般“必须”之后为对策，“才”之后为目的⑧。因此，本题对策核心为“必须掌握核心技术”, 而非“避免受制于人，掌握我国互联网发展主动权”。","notes":[{"marker":"②","content":"行文结构：后对策结构。\n先转折引出问题：我国与世界先进水平相比，互联网核心技术存在差距(转折前内容非重点);\n最后通过“必须才”提出对策：新时代我国要掌握互联网发展的主动权，必须掌握核心技术。\n这段文字意在说明：\nA. 核心技术突破才是一个国家科技实力的彰显(中性表达)\nB. 我们与世界先进水平之间依然存在一定差距(问题表述)\nC. 互联网发展的主动权应掌握在我们自己手里\nD. 新时代更需突破互联网核心技术这个“命门”","matchScore":0.8027,"pairingMode":"marker-and-content","order":26},{"marker":"28","content":"对策句可翻译为：\n要想在新时代避免受制于人，掌握互联网发展主动权，中国就必须掌握核心技术；重点在做法：必须掌握核心技术。","matchScore":0.7604,"pairingMode":"content-similarity","order":27}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300258,3,'中心理解题','在许多“80后”的童年、少年记忆中，漫画还是一摞摞的杂志和成套的画册，从电脑、手机上看网络漫画，已是成年后的事情了。但这却是“90后”“00后”们漫画阅读的起始阶段。随着数字网络技术的发展，“互联网+漫画”改变和颠覆了原来的产业格局。网络的优势吸引了大量漫画作者通过网络平台展示自己的作品。从电脑端的漫画网站、博客、论坛，到移动端的微博、微信，许多漫画作者以网络为载体，吸引了众多粉丝，创造出许多知名漫画形象。
这段文字主要介绍：','[{"label":"A","content":"互联网对漫画传播方式的影响"},{"label":"B","content":"不同年代接触漫画的不同途径"},{"label":"C","content":"网络对漫画作者与读者的吸引力"},{"label":"D","content":"数字技术对读者阅读习惯的改变\n片段阅读600 四(上册)"}]','A','文段分析见批注。
文段先介绍了漫画阅读方式的变化，再详细介绍互联网对漫画展示载体的影响；漫画、互联网为关键信息，且文段重点介绍漫画的展示和阅读方式，对应A选项的“传播方式”,当选；
B选项未提及互联网， D选项未提及漫画，可简单排除； C选项③ ,原文的表述为“网络优势吸引作者用网络平台展示漫画”,重点谈的是漫画的展示方式，而非网络对漫画的吸引力，排除。

花生批注：
⑥ 幼童是全文论述主体。
⑧ 云南是全文论述主体。
9 漫画是全文论述主体。
③0 行文结构：二层结构之"A +B”。
先介绍漫画阅读方式的变化 (从杂志画册到网络漫画); 再详细介绍网络对漫画展示载体的影响。
③ C选项可看作具体类选项，原文并未具体介绍网络对漫画作者和读者的吸引力。
在许多“80后”的童年、少年记忆中，漫画还是一摞摞的杂志和成套的画册，从电脑、手机上看网络漫画，已是成年后的事情了。但这却是“90后”“00 后”们漫画阅读的起始阶段(介绍漫画阅读方式的变化)。随着数字网络技术的发展，“互联网+漫画”改变和颠覆了原来的产业格局。网络的优势吸引了大量漫画作者通过网络平台展示自己的作品。从电脑端的漫画网站、博客、论坛，到移动端的微博、微信，许多漫画作者以网络为载体，吸引了众多粉丝，创造出许多知名漫画形象(介绍互联网对漫画展示载体的影响)。③
这段文字主要介绍：
A. 互联网对漫画传播方式的影响
B. 不同年代接触漫画的不同途径(缺主题词)
C. 网络对漫画作者与读者的吸引力(无中生有)
D. 数字技术对读者阅读习惯的改变(缺主题词)','2019年四川省考','基础','published','{"globalNumber":258,"setNumber":13,"localNumber":18,"sourceLabel":"2019年四川省考 71%","accuracy":71,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"在许多“80后”的童年、少年记忆中，漫画还是一摞摞的杂志和成套的画册，从电脑、手机上看网络漫画，已是成年后的事情了。但这却是“90后”“00后”们漫画阅读的起始阶段。随着数字网络技术的发展，“互联网+漫画”改变和颠覆了原来的产业格局。网络的优势吸引了大量漫画作者通过网络平台展示自己的作品。从电脑端的漫画网站、博客、论坛，到移动端的微博、微信，许多漫画作者以网络为载体，吸引了众多粉丝，创造出许多知名漫画形象。\n这段文字主要介绍："}],"optionRich":{"A":[{"text":"互联网对漫画传播方式的影响"}],"B":[{"text":"不同年代接触漫画的不同途径"}],"C":[{"text":"网络对漫画作者与读者的吸引力"}],"D":[{"text":"数字技术对读者阅读习惯的改变\n片段阅读600 四(上册)"}]},"annotatedStemRich":[{"text":"9花生批注：\n漫画是全文论述主体。\n③0花生批注：\n行文结构：二层结构之\"A +B”。\n先介绍漫画阅读方式的变化 (从杂志画册到网络漫画); 再详细介绍网络对漫画展示载体的影响。\n③花生批注：\nC 选项可看作具体类选项，原文并未具体介绍网络对漫画作者和读者的吸引力。\n在许多“80后”的童年、少年记忆中，漫画还是一摞摞的杂志和成套的画册，从电脑、手机上看网络"},{"text":"漫画","underline":true},{"text":"，已是成年后的事情了。但这却是“90后”“00 后”们漫画阅读的起始阶段(介绍漫画阅读方式的变化)。随着数字网络技术的发展，“互联网+漫画”改变和颠覆了原来的产业格局。网络的优势吸引了大量漫画作者通过网络平台展示自己的作品。从电脑端的漫画网站、博客、论坛，到移动端的微博、微信，许多漫画作者以网络为载体，吸引了众多粉丝，创造出许多知名漫画形象(介绍互联网对漫画展示载体的影响)。③\n这段文字主要介绍："}],"annotatedOptionRich":{"A":[{"text":"互联网对漫画传播方式的影响"}],"B":[{"text":"不同年代接触漫画的不同途径(缺主题词)"}],"C":[{"text":"网络对漫画作者与读者的吸引力(无中生有)"}],"D":[{"text":"数字技术对读者阅读习惯的改变(缺主题词)"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍了漫画阅读方式的变化，再详细介绍互联网对漫画展示载体的影响；漫画、互联网为关键信息，且文段重点介绍漫画的展示和阅读方式，对应A选项的“传播方式”,当选；\nB选项未提及互联网， D选项未提及漫画，可简单排除； C选项③ ,原文的表述为“网络优势吸引作者用网络平台展示漫画”,重点谈的是漫画的展示方式，而非网络对漫画的吸引力，排除。","notes":[{"marker":"⑥","content":"幼童是全文论述主体。","matchScore":0.7707,"pairingMode":"content-similarity","order":5},{"marker":"⑧","content":"云南是全文论述主体。","matchScore":0.7707,"pairingMode":"content-similarity","order":7},{"marker":"9","content":"漫画是全文论述主体。","matchScore":1.0266,"pairingMode":"content-similarity","order":28},{"marker":"③0","content":"行文结构：二层结构之\"A +B”。\n先介绍漫画阅读方式的变化 (从杂志画册到网络漫画); 再详细介绍网络对漫画展示载体的影响。","matchScore":1.1395,"pairingMode":"content-similarity","order":29},{"marker":"③","content":"C选项可看作具体类选项，原文并未具体介绍网络对漫画作者和读者的吸引力。\n在许多“80后”的童年、少年记忆中，漫画还是一摞摞的杂志和成套的画册，从电脑、手机上看网络漫画，已是成年后的事情了。但这却是“90后”“00 后”们漫画阅读的起始阶段(介绍漫画阅读方式的变化)。随着数字网络技术的发展，“互联网+漫画”改变和颠覆了原来的产业格局。网络的优势吸引了大量漫画作者通过网络平台展示自己的作品。从电脑端的漫画网站、博客、论坛，到移动端的微博、微信，许多漫画作者以网络为载体，吸引了众多粉丝，创造出许多知名漫画形象(介绍互联网对漫画展示载体的影响)。③\n这段文字主要介绍：\nA. 互联网对漫画传播方式的影响\nB. 不同年代接触漫画的不同途径(缺主题词)\nC. 网络对漫画作者与读者的吸引力(无中生有)\nD. 数字技术对读者阅读习惯的改变(缺主题词)","matchScore":1.5292,"pairingMode":"marker-and-content","order":30}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300259,3,'细节判断类','火山爆发喷出来的高温熔岩本身是不带磁性的，但其冷却后，就会被当时所处的地磁磁化，并与磁场方向一致。这是因为其含铁，而含铁的矿物易受到地磁场的影响，我们称被锁定在岩石内部的磁场为“热剩余磁性”,带有热剩余磁性的岩石会持续保留被磁化的磁性，即使之后遇到不同方向的磁场也不会产生变化，因此，只要我们调查岩石带有的热剩余磁性的方向，同时根据放射性元素的衰变情况进行年代测定，就可以推断出这块岩石形成(熔岩凝固)的年代，进而得知地球的磁场是如何随时间的推移而变化的。
下列说法与原文不符的是：','[{"label":"A","content":"带有热剩余磁性的岩石不会因为地磁场的影响改变磁性"},{"label":"B","content":"冷却后的高温熔岩之所以带有热剩余磁性是因为其含铁"},{"label":"C","content":"岩石带有的热剩余磁性的方向与现在地球磁场方向一致"},{"label":"D","content":"带有热剩余磁性的岩石有助于我们研究地球磁场的变化"}]','C','根据原文“但其冷却后，就会被当时所处的地磁磁化，并与磁场方向一致”和“带有热剩余磁性的岩石会持续保留被磁化的磁性，即使之后遇到不同方向的磁场也不会产生变化”可知：带有热剩余磁性的岩石的磁性方向与当时所处地磁磁场方向一致，且不会改变， A选项正确， C选项错误， C选项当选；
B选项和D选项在原文中能够简单找到对应，表述正确，排除。

