INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300261,3,'中心理解题','目前，我国住房刚性和改善性需求群体主要为工薪阶层。一些地方房贷政策“无差别”“一刀切”, 存在错位、越位的倾向，不能够满足工薪阶层的住房信贷需求，比如，有的银行对改善性需求不分青红皂白收紧乃至拒贷；有的银行因为自身信贷额度或投放节奏的偏差，人为拖延审批时间。如今，大数据时代完全可以做到详尽评估，做到精准施策，提供个性化的高质量金融服务。
这段文字意在强调：','[{"label":"A","content":"一些地方的房贷政策存在错位、越位的倾向"},{"label":"B","content":"金融服务要贯彻“以人民为中心”的发展思想"},{"label":"C","content":"银行应提供差别化、精准化的高质量服务"},{"label":"D","content":"目前我国工薪阶层的刚性和改善性需求得不到满足"}]','C','文段分析见批注。
文段开篇提出问题并举例，尾句给出建议型对策，可以翻译为“大数据时代要做到详尽评估、精准施策，提供个性化的高质量金融服务”, 对应 C选项 ②,当选；
A选项、D选项是问题表述，未谈及对策，可直接排除； B选项“以人民为中心”文段未提及，属无中生有，排除。

花生批注：
① 行文结构：后对策结构。
先提出问题：
房贷政策不能够满足工薪阶层的住房信贷需求；
再举例分析；
最后提出对策：
大数据时代要做到详尽评估、精准施策，提供个性化的高质量金融服务。
② C选项的“差别化”对应原文个性化、“精准化”对应原文精准施策。','2021年广东选调','基础','published','{"globalNumber":261,"setNumber":14,"localNumber":1,"sourceLabel":"2021年广东选调70%","accuracy":70,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"目前，我国住房刚性和改善性需求群体主要为工薪阶层。一些地方房贷政策“无差别”“一刀切”, 存在错位、越位的倾向，不能够满足工薪阶层的住房信贷需求，比如，有的银行对改善性需求不分青红皂白收紧乃至拒贷；有的银行因为自身信贷额度或投放节奏的偏差，人为拖延审批时间。如今，大数据时代完全可以做到详尽评估，做到精准施策，提供个性化的高质量金融服务。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"一些地方的房贷政策存在错位、越位的倾向"}],"B":[{"text":"金融服务要贯彻“以人民为中心”的发展思想"}],"C":[{"text":"银行应提供差别化、精准化的高质量服务"}],"D":[{"text":"目前我国工薪阶层的刚性和改善性需求得不到满足"}]},"annotatedStemRich":[{"text":"目前，我国住房刚性和改善性需求群体主要为工薪阶层。一些地方房贷政策“无差别”“一刀切”,存在错位、越位的倾向，不能够满足工薪阶层的住房信贷需求(提出问题),比如，有的银行对改善性需求不分青红皂白收紧乃至拒贷；有的银行因为自身信贷额度或投放节奏的偏差，人为拖延审批时间"},{"text":"(","bold":true},{"text":" "},{"text":"举","bold":true},{"text":"例分析)。如今，大数据时代完全可以做到详尽评估，做到精准施策，提供个性化的高质量金融服务(提出建议型对策)。①\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"一些地方的房贷政策存在错位、越位的倾向(问题表述)"}],"B":[{"text":"金融服务要贯彻“以人民为中心”的发展思想 (无中生有)"}],"C":[{"text":"银行应提供差别化、精准化的高质量服务"}],"D":[{"text":"目前我国工薪阶层的刚性和改善性需求得不到满足(问题表述)"}]},"practicalAnalysis":"文段分析见批注。\n文段开篇提出问题并举例，尾句给出建议型对策，可以翻译为“大数据时代要做到详尽评估、精准施策，提供个性化的高质量金融服务”, 对应 C选项 ②,当选；\nA选项、D选项是问题表述，未谈及对策，可直接排除； B选项“以人民为中心”文段未提及，属无中生有，排除。","notes":[{"marker":"①","content":"行文结构：后对策结构。\n先提出问题：\n房贷政策不能够满足工薪阶层的住房信贷需求；\n再举例分析；\n最后提出对策：\n大数据时代要做到详尽评估、精准施策，提供个性化的高质量金融服务。","matchScore":0.9743,"pairingMode":"marker-and-content","order":0},{"marker":"②","content":"C选项的“差别化”对应原文个性化、“精准化”对应原文精准施策。","matchScore":0.5073,"pairingMode":"marker-and-content","order":1}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300262,3,'中心理解题','当教育已经从传授知识、发明工具、认识和改造客观世界，拓展到人脑自身如何认知、如何再塑造的新阶段，人工智能对教育的挑战就不单是一个学科、一个专业的问题，而是本世纪全新、全方位、持久过程的挑战。本科生的智能课程体系设置和新形态教材的制定与开发是一项刻不容缓的巨大工程。目前人类还处在从信息时代走向智能时代的过渡区，各大学自主设置专业，为我国智能教育的课程和教材优化创造了百花齐放的勃勃生机，还要共同探索中国智能产业人才的培养体系、试验平台、成果转化方法等。
这段文字意在强调：','[{"label":"A","content":"人工智能对传统教育有巨大冲击"},{"label":"B","content":"普及智能教育是时代的呼唤"},{"label":"C","content":"大学智能教育刻不容缓"},{"label":"D","content":"人工智能教育体系亟需完善"}]','C','文段分析见批注。
文段结构简单，先引出话题：人工智能对教育提出挑战；再给出一连串对策：大学本科要进行智能课程体系设置和新形态教材的制定与开发；各大学要自主设置专业以优化我国智能教育的课程和教材；各大学还要共同探索中国智能产业人才培养等；
观察选项，A选项未体现对策，排除；
其他选项均为对策选项，但侧重点不同，B选项对策为“要普及智能教育”, 重点在“普及”;C选项对策为“要进行大学智能教育”,重点在“大学”; D选项对策为“要完善人工智能教育体系”,重点在“完善体系”;
根据文段对策可知：重点在于“各大学”的做法，答案对应C选项。

花生批注：
③ 行文结构：后对策结构。
文段开篇引出话题：
人工智能对教育产生挑战；再提出对策：
大学本科要进行智能课程体系设置和新形态教材的制定与开发，各大学要自主设置专业以优化我国智能教育的课程和教材，各大学还要共同探索中国智能产业人才培养等。
④ 刻不容缓用法不仅无误，还很恰当，理由如下：
①原文“本科生的智能课程体系设置和新形态教材的制定与开发是一项刻不容缓的巨大工程”有刻不容缓的表述；
②“教育已经拓展到..……的新阶段”、“刻不容缓的巨大工程”、“目前人类还处于走向智能时代的过渡区”, 文段多处谈及当前所处时代，即现在正是开展对策的好时机，C选项的“刻不容缓”能体现出“当前时代应该做”的急迫性。
这段文字意在强调：
A. 人工智能对传统教育有巨大冲击(问题表述)
B. 普及智能教育是时代的呼唤(对策有误)
C. 大学智能教育刻不容缓④
D. 人工智能教育体系亟需完善(对策有误)','2019年江西省法检','挑战','published','{"globalNumber":262,"setNumber":14,"localNumber":2,"sourceLabel":"2019年江西省法检39%","accuracy":39,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"当教育已经从传授知识、发明工具、认识和改造客观世界，拓展到人脑自身如何认知、如何再塑造的新阶段，人工智能对教育的挑战就不单是一个学科、一个专业的问题，而是本世纪全新、全方位、持久过程的挑战。本科生的智能课程体系设置和新形态教材的制定与开发是一项刻不容缓的巨大工程。目前人类还处在从信息时代走向智能时代的过渡区，各大学自主设置专业，为我国智能教育的课程和教材优化创造了百花齐放的勃勃生机，还要共同探索中国智能产业人才的培养体系、试验平台、成果转化方法等。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"人工智能对传统教育有巨大冲击"}],"B":[{"text":"普及智能教育是时代的呼唤"}],"C":[{"text":"大学智能教育刻不容缓"}],"D":[{"text":"人工智能教育体系亟需完善"}]},"annotatedStemRich":[{"text":"当教育已经从传授知识、发明工具、认识和改造客观世界，拓展到人脑自身如何认知、如何再塑造的新阶段，人工智能对教育的挑战就不单是一个学科、一个专业的问题，而是本世纪全新、全方位、持久过程的挑战(引出话题)。本科生的智能课程体系设置和新形态教材的制定与开发是一项刻不容缓的巨大工程。目前人类还处在从信息时代走向智能时代的过渡区，各大学自主设置专业，为我国智能教育的课程和教材优化创造了百花齐放的勃勃生机，还要共同探索中国智能产业人才的培养体系、试验平台、成果转化方法等(提出对策)。③\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"人工智能对传统教育有巨大冲击(问题表述)"}],"B":[{"text":"普及智能教育是时代的呼唤(对策有误)"}],"C":[{"text":"大学智能教育"},{"text":"刻不容","underline":true},{"text":"缓④"}],"D":[{"text":"人工智能教育体系亟需完善(对策有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段结构简单，先引出话题：人工智能对教育提出挑战；再给出一连串对策：大学本科要进行智能课程体系设置和新形态教材的制定与开发；各大学要自主设置专业以优化我国智能教育的课程和教材；各大学还要共同探索中国智能产业人才培养等；\n观察选项，A选项未体现对策，排除；\n其他选项均为对策选项，但侧重点不同，B选项对策为“要普及智能教育”, 重点在“普及”;C选项对策为“要进行大学智能教育”,重点在“大学”; D选项对策为“要完善人工智能教育体系”,重点在“完善体系”;\n根据文段对策可知：重点在于“各大学”的做法，答案对应C选项。","notes":[{"marker":"③","content":"行文结构：后对策结构。\n文段开篇引出话题：\n人工智能对教育产生挑战；再提出对策：\n大学本科要进行智能课程体系设置和新形态教材的制定与开发，各大学要自主设置专业以优化我国智能教育的课程和教材，各大学还要共同探索中国智能产业人才培养等。","matchScore":1.0921,"pairingMode":"marker-and-content","order":2},{"marker":"④","content":"刻不容缓用法不仅无误，还很恰当，理由如下：\n①原文“本科生的智能课程体系设置和新形态教材的制定与开发是一项刻不容缓的巨大工程”有刻不容缓的表述；\n②“教育已经拓展到..……的新阶段”、“刻不容缓的巨大工程”、“目前人类还处于走向智能时代的过渡区”, 文段多处谈及当前所处时代，即现在正是开展对策的好时机，C选项的“刻不容缓”能体现出“当前时代应该做”的急迫性。\n这段文字意在强调：\nA. 人工智能对传统教育有巨大冲击(问题表述)\nB. 普及智能教育是时代的呼唤(对策有误)\nC. 大学智能教育刻不容缓④\nD. 人工智能教育体系亟需完善(对策有误)","matchScore":0.6555,"pairingMode":"marker-and-content","order":3}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300263,3,'中心理解题','有人说，传统小说是依赖经验的写作，而网络小说是依赖想象的写作。看来，这两种写作需要找到一个结合点，依赖经验的写作需要吸纳网络小说的想象，而依赖想象的写作则需要揉入传统小说中丰厚充实的经验。因此，当今的文学要从原创力日益萎缩的窘境中走出来，作家们增加生活经验的积累应该是一个非常关键的举措。但这还只是由经验通往原创力的第一步，接下来必须在体验上进行认真的修炼，使生活经验转化为心灵体验，使客观的经验世界转化为作家主观的心灵世界。
这段文字重点强调的是：','[{"label":"A","content":"如何转化经验吸纳想象"},{"label":"B","content":"怎样找到传统和网络小说的结合点"},{"label":"C","content":"作家应该如何不断地积累生活经验"},{"label":"D","content":"如何提高文学的原创力"}]','D','文段分析见批注。
文段在引出传统小说写作和网络小说写作后简单分析，之后给出对策：当今文学要解决原创力缺失问题，需要作家增加生活经验并且将生活经验转化为心灵体验。要解决的问题是当今文学原创力缺失，对应D选项，当选⑦;
A选项为杂糅选项，将文末的“转化经验”和第二句的“吸纳想象”杂糅到一起，排除；B选项出处有误，“结合点”为原文中分析介绍部分，非重点，排除；C选项，“不断积累生活经验”是解决原创力缺失的对策之一，具体如何“不断积累生活经验”文章并未提及，排除⑧

花生批注：
⑥ 文章结构：后对策结构。
引出话题：传统小说写作和网络小说写作；
再分析介绍：两种写作需要找到一个结合点；
而后给出对策：当今文学要解决原创力缺失问题，需要作家增加生活经验并且将生活经验转化为心灵体验。
有人说，传统小说是依赖经验的写作⑤,而网络小说是依赖想象的写作( 引出话题)。看来，这两种写作需要找到一个结合点，依赖经验的写作需要吸纳网络小说的想象，而依赖想象的写作则需要揉入传统小说中丰厚充实的经验( 分析介绍)。因此，当今的文学要从原创力日益萎缩的窘境中走出来，作家们增加生活经验的积累应该是一个非常关键的举措。但这还只是由经验通往原创力的第一步，接下来必须在体验上进行认真的修炼，使生活经验转化为心灵体验，使客观的经验世界转化为作家主观的心灵世界(后对策)。⑥
这段文字重点强调的是：
A. 如何转化经验吸纳想象( 杂糅 )
B. 怎样找到传统和网络小说的结合点(出处有误)
C. 作家应该如何不断地积累生活经验(对策有误)
D. 如何提高文学的原创力
⑦ 例如：行测要想提高成绩要提高速度和准确率；
可针对问题进行概括：文段介绍了如何提高行测成绩。','2013年联考','进阶','published','{"globalNumber":263,"setNumber":14,"localNumber":3,"sourceLabel":"2013年联考 58%","accuracy":58,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"有人说，传统小说是依赖经验的写作，而网络小说是依赖想象的写作。看来，这两种写作需要找到一个结合点，依赖经验的写作需要吸纳网络小说的想象，而依赖想象的写作则需要揉入传统小说中丰厚充实的经验。因此，当今的文学要从原创力日益萎缩的窘境中走出来，作家们增加生活经验的积累应该是一个非常关键的举措。但这还只是由经验通往原创力的第一步，接下来必须在体验上进行认真的修炼，使生活经验转化为心灵体验，使客观的经验世界转化为作家主观的心灵世界。\n这段文字重点强调的是："}],"optionRich":{"A":[{"text":"如何转化经验吸纳想象"}],"B":[{"text":"怎样找到传统和网络小说的结合点"}],"C":[{"text":"作家应该如何不断地积累生活经验"}],"D":[{"text":"如何提高文学的原创力"}]},"annotatedStemRich":[{"text":"有人说，传统小说是依赖经验的"},{"text":"写作","underline":true},{"text":"⑤,而网络小说是依赖想象的写作( 引出话题)。看来，这两种写作需要找到一个结合点，依赖经验的写作需要吸纳网络小说的想象，而依赖想象的写作则需要揉入传统小说中丰厚充实的经验( 分析介绍)。因此，当今的文学要从原创力日益萎缩的窘境中走出来，作家们增加生活经验的积累应该是一个非常关键的举措。但这还只是由经验通往原创力的第一步，接下来必须在体验上进行认真的修炼，使生活经验转化为心灵体验，使客观的经验世界转化为作家主观的心灵世界(后对策)。⑥\n这段文字重点强调的是："}],"annotatedOptionRich":{"A":[{"text":"如何转化经验吸纳想象( 杂糅 )"}],"B":[{"text":"怎样找到传统和网络小说的结合点(出处有误)"}],"C":[{"text":"作家应该如何不断地积累生活经验(对策有误)"}],"D":[{"text":"如何提高文学的原创力"}]},"practicalAnalysis":"文段分析见批注。\n文段在引出传统小说写作和网络小说写作后简单分析，之后给出对策：当今文学要解决原创力缺失问题，需要作家增加生活经验并且将生活经验转化为心灵体验。要解决的问题是当今文学原创力缺失，对应D选项，当选⑦;\nA选项为杂糅选项，将文末的“转化经验”和第二句的“吸纳想象”杂糅到一起，排除；B选项出处有误，“结合点”为原文中分析介绍部分，非重点，排除；C选项，“不断积累生活经验”是解决原创力缺失的对策之一，具体如何“不断积累生活经验”文章并未提及，排除⑧","notes":[{"marker":"⑥","content":"文章结构：后对策结构。\n引出话题：传统小说写作和网络小说写作；\n再分析介绍：两种写作需要找到一个结合点；\n而后给出对策：当今文学要解决原创力缺失问题，需要作家增加生活经验并且将生活经验转化为心灵体验。\n有人说，传统小说是依赖经验的写作⑤,而网络小说是依赖想象的写作( 引出话题)。看来，这两种写作需要找到一个结合点，依赖经验的写作需要吸纳网络小说的想象，而依赖想象的写作则需要揉入传统小说中丰厚充实的经验( 分析介绍)。因此，当今的文学要从原创力日益萎缩的窘境中走出来，作家们增加生活经验的积累应该是一个非常关键的举措。但这还只是由经验通往原创力的第一步，接下来必须在体验上进行认真的修炼，使生活经验转化为心灵体验，使客观的经验世界转化为作家主观的心灵世界(后对策)。⑥\n这段文字重点强调的是：\nA. 如何转化经验吸纳想象( 杂糅 )\nB. 怎样找到传统和网络小说的结合点(出处有误)\nC. 作家应该如何不断地积累生活经验(对策有误)\nD. 如何提高文学的原创力","matchScore":1.2721,"pairingMode":"marker-and-content","order":5},{"marker":"⑦","content":"例如：行测要想提高成绩要提高速度和准确率；\n可针对问题进行概括：文段介绍了如何提高行测成绩。","matchScore":0.1595,"pairingMode":"marker-and-content","order":6}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300264,3,'中心理解题','传记，从本质上说，是人的生命活动的记载，是人类生命的一种特殊载体。人的生命活动，不仅表现出生存和发展的渴求，而且表现出自身潜能的开发、释放。这种自身潜能的开发、释放，就是一种力的创造。创造，包括多种形式，有政治家治国平天下的才能展现，有哲学家、思想家在精神领域的探索，有军事家运筹帷幄、驰骋疆场的战斗较量，有科学家的发明创造，有文学家、艺术家的才华展示，有改革家对生存环境的革新改造，等等。这是一幅幅壮丽的生命画卷，是活力向惰性的挑战。人类只有在这样的挑战中才能保持其生命的活力，并为活力的凝聚创造更好的条件。中国古典传记，正是这种生命活力的形象性展现。
这段文字主要说明了：','[{"label":"A","content":"传记是人类生命活动最为生动的记载"},{"label":"B","content":"中国古典传记从多角度展现了生命活力"},{"label":"C","content":"人类自身潜能的开发包括多种形式"},{"label":"D","content":"人类个体与整体创造性在传记中有不同的表现"}]','B','文段分析见批注。

花生批注：
⑩ 文段结构：后观点结构。
开门见山引出话题：传记记载人的生命活动；
接下来分析介绍：“人的生命活动引出生命活力(人的生命活动是自身潜能的开发释放，这种开发释放是一种力的创造，创造是活力的挑战，在挑战中才能保持生命活力)”;
最后尾句给出观点：中国古典传记展现了生命活力。
片段阅读6 0 0 (上册)','2013年联考','进阶','published','{"globalNumber":264,"setNumber":14,"localNumber":4,"sourceLabel":"2013年联考57%","accuracy":57,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"传记，从本质上说，是人的生命活动的记载，是人类生命的一种特殊载体。人的生命活动，不仅表现出生存和发展的渴求，而且表现出自身潜能的开发、释放。这种自身潜能的开发、释放，就是一种力的创造。创造，包括多种形式，有政治家治国平天下的才能展现，有哲学家、思想家在精神领域的探索，有军事家运筹帷幄、驰骋疆场的战斗较量，有科学家的发明创造，有文学家、艺术家的才华展示，有改革家对生存环境的革新改造，等等。这是一幅幅壮丽的生命画卷，是活力向惰性的挑战。人类只有在这样的挑战中才能保持其生命的活力，并为活力的凝聚创造更好的条件。中国古典传记，正是这种生命活力的形象性展现。\n这段文字主要说明了："}],"optionRich":{"A":[{"text":"传记是人类生命活动最为生动的记载"}],"B":[{"text":"中国古典传记从多角度展现了生命活力"}],"C":[{"text":"人类自身潜能的开发包括多种形式"}],"D":[{"text":"人类个体与整体创造性在传记中有不同的表现"}]},"annotatedStemRich":[{"text":"传记","underline":true},{"text":"⑨,从本质上说，是人的生命活动的记载，是人类生命的一种特殊载体 (引出话题)。人的生命活动，不仅表现出生存和发展的渴求，而且表现出自身潜能的开发、释放。这种自身潜能的开发、释放，就是一种力的创造。创造，包括多种形式，有政治家治国平天下的才能展现，有哲学家、思想家在精神领域的探索，有军事家运筹帷幄、驰骋疆场的战斗较量，有科学家的发明创造，有文学家、艺术家的才华展示，有改革家对生存环境的革新改造，等等。这是一幅幅壮丽的生命画卷，是活力向惰性的挑战。人类只有在这样的挑战中才能保持其生命的活力，并为活力的凝聚创造更好的条件(分析介绍)。中国古典传记，正是这种生命活力的形象性展现(后观点)。⑩\n这段文字主要说明了："}],"annotatedOptionRich":{"A":[{"text":"传记是人类生命活动最为生动的记载(出处有误且绝对化)"}],"B":[{"text":"中国古典传记从多角度展现了生命活力"}],"C":[{"text":"人类自身潜能的开发包括多种形式(无主题词)"}],"D":[{"text":"人类个体与整体创造性在传记中有不同的表现(区别比较联系类)"}]},"practicalAnalysis":"文段分析见批注。","notes":[{"marker":"⑩","content":"文段结构：后观点结构。\n开门见山引出话题：传记记载人的生命活动；\n接下来分析介绍：“人的生命活动引出生命活力(人的生命活动是自身潜能的开发释放，这种开发释放是一种力的创造，创造是活力的挑战，在挑战中才能保持生命活力)”;\n最后尾句给出观点：中国古典传记展现了生命活力。\n片段阅读6 0 0 (上册)","matchScore":0.7182,"pairingMode":"marker-and-content","order":9}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300265,3,'细节判断类','随着年龄的增长，人眼睛的调节能力会下降，近视的人也不例外，只是表现出来的形式不一样而已。近视的人眼睛本来就存在一定的屈光度数，不戴近视眼镜时有点类似于正常人戴了老花镜的状态，所以近视的人在“老花”后不戴老花镜就能看清楚近的、细小的物体；但如果戴上近视眼镜，他们一样没法看清近的物体。
根据文段可知，下列说法正确的是：','[{"label":"A","content":"近视的人也会得“老花”"},{"label":"B","content":"眼睛衰老的表现就是“老花”"},{"label":"C","content":"中老年人会出现视力下降情况"},{"label":"D","content":"近视的人老了不需要佩戴老花镜"}]','A','根据“随着年龄的增长，人眼睛的调节能力会下降，近视的人也不例外”以及“所以近视的人在‘老花’后...…”可知，近视的人也会得“老花”,A选项表述正确，当选；
B选项绝对化，“老花”是眼睛调节能力下降的表现，不代表眼睛衰老的表现就是“老花”,排除；
C选项偷换概念，“调节能力会下降”不等于“视力下降”,排除；
D选项无中生有，根据“近视的人眼睛本来就存在一定的屈光度数，不戴近视眼镜时有点类似于正常人戴了老花镜的状态”可知，不戴近视眼镜有点类似不近视人戴了老花镜的状态，但根据常识可知，老花镜也是分度数的，若“近视度数”和“老花度数”不匹配，就不确定是否需要戴老花镜了.D选项原文未提及且过于绝对①,排除。','2022年大连市事业单位','进阶','published','{"globalNumber":265,"setNumber":14,"localNumber":5,"sourceLabel":"2022年大连市事业单位60%","accuracy":60,"typeAndPassage":"细节判断类","stemRich":[{"text":"随着年龄的增长，人眼睛的调节能力会下降，近视的人也不例外，只是表现出来的形式不一样而已。近视的人眼睛本来就存在一定的屈光度数，不戴近视眼镜时有点类似于正常人戴了老花镜的状态，所以近视的人在“老花”后不戴老花镜就能看清楚近的、细小的物体；但如果戴上近视眼镜，他们一样没法看清近的物体。\n根据文段可知，下列说法正确的是："}],"optionRich":{"A":[{"text":"近视的人也会得“老花”"}],"B":[{"text":"眼睛衰老的表现就是“老花”"}],"C":[{"text":"中老年人会出现视力下降情况"}],"D":[{"text":"近视的人老了不需要佩戴老花镜"}]},"annotatedStemRich":[{"text":"随着年龄的增长，人眼睛的调节能力会下降，近视的人也不例外，只是表现出来的形式不一样而已。近视的人眼睛本来就存在一定的屈光度数，不戴近视眼镜时有点类似于正常人戴了老花镜的状态，所以近视的人在“老花”后不戴老花镜就能看清楚近的、细小的物体；但如果戴上近视眼镜，他们一样没法看清近的物体。\n根据文段可知，下列说法正确的是："}],"annotatedOptionRich":{"A":[{"text":"近视的人也会得“老花”"}],"B":[{"text":"眼睛衰老的表现就是“老花”(绝对化)"}],"C":[{"text":"中老年人会出现视力下降情况(偷换概念)"}],"D":[{"text":"近视的人老了不需要佩戴老花镜(无中生有)"}]},"practicalAnalysis":"根据“随着年龄的增长，人眼睛的调节能力会下降，近视的人也不例外”以及“所以近视的人在‘老花’后...…”可知，近视的人也会得“老花”,A选项表述正确，当选；\nB选项绝对化，“老花”是眼睛调节能力下降的表现，不代表眼睛衰老的表现就是“老花”,排除；\nC选项偷换概念，“调节能力会下降”不等于“视力下降”,排除；\nD选项无中生有，根据“近视的人眼睛本来就存在一定的屈光度数，不戴近视眼镜时有点类似于正常人戴了老花镜的状态”可知，不戴近视眼镜有点类似不近视人戴了老花镜的状态，但根据常识可知，老花镜也是分度数的，若“近视度数”和“老花度数”不匹配，就不确定是否需要戴老花镜了.D选项原文未提及且过于绝对①,排除。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300266,3,'中心理解题','北大西洋暖流使得整个挪威海域常年不结冰。这股暖流虽然受盛行西风的影响，但是北冰洋的影响也不容忽视。北冰洋海水结冰时，会释放出其中含有的盐分，含盐量高的冰冷海水比重大，迅速沉入海底，于是来自墨西哥湾的温暖海水就会流过来填补空白。这股暖流为西欧带去大量热量，使得冬季的气温比同纬度的其他地区高出很多。
这段文字主要介绍：','[{"label":"A","content":"北冰洋海冰与洋流的关系"},{"label":"B","content":"南北半球冬季的气候差异"},{"label":"C","content":"北大西洋暖流的成因与影响"},{"label":"D","content":"欧洲冬季温度相对较高的原因"}]','C','文段分析见批注。
C选项为“A且B”形式⑨,“北大西洋暖流的成因”对应原文前三句内容，指出北冰洋会影响这股暖流的形成，并对此进行解释说明；“北大西洋暖流的影响”对应原文尾句“这股暖流为西欧带去大量热量，使得冬季的气温比同纬度的其他地区高出很多”,选项与原文一一对应，完美选项，当选；

花生批注：
⑫ 北大西洋暖流是全文论述话题。
⑬ 行文结构：二层结构之并列。先介绍北大西洋暖流的成因；
再介绍北大西洋暖流的影响。
A. 北冰洋海冰与洋流的关系(缺主题词)
B. 南北半球冬季的气候差异(缺主题词)
C. 北大西洋暖流的成因与影响
⑭ “A 且B”类选项概括全面，是正确答案概率很高，看到此类选项，直接考虑和原文一一对应即可。
A选项、B选项未提及北大西洋暖流，可简单排除； D选项的“欧洲”表述有误，北大西洋影响的是西欧的气温，且该选项只提及影响未提及成因，片面，排除。','2022年全国事业单位联考','进阶','published','{"globalNumber":266,"setNumber":14,"localNumber":6,"sourceLabel":"2022年全国事业单位联考53%","accuracy":53,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"北大西洋暖流使得整个挪威海域常年不结冰。这股暖流虽然受盛行西风的影响，但是北冰洋的影响也不容忽视。北冰洋海水结冰时，会释放出其中含有的盐分，含盐量高的冰冷海水比重大，迅速沉入海底，于是来自墨西哥湾的温暖海水就会流过来填补空白。这股暖流为西欧带去大量热量，使得冬季的气温比同纬度的其他地区高出很多。\n这段文字主要介绍："}],"optionRich":{"A":[{"text":"北冰洋海冰与洋流的关系"}],"B":[{"text":"南北半球冬季的气候差异"}],"C":[{"text":"北大西洋暖流的成因与影响"}],"D":[{"text":"欧洲冬季温度相对较高的原因"}]},"annotatedStemRich":[{"text":"北大西洋暖流","underline":true},{"text":"②使得整个挪威海域常年不结冰。这股暖流虽然受盛行西风的影响，但是北冰洋的影响也不容忽视。北冰洋海水结冰时，会释放出其中含有的盐分，含盐量高的冰冷海水比重大，迅速沉入海底，于是来自墨西哥湾的温暖海水就会流过来填补空白(北大西洋暖流的成因)。这股暖流为西欧带去大量热量，使得冬季的气温比同纬度的其他地区高出很多(北大西洋暖流的影响)。⑨\n这段文字主要介绍："}],"annotatedOptionRich":{"A":[{"text":"北冰洋海冰与洋流的关系(缺主题词)"}],"B":[{"text":"南北半球冬季的气候差异(缺主题词)"}],"C":[{"text":"北大西洋暖流的成因与影响","bold":true}],"D":[{"text":"欧洲冬季温度相对较高的原因(本身有误且片面)"}]},"practicalAnalysis":"文段分析见批注。\nC选项为“A且B”形式⑨,“北大西洋暖流的成因”对应原文前三句内容，指出北冰洋会影响这股暖流的形成，并对此进行解释说明；“北大西洋暖流的影响”对应原文尾句“这股暖流为西欧带去大量热量，使得冬季的气温比同纬度的其他地区高出很多”,选项与原文一一对应，完美选项，当选；","notes":[{"marker":"⑫","content":"北大西洋暖流是全文论述话题。","matchScore":0.4562,"pairingMode":"content-similarity","order":11},{"marker":"⑬","content":"行文结构：二层结构之并列。先介绍北大西洋暖流的成因；\n再介绍北大西洋暖流的影响。\nA. 北冰洋海冰与洋流的关系(缺主题词)\nB. 南北半球冬季的气候差异(缺主题词)\nC. 北大西洋暖流的成因与影响","matchScore":0.4247,"pairingMode":"content-similarity","order":12},{"marker":"⑭","content":"“A 且B”类选项概括全面，是正确答案概率很高，看到此类选项，直接考虑和原文一一对应即可。\nA选项、B选项未提及北大西洋暖流，可简单排除； D选项的“欧洲”表述有误，北大西洋影响的是西欧的气温，且该选项只提及影响未提及成因，片面，排除。","matchScore":0.3252,"pairingMode":"content-similarity","order":13}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300267,3,'中心理解题','“质疑”其实是最基本的科学精神。对于以前的结果、结论甚至得到广泛证实和接受的理论体系，都需要以怀疑的眼光进行审视。但是“质疑”并不完全等同于“怀疑”,更不是全面否定。“质疑”实际上是评判地学习和批评地接受，其目的是发现以前工作的漏洞、缺陷、不完善、没有经过检验或者不能完全适用的地方。比如爱因斯坦对牛顿力学和牛顿引力理论质疑的结果，使其发现了牛顿力学和牛顿引力理论只有在低速和弱引力场的情况下才是正确的，否则就需要使用狭义相对论和广义相对论。
这段文字主要介绍“质疑”:','[{"label":"A","content":"作为科学基本精神的原因"},{"label":"B","content":"与怀疑的内在联系和区别"},{"label":"C","content":"对科学理论发展的重要性"},{"label":"D","content":"具有的内涵及其实践价值"}]','D','文段分析见批注。
文段略读后可从选项入手，D选项为“A 且B”类选项，可反推文段是否为“A 且B”结构：文段前三句可看作是介绍“质疑的内涵”,文段后两句介绍实践中质疑的价值并举例说明，与D选项一一对应，完美选项，当选；
A选项为原因类选项，但文段并非果因结构，后文并非都在解释“质疑作为科学基本精神”,排除； B选项为区别比较联系类，“怀疑”并非文段主体，文段并未重点介绍二者联系与区别，排除；C选项的“科学理论发展”出自举例部分，出处有误，排除。

花生批注：
⑤ 写作是全文论述主体。
⑨ 传记是全文论述主体。
⑪ A选项根据原文可知一定正确，D选项原文未直接提及，仅是可能正确，二者择优，选择A选项。
文段尾句观点为文段重点，正确答案应体现出“中国古典传记展现了生命活力”这一观点，对应B选项，当选；
A选项出处有误且绝对化，只对应文段首句但未体现生命活力，而且“最为生动记载”过于绝对，排除；C选项未包含主题词“传记”,排除；D选项为区别比较联系类选项，文段并未对二者进行比较分析，排除。
⑮ 行文结构：二层结构之“A 且B”。
前三句在介绍质疑的内涵；后两句介绍质疑在实践中的价值并举例说明。
