INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300268,3,'中心理解题','“非物质文化遗产”概念兴起的最初几年，群众对它的理解大多为“跟主流、大众不一样”“已经没用了”。然而，非遗不是“物”,今天“用不上”,偏离大众的非遗，恰是过去百姓最“有用”的日常生活，是历史中由普通民众以“物”与“用”为根本需求构建起的精神体系：以人为主体，以物质为媒介，以口传心授为途径，将世代积淀的思想、观念和方法论，传导到社会生态链的各个序列。在近代特定历史和社会背景下，它长期呈现为“无用”的状态，却具有固定且持续变化的价值——其塑造了整个民族的审美和人格，赋予了个体独特的生活情趣。
这段文字意在说明：','[{"label":"A","content":"大众对非遗的认知和理解有失偏颇"},{"label":"B","content":"应该结合非遗所属的历史时期来评价它的价值"},{"label":"C","content":"非遗看似“无用”却对塑造民族性格有重要价值"},{"label":"D","content":"对于非遗的理解会影响整个社会生态链的各个环节"}]','C','文段分析见批注。
文段在引出并分析话题后，给出观点：非遗尽管长期“无用”,但有特殊价值，对应C选项，C选项可看作是“A 且B 类”完美选项，当选；
A选项，出自文段话题引入部分，出处有误，排除； B选项，文段没体现问题也没给对策，“应该结合所属历史时期评价价值”无中生有，排除；D选项，杂糅选项⑨,排除。

花生批注：
⑯ “非物质文化遗产”为全文论述话题。
⑰ 行文结构：后观点结构。
引出话题：非遗貌似没用；接着进行分析介绍；
最后给出观点：非遗尽管长期“无用”,但有特殊价值。
⑧ 重要价值：塑造了整个民族的审美和人格，赋予了个体独特的生活情趣
这段文字意在说明：
A. 大众对非遗的认知和理解有失偏颇(出处有误)
B. 应该结合非遗所属的历史时期来评价它的价值(无中生有)
C. 非遗看似“无用”却对塑造民族性格有重要价值⑧( A 且B 类 )
⑲ 对非遗的理解出自文段开头“群众对它的理解”,“生态链的各个序列”出自解释说明部分，二者无关联。','2021年事业单位联考','基础','published','{"globalNumber":268,"setNumber":14,"localNumber":8,"sourceLabel":"2021年事业单位联考 73%","accuracy":73,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"“非物质文化遗产”概念兴起的最初几年，群众对它的理解大多为“跟主流、大众不一样”“已经没用了”。然而，非遗不是“物”,今天“用不上”,偏离大众的非遗，恰是过去百姓最“有用”的日常生活，是历史中由普通民众以“物”与“用”为根本需求构建起的精神体系：以人为主体，以物质为媒介，以口传心授为途径，将世代积淀的思想、观念和方法论，传导到社会生态链的各个序列。在近代特定历史和社会背景下，它长期呈现为“无用”的状态，却具有固定且持续变化的价值——其塑造了整个民族的审美和人格，赋予了个体独特的生活情趣。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"大众对非遗的认知和理解有失偏颇"}],"B":[{"text":"应该结合非遗所属的历史时期来评价它的价值"}],"C":[{"text":"非遗看似“无用”却对塑造民族性格有重要价值"}],"D":[{"text":"对于非遗的理解会影响整个社会生态链的各个环节"}]},"annotatedStemRich":[{"text":"“"},{"text":"非物质文化遗产","underline":true},{"text":"⑩”概念兴起的最初几年，群众对它的理解大多为“跟主流、大众不一样”“已经没用了”(引出话题)。然而，非遗不是“物”, 今天“用不上”,偏离大众的非遗，恰是过去百姓最“有用”的日常生活，是历史中由普通民众以“物”与“用”为根本需求构建起的精神体系：以人为主体，以物质为媒介，以口传心授为途径，将世代积淀的思想、观念和方法论，传导到社会生态链的各个序列(分析介绍)。在近代特定历史和社会背景下，它长期呈现为“无用”的状态，却具有固定且持续变化的价值——其塑造了整个民族的审美和人格，赋予了个体独特的生活情趣(后观点)。①\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"大众对非遗的认知和理解有失偏颇(出处有误)"}],"B":[{"text":"应该结合非遗所属的历史时期来评价它的价值(无中生有)"}],"C":[{"text":"非遗看似“无用”却对塑造民族性格有"},{"text":"重要价值","underline":true},{"text":"⑧( A 且B 类 )"}],"D":[{"text":"对于非遗的理解会影响整个社会生态链的各个环节"},{"text":"(杂糅)","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段在引出并分析话题后，给出观点：非遗尽管长期“无用”,但有特殊价值，对应C选项，C选项可看作是“A 且B 类”完美选项，当选；\nA选项，出自文段话题引入部分，出处有误，排除； B选项，文段没体现问题也没给对策，“应该结合所属历史时期评价价值”无中生有，排除；D选项，杂糅选项⑨,排除。","notes":[{"marker":"⑯","content":"“非物质文化遗产”为全文论述话题。","matchScore":0.5726,"pairingMode":"content-similarity","order":15},{"marker":"⑰","content":"行文结构：后观点结构。\n引出话题：非遗貌似没用；接着进行分析介绍；\n最后给出观点：非遗尽管长期“无用”,但有特殊价值。","matchScore":0.7048,"pairingMode":"content-similarity","order":16},{"marker":"⑧","content":"重要价值：塑造了整个民族的审美和人格，赋予了个体独特的生活情趣\n这段文字意在说明：\nA. 大众对非遗的认知和理解有失偏颇(出处有误)\nB. 应该结合非遗所属的历史时期来评价它的价值(无中生有)\nC. 非遗看似“无用”却对塑造民族性格有重要价值⑧( A 且B 类 )","matchScore":0.71,"pairingMode":"marker-and-content","order":17},{"marker":"⑲","content":"对非遗的理解出自文段开头“群众对它的理解”,“生态链的各个序列”出自解释说明部分，二者无关联。","matchScore":0.6029,"pairingMode":"content-similarity","order":18}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300269,3,'细节判断类','为了生存，植物必须对周边“视觉”环境的动态了如指掌。为此它们需要知道光的方向、强度、持续时间和颜色。毫无疑问，植物可以察觉人类可见的和不可见的电磁波。我们只能感知波长范围较窄的一段电磁波，植物却能感知到波长更短或更长的电磁波。不过，尽管植物能“看”到的光谱的波长范围要比我们能看到的宽广得多，它们却“看”不到图像。植物没有神经系统，不能把光信号转化为图像，但是能够转化成调控生长的种种指示。植物没有眼睛，正如我们没有叶子，但是植物和我们都能察觉到光。
下列说法与文意相符的是：','[{"label":"A","content":"植物能看到人类可见或不可见的图像"},{"label":"B","content":"植物通过把调控生长的指示转化为光信号来感知环境"},{"label":"C","content":"植物利用神经系统感知波长"},{"label":"D","content":"植物和人类一样有“视觉”"}]','D','D选项的“视觉”一词带有双引号，具有比喻含义。根据文段的“植物必须对周边‘视觉’环境的动态了如指掌”、“植物能‘看’到的光谱的波长范围要比我们能看到的宽广得多”、“植物和我们都能察觉到光”可知，此处“视觉”是指植物能用感应电磁波的方式达到和人类一样有“视觉”, D选项与文意相符，当选。

花生批注：
② 根据⑤句可知，植物“看”不到图像。
② 根据⑥句可知，植物能把光信号转化成调控生长的指示。
②2 根据④句可知，植物能感知的是波长更短或更长的电磁波，而非感知波长；
而且根据⑥句可知，植物没有神经系统。
下列说法与文意相符的是：
A. 植物能看到人类可见或不可见的图像 (本身有误)
B. 植物通过把调控生长的指示转化为光信号来感知环境②(本身有误)
C. 植物利用神经系统感知波长②(本身有误)
D. 植物和人类一样有“视觉”','2019年辽宁营口事业单位','进阶','published','{"globalNumber":269,"setNumber":14,"localNumber":9,"sourceLabel":"2019年辽宁营口事业单位67%","accuracy":67,"typeAndPassage":"细节判断类","stemRich":[{"text":"为了生存，植物必须对周边“视觉”环境的动态了如指掌。为此它们需要知道光的方向、强度、持续时间和颜色。毫无疑问，植物可以察觉人类可见的和不可见的电磁波。我们只能感知波长范围较窄的一段电磁波，植物却能感知到波长更短或更长的电磁波。不过，尽管植物能“看”到的光谱的波长范围要比我们能看到的宽广得多，它们却“看”不到图像。植物没有神经系统，不能把光信号转化为图像，但是能够转化成调控生长的种种指示。植物没有眼睛，正如我们没有叶子，但是植物和我们都能察觉到光。\n下列说法与文意相符的是："}],"optionRich":{"A":[{"text":"植物能看到人类可见或不可见的图像"}],"B":[{"text":"植物通过把调控生长的指示转化为光信号来感知环境"}],"C":[{"text":"植物利用神经系统感知波长"}],"D":[{"text":"植物和人类一样有“视觉”"}]},"annotatedStemRich":[{"text":"①为了生存，植物必须对周边“视觉”环境的动态了如指掌。②为此它们需要知道光的方向、强度、持续时间和颜色。③毫无疑问，植物可以察觉人类可见的和不可见的电磁波。④我们只能感知波长范围较窄的一段电磁波，植物却能感知到波长更短或更长的电磁波。⑤不过，尽管植物能“看”到的光谱的波长范围要比我们能看到的宽广得多，它们却“看”不到图像 ( A选项)。⑥ 植物没有神经系统( C 选项 ) ,不能把光信号转化为图像，但是能够转化成调控生长的种种指示( B 选项 ) 。⑦植物没有眼睛，正如我们没有叶子，但是植物和我们都能察觉到光。\n下列说法与文意相符的是："}],"annotatedOptionRich":{"A":[{"text":"植物能看到人类可见或不可见的图像 (本身有误)"}],"B":[{"text":"植物通过把调控生长的指示转化为光信号来感知环境②(本身有误)"}],"C":[{"text":"植物利用神经系统感知波长②(本身有误)"}],"D":[{"text":"植物和人类一样有“视觉”"}]},"practicalAnalysis":"D选项的“视觉”一词带有双引号，具有比喻含义。根据文段的“植物必须对周边‘视觉’环境的动态了如指掌”、“植物能‘看’到的光谱的波长范围要比我们能看到的宽广得多”、“植物和我们都能察觉到光”可知，此处“视觉”是指植物能用感应电磁波的方式达到和人类一样有“视觉”, D选项与文意相符，当选。","notes":[{"marker":"②","content":"根据⑤句可知，植物“看”不到图像。","matchScore":0.661,"pairingMode":"marker-and-content","order":19},{"marker":"②","content":"根据⑥句可知，植物能把光信号转化成调控生长的指示。","matchScore":0.8683,"pairingMode":"marker-and-content","order":20},{"marker":"②2","content":"根据④句可知，植物能感知的是波长更短或更长的电磁波，而非感知波长；\n而且根据⑥句可知，植物没有神经系统。\n下列说法与文意相符的是：\nA. 植物能看到人类可见或不可见的图像 (本身有误)\nB. 植物通过把调控生长的指示转化为光信号来感知环境②(本身有误)\nC. 植物利用神经系统感知波长②(本身有误)\nD. 植物和人类一样有“视觉”","matchScore":0.7388,"pairingMode":"content-similarity","order":21}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300270,3,'中心理解题','学术资源是一种权益，尤其是知识产权的保护，已经成为推动和保障现代学术健康发展的基础和柱石。然而，学术资源更有一种公共属性，尤其对那些接受纳税人投资进行科学研究的研究者来说，更有必要保证自己的研究成果能够成为社会公共知识资源的一部分，保证社会能够利用这些研究成果提升国民素质，保证公众能够自由方便地利用这些科学成果。因此，在尊重知识产权和不违背版权法的前提下，增强学术资源的公共性，保障学术资源的无障碍传播，不仅是推进科学研究的基本要求，也是尊重和保障公众信息权利的体现。
这段文字意在强调：','[{"label":"A","content":"知识产权保护推动了现代学术发展"},{"label":"B","content":"应逐步增强学术资源获取的开放性"},{"label":"C","content":"学术资源讲权益的同时更要讲公益"},{"label":"D","content":"学术资源拥有者应让渡出部分权益"}]','C','文段分析见批注。
文段先介绍保护学术资源知识产权的必要性，又强调学术资源的公共属性更重要，尾句通过语义给出对策“要在尊重知识产权的前提下，增强学术资源公共性.保障无障碍传播”.C选项的“讲权益更要讲公益”是对“尊重知识产权、增强公共性”的同义替换，C选项③当选；
A选项未体现对策，排除；B选项的“增强学术资源获取的开放性②”和 D选项的“让渡出部分权益”均无中生有，属于对策有误，排除。

花生批注：
3 学术资源是全文论述话题。
④ 可翻译为：想要推进科学研究、尊重和保障公众信息权利，需要增强学术资源的公共性，保障学术资源的无障碍传播。
对策重点是“增强学术资源的公共性”。
25 行文结构：后对策结构。
通过转折进行介绍：
学术资源是一种权益，保护其知识产权很重要；但
学术资源更有一种公共属性，使其成为社会公共知识资源的一部分更重要；
最后总结并提出对策：
要在尊重学术资源知识产权的前提下，增强其公共性，保障无障碍传播。
6 A 且B类选项，既强调要尊重学术资源的权益，又强调了要增强其公益性，完美选项。','2017年四川省考','进阶','published','{"globalNumber":270,"setNumber":14,"localNumber":10,"sourceLabel":"2017年四川省考 59%","accuracy":59,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"学术资源是一种权益，尤其是知识产权的保护，已经成为推动和保障现代学术健康发展的基础和柱石。然而，学术资源更有一种公共属性，尤其对那些接受纳税人投资进行科学研究的研究者来说，更有必要保证自己的研究成果能够成为社会公共知识资源的一部分，保证社会能够利用这些研究成果提升国民素质，保证公众能够自由方便地利用这些科学成果。因此，在尊重知识产权和不违背版权法的前提下，增强学术资源的公共性，保障学术资源的无障碍传播，不仅是推进科学研究的基本要求，也是尊重和保障公众信息权利的体现。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"知识产权保护推动了现代学术发展"}],"B":[{"text":"应逐步增强学术资源获取的开放性"}],"C":[{"text":"学术资源讲权益的同时更要讲公益"}],"D":[{"text":"学术资源拥有者应让渡出部分权益"}]},"annotatedStemRich":[{"text":"学术资源","underline":true},{"text":"是一种权益，尤其是知识产权的保护，已经成为推动和保障现代学术健康发展的基础和柱石(引出话题)。然而，学术资源更有一种公共属性，尤其对那些接受纳税人投资进行科学研究的研究者来说，更有必要保证自己的研究成果能够成为社会公共知识资源的一部分，保证社会能够利用这些研究成果提升国民素质，保证公众能够自由方便地利用这些科学成果(分析论证)。"},{"text":"因此，在尊重知识产权和不违背版权法的前提下，增强学术资源的公共性，保障学术资源的无障碍传播，不仅是推进科学研究的基本要求，也是尊重和保障公众信息权利的体现","underline":true},{"text":" (语义表对策)。②\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"知识产权保护推动了现代学术发展(出处有误)"}],"B":[{"text":"应逐步增强学术资源获取的开放性(对策有误)"}],"C":[{"text":"学术资源讲权益的同时更要讲公益"}],"D":[{"text":"学术资源拥有者应让渡出部分权益(对策有误)\n片段阅读600 "},{"text":"四","bold":true},{"text":"(上册)\n"},{"text":"6花生批注：","bold":true},{"text":"\nA 且B类选项，既强调要尊重学术资源的权益，又强调了要增强其公益性，完美选项。\n"},{"text":"花生批注：","bold":true},{"text":"\n增强获取的开放性，即学术资源容易获取，不代表要增强学术资源的公共性。\n"},{"text":"8花生批注：","bold":true},{"text":"\n"},{"text":"行文结构：","bold":true},{"text":"后对策结构。\n先引出话题，强调“文学经典”的重要性；\n再分析论证；\n尾句语义表对策：\n要将传承和弘扬文学经典作为重大战略。"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍保护学术资源知识产权的必要性，又强调学术资源的公共属性更重要，尾句通过语义给出对策“要在尊重知识产权的前提下，增强学术资源公共性.保障无障碍传播”.C选项的“讲权益更要讲公益”是对“尊重知识产权、增强公共性”的同义替换，C选项③当选；\nA选项未体现对策，排除；B选项的“增强学术资源获取的开放性②”和 D选项的“让渡出部分权益”均无中生有，属于对策有误，排除。","notes":[{"marker":"3","content":"学术资源是全文论述话题。","matchScore":0.5214,"pairingMode":"marker-and-content","order":22},{"marker":"④","content":"可翻译为：想要推进科学研究、尊重和保障公众信息权利，需要增强学术资源的公共性，保障学术资源的无障碍传播。\n对策重点是“增强学术资源的公共性”。","matchScore":0.814,"pairingMode":"content-similarity","order":23},{"marker":"25","content":"行文结构：后对策结构。\n通过转折进行介绍：\n学术资源是一种权益，保护其知识产权很重要；但\n学术资源更有一种公共属性，使其成为社会公共知识资源的一部分更重要；\n最后总结并提出对策：\n要在尊重学术资源知识产权的前提下，增强其公共性，保障无障碍传播。","matchScore":0.8143,"pairingMode":"content-similarity","order":24},{"marker":"6","content":"A 且B类选项，既强调要尊重学术资源的权益，又强调了要增强其公益性，完美选项。","matchScore":0.4138,"pairingMode":"content-similarity","order":25}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300271,3,'中心理解题','文学经典对于一个民族及其文化的繁荣昌盛至关重要。一方面，它是一个民族在历史长河中艺术性和审美化的创造，集中表现了这个民族的核心价值和道德理想，成为维系民族内部成员集体记忆的情感纽带；另一方面，也是一个民族独特的精神创造，其中呈现的美学风格和艺术魅力也成为其不同于其他民族的精神徽章和文化标志，是最易辨识的文化品牌。正是由于文学经典拥有巨大的价值主导力、文化吸引力和审美感召力，当前国际社会普遍将传承和弘扬本民族的文学经典作为构建民族价值认同、塑造国家良好形象和提升文化软实力的重大战略。
这段文字意在强调：','[{"label":"A","content":"文学经典承载了一个民族的价值观和道德理想"},{"label":"B","content":"文学经典的传承和弘扬应成为国家的文化战略"},{"label":"C","content":"文学经典对民族发展有举足轻重的作用"},{"label":"D","content":"文学经典是一个民族的集体记忆"}]','B','文段分析见批注。
文段先介绍文学经典的重要性，尾句通过国际社会的普遍做法突出如何利用好文学经典，即“将传承和弘扬本民族的文学经典作为重大战略”,对应B选项，当选；
A选项和D选项出自文段分析论证部分的“一方面”, C选项出自文段引出话题部分，出处均有误，均可简单排除。

花生批注：
8 行文结构：后对策结构。
先引出话题，强调“文学经典”的重要性；
再分析论证；
尾句语义表对策：
要将传承和弘扬文学经典作为重大战略。','2017年四川省考','进阶','published','{"globalNumber":271,"setNumber":14,"localNumber":11,"sourceLabel":"2017年四川省考 60%","accuracy":60,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"文学经典对于一个民族及其文化的繁荣昌盛至关重要。一方面，它是一个民族在历史长河中艺术性和审美化的创造，集中表现了这个民族的核心价值和道德理想，成为维系民族内部成员集体记忆的情感纽带；另一方面，也是一个民族独特的精神创造，其中呈现的美学风格和艺术魅力也成为其不同于其他民族的精神徽章和文化标志，是最易辨识的文化品牌。正是由于文学经典拥有巨大的价值主导力、文化吸引力和审美感召力，当前国际社会普遍将传承和弘扬本民族的文学经典作为构建民族价值认同、塑造国家良好形象和提升文化软实力的重大战略。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"文学经典承载了一个民族的价值观和道德理想"}],"B":[{"text":"文学经典的传承和弘扬应成为国家的文化战略"}],"C":[{"text":"文学经典对民族发展有举足轻重的作用"}],"D":[{"text":"文学经典是一个民族的集体记忆"}]},"annotatedStemRich":[{"text":"文学经典对于一个民族及其文化的繁荣昌盛至关重要(引出话题)。一方面，它是一个民族在历史长河中艺术性和审美化的创造，集中表现了这个民族的核心价值和道德理想，成为维系民族内部成员集体记忆的情感纽带；另一方面，也是一个民族独特的精神创造，其中呈现的美学风格和艺术魅力也成为其不同于其他民族的精神徽章和文化标志，是最易辨识的文化品牌(解释分析)。正是由于文学经典拥有巨大的价值主导力、文化吸引力和审美感召力，当前国际社会普遍将传承和弘扬本民族的文学经典作为构建民族价值认同、塑造国家\n良好形象和提升文化软实力的重大战略(提出对策)。② 这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"文学经典承载了一个民族的价值观和道德理想(出处有误)"}],"B":[{"text":"文学经典的传承和弘扬应成为国家的文化战略"}],"C":[{"text":"文学经典对民族发展有举足轻重的作用 (出处有误)"}],"D":[{"text":"文学经典是一个民族的集体记忆(出处有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍文学经典的重要性，尾句通过国际社会的普遍做法突出如何利用好文学经典，即“将传承和弘扬本民族的文学经典作为重大战略”,对应B选项，当选；\nA选项和D选项出自文段分析论证部分的“一方面”, C选项出自文段引出话题部分，出处均有误，均可简单排除。","notes":[{"marker":"8","content":"行文结构：后对策结构。\n先引出话题，强调“文学经典”的重要性；\n再分析论证；\n尾句语义表对策：\n要将传承和弘扬文学经典作为重大战略。","matchScore":0.6975,"pairingMode":"content-similarity","order":26}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300272,3,'中心理解题','单看日渐升温的机器换人热潮，在目前劳动力供给偏紧的背景中，它对就业还未见明显的负面影响。而且，科技革命带来的产业深化、分工细化，还可能衍生出更多的就业机会。但是，那种决然否认机器换人和充分就业并不矛盾的说法未免过于乐观。在当下，从事重复性、常规性、高危性工作的员工，最有可能在人机竞争中先被淘汰出局。面对科技的更新，我们在结构改革中还不能轻易放弃有利于增加就业含量的传统制造业，还需要加快发展有利于吸纳就业人口的现代服务业。
这段文字意在强调：','[{"label":"A","content":"发展传统制造业和现代服务业有利于就业"},{"label":"B","content":"应该对日渐升温的机器换人热潮进行理性评估"},{"label":"C","content":"科技更新可以为缓解当前的就业压力提供新思路"},{"label":"D","content":"结构改革中应注意采取措施缓解机器对就业的冲击"}]','D','文段分析见批注。
文段指出的问题是“机器换人和人的充分就业存在矛盾”,即机器影响人的就业，并给出对策“结构改革中既要发展传统制造业，又要发展现代服务业”来解决这一问题；
B选项的对策“理性评估机器换人”既不贴合文末对策也不针对问题，排除； C选项的对策“科技更新”和问题“缓解就业压力”均与文段不一致，排除；
A选项可翻译为“解决就业问题应发展传统制造业和现代服务业”,虽然对策具体，但未体现问题；
D选项的问题为“结构改革中机器对就业的冲击”,对策概括为“采取措施”,虽然对策并不具体，但问题恰当；
用“反推法”验证，根据D选项更容易推知原文所述内容；
综上，正确答案是D选项。

花生批注：
9 行文结构：后对策结构。
先转折引出问题：
机器换人和充分就业仍然存在矛盾；
再分析问题：
在人机竞争中一些重复性、常规性、高危性岗位存在被淘汰可能；
最后提出对策：
在结构改革中不能放弃传统制造业，同时需要加快发展现代服务业。','2017年四川省考','进阶','published','{"globalNumber":272,"setNumber":14,"localNumber":12,"sourceLabel":"2017年四川省考 53%","accuracy":53,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"单看日渐升温的机器换人热潮，在目前劳动力供给偏紧的背景中，它对就业还未见明显的负面影响。而且，科技革命带来的产业深化、分工细化，还可能衍生出更多的就业机会。但是，那种决然否认机器换人和充分就业并不矛盾的说法未免过于乐观。在当下，从事重复性、常规性、高危性工作的员工，最有可能在人机竞争中先被淘汰出局。面对科技的更新，我们在结构改革中还不能轻易放弃有利于增加就业含量的传统制造业，还需要加快发展有利于吸纳就业人口的现代服务业。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"发展传统制造业和现代服务业有利于就业"}],"B":[{"text":"应该对日渐升温的机器换人热潮进行理性评估"}],"C":[{"text":"科技更新可以为缓解当前的就业压力提供新思路"}],"D":[{"text":"结构改革中应注意采取措施缓解机器对就业的冲击"}]},"annotatedStemRich":[{"text":"单看日渐升温的机器换人热潮，在目前劳动力供给偏紧的背景中，它对就业还未见明显的负面影响。而且，科技革命带来的产业深化、分工细化，还可能衍生出更多的就业机会。但是，那种决然否认机器换人和充分就业并不矛盾的说法未免过于乐观"},{"text":"(转折引出问题)。","bold":true},{"text":"在当下，从事重复性、常规性、高危性工作的员工，最有可能在人机竞争中先被淘汰出局 (分析问题)。面对科技的更新，我们在结构改革中还不能轻易放弃有利于增加就业含量的传统制造业，还需要加快发展有利于吸纳就业人口的现代服务业(后对策)。②\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"发展传统制造业和现代服务业有利于就业(缺少问题)"}],"B":[{"text":"应该对日渐升温的机器换人热潮进行理性评估(对策有误)"}],"C":[{"text":"科技更新可以为缓解当前的就业压力提供新思路(对策有误)"}],"D":[{"text":"结构改革中应注意采取措施缓解机器对就业的冲击"}]},"practicalAnalysis":"文段分析见批注。\n文段指出的问题是“机器换人和人的充分就业存在矛盾”,即机器影响人的就业，并给出对策“结构改革中既要发展传统制造业，又要发展现代服务业”来解决这一问题；\nB选项的对策“理性评估机器换人”既不贴合文末对策也不针对问题，排除； C选项的对策“科技更新”和问题“缓解就业压力”均与文段不一致，排除；\nA选项可翻译为“解决就业问题应发展传统制造业和现代服务业”,虽然对策具体，但未体现问题；\nD选项的问题为“结构改革中机器对就业的冲击”,对策概括为“采取措施”,虽然对策并不具体，但问题恰当；\n用“反推法”验证，根据D选项更容易推知原文所述内容；\n综上，正确答案是D选项。","notes":[{"marker":"9","content":"行文结构：后对策结构。\n先转折引出问题：\n机器换人和充分就业仍然存在矛盾；\n再分析问题：\n在人机竞争中一些重复性、常规性、高危性岗位存在被淘汰可能；\n最后提出对策：\n在结构改革中不能放弃传统制造业，同时需要加快发展现代服务业。","matchScore":0.8147,"pairingMode":"content-similarity","order":27}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300273,3,'下文推断类','长期以来，石墨一直是锂离子电池的关键组成部分。这种碳导电且稳定，非常适合在充电时将锂离子填充到电池的阳极中。但随着对更高能量密度电池需求的不断增加，石墨基电极也需要升级，而硅被认为是一种很好的升级版材料。与石墨相比，硅可以吸收更多的锂，但问题是，硅在遇到锂时会大幅膨胀，可能会导致锂电池阳极破裂粉化。
接下来文章最可能讲述的是：','[{"label":"A","content":"攻克锂电池阳极粉化难题的重要性"},{"label":"B","content":"开发锂离子电池硅基阳极的必要性"},{"label":"C","content":"硅是如何提高锂离子电池的性能的"},{"label":"D","content":"如何解决石墨基电池中的主要问题"}]','A','文段文末提出问题：硅可能会导致锂电池阳极破裂粉化；下文应分析或解决这一问题，只有A选项提及该问题，分析攻克这一难题的重要性，符合常见行文逻辑“提出问题→分析问题”,当选；
B选项、C选项未提及“硅导致锂电池阳极破裂粉化”这一问题，D选项谈的是“石墨基电池”,未提及新材料“硅”,均可简单排除。

