INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300274,3,'中心理解题','词典有其自身生命周期。一部优秀词典的使命就包括通过修订以适应日新月异的语言生活，并在语言生活中发挥其规范语言使用、示例雅正用法的作用。将雅正语言巩固于语言生活之中，又不固守陈俗、能反映时代变化，这两者间需要智慧的平衡。从这个角度讲，规范词典的修订，从来都是语言生活中的一件大事。
四海公考练习题14套
这段文字主要说明了：','[{"label":"A","content":"如今词典的使用方式正面临巨大变革"},{"label":"B","content":"规范词典的修订有助于扩大语言的应用范围"},{"label":"C","content":"词典是权威知识的查询入口"},{"label":"D","content":"词典是语言规范的承载者和语言生活的描述者"}]','B','文段分析见批注。
文段结构较混乱，但引出话题后，均在谈论“词典修订”,而非“词典”, 且文末可看作对策：要规范词典的修订；只有B选项提及“规范词典修正”当选③;
其他选项均在介绍“词典”,偏离主题，均可排除。

花生批注：
③ “从这个角度讲”是对前文的概括，可知前文并非表述重点；
尾句可看作语义表对策，“规范词典修订”为对策重点。
例如：从这个角度讲，考前重画思维导图，从来都是复习的一件大事：即考前要重画思维导图。
③ 行文结构：后对策结构。文段首句引出话题；
之后介绍词典修订的意义： ①适应新语言；②规范语言使用；③示例雅正用法；
再介绍词典修订的要求：① 要巩固雅正语言；②要反映时代变化；
文末语义表对策：要规范词典修订。
33 B选项可翻译为：扩大语言的应用范围应规范词典修订。
虽然B选项的“扩大语言的应用范围”有些无中生有，但可勉强将其看作是对词典修订意义的概括；
并且与其他选项未提及“词典修订”相比，问题较轻微，需抓大放小。','2023年福建省事业单位','挑战','published','{"globalNumber":274,"setNumber":14,"localNumber":14,"sourceLabel":"2023年福建省事业单位42%","accuracy":42,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"词典有其自身生命周期。一部优秀词典的使命就包括通过修订以适应日新月异的语言生活，并在语言生活中发挥其规范语言使用、示例雅正用法的作用。将雅正语言巩固于语言生活之中，又不固守陈俗、能反映时代变化，这两者间需要智慧的平衡。从这个角度讲，规范词典的修订，从来都是语言生活中的一件大事。\n"},{"text":"四海公考练习题14套","bold":true},{"text":"\n这段文字主要说明了："}],"optionRich":{"A":[{"text":"如今词典的使用方式正面临巨大变革"}],"B":[{"text":"规范词典的修订有助于扩大语言的应用范围"}],"C":[{"text":"词典是权威知识的查询入口"}],"D":[{"text":"词典是语言规范的承载者和语言生活的描述者"}]},"annotatedStemRich":[{"text":"词典有其自身生命周期(引出话题)。一部优秀词典的使命就包括通过修订以适应日新月异的语言生活，并在语言生活中发挥其规范语言使用、示例雅正用法的作用。将雅正语言巩固于语言生活之中，又不固守陈俗、能反映时代变化，这两者间需要智慧的平衡(分析介绍)。"},{"text":"从这个角度讲，规范词典的修订，从来都是语言生活中的一件大事","underline":true},{"text":"③(语义表对策)。\n这段文字主要说明了："}],"annotatedOptionRich":{"A":[{"text":"如今词典的使用方式正面临巨大变革(缺主题词)"}],"B":[{"text":"规范词典的修订有助于扩大语言的应用范围"}],"C":[{"text":"词典是权威知识的查询入口(缺主题词)"}],"D":[{"text":"词典是语言规范的承载者和语言生活的描述者(缺主题词)"}]},"practicalAnalysis":"文段分析见批注。\n文段结构较混乱，但引出话题后，均在谈论“词典修订”,而非“词典”, 且文末可看作对策：要规范词典的修订；只有B选项提及“规范词典修正”当选③;\n其他选项均在介绍“词典”,偏离主题，均可排除。","notes":[{"marker":"③","content":"“从这个角度讲”是对前文的概括，可知前文并非表述重点；\n尾句可看作语义表对策，“规范词典修订”为对策重点。\n例如：从这个角度讲，考前重画思维导图，从来都是复习的一件大事：即考前要重画思维导图。","matchScore":0.5063,"pairingMode":"marker-and-content","order":29},{"marker":"③","content":"行文结构：后对策结构。文段首句引出话题；\n之后介绍词典修订的意义： ①适应新语言；②规范语言使用；③示例雅正用法；\n再介绍词典修订的要求：① 要巩固雅正语言；②要反映时代变化；\n文末语义表对策：要规范词典修订。","matchScore":0.7561,"pairingMode":"marker-and-content","order":30},{"marker":"33","content":"B选项可翻译为：扩大语言的应用范围应规范词典修订。\n虽然B选项的“扩大语言的应用范围”有些无中生有，但可勉强将其看作是对词典修订意义的概括；\n并且与其他选项未提及“词典修订”相比，问题较轻微，需抓大放小。","matchScore":0.2445,"pairingMode":"content-similarity","order":31}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300275,3,'中心理解题','5 G 时代的推进，一方面促使内容产业要与技术产业保持同步且深度融合，另一方面也意味着原有单个产业链条之间在产业利润上的分配博弈。5G 时代下呈现融合发展的数字创意产业生态，应该是一条比传统条件下更简洁的产业链条。内容生产端与消费端之间更为垂直与扁平，以保障产业利润分配链条的简洁性。这是数字创意产业价值分配变革的第一个层次。在传统文化创意产业市场中，技术载体或技术平台往往占据更有利的位置，而进入5G 推广与成熟阶段，去中心化效应将大大降低技术平台的价值分配权限，逐渐形成以内容生产端为核心的产业价值分配模式，这是第二个分配变革层次。
这段文字意在强调：','[{"label":"A","content":"5G 建设推进数字创意产业价值的分配变革"},{"label":"B","content":"5G 建设高效赋能数字创意产业高质量发展"},{"label":"C","content":"5G 技术促使内容产业与技术产业深度融合"},{"label":"D","content":"5G 技术平台和载体逐步进入了推广成熟期"}]','A','文段分析见批注。
文段主要介绍了“5G 时代的数字创意产业价值分配两个层次的变革”, 对应A选项，当选；
B选项的“赋能高质量发展”无中生有；C选项片面，仅对应文段首句的“一方面”部分；D选项，缺少主题词“数字创意产业价值”,均可简单排除。

花生批注：
③④ 产业价值分配变革是全文论述话题。
35 行文结构：总分结构。
先总起引出下文：另一方面， 5G 时代推进产业利润上的分配博弈(“一方面促使内容产业与技术产业融合”在下文未提及，可能起到“承上”的作用);
再分别从“数字创意产业价值分配变革的第一个层次”和“第二个分配变革层次”两个层次具体介绍了5G 时代的数字创意产业价值分配两个层次的变革。','2022年事业单位联考','基础','published','{"globalNumber":275,"setNumber":14,"localNumber":15,"sourceLabel":"2022年事业单位联考72%","accuracy":72,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"5 G 时代的推进，一方面促使内容产业要与技术产业保持同步且深度融合，另一方面也意味着原有单个产业链条之间在产业利润上的分配博弈。5G 时代下呈现融合发展的数字创意产业生态，应该是一条比传统条件下更简洁的产业链条。内容生产端与消费端之间更为垂直与扁平，以保障产业利润分配链条的简洁性。这是数字创意产业价值分配变革的第一个层次。在传统文化创意产业市场中，技术载体或技术平台往往占据更有利的位置，而进入5G 推广与成熟阶段，去中心化效应将大大降低技术平台的价值分配权限，逐渐形成以内容生产端为核心的产业价值分配模式，这是第二个分配变革层次。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"5G 建设推进数字创意产业价值的分配变革"}],"B":[{"text":"5G 建设高效赋能数字创意产业高质量发展"}],"C":[{"text":"5G 技术促使内容产业与技术产业深度融合"}],"D":[{"text":"5G 技术平台和载体逐步进入了推广成熟期"}]},"annotatedStemRich":[{"text":"5G 时代的推进，一方面促使内容产业要与技术产业保持同步且深度融合，另一方面也意味着原有单个产业链条之间在产业利润上的分配博弈"},{"text":"(总)。5G ","bold":true},{"text":"时代下呈现融合发展的数字创意产业生态，应该是一条比传统条件下更简洁的产业链条。内容生产端与消费端之间更为垂直与扁平，以保障产业利润分配链条的简洁性。这是数字创意"},{"text":"产业价值分配变革","underline":true},{"text":"③的第一个层次"},{"text":"(","bold":true},{"text":" "},{"text":"分","bold":true},{"text":" "},{"text":"1","bold":true},{"text":" "},{"text":")","bold":true},{"text":" "},{"text":"。","bold":true},{"text":"在传统文化创意产业市场中，技术载体或技术平台往往占据更有利的位置，而进入5G推广与成熟阶段，去中心化效应将大大降低技术平台的价值分配权限，逐渐形成以内容生产端为核心的产业价值分配模式，这是第二个分配变革层次"},{"text":"(","bold":true},{"text":" "},{"text":"分","bold":true},{"text":" "},{"text":"2","bold":true},{"text":" "},{"text":")","bold":true},{"text":" "},{"text":"。","bold":true},{"text":"\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"5G 建设推进数字创意产业价值的分配变革"}],"B":[{"text":"5G 建设高效赋能数字创意产业高质量发展(无中生有)"}],"C":[{"text":"5G 技术促使内容产业与技术产业深度融合(片面)"}],"D":[{"text":"5G 技术平台和载体逐步进入了推广成熟期(缺主题词)"}]},"practicalAnalysis":"文段分析见批注。\n文段主要介绍了“5G 时代的数字创意产业价值分配两个层次的变革”, 对应A选项，当选；\nB选项的“赋能高质量发展”无中生有；C选项片面，仅对应文段首句的“一方面”部分；D选项，缺少主题词“数字创意产业价值”,均可简单排除。","notes":[{"marker":"③④","content":"产业价值分配变革是全文论述话题。","matchScore":0.5341,"pairingMode":"content-similarity","order":32},{"marker":"35","content":"行文结构：总分结构。\n先总起引出下文：另一方面， 5G 时代推进产业利润上的分配博弈(“一方面促使内容产业与技术产业融合”在下文未提及，可能起到“承上”的作用);\n再分别从“数字创意产业价值分配变革的第一个层次”和“第二个分配变革层次”两个层次具体介绍了5G 时代的数字创意产业价值分配两个层次的变革。","matchScore":0.7361,"pairingMode":"content-similarity","order":33}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300276,3,'中心理解题','随着我国对外开放深化和世界经济全球化加速，国际经济环境因素对我国宏观经济运行稳定性的影响越来越大，需要我们密切关注，谨慎对待。目前国际市场石油价格、粮食和食用油价格上涨对我国国内市场价格的影响越来越大，成为造成国内市场相关商品价格上涨的不可忽视的因素。这种输入型成本推动造成的价格上涨的影响，将随着我国对国外石油等重要资源性商品依赖程度的上升，而变得越来越大，可能成为推动价格上涨的长期因素，对此我们必须更加重视。
这段文字意在说明：','[{"label":"A","content":"我国输入型成本将随全球化程度的加深不断增高"},{"label":"B","content":"我国对外依赖型经济模式是价格上涨的原因之一"},{"label":"C","content":"国际市场价格对我国国内市场价格的影响很大"},{"label":"D","content":"要重视国际经济因素对我国经济稳定性的影响"}]','D','文段分析见批注。
文段开篇提出对策：我们要密切关注，谨慎对待国际经济环境因素对我国宏观经济运行稳定性的影响，直接对应D选项，当选；
A选项出自文段分析论证部分；B选项文段应该是果因类结构，重点谈价格上涨的原因，与文段不符；C选项为中性表达，文段有对策要选对策，均可简单排除。

花生批注：
36 行文结构：前对策结构。
先开门见山提出对策：我们要密切关注，谨慎对待国际经济环境因素对我国宏观经济运行稳定性的影响；
再对此对策进行分析论证；并在尾句强调：要重视国际市场价格对国内市场价格的影响。','2015年国家公务员考试','基础','published','{"globalNumber":276,"setNumber":14,"localNumber":16,"sourceLabel":"2015年国家公务员考试79%","accuracy":79,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"随着我国对外开放深化和世界经济全球化加速，国际经济环境因素对我国宏观经济运行稳定性的影响越来越大，需要我们密切关注，谨慎对待。目前国际市场石油价格、粮食和食用油价格上涨对我国国内市场价格的影响越来越大，成为造成国内市场相关商品价格上涨的不可忽视的因素。这种输入型成本推动造成的价格上涨的影响，将随着我国对国外石油等重要资源性商品依赖程度的上升，而变得越来越大，可能成为推动价格上涨的长期因素，对此我们必须更加重视。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"我国输入型成本将随全球化程度的加深不断增高"}],"B":[{"text":"我国对外依赖型经济模式是价格上涨的原因之一"}],"C":[{"text":"国际市场价格对我国国内市场价格的影响很大"}],"D":[{"text":"要重视国际经济因素对我国经济稳定性的影响"}]},"annotatedStemRich":[{"text":"随着我国对外开放深化和世界经济全球化加速，国际经济环境因素对我国宏观经济运行稳定性的影响越来越大，需要我们密切关注，谨慎对待(前对策)。目前国际市场石油价格、粮食和食用油价格上涨对我国国内市场价格的影响越来越大，成为造成国内市场相关商品价格上涨的不可忽视的因素。这种输入型成本推动造成的价格上涨的影响，将随着我国对国外石油等重要资源性商品依赖程度的上升，而变得越来越大，可能成为推动价格上涨的长期因素(分析论证 ) , 对此我们必须更加重视(重复对策)。⑧\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"我国输入型成本将随全球化程度的加深不断增高(出处有误)"}],"B":[{"text":"我国对外依赖型经济模式是价格上涨的原因之一(原因类选项)"}],"C":[{"text":"国际市场价格对我国国内市场价格的影响很大"},{"text":"(中性表达)","bold":true}],"D":[{"text":"要重视国际经济因素对我国经济稳定性的影响\n"},{"text":"36花生批注：","bold":true},{"text":"\n行文结构：前对策结构。\n"},{"text":"先开门见山提出对策：","bold":true},{"text":"我们要密切关注，谨慎对待国际经济环境因素对我国宏观经济运行稳定性的影响；\n再对此对策进行分析论证；并在尾句强调：要重视国际市场价格对国内市场价格的影响。"}]},"practicalAnalysis":"文段分析见批注。\n文段开篇提出对策：我们要密切关注，谨慎对待国际经济环境因素对我国宏观经济运行稳定性的影响，直接对应D选项，当选；\nA选项出自文段分析论证部分；B选项文段应该是果因类结构，重点谈价格上涨的原因，与文段不符；C选项为中性表达，文段有对策要选对策，均可简单排除。","notes":[{"marker":"36","content":"行文结构：前对策结构。\n先开门见山提出对策：我们要密切关注，谨慎对待国际经济环境因素对我国宏观经济运行稳定性的影响；\n再对此对策进行分析论证；并在尾句强调：要重视国际市场价格对国内市场价格的影响。","matchScore":0.8664,"pairingMode":"content-similarity","order":34}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300277,3,'语句排序类','①压力面前，一些人声称理想很丰满、现实很骨感
②在他们看来，只有为个人利益而活着才是最现实和最有意义的
③还有一些人在理想与现实反差的所谓痛苦中不能自拔，迷茫和沉沦
④一些人甚至开始奚落崇高、嘲笑理想
⑤正因如此，那些真正为理想而活着的人，才显得格外难能可贵
⑥岁月的淘洗中，坚守理想并不是一件容易的事
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"①④③②⑥⑤"},{"label":"B","content":"⑥①④②③⑤①"},{"label":"C","content":"①④②③⑤⑥"},{"label":"D","content":"⑥①②③⑤④\n片段阅读6 00 0(上册)"}]','B','由于本题①⑥不好确定首句，可先根据内容分堆：
①②③④介绍的都是“不能坚守理想”的一些人，属于具体分析；⑤通过“因此”总结观点“真正为理想而活的人，难能可贵”,⑥通过“坚守理想不是一件容易的事”引出下文；
因此，大体顺序应为⑥→①②③④→⑤,锁定B选项，当选。

花生批注：
③ 行文结构：后观点结构。
⑥引出话题“坚守理想不容易”;
①④②③介绍不能坚守理想的人，其中，①④②介绍的是因利益不能坚守理想的人，③介绍的是在理想与现实反差中痛苦迷茫沉沦的人；
⑤通过“正因如此”给出观点：“坚守理想的人更难能可贵”。','2021年四川省考','进阶','published','{"globalNumber":277,"setNumber":14,"localNumber":17,"sourceLabel":"2021年四川省考 62%","accuracy":62,"typeAndPassage":"语句排序类+说理类文章","stemRich":[{"text":"①压力面前，一些人声称理想很丰满、现实很骨感\n②在他们看来，只有为个人利益而活着才是最现实和最有意义的\n③还有一些人在理想与现实反差的所谓痛苦中不能自拔，迷茫和沉沦\n④一些人甚至开始奚落崇高、嘲笑理想\n⑤正因如此，那些真正为理想而活着的人，才显得格外难能可贵\n⑥岁月的淘洗中，坚守理想并不是一件容易的事\n将以上6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"①④③②⑥⑤"}],"B":[{"text":"⑥①④②③⑤①"}],"C":[{"text":"①④②③⑤⑥"}],"D":[{"text":"⑥①②③⑤④\n片段阅读6 00 0(上册)"}]},"annotatedStemRich":[{"text":"①压力面前，一些人声称理想很丰满、现实很骨感\n②在他们看来，只有为个人利益而活着才是最现实和最有意义的\n③还有一些人在理想与现实反差的所谓痛苦中不能自拔，迷茫和沉沦\n④一些人甚至开始奚落崇高、嘲笑理想\n⑤正因如此，那些真正为理想而活着的人，才显得格外难能可贵\n⑥岁月的淘洗中，坚守理想并不是一件容易的事将以上6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"①④③②⑥⑤"}],"B":[{"text":"⑥①④②③⑤①"}],"C":[{"text":"①④②③⑤⑥"}],"D":[{"text":"⑥①②③⑤④"}]},"practicalAnalysis":"由于本题①⑥不好确定首句，可先根据内容分堆：\n①②③④介绍的都是“不能坚守理想”的一些人，属于具体分析；⑤通过“因此”总结观点“真正为理想而活的人，难能可贵”,⑥通过“坚守理想不是一件容易的事”引出下文；\n因此，大体顺序应为⑥→①②③④→⑤,锁定B选项，当选。","notes":[{"marker":"③","content":"行文结构：后观点结构。\n⑥引出话题“坚守理想不容易”;\n①④②③介绍不能坚守理想的人，其中，①④②介绍的是因利益不能坚守理想的人，③介绍的是在理想与现实反差中痛苦迷茫沉沦的人；\n⑤通过“正因如此”给出观点：“坚守理想的人更难能可贵”。","matchScore":0.6239,"pairingMode":"marker-and-content","order":35}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300278,3,'语句排序类','①军事长官们以此为荣，往往将猛兽的爪、牙置于办公处
②还常在营门口设置旗杆端饰有兽牙、边缘剪裁成齿形的牙旗
③当时战事频繁，王者打天下、守江山，完全凭借武力，因此特别器重军事将领
④衙门是旧时官员的办公之处，其实，早先官员的办公处所被称作“牙门”而不是“衙门”
⑤后来嫌麻烦，就在军营门外以木头刻画成大型兽牙作饰
⑥军中听号令，必至牙旗之下，于是，营门也被形象地称作“牙门”
⑦而“牙门”之称，源于“牙旗”,古时常用猛兽的利牙来象征武力
将以上7个句子重新排列，语序正确的是：','[{"label":"A","content":"⑥⑦①⑤②③④"},{"label":"B","content":"④⑦①②⑤③⑥"},{"label":"C","content":"⑥⑦③①④⑤②"},{"label":"D","content":"④⑦③①⑤②⑥"}]','D','观察选项发现，首句只能为④或者⑥,④介绍古时官员的办公处所被称为“牙门”,⑥句在解释为什么被称为“牙门”且出现“牙旗”这一概念；一般逻辑应先引出再解释，④在⑥前，排除A选项、C选项；
观察B选项、D选项，可从③的指代词“当时”入手：③的“当时”可指代⑦的“古时”,且③的“完全凭借武力”呼应⑦的“古时常用猛兽利牙象征武力”;而③若接⑤后，③的解释无法呼应⑤的“因为嫌麻烦，所以木刻兽牙”;
综上，答案为D选项。

花生批注：
38 行文结构：二层结构之果因结构。
④引出“果”:古时官员办公处所被称为“牙门”;
⑦介绍“牙门”之称来自“牙旗”;
③①⑤②介绍古时军事长官往往在军营门外以木刻兽牙为饰品，并设置牙旗(即牙旗的由来);
⑥因军中听令者必至牙旗之下，所以营门被称为“牙门”。','2021年宁德市事业单位','进阶','published','{"globalNumber":278,"setNumber":14,"localNumber":18,"sourceLabel":"2021年宁德市事业单位48%","accuracy":48,"typeAndPassage":"语句排序类+科普类文章","stemRich":[{"text":"①军事长官们以此为荣，往往将猛兽的爪、牙置于办公处\n②还常在营门口设置旗杆端饰有兽牙、边缘剪裁成齿形的牙旗\n③当时战事频繁，王者打天下、守江山，完全凭借武力，因此特别器重军事将领\n④衙门是旧时官员的办公之处，其实，早先官员的办公处所被称作“牙门”而不是“衙门”\n⑤后来嫌麻烦，就在军营门外以木头刻画成大型兽牙作饰\n⑥军中听号令，必至牙旗之下，于是，营门也被形象地称作“牙门”\n⑦而“牙门”之称，源于“牙旗”,古时常用猛兽的利牙来象征武力\n将以上7个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"⑥⑦①⑤②③④"}],"B":[{"text":"④⑦①②⑤③⑥"}],"D":[{"text":"④⑦③①⑤②⑥"}],"C":[{"text":"⑥⑦③①④⑤②"}]},"annotatedStemRich":[{"text":"①军事长官们以此为荣，往往将猛兽的爪、牙置于办公处\n②还常在营门口设置旗杆端饰有兽牙、边缘剪裁成齿形的牙旗\n③当时战事频繁，王者打天下、守江山，完全凭借武力，因此特别器重军事将领\n④衙门是旧时官员的办公之处，其实，早先官员的办公处所被称作“牙门”而不是“衙门”\n⑤后来嫌麻烦，就在军营门外以木头刻画成大型兽牙作饰\n⑥军中听号令，必至牙旗之下，于是，营门也被形象地称作“牙门”\n⑦而“牙门”之称，源于“牙旗”,古时常用猛兽的利牙来象征武力\n将以上7个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"⑥⑦①⑤②③④"}],"B":[{"text":"④⑦①②⑤③⑥"}],"C":[{"text":"⑥⑦③①④⑤②\n"},{"text":"【参考答案】","bold":true},{"text":"D\n【题型与文段类型】语句排序类+科普类文章\n【实战解析】观察选项发现，首句只能为④或者⑥,④介绍古时官员的办公处所被称为“牙门”,⑥句在解释为什么被称为“牙门”且出现“牙旗”这一概念；一般逻辑应先引出再解释，④在⑥前，排除A 选项、C 选项；\n观察B选项、D 选项，可从③的指代词“当时”入手：③的“当时”可指代⑦的“古时”,且③的“完全凭借武力”呼应⑦的“古时常用猛兽利牙象征武力”;而③若接⑤后，③的解释无法呼应⑤的“因为嫌麻烦，所以木刻兽牙”;\n综上，答案为D 选项。\n38"},{"text":"花生批注：","bold":true},{"text":"\n"},{"text":"行文结构：","bold":true},{"text":"二层结构之果因结构。\n④引出“果”:古时官员办公处所被称为“牙门”;\n⑦介绍“牙门”之称来自“牙"},{"text":"旗”","bold":true},{"text":";\n③①⑤②介绍古时军事长官往往在军营门外以木刻兽牙为饰品，并设置牙旗(即牙旗的由来);\n⑥因军中听令者必至牙旗之下，所以营门被称为“牙门”。"}]},"practicalAnalysis":"观察选项发现，首句只能为④或者⑥,④介绍古时官员的办公处所被称为“牙门”,⑥句在解释为什么被称为“牙门”且出现“牙旗”这一概念；一般逻辑应先引出再解释，④在⑥前，排除A选项、C选项；\n观察B选项、D选项，可从③的指代词“当时”入手：③的“当时”可指代⑦的“古时”,且③的“完全凭借武力”呼应⑦的“古时常用猛兽利牙象征武力”;而③若接⑤后，③的解释无法呼应⑤的“因为嫌麻烦，所以木刻兽牙”;\n综上，答案为D选项。","notes":[{"marker":"38","content":"行文结构：二层结构之果因结构。\n④引出“果”:古时官员办公处所被称为“牙门”;\n⑦介绍“牙门”之称来自“牙旗”;\n③①⑤②介绍古时军事长官往往在军营门外以木刻兽牙为饰品，并设置牙旗(即牙旗的由来);\n⑥因军中听令者必至牙旗之下，所以营门被称为“牙门”。","matchScore":0.6381,"pairingMode":"content-similarity","order":36}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300279,3,'中心理解题','事实上，延期偿债不仅无助于真正缓解地方政府债务风险，在大多数情况下反而是埋下了威力更为巨大的“定时炸弹”。一旦“借新还旧”成为地方政府的常规做法，后果更是不堪设想。有鉴于此，
中央政府应及时采取强硬手段，制止地方政府继续大唱“拖字诀”;有关部委也应积极考虑借助资本市场消化地方政府公共债务，以债务证券化等方式引入民间资本，化解债务风险；地方政府也应适当削减其经济建设职能，实现财权、事权对等，从根本上消除负债过度的生存土壤。
对这段文字概括最准确的是：','[{"label":"A","content":"强调中央政府在缓解地方政府债务风险上的指导作用"},{"label":"B","content":"论述缓解地方政府债务风险的有效手段"},{"label":"C","content":"分析限制地方政府延期偿债的原因"},{"label":"D","content":"说明地方政府偿还债务的常规做法"}]','B','文段分析见批注。
文段先介绍延期偿债的问题，再分主体提出对策， B选项可看作对策类选项，对应文段问题、对策，当选；
A选项片面，仅对应三方面对策中的“中央政府”层面，排除； C选项为原因类选项，如果C选项作为正确答案，对应文段应是因果或果因结构，重点谈论地方政府为何延期偿债，与本文段不符，排除； D选项无中生有，原文并未介绍地方政府偿还债务的常规做法，排除。

花生批注：
⑧ 例如：行测要想提高成绩要提高速度和准确率；
正确概括：如何提高行测成绩；
C选项错误：如何提高行测速度。
39 行文结构：后对策结构。
开篇提出问题：延期偿债有很大问题；
之后分不同主体提出具体对策：
1.中央政府，采取手段，制止地方政府拖欠；
2. 有关部委，借助市场，化解公共债务风险；
3. 地方政府，削减职能，消除负债生存土壤。
④0 “有效手段”是文段中三个主体的具体对策的概括。
A海IG
片段阅读6 00 (上册)','2014年国家公务员考试','基础','published','{"globalNumber":279,"setNumber":14,"localNumber":19,"sourceLabel":"2014年国家公务员考试82%","accuracy":82,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"事实上，延期偿债不仅无助于真正缓解地方政府债务风险，在大多数情况下反而是埋下了威力更为巨大的“定时炸弹”。一旦“借新还旧”成为地方政府的常规做法，后果更是不堪设想。有鉴于此，\n中央政府应及时采取强硬手段，制止地方政府继续大唱“拖字诀”;有关部委也应积极考虑借助资本市场消化地方政府公共债务，以债务证券化等方式引入民间资本，化解债务风险；地方政府也应适当削减其经济建设职能，实现财权、事权对等，从根本上消除负债过度的生存土壤。\n对这段文字概括最准确的是："}],"optionRich":{"A":[{"text":"强调中央政府在缓解地方政府债务风险上的指导作用"}],"B":[{"text":"论述缓解地方政府债务风险的有效手段"}],"C":[{"text":"分析限制地方政府延期偿债的原因"}],"D":[{"text":"说明地方政府偿还债务的常规做法"}]},"annotatedStemRich":[{"text":"事实上，延期偿债不仅无助于真正缓解地方政府债务风险，在大多数情况下反而是埋下了威力更为巨大的“定时炸弹”。一旦“借新还旧”成为地方政府的常规做法，后果更是不堪设想("},{"text":"提出问题","bold":true},{"text":")。有鉴于此，中央政府应及时采取强硬手段，制止地方政府继续大唱“拖字诀”;有关部委也应积极考虑借助资本市场消化地方政府公共债务，以债务证券化等方式引入民间资本，化解债务风险；地方政府也应适当削减其经济建设职能，实现财权、事权对等，从根本上消除负债过度的生存土壤(后对策)。③\n对这段文字概括最准确的是："}],"annotatedOptionRich":{"A":[{"text":"强调中央政府在缓解地方政府债务风险上的指导作用( 片面 )"}],"B":[{"text":"论述缓解地方政府债务风险的有效手段","bold":true}],"C":[{"text":"分析限制地方政府延期偿债的原因 (原因类选项)"}],"D":[{"text":"说明地方政府偿还债务的常规做法(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍延期偿债的问题，再分主体提出对策， B选项可看作对策类选项，对应文段问题、对策，当选；\nA选项片面，仅对应三方面对策中的“中央政府”层面，排除； C选项为原因类选项，如果C选项作为正确答案，对应文段应是因果或果因结构，重点谈论地方政府为何延期偿债，与本文段不符，排除； D选项无中生有，原文并未介绍地方政府偿还债务的常规做法，排除。","notes":[{"marker":"⑧","content":"例如：行测要想提高成绩要提高速度和准确率；\n正确概括：如何提高行测成绩；\nC选项错误：如何提高行测速度。","matchScore":0.2206,"pairingMode":"content-similarity","order":7},{"marker":"39","content":"行文结构：后对策结构。\n开篇提出问题：延期偿债有很大问题；\n之后分不同主体提出具体对策：\n1.中央政府，采取手段，制止地方政府拖欠；\n2. 有关部委，借助市场，化解公共债务风险；\n3. 地方政府，削减职能，消除负债生存土壤。","matchScore":0.6632,"pairingMode":"content-similarity","order":37},{"marker":"④0","content":"“有效手段”是文段中三个主体的具体对策的概括。\nA海IG\n片段阅读6 00 (上册)","matchScore":0.2303,"pairingMode":"content-similarity","order":38}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300280,3,'语句填入类','萝卜青菜各有所爱，同样的食物有人吃上一口就欲罢不能，有人则难以下咽，这到底是为什么呢? 科学研究告诉我们，人们喜欢或不喜欢某一种食品其实不仅在于食品本身的味道，还在于人们的不
。这就是说，食物中的化学物质跟味蕾反应并产生一个信号，信号在传入大脑后立即被精确地给予分析，由此甜、酸、苦、辣一一体味出来。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"味觉的本质其实是一种“化学感觉”"},{"label":"B","content":"味蕾需要强刺激才能引起化学反应"},{"label":"C","content":"味觉反应不应仅仅限于舌头的味蕾"},{"label":"D","content":"味觉器官能在短时间内区分出物质"}]','A','所填入语句在文段中间，下文由“这就是说”引出，可知下文是对所填入语句的解释；下文介绍食物给人们的感觉由食物中的化学物质跟味蕾反应而得，所填入语句应和“化学物质”、“化学反应”有关，定位A、 B选项；
A选项的“化学”对应后文的“食物中的化学物质跟味蕾反应(这是化学反应)”,“感觉”对应前文的“还在于人们的不同感觉(化学反应后带来的感觉)”,前后呼应，完美选项，当选；B选项的“味蕾需要强刺激”无中生有，无法呼应，排除；
C选项、D选项未提及“化学”,均可简单排除。
