INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300281,3,'中心理解题','年年招工年年“荒”,受国内外经济新形势、省域产业步入新格局、务工群体产生新诉求等多重影响，持续多年的“用工荒”今年在浙江“如期而至”。与往年不同的是，随着新生代农民工群体的日益扩大，因诉求增多而导致的“用工荒”日渐明显。
这段文字主要讲的是：','[{"label":"A","content":"“用工荒”对企业发展的影响"},{"label":"B","content":"“用工荒”表现出的新特点"},{"label":"C","content":"“用工荒”产生的原因及变化"},{"label":"D","content":"“用工荒”问题的解决途径"}]','C','文段分析见批注。
文段略读后可从选项入手， C选项为“A 且 B”类选项，可反推文段是否为“ A 且B”结构：文段第一句可看作是介绍“用工荒产生的原因”,文段第两句可看作在介绍“用工荒今年的变化”,与 C选项一一对应，完美选项，当选；
A选项的“对企业发展的影响”和D选项的“解决途径”无中生有，排除； B选项的“表现出的新特点”只对应第二句，片面，排除。

