INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300283,3,'中心理解题','社会重视老年工作，关注的重点在帮助老年人解决他们做不了的各种事情上，这自然是对的，但同时还需要关注老年人自己还能做什么。发现、发掘老年人自己还能做什么,加以支持，提供条件和方便，进行组织引导，这不仅可以增加老年人对社会、家庭的贡献，减轻他人的负担，更有利于老年人身心愉快，健康长寿。
这段文字意在说明：','[{"label":"A","content":"组织引导老年人做些力所能及的事可以帮助其树立生活信心"},{"label":"B","content":"关注老年人更应当组织引导老年人实现老有所为"},{"label":"C","content":"老年人实现老有所为可以减轻社会家庭负担，利于长寿"},{"label":"D","content":"老年工作的重点是帮助老年人解决他们做不了的事情"}]','B','文段分析见批注。
文段首句转折后直接给出对策：社会关注老年工作，要关注老年人自己能做什么,并进行组织引导；
A选项可翻译为：要想帮助老年人树立生活信心，可组织引导老年人做些力所能及的事；
B选项可翻译为：社会关注老年工作，应关注并组织引导老年人自己能做什么(老有所为);
二者相比，B选项贴近原文对策表述，A选项的“帮助老年人树立生活信心”
无中生有⑨,排除；
C选项出自论证部分，出处有误，排除；D选项出自首句转折前部分，出处有误，排除；
综上，B选项为正确答案。

花生批注：
⑤ 行文结构：前对策结构。
开篇转折引出对策：
社会关注老年工作，要关注老年人自己能做什么,并进行组织引导；
再介绍这么做的意义：
有利于增加老年人对社会家庭的贡献，减轻负担，更有利于老年人身心愉快，健康长寿。
社会重视老年工作，关注的重点在帮助老年人解决他们做不了的各种事情上，这自然是对的，但同时还需要关注老年人自己还能做什么。发现、发掘老年人自己还能做什么,加以支持，提供条件和方便，进行组织引导(转折引出对策 ) ,这不仅可以增加老年人对社会、家庭的贡献，减轻他人的负担，更有利于老年人身心愉快，健康长寿(分析论证)。⑤
这段文字意在说明：
A. 组织引导老年人做些力所能及的事可以帮助其树立生活信心(无中生有)
B. 关注老年人更应当组织引导老年人实现老有所为
C. 老年人实现老有所为可以减轻社会家庭负担，利于长寿(出处有误)
⑥ 若答案为A选项，原文应介绍“很多老年人失去了生活信心”之类的问题。','2014年河北省考','进阶','published','{"globalNumber":283,"setNumber":15,"localNumber":3,"sourceLabel":"2014年河北省考 69%","accuracy":69,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"社会重视老年工作，关注的重点在帮助老年人解决他们做不了的各种事情上，这自然是对的，但同时还需要关注老年人自己还能做什么。发现、发掘老年人自己还能做什么,加以支持，提供条件和方便，进行组织引导，这不仅可以增加老年人对社会、家庭的贡献，减轻他人的负担，更有利于老年人身心愉快，健康长寿。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"组织引导老年人做些力所能及的事可以帮助其树立生活信心"}],"B":[{"text":"关注老年人更应当组织引导老年人实现老有所为"}],"C":[{"text":"老年人实现老有所为可以减轻社会家庭负担，利于长寿"}],"D":[{"text":"老年工作的重点是帮助老年人解决他们做不了的事情"}]},"annotatedStemRich":[{"text":"⑤花生批注：\n行文结构：前对策结构。\n开篇转折引出对策：\n社会关注老年工作，要关注老年人自己能做什么,并进行组织引导；\n再介绍这么做的意义：\n有利于增加老年人对社会家庭的贡献，减轻负担，更有利于老年人身心愉快，健康长寿。\n社会重视老年工作，关注的重点在帮助老年人解决他们做不了的各种事情上，这自然是对的，但同时还需要关注老年人自己还能做什么。发现、发掘老年人自己还能做什么,加以支持，提供条件和方便，进行组织引导(转折引出对策 ) ,这不仅可以增加老年人对社会、家庭的贡献，减轻他人的负担，更有利于老年人身心愉快，健康长寿(分析论证)。⑤\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"组织引导老年人做些力所能及的事可以帮助其树立生活信心(无中生有)"}],"B":[{"text":"关注老年人更应当组织引导老年人实现老有所为","bold":true}],"C":[{"text":"老年人实现老有所为可以减轻社会家庭负担，利于长寿(出处有误)"}],"D":[{"text":"老年工作的重点是帮助老年人解决他们做不了的事情 (出处有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段首句转折后直接给出对策：社会关注老年工作，要关注老年人自己能做什么,并进行组织引导；\nA选项可翻译为：要想帮助老年人树立生活信心，可组织引导老年人做些力所能及的事；\nB选项可翻译为：社会关注老年工作，应关注并组织引导老年人自己能做什么(老有所为);\n二者相比，B选项贴近原文对策表述，A选项的“帮助老年人树立生活信心”\n无中生有⑨,排除；\nC选项出自论证部分，出处有误，排除；D选项出自首句转折前部分，出处有误，排除；\n综上，B选项为正确答案。","notes":[{"marker":"⑤","content":"行文结构：前对策结构。\n开篇转折引出对策：\n社会关注老年工作，要关注老年人自己能做什么,并进行组织引导；\n再介绍这么做的意义：\n有利于增加老年人对社会家庭的贡献，减轻负担，更有利于老年人身心愉快，健康长寿。\n社会重视老年工作，关注的重点在帮助老年人解决他们做不了的各种事情上，这自然是对的，但同时还需要关注老年人自己还能做什么。发现、发掘老年人自己还能做什么,加以支持，提供条件和方便，进行组织引导(转折引出对策 ) ,这不仅可以增加老年人对社会、家庭的贡献，减轻他人的负担，更有利于老年人身心愉快，健康长寿(分析论证)。⑤\n这段文字意在说明：\nA. 组织引导老年人做些力所能及的事可以帮助其树立生活信心(无中生有)\nB. 关注老年人更应当组织引导老年人实现老有所为\nC. 老年人实现老有所为可以减轻社会家庭负担，利于长寿(出处有误)","matchScore":1.5726,"pairingMode":"marker-and-content","order":4},{"marker":"⑥","content":"若答案为A选项，原文应介绍“很多老年人失去了生活信心”之类的问题。","matchScore":0.3933,"pairingMode":"content-similarity","order":5}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300284,3,'中心理解题','一个多世纪以来，伴随着考古发掘和文物出土，出土文献成为学术研究的基本史料，渐有与传世文献分庭抗礼之势，成为另一重要研究方向，然而，面对数量巨大，不断增长的石刻资料，全面准确地掌握相关信息，查阅历代著录及相关研究成果，成为学界推进研究，公众提高认知的一大阻碍。因此，内容完整、使用便利、实时更新的石刻目录，成为文史领域研究者和爱好者的迫切需要，石刻资料数字化，使得这些需求的满足成为可能。
这段文字意在强调：','[{"label":"A","content":"考古成果助力文史领域的学术研究"},{"label":"B","content":"石刻数据库是适应时代需求的成果"},{"label":"C","content":"出土文献对学术研究具有重要价值"},{"label":"D","content":"历代存留下来的石刻资源亟需整理"}]','B','文段分析见批注。
文段先提出“石刻资料不断增长、数量巨大，难以全面掌握和查阅”的问题，再给出了“需要石刻资料数字化，满足需求”的对策；
A选项和C选项均缺少文段论述主体“石刻资料”,可简单排除；
B选项和D选项都是对策表述，需要仔细辨析：B选项可翻译为“要建设石刻数据库”,可对应对策“石刻资料数字化”;D选项对策不具体，只强调需要整理，但是具体方式(石刻资料数据化)没有体现⑨;
综上，正确答案为B选项。

花生批注：
⑦ “石刻资料”是全文论述主体。
