INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300286,3,'中心理解题','隋唐时期的三彩陶器，标志着彩釉陶器的横空出世，同时也开启了中国陶器与西域的交流。襟怀宽广的大唐盛世，借鉴了中亚、南亚诸国的金银器造型及工艺，丰富了中国壶具的型制与装饰语言。长沙窑的盘口壶、广口壶，还有更具代表性的执壶等名声显赫的中国陶瓷，则通过陆上、海上两条途径实现了西至阿拉伯与欧洲、非洲，东到日本、朝鲜及东南亚诸国的商品与文化输出，并深刻影响了这些国家民众的生活方式。
这段文字主要介绍了：','[{"label":"A","content":"唐代文化艺术交流对其他国家产生影响"},{"label":"B","content":"陶瓷发展的历程闪现着文化交流的光辉"},{"label":"C","content":"唐代陶器吸收国外工艺并向全世界输出"},{"label":"D","content":"陶制壶具的输出影响当地居民生活方式"}]','B','文段分析见批注。
文段介绍了我国陶瓷在发展过程中与他国的文化交流，重点为“陶瓷”与“交流”,对应B选项，当选；
A选项未提及“陶瓷”,排除； C选项，未体现“交流”且唐代只是其中一个朝代，排除；D选项杂糅，壶具出自“分2”,影响当地居民的生活方式出自“分3”,排除。

花生批注：
⑫ 行文结构：大并列结构。
文段依次介绍：
①隋唐时期的三彩陶器开启和西域的交流；
②大唐壶具借鉴中亚、南亚造型与工艺；
③长沙窑的盘口壶、广口壶和执壶等通过陆上、海上与外国交流。
这段文字主要介绍了：
A. 唐代文化艺术交流对其他国家产生影响(片面)
B. 陶瓷发展的历程闪现着文化交流的光辉
C. 唐代陶器吸收国外工艺并向全世界输出(出处有误)','2013年联考','挑战','published','{"globalNumber":286,"setNumber":15,"localNumber":6,"sourceLabel":"2013年联考 39%","accuracy":39,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"隋唐时期的三彩陶器，标志着彩釉陶器的横空出世，同时也开启了中国陶器与西域的交流。襟怀宽广的大唐盛世，借鉴了中亚、南亚诸国的金银器造型及工艺，丰富了中国壶具的型制与装饰语言。长沙窑的盘口壶、广口壶，还有更具代表性的执壶等名声显赫的中国陶瓷，则通过陆上、海上两条途径实现了西至阿拉伯与欧洲、非洲，东到日本、朝鲜及东南亚诸国的商品与文化输出，并深刻影响了这些国家民众的生活方式。\n这段文字主要介绍了："}],"optionRich":{"A":[{"text":"唐代文化艺术交流对其他国家产生影响"}],"B":[{"text":"陶瓷发展的历程闪现着文化交流的光辉"}],"C":[{"text":"唐代陶器吸收国外工艺并向全世界输出"}],"D":[{"text":"陶制壶具的输出影响当地居民生活方式"}]},"annotatedStemRich":[{"text":"隋唐时期的三彩陶器，标志着彩釉陶器的横空出世，同时也开启了中国陶器与西域的交流( 分 1 ) 。襟怀宽广的大唐盛世，借鉴了中亚、南亚诸国的金银器造型及工艺，丰富了中国壶具的型制与装饰语言( 分 2 ) 。长沙窑的盘口壶、广口壶，还有更具代表性的执壶等名声显赫的中国陶瓷，则通过陆上、海上两条途径实现了西至阿拉伯与欧洲、非洲，东到日本、朝鲜及东南亚诸国的商品与文化输出，并深刻影响了这些国家民众的生活方式(分3)。 ⑫\n这段文字主要介绍了："}],"annotatedOptionRich":{"A":[{"text":"唐代文化艺术交流对其他国家产生影响(片面)"}],"B":[{"text":"陶瓷发展的历程闪现着文化交流的光辉"}],"C":[{"text":"唐代陶器吸收国外工艺并向全世界输出(出处有误)"}],"D":[{"text":"陶制壶具的输出影响当地居民生活方式(出处有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段介绍了我国陶瓷在发展过程中与他国的文化交流，重点为“陶瓷”与“交流”,对应B选项，当选；\nA选项未提及“陶瓷”,排除； C选项，未体现“交流”且唐代只是其中一个朝代，排除；D选项杂糅，壶具出自“分2”,影响当地居民的生活方式出自“分3”,排除。","notes":[{"marker":"⑫","content":"行文结构：大并列结构。\n文段依次介绍：\n①隋唐时期的三彩陶器开启和西域的交流；\n②大唐壶具借鉴中亚、南亚造型与工艺；\n③长沙窑的盘口壶、广口壶和执壶等通过陆上、海上与外国交流。\n这段文字主要介绍了：\nA. 唐代文化艺术交流对其他国家产生影响(片面)\nB. 陶瓷发展的历程闪现着文化交流的光辉\nC. 唐代陶器吸收国外工艺并向全世界输出(出处有误)","matchScore":0.6682,"pairingMode":"marker-and-content","order":11}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300287,3,'中心理解题','在“一切皆可量化”的大数据浪潮中，网络逐渐成为现实世界的“镜像”。网络社会与现实社会日益融为一体，政府管理不能再局限于线下管理，而必须全面掌握互联网对政府与公众行为的影响机制、调节规律及其与现实社会的联系，实现网上网下充分联动、协调共治。
这段文字意在说明大数据：','[{"label":"A","content":"强化了政府的治理手段"},{"label":"B","content":"提升了政府管理的效率"},{"label":"C","content":"调整了政府管理的重心"},{"label":"D","content":"拓展了政府的治理领域"}]','D','文段分析见批注。
文段结构较为简单，提出话题后直接给出对策：政府管理不能再局限于现实世界，还要网络和现实联动，协调共治，即要拓展政府管理的领域：从现实到“网络+现实”,对应D选项，当选；
A选项“治理手段”和B选项“管理效率”均无中生有，排除； C选项调整重心意味着以前偏向线下，以后要偏向线上，与原文对策不符⑨,排除。

花生批注：
⑬ 行文结构：后对策结构。
开篇提出话题：
网络是现实世界的“镜像”; 接着给出对策：
①政府管理不能局限于线下；②政府管理要网络和现实联动，协调共治(即“都要管”)。
⑭ 原文对策是线上线下充分联动、协调共治；
没有体现偏向哪一边，线上线下都重要，所以这里用D选项的“扩展治理领域”更合适。
(上册)','2021年浙江省考','进阶','published','{"globalNumber":287,"setNumber":15,"localNumber":7,"sourceLabel":"2021年浙江省考67%","accuracy":67,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"在“一切皆可量化”的大数据浪潮中，网络逐渐成为现实世界的“镜像”。网络社会与现实社会日益融为一体，政府管理不能再局限于线下管理，而必须全面掌握互联网对政府与公众行为的影响机制、调节规律及其与现实社会的联系，实现网上网下充分联动、协调共治。\n这段文字意在说明大数据："}],"optionRich":{"A":[{"text":"强化了政府的治理手段"}],"B":[{"text":"提升了政府管理的效率"}],"C":[{"text":"调整了政府管理的重心"}],"D":[{"text":"拓展了政府的治理领域"}]},"annotatedStemRich":[{"text":"在“一切皆可量化”的大数据浪潮中，网络逐渐成为现实世界的“镜像”(提出话题)。网络社会与现实社会日益融为一体，政府管理不能再局限于线下管理，而必须全面掌握互联网对政府与公众行为的影响机制、调节规律及其与现实社会的联系，实现网上网下充分联动、协调共治(提出对策)。⑤\n这段文字意在说明大数据："}],"annotatedOptionRich":{"A":[{"text":"强化了政府的治理手段(无中生有)"}],"B":[{"text":"提升了政府管理的效率(无中生有)"}],"C":[{"text":"调整了政府管理的重心(本身有误)"}],"D":[{"text":"拓展了政府的治理领域"}]},"practicalAnalysis":"文段分析见批注。\n文段结构较为简单，提出话题后直接给出对策：政府管理不能再局限于现实世界，还要网络和现实联动，协调共治，即要拓展政府管理的领域：从现实到“网络+现实”,对应D选项，当选；\nA选项“治理手段”和B选项“管理效率”均无中生有，排除； C选项调整重心意味着以前偏向线下，以后要偏向线上，与原文对策不符⑨,排除。","notes":[{"marker":"⑬","content":"行文结构：后对策结构。\n开篇提出话题：\n网络是现实世界的“镜像”; 接着给出对策：\n①政府管理不能局限于线下；②政府管理要网络和现实联动，协调共治(即“都要管”)。","matchScore":0.8174,"pairingMode":"content-similarity","order":12},{"marker":"⑭","content":"原文对策是线上线下充分联动、协调共治；\n没有体现偏向哪一边，线上线下都重要，所以这里用D选项的“扩展治理领域”更合适。\n(上册)","matchScore":0.4537,"pairingMode":"content-similarity","order":13}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300288,3,'标题拟定类','关于第一批人类如何来到美洲大陆，通常的说法是靠步行。在冰河时期，人们横穿了1500公里，从当时连接西伯利亚和加拿大北部的大片陆块迁徙过去。随着冰河期结束，这片称为“白令陆桥”的陆块成为白令海峡。然而，“陆桥说”已逐渐不再流行，一些迹象显示，人类有可能是顺着太平洋沿岸搭船前往美洲的。考古发现美洲有14000年历史的人类聚落，足以作为早期人们由出海口逆流而上、踏入内陆的佐证，例如位于俄勒冈州太平洋沿岸的佩斯利洞穴。现在，有更确切的证据表明，人类并未经由“白令陆桥”抵达美洲。
最适合做这段文字标题的是：','[{"label":"A","content":"“白令陆桥”真的存在吗"},{"label":"B","content":"人类航海史超出你想象"},{"label":"C","content":"人类究竟是怎样来到美洲大陆的"},{"label":"D","content":"考古发现再现远古人类迁徙路线"}]','C','文段分析见批注。
文段先介绍了过去的看法：“人类通过步行经过白令陆桥来到美洲大陆”, 转折后用新发现的证据否定了这种看法，表明“人类并未经过白令陆桥到达美洲，有可能是搭船前往美洲的”;
谈论的话题是“人类如何到达美洲大陆”,对应C选项，当选；其他选项均未谈及这一重点话题，排除。

花生批注：
⑮ 第一批人类如何到达美洲大陆是全文论述话题。
⑯ 行文结构：二层结构之转折。转折前介绍过去看法：人类通过步行经过白令陆桥来到美洲大陆；
转折后介绍新发现：人类并未经过白令陆桥抵达美洲，可能是搭船前往美洲的。
⑰ 用疑问句做标题是科普文章的常见方式。
最适合做这段文字标题的是：
A. “白令陆桥”真的存在吗
B. 人类航海史超出你想象
C. 人类究竟是怎样来到美洲大陆的①
D. 考古发现再现远古人类迁徙路线','2019年国家公务员考试','进阶','published','{"globalNumber":288,"setNumber":15,"localNumber":8,"sourceLabel":"2019年国家公务员考试66%","accuracy":66,"typeAndPassage":"标题拟定类+科普介绍文章","stemRich":[{"text":"关于第一批人类如何来到美洲大陆，通常的说法是靠步行。在冰河时期，人们横穿了1500公里，从当时连接西伯利亚和加拿大北部的大片陆块迁徙过去。随着冰河期结束，这片称为“白令陆桥”的陆块成为白令海峡。然而，“陆桥说”已逐渐不再流行，一些迹象显示，人类有可能是顺着太平洋沿岸搭船前往美洲的。考古发现美洲有14000年历史的人类聚落，足以作为早期人们由出海口逆流而上、踏入内陆的佐证，例如位于俄勒冈州太平洋沿岸的佩斯利洞穴。现在，有更确切的证据表明，人类并未经由“白令陆桥”抵达美洲。\n最适合做这段文字标题的是："}],"optionRich":{"A":[{"text":"“白令陆桥”真的存在吗"}],"B":[{"text":"人类航海史超出你想象"}],"C":[{"text":"人类究竟是怎样来到美洲大陆的"}],"D":[{"text":"考古发现再现远古人类迁徙路线"}]},"annotatedStemRich":[{"text":"关于"},{"text":"第一批人类如何来到美洲大陆","underline":true},{"text":"⑮,通常的说法是靠步行。在冰河时期，人们横穿了1500公里，从当时连接西伯利亚和加拿大北部的大片陆块迁徙过去。随着冰河期结束，这片称为“白令陆桥”的陆块成为白令海峡(介绍以往认为人类是通过步行经过白令陆桥来到美洲大陆的)。然而，“陆桥说”已逐渐不再流行，一些迹象显示，人类有可能是顺着太平洋沿岸搭船前往美洲的。考古发现美洲有14000年历史的人类聚落，足以作为早期人们由出海口逆流而上、踏入内陆的佐证，例如位于俄勒冈州太平洋沿岸的佩斯利洞穴。现在，有更确切的证据表明，人类并未经由“白令陆桥”抵达美洲(证明人类并未通过白令陆桥步行，而可能是通过搭船前往美洲)。⑩\n最适合做这段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"“白令陆桥”真的存在吗"}],"B":[{"text":"人类航海史超出你想象"}],"C":[{"text":"人类究竟是怎样来到美洲大陆的①"}],"D":[{"text":"考古发现再现远古人类迁徙路线"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍了过去的看法：“人类通过步行经过白令陆桥来到美洲大陆”, 转折后用新发现的证据否定了这种看法，表明“人类并未经过白令陆桥到达美洲，有可能是搭船前往美洲的”;\n谈论的话题是“人类如何到达美洲大陆”,对应C选项，当选；其他选项均未谈及这一重点话题，排除。","notes":[{"marker":"⑮","content":"第一批人类如何到达美洲大陆是全文论述话题。","matchScore":0.7302,"pairingMode":"marker-and-content","order":14},{"marker":"⑯","content":"行文结构：二层结构之转折。转折前介绍过去看法：人类通过步行经过白令陆桥来到美洲大陆；\n转折后介绍新发现：人类并未经过白令陆桥抵达美洲，可能是搭船前往美洲的。","matchScore":0.8584,"pairingMode":"content-similarity","order":15},{"marker":"⑰","content":"用疑问句做标题是科普文章的常见方式。\n最适合做这段文字标题的是：\nA. “白令陆桥”真的存在吗\nB. 人类航海史超出你想象\nC. 人类究竟是怎样来到美洲大陆的①\nD. 考古发现再现远古人类迁徙路线","matchScore":0.4555,"pairingMode":"content-similarity","order":16}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300289,3,'中心理解题','一个国家的发展应该致力于将经济发展的蛋糕做大，在此基础上，注重公平的分配。对区域经济发展来说，应牢牢建立比较优势的概念。不同的地方在自然地理条件上有巨大的差异。即便是两个自然条件完全相同，地理上相邻的省份或城市，最佳的发展模式也不是大家发展同样的生产结构，而是应该各自有分工。
作者通过这段文字重在强调：','[{"label":"A","content":"不同地理条件的区域发展模式应当有所不同"},{"label":"B","content":"地理相邻的两个城市也应该有各自不同特色"},{"label":"C","content":"不同区域经济发展应与当地比较优势相吻合"},{"label":"D","content":"最佳发展模式并不适合所有地理条件的区域"}]','C','文段分析见批注。
文段对策句“对区域经济发展来说，应牢牢建立比较优势的概念”可翻译为“区域经济发展要发挥比较优势”,C选项可翻译为“区域经济的发展要围绕当地比较优势”,是原文对策的同义替换，当选；
D选项不是对策表述，根据原文有对策要选对策原则，排除；
A选项和B选项一方面均出自文段分析论证部分，出处有误，另一方面原文对策核心为“建立比较优势”,A选项对策“应当不同”和B选项“有不同的特色”均未体现“比较优势”②,A选项和B选项均要排除；
综上，正确答案是C选项。

花生批注：
⑪ “支撑”必要条件表对策，谁是“支撑”谁是对策重点。例如：高水平保护是高质量发展的重要支撑，可翻译为“高质量发展需要高水平保护”。
A选项可翻译为“信息化社会需要宽带建设”,是对策的同义替换，当选；
B选项只谈及过去认识的错误，未提及对策，且出处有误； C选项的“网络运营商服务质量”无中生有；D选项的“信息交流效率”只是问题之一，片面且出自分析论证部分，出处有误，均排除；
综上，A选项为正确答案。
⑱ “区域经济发展”为文段核心话题。
⑲ 行文结构：前对策结构。先背景引出话题；
再祈使句提出对策：
区域经济发展应牢牢建立比较优势的概念；
最后分析论证。
作者通过这段文字重在强调：
A. 不同地理条件的区域发展模式应当有所不同(出处有误)
B. 地理相邻的两个城市也应该有各自不同特色(出处有误)
C. 不同区域经济发展应与当地比较优势相吻合
D. 最佳发展模式并不适合所有地理条件的区域(问题表述)
② 论证部分把两个城市分为“自然地理条件不同的不同地方”、“地理上相邻、自然条件完全相同的地方”, A选项、B选项分别对应上述两类不同城市，表述也片面。
② 原文“优势”侧重表达的是自己相对于其他人的长处；
“特色”和“不同”侧重于体现自己与他人的区别；
“区别”不一定是“长处”; 所以A选项和B选项没体现原文对策的核心“建立比较优势的概念”。','2020年江苏省考','基础','published','{"globalNumber":289,"setNumber":15,"localNumber":9,"sourceLabel":"2020年江苏省考 70%","accuracy":70,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"一个国家的发展应该致力于将经济发展的蛋糕做大，在此基础上，注重公平的分配。对区域经济发展来说，应牢牢建立比较优势的概念。不同的地方在自然地理条件上有巨大的差异。即便是两个自然条件完全相同，地理上相邻的省份或城市，最佳的发展模式也不是大家发展同样的生产结构，而是应该各自有分工。\n作者通过这段文字重在强调："}],"optionRich":{"A":[{"text":"不同地理条件的区域发展模式应当有所不同"}],"B":[{"text":"地理相邻的两个城市也应该有各自不同特色"}],"C":[{"text":"不同区域经济发展应与当地比较优势相吻合"}],"D":[{"text":"最佳发展模式并不适合所有地理条件的区域"}]},"annotatedStemRich":[{"text":"一个国家的发展应该致力于将经济发展的蛋糕做大，在此基础上，注重公平的分配(背景引出话题)。对"},{"text":"区域经济发展","underline":true},{"text":"⑱来说，应牢牢建立比较优势的概念(祈使句提出对策)。不同的地方在自然地理条件上有巨大的差异。即便是两个自然条件完全相同，地理上相邻的省份或城市，最佳的发展模式也不是大家发展同样的生产结构，而是应该各自有分工(分析论证)。⑨\n作者通过这段文字重在强调："}],"annotatedOptionRich":{"A":[{"text":"不同地理条件的区域发展模式应当有所不同(出处有误)"}],"B":[{"text":"地理相邻的两个城市也应该有各自不同特色(出处有误)"}],"C":[{"text":"不同区域经济发展应与当地比较优势相吻合"}],"D":[{"text":"最佳发展模式并不适合所有地理条件的区域(问题表述)"}]},"practicalAnalysis":"文段分析见批注。\n文段对策句“对区域经济发展来说，应牢牢建立比较优势的概念”可翻译为“区域经济发展要发挥比较优势”,C选项可翻译为“区域经济的发展要围绕当地比较优势”,是原文对策的同义替换，当选；\nD选项不是对策表述，根据原文有对策要选对策原则，排除；\nA选项和B选项一方面均出自文段分析论证部分，出处有误，另一方面原文对策核心为“建立比较优势”,A选项对策“应当不同”和B选项“有不同的特色”均未体现“比较优势”②,A选项和B选项均要排除；\n综上，正确答案是C选项。","notes":[{"marker":"⑪","content":"“支撑”必要条件表对策，谁是“支撑”谁是对策重点。例如：高水平保护是高质量发展的重要支撑，可翻译为“高质量发展需要高水平保护”。\nA选项可翻译为“信息化社会需要宽带建设”,是对策的同义替换，当选；\nB选项只谈及过去认识的错误，未提及对策，且出处有误； C选项的“网络运营商服务质量”无中生有；D选项的“信息交流效率”只是问题之一，片面且出自分析论证部分，出处有误，均排除；\n综上，A选项为正确答案。","matchScore":0.4391,"pairingMode":"content-similarity","order":10},{"marker":"⑱","content":"“区域经济发展”为文段核心话题。","matchScore":0.7091,"pairingMode":"marker-and-content","order":17},{"marker":"⑲","content":"行文结构：前对策结构。先背景引出话题；\n再祈使句提出对策：\n区域经济发展应牢牢建立比较优势的概念；\n最后分析论证。\n作者通过这段文字重在强调：\nA. 不同地理条件的区域发展模式应当有所不同(出处有误)\nB. 地理相邻的两个城市也应该有各自不同特色(出处有误)\nC. 不同区域经济发展应与当地比较优势相吻合\nD. 最佳发展模式并不适合所有地理条件的区域(问题表述)","matchScore":0.7416,"pairingMode":"content-similarity","order":18},{"marker":"②","content":"论证部分把两个城市分为“自然地理条件不同的不同地方”、“地理上相邻、自然条件完全相同的地方”, A选项、B选项分别对应上述两类不同城市，表述也片面。","matchScore":0.5973,"pairingMode":"marker-and-content","order":19},{"marker":"②","content":"原文“优势”侧重表达的是自己相对于其他人的长处；\n“特色”和“不同”侧重于体现自己与他人的区别；\n“区别”不一定是“长处”; 所以A选项和B选项没体现原文对策的核心“建立比较优势的概念”。","matchScore":0.3729,"pairingMode":"marker-and-content","order":20}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300290,3,'语句排序类','近日，由中国、意大利、美国学者组成的研究团队，最新研发出一种三维石墨烯——碳纳米管复合网络支架。这种生物支架能很好地模拟大脑神经网络结构，未来，将可用于药物筛选或植入大脑帮助治疗脑部疾病，该碳神经支架由我国率先提出并完成材料制备。科学家科研人员发现，相比在二维的培养皿中观察、培养神经细胞，三维支架更接近脑部实际环境。
将下列4个句子重新排列，填入画横线处，语序正确的是：
①把体内正常的神经干细胞移植到细小的碳纳米管中
②用石墨烯模拟大脑内部四通八达的三维框架
③从而构建出一个“互联互通”的人造神经网络
④增殖和定向分化神经元细胞','[{"label":"A","content":"①②③④"},{"label":"B","content":"②④①③"},{"label":"C","content":"①③②④"},{"label":"D","content":"②①④③"}]','D','文段分析见批注。
观察选项，③是“从而”引导的总结句，很可能做尾句。同时根据上文“这种生物支架能很好地模拟大脑神经网络结构”可知，“构建人造神经网络”应该是实验最后一步。因此，③做句尾。排除A选项、C选项；
比较B选项和D选项，只需确定①④相对顺序即可。根据实验顺序，应先把神经干细胞移植完毕，再将神经干细胞分化成神经元细胞。因此，①应在 ④之前，验证 D选项，逻辑正确，当选。

花生批注：
2 文章结构：总分结构。
首句引出话题：
介绍研究团队新研发出一种三维石墨烯；
接着对其进行介绍：
该碳神经支架由我国率先提出并完成材料制备；
尾句介绍三维支架好处。
那么横线处应该介绍科学家如何构建三维支架。
3 整体思路：石墨烯构建框架 →移植神经干细胞→增殖分化神经元细胞→构建人造神经网。
这是构建三维支架的完整过程。
将下列4个句子重新排列，填入画横线处，语序正确的是：
①把体内正常的神经干细胞移植到细小的碳纳米管中
②用石墨烯模拟大脑内部四通八达的三维框架
③从而构建出一个“互联互通”的人造神经网络
④增殖和定向分化神经元细胞
A.①②③④ B.②④①③
C.①③②④ D.②①④③','2021年云南省考','基础','published','{"globalNumber":290,"setNumber":15,"localNumber":10,"sourceLabel":"2021年云南省考72%","accuracy":72,"typeAndPassage":"语句排序类+科普介绍文章","stemRich":[{"text":"近日，由中国、意大利、美国学者组成的研究团队，最新研发出一种三维石墨烯——碳纳米管复合网络支架。这种生物支架能很好地模拟大脑神经网络结构，未来，将可用于药物筛选或植入大脑帮助治疗脑部疾病，该碳神经支架由我国率先提出并完成材料制备。科学家 "},{"text":"                       ","underline":true},{"text":" 科研人员发现，相比在二维的培养皿中观察、培养神经细胞，三维支架更接近脑部实际环境。\n将下列4个句子重新排列，填入画横线处，语序正确的是：\n①把体内正常的神经干细胞移植到细小的碳纳米管中\n②用石墨烯模拟大脑内部四通八达的三维框架\n③从而构建出一个“互联互通”的人造神经网络\n④增殖和定向分化神经元细胞"}],"optionRich":{"A":[{"text":"①②③④"}],"B":[{"text":"②④①③"}],"C":[{"text":"①③②④"}],"D":[{"text":"②①④③"}]},"annotatedStemRich":[{"text":"近日，由中国、意大利、美国学者组成的研究团队，最新研发出一种三维石墨烯"},{"text":"    ","underline":true},{"text":" 碳纳米管复合网络支架。这种生物支架能很好地模拟大脑神经网络结构，未来，将可用于药物筛选或植入大脑帮助治疗脑部疾病，该碳神经支架由我国率先提出并完成材料制备。科学家 "},{"text":"                      ","underline":true},{"text":"。科研人员发现，相比在二维的培养皿中观察、培养神经细胞，三维支架更接近脑部实际环境。\n将下列4个句子重新排列，填入画横线处，语序正确的是：\n①把体内正常的神经干细胞移植到细小的碳纳米管中\n②用石墨烯模拟大脑内部四通八达的三维框架\n③从而构建出一个“互联互通”的人造神经网络\n④增殖和定向分化神经元细胞"}],"annotatedOptionRich":{"A":[{"text":"①②③④"}],"B":[{"text":"②④①③"}],"C":[{"text":"①③②④"}],"D":[{"text":"②①④③"}]},"practicalAnalysis":"文段分析见批注。\n观察选项，③是“从而”引导的总结句，很可能做尾句。同时根据上文“这种生物支架能很好地模拟大脑神经网络结构”可知，“构建人造神经网络”应该是实验最后一步。因此，③做句尾。排除A选项、C选项；\n比较B选项和D选项，只需确定①④相对顺序即可。根据实验顺序，应先把神经干细胞移植完毕，再将神经干细胞分化成神经元细胞。因此，①应在 ④之前，验证 D选项，逻辑正确，当选。","notes":[{"marker":"2","content":"文章结构：总分结构。\n首句引出话题：\n介绍研究团队新研发出一种三维石墨烯；\n接着对其进行介绍：\n该碳神经支架由我国率先提出并完成材料制备；\n尾句介绍三维支架好处。\n那么横线处应该介绍科学家如何构建三维支架。","matchScore":0.6842,"pairingMode":"marker-and-content","order":21},{"marker":"3","content":"整体思路：石墨烯构建框架 →移植神经干细胞→增殖分化神经元细胞→构建人造神经网。\n这是构建三维支架的完整过程。\n将下列4个句子重新排列，填入画横线处，语序正确的是：\n①把体内正常的神经干细胞移植到细小的碳纳米管中\n②用石墨烯模拟大脑内部四通八达的三维框架\n③从而构建出一个“互联互通”的人造神经网络\n④增殖和定向分化神经元细胞\nA.①②③④ B.②④①③\nC.①③②④ D.②①④③","matchScore":1.0658,"pairingMode":"marker-and-content","order":22}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300291,3,'语句排序类','①然而，监管执法的覆盖面毕竟有限，执法成本也相对较高
②但这毕竟只是消极的自我保护，被侵犯的合法权益没有得到弥补，违法违规者也没有受到应有惩戒
③过去，用脚投票是很多“小散”的无奈选择，“惹不起总还躲得起”
④要从根本上保障小投资者的利益，固然要有强有力的外部保护，而增强其自我保护能力也同样重要
⑤随着监管力度加强，很多损害中小投资者利益的违法行为受到严厉处罚
⑥在A股市场，由于个人投资者数量庞大，如何有效保护“股微言轻”的小股东，就显得尤其重要将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"③②⑤①④⑥"},{"label":"B","content":"③⑤②①⑥④"},{"label":"C","content":""},{"label":"D","content":""}]','D','文段分析见批注。
由于本题⑥③不好判断首句，可从转折词“然而”入手；
观察选项①句前面只能是⑤②④,其中只有⑤句提到①句的主语“监管执法”,排除B 、C 两项；
观察A选项、D选项，④句、⑥句的位置为选项不同点，⑥句指出保护小股东很重要，④句指出具体对策，因此④比⑥更适合作为尾句，⑥句更适合做首句引出话题，D选项当选。

花生批注：
④ 行文结构：后对策结构。
⑥句引出话题：
保护小股东很重要；
③②⑤①提出并分析问题：原来“小散”依靠自我保护，但合法权益没有弥补、违法行为也没有惩戒；
虽然随着监管力度加强，有所改变，但监管执法的覆盖面有限，执法成本也相对较高；
