INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300293,3,'细节判断类','生活中，选择仰卧睡姿的人群占比较大，这种睡眠姿势不会压迫体内脏腑等器官，可以减轻内脏、胸腔的压迫感，还可以让脊椎部位成一条线，能有效缓解颈部、背部酸痛的症状。同时，它也是美容觉的最佳姿势，因为脸部不会因枕头挤压而产生皱纹，可以放松皮肤。
根据这段文字，下列说法中正确的是：','[{"label":"A","content":"仰卧是最适合人类的睡姿"},{"label":"B","content":"颈部与背部的酸痛是由于不良睡姿造成的"},{"label":"C","content":"想要减少脸部皱纹的产生，可以选择仰卧睡姿"},{"label":"D","content":"仰卧睡姿比较适合女性，不适合男性"}]','C','根据“它也是美容觉的最佳姿势，因为脸部不会因枕头挤压而产生皱纹，可以放松皮肤”可知，仰卧睡姿可减少脸部产生皱纹，C选项正确，当选。','2020年河北省事业单位','进阶','published','{"globalNumber":293,"setNumber":15,"localNumber":13,"sourceLabel":"2020年河北省事业单位67%","accuracy":67,"typeAndPassage":"细节判断类","stemRich":[{"text":"生活中，选择仰卧睡姿的人群占比较大，这种睡眠姿势不会压迫体内脏腑等器官，可以减轻内脏、胸腔的压迫感，还可以让脊椎部位成一条线，能有效缓解颈部、背部酸痛的症状。同时，它也是美容觉的最佳姿势，因为脸部不会因枕头挤压而产生皱纹，可以放松皮肤。\n根据这段文字，下列说法中正确的是："}],"optionRich":{"A":[{"text":"仰卧是最适合人类的睡姿"}],"B":[{"text":"颈部与背部的酸痛是由于不良睡姿造成的"}],"C":[{"text":"想要减少脸部皱纹的产生，可以选择仰卧睡姿"}],"D":[{"text":"仰卧睡姿比较适合女性，不适合男性"}]},"annotatedStemRich":[{"text":"生活中，选择仰卧睡姿的人群占比较大，这种睡眠姿势不会压迫体内脏腑等器官，可以减轻内脏、胸腔的压迫感，还可以让脊椎部位成一条线，能有效缓解颈部、背部酸痛的症状。同时，它也是美容觉的最佳姿势，因为脸部不会因枕头挤压而产生皱纹，可以放松皮肤。\n根据这段文字，下列说法中正确的是："}],"annotatedOptionRich":{"A":[{"text":"仰卧是最适合人类的睡姿","underline":true},{"text":"②(绝对化且偷换概念)"}],"B":[{"text":"颈部与背部的酸痛是由于不良睡姿造成的"}],"C":[{"text":"想要减少脸部皱纹的产生，可以选择仰卧睡姿","bold":true}],"D":[{"text":"仰卧睡姿比较适合女性，不适合男性(无中生有)"}]},"practicalAnalysis":"根据“它也是美容觉的最佳姿势，因为脸部不会因枕头挤压而产生皱纹，可以放松皮肤”可知，仰卧睡姿可减少脸部产生皱纹，C选项正确，当选。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300294,3,'下文推断类③','古语有云，“慎终追远，民德归厚矣”。作为文化的重要载体，传统节日集中体现了中华民族的传统信仰、伦理道德、价值观念、行为规范等。我们在端午节纪念2000多年前的爱国者屈原，就是为了忆念其伟大，传承其精神。又因为农历五月是仲夏，第一个午日正是登高顺阳的好日子，故五月初五也被称为“端阳节”。这些丰富的历史意义、文化意涵，赋予中华民族传统节日以巨大魅力，并以潜移默化的方式，将中华民族的精神操守、道德力量根植人心。然而，包括端午节在内的许多传统节日的内涵一度被人们淡忘，不少人索性将端午节称为“粽子节”,仿佛节日除了吃粽子再无别的含义。
这段文字接下来最应当探讨并解决的问题是：','[{"label":"A","content":"怎样重拾传统文化"},{"label":"B","content":"怎样才能给端午节赋予更强的传统文化内涵"},{"label":"C","content":"怎样过节才是对中华民族传统信仰的传承"},{"label":"D","content":"怎样才能让人们更好地体验传统节日背后传统文化"}]','D','文段先介绍了传统节日，尾句转折后提出问题，即“传统节日内涵被人淡忘”,上文提出问题，下文应给出有针对性的对策，D选项的“让人们更好体验传统节日背后的传统文化”对应上文问题“传统节日内涵(即文化) 被遗忘”,当选；
A选项缺少主题词“传统节日”,排除； B选项主体有误，“端午节”出自举例部分，且对策有误，针对“传统节日的内涵被遗忘”的对策不应是“赋予更强文化内涵”,排除； C项的对策有误，未提及“传统节日背后的文化”, 排除。

花生批注：
26 根据③的“氟利昂被发现泄漏到空气中会释放破坏大气臭氧层的氯”可知，氟利昂中的氯会破坏大气臭氧层。
②7 根据②的“汽车空调领域使用的唯一制冷剂也是R12”可知，汽车空调的使用会增加氟利昂释放；又因“氟利昂的氯会破坏大气臭氧层，臭氧层漏洞能加剧温室效应”可知，汽车空调使用会加剧温室效应。
28 原文虽介绍了仰卧的很多好处，但无法推知仰卧就是最适合人类的睡姿。
29 原文表述为“能有效缓解颈部、背部酸痛的症状”,仰卧睡姿可缓解颈部和背部酸痛，不代表颈部和背部酸痛是由不良睡姿造成。也可能由不良坐姿、运动损伤等各种原因造成。
例如：多吃菠菜可以补铁，不代表“缺铁是由于食用菠菜过少”。
③0 传统节日是全文论述主体。
性将端午节称为“粽子节”,仿佛节日除了吃粽子再无别的含义(转折引出问题)。
这段文字接下来最应当探讨并解决的问题是：
A. 怎样重拾传统文化(缺少主题词)
B. 怎样才能给端午节赋予更强的传统文化内涵(主体有误)
C. 怎样过节才是对中华民族传统信仰的传承(对策有误)','2019年天津市事业单位','进阶','published','{"globalNumber":294,"setNumber":15,"localNumber":14,"sourceLabel":"2019年天津市事业单位63%","accuracy":63,"typeAndPassage":"下文推断类③+提出问题 → 解决问题","stemRich":[{"text":"古语有云，“慎终追远，民德归厚矣”。作为文化的重要载体，传统节日集中体现了中华民族的传统信仰、伦理道德、价值观念、行为规范等。我们在端午节纪念2000多年前的爱国者屈原，就是为了忆念其伟大，传承其精神。又因为农历五月是仲夏，第一个午日正是登高顺阳的好日子，故五月初五也被称为“端阳节”。这些丰富的历史意义、文化意涵，赋予中华民族传统节日以巨大魅力，并以潜移默化的方式，将中华民族的精神操守、道德力量根植人心。然而，包括端午节在内的许多传统节日的内涵一度被人们淡忘，不少人索性将端午节称为“粽子节”,仿佛节日除了吃粽子再无别的含义。\n这段文字接下来最应当探讨并解决的问题是："}],"optionRich":{"A":[{"text":"怎样重拾传统文化"}],"B":[{"text":"怎样才能给端午节赋予更强的传统文化内涵"}],"C":[{"text":"怎样过节才是对中华民族传统信仰的传承"}],"D":[{"text":"怎样才能让人们更好地体验传统节日背后传统文化"}]},"annotatedStemRich":[{"text":"古语有云，“慎终追远，民德归厚矣”。作为文化的重要载体，"},{"text":"传 统 节 日","underline":true},{"text":"集中体现了中华民族的传统信仰、伦理道德、价值观念、行为规范等。我们在端午节纪念2000多年前的爱国者屈原，就是为了忆念其伟大，传承其精神。又因为农历五月是仲夏，第一个午日正是登高顺阳的好日子，故五月初五也被称为“端阳节”。这些丰富的历史意义、文化意涵，赋予中华民族传统节日以巨大魅力，并以潜移默化的方式，将中华民族的精神操守、道德力量根植人心(介绍传统节日 ) 。然而，包括端午节在内的许多传统节日的内涵一度被人们淡忘，不少人索\n26花生批注：\n根据③的“氟利昂被发现泄漏到空气中会释放破坏大气臭氧层的氯”可知，氟利昂中的氯会破坏大气臭氧层。\n②7花生批注：\n根据②的“汽车空调领域使用的唯一制冷剂也是R12”可知，汽车空调的使用会增加氟利昂释放；又因“氟利昂的氯会破坏大气臭氧层，臭氧层漏洞能加剧温室效应”可知，汽车空调使用会加剧温室效应。\n28花生批注：\n原文虽介绍了仰卧的很多好处，但无法推知仰卧就是最适合人类的睡姿。\n29花生批注：\n原文表述为“能有效缓解颈部、背部酸痛的症状”,仰卧睡姿可缓解颈部和背部酸痛，不代表颈部和背部酸痛是由不良睡姿造成。也可能由不良坐姿、运动损伤等各种原因造成。\n例如：多吃菠菜可以补铁，不代表“缺铁是由于食用菠菜过少”。\n③0花生批注：\n传统节日是全文论述主体。\n性将端午节称为“粽子节”,仿佛节日除了吃粽子再无别的含义(转折引出问题)。\n这段文字接下来最应当探讨并解决的问题是："}],"annotatedOptionRich":{"A":[{"text":"怎样重拾传统文化(缺少主题词)"}],"B":[{"text":"怎样才能给端午节赋予更强的传统文化内涵(主体有误)"}],"C":[{"text":"怎样过节才是对中华民族传统信仰的传承(对策有误)"}],"D":[{"text":"怎样才能让人们更好地体验传统节日背后传统文化"}]},"practicalAnalysis":"文段先介绍了传统节日，尾句转折后提出问题，即“传统节日内涵被人淡忘”,上文提出问题，下文应给出有针对性的对策，D选项的“让人们更好体验传统节日背后的传统文化”对应上文问题“传统节日内涵(即文化) 被遗忘”,当选；\nA选项缺少主题词“传统节日”,排除； B选项主体有误，“端午节”出自举例部分，且对策有误，针对“传统节日的内涵被遗忘”的对策不应是“赋予更强文化内涵”,排除； C项的对策有误，未提及“传统节日背后的文化”, 排除。","notes":[{"marker":"26","content":"根据③的“氟利昂被发现泄漏到空气中会释放破坏大气臭氧层的氯”可知，氟利昂中的氯会破坏大气臭氧层。","matchScore":1.0829,"pairingMode":"content-similarity","order":25},{"marker":"②7","content":"根据②的“汽