INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300295,3,'下文推断类⑧','2021年4月8日，国家发展改革委印发《2021年新型城镇化和城乡融合发展重点任务》,落实适用、经济、绿色、美观的新时期建筑方针，严格限制建设500米以上超高层建筑，严禁建设“丑陋建筑”。作者接下来最有可能讲述的是：','[{"label":"A","content":"丑陋建筑上新闻的具体实例"},{"label":"B","content":"网友的审美是不可捉摸的"},{"label":"C","content":"“丑陋建筑”的共同特点"},{"label":"D","content":"网友们对这些建筑物外形的反感和不认可"}]','C','文段首先介绍文件的相关内容，文末提出新内容“丑陋建筑”, 下文应具体对新内容“丑陋建筑”进行介绍，故排除B选项、 D选项；
