INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300296,3,'标题拟定类','观看网络直播，其实也是观众寻找自我认同的一部分。在这个意义上来说，直播的具体内容并不是十分重要，重要的是，这种直播所激发的认同性想象。这也意味着，人们在消费感官娱乐的同时，也在认同直播者所传递出来的行为标准和模式。比如，观看购物直播，我们最后买到的往往不是最初想买的东西，而是被推销的东西，但事后想想其实根本用不着。
最适合做这段文字标题的是：','[{"label":"A","content":"网络主播的自我修炼"},{"label":"B","content":"方兴未艾的网络购物新模式"},{"label":"C","content":"当我们看直播时到底在看什么"},{"label":"D","content":"为什么我们买不到自己想要的东西"}]','C','文段分析见批注。
