INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300297,3,'语句填入类','科学就是不断接近真理的过程，所有理解这一点的人都明白：在发展过程中，不断更新知识才是科学进步的正道。然而， _:吸烟就从曾被医生推崇转变为被认为危害健康；吃肉曾被认为是有益的，后来又被说成是有害的，后来又变成有益的，现在又变成一个个人观点问题；女性应该接受乳房X光检查的年龄也提高了；地球曾被认为是宇宙的中心，后来又被发现不过是宇宙边缘的一颗行星。至于我自己，现在已经不知道喝红酒对健康究竟是有益还是有害了。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"这个过程有时会令人困惑和不安"},{"label":"B","content":"不同知识的“有效期”是不同的"},{"label":"C","content":"自然科学的前沿理论淘汰起来比社会科学更快"},{"label":"D","content":"人们总是固执地认为头脑中的某些知识是正确的\n片段阅读6 00 (上册)"}]','A','文段分析见批注。
文段首句介绍了科学是不断更新、不断接近真理的过程，转折后应当引出作者观点，下文举例说明一些知识的更新出现前后矛盾的现象，并在文末重申观点：“我已经不知道喝红酒对健康究竟有益还是有害了”,即因为科学的不断更新，有时甚至前后矛盾，给人们带来了困惑，正对应A选项，当选；
B选项的“不同知识的有效期”、 D选项的“固执认为某些知识正确”无中生有；C选项为区别比较联系类选项，文段未比较二者的淘汰速度，均排除。

花生批注：
35 行文结构：转折结构。
首句介绍了科学是不断更新、不断接近真理的过程；第二句是“然而”表转折提出观点并举例论证；
尾句总结作者观点态度“已经不知道有益还是有害”。','2018年黑龙江省考','进阶','published','{"globalNumber":297,"setNumber":15,"localNumber":17,"sourceLabel":"2018年黑龙江省考54%","accuracy":54,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"科学就是不断接近真理的过程，所有理解这一点的人都明白：在发展过程中，不断更新知识才是科学进步的正道。然而，"},{"text":"                        ","underline":true},{"text":" _:吸烟就从曾被医生推崇转变为被认为危害健康；吃肉曾被认为是有益的，后来又被说成是有害的，后来又变成有益的，现在又变成一个个人观点问题；女性应该接受乳房X光检查的年龄也提高了；地球曾被认为是宇宙的中心，后来又被发现不过是宇宙边缘的一颗行星。至于我自己，现在已经不知道喝红酒对健康究竟是有益还是有害了。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"这个过程有时会令人困惑和不安"}],"B":[{"text":"不同知识的“有效期”是不同的"}],"C":[{"text":"自然科学的前沿理论淘汰起来比社会科学更快"}],"D":[{"text":"人们总是固执地认为头脑中的某些知识是正确的\n片段阅读6 00 (上册)"}]},"annotatedStemRich":[{"text":"科学就是不断接近真理的过程，所有理解这一点的人都明白：在发展过程中，不断更新知识才是科学进步的正道。然而，"},{"text":"                         ","underline":true},{"text":"\n吸烟就从曾被医生推崇转变为被认为危害健康；吃肉曾被认为是有益的，后来又被说成是有害的，后来又变成有益的，现在又变成一个个人观点问题；女性应该接受乳房X 光检查的年龄也提高了；地球曾被认为是宇宙的中心，后来又被发现不过是宇宙边缘的一颗行星。至于我自己，现在已经不知道喝红酒对健康究竟是有益还是有害了。⑮\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"这个过程有时会令人困惑和不安"}],"B":[{"text":"不同知识的“有效期”是不同的"}],"C":[{"text":"自然科学的前沿理论淘汰起来比社会科学更快"}],"D":[{"text":"人们总是固执地认为头脑中的某些知识是正确的"}]},"practicalAnalysis":"文段分析见批注。\n文段首句介绍了科学是不断更新、不断接近真理的过程，转折后应当引出作者观点，下文举例说明一些知识的更新出现前后矛盾的现象，并在文末重申观点：“我已经不知道喝红酒对健康究竟有益还是有害了”,即因为科学的不断更新，有时甚至前后矛盾，给人们带来了困惑，正对应A选项，当选；\nB选项的“不同知识的有效期”、 D选项的“固执认为某些知识正确”无中生有；C选项为区别比较联系类选项，文段未比较二者的淘汰速度，均排除。","notes":[{"marker":"35","content":"行文结构：转折结构。\n首句介绍了科学是不断更新、不断接近真理的过程；第二句是“然而”表转折提出观点并举例论证；\n尾句总结作者观点态度“已经不知道有益还是有害”。","matchScore":0.6628,"pairingMode":"content-similarity","order":34}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300298,3,'下文推断类','人工智能的数据垄断为反垄断理论提出了新的实践问题，换句话说，反垄断法的理论创新是一种现实的实践需求。具体而言，反垄断法的理论创新需求主要有以下几个方面：第一，双边市场理论。与单边市场相对应，经济学家所提出的双边市场理论，能够为多边性数据市场的反垄断执法提供有益思路。当前的双边市场理论，一方面需要关注实践动向进一步完善理论自身，另一方面需要探索双边市场理论如何转化为可供操作适用的反垄断法律法规。第二，相关市场理论。人工智能的数据反垄断，需要探讨单独界定“数据市场”的必要性和可行性，还需要正视传统相关市场界定工具(如 SSNIP 测试法)在数据市场的无能为力，进而积极探索可替代性的分析工具。
这段文字接下来最可能讲述的是数据垄断的：','[{"label":"A","content":"法律渊源"},{"label":"B","content":"执法问题"},{"label":"C","content":"立法问题"},{"label":"D","content":"法律界定"}]','C','文段分析见批注。
文段开篇给出对策：反垄断法需要理论创新。下文具体分析为何需要理论创新。
上文的重点是宏观对策“反垄断法要理论创新”,下文应具体展开对策：介绍“反垄断法针对数据垄断该如何进行理论创新”,“法的理论创新”即立法问题，C选项正确；
其他选项均有逻辑问题，针对新问题“人工智能的数据垄断”,还没有相关法律法规，就无法谈论“法律渊源”、“法律执行”、“法律界定”问题，均排除。

