INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300299,3,'中心理解题','官兵中蕴藏着无穷的智慧，必须尊重官兵的主体地位和首创精神，集思广益、群策群力，推动部队发展。依靠官兵献计策。基层建得强不强，身处一线的基层官兵最有话语权。要充分发挥基层群众组织作用，畅通民主渠道，充分听取官兵建议，让官兵有话敢讲、畅所欲言，做到对官兵有问必答、有需必应。依靠官兵防风险。安全得之于众人之力，失之于一人之手，要把安全工作分解到每个人员、每个岗位，真正做到“我的安全我负责、单位安全我尽责、别人安全我有责”。
这段文字的内容可以概括为：','[{"label":"A","content":"端正态度走进基层官兵"},{"label":"B","content":"推进建设依靠基层官兵"},{"label":"C","content":"关心关爱赢得基层官兵"},{"label":"D","content":"要增强基层内生动力和工作主动性"}]','B','文段分析见批注。
文段开篇总观点是“要尊重官兵的主体地位，推动部队发展”,可翻译为“部队发展要尊重官兵”;B选项可翻译为“推进部队建设要依靠基层官兵”, 是原文对策的同义替换，当选；
A选项“端正态度”和C选项“关心关爱”均无中生有，直接排除；D选项缺少文段论述主体“官兵”,排除。

花生批注：
④ 官兵是文段论述主体。
④ 行文结构：总分结构。
首句总起：
要尊重官兵的主体地位，群策群力推动部队发展；
再从两个角度给出具体对策：
1. 要依靠官兵献计策；
2. 要依靠官兵防风险。','2020年湖北省事业单位','进阶','published','{"globalNumber":299,"setNumber":15,"localNumber":19,"sourceLabel":"2020年湖北省事业单位62%","accuracy":62,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"官兵中蕴藏着无穷的智慧，必须尊重官兵的主体地位和首创精神，集思广益、群策群力，推动部队发展。依靠官兵献计策。基层建得强不强，身处一线的基层官兵最有话语权。要充分发挥基层群众组织作用，畅通民主渠道，充分听取官兵建议，让官兵有话敢讲、畅所欲言，做到对官兵有问必答、有需必应。依靠官兵防风险。安全得之于众人之力，失之于一人之手，要把安全工作分解到每个人员、每个岗位，真正做到“我的安全我负责、单位安全我尽责、别人安全我有责”。\n这段文字的内容可以概括为："}],"optionRich":{"A":[{"text":"端正态度走进基层官兵"}],"B":[{"text":"推进建设依靠基层官兵"}],"C":[{"text":"关心关爱赢得基层官兵"}],"D":[{"text":"要增强基层内生动力和工作主动性"}]},"annotatedStemRich":[{"text":"官兵","underline":true},{"text":"◎中蕴藏着无穷的智慧，必须尊重官兵的主体地位和首创精神，集思广益、群策群力，推动部队发展(总)。依靠官兵献计策(分1)。基层建得强不强，身处一线的基层官兵最有话语权。要充分发挥基层群众组织作用，畅通民主渠道，充分听取官兵建议，让官兵有话敢讲、畅所欲言，做到对官兵有问必答、有需必应。依靠官兵防风险(分2)。安全得之于众人之力，失之于一人之手，要把安全工作分解到每个人员、每个岗位，真正做到“我的安全我\n负责、单位安全我尽责、别人安全我有责”。⑨ 这段文字的内容可以概括为："}],"annotatedOptionRich":{"A":[{"text":"端正态度走进基层官兵(无中生有)"}],"B":[{"text":"推进建设依靠基层官兵"}],"C":[{"text":"关心关爱赢得基层官兵(无中生有)"}],"D":[{"text":"要增强基层内生动力和工作主动性(缺主体)"}]},"practicalAnalysis":"文段分析见批注。\n文段开篇总观点是“要尊重官兵的主体地位，推动部队发展”,可翻译为“部队发展要尊重官兵”;B选项可翻译为“推进部队建设要依靠基层官兵”, 是原文对策的同义替换，当选；\nA选项“端正态度”和C选项“关心关爱”均无中生有，直接排除；D选项缺少文段论述主体“官兵”,排除。","notes":[{"marker":"④","content":"官兵是文段论述主体。","matchScore":0.9088,"pairingMode":"content-similarity","order":39},{"marker":"④","content":"行文结构：总分结构。\n首句总起：\n要尊重官兵的主体地位，群策群力推动部队发展；\n再从两个角度给出具体对策：\n1. 要依靠官兵献计策；\n2. 要依靠官兵防风险。","matchScore":0.6354,"pairingMode":"content-similarity","order":40}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300300,3,'中心理解题','没有18世纪的蒸汽机和纺织机，也就没有工业革命；没有19世纪的电气技术和汽车，没有20世纪的半导体、集成电路以及生物制药、互联网，也就没有今天众多的新产业和极大丰富的产品。但是， 21世纪的智能化手机能和蒸汽机、汽车相比吗?今天的很多技术虽然改变了生活方式，但没有带来新的动力和产业的巨变；许多高科技公司虽然抢眼风光，但对经济的实际影响并不像社会关注的那么大。我们面对的不单单是金融危机，其实也是一场产业危机和创新性危机。
这段文字表达了作者：','[{"label":"A","content":"对产业发展缺乏革命性创新的批评"},{"label":"B","content":"对缺乏提振经济的重大创新的忧虑"},{"label":"C","content":"对新技术革命不如传统技术的遗憾"},{"label":"D","content":"对创新性危机引发金融危机的警惕"}]','A','文段分析见批注。
文段对比18-20世纪与21世纪新技术的不同影响，得出“今天我们面对的是产业危机和创新性危机”;
观察选项，四个选项均为指出问题，问题依次概括为：产业发展缺乏革命性创新、缺乏提振经济的重大创新、新技术革命不如传统技术、创新性危机引发金融危机；
A选项的“产业发展”与“革命性创新”更能对应文末观点与前文分析，当选；
B选项的“经济”在尾句“其实”之前，并非重点，而且分析部分的“工业革命”、“今天的新产业和丰富产品”、“未带来新的动力和产业巨变”均未提及经济，排除；
C选项为区别比较联系类选项，文段并未进行二者比较，排除；
D选项的“创新性危机引发金融危机”为强加因果，无中生有，排除。

花生批注：
④ 行文结构：分总结构。
先对比古今：
18世纪的蒸汽机和纺织机，带来工业革命；
19世纪的电气技术和汽车， 20世纪的半导体、集成电路、生物制药和互联网，带来今天的新产业和丰富产品；
但21世纪的智能化手机能技术，许多高科技公司，无法和过去比较，没有带来新的动力和产业巨变，也没有巨大的经济影响；
最后给出总观点：
现在，我们面对的是产业危机和创新性危机。
④③ 批评、忧虑、遗憾、警惕，均能体现作者对问题的态度，不好辨析，并非解题重点。
④ A选项为正确选项有如下理由：
①产业与创新，能对应文末“其实也是一场产业危机和创新性危机”;
②产业更能对应前文的“也就没有今天众多的新产业”和“没有带来新的动力和产业巨变”;
③革命性创新，根据常识更能对应“工业革命”与“20 世纪的巨变”(工业革命、 20世纪巨变均是人类社会划时代的、革命性的进步);
④产业发展更具高度，经济只是产业发展、产业创新带来的结果。','2018年黑龙江省考','挑战','published','{"globalNumber":300,"setNumber":15,"localNumber":20,"sourceLabel":"2018年黑龙江省考 38%","accuracy":38,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"没有18世纪的蒸汽机和纺织机，也就没有工业革命；没有19世纪的电气技术和汽车，没有20世纪的半导体、集成电路以及生物制药、互联网，也就没有今天众多的新产业和极大丰富的产品。但是， 21世纪的智能化手机能和蒸汽机、汽车相比吗?今天的很多技术虽然改变了生活方式，但没有带来新的动力和产业的巨变；许多高科技公司虽然抢眼风光，但对经济的实际影响并不像社会关注的那么大。我们面对的不单单是金融危机，其实也是一场产业危机和创新性危机。\n这段文字表达了作者："}],"optionRich":{"A":[{"text":"对产业发展缺乏革命性创新的批评"}],"B":[{"text":"对缺乏提振经济的重大创新的忧虑"}],"C":[{"text":"对新技术革命不如传统技术的遗憾"}],"D":[{"text":"对创新性危机引发金融危机的警惕"}]},"annotatedStemRich":[{"text":"没有18世纪的蒸汽机和纺织机，也就没有工业革命；没有19世纪的电气技术和汽车，没有20世纪的半导体、集成电路以及生物制药、互联网，也就没有今天众多的新产业和极大丰富的产品。但是，21世纪的智能化手机能和蒸汽机、汽车相比吗?今天的很多技术虽然改变了生活方式，但没有带来新的动力和产业的巨变；许多高科技公司虽然抢眼风光，但对经济的实际影响并不像社会关注的那么大(举例分析)。我们面对的不单单是金融危机，其实也是一场产业危机和创新性危机(总观点)。②\n这段文字表达了作者："}],"annotatedOptionRich":{"A":[{"text":"对产业发展缺乏革命性创新的批评"}],"B":[{"text":"对缺乏提振经济的重大创新的忧虑(出处有误)"}],"C":[{"text":"对新技术革命不如传统技术的遗憾 (区别比较联系类)"}],"D":[{"text":"对创新性危机引发金融危机的警惕 (无中生有)\n④花生批注：\n行文结构：分总结构。\n先对比古今：\n18世纪的蒸汽机和纺织机，带来工业革命；\n19世纪的电气技术和汽车， 20世纪的半导体、集成电路、生物制药和互联网，带来今天的新产业和丰富产品；\n但21世纪的智能化手机能技术，许多高科技公司，无法和过去比较，没有带来新的动力和产业巨变，也没有巨大的经济影响；\n最后给出总观点：\n现在，我们面对的是产业危机和创新性危机。\n④③花生批注：\n批评、忧虑、遗憾、警惕，均能体现作者对问题的态度，不好辨析，并非解题重点。\n④花生批注：\nA 选项为正确选项有如下理由：\n①产业与创新，能对应文末“其实也是一场产业危机和创新性危机”;\n②产业更能对应前文的“也就没有今天众多的新产业”和“没有带来新的动力和产业巨变”;\n③革命性创新，根据常识更能对应“工业革命”与“20 世纪的巨变”(工业革命、 20世纪巨变均是人类社会划时代的、革命性的进步);\n④产业发展更具高度，经济只是产业发展、产业创新带来的结果"}]},"practicalAnalysis":"文段分析见批注。\n文段对比18-20世纪与21世纪新技术的不同影响，得出“今天我们面对的是产业危机和创新性危机”;\n观察选项，四个选项均为指出问题，问题依次概括为：产业发展缺乏革命性创新、缺乏提振经济的重大创新、新技术革命不如传统技术、创新性危机引发金融危机；\nA选项的“产业发展”与“革命性创新”更能对应文末观点与前文分析，当选；\nB选项的“经济”在尾句“其实”之前，并非重点，而且分析部分的“工业革命”、“今天的新产业和丰富产品”、“未带来新的动力和产业巨变”均未提及经济，排除；\nC选项为区别比较联系类选项，文段并未进行二者比较，排除；\nD选项的“创新性危机引发金融危机”为强加因果，无中生有，排除。","notes":[{"marker":"④","content":"行文结构：分总结构。\n先对比古今：\n18世纪的蒸汽机和纺织机，带来工业革命；\n19世纪的电气技术和汽车， 20世纪的半导体、集成电路、生物制药和互联网，带来今天的新产业和丰富产品；\n但21世纪的智能化手机能技术，许多高科技公司，无法和过去比较，没有带来新的动力和产业巨变，也没有巨大的经济影响；\n最后给出总观点：\n现在，我们面对的是产业危机和创新性危机。","matchScore":0.937,"pairingMode":"marker-and-content","order":41},{"marker":"④③","content":"批评、忧虑、遗憾、警惕，均能体现作者对问题的态度，不好辨析，并非解题重点。","matchScore":0.2092,"pairingMode":"content-similarity","order":42},{"marker":"④","content":"A选项为正确选项有如下理由：\n①产业与创新，能对应文末“其实也是一场产业危机和创新性危机”;\n②产业更能对应前文的“也就没有今天众多的新产业”和“没有带来新的动力和产业巨变”;\n③革命性创新，根据常识更能对应“工业革命”与“20 世纪的巨变”(工业革命、 20世纪巨变均是人类社会划时代的、革命性的进步);\n④产业发展更具高度，经济只是产业发展、产业创新带来的结果。","matchScore":0.6786,"pairingMode":"marker-and-content","order":43}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300301,3,'中心理解题','任何一个生命体都有生命周期，城市成长亦如此。人为拔苗助长只会打乱其发展过程中正常的自适应能力，进而引发一系列“城市病”,例如城市拥堵、环境污染、资源短缺等。“城市病”并非城市化进程中不可避免的问题，城市人口过快增长带来的较大的公共资源需求与公共资源有限供给及配置失衡的矛盾，人口非永久性的乡城迁移，城市规划的偏差与失调，使得“城市病”陷入迁延难愈或“旧病新疾”的困境之中。
这段文字重在强调：','[{"label":"A","content":"“城市病”的生命成长周期"},{"label":"B","content":"“城市病”症候的主要表现"},{"label":"C","content":"“城市病”陷入困境的原因"},{"label":"D","content":"“城市病”的“旧病新疾”"}]','C','文段分析见批注。
文段先提出问题，再分析造成这一问题的原因，是典型的果因结构文段， C选项是原因类选项，完美对应，当选；
A选项的“生命成长周期”出自首句引出话题部分，文段并未展开说明，非重点，排除；B选项“主要表现”仅对应提出问题的举例部分，并非重点，排除；
D选项③“旧病新疾”出自尾句，但“旧病新疾”是什么并未展开介绍，排除。

花生批注：
① 城市病是全文论述话题。
② 行文结构：果因结构；
先提出“城市病”这一问题；接着分析造成“城市病”这
一现象的原因：城市人口过快增长带来的较大的公共资源需求与公共资源有限供给及配置失衡的矛盾，人口非永久性的乡城迁移，城市规划的偏差与失调。
③ 若D选项是正确答案，原文应是具体类文段，重点介绍城市病以前的表现和现在的表现；
原文并未体现，D选项排除。
片段阅读600','2022年福建省事业单位','基础','published','{"globalNumber":301,"setNumber":16,"localNumber":1,"sourceLabel":"2022年福建省事业单位73%","accuracy":73,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"任何一个生命体都有生命周期，城市成长亦如此。人为拔苗助长只会打乱其发展过程中正常的自适应能力，进而引发一系列“城市病”,例如城市拥堵、环境污染、资源短缺等。“城市病”并非城市化进程中不可避免的问题，城市人口过快增长带来的较大的公共资源需求与公共资源有限供给及配置失衡的矛盾，人口非永久性的乡城迁移，城市规划的偏差与失调，使得“城市病”陷入迁延难愈或“旧病新疾”的困境之中。\n这段文字重在强调："}],"optionRich":{"A":[{"text":"“城市病”的生命成长周期"}],"B":[{"text":"“城市病”症候的主要表现"}],"C":[{"text":"“城市病”陷入困境的原因"}],"D":[{"text":"“城市病”的“旧病新疾”"}]},"annotatedStemRich":[{"text":"任何一个生命体都有生命周期，城市成长亦如此。人为拔苗助长只会打乱其发展过程中正常的自适应能力，进而引发一系列“"},{"text":"城市病","underline":true},{"text":"①”,例如城市拥堵、环境污染、资源短缺等(提出问题)。“城市病”并非城市化进程中不可避免的问题，城市人口过快增长带来的较大的公共资源需求与公共资源有限供给及配置失衡的矛盾，人口非永久性的乡城迁移，城市规划的偏差与失调，使得“城市病”陷入迁延难愈或“旧病新疾”的困境之中("},{"text":"分析造成城市病的原因)。②","bold":true},{"text":"\n这段文字重在强调："}],"annotatedOptionRich":{"A":[{"text":"“城市病”的生命成长周期(无中生有)"}],"B":[{"text":"“城市病”症候的主要表现 (出处有误)"}],"C":[{"text":"“城市病”陷入困境的原因"}],"D":[{"text":"“城市病”的“旧病新疾”(具体类)"}]},"practicalAnalysis":"文段分析见批注。\n文段先提出问题，再分析造成这一问题的原因，是典型的果因结构文段， C选项是原因类选项，完美对应，当选；\nA选项的“生命成长周期”出自首句引出话题部分，文段并未展开说明，非重点，排除；B选项“主要表现”仅对应提出问题的举例部分，并非重点，排除；\nD选项③“旧病新疾”出自尾句，但“旧病新疾”是什么并未展开介绍，排除。","notes":[{"marker":"①","content":"城市病是全文论述话题。","matchScore":0.3604,"pairingMode":"marker-and-content","order":0},{"marker":"②","content":"行文结构：果因结构；\n先提出“城市病”这一问题；接着分析造成“城市病”这\n一现象的原因：城市人口过快增长带来的较大的公共资源需求与公共资源有限供给及配置失衡的矛盾，人口非永久性的乡城迁移，城市规划的偏差与失调。","matchScore":1.0608,"pairingMode":"marker-and-content","order":1},{"marker":"③","content":"若D选项是正确答案，原文应是具体类文段，重点介绍城市病以前的表现和现在的表现；\n原文并未体现，D选项排除。\n片段阅读600","matchScore":0.2927,"pairingMode":"marker-and-content","order":2}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300302,3,'中心理解题','书院是中国历史上一种独具特色的文化教育形式，在书院发展的一千多年历史进程中，它不仅是中国文化的象征，更是中国文化向域外传播的窗口。书院之名起于唐代，由最早的修书、藏书的机构，逐步演变为具有教学、研究功能的场所。书院制度在宋代不断发展、壮大、成熟，清代是书院发展的鼎盛时期，无论是穷乡僻壤，还是边陲小镇都可见到书院。不仅如此，书院还随儒学走出国门，在朝鲜半岛生根、萌芽、兴盛起来，对中国文化传播起着不可替代的作用。
这段文字主要说明：','[{"label":"A","content":"书院的发展经历了漫长的历史过程"},{"label":"B","content":"书院所承载的教育及文化传播功能"},{"label":"C","content":"书院与文明传承之间有着密切关系"},{"label":"D","content":"书院制度的影响遍布我国以及域外"}]','B','文段分析见批注。
文段可看作总分结构，首句直接给出总观点，根据下文分述内容可将其理解为“书院既是我国独具特色的文化教育形式，也是中国文化的象征和向外传播的窗口”,强调书院包含了“教育”和“文化传播”这两项功能，只有B选项同时提到了书院的这两个特征⑥,完美选项，当选；
A选项是历程类选项⑦,且只对应分析论证的第一部分，表述片面，排除； D选项只强调了书院制度的文化传播属性，忽略了其教育属性，表述片面，排除；
C选项“文明传承”无中生有，排除；综上，正确答案是B选项。

花生批注：
⑤ 行文结构：总分结构。
首句给出总观点：
书院是我国独具特色的文化教育形式；
还是中国文化象征，是中国文化向外传播的窗口；
后文从两方面介绍：
“不仅如此”前：介绍书院的教育功能；
“不仅如此”后：介绍书院的文化传播功能。
⑥ 1. A 且B 类选项，满足一正确；
2. 概括首句作者观点，同时体现书院的“教育”和“文化传播”功能。
⑦ 文段只在分析论证的第一部分体现了书院的发展(且不是“分1”的全部内容), 不是文段论述的重点。
(下册)','2020年江苏省考','基础','published','{"globalNumber":302,"setNumber":16,"localNumber":2,"sourceLabel":"2020年江苏省考 74%","accuracy":74,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"书院是中国历史上一种独具特色的文化教育形式，在书院发展的一千多年历史进程中，它不仅是中国文化的象征，更是中国文化向域外传播的窗口。书院之名起于唐代，由最早的修书、藏书的机构，逐步演变为具有教学、研究功能的场所。书院制度在宋代不断发展、壮大、成熟，清代是书院发展的鼎盛时期，无论是穷乡僻壤，还是边陲小镇都可见到书院。不仅如此，书院还随儒学走出国门，在朝鲜半岛生根、萌芽、兴盛起来，对中国文化传播起着不可替代的作用。\n这段文字主要说明："}],"optionRich":{"A":[{"text":"书院的发展经历了漫长的历史过程"}],"B":[{"text":"书院所承载的教育及文化传播功能"}],"C":[{"text":"书院与文明传承之间有着密切关系"}],"D":[{"text":"书院制度的影响遍布我国以及域外"}]},"annotatedStemRich":[{"text":"书院","underline":true},{"text":"⑨是中国历史上一种独具特色的文化教育形式，在书院发展的一千多年历史进程中，它不仅是中国文化的象征，更是中国文化向域外传播的窗口(开门见山提出观点)。书院之名起于唐代，由最早的修书、藏书的机构，逐步演变为具有教学、研究功能的场所。书院制度在宋代不断发展、壮大、成熟，清代是书院发展的鼎盛时期，无论是穷乡僻壤，还是边陲小镇都可见到书院(分 1)。不仅如此，书院还随儒学走出国门，在朝鲜半岛生根、萌芽、兴盛起来，对中国文化传播起着不可替代的作用(分2)。⑤\n这段文字主要说明："}],"annotatedOptionRich":{"A":[{"text":"书院的发展经历了漫长的历史过程(历程类)"}],"B":[{"text":"书院所承载的教育及文化传播功能"}],"C":[{"text":"书院与文明传承之间有着密切关系(无中生有)"}],"D":[{"text":"书院制度的影响遍布我国以及域外(片面)"}]},"practicalAnalysis":"文段分析见批注。\n文段可看作总分结构，首句直接给出总观点，根据下文分述内容可将其理解为“书院既是我国独具特色的文化教育形式，也是中国文化的象征和向外传播的窗口”,强调书院包含了“教育”和“文化传播”这两项功能，只有B选项同时提到了书院的这两个特征⑥,完美选项，当选；\nA选项是历程类选项⑦,且只对应分析论证的第一部分，表述片面，排除； D选项只强调了书院制度的文化传播属性，忽略了其教育属性，表述片面，排除；\nC选项“文明传承”无中生有，排除；综上，正确答案是B选项。","notes":[{"marker":"⑤","content":"行文结构：总分结构。\n首句给出总观点：\n书院是我国独具特色的文化教育形式；\n还是中国文化象征，是中国文化向外传播的窗口；\n后文从两方面介绍：\n“不仅如此”前：介绍书院的教育功能；\n“不仅如此”后：介绍书院的文化传播功能。","matchScore":0.8106,"pairingMode":"marker-and-content","order":4},{"marker":"⑥","content":"1. A 且B 类选项，满足一正确；\n2. 概括首句作者观点，同时体现书院的“教育”和“文化传播”功能。","matchScore":0.4725,"pairingMode":"marker-and-content","order":5},{"marker":"⑦","content":"文段只在分析论证的第一部分体现了书院的发展(且不是“分1”的全部内容), 不是文段论述的重点。\n(下册)","matchScore":0.4615,"pairingMode":"marker-and-content","order":6}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300303,3,'中心理解题','历史表明，中国抗日战争是世界反法西斯战争的重要组成部分，中国战场是世界反法西斯战争的东方主战场。确立“十四年抗战”,更能完整地审视中国抗日战争与世界反法西斯战争的密切关联，更能完整地体现中国人民为夺取世界反法西斯战争的胜利、维护世界正义与进步事业所付出的巨大牺牲和作出的重大贡献，更能完整地讲好“中国抗战故事”。
