INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300312,3,'下文推断类②','今年来，通过“葛优躺”“懒猫瘫”等娱乐文化符号表达态度情绪的“丧文化”,借助网络社交平台，搭车商业营销在部分青年中流行开来，“我差不多是个废人了”等散发着绝望特质的话语，成为时下一些青年人的口头禅。客观来讲，我们尚不至于谈“丧”色变，然而语言毕竟是传播人们思想和情绪的交互性工具。“丧文化”消极的解构话语在相互调侃中，自然会将负面消极情绪渲染开来。“丧文化”的背后是西方资本主义个人至上价值观，其极端自我功利性误导人们轻视家庭，蔑视亲情，偶遇挫折便自暴自弃、甘于堕落、颓废人生。
接下来最可能讲的是：','[{"label":"A","content":"我们要警惕和抵制丧文化"},{"label":"B","content":"丧文化源自互联网，注定只会是昙花一现"},{"label":"C","content":"年轻人更要正视挫折和困难，不能一味躲避乃至屈服"},{"label":"D","content":"文化氛围的造就需要网民媒体社会组织乃至国家机构齐心协力"}]','A','文段提出了“丧文化”背后的问题，并分析了其实质和带来的后果，根据下文推断类常见行文结构，提出并分析问题后常会提出对策，且应包含文段话题“丧文化”,对应A选项，当选；
其他选项：B选项非对策表述，并且“昙花一现”无中生有；C选项对策针对的问题为年轻人面对挫折和困难躲避乃至屈服，这只是原文“丧文化”问题带来的后果，而非根本问题；D选项的对策针对的问题为“怎样造就文化氛围”,不能解决“丧文化”问题，均可排除。

花生批注：
② 丧文化是全文论述话题。','2019年安徽省事业单位','基础','published','{"globalNumber":312,"setNumber":16,"localNumber":12,"sourceLabel":"2019年安徽省事业单位73%","accuracy":73,"typeAndPassage":"下文推断类②+提出、分析问题→解决问题","stemRich":[{"text":"今年来，通过“葛优躺”“懒猫瘫”等娱乐文化符号表达态度情绪的“丧文化”,借助网络社交平台，搭车商业营销在部分青年中流行开来，“我差不多是个废人了”等散发着绝望特质的话语，成为时下一些青年人的口头禅。客观来讲，我们尚不至于谈“丧”色变，然而语言毕竟是传播人们思想和情绪的交互性工具。“丧文化”消极的解构话语在相互调侃中，自然会将负面消极情绪渲染开来。“丧文化”的背后是西方资本主义个人至上价值观，其极端自我功利性误导人们轻视家庭，蔑视亲情，偶遇挫折便自暴自弃、甘于堕落、颓废人生。\n接下来最可能讲的是："}],"optionRich":{"A":[{"text":"我们要警惕和抵制丧文化"}],"B":[{"text":"丧文化源自互联网，注定只会是昙花一现"}],"C":[{"text":"年轻人更要正视挫折和困难，不能一味躲避乃至屈服"}],"D":[{"text":"文化氛围的造就需要网民媒体社会组织乃至国家机构齐心协力"}]},"annotatedStemRich":[{"text":"今年来，通过“葛优躺”“懒猫瘫”等娱乐文化符号表达态度情绪的“丧"},{"text":"文化","underline":true},{"text":"②”,借助网络社交平台，搭车商业营销在部分青年中流行开来，“我差不多是个废人了”等散发着绝望特质的话语，成为时下一些青年人的口头禅( 背景引入话题)。客观来讲，我们尚不至于谈“丧”色变，然而语言毕竟是传播人们思想和情绪的交互性工具。“丧文化”消极的解构话语在相互调侃中，自然会将负面消极情绪渲染开来("},{"text":"转折提出问题)","bold":true},{"text":"。“丧文化”的背后是西方资本主义个人至上价值观，其极端自我功利性误导人们轻视家庭，蔑视亲情，偶遇挫折便自暴自弃、甘于堕落、颓废人生"},{"text":"(分析问题)。","bold":true},{"text":"\n接下来最可能讲的是："}],"annotatedOptionRich":{"A":[{"text":"我们要警惕和抵制丧文化"}],"B":[{"text":"丧文化源自互联网，注定只会是昙花一现("},{"text":"非对策选项)","bold":true}],"C":[{"text":"年轻人更要正视挫折和困难，不能一味躲避乃至屈服(对策有误)"}],"D":[{"text":"文化氛围的造就需要网民媒体社会组织乃至国家机构齐心协力"},{"text":"(对策有误)","bold":true},{"text":"\n"},{"text":"IG","bold":true}]},"practicalAnalysis":"文段提出了“丧文化”背后的问题，并分析了其实质和带来的后果，根据下文推断类常见行文结构，提出并分析问题后常会提出对策，且应包含文段话题“丧文化”,对应A选项，当选；\n其他选项：B选项非对策表述，并且“昙花一现”无中生有；C选项对策针对的问题为年轻人面对挫折和困难躲避乃至屈服，这只是原文“丧文化”问题带来的后果，而非根本问题；D选项的对策针对的问题为“怎样造就文化氛围”,不能解决“丧文化”问题，均可排除。","notes":[{"marker":"②","content":"丧文化是全文论述话题。","matchScore":0.3518,"pairingMode":"marker-and-content","order":25}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300313,3,'语句填入类','近几年电价一直没有上涨，管控较紧，因为电价跟粮食一样，影响面很大，从经济和人民生活的高质量追求角度考虑，只能稳电价，不敢轻易涨。对于电力系统来说，成本上升，电价稳定不动的话，电力系统将无法消化转型成本，如果靠政府补贴，将不可持续；即使通过技术进步提高效率、抵消成本，空间也有限。因此，。当然，市场化的手段不是简单地转嫁成本，而是通过市场化的价格信号，改变产业的格局，推进相关的改革。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"就必须借助降低转型成本来拓展其市场空间"},{"label":"B","content":"有必要通过运用市场化手段来协助政策调控"},{"label":"C","content":"可尝试通过合理配置资源来启动市场化手段"},{"label":"D","content":"还需要依靠相对市场化的手段解决转型成本"}]','D','文段分析见批注。
文段可看作前对策结构，前文提出电力系统的转型成本问题，横线处的对策需要从后文论证部分提炼，即“用市场化手段解决电力系统成本大的问题”; D选项既体现了问题也体现了对策，可翻译为“解决转型成本(问题)需要市场化手段(对策)”,完美选项，当选；
A选项可翻译为“扩展市场空间(问题)需要降低转型成本(对策)”, 对策问题均有误；B选项可翻译为“协助政策调控(问题)需要市场化手段(对策)”,问题有误；C选项可翻译为“启动市场化手段(问题)需要合理资源

花生批注：
9 行文结构：前对策结构。
背景引出问题：
电力系统转型成本大；
横线处从论证部分提炼对策：
电力系统转型成本大可以用市场化手段解决。
填入文中画横线部分最恰当的一项是：
A. 就必须借助降低转型成本来拓展其市场空间
B. 有必要通过运用市场化手段来协助政策调控
C. 可尝试通过合理配置资源来启动市场化手段
D. 还需要依靠相对市场化的手段解决转型成本
③0 选项的句式变来变去，要学会把选项的语序统一：解决 XXX问题，需要XXX对策，这样问题和对策才清晰，不容易选错。
配置(对策)”,对策问题均有误；⑧
综上，正确答案是D选项。
