INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300314,3,'语句填入类','压缩空气储能属于一种物理方式的储能，即空气在整个过程中只存在温度、压强等状态的变化，而不会发生化学方面的变化。储存了众多电力的压缩空气需要放在一间封闭性极好的“屋子”里，而这间“屋子”的“主人”就是盐。食盐开采后会自然留下一个场所，学名叫做“盐穴”。“盐穴”是一种极其宝贵的不可再生资源，并且密封性能良好。然而，长期以来这种资源的利用系数很低。由于盐岩具有良好的蠕变特性、自愈合特性，渗透率极低，并且不会与空气中的氧气发生反应。因此，
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"要依托盐穴资源的优势发展储能产业"},{"label":"B","content":"“盐穴”是储存高压空气的理想场所"},{"label":"C","content":"应当利用盐穴储能改善发电与用电"},{"label":"D","content":"要大力开发盐岩提高能源利用效率"}]','B','所填入语句在文末，可猜测其是对上文的概括总结。
文段先介绍“压缩空气需要一间封闭性极好的‘屋子’”,之后介绍“这间屋子叫‘盐穴’”,并且介绍了“盐穴和盐岩的优点，且过去利用系数很低”;

花生批注：
③ 文段类似逻辑的断点搭桥题目：
压缩空气需要存放场所；
盐穴是合适的存放场所；
因此：可以用盐穴存放压缩空气。
填入文中画横线部分最恰当的一项是：
A. 要依托盐穴资源的优势发展储能产业
B. “盐穴”是储存高压空气的理想场所
C. 应当利用盐穴储能改善发电与用电
D. 要大力开发盐岩提高能源利用效率
③ 例如：现金需要保存场所，保险柜有安全、封闭等优点，但保险柜现在利用率很低，所以…… ;
“所以”后给出的对策应是“用保险柜存放现金”;
而非“要提高保险柜利用率”,后者对策不够具体，不知道应如何提高利用率，而且未解决“现金需要保存场所”这一问题。
简略来说就是，“压缩空气需要存放场所”,“盐穴正合适”,所以“因此”后应作总结“压缩空气可以存储在盐穴”,即提及“盐穴”,又解决了“压缩空气需要存储场所”的问题，对应B选项，当选；
A选项的“储能产业”过于宽泛，盐穴适合存放“压缩空气储能的‘高压空气’”,而非适合所有储能产业，排除；C选项未提及“压缩空气”,排除； D选项只对应前文的“盐穴利用系数很低”,未提及全文谈论的“压缩空气储能” , 排除。','2020年海南省考','进阶','published','{"globalNumber":314,"setNumber":16,"localNumber":14,"sourceLabel":"2020年海南省考55%","accuracy":55,"typeAndPassage":"语句填入类+科普介绍文章","stemRich":[{"text":"压缩空气储能属于一种物理方式的储能，即空气在整个过程中只存在温度、压强等状态的变化，而不会发生化学方面的变化。储存了众多电力的压缩空气需要放在一间封闭性极好的“屋子”里，而这间“屋子”的“主人”就是盐。食盐开采后会自然留下一个场所，学名叫做“盐穴”。“盐穴”是一种极其宝贵的不可再生资源，并且密封性能良好。然而，长期以来这种资源的利用系数很低。由于盐岩具有良好的蠕变特性、自愈合特性，渗透率极低，并且不会与空气中的氧气发生反应。因此，\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"要依托盐穴资源的优势发展储能产业"}],"B":[{"text":"“盐穴”是储存高压空气的理想场所"}],"C":[{"text":"应当利用盐穴储能改善发电与用电"}],"D":[{"text":"要大力开发盐岩提高能源利用效率"}]},"annotatedStemRich":[{"text":"压缩空气储能属于一种物理方式的储能，即空气在整个过程中只存在温度、压强等状态的变化，而不会发生化学方面的变化。储存了众多电力的压缩空气需要放在一间封闭性极好的“屋子”里(压缩空气需要存放场所),而这间“屋子”的“主人”就是盐。食盐开采后会自然留下一个场所，学名叫做“盐穴”。“盐穴”是一种极其宝贵的不可再生资源，并且密封性能良好。然而，长期以来这种资源的利用系数很低。由于盐岩具有良好的蠕变特性、自愈合特性，渗透率极低，并且不会与空气中的氧气发生反应(盐穴正合适存放压缩空气)。因此， "},{"text":" ","underline":true},{"text":" ③\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"要依托盐穴资源的优势发展储能产业"}],"B":[{"text":"“盐穴”是储存高压空气的理想场所"}],"C":[{"text":"应当利用盐穴储能改善发电与用电"}],"D":[{"text":"要大力开发盐岩提高能源利用效率"}]},"practicalAnalysis":"所填入语句在文末，可猜测其是对上文的概括总结。\n文段先介绍“压缩空气需要一间封闭性极好的‘屋子’”,之后介绍“这间屋子叫‘盐穴’”,并且介绍了“盐穴和盐岩的优点，且过去利用系数很低”;","notes":[{"marker":"③","content":"文段类似逻辑的断点搭桥题目：\n压缩空气需要存放场所；\n盐穴是合适的存放场所；\n因此：可以用盐穴存放压缩空气。\n填入文中画横线部分最恰当的一项是：\nA. 要依托盐穴资源的优势发展储能产业\nB. “盐穴”是储存高压空气的理想场所\nC. 应当利用盐穴储能改善发电与用电\nD. 要大力开发盐岩提高能源利用效率","matchScore":0.4976,"pairingMode":"marker-and-content","order":29},{"marker":"③","content":"例如：现金需要保存场所，保险柜有安全、封闭等优点，但保险柜现在利用率很低，所以…… ;\n“所以”后给出的对策应是“用保险柜存放现金”;\n而非“要提高保险柜利用率”,后者对策不够具体，不知道应如何提高利用率，而且未解决“现金需要保存场所”这一问题。\n简略来说就是，“压缩空气需要存放场所”,“盐穴正合适”,所以“因此”后应作总结“压缩空气可以存储在盐穴”,即提及“盐穴”,又解决了“压缩空气需要存储场所”的问题，对应B选项，当选；\nA选项的“储能产业”过于宽泛，盐穴适合存放“压缩空气储能的‘高压空气’”,而非适合所有储能产业，排除；C选项未提及“压缩空气”,排除； D选项只对应前文的“盐穴利用系数很低”,未提及全文谈论的“压缩空气储能” , 排除。","matchScore":0.3128,"pairingMode":"marker-and-content","order":30}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300315,3,'语句填入类','世界充满了流动，人类社会也是这样，现代智人出现以来，经历了大陆、岛屿间的漫长迁徙历史，而小麦和玉米等物种也实现了跨大陆流动。从世界文明进程来看，同样是流动促进了人类文明的存续与发展。某一区域的文化传播到世界各地，会与当地文化结合产生新的文化形态，但 ,结合得好就成为新的文明方式，如佛教从印度传入中国后，受到中国固有传统思想的改造和融合，经1000多年形成了独具特质的新体系，相反，结合得不好就“水过地皮湿”。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"看待文化流动所带来的价值"},{"label":"B","content":"这种新文化形态也会有不同的命运"},{"label":"C","content":"文化传播也应兼顾当地文化的特殊属性"},{"label":"D","content":"文化流动在各地发挥的作用是不一样的"}]','D','文段分析见批注。
所填入语句后介绍的是文化“结合得好”和“结合的不好”的不同结果， A选项、C选项未体现结果的不同，可简单排除；
与 B选项③相比，D选项的主语“文化流动”对应前文的“世界流动、人类流动和文明流动”,“各地发挥的作用是不一样的”对应后文的“结合的好与不好”的不同结果，呼应上下文，更贴近文段，当选。

花生批注：
33 文段三句话可依次分析：
①②两句话介绍世界流动、人类流动和文明流动；
③句介绍文化流动的不同结果。
②从世界文明进程来看，同样是流动促进了人类文明的存续与发展。③某一区域的文化传播到世界各地，会与当地文化结合产生新的文化形态，但 ,结合得好就成为新的文明方式，如佛教从印度传入中国后，受到中国固有传统思想的改造和融合，经1000多年形成了独具特质的新体系，相反，结合得不好就“水过地皮湿”。③
A海IGO公NGK考AO 练习题16套
填入文中画横线部分最恰当的一项是：
A. 看待文化流动所带来的价值
③④ 除了未体现“流动”,B选项还有如下两个问题：
①“新文化形态结合的好就成为新的文明方式”,逻辑存在问题，“新文化形态”已经是结合后的新文化，结合后的新文化不会再成为新的文明方式；
②某一区域的文化传播到世界各地，与当地文化结合产生新的文化形态，形成的“新文化形态”应是多种多样，应是复数，用“这种新文化形态”指代有误，应是“这些新文化形态”。
C. 文化传播也应兼顾当地文化的特殊属性','2022年天津市考','挑战','published','{"globalNumber":315,"setNumber":16,"localNumber":15,"sourceLabel":"2022年天津市考 11%","accuracy":11,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"世界充满了流动，人类社会也是这样，现代智人出现以来，经历了大陆、岛屿间的漫长迁徙历史，而小麦和玉米等物种也实现了跨大陆流动。从世界文明进程来看，同样是流动促进了人类文明的存续与发展。某一区域的文化传播到世界各地，会与当地文化结合产生新的文化形态，但 "},{"text":" ","underline":true},{"text":" ,结合得好就成为新的文明方式，如佛教从印度传入中国后，受到中国固有传统思想的改造和融合，经1000多年形成了独具特质的新体系，相反，结合得不好就“水过地皮湿”。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"看待文化流动所带来的价值"}],"B":[{"text":"这种新文化形态也会有不同的命运"}],"C":[{"text":"文化传播也应兼顾当地文化的特殊属性"}],"D":[{"text":"文化流动在各地发挥的作用是不一样的"}]},"annotatedStemRich":[{"text":"①世界充满了流动，人类社会也是这样，现代智人出现以来，经历了大陆、岛屿间的漫长迁徙历史，而小麦和玉米等物种也实现了跨大陆流动。\n②从世界文明进程来看，同样是流动促进了人类文明的存续与发展。③某一区域的文化传播到世界各地，会与当地文化结合产生新的文化形态，但 "},{"text":" ","underline":true},{"text":" ,结合得好就成为新的文明方式，如佛教从印度传入中国后，受到中国固有传统思想的改造和融合，经1000多年形成了独具特质的新体系，相反，结合得不好就“水过地皮湿”。③\n"},{"text":"A海IGO公NGK考AO ","bold":true},{"text":"练习题16套\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"看待文化流动所带来的价值"}],"B":[{"text":"这种新文化形态也会有不同的命运"}],"C":[{"text":"文化传播也应兼顾当地文化的特殊属性"}],"D":[{"text":"文化流动在各地发挥的作用是不一样的"}]},"practicalAnalysis":"文段分析见批注。\n所填入语句后介绍的是文化“结合得好”和“结合的不好”的不同结果， A选项、C选项未体现结果的不同，可简单排除；\n与 B选项③相比，D选项的主语“文化流动”对应前文的“世界流动、人类流动和文明流动”,“各地发挥的作用是不一样的”对应后文的“结合的好与不好”的不同结果，呼应上下文，更贴近文段，当选。","notes":[{"marker":"33","content":"文段三句话可依次分析：\n①②两句话介绍世界流动、人类流动和文明流动；\n③句介绍文化流动的不同结果。\n②从世界文明进程来看，同样是流动促进了人类文明的存续与发展。③某一区域的文化传播到世界各地，会与当地文化结合产生新的文化形态，但 ,结合得好就成为新的文明方式，如佛教从印度传入中国后，受到中国固有传统思想的改造和融合，经1000多年形成了独具特质的新体系，相反，结合得不好就“水过地皮湿”。③\nA海IGO公NGK考AO 练习题16套\n填入文中画横线部分最恰当的一项是：\nA. 看待文化流动所带来的价值","matchScore":1.3217,"pairingMode":"content-similarity","order":31},{"marker":"③④","content":"除了未体现“流动”,B选项还有如下两个问题：\n①“新文化形态结合的好就成为新的文明方式”,逻辑存在问题，“新文化形态”已经是结合后的新文化，结合后的新文化不会再成为新的文明方式；\n②某一区域的文化传播到世界各地，与当地文化结合产生新的文化形态，形成的“新文化形态”应是多种多样，应是复数，用“这种新文化形态”指代有误，应是“这些新文化形态”。\nC. 文化传播也应兼顾当地文化的特殊属性","matchScore":0.5167,"pairingMode":"content-similarity","order":32}],"pairingMode":"text-and-seq