INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300316,3,'语句排序类','①王国维发现了庙号与祭祀天干日的对应，即某王的庙号为某天干，则在该天干日祭祀该王
②有学者则提出，商王族分为以天干命名的十个“支派”,庙号标志的是商王所属支派
③如商王朝的建立者成汤庙号为大乙，对他的祭祀便都安排在乙日举行，王国维因此提出，庙号是根据各种情况确定的“祭名”
④商王均以天干为庙号，汉儒们曾认为是其生日的天干名，即所谓“殷家质，故直以生日名子也”
⑤无论如何，天干地支计日法在商代的祭祀活动中都是至关重要的
⑥十天干配十二地支形成60天循环的计日法在商代已经完备，主要用于安排仪式活动将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"①③⑤⑥④②"},{"label":"B","content":"⑥④①③②⑤"},{"label":"C","content":"④⑤③①②⑥"},{"label":"D","content":"⑤①③②⑥④"}]','B','根据选项观察首句，⑥句介绍了“十天干配十二地支的60 天循环的计日法”,⑤评价该计日法的作用且有“无论如何”这一常见结论标志词，根据逻辑，⑥一定在⑤前，答案直接锁定B选项；
验证B选项：⑥引出“天干地支计日法”,④介绍汉儒的猜想，①③介绍王国维的猜想，②介绍某学者猜想，⑤用“无论如何”作总结，无论实际如何，该计日法在商代都很重要。

花生批注：
35 行文结构：分总结构；
⑥句引出话题：天干地支计日法；
④①③②四句按照研究时间的推移针对“天干与庙号”的关系提出了三种不同的见解
⑤句总结前文，指出无论实际如何，此计日法在商代都有重要地位。
