INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300318,3,'语句排序类','①目前我国常住人口城镇化率为59.58%,户籍人口城镇化率为43.37%
②社会治理是中国特色社会学研究的一个基本课题，也是有可能做出突出研究成果的一个重要领域
③所以，我国社会学者的一大任务，就是探索一条使我国社会既充满活力，又保持秩序的现代化转型之路
④社会治理的基本原则是激发活力和保持社会秩序，困难之处在于我国正处于现代化转型任务比较艰巨的时期
⑤根据世界各国现代化的经验，当城镇化率处于50%上下的时候，是现代化转型最为艰巨的时期
⑥正是在这样的背景下，党中央提出“社会治理”的概念将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"④①②③⑥⑤"},{"label":"B","content":"①④⑥②③⑤"},{"label":"C","content":"⑤②⑥①③④"},{"label":"D","content":"②④⑤①③⑥"}]','D','本题可从两个角度入手：一是首句，②介绍社会治理是什么, ④介绍社会治理的基本原则是什么,这两句均为下定义，常用作首句；二是 ①⑤均包含数字(城镇化率),二者捆绑可能性较大。由此，基本锁定D选项；
验证D选项：②④下定义介绍社会治理和其基本原则，④引出我国正处于现代化转型任务比较艰巨的时期，⑤①通过城镇化率解释我国为何处于现代化转型艰巨时期，③⑥给出对策：在上述背景下，党中央提出“社会治理”的概念，且与首句“社会治理”呼应；逻辑正确，当选。','2021年四川省考','基础','published','{"globalNumber":318,"setNumber":16,"localNumber":18,"sourceLabel":"2021年四川省考 71%","accuracy":71,"typeAndPassage":"语句排序类+科普介绍文章","stemRich":[{"text":"①目前我国常住人口城镇化率为59.58%,户籍人口城镇化率为43.37%\n②社会治理是中国特色社会学研究的一个基本课题，也是有可能做出突出研究成果的一个重要领域\n③所以，我国社会学者的一大任务，就是探索一条使我国社会既充满活力，又保持秩序的现代化转型之路\n④社会治理的基本原则是激发活力和保持社会秩序，困难之处在于我国正处于现代化转型任务比较艰巨的时期\n⑤根据世界各国现代化的经验，当城镇化率处于50%上下的时候，是现代化转型最为艰巨的时期\n⑥正是在这样的背景下，党中央提出“社会治理”的概念将以上6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"④①②③⑥⑤"}],"B":[{"text":"①④⑥②③⑤"}],"C":[{"text":"⑤②⑥①③④"}],"D":[{"text":"②④⑤①③⑥"}]},"annotatedStemRich":[{"text":"①目前我国常住人口城镇化率为59.58%,户籍人口城镇化率为43.37%\n②社会治理是中国特色社会学研究的一个基本课题，也是有可能做出突出研究成果的一个重要领域\n③所以，我国社会学者的一大任务，就是探索一条使我国社会既充满活力，又保持秩序的现代化转型之路\n④社会治理的基本原则是激发活力和保持社会秩序，困难之处在于我国正处于现代化转型任务比较艰巨的时期\n⑤根据世界各国现代化的经验，当城镇化率处于50%上下的时候，是现代化转型最为艰巨的时期\n⑥正是在这样的背景下，党中央提出“社会治理”的概念将以上6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"④①②③⑥⑤"}],"B":[{"text":"①④⑥②③⑤"}],"C":[{"text":"⑤②⑥①③④"}],"D":[{"text":"②④⑤①③⑥"}]},"practicalAnalysis":"本题可从两个角度入手：一是首句，②介绍社会治理是什么, ④介绍社会治理的基本原则是什么,这两句均为下定义，常用作首句；二是 ①⑤均包含数字(城镇化率),二者捆绑可能性较大。由此，基本锁定D选项；\n验证D选项：②④下定义介绍社会治理和其基本原则，④引出我国正处于现代化转型任务比较艰巨的时期，⑤①通过城镇化率解释我国为何处于现代化转型艰巨时期，③⑥给出对策：在上述背景下，党中央提出“社会治理”的概念，且与首句“社会治理”呼应；逻辑正确，当选。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300319,3,'标题拟定类','川剧大师们应邀来到洛杉矶加州大学世界舞蹈历史大师课堂，以川剧经典剧目《打神》为例，结合自己的表演经验，同现场60多位学生分享、介绍了川剧艺术的特点和风格。第二天，他们又应戏剧学院的邀请开设大师课，继续分享传播川剧艺术，洛杉矶一所中学特地邀请他们参加学校高年级的中国年活动，大师们表演的《射雕》、变脸等点燃了全场气氛，笑声、喝彩声不断，学生们在度过了一个欢乐中国年的同时，也充分感受了中国优秀传统艺术的神奇魅力。
