INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300320,3,'词句理解题','笔是写作业的必需品，但是简单的笔，换一个角度看它，就会产生不同的认识。黑色笔：记录笔，自己使用，写作业、记笔记、做练习；绿色笔：反思笔，同伴使用，彼此修改、相互点评、略加批注；蓝色笔：补充笔，自己使用，做出修改、协助完善、进行反思；红色笔：评判笔，老师使用，做出点评、加以批注、进行修改。
对上文中“换一个角度看它，就会产生不同的认识”的理解，不正确的是：','[{"label":"A","content":"换一个角度，认识会更准确"},{"label":"B","content":"换一个角度，认识会更具体"},{"label":"C","content":"换一个角度，认识会更丰富"},{"label":"D","content":"换一个角度，认识会更繁琐"}]','D','文段介绍了在另一个角度下，不同颜色笔作用的新认识，“更准确”、“更具体”、“更丰富”表述均恰当。但原文并未说明这些颜色会让我们对笔的认识更繁琐⑨,D选项无中生有，当选。
S四IHA海IGO公NGK考AO 练习题17套
