INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300330,3,'中心理解题','美国历史学家戴维斯在《档案中的虚构》一书中，以16世纪法国赦罪书中的案情编造为例，凸显所谓原始档案的虚构性，引发历史研究者对档案可信性的质疑，但是换一个角度，在档案的记录、归档与筛选、保存等制作环节中所掺杂的主观意识，恰好也是档案的一种真实性，更可以反映某种特定的时代风尚。因此，对档案可信性的质疑，不应导致对档案的否定与摒弃，而是更应进一步地发掘其中深藏的多元化的历史真貌。
这段文字意在说明：','[{"label":"A","content":"主观意识可能会影响档案的可信性"},{"label":"B","content":"档案多少都会反映特定的时代风尚"},{"label":"C","content":"学者对档案的虚构性持有不同见解"},{"label":"D","content":"存在虚构成分的档案也应善加利用"}]','D','文段分析见批注。
文段为典型后对策结构，先提出“原始档案存在虚构性”的问题，分析论证后给出了对策，只有D选项为对策表述，“应善加利用”是对“不应导致对档案的否定与摒弃，而是更应进一步地发掘其中深藏的多元化的历史真貌”的概括，当选；
A选项为问题类表述，文中有对策要体现对策，排除； B选项出处有误，
出自文段分析部分，且片面，排除； C选项无中生有，文段并未提及学者的不同见解，排除。

花生批注：
⑰ 行文结构：后对策结构。
开篇提出问题：原始档案存在虚构；
再解释分析：
档案制作环节中所掺杂的主观意识也能反映真实性和特定的时代风尚；
最后给出对策：
对档案可信性的质疑，不应对档案否定和摒弃，应进一步挖掘档案的多元化历史真貌。','2021年四川省考','基础','published','{"globalNumber":330,"setNumber":17,"localNumber":10,"sourceLabel":"2021年四川省考 78%","accuracy":78,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"美国历史学家戴维斯在《档案中的虚构》一书中，以16世纪法国赦罪书中的案情编造为例，凸显所谓原始档案的虚构性，引发历史研究者对档案可信性的质疑，但是换一个角度，在档案的记录、归档与筛选、保存等制作环节中所掺杂的主观意识，恰好也是档案的一种真实性，更可以反映某种特定的时代风尚。因此，对档案可信性的质疑，不应导致对档案的否定与摒弃，而是更应进一步地发掘其中深藏的多元化的历史真貌。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"主观意识可能会影响档案的可信性"}],"B":[{"text":"档案多少都会反映特定的时代风尚"}],"C":[{"text":"学者对档案的虚构性持有不同见解"}],"D":[{"text":"存在虚构成分的档案也应善加利用"}]},"annotatedStemRich":[{"text":"美国历史学家戴维斯在《档案中的虚构》一书中，以16世纪法国赦罪书中的案情编造为例，凸显所谓原始档案的虚构性，引发历史研究者对档案可信性的质疑 (提出问题),但是换一个角度，在档案的记录、归档与筛选、保存等制作环节中所掺杂的主观意识，恰好也是档案的一种真实性，更可以反映某种特定的时代风尚 (分析说明)。因此，对档案可信性的质疑，不应导致对档案的否定与摒弃，而是更应进一步地发掘其中深藏的多元化的历史真貌(后对策)。①\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"主观意识可能会影响档案的可信性"},{"text":"(问题表述)","bold":true}],"B":[{"text":"档案多少都会反映特定的时代风尚(出处有误)"}],"C":[{"text":"学者对档案的虚构性持有不同见解(无中生有)"}],"D":[{"text":"存在虚构成分的档案也应善加利用"}]},"practicalAnalysis":"文段分析见批注。\n文段为典型后对策结构，先提出“原始档案存在虚构性”的问题，分析论证后给出了对策，只有D选项为对策表述，“应善加利用”是对“不应导致对档案的否定与摒弃，而是更应进一步地发掘其中深藏的多元化的历史真貌”的概括，当选；\nA选项为问题类表述，文中有对策要体现对策，排除； B选项出处有误，\n出自文段分析部分，且片面，排除； C选项无中生有，文段并未提及学者的不同见解，排除。","notes":[{"marker":"⑰","content":"行文结构：后对策结构。\n开篇提出问题：原始档案存在虚构；\n再解释分析：\n档案制作环节中所掺杂的主观意识也能反映真实性和特定的时代风尚；\n最后给出对策：\n对档案可信性的质疑，不应对档案否定和摒弃，应进一步挖掘档案的多元化历史真貌。","matchScore":0.8474,"pairingMode":"content-similarity","order":16}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300331,3,'下文推断类⑧','加强小农户和现代农业的有机衔接，离不开农业社会化服务体系的建立，以及多元化生产性服务业
的健康成长。为了推动农业生产性服务业的发展，近年来相关政策给予有力扶持。数据显示，仅
2017年至2018年，我国直接面向小农户的农业社会化服务项目财政补助累计已达70亿元。
这段文字接下来最应该补充的是：','[{"label":"A","content":"受服务的小农户的具体情况"},{"label":"B","content":"社会化服务体系的基本框架"},{"label":"C","content":"农业社会化生产服务的前景"},{"label":"D","content":"小农户在农业生产中的困境"}]','A','文段先进行背景知识引入“加强小农户和现代农业的有机衔接，离不开‘农业社会化服务’”,之后展开介绍我国的相关做法，即“我国直接面向小农户的农业社会化服务项目财政补助累计已达70亿元”,接下来应就此展开详细介绍，介绍扶持政策的具体落实。 A选项与尾句话题一致，介绍获得此服务项目服务的小农户的具体情况，当选；
B选项依然属于理论研究，并非“我国的具体做法”,若填入应在首句之后介绍，排除；
C选项的“前景”无中生有，文段尾句主要介绍的是我国目前的做法，而非未来前景，该选项与尾句新内容无关，排除；
D选项，“小农户在农业生产中的困境”不是“近年来相关政策给予有力扶持”的具体内容，若将其看作“扶持”背景，应在上文介绍，而非下文补充⑨,排除。

花生批注：
⑲ 本题问法相对特殊：“接下来最应该补充”,补充的应是缺少的内容，即我国农业社会化服务的具体落实，而非“小农户的困境(更像政策制定背景)”。','2020年浙江省事业单位','进阶','published','{"globalNumber":331,"setNumber":17,"localNumber":11,"sourceLabel":"2020年浙江省事业单位68%","accuracy":68,"typeAndPassage":"下文推断类⑧+宏观对策 →具体展开","stemRich":[{"text":"加强小农户和现代农业的有机衔接，离不开农业社会化服务体系的建立，以及多元化生产性服务业\n的健康成长。为了推动农业生产性服务业的发展，近年来相关政策给予有力扶持。数据显示，仅\n2017年至2018年，我国直接面向小农户的农业社会化服务项目财政补助累计已达70亿元。\n这段文字接下来最应该补充的是："}],"optionRich":{"A":[{"text":"受服务的小农户的具体情况"}],"B":[{"text":"社会化服务体系的基本框架"}],"C":[{"text":"农业社会化生产服务的前景"}],"D":[{"text":"小农户在农业生产中的困境"}]},"annotatedStemRich":[{"text":"加强小农户和现代农业的有机衔接，离不开农业社会化服务体系的建立，以及多元化生产性服务业的健康成长(背景知识引出)。为了推动农业生产性服务业的发展，近年来相关政策给予有力扶持。数据显示，仅2017年至2018 年，我国直接面向小农户的农业社会化服务项目财政补助累计已达70亿元( 我国做法)。\n这段文字接下来最应该补充的是："}],"annotatedOptionRich":{"A":[{"text":"受服务的小农户的具体情况"}],"B":[{"text":"社会化服务体系的基本框架"}],"C":[{"text":"农业社会化生产服务的前景(无中生有)"}],"D":[{"text":"小农户在农业生产中的困境"}]},"practicalAnalysis":"文段先进行背景知识引入“加强小农户和现代农业的有机衔接，离不开‘农业社会化服务’”,之后展开介绍我国的相关做法，即“我国直接面向小农户的农业社会化服务项目财政补助累计已达70亿元”,接下来应就此展开详细介绍，介绍扶持政策的具体落实。 A选项与尾句话题一致，介绍获得此服务项目服务的小农户的具体情况，当选；\nB选项依然属于理论研究，并非“我国的具体做法”,若填入应在首句之后介绍，排除；\nC选项的“前景”无中生有，文段尾句主要介绍的是我国目前的做法，而非未来前景，该选项与尾句新内容无关，排除；\nD选项，“小农户在农业生产中的困境”不是“近年来相关政策给予有力扶持”的具体内容，若将其看作“扶持”背景，应在上文介绍，而非下文补充⑨,排除。","notes":[{"marker":"⑲","content":"本题问法相对特殊：“接下来最应该补充”,补充的应是缺少的内容，即我国农业社会化服务的具体落实，而非“小农户的困境(更像政策制定背景)”。","matchScore":0.6546,"pairingMode":"content-similarity","order":18}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300332,3,'下文推断类','PM2.5浓度升高既有气象原因，也有污染排放的原因，其中污染排放为首的主要因素有：汽车尾气的排放，使用柴油的大型车是重犯，包括大型公交车、各单位的班车以及大型运输卡车等工业生产排放的废气，在工业生产过程中，不可避免地会向大气排放大量的工业废气，包括可燃性气体、含硫化物的气体、有毒的气体以及含放射性物质的气体等，这些气体随着废气的排放扩散到空气中；工地建筑和道路交通产生的扬尘，正在城镇化中崛起的新型城市，建筑工地扬尘、泥土车上路撒漏扬尘以及城市道路交通产生的扬尘均会促使PM2.5浓度升高。
作者接下来最有可能描写的是：','[{"label":"A","content":"如何更好的控制PM2.5的浓度"},{"label":"B","content":"有关PM2.5的研究是何时开始的"},{"label":"C","content":"如何减少在城市化过程中产生的扬尘"},{"label":"D","content":"PM2.5对人体健康产生的不利影响"}]','A','文段介绍了 PM2.5 浓度升高的具体污染排放因素；上文给出问题，下文应给出有针对性的对策，即“如何更好的控制PM2.5 的浓度”,对应 A选项，当选；
B选项，有关PM2.5 的研究原文并未体现，无中生有，排除；C选项片面，仅对应造成 PM2.5 浓度升高的部分原因，浓度升高的原因还有汽车尾气、工业生产等，排除；D选项话题不一致，文段未提及健康问题，排除。','2019年福建省事业单位','基础','published','{"globalNumber":332,"setNumber":17,"localNumber":12,"sourceLabel":"2019年福建省事业单位70%","accuracy":70,"typeAndPassage":"下文推断类+分析问题 →提出对策","stemRich":[{"text":"PM2.5浓度升高既有气象原因，也有污染排放的原因，其中污染排放为首的主要因素有：汽车尾气的排放，使用柴油的大型车是重犯，包括大型公交车、各单位的班车以及大型运输卡车等工业生产排放的废气，在工业生产过程中，不可避免地会向大气排放大量的工业废气，包括可燃性气体、含硫化物的气体、有毒的气体以及含放射性物质的气体等，这些气体随着废气的排放扩散到空气中；工地建筑和道路交通产生的扬尘，正在城镇化中崛起的新型城市，建筑工地扬尘、泥土车上路撒漏扬尘以及城市道路交通产生的扬尘均会促使PM2.5浓度升高。\n作者接下来最有可能描写的是："}],"optionRich":{"A":[{"text":"如何更好的控制PM2.5的浓度"}],"B":[{"text":"有关PM2.5的研究是何时开始的"}],"C":[{"text":"如何减少在城市化过程中产生的扬尘"}],"D":[{"text":"PM2.5对人体健康产生的不利影响"}]},"annotatedStemRich":[{"text":"PM2.5浓度升高既有气象原因，也有污染排放的原因(介绍PM2.5 浓度升高的原因：气象原因、污染排放原因),其中污染排放为首的主要因素有：汽车尾气的排放，使用柴油的大型车是重犯，包括大型公交车、各单位的班车以及大型运输卡车等工业生产排放的废气，在工业生产过程中，不可避免地会向大气排放大量的工业废气，包括可燃性气体、含硫化物的气体、有毒的气体以及含放射性物质的气体等，这些气体随着废气的排放扩散到空气中；工地建筑和道路交通产生的扬尘，正在城镇化中崛起的新型城市，建筑工地扬尘、泥土车上路撒漏扬尘以及城市道路交通产生的扬尘均会促使PM2.5浓度升高 (具体介绍污染排放因素有哪些)。\n作者接下来最有可能描写的是："}],"annotatedOptionRich":{"A":[{"text":"如何更好的控制PM2.5的浓度"}],"B":[{"text":"有关PM2.5的研究是何时开始的(无中生有)"}],"C":[{"text":"如何减少在城市化过程中产生的扬尘(片面)"}],"D":[{"text":"PM2.5 对人体健康产生的不利影响"},{"text":"(话题不一致)","bold":true}]},"practicalAnalysis":"文段介绍了 PM2.5 浓度升高的具体污染排放因素；上文给出问题，下文应给出有针对性的对策，即“如何更好的控制PM2.5 的浓度”,对应 A选项，当选；\nB选项，有关PM2.5 的研究原文并未体现，无中生有，排除；C选项片面，仅对应造成 PM2.5 浓度升高的部分原因，浓度升高的原因还有汽车尾气、工业生产等，排除；D选项话题不一致，文段未提及健康问题，排除。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300333,3,'语句填入类','。人类的美好理想，都不可能唾手可得，都离不开筚路蓝缕、手胼足胝的艰苦奋斗。我们的国家，我们的民族，从积贫积弱一步一步走到今天的发展繁荣，靠的就是一代又一代人的顽强拼搏，靠的就是中华民族自强不息的奋斗精神。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"长风破浪会有时，直挂云帆济沧海"},{"label":"B","content":"千磨万击还坚劲，任尔东西南北风"},{"label":"C","content":"宝剑锋从磨砺出，梅花香自苦寒来"},{"label":"D","content":"千淘万漉虽辛苦，吹尽狂沙始到金"}]','C','所填入语句在段首，可能起到总概括的作用。分析下文：先说“人类的美好理想离不开艰苦奋斗”,再说“国家的发展繁荣需要顽强拼搏和奋斗精神”,通过人们和国家强调需要“拼搏与奋斗”,首句应有所体现；
C选项的意思是“宝剑的锐利刀锋是从不断的磨砺中得到的，梅花飘香是来自于它度过了寒冷的冬季”,强调要想拥有珍贵品质或美好才华等是需要不断的努力、修炼、克服一定的困难才能达到的；
C选项强调“艰苦奋斗、顽强拼搏”,能更好的概括后文；且“宝剑锋、梅花香”可与“人类美好理想、国家发展繁荣”对应，“磨砺、苦寒”与“艰苦奋斗、顽强拼搏”对应，当选。

花生批注：
② A选项的意思是“尽管前路困难险阻，危险重重，但心中始终相信终有一天会乘长风破万里浪，到达理想的彼岸”,强调内心坚定自信的豁达心态。
2 B选项的意思是“经历无数磨炼和打击，竹子依然坚强有力地生长着，任凭你刮酷暑的东南风，还是严冬的西北风。”,强调自身坚强，无法摧毁，体现无畏无惧的顽强精神。','2020年湖北省事业单位','进阶','published','{"globalNumber":333,"setNumber":17,"localNumber":13,"sourceLabel":"2020年湖北省事业单位67%","accuracy":67,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"。人类的美好理想，都不可能唾手可得，都离不开筚路蓝缕、手胼足胝的艰苦奋斗。我们的国家，我们的民族，从积贫积弱一步一步走到今天的发展繁荣，靠的就是一代又一代人的顽强拼搏，靠的就是中华民族自强不息的奋斗精神。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"长风破浪会有时，直挂云帆济沧海"}],"B":[{"text":"千磨万击还坚劲，任尔东西南北风"}],"C":[{"text":"宝剑锋从磨砺出，梅花香自苦寒来"}],"D":[{"text":"千淘万漉虽辛苦，吹尽狂沙始到金"}]},"annotatedStemRich":[{"text":" ","underline":true},{"text":" 。人类的美好理想，都不可能唾手可得，都离不开筚路蓝缕、手胼足胝的艰苦奋斗。我们的国家，我们的民族，从积贫积弱一步一步走到今天的发展繁荣，靠的就是一代又一代人的顽强拼搏，靠的就是中华民族自强不息的奋斗精神。\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"长风破浪会有时，直挂云帆济沧海②"}],"B":[{"text":"千磨万击还坚劲，任尔东西南北风②"}],"C":[{"text":"宝剑锋从磨砺出，梅花香自苦寒来"}],"D":[{"text":"千淘万漉虽辛苦，吹尽狂沙始到金"}]},"practicalAnalysis":"所填入语句在段首，可能起到总概括的作用。分析下文：先说“人类的美好理想离不开艰苦奋斗”,再说“国家的发展繁荣需要顽强拼搏和奋斗精神”,通过人们和国家强调需要“拼搏与奋斗”,首句应有所体现；\nC选项的意思是“宝剑的锐利刀锋是从不断的磨砺中得到的，梅花飘香是来自于它度过了寒冷的冬季”,强调要想拥有珍贵品质或美好才华等是需要不断的努力、修炼、克服一定的困难才能达到的；\nC选项强调“艰苦奋斗、顽强拼搏”,能更好的概括后文；且“宝剑锋、梅花香”可与“人类美好理想、国家发展繁荣”对应，“磨砺、苦寒”与“艰苦奋斗、顽强拼搏”对应，当选。","notes":[{"marker":"②","content":"A选项的意思是“尽管前路困难险阻，危险重重，但心中始终相信终有一天会乘长风破万里浪，到达理想的彼岸”,强调内心坚定自信的豁达心态。","matchScore":0.1996,"pairingMode":"marker-and-content","order":20},{"marker":"2","content":"B选项的意思是“经历无数磨炼和打击，竹子依然坚强有力地生长着，任凭你刮酷暑的东南风，还是严冬的西北风。”,强调自身坚强，无法摧毁，体现无畏无惧的顽强精神。","matchScore":0.2237,"pairingMode":"marker-and-content","order":21}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300334,3,'语句填入类','虽然物质生产是社会生活的基础，但上层建筑也可以反作用于经济基础，生产力和生产关系、经济基础和上层建筑之间有着十分复杂的关系，有着作用和反作用的现实过程，并不是单线式的简单决定和被决定逻辑。世界上的事物总是有着这样那样的联系，不能孤立地静止地看待事物发展，。正所谓“有无相生，难易相成，长短相形，高下相倾，音声相和，前后相随”。在观察社会发展时，一定要注意这种决定和被决定、作用和反作用的有机联系。对生产力标准必须全面准确理解，不能绝对化，不能撇开生产关系、上层建筑来理解生产力标准。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"广袤的自然界是如此，丰富的精神世界也是如此"},{"label":"B","content":"每一个事物各部分、要素之间都存在联系"},{"label":"C","content":"否则往往会出现盲人摸象、以偏概全的问题"},{"label":"D","content":"任何事物都与周围的其他事物相互联系着"}]','C','文段分析见批注。
横线出现在对策句中，横线前提出禁止型对策“不能孤立地静止地看待事物发展”,横线上若填入 C选项，是“孤立地静止地看待事物发展”可能导致的后果，逻辑正确⑤,当选；
A选项无中生有，自然界、精神世界前后文均未提及，若填入A选项，横线前应该讲“自然界”,横线后讲“精神世界”,起到承上启下的作用，排除；
B选项和 D选项，都是继续介绍“事物之间有联系”,若填入横线，这句话逻辑变成：“事物有联系，不能孤立地静止地看待事物发展，事物有联系”, 前后重复且逻辑混乱，排除；
综上，正确答案是C选项。
IG

花生批注：
④ 行文结构：前对策结构。
先引出话题：
介绍生产力和生产关系、经济基础和上层建筑之间有着十分复杂的关系；
再提出禁止型对策：
不能孤立地静止地看待事物发展；
随后分析论证。
25 C选项若填入横线，则为先介绍事实：“世界上的事物总是有着这样那样的联系”, 再给出禁止性对策：“不能孤立地静止地看待事物发展”,最后“否则”引导不这样做的后果，对横线之前的对策进行反面论述；
形成“介绍事实→提出对策 →反面论述”的逻辑结构，结构完整且合理，当选。','2021年国家公务员考试','挑战','published','{"globalNumber":334,"setNumber":17,"localNumber":14,"sourceLabel":"2021年国家公务员考试 40%","accuracy":40,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"虽然物质生产是社会生活的基础，但上层建筑也可以反作用于经济基础，生产力和生产关系、经济基础和上层建筑之间有着十分复杂的关系，有着作用和反作用的现实过程，并不是单线式的简单决定和被决定逻辑。世界上的事物总是有着这样那样的联系，不能孤立地静止地看待事物发展， "},{"text":" ","underline":true},{"text":"。正所谓“有无相生，难易相成，长短相形，高下相倾，音声相和，前后相随”。在观察社会发展时，一定要注意这种决定和被决定、作用和反作用的有机联系。对生产力标准必须全面准确理解，不能绝对化，不能撇开生产关系、上层建筑来理解生产力标准。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"广袤的自然界是如此，丰富的精神世界也是如此"}],"B":[{"text":"每一个事物各部分、要素之间都存在联系"}],"C":[{"text":"否则往往会出现盲人摸象、以偏概全的问题"}],"D":[{"text":"任何事物都与周围的其他事物相互联系着"}]},"annotatedStemRich":[{"text":"虽然物质生产是社会生活的基础，但上层建筑也可以反作用于经济基础，\n生产力和生产关系、经济基础和上层建筑之间有着十分复杂的关系，有着作用和反作用的现实过程，并不是单线式的简单决定和被决定逻辑(引出话题)。世界上的事物总是有着这样那样的联系，不能孤立地静止地看待事物发展，\n"},{"text":" ","underline":true},{"text":" (提出对策)。正所谓“有无相生，难易相成，长短相形，高下相倾，音声相和，前后相随”。在观察社会发展时，一定要注意这种决定和被决定、作用和反作用的有机联系。对生产力标准必须全面准确理解，不能绝对化，不能撇开生产关系、上层建筑来理解生产力标准"},{"text":"(分析论证)。②","bold":true},{"text":"\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"广袤的自然界是如此，丰富的精神世界也是如此"}],"B":[{"text":"每一个事物各部分、要素之间都存在联系"}],"C":[{"text":"否则往往会出现盲人摸象、以偏概全的问题"}],"D":[{"text":"任何事物都与周围的其他事物相互联系着"}]},"practicalAnalysis":"文段分析见批注。\n横线出现在对策句中，横线前提出禁止型对策“不能孤立地静止地看待事物发展”,横线上若填入 C选项，是“孤立地静止地看待事物发展”可能导致的后果，逻辑正确⑤,当选；\nA选项无中生有，自然界、精神世界前后文均未提及，若填入A选项，横线前应该讲“自然界”,横线后讲“精神世界”,起到承上启下的作用，排除；\nB选项和 D选项，都是继续介绍“事物之间有联系”,若填入横线，这句话逻辑变成：“事物有联系，不能孤立地静止地看待事物发展，事物有联系”, 前后重复且逻辑混乱，排除；\n综上，正确答案是C选项。\nIG","notes":[{"marker":"④","content":"行文结构：前对策结构。\n先引出话题：\n介绍生产力和生产关系、经济基础和上层建筑之间有着十分复杂的关系；\n再提出禁止型对策：\n不能孤立地静止地看待事物发展；\n随后分析论证。","matchScore":0.9088,"pairingMode":"content-similarity","order":23},{"marker":"25","content":"C选项若填入横线，则为先介绍事实：“世界上的事物总是有着这样那样的联系”, 再给出禁止性对策：“不能孤立地静止地看待事物发展”,最后“否则”引导不这样做的后果，对横线之前的对策进行反面论述；\n形成“介绍事实→提出对策 →反面论述”的逻辑结构，结构完整且合理，当选。","matchScore":0.6107,"pairingMode":"content-similarity","order":24}],"pairingMode":"text-and-sequence"}