INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300335,3,'语句填入类','近年来，新崛起的中西部城市武汉、郑州、成都、西安等都加入到“新一线”城市的争夺中。在信息鸿沟被逐渐“抹平”,高铁也拉近了城市间距离时，“准一线”和“二线”城市看到了“换道超车”的机会，而人才是其间的关键。从武汉2017年初提出“百万人才留汉计划”,到成都发布“人才新政12条”等，都足见揽人心切。眼下中国城市间发展的差距越拉越大，人才在中国经济版图上的分布呈现出马太效应，一旦错失这拨儿人才，未来10年很难再有翻盘的机会。而中国经济经历了 40余年高速发展，如今到达了一个拐点——人口红利正在消失，老龄化问题严重，同时，新的历史时期因有大批接受过高等教育的人才而逐渐形成“新的人口红利”,故中国经济已在向高质量发展转变，粗放式的发展已难以为继。这样，人才与创新就成为经济发展的重要驱动力。“抢人才大战”实质是中国经济转型升级的紧迫性和内驱力所致。因此，口
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"这将重新塑造中国未来的经济版图"},{"label":"B","content":"人才是城市未来发展的引擎"},{"label":"C","content":"要抓紧实施人才计划"},{"label":"D","content":"人力资本比物质资源更加重要"}]','B','文段分析见批注。
文段开篇给出观点：城市竞争，人才是关键；之后分析论证，全文关键词为“城市”和“人才”。只有B选项包含二者，且 B选项是文段观点的同义替换，体现了人才对城市发展的重要意义，当选；
A选项缺少主题词“人才”,排除； C选项只提及“人才”未提及城市，且“实施人才计划”只对应分析论证中的①,排除；D选项为区别比较类选项，文段并非将人力资本和物质资源进行比较，排除。

花生批注：
26 行文结构：前观点结构。
文段开篇开门见山给出观点：城市竞争，人才是关键；接下来举例及分析论证：
①武汉、成都提出人才新政； ②城市差距拉大，人才也出现马太效应(好的越好), 错过机会很难翻身；
③介绍为什么城市之间出现“抢人才大战”;
所填入语句在文末，可猜测其是对上文的概括总结，且应对应首句观点。
A. 这将重新塑造中国未来的经济版图(缺少主题词)
B. 人才是城市未来发展的引擎
C. 要抓紧实施人才计划(片面)','2019年上海市考','进阶','published','{"globalNumber":335,"setNumber":17,"localNumber":15,"sourceLabel":"2019年上海市考53%","accuracy":53,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"近年来，新崛起的中西部城市武汉、郑州、成都、西安等都加入到“新一线”城市的争夺中。在信息鸿沟被逐渐“抹平”,高铁也拉近了城市间距离时，“准一线”和“二线”城市看到了“换道超车”的机会，而人才是其间的关键。从武汉2017年初提出“百万人才留汉计划”,到成都发布“人才新政12条”等，都足见揽人心切。眼下中国城市间发展的差距越拉越大，人才在中国经济版图上的分布呈现出马太效应，一旦错失这拨儿人才，未来10年很难再有翻盘的机会。而中国经济经历了 40余年高速发展，如今到达了一个拐点——人口红利正在消失，老龄化问题严重，同时，新的历史时期因有大批接受过高等教育的人才而逐渐形成“新的人口红利”,故中国经济已在向高质量发展转变，粗放式的发展已难以为继。这样，人才与创新就成为经济发展的重要驱动力。“抢人才大战”实质是中国经济转型升级的紧迫性和内驱力所致。因此，"},{"text":"                      ","underline":true},{"text":" 口\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"这将重新塑造中国未来的经济版图"}],"B":[{"text":"人才是城市未来发展的引擎"}],"C":[{"text":"要抓紧实施人才计划"}],"D":[{"text":"人力资本比物质资源更加重要"}]},"annotatedStemRich":[{"text":"近年来，新崛起的中西部城市武汉、郑州、成都、西安等都加入到“新一线”城市的争夺中。在信息鸿沟被逐渐“抹平”,高铁也拉近了城市间距离时，“准一线”和“二线”城市看到了“换道超车”的机会，而人才是其间的关键(前观点)。从武汉2017 年初提出“百万人才留汉计划”,到成都发布“人才新政12条”等，都足见揽人心切。眼下中国城市间发展的差距越拉越大，人才在中国经济版图上的分布呈现出马太效应，一旦错失这拨儿人才，未来10年很难再有翻盘的机会。而中国经济经历了40余年高速发展，如今到达了一个拐点——人口红利正在消失，老龄化问题严重，同时，新的历史时期因有大批接受过高等教育的人才而逐渐形成“新的人口红利”,故中国经济已在向高质量发展转变，粗放式的发展已难以为继。这样，人才与创新就成为经济发展的重要驱动力。“抢人才大战”实质是中国经济转型升级的紧迫性和内\n驱力所致(分析论证)。因此，"},{"text":"                         ","underline":true},{"text":" (重复对策)。② 填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"这将重新塑造中国未来的经济版图(缺少主题词)"}],"B":[{"text":"人才是城市未来发展的引擎"}],"C":[{"text":"要抓紧实施人才计划(片面)"}],"D":[{"text":"人力资本比物质资源更加重要(区别比较类选项)"}]},"practicalAnalysis":"文段分析见批注。\n文段开篇给出观点：城市竞争，人才是关键；之后分析论证，全文关键词为“城市”和“人才”。只有B选项包含二者，且 B选项是文段观点的同义替换，体现了人才对城市发展的重要意义，当选；\nA选项缺少主题词“人才”,排除； C选项只提及“人才”未提及城市，且“实施人才计划”只对应分析论证中的①,排除；D选项为区别比较类选项，文段并非将人力资本和物质资源进行比较，排除。","notes":[{"marker":"26","content":"行文结构：前观点结构。\n文段开篇开门见山给出观点：城市竞争，人才是关键；接下来举例及分析论证：\n①武汉、成都提出人才新政； ②城市差距拉大，人才也出现马太效应(好的越好), 错过机会很难翻身；\n③介绍为什么城市之间出现“抢人才大战”;\n所填入语句在文末，可猜测其是对上文的概括总结，且应对应首句观点。\nA. 这将重新塑造中国未来的经济版图(缺少主题词)\nB. 人才是城市未来发展的引擎\nC. 要抓紧实施人才计划(片面)","matchScore":0.427,"pairingMode":"content-similarity","ord