INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300337,3,'语句排序类','①交通的高速发展使人们感觉生活在“地球村”,空间成为虚拟符号或只意味着数字的变化。
②正如有人指出的，“在城市消费时代，艺术的接受者与创造者都趋向于职业化”。
③民俗是在特定地理环境下产生的有明显地域性的文化，当地方性消弭时民俗也随之消失。
④大众传播媒介使时空缩小，网络瞬时传播的速度和广度超越以往任何时候。
⑤即由于地理气候等因素长期养成的生存智慧失去了优势，地方文化的多样性也不复存在了。
⑥一些传统民俗在当代被商家和政府征用，变成了量贩式的“工业产品”。
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"④⑤③①②⑥"},{"label":"B","content":"⑥⑤③②①④"},{"label":"C","content":"③⑤④( ①⑥②"},{"label":"D","content":"①⑤⑥②④③"}]','C','观察首句可知，③句是介绍民俗是什么,⑥句介绍一些传统民俗的现状，③应在⑥前，排除B选项、D选项；
⑤句的“即”是对上文解释，其后半句的“地方文化的多样性也不复存在”对应③句的“当地方性消弭时民俗也随之消失”,二者话题一致，③⑤捆绑，
确定答案为C选项。

