INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300339,3,'下文推断类②','对个人数据信息的抓取和使用，的确有助于金融机构更准确地把握消费者需求，全面识别风险，设计出更符合消费者需求的产品和服务。因而有观点认为，大数据时代，消费者只要享受了信息互联互通的便利，就必须付出信息让渡的代价，这是一种公平交易。这一观点实际上忽视了信息的价值，忽略了信息的所有权。
作者在后文应该不会谈论：','[{"label":"A","content":"互联网时代个人信息的价值及获取方式"},{"label":"B","content":"个人信息被泄露或者滥用所带来的危害"},{"label":"C","content":"通过法律规范个人信息交易的必要性"},{"label":"D","content":"整顿信息交易对数字经济发展的影响"}]','A','文段分析见批注。
文段通过转折引出问题：抓取和使用个人信息忽视了信息的价值，忽略了信息的所有权；即抓取和使用个人信息这一行为是不对的；文末提出问题，下文可以分析问题也可以解决问题。

