INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300340,3,'中心理解题','以牺牲用户体验、给用户带来困扰的方式追求好看的点击数据，以提升广告收益，是一种唯利是图的做法，也是一种短视的行为，换来的恐将是用户的用脚投票。APP 开发运营者这种竭泽而渔的做法，不足取也不可取。在强化行业监管之外，还应要求广告投放者、APP 开发运营者以及行业组织，共同优化单纯以点击率为依据的广告效果评价模式，共同推动形成健康的网络广告生态，只有这样，才能实现多赢局面。
这段文字意在强调：','[{"label":"A","content":"高质量内容和适当的投放方式才是广告能够赢取消费者好感的关键"},{"label":"B","content":"改善网络广告生态、实现多方共赢要从改变广告效果的评价依据入手"},{"label":"C","content":"行业部门应该对靠牺牲用户体验博取广告收益的平台加强监管和整治"},{"label":"D","content":"形成健康的网络广告生态需要行业部门、企业、平台和消费者同心协力"}]','B','文段分析见批注。
本题是典型的先提出问题，再针对问题给出对策，对策部分为文段重点，
对策重点也针对首句的问题：“以牺牲用户体验、给用户带来困扰的方式追求好看的点击数据，以提升广告收益”,"追求好看的点击数据”就是一种错误的广告效果评价模式。
即“多方共同优化广告效果评价模式，形成健康网络广告生态，实现多赢局面”, 对策的重点是“优化广告效果评价模式”⑤,只有B选项体现这一对策重点，当选：
其他选项除未体现对策重点外，还有如下问题：A选项对策“高质量内容和适当的投放方式”无中生有；C选项“加强监管和整治”出自对策句“在强化行业监管之外”,并非文段对策部分重点； D选项对策中的“消费者”无中生有，均可简单排除。
