INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300343,3,'中心理解题','传统文化中生态伦理思想有助于人们树立节约资源、保护环境的意识，选择适度的消费方式。儒家的“取之有度，用之有节”思想和道家的“知足去奢”思想，告诫人类应当克制自身欲望，珍惜、节约资源，既考虑到当前，也应该考虑到未来。引导人们树立正确合理的消费理念，更加注重环境、资源在代际之间的公正分配。给自然留下更多的修复空间，给子孙留下地绿、天蓝、水净的生存环境。这一思想与当今社会存在的享乐主义、消费主义思潮是针锋相对的。
这段文字主要谈论的是：','[{"label":"A","content":"生态伦理思想的传统文化渊源"},{"label":"B","content":"生态伦理思想对消费理念的影响"},{"label":"C","content":"传统文化中生态伦理思想的当代价值"},{"label":"D","content":"儒家与道家在生态伦理方面的相同之处\n片段阅读6 0 0 (下册)"}]','C','文段分析见批注。
文段首句直接给出作者观点，传统文化中生态伦理思想在当代有一系列正面作用；
A选项“传统文化渊源”⑦无中生有；D选项出处有误，出自文段分析部分，属于从论证中提炼的选项，均可简单排除；
C选项和B选项需要辨析，B选项与C选项相比表述片面⑧,排除；C选项“当代价值”既体现“树立环保意识”又体现“转变消费理念”,完美选项，当选。

花生批注：
⑥ 行文结构：总分结构。
开篇给出总观点：
传统文化中生态伦理思想有积极意义；
再解释分析：
通过儒家和道家的思想，论证传统文化生态伦理思想的正面作用，否定享乐、消费主义。
传统文化中生态伦理思想有助于人们树立节约资源、保护环境的意识，选择适度的消费方式(提出总观点)。儒家的“取之有度，用之有节”思想和道家的“知足去奢”思想，告诫人类应当克制自身欲望，珍惜、节约资源，既考虑到当前，也应该考虑到未来。引导人们树立正确合理的消费理念，更加注重环境、资源在代际之间的公正分配。给自然留下更多的修复空间，给子孙留下地绿、天蓝、水净的生存环境。这一思想与当今社会存在的享乐主义、消费主义思潮是针锋相对的(分析论证)。⑥
这段文字主要谈论的是：
A. 生态伦理思想的传统文化渊源 (无中生有)
B. 生态伦理思想对消费理念的影响( 片面 )
C. 传统文化中生态伦理思想的当代价值
D. 儒家与道家在生态伦理方面的相同之处(出处有误)
四SIHA海IGO公NGK考AO 练习题18套
⑧ B选项为易错项，原文观点句可翻译为“生态伦理思想有助于人们树立环保意识，有助于人们选择适度消费方式”,B选项“对消费理念的影响”只对应了观点句的后半句，没体现生“树立环保意识”, 故B选项片面，排除。','2021年四川省考','基础','published','{"globalNumber":343,"setNumber":18,"localNumber":3,"sourceLabel":"2021年四川省考76%","accuracy":76,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"传统文化中生态伦理思想有助于人们树立节约资源、保护环境的意识，选择适度的消费方式。儒家的“取之有度，用之有节”思想和道家的“知足去奢”思想，告诫人类应当克制自身欲望，珍惜、节约资源，既考虑到当前，也应该考虑到未来。引导人们树立正确合理的消费理念，更加注重环境、资源在代际之间的公正分配。给自然留下更多的修复空间，给子孙留下地绿、天蓝、水净的生存环境。这一思想与当今社会存在的享乐主义、消费主义思潮是针锋相对的。\n这段文字主要谈论的是："}],"optionRich":{"A":[{"text":"生态伦理思想的传统文化渊源"}],"B":[{"text":"生态伦理思想对消费理念的影响"}],"C":[{"text":"传统文化中生态伦理思想的当代价值"}],"D":[{"text":"儒家与道家在生态伦理方面的相同之处\n片段阅读6 0 0 (下册)"}]},"annotatedStemRich":[{"text":"⑥花生批注：","bold":true},{"text":"\n"},{"text":"行文结构：","bold":true},{"text":"总分结构。\n"},{"text":"开篇给出总观点：","bold":true},{"text":"\n传统文化中生态伦理思想有积极意义；\n"},{"text":"再解释分析：","bold":true},{"text":"\n通过儒家和道家的思想，论证传统文化生态伦理思想的正面作用，否定享乐、消费主义。\n传统文化中生态伦理思想有助于人们树立节约资源、保护环境的意识，选择适度的消费方式(提出总观点)。儒家的“取之有度，用之有节”思想和道家的“知足去奢”思想，告诫人类应当克制自身欲望，珍惜、节约资源，既考虑到当前，也应该考虑到未来。引导人们树立正确合理的消费理念，更加注重环境、资源在代际之间的公正分"},{"text":"配。给自然留下更多的修复空间，","bold":true},{"text":"给子孙留下地绿、天蓝、水净的生存环境。这一思想与当今社会存在的享乐主义、消费主义思潮是针锋相对的(分析论证)。⑥\n这段文字主要谈论的是："}],"annotatedOptionRich":{"A":[{"text":"生态伦理思想的传统文化渊源 "},{"text":"(无中生有)","bold":true}],"B":[{"text":"生态伦理思想对消费理念的影响( 片面 )"}],"C":[{"text":"传统文化中生态伦理思想的当代价值"}],"D":[{"text":"儒家与道家在生态伦理方面的相同之处(出处有误)\n"},{"text":"四SIHA海IGO公NGK考AO 练习题18","bold":true},{"text":"套\n⑦"},{"text":"花生批注：","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段首句直接给出作者观点，传统文化中生态伦理思想在当代有一系列正面作用；\nA选项“传统文化渊源”⑦无中生有；D选项出处有误，出自文段分析部分，属于从论证中提炼的选项，均可简单排除；\nC选项和B选项需要辨析，B选项与C选项相比表述片面⑧,排除；C选项“当代价值”既体现“树立环保意识”又体现“转变消费理念”,完美选项，当选。","notes":[{"marker":"⑥","content":"行文结构：总分结构。\n开篇给出总观点：\n传统文化中生态伦理思想有积极意义；\n再解释分析：\n通过儒家和道家的思想，论证传统文化生态伦理思想的正面作用，否定享乐、消费主义。\n传统文化中生态伦理思想有助于人们树立节约资源、保护环境的意识，选择适度的消费方式(提出总观点)。儒家的“取之有度，用之有节”思想和道家的“知足去奢”思想，告诫人类应当克制自身欲望，珍惜、节约资源，既考虑到当前，也应该考虑到未来。引导人们树立正确合理的消费理念，更加注重环境、资源在代际之间的公正分配。给自然留下更多的修复空间，给子孙留下地绿、天蓝、水净的生存环境。这一思想与当今社会存在的享乐主义、消费主义思潮是针锋相对的(分析论证)。⑥\n这段文字主要谈论的是：\nA. 生态伦理思想的传统文化渊源 (无中生有)\nB. 生态伦理思想对消费理念的影响( 片面 )\nC. 传统文化中生态伦理思想的当代价值\nD. 儒家与道家在生态伦理方面的相同之处(出处有误)\n四SIHA海IGO公NGK考AO 练习题18套","matchScore":1.5575,"pairingMode":"marker-and-content","order":5},{"marker":"⑧","content":"B选项为易错项，原文观点句可翻译为“生态伦理思想有助于人们树立环保意识，有助于人们选择适度消费方式”,B选项“对消费理念的影响”只对应了观点句的后半句，没体现生“树立环保意识”, 故B选项片面，排除。","matchScore":0.5794,"pairingMode":"marker-and-content","order":6}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300344,3,'中心理解题','抽象的价值，存留在理论之中；具体的公正，则需体现在每一个人身上，不像喊喊口号那样简单。医疗改革既需协调利益魔方，更需面对海量刚需和分布不均的现实；收入分配改革“分好蛋糕”理论明确，具体调整却是复杂的系统工程。不存在一种简单的理论，可以立竿见影搞定所有中国式问题。
这段文字强调的是改革中需解决好以下哪项关系：','[{"label":"A","content":"偏与全"},{"label":"B","content":"快与慢"},{"label":"C","content":"知与行"},{"label":"D","content":"难与易"}]','C','文段分析见批注。
文段四句话均谈论的是理论与现实的问题，C选项完美对应(知即理论，行即现实),当选。
“渊源”指事物的本源，故 A选项应翻译为“生态伦理思想来源于传统文化”,若A选项是正确答案，原文应详细介绍生态伦理思想从传统文化起源和发展的具体过程，呈现历程类文段的特征，但原文没体现起源，所以A选项无中生有。

花生批注：
⑨ 文段四句话意思相似，依次翻译即可：
①理论是抽象的价值(可理解为不具体、未落实的价值),现实需要体现在每一个人(可理解为理论中的价值要落到实处)身上；
②医疗改革需要协调各方利益(理论构想层面),但更需要面对困难现实；
③收入分配理论明确，但现实调整却很复杂；
④不存在一种理论能解决所有中国式的现实问题。
⑩ 考场思维：
四句话的前半句依次是“理论”、“需协调利益”、“理论”、“理论”;
根据另外三句可确定，“需协调利益”也是“理论”;
四句话的后半句依次是“具体的公正”、“现实”、“具体调整”、“搞定中国式问题”; 根据第一、三句的“具体”
和二句的“现实”,可推出后半句可统一概括为“现实”或“实践”或“落实”。','2021年新疆省考','进阶','published','{"globalNumber":344,"setNumber":18,"localNumber":4,"sourceLabel":"2021年新疆省考 48%","accuracy":48,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"抽象的价值，存留在理论之中；具体的公正，则需体现在每一个人身上，不像喊喊口号那样简单。医疗改革既需协调利益魔方，更需面对海量刚需和分布不均的现实；收入分配改革“分好蛋糕”理论明确，具体调整却是复杂的系统工程。不存在一种简单的理论，可以立竿见影搞定所有中国式问题。\n这段文字强调的是改革中需解决好以下哪项关系："}],"optionRich":{"A":[{"text":"偏与全"}],"B":[{"text":"快与慢"}],"C":[{"text":"知与行"}],"D":[{"text":"难与易"}]},"annotatedStemRich":[{"text":"①抽象的价值，存留在理论之中；具体的公正，则需体现在每一个人身上，不像喊喊口号那样简单。②医疗改革既需协调利益魔方，更需面对海量刚需和分布不均的现实；③收入分配改革“分好蛋糕”理论明确，具体调整却是复杂的系统工程。④不存在一种简单的理论，可以立竿见影搞定所有中国式问题。⑨\n这段文字强调的是改革中需解决好以下哪项关系："}],"annotatedOptionRich":{"A":[{"text":"偏与全(无中生有)"}],"B":[{"text":"快与慢(无中生有)"}],"C":[{"text":"知与行"}],"D":[{"text":"难与易(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段四句话均谈论的是理论与现实的问题，C选项完美对应(知即理论，行即现实),当选。\n“渊源”指事物的本源，故 A选项应翻译为“生态伦理思想来源于传统文化”,若A选项是正确答案，原文应详细介绍生态伦理思想从传统文化起源和发展的具体过程，呈现历程类文段的特征，但原文没体现起源，所以A选项无中生有。","notes":[{"marker":"⑨","content":"文段四句话意思相似，依次翻译即可：\n①理论是抽象的价值(可理解为不具体、未落实的价值),现实需要体现在每一个人(可理解为理论中的价值要落到实处)身上；\n②医疗改革需要协调各方利益(理论构想层面),但更需要面对困难现实；\n③收入分配理论明确，但现实调整却很复杂；\n④不存在一种理论能解决所有中国式的现实问题。","matchScore":0.6643,"pairingMode":"marker-and-content","order":7},{"marker":"⑩","content":"考场思维：\n四句话的前半句依次是“理论”、“需协调利益”、“理论”、“理论”;\n根据另外三句可确定，“需协调利益”也是“理论”;\n四句话的后半句依次是“具体的公正”、“现实”、“具体调整”、“搞定中国式问题”; 根据第一、三句的“具体”\n和二句的“现实”,可推出后半句可统一概括为“现实”或“实践”或“落实”。","matchScore":0.3998,"pairingMode":"content-similarity","order":8}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300345,3,'中心理解题','古人云：“道不同而不相悖，万物并育而不相害。”建设文化强国，必不能抛弃传统文化，更不能盲目沉溺在对外来事物迷离含混的幻想之中。相反，我们首先要坚守自己的长处，同时要懂得交流、借鉴、分析和辨别异质文明和他者文化的“表象”与“根质”。只有这样，我们才能最终实现中华民族伟大复兴的“中国梦”。
这段文字的主旨是：','[{"label":"A","content":"对待传统的旧有文化，我们应该去粗取精"},{"label":"B","content":"对待异质文明和他者文化，我们应该兼容并包"},{"label":"C","content":"我国建设文化强国，应吸收和借鉴中外文明成果"},{"label":"D","content":"建设文化强国有助于实现中华民族伟大复兴"}]','C','文段分析见批注。
文段在引出话题后，通过“不能”给出禁止型对策，又通过“要”给出祈使句对策，C选项是对对策的概括，可看作“A且B类”的完美选项⑫,当选：
A选项、B选项均片面，A选项未提及外来文化，B选项未提及传统文化，均可以简单排除；D选项可翻译为“实现中华民族伟大复兴需要建设文化强国”, 未体现建设文化强国的对策，排除。

花生批注：
⑪ 文段在引出话题后，全文都是对策：
①建设文化强国，不能抛弃传统文化；
②建设文化强国，不能盲目沉溺于外来文化；
③建设文化强国，要坚守传统文化的长处；
④建设文化强国，要学会分辨外来文化。
⑫ 吸收中华文明成果，对应 ①③;
借鉴外来文明成果，对应 ②④;
且C选项 = A选项 + B选项。','2021年广东选调','基础','published','{"globalNumber":345,"setNumber":18,"localNumber":5,"sourceLabel":"2021年广东选调 73%","accuracy":73,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"古人云：“道不同而不相悖，万物并育而不相害。”建设文化强国，必不能抛弃传统文化，更不能盲目沉溺在对外来事物迷离含混的幻想之中。相反，我们首先要坚守自己的长处，同时要懂得交流、借鉴、分析和辨别异质文明和他者文化的“表象”与“根质”。只有这样，我们才能最终实现中华民族伟大复兴的“中国梦”。\n这段文字的主旨是："}],"optionRich":{"A":[{"text":"对待传统的旧有文化，我们应该去粗取精"}],"B":[{"text":"对待异质文明和他者文化，我们应该兼容并包"}],"C":[{"text":"我国建设文化强国，应吸收和借鉴中外文明成果"}],"D":[{"text":"建设文化强国有助于实现中华民族伟大复兴"}]},"annotatedStemRich":[{"text":"古人云：“道不同而不相悖，万物并育而不相害(引出话题)。”建设文化强国，①必不能抛弃传统文化，②更不能盲目沉溺在对外来事物迷离含混的幻想之中。相反，③我们首先要坚守自己的长处，④同时要懂得交流、借鉴、分析和辨别异质文明和他者文化的“表象”与“根质”。只有这样，我们才能最终实现中华民族伟大复兴的“中国梦”(意义)。四\n这段文字的主旨是："}],"annotatedOptionRich":{"A":[{"text":"对待传统的旧有文化，我们应该去粗取精(片面)"}],"B":[{"text":"对待异质文明和他者文化，我们应该兼容并包(片面)"}],"C":[{"text":"我国建设文化强国，应吸收和借鉴中外文明成果"}],"D":[{"text":"建设文化强国有助于实现中华民族伟大复兴(对策有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段在引出话题后，通过“不能”给出禁止型对策，又通过“要”给出祈使句对策，C选项是对对策的概括，可看作“A且B类”的完美选项⑫,当选：\nA选项、B选项均片面，A选项未提及外来文化，B选项未提及传统文化，均可以简单排除；D选项可翻译为“实现中华民族伟大复兴需要建设文化强国”, 未体现建设文化强国的对策，排除。","notes":[{"marker":"⑪","content":"文段在引出话题后，全文都是对策：\n①建设文化强国，不能抛弃传统文化；\n②建设文化强国，不能盲目沉溺于外来文化；\n③建设文化强国，要坚守传统文化的长处；\n④建设文化强国，要学会分辨外来文化。","matchScore":0.8135,"pairingMode":"content-similarity","order":9},{"marker":"⑫","content":"吸收中华文明成果，对应 ①③;\n借鉴外来文明成果，对应 ②④;\n且C选项 = A选项 + B选项。","matchScore":0.5178,"pairingMode":"marker-and-content","order":10}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300346,3,'标题拟定类','荆轲，那个“风萧萧兮易水寒，壮士一去兮不复还”的勇士，在我国历史上是个特有的文化符号。然而，在手游里，“荆轲”二字变成了刺客家族世代传承的名号；刘备变成了肩扛火枪身穿风衣的黑帮教父；“刺秦”的故事也被胡编乱造得南辕北辙……在手游里，几千年来人们熟知的历史人物变得面目全非。这对缺少历史知识的少年儿童来说很容易产生迷惑，历史在这里，真成了可以“被随意打扮的小姑娘”。最适合做以上文字标题的一项是：','[{"label":"A","content":"手游也需要尊重历史"},{"label":"B","content":"手游不该“游戏”历史"},{"label":"C","content":"对历史的演绎不能过火"},{"label":"D","content":"历史不该被手游过度消费"}]','B','文段分析见批注。
文段转折之后引出问题“在手游中历史人物被改的面目全非，容易导致缺少历史知识的少年儿童迷惑”,C选项缺主体“手游”,可简单排除；
A选项、B选项和D选项表达的意思类似，都是针对问题的对策，但B选项有以下几点优势：①“游戏”与手游天然对应(手游虽是“游戏”,但不能“游戏”历史),更有可读性和趣味性；②用“不该游戏历史”提出对策，更有力量感；③标题包括双引号，表达生动形象，更能吸引人阅读；
综上，B选项更适合做本段标题，当选。

花生批注：
⑬ “手游”是文段主体。
⑭ 行文结构：二层结构之转折。先引出话题；
再转折引出问题：
手游中人们熟知的历史人物被改的面目全非，很容易导致缺少历史知识的少年儿童产生迷惑。','2018年贵州选调','进阶','published','{"globalNumber":346,"setNumber":18,"localNumber":6,"sourceLabel":"2018年贵州选调 63%","accuracy":63,"typeAndPassage":"标题拟定类+说理类文章","stemRich":[{"text":"荆轲，那个“风萧萧兮易水寒，壮士一去兮不复还”的勇士，在我国历史上是个特有的文化符号。然而，在手游里，“荆轲”二字变成了刺客家族世代传承的名号；刘备变成了肩扛火枪身穿风衣的黑帮教父；“刺秦”的故事也被胡编乱造得南辕北辙……在手游里，几千年来人们熟知的历史人物变得面目全非。这对缺少历史知识的少年儿童来说很容易产生迷惑，历史在这里，真成了可以“被随意打扮的小姑娘”。最适合做以上文字标题的一项是："}],"optionRich":{"A":[{"text":"手游也需要尊重历史"}],"B":[{"text":"手游不该“游戏”历史"}],"C":[{"text":"对历史的演绎不能过火"}],"D":[{"text":"历史不该被手游过度消费"}]},"annotatedStemRich":[{"text":"荆轲，那个“风萧萧兮易水寒，壮士一去兮不复还”的勇士，在我国历史上是个特有的文化符号(引出话题)。然而，在"},{"text":"手游","underline":true},{"text":"③里，“荆轲”二字变成了刺客家族世代传承的名号；刘备变成了肩扛火枪身穿风衣的黑帮教父；“刺秦”的故事也被胡编乱造得南辕北辙……在手游里，几千年来人们熟知的历史人物变得面目全非。这对缺少历史知识的少年儿童来说很容易产生迷惑，历史在这里，真成了可以“被随意打扮的小姑娘”(转折引出问题)。⑩\n最适合做以上文字标题的一项是："}],"annotatedOptionRich":{"A":[{"text":"手游也需要尊重历史"}],"B":[{"text":"手游不该“游戏”历史"}],"C":[{"text":"对历史的演绎不能过火"},{"text":"(","bold":true},{"text":" "},{"text":"缺主体","bold":true},{"text":" "},{"text":")","bold":true}],"D":[{"text":"历史不该被手游过度消费\n"},{"text":"四SIHA海IGO公NGK考AO ","bold":true},{"text":"练习题18套"}]},"practicalAnalysis":"文段分析见批注。\n文段转折之后引出问题“在手游中历史人物被改的面目全非，容易导致缺少历史知识的少年儿童迷惑”,C选项缺主体“手游”,可简单排除；\nA选项、B选项和D选项表达的意思类似，都是针对问题的对策，但B选项有以下几点优势：①“游戏”与手游天然对应(手游虽是“游戏”,但不能“游戏”历史),更有可读性和趣味性；②用“不该游戏历史”提出对策，更有力量感；③标题包括双引号，表达生动形象，更能吸引人阅读；\n综上，B选项更适合做本段标题，当选。","notes":[{"marker":"⑬","content":"“手游”是文段主体。","matchScore":0.6919,"pairingMode":"content-similarity","order":11},{"marker":"⑭","content":"行文结构：二层结构之转折。先引出话题；\n再转折引出问题：\n手游中人们熟知的历史人物被改的面目全非，很容易导致缺少历史知识的少年儿童产生迷惑。","matchScore":0.8638,"pairingMode":"content-similarity","order":12}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300347,3,'中心理解题','对孩童而言，在自然中嬉戏，不但能有效减轻压力，促进认知和免疫系统的发展，而且探索自然、观察自然万物的变化，本身就是重要的学习过程。著名物理学家费曼晚年回忆自己的成长道路，特别提到了父亲带自己在林间散步的意义。正是在观察动物的繁衍、树木的生死、生命的更迭中，他学到了最基本的科学观察方法和思维方式。
这段文字意在说明：','[{"label":"A","content":"如何学习科学的观察方法和思维方式"},{"label":"B","content":"儿童应该学会探索自然和观察自然"},{"label":"C","content":"在自然中嬉戏有利于身心健康"},{"label":"D","content":"亲近自然有助于儿童的学习"}]','D','文段分析见批注。
文段开篇即给出观点：孩童在自然中嬉戏有利学习，下文进行分析举例论证。D选项可翻译为“儿童亲近自然有助于学习”,是观点的同义替换，当选；
A选项出处有误，对应例子内容，且属于具体类选项，原文并未重点介绍“一二三四五”,排除；B选项虽提及“要学会探索自然和观察自然”,但未体现这样做的意义(即有利于学习),排除； C选项没有主语儿童且“有利于身心健康”未体现“有助于学习”,排除。

花生批注：
⑮ 行文结构：前观点结构。
首句开门见山提出观点：
孩子在自然中嬉戏，有好处，是重要的学习过程；
第二句和尾句：举出费曼的例子，并分析论证。
这段文字意在说明：
A. 如何学习科学的观察方法和思维方式(出处有误)
B. 儿童应该学会探索自然和观察自然(片面)
C. 在自然中嬉戏有利于身心健康( 缺主语 )
D. 亲近自然有助于儿童的学习','2021年广东选调','进阶','published','{"globalNumber":347,"setNumber":18,"localNumber":7,"sourceLabel":"2021年广东选调 69%","accuracy":69,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"对孩童而言，在自然中嬉戏，不但能有效减轻压力，促进认知和免疫系统的发展，而且探索自然、观察自然万物的变化，本身就是重要的学习过程。著名物理学家费曼晚年回忆自己的成长道路，特别提到了父亲带自己在林间散步的意义。正是在观察动物的繁衍、树木的生死、生命的更迭中，他学到了最基本的科学观察方法和思维方式。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"如何学习科学的观察方法和思维方式"}],"B":[{"text":"儿童应该学会探索自然和观察自然"}],"C":[{"text":"在自然中嬉戏有利于身心健康"}],"D":[{"text":"亲近自然有助于儿童的学习"}]},"annotatedStemRich":[{"text":"对孩童而言，在自然中嬉戏，不但能有效减轻压力，促进认知和免疫系统的发展，而且探索自然、观察自然万物的变化，本身就是重要的学习过程( 前观点)。著名物理学家费曼晚年回忆自己的成长道路，特别提到了父亲带自己在林间散步的意义。正是在观察动物的繁衍、树木的生死、生命的更迭中，他学到了最基本的科学观察方法和思维方式(分析论证)。⑤\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"如何学习科学的观察方法和思维方式(出处有误)"}],"B":[{"text":"儿童应该学会探索自然和观察自然(片面)"}],"C":[{"text":"在自然中嬉戏有利于身心健康( 缺主语 )"}],"D":[{"text":"亲近自然有助于儿童的学习"}]},"practicalAnalysis":"文段分析见批注。\n文段开篇即给出观点：孩童在自然中嬉戏有利学习，下文进行分析举例论证。D选项可翻译为“儿童亲近自然有助于学习”,是观点的同义替换，当选；\nA选项出处有误，对应例子内容，且属于具体类选项，原文并未重点介绍“一二三四五”,排除；B选项虽提及“要学会探索自然和观察自然”,但未体现这样做的意义(即有利于学习),排除； C选项没有主语儿童且“有利于身心健康”未体现“有助于学习”,排除。","notes":[{"marker":"⑮","content":"行文结构：前观点结构。\n首句开门见山提出观点：\n孩子在自然中嬉戏，有好处，是重要的学习过程；\n第二句和尾句：举出费曼的例子，并分析论证。\n这段文字意在说明：\nA. 如何学习科学的观察方法和思维方式(出处有误)\nB. 儿童应该学会探索自然和观察自然(片面)\nC. 在自然中嬉戏有利于身心健康( 缺主语 )\nD. 亲近自然有助于儿童的学习","matchScore":0.7541,"pairingMode":"content-similarity","order":13}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300348,3,'中心理解题','中国最早的文学作品《诗经》中就有不少有关乡愁的篇章(如《采薇》),唐诗宋词中表现乡愁主题的更是不在少数。20世纪中国现代早期的作家，如鲁迅、沈从文、废名、萧红等人，都有书写乡村记忆的作品，那里流宕着他们对乡村陷入现代困境的深切关怀。乡愁当然也是世界文学传统中的主题，荷马史诗《奥德赛》中写的就是奥德修斯历经千辛万苦，在海上漂泊10年，最终回到故土伊萨卡与家人团聚。德国浪漫主义文学兴起，怀乡是其重要的主题，并且具有了现代意义。
这段文字意在说明的是：','[{"label":"A","content":"中外作家通过怀乡或乡愁作品表现他们对乡村困境的深切关怀"},{"label":"B","content":"中外的作家都把怀乡或乡愁作为漫长传统中的重要主题来看待"},{"label":"C","content":"怀乡或乡愁是中外作家通过文学作品铭记历史的最好精神慰藉"},{"label":"D","content":"中外作家通过怀乡或乡愁的作品表现人类最基本、最普遍情感"}]','B','文段分析见批注。
文段为并列结构，依次介绍乡愁是我国及世界文学传统中的重要主题， B选项“中外作家都把乡愁作为重要主题”很好地概括了文段并列的两部分内容，当选；
A选项“对乡村困境的关怀”只在文段前半部分关于我国作家的部分提到，表述片面，排除；C选项的“最好精神慰藉”和D选项“最基本、最普遍情感”属绝对化表述，排除。

花生批注：
⑯ 抓住“也”表并列，既然此处指出乡愁也是世界文学传统中的主题，那么前文可以总结为乡愁是中国文学传统中的主题。
⑰ 行文结构：并列结构。
先介绍乡愁是中国文学传统中的主题；
再介绍乡愁也是世界文学传统中的主题。','2016年重庆市考','进阶','published','{"globalNumber":348,"setNumber":18,"localNumber":8,"sourceLabel":"2016年重庆市考 66%","accuracy":66,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"中国最早的文学作品《诗经》中就有不少有关乡愁的篇章(如《采薇》),唐诗宋词中表现乡愁主题的更是不在少数。20世纪中国现代早期的作家，如鲁迅、沈从文、废名、萧红等人，都有书写乡村记忆的作品，那里流宕着他们对乡村陷入现代困境的深切关怀。乡愁当然也是世界文学传统中的主题，荷马史诗《奥德赛》中写的就是奥德修斯历经千辛万苦，在海上漂泊10年，最终回到故土伊萨卡与家人团聚。德国浪漫主义文学兴起，怀乡是其重要的主题，并且具有了现代意义。\n这段文字意在说明的是："}],"optionRich":{"A":[{"text":"中外作家通过怀乡或乡愁作品表现他们对乡村困境的深切关怀"}],"B":[{"text":"中外的作家都把怀乡或乡愁作为漫长传统中的重要主题来看待"}],"C":[{"text":"怀乡或乡愁是中外作家通过文学作品铭记历史的最好精神慰藉"}],"D":[{"text":"中外作家通过怀乡或乡愁的作品表现人类最基本、最普遍情感"}]},"annotatedStemRich":[{"text":"中国最早的文学作品《诗经》中就有不少有关乡愁的篇章(如《采薇》), 唐诗宋词中表现乡愁主题的更是不在少数。20世纪中国现代早期的作家，如鲁迅、沈从文、废名、萧红等人，都有书写乡村记忆的作品，那里流宕着他们对乡村陷入现代困境的深切关怀。乡愁当然也⑨是世界文学传统中的主题，荷马史诗《奥德赛》中写的就是奥德修斯历经千辛万苦，在海上漂泊10年，最终回到故土伊萨卡与家人团聚。德国浪漫主义文学兴起，怀乡是其重要的主题，并且具有了现代意义。①\n这段文字意在说明的是："}],"annotatedOptionRich":{"A":[{"text":"中外作家通过怀乡或乡愁作品表现他们对乡村困境的深切关怀( 片面 )"}],"B":[{"text":"中外的作家都把怀乡或乡愁作为漫长传统中的重要主题来看待"}],"C":[{"text":"怀乡或乡愁是中外作家通过文学作品铭记历史的最好精神慰藉(绝对化)"}],"D":[{"text":"中外作家通过怀乡或乡愁的作品表现人类最基本、最普遍情感(绝对化)"}]},"practicalAnalysis":"文段分析见批注。\n文段为并列结构，依次介绍乡愁是我国及世界文学传统中的重要主题， B选项“中外作家都把乡愁作为重要主题”很好地概括了文段并列的两部分内容，当选；\nA选项“对乡村困境的关怀”只在文段前半部分关于我国作家的部分提到，表述片面，排除；C选项的“最好精神慰藉”和D选项“最基本、最普遍情感”属绝对化表述，排除。","notes":[{"marker":"⑯","content":"抓住“也”表并列，既然此处指出乡愁也是世界文学传统中的主题，那么前文可以总结为乡愁是中国文学传统中的主题。","matchScore":0.5079,"pairingMode":"content-similarity","order":14},{"marker":"⑰","content":"行文结构：并列结构。\n先介绍乡愁是中国文学传统中的主题；\n再介绍乡愁也是世界文学传统中的主题。","matchScore":0.7646,"pairingMode":"content-similarity","order":15}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300349,3,'细节判断题','所谓圩田，是指在临近江河湖海的地势低洼地区，人工筑堤挡水形成的农田，在我国特别是南方分布广泛，如长江中下游、江淮地区和江汉地区、珠江三角洲、四川盆地等地区。在不同的地方，圩田有着众多“别名”,如垸田、坝田、湖田、桑基鱼塘等，但其不变的共同特征是：低洼处筑堤，
内以围田，外以围水。作为我国典型的乡土景观，从空中鸟瞰，各种圩田像是一个个大大小小的模盘——外堤是棋盘边缘，内部纵横的河道、内堤，道路则是棋盘经纬，池塘、村庄则像一枚枚棋子。圩田尺度差异巨大，小者几亩，大者可达数十平方公里。其形态、地形也颇为多样，有四周高中间低的仰盂圩。中间高四周低的覆盆圩，半边高半边低的倾斜圩等。
根据这段文字，可以知道：','[{"label":"A","content":"圩田的众多“别名”显示其诸多的功能和特征"},{"label":"B","content":"圩田是劳动人民利用和改造自然的重要创造"},{"label":"C","content":"圩田的过度开发会对自然生态平衡造成破坏"},{"label":"D","content":"圩田是我国农村中独有的一种农业生产模式"}]','B','根据①句的“所谓圩田，是指在临近江河湖海的地势低洼地区”可知，圩田需利用临近江河胡海的地势低洼地区，体现“劳动人民利用自然”; 根据①句的“所谓圩田……人工筑堤挡水形成的农田”可知，圩田需要人工筑堤，体现“劳动人民改造自然”,由此可知，B选项正确，当选。

花生批注：
⑱ 原文表述为“在不同的地方，圩田有着众多“别名”, … … , 但其不变的共同特征是……”,别名和共同特征分属转折前后，并非“别名显示诸多功能和特征”。
⑲ 原文表述为“作为我国典型的乡土景观”,“典型”不意味着“我国独有”;
例如：卷发是黑色人种的典型特征，不代表只有黑人有卷发。','2022年安徽省事业单位','进阶','published','{"globalNumber":349,"setNumber":18,"localNumber":9,"sourceLabel":"2022年安徽省事业单位48%","accuracy":48,"typeAndPassage":"细节判断题","stemRich":[{"text":"所谓圩田，是指在临近江河湖海的地势低洼地区，人工筑堤挡水形成的农田，在我国特别是南方分布广泛，如长江中下游、江淮地区和江汉地区、珠江三角洲、四川盆地等地区。在不同的地方，圩田有着众多“别名”,如垸田、坝田、湖田、桑基鱼塘等，但其不变的共同特征是：低洼处筑堤，\n内以围田，外以围水。作为我国典型的乡土景观，从空中鸟瞰，各种圩田像是一个个大大小小的模盘——外堤是棋盘边缘，内部纵横的河道、内堤，道路则是棋盘经纬，池塘、村庄则像一枚枚棋子。圩田尺度差异巨大，小者几亩，大者可达数十平方公里。其形态、地形也颇为多样，有四周高中间低的仰盂圩。中间高四周低的覆盆圩，半边高半边低的倾斜圩等。\n根据这段文字，可以知道："}],"optionRich":{"A":[{"text":"圩田的众多“别名”显示其诸多的功能和特征"}],"B":[{"text":"圩田是劳动人民利用和改造自然的重要创造"}],"C":[{"text":"圩田的过度开发会对自然生态平衡造成破坏"}],"D":[{"text":"圩田是我国农村中独有的一种农业生产模式"}]},"annotatedStemRich":[{"text":"①所谓圩田，是指在临近江河湖海的地势低洼地区，人工筑堤挡水形成的农田，在我国特别是南方分布广泛，如长江中下游、江淮地区和江汉地区、珠江三角洲、四川盆地等地区。②在不同的地方，圩田有着众多“别名”,如垸田、坝田、湖田、桑基鱼塘等，但其不变的共同特征是：低洼处筑堤，内以围田，外以围水。③作为我国典型的乡土景观，从空中鸟瞰，各种圩田像是一个个大大小小的模盘——外堤是棋盘边缘，内部纵横的河道、内堤，道路则是棋盘经纬，池塘、村庄则像一枚枚棋子。④圩田尺度差异巨大，小者几亩，大者可达数十平方公里。⑤其形态、地形也颇为多样，有四周高中间低的仰盂圩。⑥中间高四周低的覆盆圩，半边高半边低的倾斜圩等。\n根据这段文字，可以知道："}],"annotatedOptionRich":{"A":[{"text":"圩田的众多“别名”显示其诸多的功能和特征"},{"text":"(杂糅)⑩","bold":true}],"B":[{"text":"圩田是劳动人民利用和改造自然的重要创造"}],"C":[{"text":"圩田的过度开发会对自然生态平衡造成破坏(无中生有)"}],"D":[{"text":"圩田是我国农村中独有的一种农业生产模式(无中生有)\n"},{"text":"四SIHA海IGO公NGK考AO ","bold":true},{"text":"练习题18套"}]},"practicalAnalysis":"根据①句的“所谓圩田，是指在临近江河湖海的地势低洼地区”可知，圩田需利用临近江河胡海的地势低洼地区，体现“劳动人民利用自然”; 根据①句的“所谓圩田……人工筑堤挡水形成的农田”可知，圩田需要人工筑堤，体现“劳动人民改造自然”,由此可知，B选项正确，当选。","notes":[{"marker":"⑱","content":"原文表述为“在不同的地方，圩田有着众多“别名”, … … , 但其不变的共同特征是……”,别名和共同特征分属转折前后，并非“别名显示诸多功能和特征”。","matchScore":0.549,"pairingMode":"content-similarity","order":16},{"marker":"⑲","content":"原文表述为“作为我国典型的乡土景观”,“典型”不意味着“我国独有”;\n例如：卷发是黑色人种的典型特征，不代表只有黑人有卷发。","matchScore":0.2886,"pairingMode":"content-similarity","order":17}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300350,3,'细节判断题','据美国宇航局太空网报道，天文学家发现专业术语“行星状星云”是用词不当。然而，事实上，这些壮观的气体和尘埃云团与行星确实有一些联系。300年前，当天文学家发现这些天体时，他们无法说出这到底是些什么东西，因为他们利用早期相对粗糙的望远镜观测到的这些天体和天王星有相似之处，把它命名为行星状星云。但是到19世纪中期，天文学家意识到，这些天体实际上是垂死恒星喷发出的尘埃云团。
对于本段话理解不正确的是：','[{"label":"A","content":"“行星状星云”事实上并不是行星"},{"label":"B","content":"“行星状星云”在外形上和天王星相似，并因此而得名"},{"label":"C","content":"“行星状星云”是恒星某个时期所呈现的一种必然现象"},{"label":"D","content":"天文学家认为专业术语“行星状星云”用词不当的原因在于这个术语只描述了现象，而没有说明本质"}]','C','本题为选非题，只需在文段找到相应对应句即可。C选项为绝对化选项②,原文未提及“必然”,选项中也不应提及，当选。

花生批注：
②⑳ D选项为本题强干扰项：
早期因这些天体和天王星相似(天王星为行星),所以被命名行星状星云，这是从
“现象”角度描述；
后来意识到这些天体实际是尘埃云团，即这些天体本质是尘埃云团，说明“行星状星云”未说明这些天体本质。综上，D选项表述正确。
② 原文为“行星状云团为垂死恒星所喷发”,并非所有垂死恒星均喷发尘埃云团；且不能从垂死恒星(小部分的特殊现象)推导所有恒星均有此现象。
A. “行星状星云”事实上并不是行星
B. “行星状星云”在外形上和天王星相似，并因此而得名
C. “行星状星云”是恒星某个时期所呈现的一种必然现象(绝对化选项)
D. 天文学家认为专业术语“行星状星云”用词不当的原因在于这个术语只描述了现象，而没有说明本质','2019年天津市事业单位','进阶','published','{"globalNumber":350,"setNumber":18,"localNumber":10,"sourceLabel":"2019年天津市事业单位61%","accuracy":61,"typeAndPassage":"细节判断题","stemRich":[{"text":"据美国宇航局太空网报道，天文学家发现专业术语“行星状星云”是用词不当。然而，事实上，这些壮观的气体和尘埃云团与行星确实有一些联系。300年前，当天文学家发现这些天体时，他们无法说出这到底是些什么东西，因为他们利用早期相对粗糙的望远镜观测到的这些天体和天王星有相似之处，把它命名为行星状星云。但是到19世纪中期，天文学家意识到，这些天体实际上是垂死恒星喷发出的尘埃云团。\n对于本段话理解不正确的是："}],"optionRich":{"A":[{"text":"“行星状星云”事实上并不是行星"}],"B":[{"text":"“行星状星云”在外形上和天王星相似，并因此而得名"}],"C":[{"text":"“行星状星云”是恒星某个时期所呈现的一种必然现象"}],"D":[{"text":"天文学家认为专业术语“行星状星云”用词不当的原因在于这个术语只描述了现象，而没有说明本质"}]},"annotatedStemRich":[{"text":"据美国宇航局太空网报道，天文学家发现专业术语“行星状星云”是用词不当。然而，事实上，这些壮观的气体和尘埃云团与行星确实有一些联系。 300年前，当天文学家发现这些天体时，他们无法说出这到底是些什么东西，因为他们利用早期相对粗糙的望远镜观测到的这些天体和天王星有相似之处，把它命名为行星状星云( B 选项)。但是到19世纪中期，天文学家意识到，这些天体实际上是垂死恒星喷发出的尘埃云团 ( A 选项)。\n对于本段话理解不正确的是："}],"annotatedOptionRich":{"A":[{"text":"“行星状星云”事实上并不是行星"}],"B":[{"text":"“行星状星云”在外形上和天王星相似，并因此而得名"}],"C":[{"text":"“行星状星云”是恒星某个时期所呈现的一种必然现象(绝对化选项)"}],"D":[{"text":"天文学家认为专业术语“行星状星云”用词不当的原因在于这个术语只描述了现象，而没有说明本质"}]},"practicalAnalysis":"本题为选非题，只需在文段找到相应对应句即可。C选项为绝对化选项②,原文未提及“必然”,选项中也不应提及，当选。","notes":[{"marker":"②⑳","content":"D选项为本题强干扰项：\n早期因这些天体和天王星相似(天王星为行星),所以被命名行星状星云，这是从\n“现象”角度描述；\n后来意识到这些天体实际是尘埃云团，即这些天体本质是尘埃云团，说明“行星状星云”未说明这些天体本质。综上，D选项表述正确。","matchScore":0.5485,"pairingMode":"content-similarity","order":18},{"marker":"②","content":"原文为“行星状云团为垂死恒星所喷发”,并非所有垂死恒星均喷发尘埃云团；且不能从垂死恒星(小部分的特殊现象)推导所有恒星均有此现象。\nA. “行星状星云”事实上并不是行星\nB. “行星状星云”在外形上和天王星相似，并因此而得名\nC. “行星状星云”是恒星某个时期所呈现的一种必然现象(绝对化选项)\nD. 天文学家认为专业术语“行星状星云”用词不当的原因在于这个术语只描述了现象，而没有说明本质","matchScore":0.3475,"pairingMode":"marker-and-content","order":19}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300351,3,'下文推断类','科学家认为，海洋对大气中二氧化碳的吸收暂时缓解了二氧化碳浓度的上升速度，一旦这种缓解作用失效，大气中二氧化碳的浓度将以更快速度增长。那么,增加的二氧化碳是否会导致大气温度上升呢?虽然绝大部分科学家相信答案是肯定的，但这毕竟是一个漫长的过程，存在诸多变数，于是气候变化怀疑论者一直在这一点上做文章，试图让老百姓相信二氧化碳浓度不一定和大气温度有关联。这个策略非常有效，以至于很多人至今仍然拒绝相信是人类活动导致了全球变暖，因此拒绝参与减排。
这段文字接下来最可能说的是：','[{"label":"A","content":"气候变化与二氧化碳浓度关系不大"},{"label":"B","content":"海洋对二氧化碳的吸收能力越来越弱"},{"label":"C","content":"人类活动会导致二氧化碳浓度的增加"},{"label":"D","content":"人类活动是导致全球变暖的主要原因"}]','D','文段先介绍了气候变化怀疑论者一直试图让百姓相信二氧化碳浓度不一定和大气温度有关联，文末给出现在很多百姓的观点：很多人不相信是人类活动导致全球变暖；
下文应该对此观点进行反驳，要解释清楚为什么人类活动确实会导致全球变暖，后文与此文段构成转折关系，对应到D选项；
A选项反而支持了怀疑者，排除；B选项和C选项未提及全球变暖的原因，排除；综上，正确答案是D选项。','2014年山东省考','进阶','published','{"globalNumber":351,"setNumber":18,"localNumber":11,"sourceLabel":"2014年山东省考68%","accuracy":68,"typeAndPassage":"下文推断类 + 转折","stemRich":[{"text":"科学家认为，海洋对大气中二氧化碳的吸收暂时缓解了二氧化碳浓度的上升速度，一旦这种缓解作用失效，大气中二氧化碳的浓度将以更快速度增长。那么,增加的二氧化碳是否会导致大气温度上升呢?虽然绝大部分科学家相信答案是肯定的，但这毕竟是一个漫长的过程，存在诸多变数，于是气候变化怀疑论者一直在这一点上做文章，试图让老百姓相信二氧化碳浓度不一定和大气温度有关联。这个策略非常有效，以至于很多人至今仍然拒绝相信是人类活动导致了全球变暖，因此拒绝参与减排。\n这段文字接下来最可能说的是："}],"optionRich":{"A":[{"text":"气候变化与二氧化碳浓度关系不大"}],"B":[{"text":"海洋对二氧化碳的吸收能力越来越弱"}],"C":[{"text":"人类活动会导致二氧化碳浓度的增加"}],"D":[{"text":"人类活动是导致全球变暖的主要原因"}]},"annotatedStemRich":[{"text":"科学家认为，海洋对大气中二氧化碳的吸收暂时缓解了二氧化碳浓度的上升速度，一旦这种缓解作用失效，大气中二氧化碳的浓度将以更快速度增长。那么, 增加的二氧化碳是否会导致大气温度上升呢?虽然绝大部分科学家相信答案是肯定的，但这毕竟是一个漫长的过程，存在诸多变数，于是气候变化怀疑论者一直在这一点上做文章，试图让老百姓相信二氧化碳浓度不一定和大气温度有关联( 背景介绍)。这个策略非常有效，以至于很多人至今仍然拒绝相信是人类活动导致了全球变暖，因此拒绝参与减排(介绍很多人不相信是人类活动导致全球变暖)。\n这段文字接下来最可能说的是："}],"annotatedOptionRich":{"A":[{"text":"气候变化与二氧化碳浓度关系不大"}],"B":[{"text":"海洋对二氧化碳的吸收能力越来越弱"}],"C":[{"text":"人类活动会导致二氧化碳浓度的增加"}],"D":[{"text":"人类活动是导致全球变暖的主要原因"}]},"practicalAnalysis":"文段先介绍了气候变化怀疑论者一直试图让百姓相信二氧化碳浓度不一定和大气温度有关联，文末给出现在很多百姓的观点：很多人不相信是人类活动导致全球变暖；\n下文应该对此观点进行反驳，要解释清楚为什么人类活动确实会导致全球变暖，后文与此文段构成转折关系，对应到D选项；\nA选项反而支持了怀疑者，排除；B选项和C选项未提及全球变暖的原因，排除；综上，正确答案是D选项。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300352,3,'上文推断类','然而，随着经学日益变成章句之学和庸俗的谶纬，情况便大不一样了。光武、章帝就因不满经学的烦琐多次命人“省减五经章句”;曾使王莽、刘秀荣登皇帝宝座的谶纬，后来也变成了篡权、谋反的工具，这表明一切都走到了专制王权期望的反面。因此，到东汉中期以后，皇权对经学和儒生的依赖开始变小，加上外戚、官宦专权，大封党羽、排挤士人，进一步拆散了经学与官僚政治的联盟。本文段上文最有可能讲述的是：','[{"label":"A","content":"经学的理论来源与后续发展状况"},{"label":"B","content":"经学的特点和对官僚政治的影响"},{"label":"C","content":"经学的光辉历史与儒生的联系"},{"label":"D","content":"经学的主要内容与皇权的关系"}]','D','需要注意本题提问方式，是对本段上文内容的分析判断。

花生批注：
3 填入D选项后，文段结构如下：
先介绍经学主要内容，和经学与皇权过去“亲密”的关系；
转折后引出问题：经学走向皇权期待的反面；
最后总结：皇权对经学依赖开始变小，经学和官僚政治的联盟被拆散。
文段先通过转折引出问题：经学走到皇权的反面；文末给出总结：皇权对经学和儒生的依赖开始变小，经学和官僚政治的联盟被拆散。
转折后指出“经学的问题”,那么转折前应介绍“经学是什么和经学对皇权的帮助”;根据文末“皇权对经学依赖开始变小”也可知，前文应介绍“皇权之前对经学的依赖”;“经学对皇权的帮助”和“之前皇权对经学的依赖”均可概括为“经学与皇权的关系”,对应D选项，当选；
其他选项均未提及“皇权”,可简单排除。','2019年黑龙江省边境','挑战','published','{"globalNumber":352,"setNumber":18,"localNumber":12,"sourceLabel":"2019年黑龙江省边境 28%","accuracy":28,"typeAndPassage":"上文推断类","stemRich":[{"text":"然而，随着经学日益变成章句之学和庸俗的谶纬，情况便大不一样了。光武、章帝就因不满经学的烦琐多次命人“省减五经章句”;曾使王莽、刘秀荣登皇帝宝座的谶纬，后来也变成了篡权、谋反的工具，这表明一切都走到了专制王权期望的反面。因此，到东汉中期以后，皇权对经学和儒生的依赖开始变小，加上外戚、官宦专权，大封党羽、排挤士人，进一步拆散了经学与官僚政治的联盟。本文段上文最有可能讲述的是："}],"optionRich":{"A":[{"text":"经学的理论来源与后续发展状况"}],"B":[{"text":"经学的特点和对官僚政治的影响"}],"C":[{"text":"经学的光辉历史与儒生的联系"}],"D":[{"text":"经学的主要内容与皇权的关系"}]},"annotatedStemRich":[{"text":"然而，随着经学日益变成章句之学和庸俗的谶纬，情况便大不一样了。光武、章帝就因不满经学的烦琐多次命人“省减五经章句”;曾使王莽、刘秀荣登皇帝宝座的谶纬，后来也变成了篡权、谋反的工具，这表明一切都走到了专制王权期望的反面(转折提出问题)。因此，到东汉中期以后，皇权对经学和儒生的依赖开始变小，加上外戚、官宦专权，大封党羽、排挤士人，进一步拆散了经学与官僚政治的联盟(总结)。\n本文段上文最有可能讲述的是："}],"annotatedOptionRich":{"A":[{"text":"经学的理论来源与后续发展状况"}],"B":[{"text":"经学的特点和对官僚政治的影响"}],"C":[{"text":"经学的光辉历史与儒生的联系"}],"D":[{"text":"经学的主要内容与皇权的关系\n"},{"text":"四SIHA海IGO公NGK考AO ","bold":true},{"text":"练习题18套"}]},"practicalAnalysis":"需要注意本题提问方式，是对本段上文内容的分析判断。","notes":[{"marker":"3","content":"填入D选项后，文段结构如下：\n先介绍经学主要内容，和经学与皇权过去“亲密”的关系；\n转折后引出问题：经学走向皇权期待的反面；\n最后总结：皇权对经学依赖开始变小，经学和官僚政治的联盟被拆散。\n文段先通过转折引出问题：经学走到皇权的反面；文末给出总结：皇权对经学和儒生的依赖开始变小，经学和官僚政治的联盟被拆散。\n转折后指出“经学的问题”,那么转折前应介绍“经学是什么和经学对皇权的帮助”;根据文末“皇权对经学依赖开始变小”也可知，前文应介绍“皇权之前对经学的依赖”;“经学对皇权的帮助”和“之前皇权对经学的依赖”均可概括为“经学与皇权的关系”,对应D选项，当选；\n其他选项均未提及“皇权”,可简单排除。","matchScore":0.4363,"pairingMode":"content-similarity","order":21}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300353,3,'语句填入类','农业危机根本上也是资源危机，关键是土地资源。我们总希望自己的住房大一点，然而，土地是有存量没有增量的要素，人类的需求却是没有止境的。所以，更多的农业用地被工业侵占，更多的农村土地被城市侵占，农业危机的根源就在这里。发达国家已经完成工业化，进入所谓后现代社会了，已经没有改弦更张的可能了。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"因此，我们应该把为数不多的土地做成高附加值的东西"},{"label":"B","content":"我们所能做的，就是改变过度消耗资源的产业体系"},{"label":"C","content":"我们要提高技术进步对经济增长的贡献率，改变生产和生活方式"},{"label":"D","content":"这就提醒我们：面临资源环境压力，在产业升级中要保护好农田\nS四IHA海IGO公NGK考AO 练习题18套"}]','D','文段分析见批注。
文段为后对策结构，尾句对比发达国家给出对策，对策应针对问题，即“要保护农业土地资源，不能再侵占农业土地资源”。只有D选项提到“保护农田”, 当选；
A选项对策针对的问题应是“土地附加值不够”,和原文问题不一致；B选项、 C选项均未提及“农业土地资源”,排除。

花生批注：
④ 行文结构：后对策结构。
首句开门见山提出问题：
农业危机关键是土地资源危机；
下文分析介绍：
土地总量有限，人类需求无止境，侵占了太多土地；
尾句对比发达国家给出对策：
发达国家已无法改弦更张，我们要吸取教训。','2018年联考','基础','published','{"globalNumber":353,"setNumber":18,"localNumber":13,"sourceLabel":"2018年联考 75%","accuracy":75,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"农业危机根本上也是资源危机，关键是土地资源。我们总希望自己的住房大一点，然而，土地是有存量没有增量的要素，人类的需求却是没有止境的。所以，更多的农业用地被工业侵占，更多的农村土地被城市侵占，农业危机的根源就在这里。发达国家已经完成工业化，进入所谓后现代社会了，已经没有改弦更张的可能了。"},{"text":"                        ","underline":true},{"text":"\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"因此，我们应该把为数不多的土地做成高附加值的东西"}],"B":[{"text":"我们所能做的，就是改变过度消耗资源的产业体系"}],"C":[{"text":"我们要提高技术进步对经济增长的贡献率，改变生产和生活方式"}],"D":[{"text":"这就提醒我们：面临资源环境压力，在产业升级中要保护好农田\nS四IHA海IGO公NGK考AO 练习题18套"}]},"annotatedStemRich":[{"text":"农业危机根本上也是资源危机，关键是土地资源(引出话题)。我们总希望自己的住房大一点，然而，土地是有存量没有增量的要素，人类的需求却是没有止境的。所以，更多的农业用地被工业侵占，更多的农村土地被城市侵占，农业危机的根源就在这里(分析论证)。发达国家已经完成工业化，进入所谓后现代社会了，已经没有改弦更张的可能了。"},{"text":"                         ","underline":true},{"text":" ( 提出对策)。②\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"因此，我们应该把为数不多的土地做成高附加值的东西"}],"B":[{"text":"我们所能做的，就是改变过度消耗资源的产业体系"}],"C":[{"text":"我们要提高技术进步对经济增长的贡献率，改变生产和生活方式"}],"D":[{"text":"这就提醒我们：面临资源环境压力，在产业升级中要保护好农田"}]},"practicalAnalysis":"文段分析见批注。\n文段为后对策结构，尾句对比发达国家给出对策，对策应针对问题，即“要保护农业土地资源，不能再侵占农业土地资源”。只有D选项提到“保护农田”, 当选；\nA选项对策针对的问题应是“土地附加值不够”,和原文问题不一致；B选项、 C选项均未提及“农业土地资源”,排除。","notes":[{"marker":"④","content":"行文结构：后对策结构。\n首句开门见山提出问题：\n农业危机关键是土地资源危机；\n下文分析介绍：\n土地总量有限，人类需求无止境，侵占了太多土地；\n尾句对比发达国家给出对策：\n发达国家已无法改弦更张，我们要吸取教训。","matchScore":0.6159,"pairingMode":"content-similarity","order":22}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300354,3,'语句填入类','在一项针对留学生的跨文化交际调查中，当被问及“你适应中国的生活吗”时，超过60%的亚洲学生和欧美学生都选择了“比较适应”,可见伴随汉语水平的提高和对中国了解程度的加深，大多数受访者已经逐渐步入了跨文化适应中的“恢复期”,正在更加理性地认识中国，并且寻找办法解决文化休克带来的交际问题。但是，仍然有20%的亚洲学生处于“危机期”,认为“不太适应中国，对中国文化还很困惑”,而仅有8%左右的欧美学生有同样的感受。这说明，
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"中国文化与亚洲文化有亲缘关系的说法似乎并不成立"},{"label":"B","content":"文化距离的远近并不是影响跨文化适应的关键性因素"},{"label":"C","content":"某种意义上讲，欧美学生比亚洲学生更能适应中国文化"},{"label":"D","content":"对地域文化的了解程度决定其对该地域文化的接受程度"}]','B','文段先介绍了“针对留学生跨文化交际”的调查结果：①超过60%的亚洲学生和欧洲学生都“比较适应”中国生活，②20%的亚洲学生和8% 的欧美学生“不太适应”中国生活。文末“这说明”引出对上文调查的总结。
A选项的“中国文化与亚洲文化有亲缘关系”和D选项的“对地域文化的了解程度”属于无中生有，可简单排除；
B选项、C选项均可看作是对上文的概括，二者相比， B选项更优，当选。

花生批注：
25 分总结构，尾句由“这说明”引出对上文的总结。
⑥ B选项更优的理由有三：
①是“跨文化适应的关键性因素”与首句“跨文化交际调查”呼应；
②是“文化距离的远近”正是欧美国家和亚洲国家的实质不同，更能对应调查的两个群体；
③是“这说明”引出尾句，“说明”对应更深层次的探讨， C选项的说法太过于表面；
例如：某项调查中，A 国年轻男性平均身高为175cm,B 国平均身高为170cm, 这说明，A国比B 国男性青年身高更高(过于表面，没有深入分析，未说明什么问题)。','2020年四川下半年省考','进阶','published','{"globalNumber":354,"setNumber":18,"localNumber":14,"sourceLabel":"2020年四川下半年省考69%","accuracy":69,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"在一项针对留学生的跨文化交际调查中，当被问及“你适应中国的生活吗”时，超过60%的亚洲学生和欧美学生都选择了“比较适应”,可见伴随汉语水平的提高和对中国了解程度的加深，大多数受访者已经逐渐步入了跨文化适应中的“恢复期”,正在更加理性地认识中国，并且寻找办法解决文化休克带来的交际问题。但是，仍然有20%的亚洲学生处于“危机期”,认为“不太适应中国，对中国文化还很困惑”,而仅有8%左右的欧美学生有同样的感受。这说明，"},{"text":"                         ","underline":true},{"text":"\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"中国文化与亚洲文化有亲缘关系的说法似乎并不成立"}],"B":[{"text":"文化距离的远近并不是影响跨文化适应的关键性因素"}],"C":[{"text":"某种意义上讲，欧美学生比亚洲学生更能适应中国文化"}],"D":[{"text":"对地域文化的了解程度决定其对该地域文化的接受程度"}]},"annotatedStemRich":[{"text":"在一项针对留学生的跨文化交际调查中，当被问及“你适应中国的生活吗”时，超过60%的亚洲学生和欧美学生都选择了“比较适应”,可见伴随汉语水平的提高和对中国了解程度的加深，大多数受访者已经逐渐步入了跨文化适应中的“恢复期”,正在更加理性地认识中国，并且寻找办法解决文化休克带来的交际问题。但是，仍然有20%的亚洲学生处于“危机期”,认为“不太适应中国，对中国文化还很困惑”,而仅有8%左右的欧美学生有同样的感受。"},{"text":"这说明，","underline":true},{"text":"\n⑮\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"中国文化与亚洲文化有亲缘关系的说法似乎并不成立"}],"B":[{"text":"文化距离的远近并不是影响跨文化适应的关键性因素"}],"C":[{"text":"某种意义上讲，欧美学生比亚洲学生更能适应中国文化"}],"D":[{"text":"对地域文化的了解程度决定其对该地域文化的接受程度"}]},"practicalAnalysis":"文段先介绍了“针对留学生跨文化交际”的调查结果：①超过60%的亚洲学生和欧洲学生都“比较适应”中国生活，②20%的亚洲学生和8% 的欧美学生“不太适应”中国生活。文末“这说明”引出对上文调查的总结。\nA选项的“中国文化与亚洲文化有亲缘关系”和D选项的“对地域文化的了解程度”属于无中生有，可简单排除；\nB选项、C选项均可看作是对上文的概括，二者相比， B选项更优，当选。","notes":[{"marker":"25","content":"分总结构，尾句由“这说明”引出对上文的总结。","matchScore":0.6701,"pairingMode":"content-similarity","order":23},{"marker":"⑥","content":"B选项更优的理由有三：\n①是“跨文化适应的关键性因素”与首句“跨文化交际调查”呼应；\n②是“文化距离的远近”正是欧美国家和亚洲国家的实质不同，更能对应调查的两个群体；\n③是“这说明”引出尾句，“说明”对应更深层次的探讨， C选项的说法太过于表面；\n例如：某项调查中，A 国年轻男性平均身高为175cm,B 国平均身高为170cm, 这说明，A国比B 国男性青年身高更高(过于表面，没有深入分析，未说明什么问题)。","matchScore":0.2943,"pairingMode":"content-similarity","order":24}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300355,3,'下文推断类②','大家都知道中国文化需要“走出去”,但是很少有人清楚地知道文化方面什么东西要走出去。正如商家做营销，你要推销产品，首先必须有产品。营销只是包装和策略问题，营销得当就能够逐步确立人们对产品的认同感。但无论如何，首先必须有高质量的产品。如果产品质量低下，营销做得再好也无济于事。这段文字接下来最有可能讲述的是：','[{"label":"A","content":"营销与产品的相互关系"},{"label":"B","content":"如何建立文化产品的质量标准"},{"label":"C","content":"目前中国文化“走出去”所面临的困境"},{"label":"D","content":"中国文化“走出去”应确立的主要产品"}]','D','文段分析见批注。
文段首句先提出问题“不知道文化方面什么东西要走出去”,之后举例进行解释：商家推销要先有优质产品，否则营销再好也无济于事。下文应针对问题给出解决方案，即“确定中国文化走出去的‘产品’”,对应D选项，当选；
A选项、B选项与“中国文化走出去”这一话题无关，排除；C选项，中国文化走出去面临的困境(即“不清楚什么东西要走出去”)已经有所阐述，若需要继续介绍应在首句后展开，排除。

花生批注：
2 下文推断的常见结构：
①上文文末提出新内容→下文解释新内容
②上文提出问题→下文分析问题、解决问题
③上文给出宏观对策、原因等→下文具体展开
④时间对比：过去不行→现在有了新突破
⑤总分：上文是总+分→下文补充另一“分”
⑥转折
⑳ 中国文化走出去是全文谈论主题。
28 下文推断的常见结构：
①上文文末提出新内容→下文解释新内容
②上文提出问题→下文分析问题、解决问题
③上文给出宏观对策、原因等→下文具体展开
④时间对比；过去不行→现在有了新突破
