INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300356,3,'语句排序类','①他对书法，颇不自重，始终把它看成是“静中自是一乐事”
②当时他以杰出的诗人、书法家出名，随时有人登门求字
③他写字，说是“天真烂漫是吾师”,往往信笔一挥，不计工拙
④一生中，他不知写过多少诗，写过多少书作
⑤他习惯于随时题诗，或是书写杂感评论，随后随手赠与他人
⑥于是，奇迹就在这样一种平淡无求的心态下产生了将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"④②①⑤③⑥"},{"label":"B","content":"②③⑤④①⑥"},{"label":"C","content":"②⑤①④⑥③"},{"label":"D","content":"④②⑤①③⑥30"}]','D','本题首句不好判断，但②④均是先说作诗再说书法，后续具体介绍也应按此顺序；①③句讲的是书法，⑤讲的是写诗，⑤应在①③前，排除 A选项、B选项；
此外，②句提及“随时有人登门求字”,⑤句提及“他习惯随手赠与他人”, 两句有顺承关系，而且应先有“求字”再说“赠与”,因此应当②⑤绑定；再次， ⑥是对上文的总结，奇迹指的是“无心反而出色”,确定D选项。

花生批注：
③0 行文逻辑如下：
④②引出他写诗、书法出名， ⑤①③依次介绍他对写诗和书法的态度，⑥做总结：平淡无奇的心态反而创造奇迹 (即成就高水平)。
