INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300357,3,'中心理解题','隐身战机目前主要依靠外形设计和材料表面涂层，来降低其可探测性，实现雷达隐身。但是，受现有技术和材料水平以及战机制造难度、机动性能、造价与后续费用、维护保障方便性等诸多限制，隐身战机不得不在上述几方面做出一定平衡，因此一般不可能实现全方位和全电磁波段的所谓全隐身，特别是它在执行特殊任务，携带或挂载暴露在机体外的非隐形配置时，隐身能力要下降很多。
这段文字意在：','[{"label":"A","content":"介绍制造隐身战机的困境"},{"label":"B","content":"分析隐身战机的设计缺陷"},{"label":"C","content":"探讨隐身战机的技术难点"},{"label":"D","content":"阐述隐身战机的隐身原理"}]','A','文段分析见批注。
文段可视为二层结构之转折，转折后介绍隐身战机制造的现状，即“因为存在诸多限制，只能做出一定的平衡，一般不能实现全隐身”,对应A选项，“困境”体现受限制而无奈的现状； B选项为强干扰项⑧,设计缺陷指的是设计过程中未考虑到的问题，但目前隐身战机的制造是在考虑充分后不得已选择的一种平衡，而非设计存在“缺陷”,排除；
C选项的“技术难点”并没有展开讨论，无中生有，排除；D选项出处有误，对应转折之前，且未体现制造隐身战机遇到的困境，排除。

花生批注：
③ 行文结构：二层结构之转折。
转折前引出话题：
隐身战机实现雷达隐身的方式；
转折后介绍现状：
受诸多限制，隐身战机的制造需做出一定平衡；因此一般不可能实现全隐身。
③2 例如：因行测课程较多，花生老师无法根据同学的基础分别开班授课(基础较差的在基础班、基础好的在提高班、冲刺行测80分的在拔高班);
可以说这是目前的困境(考虑到该问题，但受限客观情况，无法兼顾),但不能说是设计缺陷(设计课程时，未考虑到这一问题，存在缺陷 ) 。
