INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300358,3,'语句排序类','①有线耳机跟手机的关系是“山中只见藤缠树，世上哪见树缠藤”,无线耳机跟手机的关系则是“左右本是同林鸟，大难来时各自飞”
②也就是说，本来已经自成一个小宇宙的包，里面的复杂度、混乱度、神秘度又增添了一分
③有形之线永远剪不断、理还乱，耳机线可能听了太多故事，所以心有千千结，放在包里后再拿出来，哪怕只要五分钟，不知什么神奇力量已经把它缠绞成了一团
④但无线耳机并不比有线耳机的麻烦要少，因为它直接把物品变成三个
⑤无线耳机真的很方便，它永久免除了耳机线打成千奇百怪的结的危险，以及耳机线挂在各种障碍物上
⑥无线耳机取下来要放进专门的充电盒里，手头多一重麻烦，包里多一件小物
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"①⑤⑥③②④"},{"label":"B","content":"⑤③①⑥②④"},{"label":"C","content":"①⑥②④③⑤"},{"label":"D","content":"⑤③④①⑥②"}]','D','本题首句不好判断，可从④⑥入手，④句转折引出无线耳机有“麻烦”,⑥句具体介绍无线耳机的“麻烦”是什么,显然④在⑥前，锁定 D选项；
