INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300360,3,'标题拟定类','微藻是一类单细胞或多细胞的微小光合生物，一般利用太阳光能进行光合作用、生长繁殖。但也有一些种类能够利用葡萄糖等有机碳源进行高密度发酵生长，也就是异养生长。据估算，我国每年排放两千万吨氮氧化物，利用“异养生长”的微藻发酵技术将获得解决。工业尾气中的氮氧化物可以在适当条件下与水反应生成硝酸根、亚硝酸根，作为微藻异养生长所需要的氮营养。以往依靠太阳光能生产微藻，因占用大量土地难以用于工厂尾气处理，而利用微藻发酵则使单位面积生物量产率提高上千倍，从而有可能在厂区有限的面积进行生物脱硝。
最适合做这段文字标题的一项是：','[{"label":"A","content":"微藻科技：生物量产的催化剂"},{"label":"B","content":"微藻发酵技术：生物脱硝新路径"},{"label":"C","content":"生物脱硝：引领未来环保产业方向"},{"label":"D","content":"异养生长：微藻产业化的原动力"}]','B','文段分析见批注。
文段可视为前观点结构，观点句可翻译为：异养生长的微藻发酵技术可解决我国的氮氧化物问题，再根据下文分析论证可知，氮氧化物问题又可称为“生物脱硝”,所以文段观点可概括为“异养生长的微藻发酵技术能解决我国的生物脱硝问题”。对应B选项，当选。
其他选项：A选项、D选项未提及问题，C选项未提及解决方法，可简单排除。
