INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300361,3,'中心理解题','牛奶在浓缩干燥过程中要经过一次高温灭菌，冲兑之后还要再经过一次高温灭菌。由于复原乳经过两次高温处理，所以人们最大的担心就是“高温破坏了营养成分，导致营养严重流失”。实际上，
复原乳的营养价值损失并不大。首先，奶制品的主要优点在于提供钙和优质的蛋白质。钙作为一种无机盐，加热对它的含量多少是不会有影响的。可能有人会说，经过加热蛋白质会变性，其实即使不加热，我们吃进的蛋白质也要经过消化分解为氨基酸才能被人体吸收利用，所以加热变性不仅不会降低其营养价值，还有助于消化吸收。其次，加热确实会使复原乳损失一些维生素，但其损失程度比我们想象的要小得多。
通过这段文字，作者意在说明：','[{"label":"A","content":"消费者无需担心复原乳营养成分流失"},{"label":"B","content":"复原乳当中含有相当丰富的营养成分"},{"label":"C","content":"复原乳中的营养成分不易被高温破坏"},{"label":"D","content":"复原乳加热后更有利于人体消化吸收"}]','A','文段分析见批注。
文段先提出问题：“人们对于复原乳营养流失的担心”,再给出观点“复原乳的营养价值损失并不大”,最后对此观点进行分析论证，即作者意在表达“人们不需要担心复原乳营养流失”,对应 A选项②,当选；
B选项无中生有，文段并未对复原乳中的营养成分进行展开论述；C选项③、 D选项出处有误，均出自分析论证部分，非重点，均可排除。

花生批注：
① 行文结构：前观点结构。
转折前提出问题：
人们担心“高温破坏复原乳的营养成分，导致营养严重流失”;
再转折给出观点：
复原乳的营养价值损失并不大；最后针对观点进行分析论证： ①加热不会影响钙含量，加热还有助于蛋白质消化吸收；
②加热损失的维生素，比我们担心的小得多。
② 虽然A选项将“人们”变为“消费者”,但文段作者表达的“复原乳在生产环节营养损失不大”,可猜测其是对要购买牛奶或复原乳的消费者的说明，主体为“消费者”并无不妥(且原文主体确实为消费者);
另外，有同学可能会认为A选项缺少“高温”或“加热”这一高频词，但两次高温灭菌都是生产过程的一个环节，作者想表达的是“无须担心复原乳生产过程中的营养价值损失”,“消费者无需担心营养成分流失”与“消费者无需担心高温灭菌过程中营养成分流失”表达的主要意思不变。','2022年安徽省事业单位','挑战','published','{"globalNumber":361,"setNumber":19,"localNumber":1,"sourceLabel":"2022年安徽省事业单位35%","accuracy":35,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"牛奶在浓缩干燥过程中要经过一次高温灭菌，冲兑之后还要再经过一次高温灭菌。由于复原乳经过两次高温处理，所以人们最大的担心就是“高温破坏了营养成分，导致营养严重流失”。实际上，\n复原乳的营养价值损失并不大。首先，奶制品的主要优点在于提供钙和优质的蛋白质。钙作为一种无机盐，加热对它的含量多少是不会有影响的。可能有人会说，经过加热蛋白质会变性，其实即使不加热，我们吃进的蛋白质也要经过消化分解为氨基酸才能被人体吸收利用，所以加热变性不仅不会降低其营养价值，还有助于消化吸收。其次，加热确实会使复原乳损失一些维生素，但其损失程度比我们想象的要小得多。\n通过这段文字，作者意在说明："}],"optionRich":{"A":[{"text":"消费者无需担心复原乳营养成分流失"}],"B":[{"text":"复原乳当中含有相当丰富的营养成分"}],"C":[{"text":"复原乳中的营养成分不易被高温破坏"}],"D":[{"text":"复原乳加热后更有利于人体消化吸收"}]},"annotatedStemRich":[{"text":"牛奶在浓缩干燥过程中要经过一次高温灭菌，冲兑之后还要再经过一次高温灭菌。由于复原乳经过两次高温处理，所以人们最大的担心就是“高温破坏了营养成分，导致营养严重流失”。实际上，复原乳的营养价值损失并不大( 转折引出观点)。首先，奶制品的主要优点在于提供钙和优质的蛋白质。钙作为一种无机盐，加热对它的含量多少是不会有影响的。可能有人会说，经过加热蛋白质会变性，其实即使不加热，我们吃进的蛋白质也要经过消化分解为氨基酸才能被人体吸收利用，所以加热变性不仅不会降低其营养价值，还有助于消化吸收。其次，加热确实会使复原乳损失一些维生素，但其损失程度比我们想象的要小得多(分析论证)。①\n通过这段文字，作者意在说明："}],"annotatedOptionRich":{"A":[{"text":"消费者无需担心复原乳营养成分流失"}],"B":[{"text":"复原乳当中含有相当丰富的营养成分(无中生有)"}],"C":[{"text":"复原乳中的营养成分不易被高温破坏"},{"text":"(出处有误)","bold":true}],"D":[{"text":"复原乳加热后更有利于人体消化吸收"},{"text":"(出处有误)","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段先提出问题：“人们对于复原乳营养流失的担心”,再给出观点“复原乳的营养价值损失并不大”,最后对此观点进行分析论证，即作者意在表达“人们不需要担心复原乳营养流失”,对应 A选项②,当选；\nB选项无中生有，文段并未对复原乳中的营养成分进行展开论述；C选项③、 D选项出处有误，均出自分析论证部分，非重点，均可排除。","notes":[{"marker":"①","content":"行文结构：前观点结构。\n转折前提出问题：\n人们担心“高温破坏复原乳的营养成分，导致营养严重流失”;\n再转折给出观点：\n复原乳的营养价值损失并不大；最后针对观点进行分析论证： ①加热不会影响钙含量，加热还有助于蛋白质消化吸收；\n②加热损失的维生素，比我们担心的小得多。","matchScore":0.8552,"pairingMode":"marker-and-content","order":0},{"marker":"②","content":"虽然A选项将“人们”变为“消费者”,但文段作者表达的“复原乳在生产环节营养损失不大”,可猜测其是对要购买牛奶或复原乳的消费者的说明，主体为“消费者”并无不妥(且原文主体确实为消费者);\n另外，有同学可能会认为A选项缺少“高温”或“加热”这一高频词，但两次高温灭菌都是生产过程的一个环节，作者想表达的是“无须担心复原乳生产过程中的营养价值损失”,“消费者无需担心营养成分流失”与“消费者无需担心高温灭菌过程中营养成分流失”表达的主要意思不变。","matchScore":0.3566,"pairingMode":"marker-and-content","order":1}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300362,3,'中心理解题','专家认为，家庭氛围不和谐、缺少父母关爱是导致青少年出现心理精神问题，继而迷上网游的原因之一。家庭是孩子体验情感，发展情商的关键场所。如果家庭中不能给孩子提供需要的安全感、尊重、亲密与爱，孩子很有可能在网游中逃避恐惧和孤独，寻求安慰。忙于工作的父亲和爱批评唠叨的母亲往往“善于”制造这样的情感生态。如果一个充满冒险精神追求刺激的男孩过着单调和一成不变的生活时，网游世界自然显得精彩无限。
这段文字的主要观点是：','[{"label":"A","content":"应尽可能地保证孩子的情感供给"},{"label":"B","content":"情感缺位容易使孩子沉迷于网游"},{"label":"C","content":"亲子关系和谐可使孩子冷落网游"},{"label":"D","content":"应创造满足孩子个性的情感生态"}]','B','文段分析见批注。
文段开篇给出观点：家庭氛围不和谐、缺少父母关爱可能导致青少年出现心理精神问题，继而迷上网游；根据下文论证可知，“家庭氛围不和谐、缺少父母关爱”可概括为“情感缺位(忙于工作的父亲和爱批评唠叨的母亲容易制造这种情感生态)”,对应B选项，当选；
A选项、D选项未提及网游，C选项⑤是改变“沉迷网游”的措施，不如 B选项明确，排除。

花生批注：
④ 行文结构：总分结构。
开篇直接给出观点：
家庭情感缺失是导致青少年沉迷网游的原因之一；
后文为分析论证：
①家庭不能给孩子爱，孩子容易沉迷上网；
②忙于工作的父亲和爱批评唠叨的母亲容易制造这种家庭情感生态；
③生活单调、喜欢冒险刺激的男孩此时容易沉迷网络。
⑤ C选项可翻译为“和谐亲子关系使孩子冷落网游”,原文为“家庭情感”,选项偷换为“亲子关系”,缩小了范围，且原文仅论述“沉迷网游的原因是家庭情感的缺失”,若提对策应为“要避免家庭情感缺位使青少年沉迷网游”并非“沉迷网游后如何冷落”。
这段文字的主要观点是：
A. 应尽可能地保证孩子的情感供给(对策有误)
B. 情感缺位容易使孩子沉迷于网游
C. 亲子关系和谐可使孩子冷落网游(对策有误)
D. 应创造满足孩子个性的情感生态(对策有误)','2015年河南选调','基础','published','{"globalNumber":362,"setNumber":19,"localNumber":2,"sourceLabel":"2015年河南选调 77%","accuracy":77,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"专家认为，家庭氛围不和谐、缺少父母关爱是导致青少年出现心理精神问题，继而迷上网游的原因之一。家庭是孩子体验情感，发展情商的关键场所。如果家庭中不能给孩子提供需要的安全感、尊重、亲密与爱，孩子很有可能在网游中逃避恐惧和孤独，寻求安慰。忙于工作的父亲和爱批评唠叨的母亲往往“善于”制造这样的情感生态。如果一个充满冒险精神追求刺激的男孩过着单调和一成不变的生活时，网游世界自然显得精彩无限。\n这段文字的主要观点是："}],"optionRich":{"A":[{"text":"应尽可能地保证孩子的情感供给"}],"B":[{"text":"情感缺位容易使孩子沉迷于网游"}],"C":[{"text":"亲子关系和谐可使孩子冷落网游"}],"D":[{"text":"应创造满足孩子个性的情感生态"}]},"annotatedStemRich":[{"text":"专家认为，家庭氛围不和谐、缺少父母关爱是导致青少年出现心理精神问题，继而迷上网游的原因之一"},{"text":"(总观点)。","bold":true},{"text":"家庭是孩子体验情感，发展情商的关键场所。如果家庭中不能给孩子提供需要的安全感、尊重、亲密与爱，孩子很有可能在网游中逃避恐惧和孤独，寻求安慰。忙于工作的父亲和爱批评唠叨的母亲往往“善于”制造这样的情感生态。如果一个充满冒险精神追求刺激的男孩过着单调和一成不变的生活时，网游世界自然显得精彩无限"},{"text":"(分析论证)。④","bold":true},{"text":"\n这段文字的主要观点是："}],"annotatedOptionRich":{"A":[{"text":"应尽可能地保证孩子的情感供给"},{"text":"(对策有误)","bold":true}],"B":[{"text":"情感缺位容易使孩子沉迷于网游"}],"C":[{"text":"亲子关系和谐可使孩子冷落网游"},{"text":"(对策有误)","bold":true}],"D":[{"text":"应创造满足孩子个性的情感生态"},{"text":"(对策有误)","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段开篇给出观点：家庭氛围不和谐、缺少父母关爱可能导致青少年出现心理精神问题，继而迷上网游；根据下文论证可知，“家庭氛围不和谐、缺少父母关爱”可概括为“情感缺位(忙于工作的父亲和爱批评唠叨的母亲容易制造这种情感生态)”,对应B选项，当选；\nA选项、D选项未提及网游，C选项⑤是改变“沉迷网游”的措施，不如 B选项明确，排除。","notes":[{"marker":"④","content":"行文结构：总分结构。\n开篇直接给出观点：\n家庭情感缺失是导致青少年沉迷网游的原因之一；\n后文为分析论证：\n①家庭不能给孩子爱，孩子容易沉迷上网；\n②忙于工作的父亲和爱批评唠叨的母亲容易制造这种家庭情感生态；\n③生活单调、喜欢冒险刺激的男孩此时容易沉迷网络。","matchScore":0.841,"pairingMode":"marker-and-content","order":3},{"marker":"⑤","content":"C选项可翻译为“和谐亲子关系使孩子冷落网游”,原文为“家庭情感”,选项偷换为“亲子关系”,缩小了范围，且原文仅论述“沉迷网游的原因是家庭情感的缺失”,若提对策应为“要避免家庭情感缺位使青少年沉迷网游”并非“沉迷网游后如何冷落”。\n这段文字的主要观点是：\nA. 应尽可能地保证孩子的情感供给(对策有误)\nB. 情感缺位容易使孩子沉迷于网游\nC. 亲子关系和谐可使孩子冷落网游(对策有误)\nD. 应创造满足孩子个性的情感生态(对策有误)","matchScore":0.4105,"pairingMode":"marker-and-content","order":4}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300363,3,'标题拟定类','不久前，一个收获颇丰的考古队发现了一个来自伦敦泰晤士河泥泞河岸的玩具骑士。据悉，它已有 1300年左右的历史。这个玩具为我们展现了中世纪儿童童年的一些面貌。中世纪的人们和现在一样，有自己的文化。这个玩具骑士是使用模具批量生产而成。它可能流传于商人、店主、工匠、贵族和绅士家庭。
最适合做这段文字标题的是：','[{"label":"A","content":"玩具是了解中世纪儿童童年的一扇窗户"},{"label":"B","content":"中世纪父母对孩子的爱传承到今天"},{"label":"C","content":"中世纪玩具的起源"},{"label":"D","content":"中世纪玩具的考古价值\n片段阅读6 00 四(下册)"}]','D','文段分析见批注。
文段依次介绍了中世纪玩具骑士能够反映的历史信息，可理解为考古价值，对应D选项，当选；
A选项片面，仅对应“分1”部分；B选项“父母对孩子的爱”和C选项“起源”原文均未体现，可简单排除。

花生批注：
⑥ 中世纪玩具为全文论述主体。
⑦ 行文结构：大并列结构。
文段通过并列结构依次介绍该玩具能够反映的历史价值：
①展现中世纪儿童童年的面貌；
②反映当时文化；
③反映生产方式；
④可能的流传范围。','2021年黑龙江省公检法','进阶','published','{"globalNumber":363,"setNumber":19,"localNumber":3,"sourceLabel":"2021年黑龙江省公检法64%","accuracy":64,"typeAndPassage":"标题拟定类+科普介绍文章","stemRich":[{"text":"不久前，一个收获颇丰的考古队发现了一个来自伦敦泰晤士河泥泞河岸的玩具骑士。据悉，它已有 1300年左右的历史。这个玩具为我们展现了中世纪儿童童年的一些面貌。中世纪的人们和现在一样，有自己的文化。这个玩具骑士是使用模具批量生产而成。它可能流传于商人、店主、工匠、贵族和绅士家庭。\n最适合做这段文字标题的是："}],"optionRich":{"A":[{"text":"玩具是了解中世纪儿童童年的一扇窗户"}],"B":[{"text":"中世纪父母对孩子的爱传承到今天"}],"C":[{"text":"中世纪玩具的起源"}],"D":[{"text":"中世纪玩具的考古价值\n片段阅读6 00 四(下册)"}]},"annotatedStemRich":[{"text":"不久前，一个收获颇丰的考古队发现了一个"},{"text":"来自伦敦泰晤士河泥泞河岸的玩具骑士","underline":true},{"text":"⑥。据悉，它已有1300年左右的历史"},{"text":"(引出话题)。","bold":true},{"text":"这个玩具为我们展现了中世纪儿童童年的一些面貌("},{"text":"分","bold":true},{"text":" "},{"text":"1","bold":true},{"text":" "},{"text":")","bold":true},{"text":" "},{"text":"。","bold":true},{"text":"中世纪的人们和现在一样，有自己的文化( 分 2 ) 。这个玩具骑士是使用模具批量生产而成(分3)。它可能流传于商人、店主、工匠、贵族和绅士家庭"},{"text":"(分4)。⑦","bold":true},{"text":"\n最适合做这段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"玩具是了解中世纪儿童童年的一扇窗户("},{"text":"片面)","bold":true}],"B":[{"text":"中世纪父母对孩子的爱传承到今天("},{"text":"无中生有)","bold":true}],"C":[{"text":"中世纪玩具的起源"},{"text":"(无中生有)","bold":true}],"D":[{"text":"中世纪玩具的考古价值"}]},"practicalAnalysis":"文段分析见批注。\n文段依次介绍了中世纪玩具骑士能够反映的历史信息，可理解为考古价值，对应D选项，当选；\nA选项片面，仅对应“分1”部分；B选项“父母对孩子的爱”和C选项“起源”原文均未体现，可简单排除。","notes":[{"marker":"⑥","content":"中世纪玩具为全文论述主体。","matchScore":0.4953,"pairingMode":"marker-and-content","order":5},{"marker":"⑦","content":"行文结构：大并列结构。\n文段通过并列结构依次介绍该玩具能够反映的历史价值：\n①展现中世纪儿童童年的面貌；\n②反映当时文化；\n③反映生产方式；\n④可能的流传范围。","matchScore":0.5644,"pairingMode":"marker-and-content","order":6}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300364,3,'中心理解题','彩色摄影是饱含缤纷色彩的造型语言，黑白摄影是经典的、表达独特艺术思考的视觉化工具，它们之间不存在哪个更好、表现力更强的问题。无论是使用经验，还是作品所呈现的视觉效果，这两者都是完全不同的事物。今天的黑白摄影，即使不再是摄影艺术性和技术性的代表，也并不是什么过时的事物。黑白摄影仍具有自身独特的语言和能力，发挥着自己的特色，展现着新的可能，依然是解决、分析、阐述艺术问题的方法手段和需要研究探索的课题。
这段文字意在说明，黑白摄影：','[{"label":"A","content":"与彩色摄影不具有可比性"},{"label":"B","content":"在当今语境下仍有较高的艺术价值"},{"label":"C","content":"需要与时俱进不断发展"},{"label":"D","content":"自身具有独特的艺术评价标准"}]','B','文段分析见批注。
文段先通过对比彩色摄影和黑白摄影引出话题，后文介绍“今天的黑白摄影依然不过时，具有独特语言和能力，发挥自己特色，依然能解决艺术问题”; 重点为“今天的黑白摄影依然有用”,对应B选项，当选；
A选项本身有误，文段强调彩色摄影和黑白摄影不存在哪个更好的问题，而非黑白摄影“比不了”彩色摄影；而且，提及彩色摄影是为了引出黑白摄影，彩色摄影并非重点，排除；
C选项的对策⑩和D选项的“独特艺术评价标准”均无中生有，排除。

花生批注：
⑧ 黑白摄影是全文论述主体。
⑨ 行文结构：二层结构之背景 +正文。
先对比引出话题：
黑白摄影与彩色摄影是不同的，且各具意义；
之后都在介绍“今天的黑白摄影”。
⑩ 如果选C, 文段应当体现“黑白摄影守旧不创新”,但原文没有体现黑白摄影存在问题，所以不能给出“与时俱进”的对策。
片段阅读6 00','2021年山东省考','进阶','published','{"globalNumber":364,"setNumber":19,"localNumber":4,"sourceLabel":"2021年山东省考69%","accuracy":69,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"彩色摄影是饱含缤纷色彩的造型语言，黑白摄影是经典的、表达独特艺术思考的视觉化工具，它们之间不存在哪个更好、表现力更强的问题。无论是使用经验，还是作品所呈现的视觉效果，这两者都是完全不同的事物。今天的黑白摄影，即使不再是摄影艺术性和技术性的代表，也并不是什么过时的事物。黑白摄影仍具有自身独特的语言和能力，发挥着自己的特色，展现着新的可能，依然是解决、分析、阐述艺术问题的方法手段和需要研究探索的课题。\n这段文字意在说明，黑白摄影："}],"optionRich":{"A":[{"text":"与彩色摄影不具有可比性"}],"B":[{"text":"在当今语境下仍有较高的艺术价值"}],"C":[{"text":"需要与时俱进不断发展"}],"D":[{"text":"自身具有独特的艺术评价标准"}]},"annotatedStemRich":[{"text":"彩色摄影是饱含缤纷色彩的造型语言，黑白摄影是经典的、表达独特艺术思考的视觉化工具，它们之间不存在哪个更好、表现力更强的问题。无论是使用经验，还是作品所呈现的视觉效果，这两者都是完全不同的事物(对比引出话题)。"},{"text":"今天的黑白摄影","underline":true},{"text":"⑧,即使不再是摄影艺术性和技术性的代表，也并不是什么过时的事物。黑白摄影仍具有自身独特的语言和能力，发挥着自己的特色，展现着新的可能，依然是解决、分析、阐述艺术问题的方法手段和需要研\n究探索的课题(介绍黑白摄影)。⑨\n这段文字意在说明，黑白摄影："}],"annotatedOptionRich":{"A":[{"text":"与彩色摄影不具有可比性(本身有误)"}],"B":[{"text":"在当今语境下仍有较高的艺术价值"}],"C":[{"text":"需要与时俱进不断发展(无中生有)"}],"D":[{"text":"自身具有独特的艺术评价标准(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段先通过对比彩色摄影和黑白摄影引出话题，后文介绍“今天的黑白摄影依然不过时，具有独特语言和能力，发挥自己特色，依然能解决艺术问题”; 重点为“今天的黑白摄影依然有用”,对应B选项，当选；\nA选项本身有误，文段强调彩色摄影和黑白摄影不存在哪个更好的问题，而非黑白摄影“比不了”彩色摄影；而且，提及彩色摄影是为了引出黑白摄影，彩色摄影并非重点，排除；\nC选项的对策⑩和D选项的“独特艺术评价标准”均无中生有，排除。","notes":[{"marker":"⑧","content":"黑白摄影是全文论述主体。","matchScore":0.4297,"pairingMode":"marker-and-content","order":7},{"marker":"⑨","content":"行文结构：二层结构之背景 +正文。\n先对比引出话题：\n黑白摄影与彩色摄影是不同的，且各具意义；\n之后都在介绍“今天的黑白摄影”。","matchScore":0.4773,"pairingMode":"marker-and-content","order":8},{"marker":"⑩","content":"如果选C, 文段应当体现“黑白摄影守旧不创新”,但原文没有体现黑白摄影存在问题，所以不能给出“与时俱进”的对策。\n片段阅读6 00","matchScore":0.2282,"pairingMode":"marker-and-content","order":9}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300365,3,'中心理解题','企业、媒体等出于利益考量，传递出一些物质主义的消费理念，使部分人过分追求消费水平的提升，忽视了对自身债务负担及环境资源保护的重视，这类现象应当引起关注。一方面，我们处于经济转型期，国家呼吁刺激消费拉动内需，人们随着生活水平的提高也有消费升级的需求；但另一方面，传统文化推崇节俭节约，反对物欲横流。事实上，国家鼓励消费并不是鼓励浪费，也是希望在改善人民物质生活水平与环境资源可持续利用之间实现平衡，引导居民把握收入水平与消费水平之间的平衡。
这段文字针对的主要问题是：','[{"label":"A","content":"过度消费对环境的破坏"},{"label":"B","content":"消费者的盲目消费倾向"},{"label":"C","content":"商家对消费理念的误导"},{"label":"D","content":"传统的节俭观念被淡忘"}]','B','文段分析见批注。
文段问法为“文段针对的主要问题”,开篇即指出问题：部分消费者不顾自身债务和环境资源保护而过度追求消费；B选项是该问题的同义替换，当选；
A选项未提及“忽视自身债务”,且问题重点是“过度消费”,而非“过度消费对环境的破坏”,排除； C选项主体为商家，但根据后文观点可知，问题的重点是“消费者过度消费” ,而非“商家对消费理念的引导”②,排除； D选项的“传统节俭观点”无中生有，排除。

花生批注：
⑪ 行文结构：后观点结构。
先提出问题并分析：
商家传递物质主义的消费理念导致部分人盲目消费，忽视自身债务和环境资源保护；
后给出观点：
国家鼓励消费并不是鼓励浪费。
⑫ 若C选项是正确答案，后文分析和观点部分应该体现怎样通过行政或者调控等手段约束商家的行为；
但是原文强调的是消费者要节俭和节约，不能浪费；
所以C选项问题的主体有误，排除。','2019年四川省考','进阶','published','{"globalNumber":365,"setNumber":19,"localNumber":5,"sourceLabel":"2019年四川省考63%","accuracy":63,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"企业、媒体等出于利益考量，传递出一些物质主义的消费理念，使部分人过分追求消费水平的提升，忽视了对自身债务负担及环境资源保护的重视，这类现象应当引起关注。一方面，我们处于经济转型期，国家呼吁刺激消费拉动内需，人们随着生活水平的提高也有消费升级的需求；但另一方面，传统文化推崇节俭节约，反对物欲横流。事实上，国家鼓励消费并不是鼓励浪费，也是希望在改善人民物质生活水平与环境资源可持续利用之间实现平衡，引导居民把握收入水平与消费水平之间的平衡。\n这段文字针对的主要问题是："}],"optionRich":{"A":[{"text":"过度消费对环境的破坏"}],"B":[{"text":"消费者的盲目消费倾向"}],"C":[{"text":"商家对消费理念的误导"}],"D":[{"text":"传统的节俭观念被淡忘"}]},"annotatedStemRich":[{"text":"企业、媒体等出于利益考量，传递出一些物质主义的消费理念，使部分人过分追求消费水平的提升，忽视了对自身债务负担及环境资源保护的重视，这类现象应当引起关注。一方面，我们处于经济转型期，国家呼吁刺激消费拉动内需，人们随着生活水平的提高也有消费升级的需求；但另一方面，传统文化推崇节俭节约，反对物欲横流(提出问题)。事实上，国家鼓励消费并不是鼓励浪费，也是希望在改善人民物质生活水平与环境资源可持续利用之间实现平衡，引导居民把握收入水平与消费水平之间的平衡(提出观点)。①\n这段文字针对的主要问题是："}],"annotatedOptionRich":{"A":[{"text":"过度消费对环境的破坏(片面)"}],"B":[{"text":"消费者的盲目消费倾向"}],"C":[{"text":"商家对消费理念的误导"}],"D":[{"text":"传统的节俭观念被淡忘(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段问法为“文段针对的主要问题”,开篇即指出问题：部分消费者不顾自身债务和环境资源保护而过度追求消费；B选项是该问题的同义替换，当选；\nA选项未提及“忽视自身债务”,且问题重点是“过度消费”,而非“过度消费对环境的破坏”,排除； C选项主体为商家，但根据后文观点可知，问题的重点是“消费者过度消费” ,而非“商家对消费理念的引导”②,排除； D选项的“传统节俭观点”无中生有，排除。","notes":[{"marker":"⑪","content":"行文结构：后观点结构。\n先提出问题并分析：\n商家传递物质主义的消费理念导致部分人盲目消费，忽视自身债务和环境资源保护；\n后给出观点：\n国家鼓励消费并不是鼓励浪费。","matchScore":0.7517,"pairingMode":"content-similarity","order":10},{"marker":"⑫","content":"若C选项是正确答案，后文分析和观点部分应该体现怎样通过行政或者调控等手段约束商家的行为；\n但是原文强调的是消费者要节俭和节约，不能浪费；\n所以C选项问题的主体有误，排除。","matchScore":0.318,"pairingMode":"content-similarity","order":11}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300366,3,'中心理解题','戏曲之舞追求气韵生动、兴味蕴藉，独立成章的舞段虽不多，却有极为完善的审美规范，体现为众多程式技巧，有相应的评判标准，也就是人们常说的“规矩”。当我们想把某种舞蹈引入戏曲时，首先应考虑这种舞蹈于戏曲是否合适。曾有人用舞剧《丝路花雨》的舞姿造型改造京剧《天女散花》, 好像很贴近主题，不想天女的轻盈飘逸之态尽失，反显笨拙。从石窟壁画复原的“敦煌舞”在身形、力量、技巧方面的要求，均与戏曲之舞不同，当后者的“拧、倾、圆、曲”被替换为“双手平托、出胯冲身成三道弯”的基本体态时，戏曲的味道也就荡然无存了。
这段文字意在说明：','[{"label":"A","content":"不是所有舞蹈类型都适合戏曲"},{"label":"B","content":"过多的舞蹈会破坏戏曲的韵味"},{"label":"C","content":"引入戏曲的舞蹈应该符合戏曲的审美特质"},{"label":"D","content":"“规矩”是戏曲之舞与其他舞蹈融合的鸿沟"}]','C','文段分析见批注。
文段为典型的前观点结构，文章观点为“某种舞蹈引入戏曲应考虑是否合适” ,C选项可翻译为“某种舞蹈引入戏曲应考虑是否符合戏曲的审美特点”, 是文段观点的同义替换，当选；
A选项为“不是……而是……”的“不是 ·……”部分，出处有误；B选项、 D选项均为问题表述，可简单排除。

花生批注：
⑬ 行文结构：前观点结构。
首句引出话题：“戏曲之舞的规矩”;
之后祈使句给出观点：
某种舞蹈引入戏曲应考虑是否合适；
之后进行举例论证。
(下册)','2021年四川省考','基础','published','{"globalNumber":366,"setNumber":19,"localNumber":6,"sourceLabel":"2021年四川省考 72%","accuracy":72,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"戏曲之舞追求气韵生动、兴味蕴藉，独立成章的舞段虽不多，却有极为完善的审美规范，体现为众多程式技巧，有相应的评判标准，也就是人们常说的“规矩”。当我们想把某种舞蹈引入戏曲时，首先应考虑这种舞蹈于戏曲是否合适。曾有人用舞剧《丝路花雨》的舞姿造型改造京剧《天女散花》, 好像很贴近主题，不想天女的轻盈飘逸之态尽失，反显笨拙。从石窟壁画复原的“敦煌舞”在身形、力量、技巧方面的要求，均与戏曲之舞不同，当后者的“拧、倾、圆、曲”被替换为“双手平托、出胯冲身成三道弯”的基本体态时，戏曲的味道也就荡然无存了。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"不是所有舞蹈类型都适合戏曲"}],"B":[{"text":"过多的舞蹈会破坏戏曲的韵味"}],"C":[{"text":"引入戏曲的舞蹈应该符合戏曲的审美特质"}],"D":[{"text":"“规矩”是戏曲之舞与其他舞蹈融合的鸿沟"}]},"annotatedStemRich":[{"text":"戏曲之舞追求气韵生动、兴味蕴藉，独立成章的舞段虽不多，却有极为完善的审美规范，体现为众多程式技巧，有相应的评判标准，也就是人们常说的“规矩”"},{"text":"(背景介绍引出话题)。","bold":true},{"text":"当我们想把某种舞蹈引入戏曲时，首先应考虑这种舞蹈于戏曲是否合适"},{"text":"(前观点)。","bold":true},{"text":"曾有人用舞剧《丝路花雨》的舞姿造型改造京剧《天女散花》,好像很贴近主题，不想天女的轻盈飘逸之态尽失，反显笨拙。从石窟壁画复原的“敦煌舞”在身形、力量、技巧方面的要求，均与戏曲之舞不同，当后者的“拧、倾、圆、曲”被替换为“双手平托、出胯冲身成三道弯”的基本体态时，戏曲的味道也就荡然无存了"},{"text":"(举例分析论证)。⑪","bold":true},{"text":"\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"不是所有舞蹈类型都适合戏曲(出处有误)"}],"B":[{"text":"过多的舞蹈会破坏戏曲的韵味(问题表述)"}],"C":[{"text":"引入戏曲的舞蹈应该符合戏曲的审美特质"}],"D":[{"text":"“规矩”是戏曲之舞与其他舞蹈融合的鸿沟"},{"text":"(问题表述)","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段为典型的前观点结构，文章观点为“某种舞蹈引入戏曲应考虑是否合适” ,C选项可翻译为“某种舞蹈引入戏曲应考虑是否符合戏曲的审美特点”, 是文段观点的同义替换，当选；\nA选项为“不是……而是……”的“不是 ·……”部分，出处有误；B选项、 D选项均为问题表述，可简单排除。","notes":[{"marker":"⑬","content":"行文结构：前观点结构。\n首句引出话题：“戏曲之舞的规矩”;\n之后祈使句给出观点：\n某种舞蹈引入戏曲应考虑是否合适；\n之后进行举例论证。\n(下册)","matchScore":0.608,"pairingMode":"content-similarity","order":12}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300367,3,'中心理解题','2018年，国家大幅上调了科学技术奖的奖金标准，最高奖奖金由此前的500万元/人上调至800万元/人，且全部由获奖者个人支配。在人们的印象里，科研工作者的形象似乎总是与清苦绑定在一起，科研中个人智力劳动的价值，常常被有意无意地轻视。事实上，没有科研工作者的个人努力与智慧，再多的投入，也不能确保取得相应的产出。因此，不论是国家、社会还是科研机构，都该为他们的努力提供回报。这也传达出一个信号，国家尊重科研工作中个人的价值，或者说，只要能取得相应的成就，科研工作者就完全可以堂堂正正地过上富裕、优渥的生活。也只有这样，科研事业才能有源源不断的新鲜血液注入，进而变得更加繁荣、昌盛。这一文段的主要意思是：','[{"label":"A","content":"国家大幅上调了科学技术奖的奖金标准"},{"label":"B","content":"要加大对科研中个人智力劳动的奖励"},{"label":"C","content":"科研工作者配得上这样的奖励"},{"label":"D","content":"科研工作者的清苦生活已在改变"}]','C','文段分析见批注。
文段先介绍了一个新闻事件：国家大幅上调科研奖金；之后作者通过分析论证表达了观点(对这一改变的肯定):这一变化体现国家对科研工作个人价值的尊重并且有助于科研事业发展； C选项体现了作者态度，当选；
B选项为对策表述，但“要加大奖励”无中生有⑮;文段是对“国家大幅上调科学奖金”的分析与评价，而非认为“要继续加大奖励力度”,排除；
A选项只提及这一新闻事件，但未体现作者观点，排除； D选项既未体现这一新闻，也未体现作者态度，排除。

花生批注：
⑭ 行文结构：二层结构。
开篇介绍新闻事件：
国家大幅上调科研奖金标准且由个人支配；
之后进行分析说明：
①以往科研总与清贫绑定，科研价值被轻视；
②但事实上，科研工作者的努力非常重要；
③国家上调科研奖金说明国家尊重科研工作者的个人价值；
④这种尊重会让科研事业更加繁荣昌盛。
⑮ 若选择B选项，原文应体现“现在奖金依然不足”这一问题。','2020年上海市考','进阶','published','{"globalNumber":367,"setNumber":19,"localNumber":7,"sourceLabel":"2020年上海市考58%","accuracy":58,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"2018年，国家大幅上调了科学技术奖的奖金标准，最高奖奖金由此前的500万元/人上调至800万元/人，且全部由获奖者个人支配。在人们的印象里，科研工作者的形象似乎总是与清苦绑定在一起，科研中个人智力劳动的价值，常常被有意无意地轻视。事实上，没有科研工作者的个人努力与智慧，再多的投入，也不能确保取得相应的产出。因此，不论是国家、社会还是科研机构，都该为他们的努力提供回报。这也传达出一个信号，国家尊重科研工作中个人的价值，或者说，只要能取得相应的成就，科研工作者就完全可"},{"text":"以堂堂正","underline":true},{"text":"正地过上富裕、优渥的生活。也只有这样，科研事业才能有源源不断的新鲜血液注入，进而变得更加繁荣、昌盛。这一文段的主要意思是："}],"optionRich":{"A":[{"text":"国家大幅上调了科学技术奖的奖金标准"}],"B":[{"text":"要加大对科研中个人智力劳动的奖励"}],"C":[{"text":"科研工作者配得上这样的奖励"}],"D":[{"text":"科研工作者的清苦生活已在改变"}]},"annotatedStemRich":[{"text":"2018年，国家大幅上调了科学技术奖的奖金标准，最高奖奖金由此前的 500万元/人上调至800万元/人，且全部由获奖者个人支配(新闻事件)。在人们的印象里，科研工作者的形象似乎总是与清苦绑定在一起，科研中个人智力劳动的价值，常常被有意无意地轻视。事实上，没有科研工作者的个人努力与智慧，再多的投入，也不能确保取得相应的产出。因此，不论是国家、社会还是科研机构，都该为他们的努力提供回报。这也传达出一个信号，国家尊重科研工作中个人的价值，或者说，只要能取得相应的成就，科研工作者就完全可以堂堂正正地过上富裕、优渥的生活。也只有这样，科研事业才能有源源\n不断的新鲜血液注入，进而变得更加繁荣、昌盛(分析说明)。⑨ 这一文段的主要意思是："}],"annotatedOptionRich":{"A":[{"text":"国家大幅上调了科学技术奖的奖金标准(出处有误)"}],"B":[{"text":"要加大对科研中个人智力劳动的奖励(对策有误)"}],"C":[{"text":"科研工作者配得上这样的奖励"}],"D":[{"text":"科研工作者的清苦生活已在改变(本身有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍了一个新闻事件：国家大幅上调科研奖金；之后作者通过分析论证表达了观点(对这一改变的肯定):这一变化体现国家对科研工作个人价值的尊重并且有助于科研事业发展； C选项体现了作者态度，当选；\nB选项为对策表述，但“要加大奖励”无中生有⑮;文段是对“国家大幅上调科学奖金”的分析与评价，而非认为“要继续加大奖励力度”,排除；\nA选项只提及这一新闻事件，但未体现作者观点，排除； D选项既未体现这一新闻，也未体现作者态度，排除。","notes":[{"marker":"⑭","content":"行文结构：二层结构。\n开篇介绍新闻事件：\n国家大幅上调科研奖金标准且由个人支配；\n之后进行分析说明：\n①以往科研总与清贫绑定，科研价值被轻视；\n②但事实上，科研工作者的努力非常重要；\n③国家上调科研奖金说明国家尊重科研工作者的个人价值；\n④这种尊重会让科研事业更加繁荣昌盛。","matchScore":0.6439,"pairingMode":"content-similarity","order":13},{"marker":"⑮","content":"若选择B选项，原文应体现“现在奖金依然不足”这一问题。","matchScore":0.2634,"pairingMode":"marker-and-content","order":14}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300368,3,'中心理解题','文学走进互联网，获得了一个崭新的平民化开放视野；网络上自由、兼容和共享的虚拟空间，打破了精英写作对文学话语权的垄断，为愿意上网创作的网民提供了“人人都能当作家”的机会。这种“新民间文学”,标志着文学话语权向民间回归。尽管如此，网络写作仍然不能与“人民写作”相提并论，因为文学的“人民写作”并不取决于传媒的公共性和参与的广泛性，而取决于这种文学的人民性价值取向和为广大民众喜闻乐见的审美品格。
这段文字主要说的是：','[{"label":"A","content":"大众化是未来文学发展的趋势"},{"label":"B","content":"文学创作应坚持人民性的价值取向"},{"label":"C","content":"网络写作为普通人提供了平等的话语权"},{"label":"D","content":"平民化的网络文学不能等同于“人民写作”"}]','D','文段分析见批注。
文段为典型的前对策结构，转折后提出观点：“网络写作仍然不能与‘人民写作’相提并论”,对应D选项，当选；
A选项为下定义的中性表达，未体现观点， B选项“人民性的价值取向”出自最后解释说明部分，C选项出自背景介绍部分，均可简单排除。

