INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300371,3,'下文推断类②','近日，我国2000吨地沟油加工成的生物煤油被荷兰航空公司买走的报道震撼了国民：地沟油还有这么高端的用途!原来，经过特殊技术加工后的地沟油可以作为一种生物煤油来替代传统的柴油和汽油，用于航空飞行。事实上，不只是荷兰，欧美很多国家近些年来都在寻找妥善处理餐厨余油的办法。通过严格的国家立法和执法、先进的技术投入以及人们日益提高的环保意识和健康觉悟，餐厨余油经过回收、加工后流进了工矿、发电厂，甚至是家庭的汽车油箱，成为真正的可再生清洁能源，继续造福人类。
如果这是一篇文章的引言，这篇文章的内容最有可能是：','[{"label":"A","content":"世界各国都致力于研究地沟油的回收利用"},{"label":"B","content":"设立完整的处理地沟油的方法以造福民生"},{"label":"C","content":"地沟油已经成为真正的可再生清洁能源"},{"label":"D","content":"我国餐厨余油的加工生产前景广阔"}]','B','文段强调地沟油可以成为可再生的清洁能源，并给出了宏观对策，但具体地沟油怎样变废为宝，需要采取哪些技术和行政手段，引言中没体现；B选项的“设立完整的处理地沟油的方法”即是对策的具体展开，“以造福民生”是这样做的意义与价值，最有可能是文章的内容，当选；
A选项，引言中只提到了欧美很多国家在寻找利用地沟油的方法，不是“世界各国”,排除；C选项“已经成为”时态有误，排除；D选项，“加工生产”是引言中给出的宏观对策，目前还未进行，“前景广阔”无从谈起，排除。
那么这篇文章的引言部分应简单介绍我国餐厨余油加工生产的规模以及如何受市场欢迎，但原文只介绍了我国地沟油加工成的生物煤油被荷兰公司买走，由此推出“前景广阔”并不合适。','2013年广东省考','挑战','published','{"globalNumber":371,"setNumber":19,"localNumber":11,"sourceLabel":"2013年广东省考40%","accuracy":40,"typeAndPassage":"下文推断类②+宏观对策 → 下文具体展开","stemRich":[{"text":"近日，我国2000吨地沟油加工成的生物煤油被荷兰航空公司买走的报道震撼了国民：地沟油还有这么高端的用途!原来，经过特殊技术加工后的地沟油可以作为一种生物煤油来替代传统的柴油和汽油，用于航空飞行。事实上，不只是荷兰，欧美很多国家近些年来都在寻找妥善处理餐厨余油的办法。通过严格的国家立法和执法、先进的技术投入以及人们日益提高的环保意识和健康觉悟，餐厨余油经过回收、加工后流进了工矿、发电厂，甚至是家庭的汽车油箱，成为真正的可再生清洁能源，继续造福人类。\n如果这是一篇文章的引言，这篇文章的内容最有可能是："}],"optionRich":{"A":[{"text":"世界各国都致力于研究地沟油的回收利用"}],"B":[{"text":"设立完整的处理地沟油的方法以造福民生"}],"C":[{"text":"地沟油已经成为真正的可再生清洁能源"}],"D":[{"text":"我国餐厨余油的加工生产前景广阔"}]},"annotatedStemRich":[{"text":"近日，我国2000吨地沟油加工成的生物煤油被荷兰航空公司买走的报道震撼了国民：地沟油还有这么高端的用途!原来，经过特殊技术加工后的地沟油可以作为一种生物煤油来替代传统的柴油和汽油，用于航空飞行。事实上，不只是荷兰，欧美很多国家近些年来都在寻找妥善处理餐厨余油的办法"},{"text":"(引出话题)。","bold":true},{"text":"通过严格的国家立法和执法、先进的技术投入以及人们日益提高的环保意识和健康觉悟，餐厨余油经过回收、加工后流进了工矿、发电厂，甚至是家庭的汽车油箱，\n成为真正的可再生清洁能源，继续造福人类"},{"text":"(提出宏观对策)。②","bold":true},{"text":"\n如果这是一篇文章的引言，这篇文章的内容最有可能是："}],"annotatedOptionRich":{"A":[{"text":"世界各国都致力于研究地沟油的回收利用 "},{"text":"(无中生有)","bold":true}],"B":[{"text":"设立完整的处理地沟油的方法以造福民生"}],"C":[{"text":"地沟油已经成为真正的可再生清洁能源"},{"text":"(时态有误)","bold":true}],"D":[{"text":"我国餐厨余油的加工生产前景广阔"}]},"practicalAnalysis":"文段强调地沟油可以成为可再生的清洁能源，并给出了宏观对策，但具体地沟油怎样变废为宝，需要采取哪些技术和行政手段，引言中没体现；B选项的“设立完整的处理地沟油的方法”即是对策的具体展开，“以造福民生”是这样做的意义与价值，最有可能是文章的内容，当选；\nA选项，引言中只提到了欧美很多国家在寻找利用地沟油的方法，不是“世界各国”,排除；C选项“已经成为”时态有误，排除；D选项，“加工生产”是引言中给出的宏观对策，目前还未进行，“前景广阔”无从谈起，排除。\n那么这篇文章的引言部分应简单介绍我国餐厨余油加工生产的规模以及如何受市场欢迎，但原文只介绍了我国地沟油加工成的生物煤油被荷兰公司买走，由此推出“前景广阔”并不合适。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300372,3,'下文推断类②','碳酸铅为无机化合物，它以白铅矿的形式存在于自然界中。像碳酸铅这样的无机样本很难直接进行年代测定。这是因为，自然界中的碳元素主要有3种同位素，其中碳14为天然放射性同位素，碳测年法就是利用生物体死亡后体内碳14含量随时间减少的规律进行年代测定的技术，主要用于测定生物物质，例如动植物遗骸，也可以测定藏品中木器、竹器、牙骨器、纸张、纺织物等含碳有机物的年代。虽然碳酸铅含有放射性碳，可惜长期以来，科学家一直没能找到直接测定碳酸铅年代的方法。接下来最可能说的是：','[{"label":"A","content":"测定碳酸铅年代的新方法"},{"label":"B","content":"碳测年法的优势和弊端"},{"label":"C","content":"碳酸铅和考古的关系"},{"label":"D","content":"碳测年法的技术原理"}]','A','文段先介绍碳酸铅很难直接进行年代测定并解释原因；尾句介绍过去一直没找到直接测定碳酸铅年代的方法；
典型的时间对比结构，先介绍“过去的不足”,下文补充“现在的突破”, 下文应介绍测定碳酸铅年代的新方法，直接定位到A选项；
B选项和D选项均未提及主题词“碳酸铅”⑤,排除；C选项原文只提到了可以借助碳的同位素测定含碳有机物的年代，没提到碳酸铅与考古的关系，无中生有，排除。

花生批注：
④ 下文推断的常见结构：','2022年天津市考','基础','published','{"globalNumber":372,"setNumber":19,"localNumber":12,"sourceLabel":"2022年天津市考 72%","accuracy":72,"typeAndPassage":"下文推断类②+过去不行→现在的新突破","stemRich":[{"text":"碳酸铅为无机化合物，它以白铅矿的形式存在于自然界中。像碳酸铅这样的无机样本很难直接进行年代测定。这是因为，自然界中的碳元素主要有3种同位素，其中碳14为天然放射性同位素，碳测年法就是利用生物体死亡后体内碳14含量随时间减少的规律进行年代测定的技术，主要用于测定生物物质，例如动植物遗骸，也可以测定藏品中木器、竹器、牙骨器、纸张、纺织物等含碳有机物的年代。虽然碳酸铅含有放射性碳，可惜长期以来，科学家一直没能找到直接测定碳酸铅年代的方法。接下来最可能说的是："}],"optionRich":{"A":[{"text":"测定碳酸铅年代的新方法"}],"B":[{"text":"碳测年法的优势和弊端"}],"C":[{"text":"碳酸铅和考古的关系"}],"D":[{"text":"碳测年法的技术原理"}]},"annotatedStemRich":[{"text":"碳酸铅为无机化合物，它以白铅矿的形式存在于自然界中。像碳酸铅这样的无机样本很难直接进行年代测定。这是因为，自然界中的碳元素主要有3种同位素，其中碳14为天然放射性同位素，碳测年法就是利用生物体死亡后体内碳 14含量随时间减少的规律进行年代测定的技术，主要用于测定生物物质，例如动植物遗骸，也可以测定藏品中木器、竹器、牙骨器、纸张、纺织物等含碳有机物的年代"},{"text":"(背景知识介绍)。","bold":true},{"text":"虽然碳酸铅含有放射性碳，可惜长期以来，科学家一直没能找到直接测定碳酸铅年代的方法("},{"text":"过去没找到测定碳酸铅年代的方法)。","bold":true},{"text":"\n接下来最可能说的是："}],"annotatedOptionRich":{"A":[{"text":"测定碳酸铅年代的新方法"}],"B":[{"text":"碳测年法的优势和弊端"}],"C":[{"text":"碳酸铅和考古的关系"}],"D":[{"text":"碳测年法的技术原理"}]},"practicalAnalysis":"文段先介绍碳酸铅很难直接进行年代测定并解释原因；尾句介绍过去一直没找到直接测定碳酸铅年代的方法；\n典型的时间对比结构，先介绍“过去的不足”,下文补充“现在的突破”, 下文应介绍测定碳酸铅年代的新方法，直接定位到A选项；\nB选项和D选项均未提及主题词“碳酸铅”⑤,排除；C选项原文只提到了可以借助碳的同位素测定含碳有机物的年代，没提到碳酸铅与考古的关系，无中生有，排除。","notes":[{"marker":"④","content":"下文推断的常见结构：","matchScore":0.516,"pairingMode":"content-similarity","order":22}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300373,3,'语句填入类','农民卖粮舒心，源于市场之“手”用得好。2020年的夏粮生产，不仅数量增加，质量也在提升。一个重要指标就是专用麦比例高，全国优质强筋弱筋小麦面积占比35.8%,比上年提高2.8 个百分点。从目前收购市场情况看，每斤优质小麦要比普通品种高出0.1元左右。这背后，。如今，多元化市场主体入市收购，既让丰收粮有了更加多样化的销售渠道，也让优质粮食品种销路更好、价格更高，优粮优价成为种粮农民增收的“金钥匙”。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"说到底就是稳住这些农民的种粮收益，保护农民的种粮积极性"},{"label":"B","content":"正是粮食收储制度改革持续推进，市场机制作用得到更好发挥"},{"label":"C","content":"全国农户构成了粮食安全的坚强基石，稳住粮食生产的好形势"},{"label":"D","content":"通过优化供给体系，拓展粮食产加销增值空间，分享增值收益"}]','B','文段开篇给出观点：农民卖粮舒心( M), 源于“市场之手” (N) 。下文应该展开介绍为什么“市场之手”让农民卖粮舒心：“2020年的夏粮生产，……。从目前收购市场情况看，每斤优质小麦要比普通品种高出0.1 元左右”对应“农民卖粮舒心( M)”; “这背后”引出“卖得好”的原因，
对应“源于市场之‘手’用得好( N)”, 只有B选项提及“市场”,当选；其他选项均未提及“市场”,可简单排除。
片段阅读6 00

花生批注：
③ 若选择C选项，原文就成为了科普介绍文章，但文段先提出“一个担心”,并给出观点“实际上，无需担心”,并加以解释，综上，“无需担心”更可能是作者想传达给读者的信息，应在正确选项中有所体现。
片段阅读6 0 0 (下册)
2 下文推断的常见结构：
①上文文末提出新内容→下文解释新内容
②上文提出问题→下文分析问题、解决问题
③上文给出宏观对策、原因等→下文具体展开
④时间对比：过去不行→现在有了新突破
⑤总分：上文是总+分→下文补充另一“分”
⑥转折
5 同学们要注意，“碳测年法”与测定碳酸铅年代的方法不是同一方法。
B选项和D选项的主语是“碳测年法”,出自背景知识部分，非重点。
⑥ 后文继续解释说明“市场为何让农民卖粮舒心”:
市场，让粮食有了更加多样化的销售渠道，也让粮食销路更好价格更好，让农民增收。
填入文中画横线部分最恰当的一项是：
A. 说到底就是稳住这些农民的种粮收益，保护农民的种粮积极性
B. 正是粮食收储制度改革持续推进，市场机制作用得到更好发挥
