INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300374,3,'语句填入类','研究发现，地震前岩石中氡值会有明显变化，就此可对地壳活动作出研判。氡观测是国际上普遍认可的地震监测手段之一，氡值是我国地震观测台网中最重要的测项之一。地震行业氡观测仪主要采用固体氡源进行校准，但固体氡源属于受国家严格监管的放射类源，由于存在运输不便等问题，氡观测仪无法实现全国统一校准。由于监测仪器标准不统一，A地区测出的氡气含量100Bq/L 可能跟B地区测出的50Bq/L 是一回事。这样的话，测出的数据就没有意义。因此， o
