INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300375,3,'语句填入类','从概念上讲，数字经济是指人们通过大数据的“识别一选择一过滤—存储一使用”,引导资源快速优化配置与再生，进而实现经济高质量发展的经济形态。从技术层面的大数据、物联网、云计算、区块链，到应用层面的数字金融、新零售、智慧城市等，都属于数字经济的范畴，近年来，我国数字经济快速发展，取得丰硕成果，特别是在当前经济下行压力加大的背景下，数字经济仍然保持强劲的增长势头。有统计显示，2018年数字经济对GDP 增长贡献率达到67.9%,同比增长12.9%。这充分说明，数字经济已经
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"在引导资源快速优化配置与再生中发挥关键作用"},{"label":"B","content":"成为带动经济增长、推动高质量发展的重要引擎"},{"label":"C","content":"在我国当前的经济结构中占有越来越重要的位置"},{"label":"D","content":"成为当前经济下行背景下带动GDP 增长的主力军"}]','B','文段结构见批注。
