INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300377,3,'语句排序类','①学会做家务是最生活化的教育，也是生活所必需的教育
②家务劳动是最好的生活教育
③“童孙未解供耕织，也傍桑阴学种后”,中国古代家庭教育中孩子事农、做家务的生动情景，成为现代生活中遥远的想象
④然而在唯成绩论的家庭中，以学习之名被弱化的家务劳动仍然是孩子的生活盲区
⑤家务劳动是最适合孩子的生活实践，是孩子回归生活本真、发现生活乐趣、历练生活能力的“家本课程”
⑥家长如果主动屏蔽掉孩子的家务劳动，其实也屏藏了孩子与生活建立感性、和谐和深刻联系的实践机会将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"⑤⑥③②①④"},{"label":"B","content":"⑤⑥④②①③"},{"label":"C","content":"②①③④⑤⑥"},{"label":"D","content":"②①④③⑤⑥ ③"}]','D','观察选项，文段开篇或者是“②①”或者是“⑤⑥”,②① 是下定义引出并介绍家务劳动，⑤⑥存在分析论证，②①更适合放在开头，排除A选项、B选项；
C选项、D选项只有③④顺序不同，③④均在介绍当今问题，应由④句的“然而”引出，所以④在③前，确定D选项。

