INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300378,3,'中心理解题','我国天气预报、气候、大气化学等方面的业务主要依靠风云系列气象卫星完成，但高分系列卫星提供的高空间分辨率数据产品起到了很好的补充作用。尤其在应对特殊天气和地表灾害方面，高分卫星的作用更为关键。例如在此前发射的高分系列卫星中，高分一号、二号可以为地震、泥石流、森林火灾等提供高分辨率图像；高分三号的雷达成像模式不受云雾影响，可以实现全天候立体监测；位于地球静止轨道的高分四号，可以观测到台风内部的精细结构，并实现对台风的高精度定位。而在新增的两颗高分卫星中，高分六号可以说是高分一号的“升级版”,而高分五号的高光谱作用更是独一无二。
这段文字意在说明：','[{"label":"A","content":"高分系列卫星的作用是不可替代的"},{"label":"B","content":"高分系列卫星功能强大、用途广泛"},{"label":"C","content":"高分系列卫星拍得更清、测得更准"},{"label":"D","content":"高分系列卫星是风云系列的重要补充"}]','D','文段分析见批注。
文段属于典型的总分结构，首句为总观点，D选项是首句的同义替换，当选；
其他选项，A选项的“不可替代”无中生有，原文用词为“补充作用”、“在某些方面作用关键”,未提及“不可替代”,排除； B选项、C选项虽与后续的某个例子意思相近，但稍显片面，也未提及原文中的概括用词“补充作用”, 排除。

花生批注：
③ 高分系列卫星是全文论述主体。
33 行文结构：总分结构。
先转折提出总观点：高分系列卫星为风云系列气象卫星起到了补充作用；
再具体举例介绍：高分系列一号、二号、三号、四号、五号、六号卫星起到了哪些补充作用。','2021年新疆省考','进阶','published','{"globalNumber":378,"setNumber":19,"localNumber":18,"sourceLabel":"2021年新疆省考 61%","accuracy":61,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"我国天气预报、气候、大气化学等方面的业务主要依靠风云系列气象卫星完成，但高分系列卫星提供的高空间分辨率数据产品起到了很好的补充作用。尤其在应对特殊天气和地表灾害方面，高分卫星的作用更为关键。例如在此前发射的高分系列卫星中，高分一号、二号可以为地震、泥石流、森林火灾等提供高分辨率图像；高分三号的雷达成像模式不受云雾影响，可以实现全天候立体监测；位于地球静止轨道的高分四号，可以观测到台风内部的精细结构，并实现对台风的高精度定位。而在新增的两颗高分卫星中，高分六号可以说是高分一号的“升级版”,而高分五号的高光谱作用更是独一无二。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"高分系列卫星的作用是不可替代的"}],"B":[{"text":"高分系列卫星功能强大、用途广泛"}],"C":[{"text":"高分系列卫星拍得更清、测得更准"}],"D":[{"text":"高分系列卫星是风云系列的重要补充"}]},"annotatedStemRich":[{"text":"我国天气预报、气候、大气化学等方面的业务主要依靠风云系列气象卫星完成，但"},{"text":"高分系列卫星","underline":true},{"text":"③提供的高空间分辨率数据产品起到了很好的补充作用 (转折提出总观点)。尤其在应对特殊天气和地表灾害方面，高分卫星的作用更为关键。例如在此前发射的高分系列卫星中，高分一号、二号可以为地震、泥石流、森林火灾等提供高分辨率图像；高分三号的雷达成像模式不受云雾影响，可以实现全天候立体监测；位于地球静止轨道的高分四号，可以观测到台风内部的精细结构，并实现对台风的高精度定位。而在新增的两颗高分卫星中，高分六号可以说是高分一号的“升级版”,而高分五号的高光谱作用更是独一无二(分析论证)。\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"高分系列卫星的作用是不可替代的"},{"text":"(绝对化)","bold":true}],"B":[{"text":"高分系列卫星功能强大、用途广泛(片面)"}],"C":[{"text":"高分系列卫星拍得更清、测得更准(片面)"}],"D":[{"text":"高分系列卫星是风云系列的重要补充"}]},"practicalAnalysis":"文段分析见批注。\n文段属于典型的总分结构，首句为总观点，D选项是首句的同义替换，当选；\n其他选项，A选项的“不可替代”无中生有，原文用词为“补充作用”、“在某些方面作用关键”,未提及“不可替代”,排除； B选项、C选项虽与后续的某个例子意思相近，但稍显片面，也未提及原文中的概括用词“补充作用”, 排除。","notes":[{"marker":"③","content":"高分系列卫星是全文论述主体。","matchScore":0.444,"pairingMode":"marker-and-content","order":30},{"marker":"33","content":"行文结构：总分结构。\n先转折提出总观点：高分系列卫星为风云系列气象卫星起到了补充作用；\n再具体举例介绍：高分系列一号、二号、三号、四号、五号、六号卫星起到了哪些补充作用。","matchScore":0.6464,"pairingMode":"content-similarity","order":31}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300379,3,'上文推断类','事实上，教育方法从来不是“铁板一块”,关键要因材施教。因此对打击式教育的效果和影响也不能一概而论。对家长来说，教育子女更是充满个性化选择的过程。比如有的孩子容易骄傲自满，适时“敲打”实属必须；有的孩子缺乏自信，则需要多一些鼓励与肯定。当然，凡事都要掌握好分寸，不能过度打击，误伤了孩子的自信心。
