INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300381,3,'中心理解题','眼下，房地产市场正在步入稳定有序的轨道，房地产业的“信贷红利”也在逐步消失。如果出现房价稳中有降的现象，那房地产业的“信贷红利”就很有可能转化成“信贷风险”。那么,把希望寄托于房地产业的金融机构，就有可能面临着比向实体经济放贷大得多的风险。既然如此，何不尽快调整信贷理念，把支持实体经济放在金融机构的突出位置，通过支持实体经济来有效降低风险并寻找效益增长的新空间呢?也正因为如此，我们期待监管机构能够转变和升级处罚方式，从只对具体违规案件处罚转向对不执行中央决策的行为进行处罚。
从这段文字我们可以看出，作者的态度是：','[{"label":"A","content":"认为实体经济更值得金融机构放贷"},{"label":"B","content":"对房地产行业未来的发展比较乐观"},{"label":"C","content":"认为监管机构以往的处罚方式欠妥"},{"label":"D","content":"对金融机构不合理放贷行为很无奈"}]','A','文段分析见批注。
文段先提出问题“金融机构向房地产业放贷比向实体经济放贷风险更大”, 后对此给出两点对策：一是金融机构可以向实体经济放贷，二是监管机构对不向实体经济放贷进行处罚。对策二的目的也是通过处罚让金融机构执行中央决策(支持实体经济),两点对策都在表达应向实体经济放贷，对应A选项，当选；
其他选项：B选项未体现问题、D选项未体现对策，文段有对策应选对策，排除；作者建议监管机构转变处罚方式，不代表监管机构以前是错的，C选项本身有误，排除③

花生批注：
① 实体经济为全文论述主体。
② 文章结构：后对策结构。
先引出话题：
房地产业信贷红利消失；
后提出问题：
金融机构向房地产业放贷比向实体经济放贷风险更大；最后并列提出两点对策：
①金融机构可以向实体经济放贷；
②监管机构要转变和升级处罚方式：对具体违规案件处罚转向对不执行中央决策的行为进行处罚(即对不执行向实体经济放贷的金融机构进行处罚)。
③ C选项存在如下两个严重问题：
①是未体现金融机构应向实体经济放贷；
②是本身有误，要转变处罚方式，不代表原来处罚方式欠妥，可能是时代不同情况不同处于不同的发展阶段，处罚方式要与时俱进，随之调整，不代表之前就是错的。','2018年新疆省考','挑战','published','{"globalNumber":381,"setNumber":20,"localNumber":1,"sourceLabel":"2018年新疆省考 30%","accuracy":30,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"眼下，房地产市场正在步入稳定有序的轨道，房地产业的“信贷红利”也在逐步消失。如果出现房价稳中有降的现象，那房地产业的“信贷红利”就很有可能转化成“信贷风险”。那么,把希望寄托于房地产业的金融机构，就有可能面临着比向实体经济放贷大得多的风险。既然如此，何不尽快调整信贷理念，把支持实体经济放在金融机构的突出位置，通过支持实体经济来有效降低风险并寻找效益增长的新空间呢?也正因为如此，我们期待监管机构能够转变和升级处罚方式，从只对具体违规案件处罚转向对不执行中央决策的行为进行处罚。\n从这段文字我们可以看出，作者的态度是："}],"optionRich":{"A":[{"text":"认为实体经济更值得金融机构放贷"}],"B":[{"text":"对房地产行业未来的发展比较乐观"}],"C":[{"text":"认为监管机构以往的处罚方式欠妥"}],"D":[{"text":"对金融机构不合理放贷行为很无奈"}]},"annotatedStemRich":[{"text":"眼下，房地产市场正在步入稳定有序的轨道，房地产业的“信贷红利”也在逐步消失(引出话题)。如果出现房价稳中有降的现象，那房地产业的“信贷红利”就很有可能转化成“信贷风险”。那么,把希望寄托于房地产业的金融机构，就有可能面临着比向"},{"text":"实体经济","underline":true},{"text":"①放贷大得多的风险(提出问题"},{"text":")。既","bold":true},{"text":"然如此，何不尽快调整信贷理念，把支持实体经济放在金融机构的突出位置，通过支持实体经济来有效降低风险并寻找效益增长的新空间呢?也正因为如此，我们期待监管机构能够转变和升级处罚方式，从只对具体违规案件处罚转向对不执行中央决策的行为进行处罚(后对策)。②\n从这段文字我们可以看出，作者的态度是："}],"annotatedOptionRich":{"A":[{"text":"认为实体经济更值得金融机构放贷","bold":true}],"B":[{"text":"对房地产行业未来的发展比较乐观(中性表达)"}],"C":[{"text":"认为监管机构以往的处罚方式欠妥(本身有误)"}],"D":[{"text":"对金融机构不合理放贷行为很无奈(中性表达)"}]},"practicalAnalysis":"文段分析见批注。\n文段先提出问题“金融机构向房地产业放贷比向实体经济放贷风险更大”, 后对此给出两点对策：一是金融机构可以向实体经济放贷，二是监管机构对不向实体经济放贷进行处罚。对策二的目的也是通过处罚让金融机构执行中央决策(支持实体经济),两点对策都在表达应向实体经济放贷，对应A选项，当选；\n其他选项：B选项未体现问题、D选项未体现对策，文段有对策应选对策，排除；作者建议监管机构转变处罚方式，不代表监管机构以前是错的，C选项本身有误，排除③","notes":[{"marker":"①","content":"实体经济为全文论述主体。","matchScore":0.32,"pairingMode":"marker-and-content","order":0},{"marker":"②","content":"文章结构：后对策结构。\n先引出话题：\n房地产业信贷红利消失；\n后提出问题：\n金融机构向房地产业放贷比向实体经济放贷风险更大；最后并列提出两点对策：\n①金融机构可以向实体经济放贷；\n②监管机构要转变和升级处罚方式：对具体违规案件处罚转向对不执行中央决策的行为进行处罚(即对不执行向实体经济放贷的金融机构进行处罚)。","matchScore":0.9826,"pairingMode":"marker-and-content","order":1},{"marker":"③","content":"C选项存在如下两个严重问题：\n①是未体现金融机构应向实体经济放贷；\n②是本身有误，要转变处罚方式，不代表原来处罚方式欠妥，可能是时代不同情况不同处于不同的发展阶段，处罚方式要与时俱进，随之调整，不代表之前就是错的。","matchScore":0.4483,"pairingMode":"marker-and-content","order":2}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300382,3,'中心理解题','要充分扩大零工市场，当下最紧要的或是在招聘服务等方面快速“提质”,要广泛收集零工需求信息，多渠道、多形式发布。要线上和线下共同发力拓宽渠道、搭建平台，让劳动者与工作机会更快更便捷更低成本地实现匹配和对接，不再总是人追着活儿跑，也可以岗位找人。保证工作机会的连续性和稳定性，对于那些以“日结”零工为生的低技能劳动者来说，尤为重要。
上述文字意在说明：','[{"label":"A","content":"将零工信息纳入公共就业信息服务范围"},{"label":"B","content":"要明确零工人员的职业发展规划"},{"label":"C","content":"要对零工市场进行监管原则和准入原则"},{"label":"D","content":"保障零工就业率，扩大零工就业范围"}]','A','文段分析见批注。
