INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300383,3,'中心理解题','土豆被称为“十全十美”的营养产品，富含膳食纤维，脂肪含量低，有利于控制体重增长，预防高血压、高胆固醇及糖尿病等。彩色土豆富含的花青素具有抗氧化及清除自由基功能，还能有效预防不同阶段癌变发生。土豆不但营养齐全，而且结构合理，尤其是蛋白质的分子结构与人体的蛋白质分子结构基本一致，极易被人体吸收利用，其吸收利用率几乎达到100%。此外，土豆还含有其它粮食作物中所没有的胡萝卜素和扰坏血酸。
这段文字主要介绍了土豆的：','[{"label":"A","content":"分子结构"},{"label":"B","content":"营养成分"},{"label":"C","content":"食用价值"},{"label":"D","content":"养生效果"}]','C','文段全文都在介绍土豆，句句分析即可。
①②句介绍土豆营养成分和养生价值，③句介绍土豆蛋白质结构与人体一致，极易吸收，④句介绍土豆特有的营养成分；
观察选项：分子结构只对应③,过于片面；营养成分和养生效果可概括为食用价值，C选项更全面，其他选项均片面，答案为C选项。','2022年浙江省事业单位','进阶','published','{"globalNumber":383,"setNumber":20,"localNumber":3,"sourceLabel":"2022年浙江省事业单位67%","accuracy":67,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"土豆被称为“十全十美”的营养产品，富含膳食纤维，脂肪含量低，有利于控制体重增长，预防高血压、高胆固醇及糖尿病等。彩色土豆富含的花青素具有抗氧化及清除自由基功能，还能有效预防不同阶段癌变发生。土豆不但营养齐全，而且结构合理，尤其是蛋白质的分子结构与人体的蛋白质分子结构基本一致，极易被人体吸收利用，其吸收利用率几乎达到100%。此外，土豆还含有其它粮食作物中所没有的胡萝卜素和扰坏血酸。\n这段文字主要介绍了土豆的："}],"optionRich":{"A":[{"text":"分子结构"}],"B":[{"text":"营养成分"}],"C":[{"text":"食用价值"}],"D":[{"text":"养生效果"}]},"annotatedStemRich":[{"text":"①土豆被称为“十全十美”的营养产品，富含膳食纤维，脂肪含量低，有利于控制体重增长，预防高血压、高胆固醇及糖尿病等。②彩色土豆富含的花青素具有抗氧化及清除自由基功能，还能有效预防不同阶段癌变发生。③土豆不但营养齐全，而且结构合理，尤其是蛋白质的分子结构与人体的蛋白质分子结构基本一致，极易被人体吸收利用，其吸收利用率几乎达到100%。④此外，土豆还含有其它粮食作物中所没有的胡萝卜素和扰坏血酸。\n这段文字主要介绍了土豆的："}],"annotatedOptionRich":{"A":[{"text":"分子结构( 片面 )"}],"B":[{"text":"营养成分( 片面 )"}],"C":[{"text":"食用价值"}],"D":[{"text":"养生效果(片面)\n"},{"text":"S四IHA海IGO公NGK考AO 练习题20","bold":true},{"text":"套"}]},"practicalAnalysis":"文段全文都在介绍土豆，句句分析即可。\n①②句介绍土豆营养成分和养生价值，③句介绍土豆蛋白质结构与人体一致，极易吸收，④句介绍土豆特有的营养成分；\n观察选项：分子结构只对应③,过于片面；营养成分和养生效果可概括为食用价值，C选项更全面，其他选项均片面，答案为C选项。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300384,3,'中心理解题','甲骨文显示商代每天都有祭祀和占卜活动，殷王平均每两天就要祭祀一次，而且配以天干、地支，有顺序、有规则地进行。这意味着“祭”在此时不再是原始人群那种非日常的巫术活动，而是成为君王和上层集团的“日常生活”的重要组成部分。这种每天祭祀祖先神的仪式和占卜，正是“礼”的开始。《礼部 ·祭》中说“礼有五经，莫重于祭”,通过“祭”原始人群的巫术活动以及其中包含的各种图腾崇拜与禁忌法则，开始演变成一套确定的仪式制度，日益支配着整个社会的日常生活，最终成为人群必须遵守的规范制度。
这段文字主要介绍：','[{"label":"A","content":"甲骨文对于研究商代文化的价值"},{"label":"B","content":"巫术活动演变成礼仪制度的过程"},{"label":"C","content":"祭祀在商代社会生活中的重要意义"},{"label":"D","content":"祖先神在殷商宗教信仰中的核心地位"}]','B','文段分析见批注。
本文可看作是顺承结构，介绍巫术转变为规范制度的过程，对应历程类的 B选项；
A选项“甲骨文”不是文段重点，D选项“祖先神”全文未提及，无中生有，均可简单排除；C选项是易错项，原文只谈到祭祀是商代君王和上层集团日常生活的重要组成，没有谈及祭祀在商代的意义⑥,故C选项无中生有，排除；
综上，正确选项是B选项。

花生批注：
⑤ 行文结构：顺承结构。
前文介绍：
原始人群非日常的巫术活动在商代演化成每天举行的“祭”,而“祭”是礼的开始；后文介绍：
“祭”的法则先演化成确定的仪式制度，然后再由仪式制度成为人人必须遵守的“礼”。
⑥ 若谈意义，原文应当重点介绍祭祀在商代由哪些“好处”,但是原文只是介绍了祭祀是商代的日常，没谈到意义。
片段阅读6 00 (下册)','2023年重庆市事业单位','进阶','published','{"globalNumber":384,"setNumber":20,"localNumber":4,"sourceLabel":"2023年重庆市事业单位57%","accuracy":57,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"甲骨文显示商代每天都有祭祀和占卜活动，殷王平均每两天就要祭祀一次，而且配以天干、地支，有顺序、有规则地进行。这意味着“祭”在此时不再是原始人群那种非日常的巫术活动，而是成为君王和上层集团的“日常生活”的重要组成部分。这种每天祭祀祖先神的仪式和占卜，正是“礼”的开始。《礼部 ·祭》中说“礼有五经，莫重于祭”,通过“祭”原始人群的巫术活动以及其中包含的各种图腾崇拜与禁忌法则，开始演变成一套确定的仪式制度，日益支配着整个社会的日常生活，最终成为人群必须遵守的规范制度。\n这段文字主要介绍："}],"optionRich":{"A":[{"text":"甲骨文对于研究商代文化的价值"}],"B":[{"text":"巫术活动演变成礼仪制度的过程"}],"C":[{"text":"祭祀在商代社会生活中的重要意义"}],"D":[{"text":"祖先神在殷商宗教信仰中的核心地位"}]},"annotatedStemRich":[{"text":"甲骨文显示商代每天都有祭祀和占卜活动，殷王平均每两天就要祭祀一次，而且配以天干、地支，有顺序、有规则地进行。这意味着“祭”在此时不再是原始人群那种非日常的巫术活动，而是成为君王和上层集团的“日常生活”的重要组成部分。这种每天祭祀祖先神的仪式和占卜，正是“礼”的开始。《礼部.祭》中说“礼有五经，莫重于祭”,通过“祭”原始人群的巫术活动以及其中包含的各种图腾崇拜与禁忌法则，开始演变成一套确定的仪式制度，日益\n支配着整个社会的日常生活，最终成为人群必须遵守的规范制度。⑤ 这段文字主要介绍："}],"annotatedOptionRich":{"A":[{"text":"甲骨文对于研究商代文化的价值"}],"B":[{"text":"巫术活动演变成礼仪制度的过程(历程类)"}],"C":[{"text":"祭祀在商代社会生活中的重要意义(无中生有)"}],"D":[{"text":"祖先神在殷商宗教信仰中的核心地位(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n本文可看作是顺承结构，介绍巫术转变为规范制度的过程，对应历程类的 B选项；\nA选项“甲骨文”不是文段重点，D选项“祖先神”全文未提及，无中生有，均可简单排除；C选项是易错项，原文只谈到祭祀是商代君王和上层集团日常生活的重要组成，没有谈及祭祀在商代的意义⑥,故C选项无中生有，排除；\n综上，正确选项是B选项。","notes":[{"marker":"⑤","content":"行文结构：顺承结构。\n前文介绍：\n原始人群非日常的巫术活动在商代演化成每天举行的“祭”,而“祭”是礼的开始；后文介绍：\n“祭”的法则先演化成确定的仪式制度，然后再由仪式制度成为人人必须遵守的“礼”。","matchScore":0.614,"pairingMode":"marker-and-content","order":4},{"marker":"⑥","content":"若谈意义，原文应当重点介绍祭祀在商代由哪些“好处”,但是原文只是介绍了祭祀是商代的日常，没谈到意义。\n片段阅读6 00 (下册)","matchScore":0.3917,"pairingMode":"marker-and-content","order":5}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300385,3,'中心理解题','我国要在21世纪中叶建成世界科技强国，科学文化建设将在这个历史进程中扮演非常重要的角色。在这个方面，我们有必要增强文化自信。文化自信不仅表现在对既往文化贡献与价值的认同上，更表现在融汇各种优质的文化资源、创造新文化的信心和决心上。尽管全面挖掘和传承我国传统文化中的科学因素、充分认识我国历史上对科学发展做出的贡献十分必要，但更需要思考如何在未来的科学发展和科学文化建设上，做出对世界有重要贡献的新成就，这应该是增强文化自信更重要的一个方面。
这段文字主要说的是：','[{"label":"A","content":"文化自信表现在文化资源的整合和创新上"},{"label":"B","content":"科学文化发展是建设科技强国的核心"},{"label":"C","content":"判断中国科学发展对世界所做贡献的标准"},{"label":"D","content":"科学文化建设中增强文化自信的途径"}]','D','文段分析见批注。
本文对策较多，可概括为：科学文化建设需要增强文化自信，增强文化自信需要挖掘传统且做出有贡献的新成就，对应到D选项当选；
A选项出处错误，出自分析论证部分，且属于中性表达，非对策，排除； B选项中性表达，且未提及“要增强文化自信”及“途径”,排除；C选项的“判断标准”无中生有，排除。

花生批注：
⑦ 行文结构：后对策结构。
首句引出话题：
建成世界科技强国，科学文化建设扮演非常重要角色；之后给出宏观对策：
科学文化建设中必须增强文化自信；
之后介绍文化自信表现在哪；
尾句转折引出具体对策：
不但要挖掘传承传统文化的科学因素，更需要在未来的科学发展和科学文化建设上做出对世界有重要贡献的新成就。
这段文字主要说的是：
A. 文化自信表现在文化资源的整合和创新上(出处错误)
B. 科学文化发展是建设科技强国的核心 (中性表达)
C. 判断中国科学发展对世界所做贡献的标准(无中生有)
D. 科学文化建设中增强文化自信的途径
④ A选项是对未来风险的预测，这应该是基于对未来分析所做的推测，并非“几十年经验”能带来的认识。','2019年国家公务员考试','基础','published','{"globalNumber":385,"setNumber":20,"localNumber":5,"sourceLabel":"2019年国家公务员考试72%","accuracy":72,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"我国要在21世纪中叶建成世界科技强国，科学文化建设将在这个历史进程中扮演非常重要的角色。在这个方面，我们有必要增强文化自信。文化自信不仅表现在对既往文化贡献与价值的认同上，更表现在融汇各种优质的文化资源、创造新文化的信心和决心上。尽管全面挖掘和传承我国传统文化中的科学因素、充分认识我国历史上对科学发展做出的贡献十分必要，但更需要思考如何在未来的科学发展和科学文化建设上，做出对世界有重要贡献的新成就，这应该是增强文化自信更重要的一个方面。\n这段文字主要说的是："}],"optionRich":{"A":[{"text":"文化自信表现在文化资源的整合和创新上"}],"B":[{"text":"科学文化发展是建设科技强国的核心"}],"C":[{"text":"判断中国科学发展对世界所做贡献的标准"}],"D":[{"text":"科学文化建设中增强文化自信的途径"}]},"annotatedStemRich":[{"text":"我国要在21世纪中叶建成世界科技强国，科学文化建设将在这个历史进程中扮演非常重要的角色(背景引出话题)。在这个方面，我们有必要增强文化自信( 必要性表对策)。文化自信不仅表现在对既往文化贡献与价值的认同上，更表现在融汇各种优质的文化资源、创造新文化的信心和决心上"},{"text":"(分析论证)。","bold":true},{"text":"尽管全面挖掘和传承我国传统文化中的科学因素、充分认识我国历史上对科学发展做出的贡献十分必要，但更需要思考如何在未来的科学发展和科学文化建设上，做出对世界有重要贡献的新成就，这应该是增强文化自信更重要的一个方面(具体对策)。②\n这段文字主要说的是："}],"annotatedOptionRich":{"A":[{"text":"文化自信表现在文化资源的整合和创新上(出处错误)"}],"B":[{"text":"科学文化发展是建设科技强国的核心 (中性表达)"}],"C":[{"text":"判断中国科学发展对世界所做贡献的标准(无中生有)"}],"D":[{"text":"科学文化建设中增强文化自信的途径"}]},"practicalAnalysis":"文段分析见批注。\n本文对策较多，可概括为：科学文化建设需要增强文化自信，增强文化自信需要挖掘传统且做出有贡献的新成就，对应到D选项当选；\nA选项出处错误，出自分析论证部分，且属于中性表达，非对策，排除； B选项中性表达，且未提及“要增强文化自信”及“途径”,排除；C选项的“判断标准”无中生有，排除。","notes":[{"marker":"⑦","content":"行文结构：后对策结构。\n首句引出话题：\n建成世界科技强国，科学文化建设扮演非常重要角色；之后给出宏观对策：\n科学文化建设中必须增强文化自信；\n之后介绍文化自信表现在哪；\n尾句转折引出具体对策：\n不但要挖掘传承传统文化的科学因素，更需要在未来的科学发展和科学文化建设上做出对世界有重要贡献的新成就。\n这段文字主要说的是：\nA. 文化自信表现在文化资源的整合和创新上(出处错误)\nB. 科学文化发展是建设科技强国的核心 (中性表达)\nC. 判断中国科学发展对世界所做贡献的标准(无中生有)\nD. 科学文化建设中增强文化自信的途径","matchScore":0.8613,"pairingMode":"content-similarity","order":6},{"marker":"④","content":"A选项是对未来风险的预测，这应该是基于对未来分析所做的推测，并非“几十年经验”能带来的认识。","matchScore":0.3108,"pairingMode":"content-similarity","order":23}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300386,3,'中心理解题','“直过民族”是指直接从原始社会和奴隶社会直接过渡到社会主义社会的民族。在云南实行“直接过渡”的主要是景颇、傈僳、独龙、怒、佤、布朗、基诺、德昂8个民族，及部分拉祜、苗、瑶、布依、纳西、阿昌、哈尼、彝、傣、白、藏等共20个民族及尚未确定族属的“克木人”共66万人，他们所居区域被划定为“民族直过区”,政府对他们采取了不同于其他地区的特殊政策，使他们跨越若干社会发展阶段，得以与其他兄弟民族一起迈步在社会主义道路上，实现各民族共同繁荣进步。
这段文字主要介绍了：','[{"label":"A","content":"“直过民族”的概念"},{"label":"B","content":"“直过民族”的特点"},{"label":"C","content":"政府对“直过民族”的特殊政策"},{"label":"D","content":"云南“直过民族”的基本状况"}]','D','文段分析见批注。
