INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300392,3,'下文推断类②——上文提出问题→下文分析问题','火热的短视频，为传统文化的传播提供了新的渠道。然而，进入各大短视频平台会发现，玩模仿秀、秀萌宠、拼搞笑、竞才艺、秀美食、炫技能等各种内容比比皆是，可跟传统文化有关的内容却少之又少，在全面复兴优秀传统文化的时代背景下，传统文化缘何缺席短视频平台?
这段文字接下来最可能讲述的是：','[{"label":"A","content":"传统文化与短视频渠道的衔接"},{"label":"B","content":"传统文化大量通过短视频传播的原因"},{"label":"C","content":"传统文化应该怎么在短视频平台发展"},{"label":"D","content":"传统文化通过新媒体传播时面临的短板"}]','D','上文先介绍短视频平台为传统文化的传播提供了新的渠道，而后转折提出问题“传统文化缘何缺席短视频平台”,上文提出问题，下文可分析问题也可解决问题。
D选项，“传统文化通过新媒体传播的短板”可理解为“传统文化缺席短视频平台的原因”,是对上文问题的原因分析，也是对问题的回答，最可能在下文讲述，当选；
A选项未针对文末问题进行讨论，B选项本身有误，传统文化未能通过短视频平台大量传播，均可简单排除；
C选项为对策选项，但是根据行文逻辑顺序，应先分析问题，再解决问题，排除。

