INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300393,3,'语句填入类','21世纪初，人口、经济和环境压力形成了独特的综合条件，使新出现和重现的传染病能以前所未有的规模传播。最近几十年的经验显示，。而想要从根本上减少病毒国际传播可能性的最有效方法，就是世卫组织与其他组织、机构一起开展工作，加强全球疫情警报和反应网络，汇集世界各地的专家来一起应对疾病暴发。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"烈性传染病发展为全球大流行的风险正在显著增强"},{"label":"B","content":"应对疾病防控挑战的最有效手段就是采取预防措施"},{"label":"C","content":"没有一个国家能够独自防范疾病及其它公共卫生威胁"},{"label":"D","content":"建立一个实现各国数据共享的传染病数据库迫在眉睫"}]','C','文段分析见批注。
所填入语句由“最近几十年的经验显示”引出，应体现一种“认识”;且后文为对策“减少病毒国际传播需要一起应对”,所填入语句应对应该对策；
C选项的“没有一个国家能独自防范疾病”可理解为“一种经验认识”, 且该认识正与后文对策对应，当选；
A选项本身不是一种认识，且“烈性传染病”无中生有，排除；B选项、 D选项也为对策表述，与转折后的对策稍显矛盾且逻辑衔接有误⑧,排除。

花生批注：
3 行文结构：后对策结构。
开门见山引出话题：
21世纪传染病能以前所未有的规模传播；
中间为所填入语句；
文末给出对策：
减少病毒国际传播需要一起应对。
5 B选项逻辑为：经验显示要预防，而最有效的方法是合作；
D选项逻辑为：经验显示要共享数据库，而最有效的方法是合作；
转折前后都是对策，那到底要怎么做呢?
填入文中画横线部分最恰当的一项是：
A. 烈性传染病发展为全球大流行的风险正在显著增强
B. 应对疾病防控挑战的最有效手段就是采取预防措施
