INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300395,3,'语句填入类','。人们通常认为菊花只枯不落，但是不看尽“寿客金英”,怎可知黄花也可遍地金?跳出教条的藩篱、突破程式化思维，多察实情、多听心声，拥抱广阔的社会生活，我们把握的将是多元多变的实际，赢得的则是更有价值的人生。
