INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300396,3,'语句排序类','①服饰形式主要采用上衣下裳制，衣用正色，裳用间色
②这种形式一直延续到春秋战国时期，直到一种名为“深衣”的连体服饰出现，才得以改变
③当时的服饰依据穿着者的身份、地位，各有分别
④中国的衣冠服饰制度，大概在夏商时期初见端倪，到了西周渐趋完善，并被纳入礼制范围
⑤这种审美观念对中国妇女服饰观的影响竟长达千余年之久
⑥在商周前后，随着封建生产关系的形成与发展，这个时期的女性服装趋向完善和华丽，一袭长衫把女人的美发挥到极致
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"④③①②⑥⑤③"},{"label":"B","content":"④⑥⑤①③②"},{"label":"C","content":"⑥④⑤③①②"},{"label":"D","content":"⑥④②③①⑤"}]','A','观察首句，④引出中国的衣冠服饰制度，⑥介绍商周前后的女性服饰，显然④应在⑥前，排除C选项、D选项；
再从②的指代词入手：②中出现“这种形式”,则前面一句话应为一种服饰形式，①是介绍服饰形式，③是介绍当时的服饰依据身份地位各有分别，所以②应在①后，排除B选项；
综上，正确答案为A选项。

花生批注：
③ 行文逻辑如下：
④引出中国衣冠服饰制度这一话题；
③的“当时”指代④中的西周，介绍当时服饰因身份地位不同而有区别；
①介绍“当时”的服饰形式；
②介绍上述服饰形式延续到春秋战国时期，并引出连体服饰；
⑥⑤介绍连体服饰和其对后世的审美影响。','2020年四川省下半年省考','进阶','published','{"globalNumber":396,"setNumber":20,"localNumber":16,"sourceLabel":"2020年四川省下半年省考52%","accuracy":52,"typeAndPassage":"语句排序类+科普介绍文章","stemRich":[{"text":"①服饰形式主要采用上衣下裳制，衣用正色，裳用间色\n②这种形式一直延续到春秋战国时期，直到一种名为“深衣”的连体服饰出现，才得以改变\n③当时的服饰依据穿着者的身份、地位，各有分别\n④中国的衣冠服饰制度，大概在夏商时期初见端倪，到了西周渐趋完善，并被纳入礼制范围\n⑤这种审美观念对中国妇女服饰观的影响竟长达千余年之久\n⑥在商周前后，随着封建生产关系的形成与发展，这个时期的女性服装趋向完善和华丽，一袭长衫把女人的美发挥到极致\n将以上6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"④③①②⑥⑤③"}],"B":[{"text":"④⑥⑤①③②"}],"C":[{"text":"⑥④⑤③①②"}],"D":[{"text":"⑥④②③①⑤"}]},"annotatedStemRich":[{"text":"①服饰形式主要采用上衣下裳制，衣用正色，裳用间色\n②这种形式一直延续到春秋战国时期，直到一种名为“深衣”的连体服饰出现，才得以改变\n③当时的服饰依据穿着者的身份、地位，各有分别\n④中国的衣冠服饰制度，大概在夏商时期初见端倪，到了西周渐趋完善，并被纳入礼制范围\n⑤这种审美观念对中国妇女服饰观的影响竟长达千余年之久\n⑥在商周前后，随着封建生产关系的形成与发展，这个时期的女性服装趋向完善和华丽，一袭长衫把女人的美发挥到极致\n将以上6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"④③①②⑥⑤③"}],"B":[{"text":"④⑥⑤①③②"}],"C":[{"text":"⑥④⑤③①②"}],"D":[{"text":"⑥④②③①⑤"}]},"practicalAnalysis":"观察首句，④引出中国的衣冠服饰制度，⑥介绍商周前后的女性服饰，显然④应在⑥前，排除C选项、D选项；\n再从②的指代词入手：②中出现“这种形式”,则前面一句话应为一种服饰形式，①是介绍服饰形式，③是介绍当时的服饰依据身份地位各有分别，所以②应在①后，排除B选项；\n综上，正确答案为A选项。","notes":[{"marker":"③","content":"行文逻辑如下：\n④引出中国衣冠服饰制度这一话题；\n③的“当时”指代④中的西周，介绍当时服饰因身份地位不同而有区别；\n①介绍“当时”的服饰形式；\n②介绍上述服饰形式延续到春秋战国时期，并引出连体服饰；\n⑥⑤介绍连体服饰和其对后世的审美影响。","matchScore":0.5098,"pairingMode":"marker-and-content","order":30}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300397,3,'语句排序类','①我们通常看到的悬索桥的基本特征是：加劲梁悬吊在钢缆上，钢缆两端用锚碇固定
②地锚因地制宜放置在不同的空间里，有的直接安置在地面或者深藏在地下，有的固结于沉井的基础之内或利用桥头地形锚固定在山崖岩层中
③悬索桥通常还会建造两个高塔，目的是为钢缆提供中间支承，使塔、墩固结，融为一体
④悬索桥上部结构包括钢缆、塔、加劲梁及吊杆，下部结构包括支承塔的桥墩、锚固钢缆的锚碇及锚台
⑤锚碇用大体积混凝土做成，有地锚和自锚两种
⑥自锚通常是将钢缆锚固定在加劲梁表面将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"①⑤②④⑥③"},{"label":"B","content":"③①④⑤②⑥"},{"label":"C","content":"④①⑤②⑥③"},{"label":"D","content":"①⑤⑥④②③\n片段阅读6 00 (下册)"}]','C','观察首句，③句有“悬索桥还会建造…”,“还”字不适合做首句，排除B选项；④句介绍悬索桥包含哪些部件(钢缆、加劲梁、锚碇等),①句介绍一些部件的关系(加劲梁吊在钢缆上，钢缆用锚碇固定),应先介绍部件有什么,再介绍之间关系，④应在①前，排除A选项、D选项；
验证C选项：④①句先介绍悬索桥的总体结构及基本特征， ⑤②⑥ 介绍锚碇的地锚和自锚，③句补充介绍“悬索桥还会建造两个高塔，最终悬索桥融为一个整体”,逻辑正确，当选。

花生批注：
③ ②和⑥分别说地锚和自锚，根据逻辑关系，⑤②⑥捆绑且⑤在②⑥之前','2023年新疆省考','进阶','published','{"globalNumber":397,"setNumber":20,"localNumber":17,"sourceLabel":"2023年新疆省考45%","accuracy":45,"typeAndPassage":"语句排序类+科普介绍文章","stemRich":[{"text":"①我们通常看到的悬索桥的基本特征是：加劲梁悬吊在钢缆上，钢缆两端用锚碇固定\n②地锚因地制宜放置在不同的空间里，有的直接安置在地面或者深藏在地下，有的固结于沉井的基础之内或利用桥头地形锚固定在山崖岩层中\n③悬索桥通常还会建造两个高塔，目的是为钢缆提供中间支承，使塔、墩固结，融为一体\n④悬索桥上部结构包括钢缆、塔、加劲梁及吊杆，下部结构包括支承塔的桥墩、锚固钢缆的锚碇及锚台\n⑤锚碇用大体积混凝土做成，有地锚和自锚两种\n⑥自锚通常是将钢缆锚固定在加劲梁表面将以上6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"①⑤②④⑥③"}],"B":[{"text":"③①④⑤②⑥"}],"C":[{"text":"④①⑤②⑥③"}],"D":[{"text":"①⑤⑥④②③\n片段阅读6 00 (下册)"}]},"annotatedStemRich":[{"text":"①我们通常看到的悬索桥的基本特征是：加劲梁悬吊在钢缆上，钢缆两端用锚碇固定\n②地锚因地制宜放置在不同的空间里，有的直接安置在地面或者深藏在地下，有的固结于沉井的基础之内或利用桥头地形锚固定在山崖岩层中\n③悬索桥通常还会建造两个高塔，目的是为钢缆提供中间支承，使塔、墩固结，融为一体\n④悬索桥上部结构包括钢缆、塔、加劲梁及吊杆，下部结构包括支承塔的桥墩、锚固钢缆的锚碇及锚台\n⑤锚碇用大体积混凝土做成，有地锚和自锚两种\n⑥自锚通常是将钢缆锚固定在加劲梁表面\n将以上6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"①⑤②④⑥③"}],"B":[{"text":"③①④⑤②⑥"}],"C":[{"text":"④①⑤②⑥③"}],"D":[{"text":"①⑤⑥④②③\n片段阅读6 "},{"text":"00","bold":true},{"text":" (下册)"}]},"practicalAnalysis":"观察首句，③句有“悬索桥还会建造…”,“还”字不适合做首句，排除B选项；④句介绍悬索桥包含哪些部件(钢缆、加劲梁、锚碇等),①句介绍一些部件的关系(加劲梁吊在钢缆上，钢缆用锚碇固定),应先介绍部件有什么,再介绍之间关系，④应在①前，排除A选项、D选项；\n验证C选项：④①句先介绍悬索桥的总体结构及基本特征， ⑤②⑥ 介绍锚碇的地锚和自锚，③句补充介绍“悬索桥还会建造两个高塔，最终悬索桥融为一个整体”,逻辑正确，当选。","notes":[{"marker":"③","content":"②和⑥分别说地锚和自锚，根据逻辑关系，⑤②⑥捆绑且⑤在②⑥之前","matchScore":0.3283,"pairingMode":"marker-and-content","order":31}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300398,3,'下文推断类','想来一杯奶茶不用排队，“代买奶茶”的小哥会将热乎的奶茶送到手中；外出旅行家里的宠物没人照看，代遛狗服务让主人们安心外出；商场停车位难找，代客泊车服务让逛街更方便；朋友聚会喝酒，代驾司机送自己安全到家……在互联网模式普及后，随着移动支付以及共享经济发展趋于成熟，“代经济”的发展速度得以提升。动动手指就能解决问题，“代经济”的发展不仅为“懒人”们提供全新消费选择，也为市场注入新活力。有学者表示，于社会而言，专业的事由专业的人来干，催生相关行业兴起，社会分工进一步细化有助于增加就业机会，促进经济增长。当然，“代经济”个性化发展还需谨防乱象伴生。
这段文字接下来最有可能讲述的是：','[{"label":"A","content":"“代经济”增加就业机会，促进经济增长的具体表现"},{"label":"B","content":"“代经济”所伴生的乱象的种种表现"},{"label":"C","content":"“代经济”所伴生的乱象对社会的负面影响"},{"label":"D","content":"对“代经济”所伴生的乱象予以监管的具体措施"}]','B','文段先举例引出“代经济”并介绍“代经济”的积极意义；
文末提出“代经济”要谨防乱象伴生③,出现新内容“乱象”,下文应展开讨论；
A选项未提及乱象，简单排除；
B选项的“乱象的种种表现”可看作是介绍何为“乱象”,C选项介绍的是“乱象对社会的危害”,D选项介绍的是“对乱象监管的具体措施(解决问题)”。根据逻辑，应先介绍乱象是什么,再分析其危害，最后给出解决措施，即下文接下来最可能讲述的是B选项，当选。

花生批注：
③④ 若此题无B选项、C选项，可看作“宏观对策-》具体对策”的逻辑选择D选项；但此题设置了B选项，就应该先介绍乱象是什么,再分析危害和给出具体措施。
这段文字接下来最有可能讲述的是：
A. “代经济”增加就业机会，促进经济增长的具体表现
B. “代经济”所伴生的乱象的种种表现
C. “代经济”所伴生的乱象对社会的负面影响
D. 对“代经济”所伴生的乱象予以监管的具体措施','2020年深圳市考','进阶','published','{"globalNumber":398,"setNumber":20,"localNumber":18,"sourceLabel":"2020年深圳市考68%","accuracy":68,"typeAndPassage":"下文推断类 +文末新内容 → 解释新内容","stemRich":[{"text":"想来一杯奶茶不用排队，“代买奶茶”的小哥会将热乎的奶茶送到手中；外出旅行家里的宠物没人照看，代遛狗服务让主人们安心外出；商场停车位难找，代客泊车服务让逛街更方便；朋友聚会喝酒，代驾司机送自己安全到家……在互联网模式普及后，随着移动支付以及共享经济发展趋于成熟，“代经济”的发展速度得以提升。动动手指就能解决问题，“代经济”的发展不仅为“懒人”们提供全新消费选择，也为市场注入新活力。有学者表示，于社会而言，专业的事由专业的人来干，催生相关行业兴起，社会分工进一步细化有助于增加就业机会，促进经济增长。当然，“代经济”个性化发展还需谨防乱象伴生。\n这段文字接下来最有可能讲述的是："}],"optionRich":{"A":[{"text":"“代经济”增加就业机会，促进经济增长的具体表现"}],"B":[{"text":"“代经济”所伴生的乱象的种种表现"}],"C":[{"text":"“代经济”所伴生的乱象对社会的负面影响"}],"D":[{"text":"对“代经济”所伴生的乱象予以监管的具体措施"}]},"annotatedStemRich":[{"text":"想来一杯奶茶不用排队，“代买奶茶”的小哥会将热乎的奶茶送到手中；\n外出旅行家里的宠物没人照看，代遛狗服务让主人们安心外出；商场停车位难找，代客泊车服务让逛街更方便；朋友聚会喝酒，代驾司机送自己安全到家…… 在互联网模式普及后，随着移动支付以及共享经济发展趋于成熟，“代经济”的发展速度得以提升。动动手指就能解决问题，“代经济”的发展不仅为“懒人”们提供全新消费选择，也为市场注入新活力。有学者表示，于社会而言，专业的事由专业的人来干，催生相关行业兴起，社会分工进一步细化有助于增加就业机会，促进经济增长"},{"text":"(背景介绍)。","bold":true},{"text":"当然，“代经济”个性化发展还需谨防乱象伴生(提出问题)。\n这段文字接下来最有可能讲述的是："}],"annotatedOptionRich":{"A":[{"text":"“代经济”增加就业机会，促进经济增长的具体表现"}],"B":[{"text":"“代经济”所伴生的乱象的种种表现"}],"C":[{"text":"“代经济”所伴生的乱象对社会的负面影响"}],"D":[{"text":"对“代经济”所伴生的乱象予以监管的具体措施"}]},"practicalAnalysis":"文段先举例引出“代经济”并介绍“代经济”的积极意义；\n文末提出“代经济”要谨防乱象伴生③,出现新内容“乱象”,下文应展开讨论；\nA选项未提及乱象，简单排除；\nB选项的“乱象的种种表现”可看作是介绍何为“乱象”,C选项介绍的是“乱象对社会的危害”,D选项介绍的是“对乱象监管的具体措施(解决问题)”。根据逻辑，应先介绍乱象是什么,再分析其危害，最后给出解决措施，即下文接下来最可能讲述的是B选项，当选。","notes":[{"marker":"③④","content":"若此题无B选项、C选项，可看作“宏观对策-》具体对策”的逻辑选择D选项；但此题设置了B选项，就应该先介绍乱象是什么,再分析危害和给出具体措施。\n这段文字接下来最有可能讲述的是：\nA. “代经济”增加就业机会，促进经济增长的具体表现\nB. “代经济”所伴生的乱象的种种表现\nC. “代经济”所伴生的乱象对社会的负面影响\nD. 对“代经济”所伴生的乱象予以监管的具体措施","matchScore":0.6568,"pairingMode":"content-similarity","order":33}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300399,3,'标题拟定类','不同时代的青年都有属于他们的历史使命。新文化运动前期，27岁的李大钊提出“为世界进文明，为人类造幸福”;抗日战争年代，31岁的赵一曼甘将热血沃中华；解放战争时期，29岁的江竹筠为迎接黎明的曙光在秋风中傲然绽放；和平建设年代，22岁的雷锋留下了大爱的胸怀和忘我的精神；信息时代，与互联网相伴成长的数字青年，理应把个人成长融入党和国家事业发展，奋力实现中国梦的伟大实践，担当起作为网络文明建设砥柱中流的青春重任。
给这段文字加上一个标题，最恰当的是：','[{"label":"A","content":"实现中国梦，青年正当时"},{"label":"B","content":"网络时代青年的理想追求与责任担当"},{"label":"C","content":"为网络文明扬旗，是中国青年的时代责任"},{"label":"D","content":"信息时代更需要有理想和有担当的新青年"}]','C','文段分析见批注。
文段为后观点结构②,尾句观点可翻译为“信息时代的数字青年，理应担当起建设网络文明的重任”,重点是新时代青年人的具体责任即“建设网络文明” ,只有C选项体现了“建设网络文明”⑧,当选；
A选项没体现“责任”或“使命”,脱离话题范围，简单排除； B选项是具体类选项，文段不是具体类文段，排除； D选项为易错项，应翻译为“比起其他时代，信息时代更加需要有理想有担当的新青年”, 原文没体现对比，排除；

花生批注：
5 首句确定话题“青年人的使命”
36 行文结构：后观点结构。
开篇引出话题：不同时代的青年都有属于他们的历史使命；
中间部分依次介绍以往不同时代青年的使命；
最后为当下青年提出观点：
信息时代的数字青年，理应担当起建设网络文明的重任。
③ 有的同学可能会认为文段属于总分结构，因为后文的每个例子都以“;”相隔；
即使这样分析文段结构，也不影响本题的作答。因为从作者列举的例子可知，李大钊、赵一曼、江竹筠、雷锋都属于过去时代的青年模范，而最后提出的主体是当下网络时代的青年，说明作者更想强调网络时代青年的使命是什么。
38 而且C选项的“中国青年的时代责任”对应“信息时代的数字青年的重任”,“为网络文明扬旗”对应“建设网络文明”,C选项是完美选项。
39 若B选项是正确答案，文段应详细罗列青年人在网络时代的理想追求和责任担当具体有哪些，而不会列举大量其他时代杰出青年的例子，故B选项排除。
④ 很多同学容易忽略选项中的“更”隐含了信息时代与其他时代的对比，把选项翻译为“信息时代需要有责任担当的新青年”;
但即使这么翻译，D选项也没体现信息时代青年人的责任是“建设网络文明”(首句给出了话题范围，文段讨论的是不同时代青年人的历史使命是什么),故D选项有误。
