INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300406,3,'中心理解题','自明清以来，大众对于国史最熟悉的段落，大概是“三国”,这主要得力于罗贯中所写的史传文学《三国演义》。《三国演义》“据实指陈，非属臆造”,但题材取舍、人物描写、故事演绎则广纳传说和野史素材，并借助艺术虚构。在受众那里，《三国演义》经常被当作三国信史，故清代史家章学诚称其“七分实事，三分虚构，以至观者往往为之惑乱”。这种“惑乱”,就是信史与史传文学两者间的矛盾性给读者带来的困惑。“文”与“史”固然不可分家，但又不能混淆，也不能相互取代。一旦以“文”代“史”,便会导致“惑乱”。
这段文字主要说的是：','[{"label":"A","content":"史传文学的生命力在于适度的史学真实性"},{"label":"B","content":"史传文学是文学性与史学价值的对立统一"},{"label":"C","content":"人们应避免落入以“文”代“史”的窠臼"},{"label":"D","content":"“文史分家”是评价史传文学的重要标准"}]','C','文段分析见批注。
文段为典型的后对策结构，先提出问题：信史与史传文学两者间的矛盾性给读者带来的困惑，文末给出对策：不能以文代史， C选项是对策的同义替换，当选；
A选项、B选项、D选项均为中性表达，文段有对策要选对策，均可简单排除。','2017年国家公务员考试','基础','published','{"globalNumber":406,"setNumber":21,"localNumber":6,"sourceLabel":"2017年国家公务员考试79%","accuracy":79,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"自明清以来，大众对于国史最熟悉的段落，大概是“三国”,这主要得力于罗贯中所写的史传文学《三国演义》。《三国演义》“据实指陈，非属臆造”,但题材取舍、人物描写、故事演绎则广纳传说和野史素材，并借助艺术虚构。在受众那里，《三国演义》经常被当作三国信史，故清代史家章学诚称其“七分实事，三分虚构，以至观者往往为之惑乱”。这种“惑乱”,就是信史与史传文学两者间的矛盾性给读者带来的困惑。“文”与“史”固然不可分家，但又不能混淆，也不能相互取代。一旦以“文”代“史”,便会导致“惑乱”。\n这段文字主要说的是："}],"optionRich":{"A":[{"text":"史传文学的生命力在于适度的史学真实性"}],"B":[{"text":"史传文学是文学性与史学价值的对立统一"}],"C":[{"text":"人们应避免落入以“文”代“史”的窠臼"}],"D":[{"text":"“文史分家”是评价史传文学的重要标准"}]},"annotatedStemRich":[{"text":"自明清以来，大众对于国史最熟悉的段落，大概是“三国”,这主要得力于罗贯中所写的史传文学《三国演义》"},{"text":"(引出话题)。","bold":true},{"text":"《三国演义》“据实指陈，非属臆造”,但题材取舍、人物描写、故事演绎则广纳传说和野史素材，并借助艺术虚构。在受众那里，《三国演义》经常被当作三国信史，故清代史家章学诚称其“七分实事，三分虚构，以至观者往往为之惑乱”。这种“惑乱”, 就是信史与史传文学两者间的矛盾性给读者带来的困惑"},{"text":"(提出并分析问题)。","bold":true},{"text":"“文”与“史”固然不可分家，但又不能混淆，也不能相互取代。一旦以“文”代“史”,便会导致“惑乱”"},{"text":"(后对策)。","bold":true},{"text":"\n这段文字主要说的是："}],"annotatedOptionRich":{"A":[{"text":"史传文学的生命力在于适度的史学真实性"},{"text":"(中性表达)","bold":true}],"B":[{"text":"史传文学是文学性与史学价值的对立统一"},{"text":"(中性表达)","bold":true}],"C":[{"text":"人们应避免落入以“文”代“史”的窠臼"}],"D":[{"text":"“文史分家”是评价史传文学的重要标准"},{"text":"(中性表达)","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段为典型的后对策结构，先提出问题：信史与史传文学两者间的矛盾性给读者带来的困惑，文末给出对策：不能以文代史， C选项是对策的同义替换，当选；\nA选项、B选项、D选项均为中性表达，文段有对策要选对策，均可简单排除。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300407,3,'中心理解题','在漫长的传统农业社会，人类一直无法摆脱生产的不足和基础物资的匮乏，而且社会总财富相对比较恒定，财富主要依靠有限的自然资源来供给。这就意味着，国际关系更多地是围绕获取有限的自然资源展开的。然而，现代工商业的发展、科学技术的进步使得社会财富总量得到了爆炸式的增长，世界各国越来越认识到，共同建立一个公正合理的世界秩序是实现大家利益的最佳途径。
这段文字意在说明的是：','[{"label":"A","content":"社会总财富的增长主要依赖对自然资源的利用"},{"label":"B","content":"社会财富获取方式的变化对国际关系产生深刻影响"},{"label":"C","content":"国际关系与自然资源之间存在紧密的联系"},{"label":"D","content":"人类正逐渐摆脱自然资源供给的束缚"}]','B','文段分析见批注。
文段依次介绍过去和现在社会财富和国际关系，即社会财富的变化带来国际关系的变化，重点应体现出“变化”,对应 B选项⑤,当选；
A选项、D选项未体现“国际关系变化”,排除； C选项是区别比较联系类，但原文并非重点介绍二者之间的关系，排除。

花生批注：
⑭ 行文结构：二层结构—转折 /古今对比。
转折前/过去：
财富总量恒定，国际关系更多围绕自然资源展开；
转折后/现在：
随着社会财富的增长，需要建立一个新的世界秩序。
⑮ B选项也可以改为：随着社会财富的变化，当今世界应建立新的世界秩序(建立新的国际关系)。
片段阅读6 00 (下册)','2014年国家公务员考试','基础','published','{"globalNumber":407,"setNumber":21,"localNumber":7,"sourceLabel":"2014年国家公务员考试70%","accuracy":70,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"在漫长的传统农业社会，人类一直无法摆脱生产的不足和基础物资的匮乏，而且社会总财富相对比较恒定，财富主要依靠有限的自然资源来供给。这就意味着，国际关系更多地是围绕获取有限的自然资源展开的。然而，现代工商业的发展、科学技术的进步使得社会财富总量得到了爆炸式的增长，世界各国越来越认识到，共同建立一个公正合理的世界秩序是实现大家利益的最佳途径。\n这段文字意在说明的是："}],"optionRich":{"A":[{"text":"社会总财富的增长主要依赖对自然资源的利用"}],"B":[{"text":"社会财富获取方式的变化对国际关系产生深刻影响"}],"C":[{"text":"国际关系与自然资源之间存在紧密的联系"}],"D":[{"text":"人类正逐渐摆脱自然资源供给的束缚"}]},"annotatedStemRich":[{"text":"在漫长的传统农业社会，人类一直无法摆脱生产的不足和基础物资的匮乏，而且社会总财富相对比较恒定，财富主要依靠有限的自然资源来供给。这就意味着，国际关系更多地是围绕获取有限的自然资源展开的"},{"text":"(背景介绍)。","bold":true},{"text":"然而，现代工商业的发展、科学技术的进步使得社会财富总量得到了爆炸式的增长，世界各国越来越认识到，共同建立一个公正合理的世界秩序是实现大家利益的最佳途径(现状)。④\n这段文字意在说明的是："}],"annotatedOptionRich":{"A":[{"text":"社会总财富的增长主要依赖对自然资源的利用"}],"B":[{"text":"社会财富获取方式的变化对国际关系产生深刻影响"}],"C":[{"text":"国际关系与自然资源之间存在紧密的联系(区别比较联系类)"}],"D":[{"text":"人类正逐渐摆脱自然资源供给的束缚"}]},"practicalAnalysis":"文段分析见批注。\n文段依次介绍过去和现在社会财富和国际关系，即社会财富的变化带来国际关系的变化，重点应体现出“变化”,对应 B选项⑤,当选；\nA选项、D选项未体现“国际关系变化”,排除； C选项是区别比较联系类，但原文并非重点介绍二者之间的关系，排除。","notes":[{"marker":"⑭","content":"行文结构：二层结构—转折 /古今对比。\n转折前/过去：\n财富总量恒定，国际关系更多围绕自然资源展开；\n转折后/现在：\n随着社会财富的增长，需要建立一个新的世界秩序。","matchScore":0.6379,"pairingMode":"content-similarity","order":13},{"marker":"⑮","content":"B选项也可以改为：随着社会财富的变化，当今世界应建立新的世界秩序(建立新的国际关系)。\n片段阅读6 00 (下册)","matchScore":0.4603,"pairingMode":"content-similarity","order":14}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300408,3,'中心理解题','扎实的知识功底、勤勉的教学态度、科学的教学方法是教师的基本素质。如果教师知识不扎实，教学中必然会捉襟见肘，更谈不上游刃有余。我国自古以来就有“学高为师”的古训，指的是教师应在学识上高人一筹，这鲜明体现了深厚学识是好老师的必备素质之一。面对当前的信息化时代，经济快速发展，社会日益多元，各种新知识不断涌现，做一名好老师，必须具备扎实的学识，努力提升自身的学识魅力，这样才能满足学生强烈的求知欲，促进学生的学习发展。
以下选项与文段表达意思最相符的是：','[{"label":"A","content":"叠叶与高节，俱从毫末生"},{"label":"B","content":"吾生也有涯，而知也无涯"},{"label":"C","content":"学而不思则罔，思而不学则殆"},{"label":"D","content":"水之积也不厚，则其负大舟也无力"}]','D','文段分析见批注。
本题问法较为特殊，但仍为概括文段中心主旨。
文段可看作前对策结构，对策句可翻译为“老师需要有扎实的学识”,D选项意思正确①,当选；
其他选项： A选项⑩强调任何事都要打好基础，排除； B选项⑩强调知识要不断积累，排除； C选项强调学习与思考的关系，排除。

花生批注：
⑯ 文章结构：前对策结构。
开篇引出话题：教师的基本素质是什么;
再给出禁止型对策：
如果教师知识不扎实，教学将捉襟见肘；
之后进行分析论证；
尾句重复对策：老师必须具备扎实的学识。
以下选项与文段表达意思最相符的是：
⑪ 水积累的不厚，就没办法承担起大船，类比为“老师没有扎实的学识就没办法游刃有余教学”。
⑱ “任何大的成就都是从微小的开始而成的”。
⑲ “人的生命是有限的，而知识是无穷无尽的。”
②⑳ 单纯学习而不思考会导致迷惑而无所得，而只思考不学习则会精神疲倦而无所得”。
② 根据⑤句可知，热敷、按摩的方法有不良后果，甚至导致窒息死亡，可见这种方法是错误的。
2 根据①句可知，长时间保持同一个姿势容易形成血栓，即预防静脉血栓需要人们运动起来。而且此种说法符合常识，正确。
23 根据②句可知，血栓把血管堵塞，会造成血液无法流通，从而引起各种不良后果；即血栓堵塞血管是引起之后后果的原因，即具有堵塞性是血栓的根本问题(即原罪)。
A. 叠叶与高节，俱从毫末生
B. 吾生也有涯，而知也无涯
C. 学而不思则罔，思而不学则殆
D. 水之积也不厚，则其负大舟也无力','2023年内蒙古事业单位','进阶','published','{"globalNumber":408,"setNumber":21,"localNumber":8,"sourceLabel":"2023年内蒙古事业单位57%","accuracy":57,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"扎实的知识功底、勤勉的教学态度、科学的教学方法是教师的基本素质。如果教师知识不扎实，教学中必然会捉襟见肘，更谈不上游刃有余。我国自古以来就有“学高为师”的古训，指的是教师应在学识上高人一筹，这鲜明体现了深厚学识是好老师的必备素质之一。面对当前的信息化时代，经济快速发展，社会日益多元，各种新知识不断涌现，做一名好老师，必须具备扎实的学识，努力提升自身的学识魅力，这样才能满足学生强烈的求知欲，促进学生的学习发展。\n以下选项与文段表达意思最相符的是："}],"optionRich":{"A":[{"text":"叠叶与高节，俱从毫末生"}],"B":[{"text":"吾生也有涯，而知也无涯"}],"C":[{"text":"学而不思则罔，思而不学则殆"}],"D":[{"text":"水之积也不厚，则其负大舟也无力"}]},"annotatedStemRich":[{"text":"扎实的知识功底、勤勉的教学态度、科学的教学方法是教师的基本素质( 引"},{"text":"出话题","bold":true},{"text":")。如果教师知识不扎实，教学中必然会捉襟见肘，更谈不上游刃有余 (前对策)。我国自古以来就有“学高为师”的古训，指的是教师应在学识上高人一筹，这鲜明体现了深厚学识是好老师的必备素质之一。面对当前的信息化时代，经济快速发展，社会日益多元，各种新知识不断涌现，做一名好老师，必须具备扎实的学识，努力提升自身的学识魅力，这样才能满足学生强烈的求知欲，促进学生的学习发展 (分析论证+重复对策)。⑩\n以下选项与文段表达意思最相符的是：\n⑪"},{"text":"花生批注：","bold":true},{"text":"\n水积累的不厚，就没办法承担起大船，类比为“老师没有扎实的学识就没办法游刃有余教学”。\n"},{"text":"⑱花生批注：","bold":true},{"text":"\n“任何大的成就都是从微小的开始而成的”。\n"},{"text":"⑲花生批注：","bold":true},{"text":"\n“人的生命是有限的，而知识是无穷无尽的。”\n"},{"text":"②⑳花生批注：","bold":true},{"text":"\n单纯学习而不思考会导致迷惑而无所得，而只思考不学习则会精神疲倦而无所得”。\n②"},{"text":"花生批注：","bold":true},{"text":"\n根据⑤句可知，热敷、按摩的方法有不良后果，甚至导致窒息死亡，可见这种方法是错误的。\n"},{"text":"2花生批注：","bold":true},{"text":"\n根据①句可知，长时间保持同一个姿势容易形成血栓，即预防静脉血栓需要人们运动起来。而且此种说法符合常识，正确。\n"},{"text":"23花生批注：","bold":true},{"text":"\n根据②句可知，血栓把血管堵塞，会造成血液无法流通，从而引起各种不良后果；即血栓堵塞血管是引起之后后果的原因，即具有堵塞性是血栓的根本问题(即原罪)。"}],"annotatedOptionRich":{"A":[{"text":"叠叶与高节，俱从毫末生"}],"B":[{"text":"吾生也有涯，而知也无涯"}],"C":[{"text":"学而不思则罔，思而不学则殆"}],"D":[{"text":"水之积也不厚，则其负大舟也无力"}]},"practicalAnalysis":"文段分析见批注。\n本题问法较为特殊，但仍为概括文段中心主旨。\n文段可看作前对策结构，对策句可翻译为“老师需要有扎实的学识”,D选项意思正确①,当选；\n其他选项： A选项⑩强调任何事都要打好基础，排除； B选项⑩强调知识要不断积累，排除； C选项强调学习与思考的关系，排除。","notes":[{"marker":"⑯","content":"文章结构：前对策结构。\n开篇引出话题：教师的基本素质是什么;\n再给出禁止型对策：\n如果教师知识不扎实，教学将捉襟见肘；\n之后进行分析论证；\n尾句重复对策：老师必须具备扎实的学识。\n以下选项与文段表达意思最相符的是：","matchScore":0.7805,"pairingMode":"content-similarity","order":15},{"marker":"⑪","content":"水积累的不厚，就没办法承担起大船，类比为“老师没有扎实的学识就没办法游刃有余教学”。","matchScore":1.0859,"pairingMode":"marker-and-content","order":16},{"marker":"⑱","content":"“任何大的成就都是从微小的开始而成的”。","matchScore":1.0404,"pairingMode":"marker-and-content","order":17},{"marker":"⑲","content":"“人的生命是有限的，而知识是无穷无尽的。”","matchScore":1.0404,"pairingMode":"marker-and-content","order":18},{"marker":"②⑳","content":"单纯学习而不思考会导致迷惑而无所得，而只思考不学习则会精神疲倦而无所得”。","matchScore":1.0793,"pairingMode":"marker-and-content","order":19},{"marker":"②","content":"根据⑤句可知，热敷、按摩的方法有不良后果，甚至导致窒息死亡，可见这种方法是错误的。","matchScore":1.0815,"pairingMode":"marker-and-content","order":20},{"marker":"2","content":"根据①句可知，长时间保持同一个姿势容易形成血栓，即预防静脉血栓需要人们运动起来。而且此种说法符合常识，正确。","matchScore":1.1101,"pairingMode":"marker-and-content","order":21},{"marker":"23","content":"根据②句可知，血栓把血管堵塞，会造成血液无法流通，从而引起各种不良后果；即血栓堵塞血管是引起之后后果的原因，即具有堵塞性是血栓的根本问题(即原罪)。\nA. 叠叶与高节，俱从毫末生\nB. 吾生也有涯，而知也无涯\nC. 学而不思则罔，思而不学则殆\nD. 水之积也不厚，则其负大舟也无力","matchScore":0.7438,"pairingMode":"content-similarity","order":22}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300409,3,'细节判断题','长时间保持同一个姿势，容易导致下肢血液回流不畅，形成血栓。静脉血栓是血栓把血管堵塞，造成血液无法流通，从而引起肢体肿胀、疼痛，以及浅静脉扩张、曲张等临床表现。静脉血回流到心脏后，会进入肺部来完成氧气的交换。深静脉血栓在血管中一端与血管壁仅有轻度粘连，血栓另一端则自由地漂浮在血管壁内。热敷、按摩和挤压下肢，容易使血栓脱落，随血流进心脏，最后“卡”在肺动脉里面，导致肺动脉血流受阻，进而引发咳嗽、胸闷等症状，甚至导致窒息死亡，即肺栓塞。对这段文字理解错误的是：','[{"label":"A","content":"用热敷、按摩的方法来缓解静脉血栓是错误的"},{"label":"B","content":"深静脉血栓比浅静脉扩张更加危险"},{"label":"C","content":"预防静脉血栓，需要人们运动起来"},{"label":"D","content":"具有堵塞性是血栓的“原罪”"}]','B','原文只在②句提及“浅静脉扩张”,这是静脉血栓的一种临床表现，文段并未将其和深静脉血栓的危害进行比较， B选项属于无中生有，选非题，当选。','2019年辽宁省事业单位','进阶','published','{"globalNumber":409,"setNumber":21,"localNumber":9,"sourceLabel":"2019年辽宁省事业单位69%","accuracy":69,"typeAndPassage":"细节判断题","stemRich":[{"text":"长时间保持同一个姿势，容易导致下肢血液回流不畅，形成血栓。静脉血栓是血栓把血管堵塞，造成血液无法流通，从而引起肢体肿胀、疼痛，以及浅静脉扩张、曲张等临床表现。静脉血回流到心脏后，会进入肺部来完成氧气的交换。深静脉血栓在血管中一端与血管壁仅有轻度粘连，血栓另一端则自由地漂浮在血管壁内。热敷、按摩和挤压下肢，容易使血栓脱落，随血流进心脏，最后“卡”在肺动脉里面，导致肺动脉血流受阻，进而引发咳嗽、胸闷等症状，甚至导致窒息死亡，即肺栓塞。对这段文字理解"},{"text":"错误","bold":true},{"text":"的是："}],"optionRich":{"A":[{"text":"用热敷、按摩的方法来缓解静脉血栓是错误的"}],"B":[{"text":"深静脉血栓比浅静脉扩张更加危险"}],"C":[{"text":"预防静脉血栓，需要人们运动起来"}],"D":[{"text":"具有堵塞性是血栓的“原罪”"}]},"annotatedStemRich":[{"text":"①长时间保持同一个姿势，容易导致下肢血液回流不畅，形成血栓。②静脉血栓是血栓把血管堵塞，造成血液无法流通，从而引起肢体肿胀、疼痛，以及浅静脉扩张、曲张等临床表现。③静脉血回流到心脏后，会进入肺部来完成氧气的交换。④深静脉血栓在血管中一端与血管壁仅有轻度粘连，血栓另一端则自由地漂浮在血管壁内。⑤热敷、按摩和挤压下肢，容易使血栓脱落，随血流进心脏，最后“卡”在肺动脉里面，导致肺动脉血流受阻，进而引发咳嗽、胸闷等症状，甚至导致窒息死亡，即肺栓塞。\n对这段文字理解"},{"text":"错误","bold":true},{"text":"的是："}],"annotatedOptionRich":{"A":[{"text":"用热敷、按摩的方法来缓解静脉血栓是错误的②"}],"B":[{"text":"深静脉血栓比浅静脉扩张更加危险(无中生有)"}],"C":[{"text":"预防静脉血栓，需要人们运动起来"}],"D":[{"text":"具有堵塞性是血栓的“原罪”3"}]},"practicalAnalysis":"原文只在②句提及“浅静脉扩张”,这是静脉血栓的一种临床表现，文段并未将其和深静脉血栓的危害进行比较， B选项属于无中生有，选非题，当选。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300410,3,'细节判断题','旧有的传播手段，在克服空间距离时造成的时间上的延宕，以及读者在意见交互时造成的时间延宕，是以往“经典化”过程中时间成本耗费巨大的原因之一。但新媒体时代，“时间”在速度的作用下失去了恒定的模样，它将不再是至关重要的维度。在新媒体的作用下，文学作品的传阅广度以及在此基础上迅速形成的读者意见的总体性研判，才是确立经典或“经典初始化”的重要杠杆。
根据以上材料，下列说法正确的是：','[{"label":"A","content":"经典要“经得起时间检验”的说法已经过时"},{"label":"B","content":"新媒体时代作品“经典化”的时间过程将被压缩"},{"label":"C","content":"被广泛传播并获得大量评论的作品都是经典"},{"label":"D","content":"新媒体时代经典作品更容易获得读者的青睐"}]','B','根据①句的“旧有的传播手段，使以往‘经典化’过程中时间成本耗费巨大”和②③句的“新媒体时代，‘时间’将不再是至关重要的维度，文学作品的传阅广度以及在此基础上迅速形成的读者意见的总体性研判，才是确立经典的重要杠杆”可知，以往“经典化”耗时较久，现今“经典化”可迅速研判，即新媒体时代作品“经典化”时间被压缩， B选项正确，当选⑧。','2019年福建省事业单位','进阶','published','{"globalNumber":410,"setNumber":21,"localNumber":10,"sourceLabel":"2019年福建省事业单位69%","accuracy":69,"typeAndPassage":"细节判断题","stemRich":[{"text":"旧有的传播手段，在克服空间距离时造成的时间上的延宕，以及读者在意见交互时造成的时间延宕，是以往“经典化”过程中时间成本耗费巨大的原因之一。但新媒体时代，“时间”在速度的作用下失去了恒定的模样，它将不再是至关重要的维度。在新媒体的作用下，文学作品的传阅广度以及在此基础上迅速形成的读者意见的总体性研判，才是确立经典或“经典初始化”的重要杠杆。\n根据以上材料，下列说法正确的是："}],"optionRich":{"A":[{"text":"经典要“经得起时间检验”的说法已经过时"}],"B":[{"text":"新媒体时代作品“经典化”的时间过程将被压缩"}],"C":[{"text":"被广泛传播并获得大量评论的作品都是经典"}],"D":[{"text":"新媒体时代经典作品更容易获得读者的青睐"}]},"annotatedStemRich":[{"text":"①旧有的传播手段，在克服空间距离时造成的时间上的延宕，以及读者在意见交互时造成的时间延宕，是以往“经典化”过程中时间成本耗费巨大的原因之一。②但新媒体时代，“时间”在速度的作用下失去了恒定的模样，它将不再是至关重要的维度。③在新媒体的作用下，文学作品的传阅广度以及在此基础上迅速形成的读者意见的总体性研判，才是确立经典或“经典初始化”的重要杠杆。\n根据以上材料，下列说法正确的是："}],"annotatedOptionRich":{"A":[{"text":"经典要“经得起时间检验”的说法已经过时"},{"text":"(本身有误)","bold":true}],"B":[{"text":"新媒体时代作品“经典化”的时间过程将被压缩"}],"C":[{"text":"被广泛传播并获得大量评论的作品都是经典 "},{"text":"(绝对化)","bold":true}],"D":[{"text":"新媒体时代经典作品更容易获得读者的青睐"},{"text":"(无中生有)","bold":true}]},"practicalAnalysis":"根据①句的“旧有的传播手段，使以往‘经典化’过程中时间成本耗费巨大”和②③句的“新媒体时代，‘时间’将不再是至关重要的维度，文学作品的传阅广度以及在此基础上迅速形成的读者意见的总体性研判，才是确立经典的重要杠杆”可知，以往“经典化”耗时较久，现今“经典化”可迅速研判，即新媒体时代作品“经典化”时间被压缩， B选项正确，当选⑧。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300411,3,'下文推断类⑤','我们常说，“字如其人”,就是说通过一个人写的字，可以看出他的人品、性格。这是有一定道理的。不久前，一位总统如心电图一般的签名曾引发全球热议。笔迹专家赛费尔称，从这位总统的签名可以看出，他非常具有攻击性，喜欢“非黑即白”地看待事情，不太喜欢妥协。这番话并非毫无科学依据。有研究显示，笔迹就像一面镜子，基于字间距、签名方式等线索，能揭示出5000多种不同的人格特征，还能预示一些疾病征兆。
接下来最可能讲述的是：','[{"label":"A","content":"笔迹与性格的关系"},{"label":"B","content":"笔迹与人品的关系"},{"label":"C","content":"笔迹与疾病的关系"},{"label":"D","content":"笔迹与职业的关系"}]','C','文段开篇提出观点：“字如其人”,而后介绍“总统”事例进行分析说明，最后介绍研究显示笔迹能揭示不同的人格特征，还能预示一些疾病征兆；
“笔迹能预示疾病征兆”是文末提出的新话题，下文应展开介绍，对应C选项，当选；公考最新资料、更新进度微信SKA674
A选项、B选项内容前文已经论述， D选项无中生有，其均与文末话题不一致，排除。

