INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300413,3,'语句填入类','输血本质上是一种移植，必然会伴随一系列可能发生的免疫反应，移植物抗宿主病就是其中之一，其发病原因简单说来就是供血者体内的免疫活性淋巴细胞在患者体内迁移、增殖，反客为主，进而攻击患者的免疫系统。正常情况下，受血者会把供血者淋巴细胞识别为“异己”而加以排斥，这样供血者淋巴细胞就不能在受血者体内存在。而当受血者与供血者有血缘关系时，两者一部分遗传基因相同，受血者免疫功能低下，不能识别供血者的淋巴细胞，使得供血者的淋巴细胞在受血者体内植活并增殖，导致发病。所以，
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"采用严格规范的临床输血技术至关重要"},{"label":"B","content":"没有经过病原体检验的血液是不安全的"},{"label":"C","content":"直系亲属之间不能相互献血"},{"label":"D","content":"血型相同者也存在输血风险"}]','C','文段先引出话题“输血会伴随免疫反应”,接下来详细分析什么情况下会发病：有血缘关系时，受血者的免疫系统不能识别供血者淋巴细胞，导致供血者体内的免疫活性淋巴细胞反客为主进而攻击患者的免疫系统，导致移植物抗宿主病；

花生批注：
② 输血是全文论述话题。
填入文中画横线部分最恰当的一项是：
A. 采用严格规范的临床输血技术至关重要(无中生有)
B. 没有经过病原体检验的血液是不安全的(无中生有)
C. 直系亲属之间不能相互献血公考最新资料、更新进度微信SKA674
D. 血型相同者也存在输血风险(无中生有)
8 供血者的血浆中本身就含有免疫活性淋巴细胞，这些血浆注入到受血者体内时，由于血缘相近，受血者自身的免疫系统识别不出这些外来的免疫细胞，导致这些外来的免疫细胞反客为主攻击受血者，导致受血者患上移植物抗宿主病。
根据前文，移植物抗宿主病是在受血者和供血者之间存在血缘关系时发生的，那么尾句提出的对策就应当是“有血缘关系的不能相互献血”,对应到C选项；
A选项“输血技术”、B选项“病原体检验”和D选项“血型相同者”原文均未提及，均属于无中生有，排除；
综上，正确答案是C选项。
