INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300414,3,'语句填入类','现在许多学者在讨论“全球变暖”这一话题时，常将其作为“科学问题”来讨论。实际上，在涉及这种超长时段的复杂问题时，现在许多标准的科学验证方法都是有局限性的，因而从历史的角度来讨论这个问题，有其特殊意义。但众所周知，历史学家在建构历史时，必须依赖史料之外的东西，而“全球变暖”涉及长时段的气候变迁，文字记载往往十分缺乏，只能通过地质材料间接推测；而且地球不是人类，它
的行为和规律，不可能借助“史料之外的东西”来推测。所以， 0
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"“全球变暖”目前仍然是科学所无法确定的问题"},{"label":"B","content":"将“全球变暖”视为一个历史问题显然是不妥的"},{"label":"C","content":"讨论“全球变暖”比通常的历史学课题难度更大"},{"label":"D","content":"积累丰富准确的地质材料形成证据链很难实现"}]','C','文段分析见批注。

花生批注：
2 行文结构：后观点结构。
转折引出话题：
全球变暖一般被认为是科学问题，但作者认为可以从历史角度讨论；
之后进行分析论证：
一般历史问题有史料和史料外的东西，但历史气候缺乏相关史料且无法借助史料外的东西；
文末所填入语句应对上文进行总结。
填入文中画横线部分最恰当的一项是：
A. “全球变暖”目前仍然是科学所无法确定的问题
B. 将“全球变暖”视为一个历史问题显然是不妥的(本身有误)
C. 讨论“全球变暖”比通常的历史学课题难度更大
D. 积累丰富准确的地质材料形成证据链很难实现
③0 全球变暖一般被认为是科学问题，但作者认为可以从历史角度讨论，后文分析的是这样做的难度问题，而非直接否定了自己的观点。
若选择B选项，则成了“我认为可以从历史角度探讨全球变暖问题，但是一般历史研究相关资料多，气候资料少，所以，从历史角度探讨显然是不妥的”,显然自相矛盾。
所填入语句在尾句，是对上文分析讨论的概括。上文的分析讨论可概括出以下三点：①全球变暖可以从历史角度讨论，②一般的历史研究可以依赖史料和史料外的东西，③但气候变迁研究文字史料稀缺、只有地质材料且无法借助史料外的东西。
重点是“从历史角度讨论全球变暖问题”,A选项、D选项未提及作者提出的“从历史
角度分析全球变暖”,排除；B选项和上文的“可以将全球变暖看作历史问题”矛盾，排除；
C选项，既体现“可以从历史角度谈论气候变暖问题”又对应上文的“气候研究相关资料较一般的历史研究少”,对应全面，且逻辑正确，当选。','2017年国家公务员考试','挑战','published','{"globalNumber":414,"setNumber":21,"localNumber":14,"sourceLabel":"2017年国家公务员考试 42%","accuracy":42,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"现在许多学者在讨论“全球变暖”这一话题时，常将其作为“科学问题”来讨论。实际上，在涉及这种超长时段的复杂问题时，现在许多标准的科学验证方法都是有局限性的，因而从历史的角度来讨论这个问题，有其特殊意义。但众所周知，历史学家在建构历史时，必须依赖史料之外的东西，而“全球变暖”涉及长时段的气候变迁，文字记载往往十分缺乏，只能通过地质材料间接推测；而且地球不是人类，它\n的行为和规律，不可能借助“史料之外的东西”来推测。所以，"},{"text":"                        ","underline":true},{"text":" 0\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"“全球变暖”目前仍然是科学所无法确定的问题"}],"B":[{"text":"将“全球变暖”视为一个历史问题显然是不妥的"}],"C":[{"text":"讨论“全球变暖”比通常的历史学课题难度更大"}],"D":[{"text":"积累丰富准确的地质材料形成证据链很难实现"}]},"annotatedStemRich":[{"text":"现在许多学者在讨论“全球变暖”这一话题时，常将其作为“科学问题”来讨论。实际上，在涉及这种超长时段的复杂问题时，现在许多标准的科学验证方法都是有局限性的，因而从历史的角度来讨论这个问题，有其特殊意义(转折引出话题)。但众所周知，历史学家在建构历史时，必须依赖史料之外的东西，而“全球变暖”涉及长时段的气候变迁，文字记载往往十分缺乏，只能通过地质材料间接推测；而且地球不是人类，它的行为和规律，不可能借助“史料之外的东西”来推测(分析论证)。所以，"},{"text":"                        ","underline":true},{"text":" (总观点)。 ②\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"“全球变暖”目前仍然是科学所无法确定的问题"}],"B":[{"text":"将“全球变暖”视为一个历史问题显然是不妥的(本身有误)"}],"C":[{"text":"讨论“全球变暖”比通常的历史学课题难度更大"}],"D":[{"text":"积累丰富准确的地质材料形成证据链很难实现"}]},"practicalAnalysis":"文段分析见批注。","notes":[{"marker":"2","content":"行文结构：后观点结构。\n转折引出话题：\n全球变暖一般被认为是科学问题，但作者认为可以从历史角度讨论；\n之后进行分析论证：\n一般历史问题有史料和史料外的东西，但历史气候缺乏相关史料且无法借助史料外的东西；\n文末所填入语句应对上文进行总结。\n填入文中画横线部分最恰当的一项是：\nA. “全球变暖”目前仍然是科学所无法确定的问题\nB. 将“全球变暖”视为一个历史问题显然是不妥的(本身有误)\nC. 讨论“全球变暖”比通常的历史学课题难度更大\nD. 积累丰富准确的地质材料形成证据链很难实现","matchScore":0.4608,"pairingMode":"marker-and-content","order":28},{"marker":"③0","content":"全球变暖一般被认为是科学问题，但作者认为可以从历史角度讨论，后文分析的是这样做的难度问题，而非直接否定了自己的观点。\n若选择B选项，则成了“我认为可以从历史角度探讨全球变暖问题，但是一般历史研究相关资料多，气候资料少，所以，从历史角度探讨显然是不妥的”,显然自相矛盾。\n所填入语句在尾句，是对上文分析讨论的概括。上文的分析讨论可概括出以下三点：①全球变暖可以从历史角度讨论，②一般的历史研究可以依赖史料和史料外的东西，③但气候变迁研究文字史料稀缺、只有地质材料且无法借助史料外的东西。\n重点是“从历史角度讨论全球变暖问题”,A选项、D选项未提及作者提出的“从历史\n角度分析全球变暖”,排除；B选项和上文的“可以将全球变暖看作历史问题”矛盾，排除；\nC选项，既体现“可以从历史角度谈论气候变暖问题”又对应上文的“气候研究相关资料较一般的历史研究少”,对应全面，且逻辑正确，当选。","matchScore":0.2304,"pairingMode":"content-similarity","order":29}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300415,3,'语句填入类','人工智能技术擅长许多人类视为畏途的工作，。比如，人类从小数据中迅速归纳出规律的直觉，心领神会的社交能力，对日常概念和场景的识别等。人类看似简单的一些能力，实际上是由人脑60亿个神经元和500万亿个连接所支撑。一个人的大脑容量相当于2的50 次方字节，等同于目前整个互联网的容量。不敢妄言计算机永远不能模拟人类的全部功能，但至少在十年之内，人工智能的能力还是有限的。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"而人们的某些能力也将被人工智能替代"},{"label":"B","content":"但人类的一些能力却成为人工智能技术的短板"},{"label":"C","content":"仍有业内人士认为人工智能无法完全替代人类"},{"label":"D","content":"未来需要模拟更多人类的特殊能力"}]','B','填入语句后有举例，概括例子即可：人类有归纳规律的直觉(直觉即能力)、人类有心理神会的社交能力、人类有识别日常概念和场景的能力。即人类存在一些人工智能不具备的能力，对应B选项。而且B选项与前文形成逻辑衔接：人工智能擅长有人类视为畏途的工作，人类也有人工智能没有的能力。此外，B选项还与文末形成呼应：“目前看，人工智能的能力还是有限的”呼应“人类的一些能力是人工智能的短板”。','2021年广东选调','基础','published','{"globalNumber":415,"setNumber":21,"localNumber":15,"sourceLabel":"2021年广东选调 71%","accuracy":71,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"人工智能技术擅长许多人类视为畏途的工作，"},{"text":"                       ","underline":true},{"text":"。比如，人类从小数据中迅速归纳出规律的直觉，心领神会的社交能力，对日常概念和场景的识别等。人类看似简单的一些能力，实际上是由人脑60亿个神经元和500万亿个连接所支撑。一个人的大脑容量相当于2的50 次方字节，等同于目前整个互联网的容量。不敢妄言计算机永远不能模拟人类的全部功能，但至少在十年之内，人工智能的能力还是有限的。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"而人们的某些能力也将被人工智能替代"}],"B":[{"text":"但人类的一些能力却成为人工智能技术的短板"}],"C":[{"text":"仍有业内人士认为人工智能无法完全替代人类"}],"D":[{"text":"未来需要模拟更多人类的特殊能力"}]},"annotatedStemRich":[{"text":"人工智能技术擅长许多人类视为畏途的工作，"},{"text":" ","underline":true},{"text":" (前观点)。比如，人类从小数据中迅速归纳出规律的直觉，心领神会的社交能力，对日常概念和场景的识别等。人类看似简单的一些能力，实际上是由人脑60亿个神经元和500万亿个连接所支撑。一个人的大脑容量相当于2的50次方字节，等同于目前整个互联网的容量(分析论证)。不敢妄言计算机永远不能模拟人类的全部功能，但至少在十年之内，人工智能的能力还是有限的(重复观点)。\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"而人们的某些能力也将被人工智能替代"}],"B":[{"text":"但人类的一些能力却成为人工智能技术的短板"}],"C":[{"text":"仍有业内人士认为人工智能无法完全替代人类(无中生有)"}],"D":[{"text":"未来需要模拟更多人类的特殊能力"}]},"practicalAnalysis":"填入语句后有举例，概括例子即可：人类有归纳规律的直觉(直觉即能力)、人类有心理神会的社交能力、人类有识别日常概念和场景的能力。即人类存在一些人工智能不具备的能力，对应B选项。而且B选项与前文形成逻辑衔接：人工智能擅长有人类视为畏途的工作，人类也有人工智能没有的能力。此外，B选项还与文末形成呼应：“目前看，人工智能的能力还是有限的”呼应“人类的一些能力是人工智能的短板”。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300416,3,'语句排序题','①不少古姓都加女字旁，如姜、姬、姚、赢、姒等，暗示先民曾经经历过母权社会
②譬如，旧说商人的祖先是子姓，后来分为殷、时、来、宋等氏
③后来由于子孙繁衍，一族分为若干分支散居各地，每支有一个特殊的称号作为标志，这就是氏
④上古有姓有氏，姓是一种族号，氏是姓的分支
⑤《通鉴 ·外纪》说“姓者统其祖考之所自出，氏者别其子孙之所自分”,可见姓和氏是既有区别又有联系的
⑥这样，姓就成了旧有的族号，氏就成了后起的族号了将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"④①③②⑥⑤"},{"label":"B","content":"⑤③②④①⑥"},{"label":"C","content":"④②①⑤③⑥"},{"label":"D","content":"⑤⑥②④①③"}]','A','本题首句在④⑤中选择，④句下定义介绍“姓”与“氏”, ⑤句说明姓和氏是既有区别又有联系，应先对“姓”和“氏”下定义，再展开讨论，即先④后⑤,排除B选项、D选项；
②句位置是剩余选项的区别之一，可从②入手：②句是“由姓分为多支氏”的例子，应在介绍“姓”、“氏”变化的①③之后，排除 C选项；
综上，正确选项为A选项。

花生批注：
32 行文逻辑如下：
④下定义引出姓与氏；
①介绍“姓”暗示先民经历过母权社会；
③介绍因子孙繁衍由“姓”分为多支“氏”;
②举例介绍这种变化；
⑥是对这种变化的总结；
⑤对姓氏关系做出总结，呼应首句。
片段阅读6 00','2022浙江省事业单位','挑战','published','{"globalNumber":416,"setNumber":21,"localNumber":16,"sourceLabel":"2022浙江省事业单位41%","accuracy":41,"typeAndPassage":"语句排序题+科普介绍文章","stemRich":[{"text":"①不少古姓都加女字旁，如姜、姬、姚、赢、姒等，暗示先民曾经经历过母权社会\n②譬如，旧说商人的祖先是子姓，后来分为殷、时、来、宋等氏\n③后来由于子孙繁衍，一族分为若干分支散居各地，每支有一个特殊的称号作为标志，这就是氏\n④上古有姓有氏，姓是一种族号，氏是姓的分支\n⑤《通鉴 ·外纪》说“姓者统其祖考之所自出，氏者别其子孙之所自分”,可见姓和氏是既有区别又有联系的\n⑥这样，姓就成了旧有的族号，氏就成了后起的族号了将以上6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"④①③②⑥⑤"}],"B":[{"text":"⑤③②④①⑥"}],"C":[{"text":"④②①⑤③⑥"}],"D":[{"text":"⑤⑥②④①③"}]},"annotatedStemRich":[{"text":"①不少古姓都加女字旁，如姜、姬、姚、赢、姒等，暗示先民曾经经历过母权社会\n②譬如，旧说商人的祖先是子姓，后来分为殷、时、来、宋等氏\n③后来由于子孙繁衍，一族分为若干分支散居各地，每支有一个特殊的称号作为标志，这就是氏\n④上古有姓有氏，姓是一种族号，氏是姓的分支\n⑤《通鉴 ·外纪》说“姓者统其祖考之所自出，氏者别其子孙之所自分”, 可见姓和氏是既有区别又有联系的\n⑥这样，姓就成了旧有的族号，氏就成了后起的族号了将以上6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"④①③②⑥⑤"}],"B":[{"text":"⑤③②④①⑥"}],"C":[{"text":"④②①⑤③⑥"}],"D":[{"text":"⑤⑥②④①③"}]},"practicalAnalysis":"本题首句在④⑤中选择，④句下定义介绍“姓”与“氏”, ⑤句说明姓和氏是既有区别又有联系，应先对“姓”和“氏”下定义，再展开讨论，即先④后⑤,排除B选项、D选项；\n②句位置是剩余选项的区别之一，可从②入手：②句是“由姓分为多支氏”的例子，应在介绍“姓”、“氏”变化的①③之后，排除 C选项；\n综上，正确选项为A选项。","notes":[{"marker":"32","content":"行文逻辑如下：\n④下定义引出姓与氏；\n①介绍“姓”暗示先民经历过母权社会；\n③介绍因子孙繁衍由“姓”分为多支“氏”;\n②举例介绍这种变化；\n⑥是对这种变化的总结；\n⑤对姓氏关系做出总结，呼应首句。\n片段阅读6 00","matchScore":0.5182,"pairingMode":"content-similarity","order":31}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300417,3,'标题拟定类','最近，欧洲航天局宣布，将于2025年发射“清洁太空-1”号航天器，启动世界首个在轨清除太空垃圾的任务。仰望星空，航天器在浩瀚太空飞行时，除了能看到星辰大海，还不得不躲避太空垃圾。截至2019年底，全球共发射了近万个航天器，其中约有1800颗卫星在轨工作。数千颗失效的卫星以及数百万个零部件和碎片成为太空垃圾，仍然环绕地球飞行。未来几年，卫星的数量还将大幅上升，将出现多个由大量小卫星组成的巨型太空互联网卫星星座，大大增加了太空垃圾产生的几率。
最适合做这段文字标题的是：','[{"label":"A","content":"太空垃圾清理将开先河"},{"label":"B","content":"太空垃圾问题日益凸显"},{"label":"C","content":"太空垃圾环绕地球飞行"},{"label":"D","content":"航天器与太空垃圾相伴"}]','A','文段分析见批注。
文段属于新闻稿类的文段，重点在“新”,故首句欧洲航天局宣布的新做法是文段的重点，对应到A选项；
B选项、C选项、D选项均出自后文“背景介绍”部分，出处有误，排除。

花生批注：
33 行文结构：二层结构之新+ 背景介绍。
首句介绍“新”:
欧洲航天局将启动世界“首个”在轨清除太空垃圾的任务；
后面为背景介绍：
过去的太空垃圾很多以及未来即将面临“太空垃圾会越来越多”的问题。
