INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300418,3,'语句排序题','①光具有能量，光线也会对照射的物体产生推力，问题在于这种推力太小，想利用激光推动巨大的物体不大可能实现
②阿什金先是试着利用激光束照射微米级别的透明圆球，正如他所设想的一样，小球在激光的推动下移动了
③他还发现，在激光的作用下，小球会向着激光束的中心，也就是激光束能量最强的地方移动
④自从有了第一束人造激光，当时还在贝尔实验室工作的阿瑟 · 阿什金就开始思考应该怎样去利用激光进行各种工作
⑤但阿什金意识到，方向性极强的光束可能非常适用于像镊子一样移动微小的物体
⑥就这样，这种利用激光束操纵微小物体的“光镊”诞生了
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"①⑥②③④⑤"},{"label":"B","content":"①②⑤④⑥③"},{"label":"C","content":"④②①⑤⑥③"},{"label":"D","content":"④①⑤②③⑥)\n四SIHA海IGO公NGK考AO 练习题21套"}]','D','文段中出现“阿什金”的有②④⑤句，应是描述最详细(在贝尔实验室工作的阿瑟 · 阿什金)的，④句在简称“阿什金”的②⑤句前，排除A选项、B选项；
观察③⑥,③句介绍的是阿什金在研究过程中的发现，⑥是总结“光镊”的诞生，显然③应在⑥句前，排除C选项；
综上，正确答案为D选项。

