INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300419,3,'词句理解题','经典，是当世仍有典范意义与价值的优秀文化遗产，是感性中融入深刻理性的杰作。因此，①阅读经典常常会陷入深刻的思考。近些年，受大众文化影响，阅读出现了去经典化的倾向。一是追求阅读的快感，推崇碎片化、快餐化、浅易化、感官化的阅读；二是盲目从众，缺乏自己的判断。阅读真正的属性在于自由。大众文化的流行恰恰挤压了读者自由的空间。久而久之，②读者的判断力理解力下降，想象力贫乏，经典也可能变成了啃不动的馒头。
对画线部分理解最准确的是：','[{"label":"A","content":"经典的理性价值难以把握"},{"label":"B","content":"读者自由阅读的空间被挤压"},{"label":"C","content":"大众阅读经典的能力下降"},{"label":"D","content":"经典阅读与大众文化背道而驰"}]','C','文段先说明①经典需要深刻思考，再介绍当今文化导致②读者的判断力、理解力、想象力都在下降；通过“啃不动的馒头”来比喻读者阅读经典的现状，即读者没有能力阅读经典作品，对应C选项，当选。
