INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300421,3,'中心理解题','发展乡村旅游缺少资金支持，这一难题亟需破解。乡村旅游景区是多方位开放式区域，属于公共空间。改善发展环境，政府义不容辞，可通过整合财政资金，促进景区提档升级，鼓励各地采取以奖代补、先建后补的形式加大财政支持力度；可通过撬动金融资金，搭建银行和政府的对接平台，解决经营主体的贷款难题，加大对乡村旅游的信贷力度；还可通过PPP、众筹等新型融资模式鼓励社会资本进入。让乡村旅游有人投、建得好、管得好。
这段文字重点强调的是：','[{"label":"A","content":"资金匮乏难题严重影响乡村旅游发展"},{"label":"B","content":"乡村旅游的建设和管理需要资金支持"},{"label":"C","content":"充分发挥不同资金渠道间的优势互补"},{"label":"D","content":"发展乡村旅游急需推进多渠道投融资"}]','D','文段分析见批注。
文段首句提出问题，之后针对性的给出加大财政支持力度、加大信贷力度、鼓励社会资本进入三条具体对策，选项需要整合对策； D选项的“多渠道”很好地概括了对策中资金的来源，当选；
A选项为问题表述， C选项未体现文段主题“乡村旅游”,均可简单排除； B选项是对策选项，需要与D选项辨析，与D选项相比对策表述太宽泛③,排除。

花生批注：
① “乡村旅游”是文段论述主题。
② 文章结构：总分结构。
先提出问题：乡村旅游缺少资金支持；
然后通过并列结构给出数条具体对策：
①加大财政支持力度；
②加大信贷力度；
③鼓励社会资本进入。
③ B选项、D选项构成“一比较”:
B选项只说“需要资金支持”, 但没有说清楚资金的来源；
D选项的“推进多渠道投融资”,具体的指出资金来源，更具体。
