INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300422,3,'中心理解题','垃圾填埋场是厌氧细菌的滋生地，会产生大量的甲烷。甲烷的温室效应比二氧化碳更强，尽管可以将其捕捉并转化为能源，但是即使最高效的回收系统，仍有高达10%的甲烷发生逃逸。由于垃圾填埋场产生的甲烷大部分来自有机废弃物，因此可以用更绿色的方式处理，最简单的方法就是堆肥。实际上，垃圾填埋场里三分之二的垃圾可以堆肥，这就大大减少了甲烷的产量。由于堆肥过程中会产生高温、高压，有机废弃物中的碳可能部分转化为二氧化碳和一氧化碳。那么,我们可以考虑将这些有机物重新组合成液态燃料(乙醇或甲醇),或用作其他工业原料。
这段文字主要介绍了：','[{"label":"A","content":"甲烷的温室效应比二氧化碳更甚"},{"label":"B","content":"现阶段的甲烷回收系统对其的捕捉利用依旧有限"},{"label":"C","content":"用堆肥方式处理垃圾填埋场的垃圾能有效减少甲烷的生成"},{"label":"D","content":"堆肥这种垃圾处理方式需要将其生成的有机废弃物重新组合"}]','C','文段分析见批注。
文段对策句可翻译为“可用堆肥的方式处理垃圾填埋场所产生的甲烷”,C选项为原文对策的同义替换且包含“堆肥”这一关键词，当选；
A选项、B选项均缺少“堆肥”这一关键词，且非对策表述，可简单排除；D选项可翻译为“堆肥需要将其生成的有机废弃物重新组合”, 对策有误⑤,排除。

花生批注：
④ 行文结构：前对策结构。
开篇提出问题：
垃圾填埋场甲烷过多且会发生逃逸现象；
再给出对策：
可采用堆肥方式处理；
最后为分析论证：
堆肥不仅可处理甲烷还可用作其他燃料。
⑤ 原文对策核心为“堆肥”这一方式，选项对策为“重新组合”, 对策需位于必要条件位置；
例：考上公务员需要努力。对策为“要努力”,而D选项则为“努力需要…… ”
A. 甲烷的温室效应比二氧化碳更甚(缺少关键词)
B. 现阶段的甲烷回收系统对其的捕捉利用依旧有限(缺少关键词)
C. 用堆肥方式处理垃圾填埋场的垃圾能有效减少甲烷的生成','2019年河南选调','基础','published','{"globalNumber":422,"setNumber":22,"localNumber":2,"sourceLabel":"2019年河南选调 76%","accuracy":76,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"垃圾填埋场是厌氧细菌的滋生地，会产生大量的甲烷。甲烷的温室效应比二氧化碳更强，尽管可以将其捕捉并转化为能源，但是即使最高效的回收系统，仍有高达10%的甲烷发生逃逸。由于垃圾填埋场产生的甲烷大部分来自有机废弃物，因此可以用更绿色的方式处理，最简单的方法就是堆肥。实际上，垃圾填埋场里三分之二的垃圾可以堆肥，这就大大减少了甲烷的产量。由于堆肥过程中会产生高温、高压，有机废弃物中的碳可能部分转化为二氧化碳和一氧化碳。那么,我们可以考虑将这些有机物重新组合成液态燃料(乙醇或甲醇),或用作其他工业原料。\n这段文字主要介绍了："}],"optionRich":{"A":[{"text":"甲烷的温室效应比二氧化碳更甚"}],"B":[{"text":"现阶段的甲烷回收系统对其的捕捉利用依旧有限"}],"C":[{"text":"用堆肥方式处理垃圾填埋场的垃圾能有效减少甲烷的生成"}],"D":[{"text":"堆肥这种垃圾处理方式需要将其生成的有机废弃物重新组合"}]},"annotatedStemRich":[{"text":"垃圾填埋场是厌氧细菌的滋生地，会产生大量的甲烷。甲烷的温室效应比二氧化碳更强，尽管可以将其捕捉并转化为能源，但是即使最高效的回收系统，仍有高达10%的甲烷发生逃逸(提出问题)。由于垃圾填埋场产生的甲烷大部分来自有机废弃物，因此可以用更绿色的方式处理，最简单的方法就是堆肥( 给出对策)。实际上，垃圾填埋场里三分之二的垃圾可以堆肥，这就大大减少了甲烷的产量。由于堆肥过程中会产生高温、高压，有机废弃物中的碳可能部分转化为二氧化碳和一氧化碳。那么,我们可以考虑将这些有机物重新组合成液态燃料(乙醇或甲醇),或用作其他工业原料"},{"text":"(分析论证)。④","bold":true},{"text":"\n行文结构：前对策结构。\n这段文字主要介绍了："}],"annotatedOptionRich":{"A":[{"text":"甲烷的温室效应比二氧化碳更甚"},{"text":"(缺少关键词)","bold":true}],"B":[{"text":"现阶段的甲烷回收系统对其的捕捉利用依旧有限(缺少关键词)"}],"C":[{"text":"用堆肥方式处理垃圾填埋场的垃圾能有效减少甲烷的生成"}],"D":[{"text":"堆肥这种垃圾处理方式需要将其生成的有机废弃物重新组合(对策有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段对策句可翻译为“可用堆肥的方式处理垃圾填埋场所产生的甲烷”,C选项为原文对策的同义替换且包含“堆肥”这一关键词，当选；\nA选项、B选项均缺少“堆肥”这一关键词，且非对策表述，可简单排除；D选项可翻译为“堆肥需要将其生成的有机废弃物重新组合”, 对策有误⑤,排除。","notes":[{"marker":"④","content":"行文结构：前对策结构。\n开篇提出问题：\n垃圾填埋场甲烷过多且会发生逃逸现象；\n再给出对策：\n可采用堆肥方式处理；\n最后为分析论证：\n堆肥不仅可处理甲烷还可用作其他燃料。","matchScore":0.6469,"pairingMode":"marker-and-content","order":3},{"marker":"⑤","content":"原文对策核心为“堆肥”这一方式，选项对策为“重新组合”, 对策需位于必要条件位置；\n例：考上公务员需要努力。对策为“要努力”,而D选项则为“努力需要…… ”\nA. 甲烷的温室效应比二氧化碳更甚(缺少关键词)\nB. 现阶段的甲烷回收系统对其的捕捉利用依旧有限(缺少关键词)\nC. 用堆肥方式处理垃圾填埋场的垃圾能有效减少甲烷的生成","matchScore":0.5221,"pairingMode":"marker-and-content","order":4}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300423,3,'词句理解题','过去100多年来，围绕达尔文进化论是否正确的争论从未停歇。不断涌现的科学事实在弥补达尔文当年未曾发现的“缺失环节”的同时，也在检验着达尔文进化论的预测能力。例如，2004年在加拿大发现的“提克塔利克鱼”化石揭示了从鱼类(鳍)到陆生动物(腿)之间的过渡状态，被公认是“种系渐变论”的一个极好例证。当然，达尔文进化论并非完美无缺，它确实存在“可证伪”之处。以自然选择理论为例，它在孟德尔遗传学建立之初就受到了强烈挑战，但各种不能用自然选择理论简单解释的新证据最终还是拓展了人们对进化动力和机制的认识，而不是摒弃该理论。
这段文字以自然选择理论受到孟德尔遗传学挑战为例，目的是：','[{"label":"A","content":"说明达尔文进化论具有可证伪性"},{"label":"B","content":"证明达尔文进化论具有预测能力"},{"label":"C","content":"提出“种系渐变论”的事实例证"},{"label":"D","content":"加深人们对生物进化机制的认识"}]','A','文段在“当然”后引出一个观点：达尔文进化论并非完美无缺，它确实存在“可证伪”之处；之后用“自然选择理论被孟德尔遗传性挑战(即自然选择理论有“可证伪”之处)”的例子来证明前面观点，即证明“达尔文进化论有可证伪之处”,对应A选项；
B选项、C选项均在“当然”之前，后续例子也和“预测能力”、“种系渐变论”无关，排除；
D选项⑥,不能被自然选择理论解释的新证据拓展了人们对进化动力和机制的认识，这是“不能被自然选择理论解释的新证据”的意义，它是例子中的一部分，不是整个“例子”的作用，排除。

花生批注：
⑥ 例如：努力自然会有收获。小明努力后，成功考取公务员。
“小明”例子是为了是证明“努力自然会有收获”;
但不能说“小明”例子的作用是证明“能考取公务员”。','2019年国家公务员考试','进阶','published','{"globalNumber":423,"setNumber":22,"localNumber":3,"sourceLabel":"2019年国家公务员考试67%","accuracy":67,"typeAndPassage":"词句理解题","stemRich":[{"text":"过去100多年来，围绕达尔文进化论是否正确的争论从未停歇。不断涌现的科学事实在弥补达尔文当年未曾发现的“缺失环节”的同时，也在检验着达尔文进化论的预测能力。例如，2004年在加拿大发现的“提克塔利克鱼”化石揭示了从鱼类(鳍)到陆生动物(腿)之间的过渡状态，被公认是“种系渐变论”的一个极好例证。当然，达尔文进化论并非完美无缺，它确实存在“可证伪”之处。以自然选择理论为例，它在孟德尔遗传学建立之初就受到了强烈挑战，但各种不能用自然选择理论简单解释的新证据最终还是拓展了人们对进化动力和机制的认识，而不是摒弃该理论。\n这段文字以自然选择理论受到孟德尔遗传学挑战为例，目的是："}],"optionRich":{"A":[{"text":"说明达尔文进化论具有可证伪性"}],"B":[{"text":"证明达尔文进化论具有预测能力"}],"C":[{"text":"提出“种系渐变论”的事实例证"}],"D":[{"text":"加深人们对生物进化机制的认识"}]},"annotatedStemRich":[{"text":"过去100多年来，围绕达尔文进化论是否正确的争论从未停歇。不断涌现的科学事实在弥补达尔文当年未曾发现的“缺失环节”的同时，也在检验着达尔文进化论的预测能力。例如，2004年在加拿大发现的“提克塔利克鱼”化石揭示了从鱼类(鳍) 到陆生动物(腿)之间的过渡状态，被公认是“种系渐变论”的一个极好例证。当然，达尔文进化论并非完美无缺，它确实存在“可证伪”之处。以自然选择理论为例，它在孟德尔遗传学建立之初就受到了强烈挑战，但各种不能用自然选择理论简单解释的新证据最终还是拓展了人们对进化动力和机制的认识，而不是摒弃该理论。\n这段文字以自然选择理论受到孟德尔遗传学挑战为例，目的是："}],"annotatedOptionRich":{"A":[{"text":"说明达尔文进化论具有可证伪性"}],"B":[{"text":"证明达尔文进化论具有预测能力(出处有误)"}],"C":[{"text":"提出“种系渐变论”的事实例证(出处有误)"}],"D":[{"text":"加深人们对生物进化机制的认识(出处有误)"}]},"practicalAnalysis":"文段在“当然”后引出一个观点：达尔文进化论并非完美无缺，它确实存在“可证伪”之处；之后用“自然选择理论被孟德尔遗传性挑战(即自然选择理论有“可证伪”之处)”的例子来证明前面观点，即证明“达尔文进化论有可证伪之处”,对应A选项；\nB选项、C选项均在“当然”之前，后续例子也和“预测能力”、“种系渐变论”无关，排除；\nD选项⑥,不能被自然选择理论解释的新证据拓展了人们对进化动力和机制的认识，这是“不能被自然选择理论解释的新证据”的意义，它是例子中的一部分，不是整个“例子”的作用，排除。","notes":[{"marker":"⑥","content":"例如：努力自然会有收获。小明努力后，成功考取公务员。\n“小明”例子是为了是证明“努力自然会有收获”;\n但不能说“小明”例子的作用是证明“能考取公务员”。","matchScore":0.2565,"pairingMode":"marker-and-content","order":5}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300424,3,'标题拟定类','中国人民正在为实现中华民族伟大复兴的中国梦而奋斗。实现中国梦，是物质文明和精神文明均衡发展、相互促进的结果，没有文明的继承和发展，没有文化的弘扬和繁荣，就没有中国梦的实现；实现中国梦，是物质文明和精神文明比翼双飞的发展过程，随着中国经济社会不断发展，中华文明也必将顺应时代发展焕发出更加蓬勃的生命力。
最适合做这段文字标题的是：','[{"label":"A","content":"为实现中国梦而奋斗"},{"label":"B","content":"伟大复兴的中国梦"},{"label":"C","content":"中国人民与中国梦"},{"label":"D","content":"中华民族的梦想"}]','A','文段分析见批注。
文段总部分强调“中国人民正为实现中国梦奋斗”,后文介绍实现中国梦的途径和必然性， A选项对应“总”,可做文段标题，当选；
B选项、 D选项⑨均缺少关键词“实现中国梦”,可简单排除； C选项为区别比较联系类选项，文段并非重点介绍二者关系，排除。

花生批注：
⑦ “实现中国梦”为全文论述主题。
⑧ 行文结构：总分结构。
开篇给出总观点：中国人民正为实现伟大复兴中国梦奋斗；
分1:实现中国梦是物质文明和精神文明发展、促进的结果；
分2:实现中国梦是物质文明和精神文明比翼双飞的发展过程。
⑨ B、D均为定义表述，若当选，文段应介绍“伟大复兴的中国梦是什么、中华民族的梦想是什么”','2015年安徽省事业单位','进阶','published','{"globalNumber":424,"setNumber":22,"localNumber":4,"sourceLabel":"2015年安徽省事业单位68%","accuracy":68,"typeAndPassage":"标题拟定类+说理类文章","stemRich":[{"text":"中国人民正在为实现中华民族伟大复兴的中国梦而奋斗。实现中国梦，是物质文明和精神文明均衡发展、相互促进的结果，没有文明的继承和发展，没有文化的弘扬和繁荣，就没有中国梦的实现；实现中国梦，是物质文明和精神文明比翼双飞的发展过程，随着中国经济社会不断发展，中华文明也必将顺应时代发展焕发出更加蓬勃的生命力。\n最适合做这段文字标题的是："}],"optionRich":{"A":[{"text":"为实现中国梦而奋斗"}],"B":[{"text":"伟大复兴的中国梦"}],"C":[{"text":"中国人民与中国梦"}],"D":[{"text":"中华民族的梦想"}]},"annotatedStemRich":[{"text":"中国人民正在为"},{"text":"实现中华民族伟大复兴的中国梦","underline":true},{"text":"⑦而奋斗(总)。实现中国梦，是物质文明和精神文明均衡发展、相互促进的结果，没有文明的继承和发展，没有文化的弘扬和繁荣，就没有中国梦的实现(分1);实现中国梦，是物质文明和精神文明比翼双飞的发展过程，随着中国经济社会不断发展，中华文明也必将顺应时代发展焕发出更加蓬勃的生命力(分2)。⑧\n最适合做这段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"为实现中国梦而奋斗","bold":true}],"B":[{"text":"伟大复兴的中国梦(缺关键词)"}],"C":[{"text":"中国人民与中国梦(区别比较联系类)"}],"D":[{"text":"中华民族的梦想(缺关键词)"}]},"practicalAnalysis":"文段分析见批注。\n文段总部分强调“中国人民正为实现中国梦奋斗”,后文介绍实现中国梦的途径和必然性， A选项对应“总”,可做文段标题，当选；\nB选项、 D选项⑨均缺少关键词“实现中国梦”,可简单排除； C选项为区别比较联系类选项，文段并非重点介绍二者关系，排除。","notes":[{"marker":"⑦","content":"“实现中国梦”为全文论述主题。","matchScore":0.4004,"pairingMode":"marker-and-content","order":6},{"marker":"⑧","content":"行文结构：总分结构。\n开篇给出总观点：中国人民正为实现伟大复兴中国梦奋斗；\n分1:实现中国梦是物质文明和精神文明发展、促进的结果；\n分2:实现中国梦是物质文明和精神文明比翼双飞的发展过程。","matchScore":0.9035,"pairingMode":"marker-and-content","order":7},{"marker":"⑨","content":"B、D均为定义表述，若当选，文段应介绍“伟大复兴的中国梦是什么、中华民族的梦想是什么”","matchScore":0.4857,"pairingMode":"marker-and-content","order":8}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300425,3,'中心理解题','元明之际，因政局混乱及思想控制的松动，文人的思想活力获得极大释放，传统诗学观念有所生新与变革。其中，一个传统的诗学话语，“穷而后工”被旧话重提。值得玩味的是，此际文人非但丧失仕进的机会，甚至穷困潦倒、避乱山林，却反对“穷而后工”,这来源于易代文人特有的儒者心态与生命意识。对“诗非穷而后工”的论说，可管窥元明之际文学思想的复杂性与独特性。
本段文字意在说明：','[{"label":"A","content":"元明之际传统诗学观念的生新与变革"},{"label":"B","content":"元明之际诗歌“穷而后工”说之新变"},{"label":"C","content":"文人际遇对当时文学思想产生的特殊影响"},{"label":"D","content":"“诗非穷而后工”说的形成原因和研究价值"}]','D','文段分析见批注。
本题可从选项入手，D选项可看作“A 且B”类选项，可借鉴D选项的概括反推文段：文段引出“元明之际‘穷而后工’被重提”这一话题后对其进行分析介绍，先介绍其原因(“这来源于易代文人特有的儒者心态与生命意识”)、再介绍其研究价值(“可管窥元明之际文学思想的复杂性与独特性”),完美对应，D选项当选；
A选项、C选项未提及“穷而后工”这一主题词，可简单排除；B选项无中生有，原文未提及该理论有什么新的变化，且该选项有杂糅之嫌②,排除。

花生批注：
⑩ “穷而后工”为全文论述主题。
穷而后工：旧时认为文人越是穷困不得志，诗文就写得越好。
⑪ 行文结构：并列结构。
开篇总起：元明之际“穷而后工”被重提；
后文依次介绍：
①反对“穷而后工”的原因； ②研究“诗非穷而后工”的价值。
⑫ “新变”提炼于“传统诗学观念有所生新与变革”,将“生新与变革”概括为“新变”,与“穷而后工”杂糅在一起。','2024年福建省事业单位','挑战','published','{"globalNumber":425,"setNumber":22,"localNumber":5,"sourceLabel":"2024年福建省事业单位30%","accuracy":30,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"元明之际，因政局混乱及思想控制的松动，文人的思想活力获得极大释放，传统诗学观念有所生新与变革。其中，一个传统的诗学话语，“穷而后工”被旧话重提。值得玩味的是，此际文人非但丧失仕进的机会，甚至穷困潦倒、避乱山林，却反对“穷而后工”,这来源于易代文人特有的儒者心态与生命意识。对“诗非穷而后工”的论说，可管窥元明之际文学思想的复杂性与独特性。\n本段文字意在说明："}],"optionRich":{"A":[{"text":"元明之际传统诗学观念的生新与变革"}],"B":[{"text":"元明之际诗歌“穷而后工”说之新变"}],"C":[{"text":"文人际遇对当时文学思想产生的特殊影响"}],"D":[{"text":"“诗非穷而后工”说的形成原因和研究价值"}]},"annotatedStemRich":[{"text":"元明之际，因政局混乱及思想控制的松动，文人的思想活力获得极大释放，传统诗学观念有所生新与变革。其中，一个传统的诗学话语，"},{"text":"“穷而后工”","underline":true},{"text":"⑩ 被旧话重提(引出话题)。值得玩味的是，此际文人非但丧失仕进的机会，甚至穷困潦倒、避乱山林，却反对“穷而后工”,这来源于易代文人特有的儒者心态与生命意识( 分 1 ) 。对“诗非穷而后工”的论说，可管窥元明之际文学思想的复杂性与独特性(分2)。①\n本段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"元明之际传统诗学观念的生新与变革"},{"text":"(缺少关键词)","bold":true}],"B":[{"text":"元明之际诗歌“穷而后工”说之新变(无中生有)"}],"C":[{"text":"文人际遇对当时文学思想产生的特殊影响"},{"text":"(缺少关键词)","bold":true}],"D":[{"text":"“诗非穷而后工”说的形成原因和研究价值( A 且B 类 )"}]},"practicalAnalysis":"文段分析见批注。\n本题可从选项入手，D选项可看作“A 且B”类选项，可借鉴D选项的概括反推文段：文段引出“元明之际‘穷而后工’被重提”这一话题后对其进行分析介绍，先介绍其原因(“这来源于易代文人特有的儒者心态与生命意识”)、再介绍其研究价值(“可管窥元明之际文学思想的复杂性与独特性”),完美对应，D选项当选；\nA选项、C选项未提及“穷而后工”这一主题词，可简单排除；B选项无中生有，原文未提及该理论有什么新的变化，且该选项有杂糅之嫌②,排除。","notes":[{"marker":"⑩","content":"“穷而后工”为全文论述主题。\n穷而后工：旧时认为文人越是穷困不得志，诗文就写得越好。","matchScore":0.2515,"pairingMode":"marker-and-content","order":9},{"marker":"⑪","content":"行文结构：并列结构。\n开篇总起：元明之际“穷而后工”被重提；\n后文依次介绍：\n①反对“穷而后工”的原因； ②研究“诗非穷而后工”的价值。","matchScore":0.5775,"pairingMode":"content-similarity","order":10},{"marker":"⑫","content":"“新变”提炼于“传统诗学观念有所生新与变革”,将“生新与变革”概括为“新变”,与“穷而后工”杂糅在一起。","matchScore":0.6015,"pairingMode":"content-similarity","order":11}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300426,3,'标题拟定类','辽宁大连一9岁女孩小鑫在虎牙直播平台给主播打赏了5万余元，其母亲维权三个多月一直没有结果。对此，虎牙公关部陈女士表示，一般会建议当事人提供孩子玩手机游戏时的视频资料，但小鑫的申诉材料里没有；因无法证明确实是孩子操作，所以申诉始终未通过审核，平台也将原因向申诉人进行了告知。虽然家长有一定责任，但类似的事情之所以不断发生，并且维权困难重重，根本还是因为监管存在种种漏洞：其一，平台往往缺乏针对未成年人的注册审核和使用限制；其二，没有建立对应的维权选项。
最适合作为本段文字的标题是：','[{"label":"A","content":"“儿童不宜”畅通无阻，巨额打赏纠纷不断"},{"label":"B","content":"父母用手机哄孩子，使“父母监管”成浮云"},{"label":"C","content":"“天价打赏”纠纷不断，规范别缺位"},{"label":"D","content":"“天价打赏”何以维权三个月无果"}]','C','文段分析见批注。
文段先讲述了“9岁女孩打赏后维权困难”的新闻事件，之后给出作者观点：天价打赏维权困难还是监管存在漏洞，重点是作者观点。 C选项的“天价打赏纠纷不断”对应新闻事件，“规范别缺位”是针对问题的对策，可看作A 且 B 类选项，完美对应，当选；
A选项、D选项关于新闻事件本身，未提及作者观点，排除； B选项的“父母用手机哄孩子”、“父母缺少对子女看管”无中生有，排除。

