INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300428,3,'标题拟定类','这个文本数据化的时代，几乎市面上所有的书籍都能找到它的电子版，就连静静地躺在藏书室里的古籍也被搬进了虚拟世界。然而，就在这网络快速发展的“读屏时代”,仍有这样一群人，用他们的坚守与情怀，守候着一家家旧书店，留住一片片静谧与光阴，让人们还能在旧书卷的书香中回忆蕉窗听雨的静思，体味图书馆午后的慵懒闲适。
最适合做这段文字标题的是：','[{"label":"A","content":"“读屏时代”的旧书店"},{"label":"B","content":"旧书店的坚守者"},{"label":"C","content":"“读屏时代”的快与慢"},{"label":"D","content":"旧书店的书卷气"}]','B','文段分析见批注。
文段转折后提出在“读屏时代”仍有人用坚守与情怀守候旧书店；转折后内容为重点，正确选项应体现“坚守”,对应B选项，当选；
A选项、C选项、D选项未提及“坚守”,均可排除。

花生批注：
⑯ 旧书店是全文论述主题。
⑰ 行文结构：二层结构之转折。转折前：介绍文本数据化的时代，书籍几乎都能找到电子版；
转折后：仍有人坚持守候旧书店。
最适合做这段文字标题的是：
A. “读屏时代”的旧书店(缺关键词)
B. 旧书店的坚守者
C. “读屏时代”的快与慢(缺关键词)
D. 旧书店的书卷气(缺关键词)','2023年福建省事业单位','进阶','published','{"globalNumber":428,"setNumber":22,"localNumber":8,"sourceLabel":"2023年福建省事业单位47%","accuracy":47,"typeAndPassage":"标题拟定类+说理类文章","stemRich":[{"text":"这个文本数据化的时代，几乎市面上所有的书籍都能找到它的电子版，就连静静地躺在藏书室里的古籍也被搬进了虚拟世界。然而，就在这网络快速发展的“读屏时代”,仍有这样一群人，用他们的坚守与情怀，守候着一家家旧书店，留住一片片静谧与光阴，让人们还能在旧书卷的书香中回忆蕉窗听雨的静思，体味图书馆午后的慵懒闲适。\n最适合做这段文字标题的是："}],"optionRich":{"A":[{"text":"“读屏时代”的旧书店"}],"B":[{"text":"旧书店的坚守者"}],"C":[{"text":"“读屏时代”的快与慢"}],"D":[{"text":"旧书店的书卷气"}]},"annotatedStemRich":[{"text":"这个文本数据化的时代，几乎市面上所有的书籍都能找到它的电子版，就连静静地躺在藏书室里的古籍也被搬进了虚拟世界。然而，就在这网络快速发展的“读屏时代”,仍有这样一群人，用他们的坚守与情怀，守候着一家家旧"},{"text":"书店","underline":true},{"text":"，留住一片片静谧与光阴，让人们还能在旧书卷的书香中回忆蕉窗听雨的静思，体味图书馆午后的慵懒闲适(转折引出观点)。①\n最适合做这段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"“读屏时代”的旧书店(缺关键词)"}],"B":[{"text":"旧书店的坚守者"}],"C":[{"text":"“读屏时代”的快与慢(缺关键词)"}],"D":[{"text":"旧书店的书卷气(缺关键词)"}]},"practicalAnalysis":"文段分析见批注。\n文段转折后提出在“读屏时代”仍有人用坚守与情怀守候旧书店；转折后内容为重点，正确选项应体现“坚守”,对应B选项，当选；\nA选项、C选项、D选项未提及“坚守”,均可排除。","notes":[{"marker":"⑯","content":"旧书店是全文论述主题。","matchScore":0.2523,"pairingMode":"content-similarity","order":15},{"marker":"⑰","content":"行文结构：二层结构之转折。转折前：介绍文本数据化的时代，书籍几乎都能找到电子版；\n转折后：仍有人坚持守候旧书店。\n最适合做这段文字标题的是：\nA. “读屏时代”的旧书店(缺关键词)\nB. 旧书店的坚守者\nC. “读屏时代”的快与慢(缺关键词)\nD. 旧书店的书卷气(缺关键词)","matchScore":0.7027,"pairingMode":"content-similarity","order":16}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300429,3,'细节判断题','比殷墟更早的牛文物，是陈列在桐乡市博物馆的一件骨耜，这是乌镇文体站清理遗址淤泥时，发现的一块牛肩胛骨，长14.5厘米，宽6.8厘米，中间的孔洞说明古人曾经精心打制过。桐乡市石门罗家角遗址，曾经发掘出7000年前后人工栽培的籼稻和粳稻。这件牛骨耜与之时间相近，说明先祖由采摘水稻为主的农业生产，在向耜耕时期迈进。一叶知秋，一件牛骨耜激活了那个遥远的时代。
根据这段文字，下列说法中不正确的一项是：','[{"label":"A","content":"乌镇文体站发现的牛肩胛骨比殷墟还早"},{"label":"B","content":"桐乡市博物馆的骨耜是古人精心打制的艺术品"},{"label":"C","content":"桐乡市石门罗家角遗址发掘出的籼稻和粳稻很可能是骨耜耕种出来的"},{"label":"D","content":"“那个遥远的年代”是指先祖由采摘时期向耜耕时期迈进的时代"}]','B','根据③句的“这件牛骨耜与之时间相近，说明先祖由采摘水稻为主的农业生产，在向耜耕时期迈进。”可知，骨耜是一件农具，并非“艺术品”,B选项错误，当选。

