INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300432,3,'下文推断②','当《枪支管理法》通过的时候，受到该法禁止的攻击性武器之中，有一种是仿苏式半自动步枪 AK47。仅此一种型号，美国民间当时就已经有100万支。最近20年美国校园不断发生恶性枪击事件，见诸世界各大媒体，并引发了一场有关《枪支管理法》的大讨论。看了大量的类似报道，国人一定会想为什么美国允许公民拥有枪支。
作者接下来最有可能介绍的是：','[{"label":"A","content":"美国各界对《枪支管理法》的观点"},{"label":"B","content":"近年来美国发生的各类枪击案件的特点"},{"label":"C","content":"当前美国政府对于民间枪支的管理制度"},{"label":"D","content":"美国各个时期的法律关于公民拥有枪支的规定"}]','D','文段分析见批注。
文段先是论述了美国不断发生恶性枪击事件引发媒体大讨论，尾句引出问题：为什么美国允许公民拥有枪支。上文给出问题，下文应分析解答问题。 D选项介绍了各个时期美国法律关于公民拥有枪支的规定，通过枪支管理规定的发展过程和变化经过可以窥见“为什么美国允许公民拥有枪支”,D选项可以回答上文文末问题，当选。
其他选项：“美国各界的观点”和“枪支案特点”无法解释为什么美国允许公民拥有枪支，排除；C选项介绍当前的管理制度，但当前的管理制度不如“各个时期枪支管理制度的变化”更能解释美国允许公民拥有枪支的原因，排除。

