INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300434,3,'语句填入类','中国刑法学要取得真正的发展，根本的出路在于密切关注司法实践和社会实践，。这一效果的达到与学术论争及对抗的出现须臾不可分离。在对抗中发现问题，从而讨论一些刑法学中的“真”问题，理论体系的合理建构才有可能。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"将理论与实践紧密联系"},{"label":"B","content":"认真研究实实在在的案例"},{"label":"C","content":"立足于解决有中国特色的具体问题"},{"label":"D","content":"避免过多纠缠于浅层次的重复性问题\n练习题 2 2 套"}]','C','文段分析见批注。
四个选项均为对策表述，我们可以根据整段的对策确定所填入对策。②句作用为引出③句，概括①③句现有对策即可，即：中国刑法学理论的构建和发展需要关注实践，需要在实践的对抗中发现问题，从而讨论刑法学中的真问题。
由上述对策可知，所填入语句应体现“实践中要关注真问题”,呼应下文对策，对应C选项，且“中国刑法学”要立足于解决有“中国特色的具体问题”政治正确、逻辑正确，可看作完美选项，当选；
其他选项：B选项的“认真研究案例”和D选项的“避免过多纠缠浅层次问题”均无中生有，排除；A选项为强干扰项，虽然“将理论与实践紧密联系⑩”对应了上文，但与下文的具体对策无关，也未提及“问题”,不如C选项恰当，排除。公考最新资料、更新进度微信SKA674

花生批注：
29 文段三句话可依次分析：
①介绍中国刑法学要取得真正发展的根本出路在于关注实践，
②介绍中国刑法学要取得真正发展离不开学术论争及对抗；
③介绍中国刑法学理论体系的合理构建需要在学术对抗中发现问题，从而讨论刑法学中的一些真问题。
