INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300447,3,'中心理解题','所有作品都迫使或者说是启示我们要静下心来，要努力使诗歌保持朴素的品格，要经常默念“敲打”这个词，要让它在耳边震荡、回响，它要像一把锤子来到手上，要敲掉那些多余的、浮华的、虚妄的东西，比如那些夸张的、沉滞的，缺乏生命力的想象，或者那些硬拼凑上去的、所谓的“意义”等等—— 这些东西应被彻底敲掉，从而使诗歌变得结实、有力，露出筋和骨。
这段话的主旨是：','[{"label":"A","content":"意义对于诗歌来说并不重要"},{"label":"B","content":"朴素是诗歌应有的品质"},{"label":"C","content":"读诗需要平心静气"},{"label":"D","content":"诗歌要经常去“敲打”"}]','D','文段分析见批注。
文段开篇直接给出对策，对策部分核心为“敲打”,根据对策句和后文论证可确定主语为“诗歌”,直接对应D选项。
A选项非对策表述，且A选项的“意义对诗歌不重要”无中生有，排除。
B选项可以理解为“诗歌要朴素”,属于对策表达，C选项的“平心静气”
出自文段对策部分，具有干扰性，但分析论证部分谈论的是敲打的意义，由此可确定“敲打”为对策重点，B选项、C选项排除；另外，文段主语是诗歌，“敲打掉一些东西”是写诗时要做了，非读诗，C选项排除。
综上，答案为D选项。

花生批注：
⑫ 行文结构：前对策结构；
文段开篇给出对策：
诗歌需要敲打，要敲打掉多余的、浮华的、虚妄的东西；后文进行分析论证：
这样能够使诗歌变得结实、有力，露出筋和骨。
