INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300448,3,'中心理解题','穿着汉服等传统服饰、一次又一次地“复习”国乐跨界视频，是不少年轻人眼里的古风时尚。近些年古风逐渐被大众了解、接受并喜爱。古风文化作为一个圈层文化，尤其在年轻人中间有较大的吸引力。谈到“李子柒为什么这么火”时，业界普遍认为，除了得益于李子柒在商业运作上的高超得当，也与古风在时下的流行风潮密不可分。这归根结底是年轻人对传统文化的认同和向往。
这段文字最后一句话中的“这”指的是：','[{"label":"A","content":"穿着汉服等传统服饰"},{"label":"B","content":"年轻人喜欢并追求古风文化"},{"label":"C","content":"李子柒为什么这么火"},{"label":"D","content":"古风对于大众的吸引力"}]','B','文段分析见批注。
文段尾句由“这”总结上文的“果”并给出原因分析；“这”指代的是上文“年轻人喜欢古风文化(果)”这一现象，对应 B选项，当选；
A选项片面，“穿着汉服等传统服饰”仅为喜欢古风的一种表现，排除； C选项出处有误，例子部分非重点，且李子柒火的原因已经介绍(和古风流行有关 ) , 排除；D选项缺少主体“年轻人”,排除。

花生批注：
⑬ 年轻人是全文论述主体。
⑭ 行文结构：二层结构之果因。文段先介绍什么是年轻人眼中的古风时尚；再介绍近年来古风被大众接受并喜爱，古风文化对年轻人有很大吸引力；举例李子柒被喜欢就和古风流行有关；
可将上述总结为：年轻人喜欢古风文化(果);
文末给出原因：年轻人喜欢古风文化是因为年轻人对传统文化的认同和向往。
这段文字最后一句话中的“这”指的是：
A. 穿着汉服等传统服饰(片面)
B. 年轻人喜欢并追求古风文化
C. 李子柒为什么这么火(出处有误)
D. 古风对于大众的吸引力(缺少主题词)','2021年新疆省考','进阶','published','{"globalNumber":448,"setNumber":23,"localNumber":8,"sourceLabel":"2021年新疆省考53%","accuracy":53,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"穿着汉服等传统服饰、一次又一次地“复习”国乐跨界视频，是不少年轻人眼里的古风时尚。近些年古风逐渐被大众了解、接受并喜爱。古风文化作为一个圈层文化，尤其在年轻人中间有较大的吸引力。谈到“李子柒为什么这么火”时，业界普遍认为，除了得益于李子柒在商业运作上的高超得当，也与古风在时下的流行风潮密不可分。这归根结底是年轻人对传统文化的认同和向往。\n这段文字最后一句话中的“这”指的是："}],"optionRich":{"A":[{"text":"穿着汉服等传统服饰"}],"B":[{"text":"年轻人喜欢并追求古风文化"}],"C":[{"text":"李子柒为什么这么火"}],"D":[{"text":"古风对于大众的吸引力"}]},"annotatedStemRich":[{"text":"穿着汉服等传统服饰、一次又一次地“复习”国乐跨界视频，是不少"},{"text":"年轻","underline":true},{"text":"人⑤眼里的古风时尚。近些年古风逐渐被大众了解、接受并喜爱。古风文化作为一个圈层文化，尤其在年轻人中间有较大的吸引力。谈到“李子柒为什么这么火”时，业界普遍认为，除了得益于李子柒在商业运作上的高超得当，也与古风在时下的流行风潮密不可分( 果：年轻人喜欢古风文化)。这归根结底是年轻人对传统文化的认同和向往("},{"text":"因：年轻人对传统文化的认同和向往)。⑭","bold":true},{"text":"\n这段文字最后一句话中的“这”指的是："}],"annotatedOptionRich":{"A":[{"text":"穿着汉服等传统服饰(片面)"}],"B":[{"text":"年轻人喜欢并追求古风文化"}],"C":[{"text":"李子柒为什么这么火(出处有误)"}],"D":[{"text":"古风对于大众的吸引力(缺少主题词)"}]},"practicalAnalysis":"文段分析见批注。\n文段尾句由“这”总结上文的“果”并给出原因分析；“这”指代的是上文“年轻人喜欢古风文化(果)”这一现象，对应 B选项，当选；\nA选项片面，“穿着汉服等传统服饰”仅为喜欢古风的一种表现，排除； C选项出处有误，例子部分非重点，且李子柒火的原因已经介绍(和古风流行有关 ) , 排除；D选项缺少主体“年轻人”,排除。","notes":[{"marker":"⑬","content":"年轻人是全文论述主体。","matchScore":0.3608,"pairingMode":"content-similarity","order":12},{"marker":"⑭","content":"行文结构：二层结构之果因。文段先介绍什么是年轻人眼中的古风时尚；再介绍近年来古风被大众接受并喜爱，古风文化对年轻人有很大吸引力；举例李子柒被喜欢就和古风流行有关；\n可将上述总结为：年轻人喜欢古风文化(果);\n文末给出原因：年轻人喜欢古风文化是因为年轻人对传统文化的认同和向往。\n这段文字最后一句话中的“这”指的是：\nA. 穿着汉服等传统服饰(片面)\nB. 年轻人喜欢并追求古风文化\nC. 李子柒为什么这么火(出处有误)\nD. 古风对于大众的吸引力(缺少主题词)","matchScore":0.88,"pairingMode":"marker-and-content","order":13}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300449,3,'细节判断类','每一次全球化浪潮都是由技术变革推动社会经济的变革而实现的。数字经济不同于工业经济和农业经济，其发展受土地、劳动力等因素限制很小，天然具有全球性竞争态势。新冠疫情发生后，数字经济的产业赋能作用增强，跨越性创新频发，正在对既有产业形成冲击并使产业竞争格局发生重构。尤其是近年来单边主义日益盛行，我国数字经济的国际影响力可能因此受到挑战，为适应跨国企业全球价值链呈现的数字化、服务化、去中介化、定制化新趋势，我国应坚持市场需求导向，以技术创新驱动促进要素集约和资源节约化配置。
下列说法符合文意的是：','[{"label":"A","content":"数字经济可以不受土地、劳动力等因素的限制"},{"label":"B","content":"数字经济产生之初是不具有全球性竞争态势的"},{"label":"C","content":"新冠疫情发生后数字经济已重构产业竞争格局"},{"label":"D","content":"跨国企业全球价值链已呈现出去中介化新趋势"}]','D','根据④句的“为适应跨国企业全球价值链呈现的数字化、服务化、去中介化、定制化新趋势，我国应……”可知，跨国企业全球价值链已呈现去中介化新趋势，D选项表述正确，当选。

花生批注：
⑯ 根据②句可知，数字经济受土地、劳动力等因素限制较小，而非“不受限制”,错误。
⑪ 根据②句可知，数字经济天然具有全球性竞争态势，“产生之初不具有竞争态势”错误。
⑱ 根据③句可知，新冠疫情发生后，数字经济正使产业竞争格局发生重构，而非“已重构”。','2022年江苏省事业单位','进阶','published','{"globalNumber":449,"setNumber":23,"localNumber":9,"sourceLabel":"2022年江苏省事业单位 54%","accuracy":54,"typeAndPassage":"细节判断类","stemRich":[{"text":"每一次全球化浪潮都是由技术变革推动社会经济的变革而实现的。数字经济不同于工业经济和农业经济，其发展受土地、劳动力等因素限制很小，天然具有全球性竞争态势。新冠疫情发生后，数字经济的产业赋能作用增强，跨越性创新频发，正在对既有产业形成冲击并使产业竞争格局发生重构。尤其是近年来单边主义日益盛行，我国数字经济的国际影响力可能因此受到挑战，为适应跨国企业全球价值链呈现的数字化、服务化、去中介化、定制化新趋势，我国应坚持市场需求导向，以技术创新驱动促进要素集约和资源节约化配置。\n下列说法符合文意的是："}],"optionRich":{"A":[{"text":"数字经济可以不受土地、劳动力等因素的限制"}],"B":[{"text":"数字经济产生之初是不具有全球性竞争态势的"}],"C":[{"text":"新冠疫情发生后数字经济已重构产业竞争格局"}],"D":[{"text":"跨国企业全球价值链已呈现出去中介化新趋势"}]},"annotatedStemRich":[{"text":"①每一次全球化浪潮都是由技术变革推动社会经济的变革而实现的。( A 选项)②数字经济不同于工业经济和农业经济，其发展受土地、劳动力等因素限制很小，"},{"text":"天然具有全球性竞争态势","underline":true},{"text":"⑤。( B 选项 )③新冠疫情发生后，数字经济的产业赋能作用增强，跨越性创新频发，正在对既有产业形成冲击并使产业竞争格局发生重构。( C 选项)④尤其是近年来单边主义日益盛行，我国数字经济的国际影响力可能因此受到挑战，为适应跨国企业全球价值链呈现的数字化、服务化、去中介化、定制化新趋势，我国应坚持市场需求导向，以技术创新驱动促进要素集约和资源节约化配置。\n下列说法符合文意的是："}],"annotatedOptionRich":{"A":[{"text":"数字经济可以不受土地、劳动力等因素的限制"},{"text":"(绝对化)⑩","bold":true}],"B":[{"text":"数字经济产生之初是不具有全球性竞争态势的"},{"text":"(本身有误)②","bold":true}],"C":[{"text":"新冠疫情发生后数字经济已重构产业竞争格局"},{"text":"(混淆时态)","bold":true},{"text":" ⑱"}],"D":[{"text":"跨国企业全球价值链已呈现出去中介化新趋势"}]},"practicalAnalysis":"根据④句的“为适应跨国企业全球价值链呈现的数字化、服务化、去中介化、定制化新趋势，我国应……”可知，跨国企业全球价值链已呈现去中介化新趋势，D选项表述正确，当选。","notes":[{"marker":"⑯","content":"根据②句可知，数字经济受土地、劳动力等因素限制较小，而非“不受限制”,错误。","matchScore":0.6454,"pairingMode":"content-similarity","order":14},{"marker":"⑪","content":"根据②句可知，数字经济天然具有全球性竞争态势，“产生之初不具有竞争态势”错误。","matchScore":0.6555,"pairingMode":"content-similarity","order":15},{"marker":"⑱","content":"根据③句可知，新冠疫情发生后，数字经济正使产业竞争格局发生重构，而非“已重构”。","matchScore":0.8244,"pairingMode":"marker-and-content","order":16}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300450,3,'细节判断类','半坡型彩陶文化是仰韶文化中历史较早，特点突出，影响较大的一个类型。器形丰富，多见圆底或平底钵、平底盆、鼓腹罐、细颈瓶。彩陶器的装饰纹样采用散点式构图，“鱼纹”和“人面鱼纹”以及由鱼头、鱼身演化而来的几何纹是半坡类型中最具特色的彩陶纹样。半坡型彩陶器造型规正，纹饰简洁生动，富有浓郁的原始气息，是当时经济、社会生活的艺术记录；同时反映了原始先民质朴的审美意识。
这段文字没有提及“半坡型彩陶”的：','[{"label":"A","content":"历史由来"},{"label":"B","content":"艺术美感"},{"label":"C","content":"文化类型"},{"label":"D","content":"器形图案"}]','A','④句介绍半坡型彩陶“造型规正，纹饰简洁生动，富有浓郁的原始气息， ……,反映了原始先民质朴的审美意识”,对应艺术美感；①句介绍了半坡型彩陶的文化类型；②③句介绍了半坡型彩陶的器型和图案；
虽然首句提及“半坡型彩陶文化是仰韶文化中历史较早的一个类型”,但“历史较早”并非具体的“历史由来⑨”,故没有提及历史由来，答案为A选项。

花生批注：
⑲ 造型规正，纹饰简洁生动，富有浓郁的原始气息，是当时经济、社会生活的艺术记录；同时反映了原始先民质朴的审美意识','2020年四川省事业单位','进阶','published','{"globalNumber":450,"setNumber":23,"localNumber":10,"sourceLabel":"2020年四川省事业单位61%","accuracy":61,"typeAndPassage":"细节判断类","stemRich":[{"text":"半坡型彩陶文化是仰韶文化中历史较早，特点突出，影响较大的一个类型。器形丰富，多见圆底或平底钵、平底盆、鼓腹罐、细颈瓶。彩陶器的装饰纹样采用散点式构图，“鱼纹”和“人面鱼纹”以及由鱼头、鱼身演化而来的几何纹是半坡类型中最具特色的彩陶纹样。半坡型彩陶器造型规正，纹饰简洁生动，富有浓郁的原始气息，是当时经济、社会生活的艺术记录；同时反映了原始先民质朴的审美意识。\n这段文字没有提及“半坡型彩陶”的："}],"optionRich":{"A":[{"text":"历史由来"}],"B":[{"text":"艺术美感"}],"C":[{"text":"文化类型"}],"D":[{"text":"器形图案"}]},"annotatedStemRich":[{"text":"①半坡型彩陶文化是仰韶文化中历史较早，特点突出，影响较大的一个类型。②器形丰富，多见圆底或平底钵、平底盆、鼓腹罐、细颈瓶。③彩陶器的装饰纹样采用散点式构图，“鱼纹”和“人面鱼纹”以及由鱼头、鱼身演化而来的几何纹是半坡类型中最具特色的彩陶纹样。④半坡型彩陶器造型规正，纹饰简洁生动，富有浓郁的原始气息，是当时经济、社会生活的艺术记录；同时反映了原始先民质朴的审美意识。\n这段文字没有提及“半坡型彩陶”的："}],"annotatedOptionRich":{"A":[{"text":"历史由来"}],"B":[{"text":"艺术美感"}],"C":[{"text":"文化类型"}],"D":[{"text":"器形图案"}]},"practicalAnalysis":"④句介绍半坡型彩陶“造型规正，纹饰简洁生动，富有浓郁的原始气息， ……,反映了原始先民质朴的审美意识”,对应艺术美感；①句介绍了半坡型彩陶的文化类型；②③句介绍了半坡型彩陶的器型和图案；\n虽然首句提及“半坡型彩陶文化是仰韶文化中历史较早的一个类型”,但“历史较早”并非具体的“历史由来⑨”,故没有提及历史由来，答案为A选项。","notes":[{"marker":"⑲","content":"造型规正，纹饰简洁生动，富有浓郁的原始气息，是当时经济、社会生活的艺术记录；同时反映了原始先民质朴的审美意识","matchScore":1.1846,"pairingMode":"content-similarity","order":17}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300451,3,'下文推断类2⑳','民族文化要有根基，精神文明的传承要有载体，而城市正是其集大成者。放眼世界，历史文化名城和现代国际大都市，座座堪称文化艺术宫殿、建筑博物馆，从民主城邦雅典到人文之城威尼斯，从时尚之都巴黎到音乐之城维也纳，独特的文化精神令城市历经千年，依然灿烂。
文章接下来最可能讲：','[{"label":"A","content":"各具文化特色的世界名城"},{"label":"B","content":"要用文化精神来涵养和提升城市品位"},{"label":"C","content":"城市建设和发展要彰显特色和魅力"},{"label":"D","content":"民族文化是如何传承的"}]','B','文段分析见批注。
文段全篇都在介绍城市和文化的关系②,并列举了一些文化名城，故下文应继续围绕“文化和城市”这个话题展开论述。
A选项上文已提到过(雅典、威尼斯、巴黎、维也纳),下文不会继续谈论；C选项缺少主题词“文化”、D选项缺少主题词“城市”,均可简单排除。只有B选项包含主题词“文化”和“城市”,当选②。

花生批注：
② 通过文段首句和尾句可知：
1. 城市是精神文明和文化的载体；
2. 独特的文化精神令城市历经千年，依然灿烂。
2 文段亦可看成“后对策结构”开篇引出话题：城市是文化和精神文明的载体；
中间举例论证：世界各地的文化名城因独特的文化精神历经千年，依然灿烂；
故下文应给出对策：如何用文化让城市历经千年，依然灿烂，对应到B选项。
38 非遗是全文论述主题。','2014年黑龙江省考','进阶','published','{"globalNumber":451,"setNumber":23,"localNumber":11,"sourceLabel":"2014年黑龙江省考59%","accuracy":59,"typeAndPassage":"下文推断类2⑳","stemRich":[{"text":"民族文化要有根基，精神文明的传承要有载体，而城市正是其集大成者。放眼世界，历史文化名城和现代国际大都市，座座堪称文化艺术宫殿、建筑博物馆，从民主城邦雅典到人文之城威尼斯，从时尚之都巴黎到音乐之城维也纳，独特的文化精神令城市历经千年，依然灿烂。\n文章接下来最可能讲："}],"optionRich":{"A":[{"text":"各具文化特色的世界名城"}],"B":[{"text":"要用文化精神来涵养和提升城市品位"}],"C":[{"text":"城市建设和发展要彰显特色和魅力"}],"D":[{"text":"民族文化是如何传承的"}]},"annotatedStemRich":[{"text":"民族文化要有根基，精神文明的传承要有载体，而城市正是其集大成者。放眼世界，历史文化名城和现代国际大都市，座座堪称文化艺术宫殿、建筑博物馆，从民主城邦雅典到人文之城威尼斯，从时尚之都巴黎到音乐之城维也纳，独特的文化精神令城市历经千年，依然灿烂。\n文章接下来最可能讲："}],"annotatedOptionRich":{"A":[{"text":"各具文化特色的世界名城(上文已论述)"}],"B":[{"text":"要用文化精神来涵养和提升城市品位"}],"C":[{"text":"城市建设和发展要彰显特色和魅力"},{"text":"(缺主题词)","bold":true}],"D":[{"text":"民族文化是如何传承的"},{"text":"(缺主题词)","bold":true},{"text":"\n"},{"text":"②⑳花生批注：","bold":true},{"text":"\n"},{"text":"下文推断的常见结构：","bold":true},{"text":"\n①上文文末提出新内容→下文解释新内容\n②上文提出问题→下文分析问题、解决问题\n③上文给出宏观对策、原因等→下文具体展开\n④时间对比：过去不行→现在有了新突破\n⑤总分：上文是总+分→下文补充另一“分”\n⑥转折\n②"},{"text":"花生批注：","bold":true},{"text":"\n通过文段首句和尾句可知：\n1. 城市是精神文明和文化的载体；\n2. 独特的文化精神令城市历经千年，依然灿烂。\n2 "},{"text":"花生批注：","bold":true},{"text":"\n文段亦可看成“后对策结构”"},{"text":"开篇引出话题：","bold":true},{"text":"城市是文化和精神文明的载体；\n"},{"text":"中间举例论证：","bold":true},{"text":"世界各地的文化名城因独特的文化精神历经千年，依然灿烂；\n"},{"text":"故下文应给出对策：","bold":true},{"text":"如何用文化让城市历经千年，依然灿烂，对应到B选项。\n"},{"text":"3花生批注：","bold":true},{"text":"\n"},{"text":"下文推断的常见结构：","bold":true},{"text":"\n①上文文末提出新内容→下文解释新内容\n②上文提出问题→下文分析问题、解决问题\n③上文给出宏观对策、原因等→下文具体展开\n④时间对比：过去不行→现在有了新突破\n⑤总分：上文是总+分→下文补充另一“分”\n⑥转折"}]},"practicalAnalysis":"文段分析见批注。\n文段全篇都在介绍城市和文化的关系②,并列举了一些文化名城，故下文应继续围绕“文化和城市”这个话题展开论述。\nA选项上文已提到过(雅典、威尼斯、巴黎、维也纳),下文不会继续谈论；C选项缺少主题词“文化”、D选项缺少主题词“城市”,均可简单排除。只有B选项包含主题词“文化”和“城市”,当选②。","notes":[{"marker":"②","content":"通过文段首句和尾句可知：\n1. 城市是精神文明和文化的载体；\n2. 独特的文化精神令城市历经千年，依然灿烂。","matchScore":0.6964,"pairingMode":"marker-and-content","order":19},{"marker":"2","content":"文段亦可看成“后对