INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300457,3,'语句排序题','①一般认为，花外蜜腺可以吸引嗜好甜食的捕食性昆虫，让它们充当“巡逻兵”,帮助植株驱赶植食性昆虫
②蜜腺是分泌糖液的外分泌结构，从花蜜腺分泌出富含糖类的汁液，是虫媒植物为访花者提供的报酬之一
③如果仔细观察，就能发现凌霄属植物的小秘密：它的花冠、花萼、叶柄、果皮上都有花外蜜腺的分布，能够分泌蜜露，但不参与传粉
④虽然目前已知拥有花外蜜腺的植物接近4000种，但像凌霄属植物这样“甜遍全身”的，却并不多见
⑤但是为了更好地生存，凌霄使出浑身解数，进化出发达的花外蜜腺，让自己浑身上下都能分泌蜜露
⑥这是植物为实现自我保护目的，而与捕食性昆虫形成的一种共生机制将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"①②④⑥⑤③"},{"label":"B","content":"②⑤④③①⑥"},{"label":"C","content":"③④⑥②①⑤"},{"label":"D","content":"④③②⑤⑥①"}]','B','观察首句，②句介绍蜜腺，①③④均提及“花外蜜腺”,根据逻辑应先引出定义再介绍，②适合做首句，锁定B选项；
验证B选项：②介绍蜜腺，⑤转折引出“凌霄进化出‘花外蜜腺’”,④③介绍带有花外蜜腺的凌霄属植物，①⑥介绍花外蜜腺的作用和功能，逻辑正确，当选。

花生批注：
③ ②引出蜜腺，⑤引出“花外蜜腺”,提及花外蜜腺的
①③④均应在②⑤之后，可秒选。
⑥这是植物为实现自我保护目的，而与捕食性昆虫形成的一种共生机制将以上6个句子重新排列，语序正确的一项是：
A.①②④⑥⑤③ B.②⑤④③①⑥
