INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300458,3,'中心理解题','如今，年轻的新生代家长普遍接受过完善的高等教育，一些人还有海外学习和生活的经历，对子女的启蒙教育有着自己的理解和要求。进口的动画片，无论在叙事风格还是在表现手法上，都更接近他们的审美标准。与此同时，儿童的理解能力也在上升，他们可以更早地观察和理解世界。其实，国内并非没有这样的动画资源，像《西游记》之所以成为经典，屡被改编，屡受欢迎，就因为它的神话体系是现实的投射。关键的问题还是在于国内的制作人有没有深度思索、挖掘现实的能力。
从这段文字可以看出作者的观点是：','[{"label":"A","content":"国产动画的不景气源于制作人不佳"},{"label":"B","content":"我国动画产业应多向国外同行学习"},{"label":"C","content":"国产动画应跟上观众群的审美要求"},{"label":"D","content":"国内实际并不缺少优秀的动画素材"}]','C','文段分析见批注。
文段可看作转折后提出对策：国内动画制作人应深度思索和挖掘现实，以
满足观众新的审美标准； C选项是对策的同义替换，当选；
A选项的“国产动画不景气”和“制作人不佳”均无中生有，且为问题表述，无法对应对策，排除； B选项对策有误，“向国外同行学习”无中生有，排除； D选项出处有误，出自对策前分析部分，排除。

花生批注：
③ 行文结构：后对策结构。
转折前引出话题：
介绍新生代年轻家长有了新的动画审美标准，同时，儿童也有了更强的理解力(可概括为新生代家长和儿童都有新的审美标准);
转折后引出对策：
介绍国内有符合观众新审美标准的动画资源，关键在于制作人的深度思索和挖掘现实(以达到观众新的审美标准 )。
从这段文字可以看出作者的观点是：
A. 国产动画的不景气源于制作人不佳(偷换概念)
B. 我国动画产业应多向国外同行学习(对策有误)
C. 国产动画应跟上观众群的审美要求
D. 国内实际并不缺少优秀的动画素材(中性表述)
四海公考练习题23套
SIHAI
KAO
33 有同学可能会疑惑：C选项未提及“制作人”可以吗? 我认为这一问题可忽略，因为动画制作必须依靠人来完成，尤其是文段提到国产动画资源没有问题(但制作人需要动画资源),那么“国产动画要跟上观众群审美要求”就是“国产动画制作人应跟上观众群审美要求”; 例如“中国作家应该更加贴近基层”,即“中国文学作品应更加贴近基层”。
③④ “国内动画不景气”也与“西游记屡被改编屡受欢迎”矛盾。
35 作者观点是为国产动画出谋划策，提出对策；而非否定国产动画发展，为其分析“不景气”的原因。
例如：如今，想考上公务员有了更高的要求和标准。其实，小李并非没有能力，关键的问题还是能不能稳定住心态、把握住机会。
文段重点是对策：小李要稳住心态，把握机会；
而非分析因果关系：小李现状不佳源于心态不稳，不能把握机会。','2018年广西选调','挑战','published','{"globalNumber":458,"setNumber":23,"localNumber":18,"sourceLabel":"2018年广西选调 44%","accuracy":44,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"如今，年轻的新生代家长普遍接受过完善的高等教育，一些人还有海外学习和生活的经历，对子女的启蒙教育有着自己的理解和要求。进口的动画片，无论在叙事风格还是在表现手法上，都更接近他们的审美标准。与此同时，儿童的理解能力也在上升，他们可以更早地观察和理解世界。其实，国内并非没有这样的动画资源，像《西游记》之所以成为经典，屡被改编，屡受欢迎，就因为它的神话体系是现实的投射。关键的问题还是在于国内的制作人有没有深度思索、挖掘现实的能力。\n从这段文字可以看出作者的观点是："}],"optionRich":{"A":[{"text":"国产动画的不景气源于制作人不佳"}],"B":[{"text":"我国动画产业应多向国外同行学习"}],"C":[{"text":"国产动画应跟上观众群的审美要求"}],"D":[{"text":"国内实际并不缺少优秀的动画素材"}]},"annotatedStemRich":[{"text":"如今，年轻的新生代家长普遍接受过完善的高等教育，一些人还有海外学习和生活的经历，对子女的启蒙教育有着自己的理解和要求。进口的动画片，无论在叙事风格还是在表现手法上，都更接近他们的审美标准。与此同时，儿童的理解能力也在上升，他们可以更早地观察和理解世界(引出话题)。其实，国内并非没有这样的动画资源，像《西游记》之所以成为经典，屡被改编，屡受欢迎，就因为它的神话体系是现实的投射。关键的问题还是在于国内的制作人有没有深度思索、挖掘现实的能力(提出对策)。②\n从这段文字可以看出作者的观点是："}],"annotatedOptionRich":{"A":[{"text":"国产动画的不景气源于制作人不佳"},{"text":"(偷换概念)","bold":true}],"B":[{"text":"我国动画产业应多向国外同行学习(对策有误)"}],"C":[{"text":"国产动画应跟上观众群的审美要求"}],"D":[{"text":"国内实际并不缺少优秀的动画素材"},{"text":"(中性表述)","bold":true},{"text":"\n"},{"text":"四海公考练习题23套","bold":true},{"text":"\n"},{"text":"GONG","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段可看作转折后提出对策：国内动画制作人应深度思索和挖掘现实，以\n满足观众新的审美标准； C选项是对策的同义替换，当选；\nA选项的“国产动画不景气”和“制作人不佳”均无中生有，且为问题表述，无法对应对策，排除； B选项对策有误，“向国外同行学习”无中生有，排除； D选项出处有误，出自对策前分析部分，排除。","notes":[{"marker":"③","content":"行文结构：后对策结构。\n转折前引出话题：\n介绍新生代年轻家长有了新的动画审美标准，同时，儿童也有了更强的理解力(可概括为新生代家长和儿童都有新的审美标准);\n转折后引出对策：\n介绍国内有符合观众新审美标准的动画资源，关键在于制作人的深度思索和挖掘现实(以达到观众新的审美标准 )。\n从这段文字可以看出作者的观点是：\nA. 国产动画的不景气源于制作人不佳(偷换概念)\nB. 我国动画产业应多向国外同行学习(对策有误)\nC. 国产动画应跟上观众群的审美要求\nD. 国内实际并不缺少优秀的动画素材(中性表述)\n四海公考练习题23套\nSIHAI\nKAO","matchScore":0.6157,"pairingMode":"content-similarity","order":30},{"marker":"33","content":"有同学可能会疑惑：C选项未提及“制作人”可以吗? 我认为这一问题可忽略，因为动画制作必须依靠人来完成，尤其是文段提到国产动画资源没有问题(但制作人需要动画资源),那么“国产动画要跟上观众群审美要求”就是“国产动画制作人应跟上观众群审美要求”; 例如“中国作家应该更加贴近基层”,即“中国文学作品应更加贴近基层”。","matchScore":0.2813,"pairingMode":"content-similarity","order":31},{"marker":"③④","content":"“国内动画不景气”也与“西游记屡被改编屡受欢迎”矛盾。","matchScore":0.765,"pairingMode":"content-similarity","order":32},{"marker":"35","content":"作者观点是为国产动画出谋划策，提出对策；而非否定国产动画发展，为其分析“不景气”的原因。\n例如：如今，想考上公务员有了更高的要求和标准。其实，小李并非没有能力，关键的问题还是能不能稳定住心态、把握住机会。\n文段重点是对策：小李要稳住心态，把握机会；\n而非分析因果关系：小李现状不佳源于心态不稳，不能把握机会。","matchScore":0.3444,"pairingMode":"content-similarity","order":33}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300459,3,'中心理解题','长期以来，猕猴乃至人类以外的其他灵长类动物说不了“人话”,有人推测这与它们的声带缺陷有关。研究人员利用X光成像，建立猕猴声带电脑模型。分析结果显示猕猴很容易就能发出许多不同的声音，包括英语字母中最基本的5个元音。研究人员据此推测，如果猕猴能像人类那样思考，那么它们将能说出数千个单词，甚至完整的句子。
上述材料重在说明：','[{"label":"A","content":"语言能力不仅需要声带的变化，更需要大脑的思考"},{"label":"B","content":"猕猴不能像人类那样思考导致它们说不了“人话”"},{"label":"C","content":"猕猴若能思考将拥有与人类一样的语言能力"},{"label":"D","content":"猕猴的声带缺陷导致它们无法正常说话"}]','B','文段分析见批注。
文段可看作古今对比结构，先介绍了过去的观点：猕猴及其他灵长类动物不会说话和声带缺陷有关，之后通过实验推翻老观点并提出新观点“如果猕猴能像人类那样思考，那么它们将能说出数千个单词，甚至完整的句子”。 B选项为新观点的同义替换，当选； ③
A选项缺少主语“猕猴”;C选项无中生有，“能说出数千个单词，甚至完整的句子”不意味着和人类有一样的语言能力；D选项为老观点，已经被推翻，排除。

花生批注：
36 行文结构：二层结构—古今对比。
过去观点：
猕猴及其他灵长类动物不会说话和声带缺陷有关；
现在观点：
新研究发现猕猴不会说话
(和声带无关)是因为不会思考。
③ 此题类似于逻辑里的归因题。
老观点认为“猕猴说不了人话的原因是声带缺陷”。新观点为“否定此因+另有他因”来质疑老观点，同时也是文段的主旨。','2022年福建省事业单位','挑战','published','{"globalNumber":459,"setNumber":23,"localNumber":19,"sourceLabel":"2022年福建省事业单位 36%","accuracy":36,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"长期以来，猕猴乃至人类以外的其他灵长类动物说不了“人话”,有人推测这与它们的声带缺陷有关。研究人员利用X光成像，建立猕猴声带电脑模型。分析结果显示猕猴很容易就能发出许多不同的声音，包括英语字母中最基本的5个元音。研究人员据此推测，如果猕猴能像人类那样思考，那么它们将能说出数千个单词，甚至完整的句子。\n上述材料重在说明："}],"optionRich":{"A":[{"text":"语言能力不仅需要声带的变化，更需要大脑的思考"}],"B":[{"text":"猕猴不能像人类那样思考导致它们说不了“人话”"}],"C":[{"text":"猕猴若能思考将拥有与人类一样的语言能力"}],"D":[{"text":"猕猴的声带缺陷导致它们无法正常说话"}]},"annotatedStemRich":[{"text":"长期以来，猕猴乃至人类以外的其他灵长类动物说不了“人话”,有人推测这与它们的声带缺陷有关(过去观点)。研究人员利用X光成像，建立猕猴声带电脑模型。分析结果显示：猕猴很容易就能发出许多不同的声音，包括英语字母中最基本的5个元音"},{"text":"(实验论证)。","bold":true},{"text":"研究人员据此推测，如果猕猴能像人类那样思考，那么它们将能说出数千个单词，甚至完整的句子"},{"text":"(现在新观点)。","bold":true},{"text":"\n上述材料重在说明："}],"annotatedOptionRich":{"A":[{"text":"语言能力不仅需要声带的变化，更需要大脑的思考"},{"text":"(缺主语)","bold":true}],"B":[{"text":"猕猴不能像人类那样思考导致它们说不了“人话”"}],"C":[{"text":"猕猴若能思考将拥有与人类一样的语言能力(无中生有)"}],"D":[{"text":"猕猴的声带缺陷导致它们无法正常说话(出处有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段可看作古今对比结构，先介绍了过去的观点：猕猴及其他灵长类动物不会说话和声带缺陷有关，之后通过实验推翻老观点并提出新观点“如果猕猴能像人类那样思考，那么它们将能说出数千个单词，甚至完整的句子”。 B选项为新观点的同义替换，当选； ③\nA选项缺少主语“猕猴”;C选项无中生有，“能说出数千个单词，甚至完整的句子”不意味着和人类有一样的语言能力；D选项为老观点，已经被推翻，排除。","notes":[{"marker":"36","content":"行文结构：二层结构—古今对比。\n过去观点：\n猕猴及其他灵长类动物不会说话和声带缺陷有关；\n现在观点：\n新研究发现猕猴不会说话\n(和声带无关)是因为不会思考。","matchScore":0.7379,"pairingMode":"content-similarity","order":34},{"marker":"③","content":"此题类似于逻辑里的归因题。\n老观点认为“猕猴说不了人话的原因是声带缺陷”。新观点为“否定此因+另有他因”来质疑老观点，同时也是文段的主旨。","matchScore":0.2954,"pairingMode":"marker-and-content","order":35}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300460,3,'中心理解题','近年来，“非遗热”广受关注。数字赋能、科技助力，促进相关产业发展升级；传统手艺跨界创新“碰撞”灵感火花，非遗以现代、时尚的形象“圈粉”无数；传承人走进社区、走进校园。在人们真实具体的触摸感知中，非遗变得更有魅力。从原汁原味又符合当代审美的表演艺术，到巧夺天工又随手可用的制作技艺，从留住乡愁的习俗，到推进乡村振兴的产业……在活态传承中有效保护，在有效保护前提下合理利用，不断满足人民群众对美好生活的需要，才能更好激发非遗的活力。
这段文字主要谈论的是：','[{"label":"A","content":"非遗的活力在于传承创新"},{"label":"B","content":"人们用更加多元的方式“打开”非遗"},{"label":"C","content":"现代、时尚的非遗形象反映其无限魅力"},{"label":"D","content":"非遗是能够穿越历史、跨越时代的宝贵财富"}]','A','文段分析见批注。
文段为后对策结构，尾句通过逻辑关联词给出对策，对策可翻译为：“更好激发非遗活力需要在保护中合理利用、动态传承、满足人们需要”。 A选项为对策句同义替换，当选；
其他选项均不是对策表述，根据原文有对策选对策原则，均可简单排除。
题目整体评价
