INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300464,3,'中心理解题','古人有忌在太岁头上动土的说法，由此看来，太岁似乎是一个不敢轻惹的凶神。其实，“太岁”源出古天文学，是为适应天干地支记时法的需要而假想出来的虚体，又称苍龙，太阴。它每12年一循环，与甲乙丙丁戊已庚辛壬癸相配。后来，道教吸收了太岁的概念，把60甲子神话化，变成60位太岁神，每位各值一岁，由于迷信，人们在本命年特别小心，怕惹恼了该年的值年太岁。
最适于做上述材料标题的是：','[{"label":"A","content":"“太岁”的来历"},{"label":"B","content":"“太岁”的古称"},{"label":"C","content":"“太岁”的演化"},{"label":"D","content":"“太岁”的禁忌"}]','A','文段分析见批注。
文段可看作并列结构，引出话题后分别表述了太岁的两个“由来”:古天文学和道教。可知文段重点围绕太岁的由来。对应A选项，当选。
其他选项：其他选项均无中生有，可简单排除。

