INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300465,3,'中心理解题','所谓“连续10年支教”的“最美支教女老师”龙晶晴，终于等来了行政处罚。龙晶晴的高光之后人设崩塌，揭示了如今部分“支教”成为生意的怪诞现象，欠发达地区的孩子则沦为这场游戏中的NPC ( 非玩家角色)。下乡旅游就是旅游，下乡捐赠就是捐赠，“支教”这块金字招牌受不了这种侵蚀。
对这段文字概括最准确的是：','[{"label":"A","content":"支教是一件很严肃的事"},{"label":"B","content":"“作秀式支教”成了精致利己主义的乡野派对"},{"label":"C","content":"“旅游式支教”别盗用支教之名"},{"label":"D","content":"支教不仅仅是生意，还是公益"}]','C','文段分析见批注。
文段为后对策结构，尾句可看作禁止型对策，可翻译为：下乡旅游就是旅游，不是捐赠，不要用把旅游说成支教。C选项②为对策的同义替换，当选；
A选项中性表达且过于宽泛，未体现对策，排除；B选项为问题表述，未体现对策，且“作秀式支教”不如“旅游式支教”贴合题干，排除；D选项本身有误，根据文段和常识可知，支教不可能是生意，排除。
中间部分进行分析：
部分“支教”成为生意，欠发达地区的孩子沦为“工具人”;
最后给出禁止型对策：
旅游不是捐赠，“支教”这块金字招牌受不了这种侵蚀 (即不要用旅游冒充支教或不要把旅游说成支教)。

花生批注：
⑪ 行文结构：后对策结构。
开篇引出话题：
所谓“连续10年支教”的“最美支教女老师”龙晶晴，终于等来了行政处罚。龙晶晴的高光之后人设崩塌，揭示了如今部分“支教”成为生意的怪诞现象，欠发达地区的孩子则沦为这场游戏中的NPC( 非玩家角色)(引出并分析话题)。下乡旅游就是旅游，下乡捐赠就是捐赠，“支教”这块金字招牌受不了这种侵蚀 (禁止型对策)。①
对这段文字概括最准确的是：
A. 支教是一件很严肃的事(中性表达)
B. “作秀式支教”成了精致利己主义的乡野派对(问题表述)
C. “旅游式支教”别盗用支教之名
D. 支教不仅仅是生意，还是公益(本身有误)
⑫ 有的同学可能认为C选项的“旅游式支教”在文段无从体现，从而选择了B选项，
但通过最后一句话中的“下乡旅游就是旅游，下乡捐赠就是捐赠”可知，作者的观点意在强调“该是什么就是什么,旅游就是旅游，不是支教(即这种现象可概括为“旅游式支教”)”,这样来看，C选项反而更贴合文段，所以不必纠结“旅游式支教”从何而来。','2023年天津市事业单位','进阶','published','{"globalNumber":465,"setNumber":24,"localNumber":5,"sourceLabel":"2023年天津市事业单位48%","accuracy":48,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"所谓“连续10年支教”的“最美支教女老师”龙晶晴，终于等来了行政处罚。龙晶晴的高光之后人设崩塌，揭示了如今部分“支教”成为生意的怪诞现象，欠发达地区的孩子则沦为这场游戏中的NPC ( 非玩家角色)。下乡旅游就是旅游，下乡捐赠就是捐赠，“支教”这块金字招牌受不了这种侵蚀。\n对这段文字概括最准确的是："}],"optionRich":{"A":[{"text":"支教是一件很严肃的事"}],"B":[{"text":"“作秀式支教”成了精致利己主义的乡野派对"}],"C":[{"text":"“旅游式支教”别盗用支教之名"}],"D":[{"text":"支教不仅仅是生意，还是公益"}]},"annotatedStemRich":[{"text":"⑪花生批注：\n"},{"text":"行文结构：","bold":true},{"text":"后对策结构。\n"},{"text":"开篇引出话题：","bold":true},{"text":"\n“最美支教女老师”受到行政处罚；\n所谓“连续10年支教”的“最美支教女老师”龙晶晴，终于等来了行政处罚。龙晶晴的高光之后人设崩塌，揭示了如今部分“支教”成为生意的怪诞现象，欠发达地区的孩子则沦为这场游戏中的NPC( 非玩家角色)(引出并分析话题)。下乡旅游就是旅游，下乡捐赠就是捐赠，“支教”这块金字招牌受不了这种侵蚀 (禁止型对策)。①\n对这段文字概括最准确的是："}],"annotatedOptionRich":{"A":[{"text":"支教是一件很严肃的事(中性表达)"}],"B":[{"text":"“作秀式支教”成了精致利己主义的乡野派对(问题表述)"}],"C":[{"text":"“旅游式支教”别盗用支教之名"}],"D":[{"text":"支教不仅仅是生意，还是公益(本身有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段为后对策结构，尾句可看作禁止型对策，可翻译为：下乡旅游就是旅游，不是捐赠，不要用把旅游说成支教。C选项②为对策的同义替换，当选；\nA选项中性表达且过于宽泛，未体现对策，排除；B选项为问题表述，未体现对策，且“作秀式支教”不如“旅游式支教”贴合题干，排除；D选项本身有误，根据文段和常识可知，支教不可能是生意，排除。\n中间部分进行分析：\n部分“支教”成为生意，欠发达地区的孩子沦为“工具人”;\n最后给出禁止型对策：\n旅游不是捐赠，“支教”这块金字招牌受不了这种侵蚀 (即不要用旅游冒充支教或不要把旅游说成支教)。","notes":[{"marker":"⑪","content":"行文结构：后对策结构。\n开篇引出话题：\n所谓“连续10年支教”的“最美支教女老师”龙晶晴，终于等来了行政处罚。龙晶晴的高光之后人设崩塌，揭示了如今部分“支教”成为生意的怪诞现象，欠发达地区的孩子则沦为这场游戏中的NPC( 非玩家角色)(引出并分析话题)。下乡旅游就是旅游，下乡捐赠就是捐赠，“支教”这块金字招牌受不了这种侵蚀 (禁止型对策)。①\n对这段文字概括最准确的是：\nA. 支教是一件很严肃的事(中性表达)\nB. “作秀式支教”成了精致利己主义的乡野派对(问题表述)\nC. “旅游式支教”别盗用支教之名\nD. 支教不仅仅是生意，还是公益(本身有误)","matchScore":1.2459,"pairingMode":"marker-and-content","order":10},{"marker":"⑫","content":"有的同学可能认为C选项的“旅游式支教”在文段无从体现，从而选择了B选项，\n但通过最后一句话中的“下乡旅游就是旅游，下乡捐赠就是捐赠”可知，作者的观点意在强调“该是什么就是什么,旅游就是旅游，不是支教(即这种现象可概括为“旅游式支教”)”,这样来看，C选项反而更贴合文段，所以不必纠结“旅游式支教”从何而来。","matchScore":0.4529,"pairingMode":"content-simi