INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300466,3,'中心理解题','古树是指经依法认定、树龄100年以上的树木；名木是指经依法认定的稀有珍贵树木和具有历史价值、重要纪念意义的树木。古树不仅以其年代久远、景观独特见长，也因其蕴含的丰富历史意义而受到广泛关注。它们是活着的历史，连接着过去现在和未来。其中一些历经世事变迁及岁月洗礼，在跨朝历代中成为“名木”,化作社会历史不可分割的一部分。
这段文字主要讲了：','[{"label":"A","content":"古树的独特景观和历史意义"},{"label":"B","content":"认定古树及名木的主要标准"},{"label":"C","content":"古树名木具有社会历史价值"},{"label":"D","content":"做好古树名木保护的重要性"}]','C','文段分析见批注。
文段通过背景知识引出话题，但背景部分非重点，重点在正文对于古树名木社会历史价值的介绍，直接对应C选项，当选；
A选项为“A 且B”选项，但“独特景观”文段未具体介绍，排除；B选项出自背景知识部分，非重点，排除；D选项“古树名木保护”文段未提及，排除。

花生批注：
⑬ 古树、名木为全文论述主体。
⑭ 行文结构：二层结构——背景知识+正文。
背景知识引出话题：介绍古树和名木是什么;
正文介绍了古树名木的历史意义和价值。
这段文字主要讲了：
A. 古树的独特景观和历史意义(无中生有)
B. 认定古树及名木的主要标准(出处有误)
C. 古树名木具有社会历史价值
D. 做好古树名木保护的重要性 (无中生有)','2023年广东省事业单位','进阶','published','{"globalNumber":466,"setNumber":24,"localNumber":6,"sourceLabel":"2023年广东省事业单位67%","accuracy":67,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"古树是指经依法认定、树龄100年以上的树木；名木是指经依法认定的稀有珍贵树木和具有历史价值、重要纪念意义的树木。古树不仅以其年代久远、景观独特见长，也因其蕴含的丰富历史意义而受到广泛关注。它们是活着的历史，连接着过去现在和未来。其中一些历经世事变迁及岁月洗礼，在跨朝历代中成为“名木”,化作社会历史不可分割的一部分。\n这段文字主要讲了："}],"optionRich":{"A":[{"text":"古树的独特景观和历史意义"}],"B":[{"text":"认定古树及名木的主要标准"}],"C":[{"text":"古树名木具有社会历史价值"}],"D":[{"text":"做好古树名木保护的重要性"}]},"annotatedStemRich":[{"text":"古树","underline":true},{"text":"是指经依法认定、树龄100年以上的树木：名木是指经依法认定的稀有珍贵树木和具有历史价值、重要纪念意义的树木(背景知识引出话题)。古树不仅以其年代久远、景观独特见长，也因其蕴含的丰富历史意义而受到广泛关注。它们是活着的历史，连接着过去现在和未来。其中一些历经世事变迁及岁月洗礼，在跨朝历代中成为“名木”,化作社会历史不可分割的一部分(介\n绍古树名木的历史价值)。⑭\n这段文字主要讲了："}],"annotatedOptionRich":{"A":[{"text":"古树的独特景观和历史意义(无中生有)"}],"B":[{"text":"认定古树及名木的主要标准(出处有误)"}],"C":[{"text":"古树名木具有社会历史价值"}],"D":[{"text":"做好古树名木保护的重要性 (无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段通过背景知识引出话题，但背景部分非重点，重点在正文对于古树名木社会历史价值的介绍，直接对应C选项，当选；\nA选项为“A 且B”选项，但“独特景观”文段未具体介绍，排除；B选项出自背景知识部分，非重点，排除；D选项“古树名木保护”文段未提及，排除。","notes":[{"marker":"⑬","content":"古树、名木为全文论述主体。","matchScore":0.3307,"pairingMode":"content-similarity","order":12},{"marker":"⑭","content":"行文结构：二层结构——背景知识+正文。\n背景知识引出话题：介绍古树和名木是什么;\n正文介绍了古树名木的历史意义和价值。\n这段文字主要讲了：\nA. 古树的独特景观和历史意义(无中生有)\nB. 认定古树及名木的主要标准(出处有误)\nC. 古树名木具有社会历史价值\nD. 做好古树名木保护的重要性 (无中生有)","matchScore":0.596,"pairingMode":"marker-and-content","order":13}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300467,3,'标题拟定类','在培育和涵养文明乡风的具体实践中，要抓住“关键少数”。党员干部是农村各项事业发展的“领头雁”, 在培育和涵养文明乡风过程中也必须发挥带头作用，除了要倡导他们“做给农民看，带着农民干”, 还要探索建立婚丧事宜报备制度，加强对他们的纪律约束。要善于发挥道德模范的引领作用，广泛开展农村道德模范、最美邻里、最美家庭等选树活动，通过选典型、评典型、学典型，让良好的乡风、民风、家风在农村蔚然成风。乡村文明建设需要社会各个方面的支持和参与，要充分发挥退休人员、企业人士等乡贤群体的作用，使之成为引领、培育和涵养文明乡风的重要力量。
下列最适合做这段文字标题的是：','[{"label":"A","content":"党员干部在乡风文明建设中的作用"},{"label":"B","content":"良好乡风需要“关键少数”来推动和引领"},{"label":"C","content":"道德模范在乡风建设中具有示范作用"},{"label":"D","content":"乡风文明建设需要齐抓共管\n练习题 2 4 套"}]','B','文段分析见批注。
文段开门见山提出对策：在培育和涵养文明乡风的具体实践中，要抓住“关键少数”,后文具体展开介绍党员、道德模范、乡贤群体要发挥作用。 B选项是对总对策的同义替换，当选。
A选项、C选项均来自于“具体展开”部分，出处有误且片面，排除；D选项“齐抓共管”过于宽泛，不如B选项具体提到“关键少数”的推动和引领，排除。

花生批注：
⑩ 古称：即古时的称谓；
演化：事物随时间发展的变化过程；
禁忌：犯忌讳的话和行为。
片段阅读600 o(下册)
⑮ 行文结构：前对策结构。
开门见山提出对策：
做好文明乡风工作，要抓住“关键少数”。
接下来分别介绍：
党员要发挥带头作用；
要发挥道德模范的引领作用；
要发挥乡贤群体的作用。
片段阅读6 00 o (下册)','2019年浙江省事业单位','进阶','published','{"globalNumber":467,"setNumber":24,"localNumber":7,"sourceLabel":"2019年浙江省事业单位67%","accuracy":67,"typeAndPassage":"标题拟定类+说理类文章","stemRich":[{"text":"在培育和涵养文明乡风的具体实践中，要抓住“关键少数”。党员干部是农村各项事业发展的“领头雁”, 在培育和涵养文明乡风过程中也必须发挥带头作用，除了要倡导他们“做给农民看，带着农民干”, 还要探索建立婚丧事宜报备制度，加强对他们的纪律约束。要善于发挥道德模范的引领作用，广泛开展农村道德模范、最美邻里、最美家庭等选树活动，通过选典型、评典型、学典型，让良好的乡风、民风、家风在农村蔚然成风。乡村文明建设需要社会各个方面的支持和参与，要充分发挥退休人员、企业人士等乡贤群体的作用，使之成为引领、培育和涵养文明乡风的重要力量。\n下列最适合做这段文字标题的是："}],"optionRich":{"A":[{"text":"党员干部在乡风文明建设中的作用"}],"B":[{"text":"良好乡风需要“关键少数”来推动和引领"}],"C":[{"text":"道德模范在乡风建设中具有示范作用"}],"D":[{"text":"乡风文明建设需要齐抓共管\n练习题 2 4 套"}]},"annotatedStemRich":[{"text":"在培育和涵养文明乡风的具体实践中，要抓住“关键少数”"},{"text":"(前对策)。","bold":true},{"text":"党员干部是农村各项事业发展的“领头雁”,在培育和涵养文明乡风过程中也必须发挥带头作用，除了要倡导他们“做给农民看，带着农民干”,还要探索建立婚丧事宜报备制度，加强对他们的纪律约束。要善于发挥道德模范的引领作用，广泛开展农村道德模范、最美邻里、最美家庭等选树活动，通过选典型、评典型、学典型，让良好的乡风、民风、家风在农村蔚然成风。乡村文明建设需要社会各个方面的支持和参与，要充分发挥退休人员、企业人士等乡贤群体的作用，使之成为引领、培育和涵养文明乡风的重要力量("},{"text":"具体展开对策)。⑥","bold":true},{"text":"\n下列最适合做这段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"党员干部在乡风文明建设中的作用"},{"text":"(出处有误)","bold":true}],"B":[{"text":"良好乡风需要“关键少数”来推动和引领"}],"C":[{"text":"道德模范在乡风建设中具有示范作用"},{"text":"(出处有误)","bold":true}],"D":[{"text":"乡风文明建设需要齐抓共管"},{"text":"(宽泛)","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段开门见山提出对策：在培育和涵养文明乡风的具体实践中，要抓住“关键少数”,后文具体展开介绍党员、道德模范、乡贤群体要发挥作用。 B选项是对总对策的同义替换，当选。\nA选项、C选项均来自于“具体展开”部分，出处有误且片面，排除；D选项“齐抓共管”过于宽泛，不如B选项具体提到“关键少数”的推动和引领，排除。","notes":[{"marker":"⑩","content":"古称：即古时的称谓；\n演化：事物随时间发展的变化过程；\n禁忌：犯忌讳的话和行为。\n片段阅读600 o(下册)","matchScore":0.1084,"pairingMode":"content-similarity","order":9},{"marker":"⑮","content":"行文结构：前对策结构。\n开门见山提出对策：\n做好文明乡风工作，要抓住“关键少数”。\n接下来分别介绍：\n党员要发挥带头作用；\n要发挥道德模范的引领作用；\n要发挥乡贤群体的作用。\n片段阅读6 00 o (下册)","matchScore":0.6766,"pairingMode":"content-similarity","order":14}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300468,3,'中心理解题','当人脑在发育阶段接触到视觉刺激，也就是通过眼睛看到外界事物时，视皮层上的神经元会被激活，也就是说这些神经元会对不同的图像特征如颜色、形状、亮度、朝向、距离等进行加工。如果人正处于视觉功能的发育关键期，而视觉神经元未被充分激活，未来在看到某些图像特征时就不会产生反应或反应比较弱，导致看不见或看不清。
这段文字最适合作为下列哪个观点的论据：','[{"label":"A","content":"人体的不同机能存在着不同的发育关键期"},{"label":"B","content":"人体功能发育不充分有可能造成终生影响"},{"label":"C","content":"图像特征对视皮层神经元的激活至关重要"},{"label":"D","content":"错过发育关键期有可能丧失部分人体机能"}]','D','本题问法特殊，为“这段文字最适合哪个观点的论据”,即文段为“论证”,选项为“观点”;
文段论证部分有两句话，分别为“当人脑发育阶段视觉神经元被激活会如何”和“当人处于视觉发育关键期视觉神经元未被激活会如何”。可看作正反论证，论证的内容是“当人脑处于视觉发育关键期，视觉神经元是否被充分激活的不同后果”。①可看作是对“错过发育关键期有可能丧失部分人体机能”的举例(视觉为例子)正反论证，对应D选项，当选。

花生批注：
⑯ 若支持A选项：
应重点介绍多种机能的不同关键期；
若支持B选项：
应重点介绍人体功能发育不充分的后果，侧重对未来生活的影响；
若支持C选项：
应以图像特征为主体，介绍图像特征是如何激活视皮层神经元的及图像特征在这一过程中的重要作用。
⑰ 重点为①发育关键期②神经元激活③后果；
A选项只提及①,B选项只提及③,C选项只提及②; D选项的“发育关键期”对应①,“错过”即“神经元未激活”对应②,“丧失部分人体机能”对应③,完美选项。','2021年山东省考','挑战','published','{"globalNumber":468,"setNumber":24,"localNumber":8,"sourceLabel":"2021年山东省考 44%","accuracy":44,"typeAndPassage":"中心理解题","stemRich":[{"text":"当人脑在发育阶段接触到视觉刺激，也就是通过眼睛看到外界事物时，视皮层上的神经元会被激活，也就是说这些神经元会对不同的图像特征如颜色、形状、亮度、朝向、距离等进行加工。如果人正处于视觉功能的发育关键期，而视觉神经元未被充分激活，未来在看到某些图像特征时就不会产生反应或反应比较弱，导致看不见或看不清。\n这段文字最适合作为下列哪个观点的论据："}],"optionRich":{"A":[{"text":"人体的不同机能存在着不同的发育关键期"}],"B":[{"text":"人体功能发育不充分有可能造成终生影响"}],"C":[{"text":"图像特征对视皮层神经元的激活至关重要"}],"D":[{"text":"错过发育关键期有可能丧失部分人体机能"}]},"annotatedStemRich":[{"text":"当人脑在发育阶段接触到视觉刺激，也就是通过眼睛看到外界事物时，视皮层上的神经元会被激活，也就是说这些神经元会对不同的图像特征如颜色、形状、亮度、朝向、距离等进行加工("},{"text":"发育关键阶段，视觉神经元被激活的情况)。","bold":true},{"text":"如果人正处于视觉功能的发育关键期，而视觉神经元未被充分激活，未来在看到某些图像特征时就不会产生反应或反应比较弱，导致看不见或看不清"},{"text":"(发育关键阶段，视觉神经元未激活的情况)。","bold":true},{"text":"\n这段文字最适合作为下列哪个观点的论据：⑯"}],"annotatedOptionRich":{"A":[{"text":"人体的不同机能存在着不同的发育关键期"}],"B":[{"text":"人体功能发育不充分有可能造成终生影响"}],"C":[{"text":"图像特征对视皮层神经元的激活至关重要"}],"D":[{"text":"错过发育关键期有可能丧失部分人体机能"}]},"practicalAnalysis":"本题问法特殊，为“这段文字最适合哪个观点的论据”,即文段为“论证”,选项为“观点”;\n文段论证部分有两句话，分别为“当人脑发育阶段视觉神经元被激活会如何”和“当人处于视觉发育关键期视觉神经元未被激活会如何”。可看作正反论证，论证的内容是“当人脑处于视觉发育关键期，视觉神经元是否被充分激活的不同后果”。①可看作是对“错过发育关键期有可能丧失部分人体机能”的举例(视觉为例子)正反论证，对应D选项，当选。","notes":[{"marker":"⑯","content":"若支持A选项：\n应重点介绍多种机能的不同关键期；\n若支持B选项：\n应重点介绍人体功能发育不充分的后果，侧重对未来生活的影响；\n若支持C选项：\n应以图像特征为主体，介绍图像特征是如何激活视皮层神经元的及图像特征在这一过程中的重要作用。","matchScore":0.3734,"pairingMode":"marker-and-content","order":15},{"marker":"⑰","content":"重点为①发育关键期②神经元激活③后果；\nA选项只提及①,B选项只提及③,C选项只提及②; D选项的“发育关键期”对应①,“错过”即“神经元未激活”对应②,“丧失部分人体机能”对应③,完美选项。","matchScore":0.5712,"pairingMode":"content-similarity","order":16}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300469,3,'细节判断类','“教资考试热”的出现体现了教师这个职业的地位逐渐提升，近年来我国出台了一系列提高教师地位、改善教师待遇的文件，教师的收入和社会地位不断提升。教师职业具有延续性、内生性发展的特点，年龄大的教师具有更丰富的教学经验，可以不断地进行自我提升、延续发展。专家提醒广大报考者，选择教师职业也要理性，教师对个人的付出和努力要求很高，选择教师职业意味着要有奉献精神。因此，每个人在选择从事教师这个职业之前，要对自己人生的定位和未来发展有一个整体判断，而不是盲目地追逐。
对这段文字理解不正确的一项是：','[{"label":"A","content":"教师职业前景光明"},{"label":"B","content":"并不是所有人都适合教师这个行业"},{"label":"C","content":"教资考试需要降温"},{"label":"D","content":"选择教师职业需要做好奉献的准备"}]','C','C选项，“教资考试需降温”无中生有，文段对策为“每个人在选择从事教师这个职业之前，要对自己人生的定位和未来发展有一个整体判断，而不是盲目地追逐”,即“要理性选择教师职业”,而非“教资考试需要降温”,本题为选非题，当选。

花生批注：
⑱ 根据文段第①句的“‘教资考试热’的出现体现了教师这个职业的地位逐渐提升，近年来我国出台了一系列提高教师地位、改善教师待遇的文件，教师的收入和社会地位不断提升”可知，教师职业前景光明，正确。
⑲ 根据文段第④句的“每个人在选择从事教师这个职业之前，要对自己人生的定位和未来发展有一个整体判断，而不是盲目地追逐”可知，并不是所有人都适合教师这个行业，正确。
