INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300471,3,'下文推断类','起床后的第一件事是摸手机，吃饭先拿起手机拍照传微博，一桌人都对着手机，有一句没一句地聊天，半夜都要从枕头底下掏出手机来看看新闻……智能手机渗透到生活的方方面面，已经对个人生活和社会交往产生不良影响。针对人们日渐依赖智能手机的现象，专家呼吁要“数字节食”—人们应该合理利用智能手机，而不是被手机掌控，全民都需要认识到手机上瘾的危害。
根据这段文字，作者接下来最有可能：','[{"label":"A","content":"介绍“数字节食”概念是如何出现的"},{"label":"B","content":"就如何减少对智能手机的依赖给出建议"},{"label":"C","content":"回顾传统手机时代人们简单而健康的生活"},{"label":"D","content":"说明智能手机在哪些方面给生活造成了影响"}]','B','文段分析见批注。
