INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300481,3,'中心理解题','从17世纪到20世纪中叶，怀旧心理一直被学界认为是由思乡病带来的痛苦、甚至病理性的体验。直到20世纪末，西方学者才将怀旧和思乡病区分开来，他们开始注意到怀旧的积极作用，并将怀旧定义为一种正面情绪。而现代心理学对怀旧的普遍理解是：对过去的渴望和喜爱。心理学家维尔德舒特认为，怀旧是正面情绪的“储藏室”,它储藏了快乐、幸福、宁静等正面情绪。而心理学家威尔曼则认为怀旧是一种喜忧参半的情绪，它既包含回忆往昔带来的快乐，又包含“再也回不去”的失落与忧伤。
这段文字主要说明的是：','[{"label":"A","content":"学界对“怀旧心理”认知的变迁"},{"label":"B","content":"以前排斥“怀旧”,如今追求“怀旧”"},{"label":"C","content":"怀旧不只有消极情绪，还有正面情绪"},{"label":"D","content":"思乡病折射出现代人的怀旧心理与真实生活"}]','A','文段分析见批注。
文段依次介绍不同时期学界对“怀旧心理”认知的变化，可看作历程类文段，对应A选项(历程类选项)当选；
其他选项均未体现这种变化，可简单排除。

花生批注：
① 怀旧心理为全文论述话题。
② 行文结构：大并列结构。
文段有清晰的时间轴：17世纪到20世纪中叶、20世纪末、现代，依次介绍了不同时期学界对“怀旧心理”认知的变化。','2023年事业单位联考','基础','published','{"globalNumber":481,"setNumber":25,"localNumber":1,"sourceLabel":"2023年事业单位联考 70%","accuracy":70,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"从17世纪到20世纪中叶，怀旧心理一直被学界认为是由思乡病带来的痛苦、甚至病理性的体验。直到20世纪末，西方学者才将怀旧和思乡病区分开来，他们开始注意到怀旧的积极作用，并将怀旧定义为一种正面情绪。而现代心理学对怀旧的普遍理解是：对过去的渴望和喜爱。心理学家维尔德舒特认为，怀旧是正面情绪的“储藏室”,它储藏了快乐、幸福、宁静等正面情绪。而心理学家威尔曼则认为怀旧是一种喜忧参半的情绪，它既包含回忆往昔带来的快乐，又包含“再也回不去”的失落与忧伤。\n这段文字主要说明的是："}],"optionRich":{"A":[{"text":"学界对“怀旧心理”认知的变迁"}],"B":[{"text":"以前排斥“怀旧”,如今追求“怀旧”"}],"C":[{"text":"怀旧不只有消极情绪，还有正面情绪"}],"D":[{"text":"思乡病折射出现代人的怀旧心理与真实生活"}]},"annotatedStemRich":[{"text":"从17世纪到20世纪中叶， "},{"text":" 怀旧心理","underline":true},{"text":"①一直被学界认为是由思乡病带来的痛苦、甚至病理性的体验(分1)。直到20世纪末，西方学者才将怀旧和思乡病区分开来，他们开始注意到怀旧的积极作用，并将怀旧定义为一种正面情绪 ( 分 2 ) 。而现代心理学对怀旧的普遍理解是：对过去的渴望和喜爱。心理学家维尔德舒特认为，怀旧是正面情绪的“储藏室”,它储藏了快乐、幸福、宁静等正面情绪。而心理学家威尔曼则认为怀旧是一种喜忧参半的情绪，它既包含回忆往昔带来的快乐，又包含“再也回不去”的失落与忧伤(分3)。②\n这段文字主要说明的是："}],"annotatedOptionRich":{"A":[{"text":"学界对“怀旧心理”认知的变迁(历程类选项)"}],"B":[{"text":"以前排斥“怀旧”,如今追求“怀旧”(无中生有)"}],"C":[{"text":"怀旧不只有消极情绪，还有正面情绪(本身有误)"}],"D":[{"text":"思乡病折射出现代人的怀旧心理与真实生活(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段依次介绍不同时期学界对“怀旧心理”认知的变化，可看作历程类文段，对应A选项(历程类选项)当选；\n其他选项均未体现这种变化，可简单排除。","notes":[{"marker":"①","content":"怀旧心理为全文论述话题。","matchScore":0.327,"pairingMode":"marker-and-content","order":0},{"marker":"②","content":"行文结构：大并列结构。\n文段有清晰的时间轴：17世纪到20世纪中叶、20世纪末、现代，依次介绍了不同时期学界对“怀旧心理”认知的变化。","matchScore":0.723,"pairingMode":"marker-and-content","order":1}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300482,3,'标题拟定类','一份哈佛商学院的报告表明，公司管理和薪资的变化使美国公司管理人员采取一种关注股价和短期业绩的管理方式。当一家公司聚焦短期利润和股价时，管理层可能会创新，但这些创新都与提高效率和降低成本有关。相反，能够带来附加值的创新，特别是具有变革意义的创新，则很可能被认为风险过大、代价过高而得不到投资。公司将持续被节省成本的创新所吸引，即使这种方式会使公司走上全球竞争力不断减弱直至灭亡的道路。
最适合这段文字的标题是：','[{"label":"A","content":"短期利润与具有变革意义的创新"},{"label":"B","content":"哈佛商学院与美国公司的管理理念"},{"label":"C","content":"利润压力使公司管理方式误入歧途"},{"label":"D","content":"管理层的短视使美国公司缺乏创新动力"}]','D','文段结构见批注。
文段在提出美国公司管理方式的问题后，对问题进行了分析：可能会放弃正确创新，而选择错误创新；文段主体为“美国公司”;
A选项、C选项均未提及美国公司，可简单排除；
B选项本身有误，原文表述为“哈佛商学院报告表明了美国公司的管理方式”,而非“哈佛商学院的管理理念”,排除；
D选项，可理解为“管理层错误管理方式让美国公司缺乏能够带来附加值、有变革意义的创新动力”,与文段问题一致，当选。

