INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300483,3,'中心理解题','先进制造业是与传统产业相对而言的，它可以由传统产业融入先进技术升级而成，也可以由新技术的颠覆性突破而衍生出，通常具备以下特点：处在全球生产体系的高端，生产流通高度智能化…… 产品附加值高、技术含量高；吸收计算机、电子信息、材料以及现代管理技术等领域的高新技术成果，在技术和研发方面保持先进水平；采用先进的管理方式和技术手段，有较好的经济收益和市场效果。这段文字主要讲了：','[{"label":"A","content":"先进制造业与传统制造业的区别"},{"label":"B","content":"先进制造业的主要特征"},{"label":"C","content":"先进制造业的突出优势"},{"label":"D","content":"传统产业与先进制造业关系"}]','B','文段分析见批注。
文段为总分结构，引出“先进制造业”这一话题后，用“通常具备以下特点”引出先进制造业所具备的特点，B选项概括了并列部分的主要内容，当选；
A选项、D选项为区别比较联系类选项⑨,但文段并非双主体，排除； C选项无中生有，“突出优势”文段未提及⑦,排除。
公考最新资料、更新进度微信SKA674

花生批注：
④ “先进制造业”是全文论述主体
⑤ 行文结构：总分结构。
先引出话题：
“先进制造业”概念及其产生方式；
接着用“通常具备以下特点”引出三个特点：
①产品附加值高、技术含量高；
②在技术和研发方面保持先进水平；
③采用先进的管理方式和技术手段，有较好的经济收益和市场效果。
⑥ 若A选项、D选项当选，则文段应为双主体两者篇幅相当且围绕二者关系、区别进行论述。
⑦ 文段用“通常具备以下特点”,尊重原文，用“特征”概括优于“突出优势”;
而且，文段主要介绍的是先进制造业的特点，并未和传统制造业进行比较。
⑯ 行文结构：后观点结构。
