INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300484,3,'中心理解题','要花钱更要花好钱，在保证义务教育经费按时足额到位的同时，有关部门需要进一步优化教育支出结构，提高教育经费使用效益。目前义务教育领域仍存在“重硬件轻软件，重支出轻绩效”的现象，
个别地方一边缺钱，一边乱花钱，铺张浪费，搞形象工程。比如，有的地方花巨资建设的“美丽校园”变成了“空壳学校”,而设有美术室、音乐室和科技室的“乡村少年宫”因经费短缺而被迫停用。因此，经费下拨过程中，要严格执行经费管理有关办法，确保经费使用的规范和安全；要完善教育财务制度体系，注重经费使用效益，坚决避免铺张浪费和挤占挪用的现象发生。
上述文字主要讲述的是：','[{"label":"A","content":"要合理使用增量教育经费"},{"label":"B","content":"要提高教育经费的使用效益"},{"label":"C","content":"公平分配存量教育经费"},{"label":"D","content":"要监督教育经费的使用"}]','B','文段分析见批注。
文段为前对策结构，且尾句重复对策，对策为“提高教育经费使用效益”, 对应B选项，当选；
A选项“增量教育经费”、C选项“公平分配”、D选项“监督使用”均无中生有，文段未提及，可简单排除。

花生批注：
⑧ 行文结构：前对策结构；
开篇直接给出对策：
有关部门需要进一步优化教育支出结构，提高教育经费使用效益；
再分析问题；
最后重复对策：
要确保经费使用的规范和安全，注重经费使用效益
片段阅读6 00 (下册)','2023年重庆市事业单位','进阶','published','{"globalNumber":484,"setNumber":25,"localNumber":4,"sourceLabel":"2023年重庆市事业单位66%","accuracy":66,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"要花钱更要花好钱，在保证义务教育经费按时足额到位的同时，有关部门需要进一步优化教育支出结构，提高教育经费使用效益。目前义务教育领域仍存在“重硬件轻软件，重支出轻绩效”的现象，\n个别地方一边缺钱，一边乱花钱，铺张浪费，搞形象工程。比如，有的地方花巨资建设的“美丽校园”变成了“空壳学校”,而设有美术室、音乐室和科技室的“乡村少年宫”因经费短缺而被迫停用。因此，经费下拨过程中，要严格执行经费管理有关办法，确保经费使用的规范和安全；要完善教育财务制度体系，注重经费使用效益，坚决避免铺张浪费和挤占挪用的现象发生。\n上述文字主要讲述的是："}],"optionRich":{"A":[{"text":"要合理使用增量教育经费"}],"B":[{"text":"要提高教育经费的使用效益"}],"C":[{"text":"公平分配存量教育经费"}],"D":[{"text":"要监督教育经费的使用"}]},"annotatedStemRich":[{"text":"要花钱更要花好钱，在保证义务教育经费按时足额到位的同时，有关部门需要进一步优化教育支出结构，提高教育经费使用效益(前对策)。目前义务教育领域仍存在“重硬件轻软件，重支出轻绩效”的现象，个别地方一边缺钱，一边乱花钱，铺张浪费，搞形象工程。比如，有的地方花巨资建设的“美丽校园”变成了“空壳学校”,而设有美术室、音乐室和科技室的“乡村少年宫”因经费短缺而被迫停用(分析问题)。因此，经费下拨过程中，要严格执行经费管理有关办法，确保经费使用的规范和安全；要完善教育财务制度体系，注重经费使用效益，坚决避免铺张浪费和挤占挪用的现象发生(重复对策)。⑨\n上述文字主要讲述的是："}],"annotatedOptionRich":{"A":[{"text":"要合理使用增量教育经费(无中生有)"}],"B":[{"text":"要提高教育经费的使用效益"}],"C":[{"text":"公平分配存量教育经费(无中生有)"}],"D":[{"text":"要监督教育经费的使用(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段为前对策结构，且尾句重复对策，对策为“提高教育经费使用效益”, 对应B选项，当选；\nA选项“增量教育经费”、C选项“公平分配”、D选项“监督使用”均无中生有，文段未提及，可简单排除。","notes":[{"marker":"⑧","content":"行文结构：前对策结构；\n开篇直接给出对策：\n有关部门需要进一步优化教育支出结构，提高教育经费使用效益；\n再分析问题；\n最后重复对策：\n要确保经费使用的规范和安全，注重经费使用效益\n片段阅读6 00 (下册)","matchScore":0.7708,"pairingMode":"content-similarity","order":7}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300485,3,'中心理解题','熟练运用一门国际通用外语，固然是涉外法治人才不可或缺的基本功，与熟练掌握国际法律规则体系和知识一样重要，但它们绝不是培养高素质涉外法治人才仅有的两门必修业务课。国际化实务能力的培养，应当包括国际贸易、国际金融、国际结算、国际谈判、国际法律文书制作等方面的知识运用能力，是融复合性、专业性、国际性、本土性为一体的跨学科人才培养系统工程。在法学院校中，这需要整合涉外法治人才能力培养相关的院系，并与法律实务部门协力才可完成。
这段文字意在说明，涉外法治人才培养：','[{"label":"A","content":"不能仅靠法学院校单独完成"},{"label":"B","content":"应着重提升国际化实务能力"},{"label":"C","content":"要把外语和国际法律列为专业必修课"},{"label":"D","content":"需进行顶层设计并构建综合培养体系"}]','D','文段分析见批注。
文段为典型后对策结构，对策句为重点，即“需要整合涉外法治人才能力培养相
关的院系，并与法律实务部门协力才可完成涉外法治人才培养⑩”,对应D选项，当选；

花生批注：
⑨ 行文结构：后对策结构。
文段引出“涉外法治人才”这一话题后，分析说明国际化能力培养是综合的系统工程；
文末提出对策：
需要整合涉外法治人才能力培养相关的院系，并与法律实务部门协力才可完成涉外法治人才培养。
这段文字意在说明，涉外法治人才培养：
A. 不能仅靠法学院校单独完成(对策有误)
B. 应着重提升国际化实务能力(对策有误)
C. 要把外语和国际法律列为专业必修课(出处有误)
D. 需进行顶层设计并构建综合培养体系
⑩ 可理解为：需要整合相关院系进行顶层设计，并且多部门协力综合培养。
A选项对策有误，未体现尾句对策重点，而且可看作“不是而是”的“不是”部分，一般不是正确选项，排除；B选项的“提升国际化实务能力”过于宽泛，未体现具体对策，排除；C选项的“外语和国际法律列为专业必修课”出自引出话题部分，非对策重点，排除。','2023年事业单位联考','进阶','published','{"globalNumber":485,"setNumber":25,"localNumber":5,"sourceLabel":"2023年事业单位联考57%","accuracy":57,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"熟练运用一门国际通用外语，固然是涉外法治人才不可或缺的基本功，与熟练掌握国际法律规则体系和知识一样重要，但它们绝不是培养高素质涉外法治人才仅有的两门必修业务课。国际化实务能力的培养，应当包括国际贸易、国际金融、国际结算、国际谈判、国际法律文书制作等方面的知识运用能力，是融复合性、专业性、国际性、本土性为一体的跨学科人才培养系统工程。在法学院校中，这需要整合涉外法治人才能力培养相关的院系，并与法律实务部门协力才可完成。\n这段文字意在说明，涉外法治人才培养："}],"optionRich":{"A":[{"text":"不能仅靠法学院校单独完成"}],"B":[{"text":"应着重提升国际化实务能力"}],"C":[{"text":"要把外语和国际法律列为专业必修课"}],"D":[{"text":"需进行顶层设计并构建综合培养体系"}]},"annotatedStemRich":[{"text":"熟练运用一门国际通用外语，固然是涉外法治人才不可或缺的基本功，与熟练掌握国际法律规则体系和知识一样重要，但它们绝不是培养高素质涉外法治人才仅有的两门必修业务课(引出话题)。国际化实务能力的培养，应当包括国际贸易、国际金融、国际结算、国际谈判、国际法律文书制作等方面的知识运用能力，是融复合性、专业性、国际性、本土性为一体的跨学科人才培养系统工程(分析说明)。在法学院校中，这需要整合涉外法治人才能力培养相关的院系，并与法律实务部门协力才可完成(后对策)。⑨\n这段文字意在说明，涉外法治人才培养："}],"annotatedOptionRich":{"A":[{"text":"不能仅靠法学院校单独完成(对策有误)"}],"B":[{"text":"应着重提升国际化实务能力(对策有误)"}],"C":[{"text":"要把外语和国际法律列为专业必修课(出处有误)"}],"D":[{"text":"需进行顶层设计并构建综合培养体系"}]},"practicalAnalysis":"文段分析见批注。\n文段为典型后对策结构，对策句为重点，即“需要整合涉外法治人才能力培养相\n关的院系，并与法律实务部门协力才可完成涉外法治人才培养⑩”,对应D选项，当选；","notes":[{"marker":"⑨","content":"行文结构：后对策结构。\n文段引出“涉外法治人才”这一话题后，分析说明国际化能力培养是综合的系统工程；\n文末提出对策：\n需要整合涉外法治人才能力培养相关的院系，并与法律实务部门协力才可完成涉外法治人才培养。\n这段文字意在说明，涉外法治人才培养：\nA. 不能仅靠法学院校单独完成(对策有误)\nB. 应着重提升国际化实务能力(对策有误)\nC. 要把外语和国际法律列为专业必修课(出处有误)\nD. 需进行顶层设计并构建综合培养体系","matchScore":0.7012,"pairingMode":"marker-and-content","order":8},{"marker":"⑩","content":"可理解为：需要整合相关院系进行顶层设计，并且多部门协力综合培养。\nA选项对策有误，未体现尾句对策重点，而且可看作“不是而是”的“不是”部分，一般不是正确选项，排除；B选项的“提升国际化实务能力”过于宽泛，未体现具体对策，排除；C选项的“外语和国际法律列为专业必修课”出自引出话题部分，非对策重点，排除。","matchScore":0.3297,"pairingMode":"marker-and-content","order":9}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300486,3,'细节判断类','今年的寒冬，其实恰恰部分源于全球变暖，这种反常的现象，和一种极地涡旋的气候现象有关。极地涡旋是一种发生于极地、介于对流层和平流层的中上部、持续性长且规模大的气旋。最早记载极地涡旋现象的文献出现于1853年。在北半球的冬季，这种现象会导致突然性平流层暖化。1952年，无线电探空仪在海拔高度超过20公里的观测中发现了这种现象导致的平流层暖化。在2013年后的北美冬季，媒体报道中经常提到这种现象，使得该术语推广成为了对极低温寒潮的解释。
下列关于极地涡旋的表述正确的是：','[{"label":"A","content":"极地涡旋是全球气候变暖的“元凶”"},{"label":"B","content":"极地涡旋现象最早出现于1853年"},{"label":"C","content":"极地涡旋说明了极低温寒潮现象"},{"label":"D","content":"极地涡旋是一种反常的气候现象"}]','C','C选项出自第④句“该术语推广成为了对极低温寒潮的解释”, 这里的“该术语”指代的就是前文提到的“极地涡旋”,本句可以翻译为：极地涡旋解释了极低温寒潮现象，当选。

花生批注：
⑪ 根据第①句可知，今年的寒冬部分源于全球变暖，今年寒冬与极地涡旋有关，而不是极地涡旋导致了全球气候变暖，错误。
⑫ 根据第③句可知，极地涡旋现象最早的记载出现在1853 年，不是极地涡旋现象最早出现于1853年，错误。
⑬ 典型的杂糅选项，根据首句可知，反常的现象指的是“今年的寒冬”,而非后文提到的极地涡旋(是一种气旋), 错误。','2021年甘肃省考','进阶','published','{"globalNumber":486,"setNumber":25,"localNumber":6,"sourceLabel":"2021年甘肃省考67%","accuracy":67,"typeAndPassage":"细节判断类","stemRich":[{"text":"今年的寒冬，其实恰恰部分源于全球变暖，这种反常的现象，和一种极地涡旋的气候现象有关。极地涡旋是一种发生于极地、介于对流层和平流层的中上部、持续性长且规模大的气旋。最早记载极地涡旋现象的文献出现于1853年。在北半球的冬季，这种现象会导致突然性平流层暖化。1952年，无线电探空仪在海拔高度超过20公里的观测中发现了这种现象导致的平流层暖化。在2013年后的北美冬季，媒体报道中经常提到这种现象，使得该术语推广成为了对极低温寒潮的解释。\n下列关于极地涡旋的表述正确的是："}],"optionRich":{"A":[{"text":"极地涡旋是全球气候变暖的“元凶”"}],"B":[{"text":"极地涡旋现象最早出现于1853年"}],"C":[{"text":"极地涡旋说明了极低温寒潮现象"}],"D":[{"text":"极地涡旋是一种反常的气候现象"}]},"annotatedStemRich":[{"text":"①今年的寒冬，其实恰恰部分源于全球变暖，这种反常的现象( D 选项), 和一种极地涡旋的气候现象有关( A选项 ) 。②极地涡旋是一种发生于极地、介于对流层和平流层的中上部、持续性长且规模大的气旋。③最早记载极地涡旋现象的文献出现于1853年( B 选项)。在北半球的冬季，这种现象会导致突然性平流层暖化。1952年，无线电探空仪在海拔高度超过20公里的观测中发现了这种现象导致的平流层暖化。④在2013年后的北美冬季，媒体报道中经常提到这种现象，使得该术语推广成为了对极低温寒潮的解释( C 选项)。\n下列关于极地涡旋的表述正确的是："}],"annotatedOptionRich":{"A":[{"text":"极地涡旋是全球气候变暖的“元凶”①"}],"B":[{"text":"极地涡旋现象最早出现于1853年"}],"C":[{"text":"极地涡旋说明了极低温寒潮现象"}],"D":[{"text":"极地涡旋是一种反常的气候现象\n"},{"text":"S四IHA海IGO公NGK考AO 练习题","bold":true},{"text":" 25 "},{"text":"套","bold":true}]},"practicalAnalysis":"C选项出自第④句“该术语推广成为了对极低温寒潮的解释”, 这里的“该术语”指代的就是前文提到的“极地涡旋”,本句可以翻译为：极地涡旋解释了极低温寒潮现象，当选。","notes":[{"marker":"⑪","content":"根据第①句可知，今年的寒冬部分源于全球变暖，今年寒冬与极地涡旋有关，而不是极地涡旋导致了全球气候变暖，错误。","matchScore":0.5845,"pairingMode":"content-similarity","order":10},{"marker":"⑫","content":"根据第③句可知，极地涡旋现象最早的记载出现在1853 年，不是极地涡旋现象最早出现于1853年，错误。","matchScore":0.5533,"pairingMode":"content-similarity","order":11},{"marker":"⑬","content":"典型的杂糅选项，根据首句可知，反常的现象指的是“今年的寒冬”,而非后文提到的极地涡旋(是一种气旋), 错误。","matchScore":0.5899,"pairingMode":"content-similarity","order":12}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300487,3,'语句填入类','猫虽然平时可能对主人不理不睬，却能在众多声音中识别出主人的声音，并对其投入更多情感和注意。研究发现，猫不仅敏感于主人的声音(音频信息),还敏感于主人呼唤自己的名字(字符信息)。不只是猫，目前的研究发现，猿猴、海豚、狗甚至鹦鹉，都可以识别出自己的名字。它们识别名字的方式与人类基本一致，都是在反复经历某个特殊字符伴随自己的事件之后，才建立起这个字符与自己的关系，
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"这揭示了人类与动物之间的互动模式"},{"label":"B","content":"名字成为与普通字符完全不同的存在"},{"label":"C","content":"它们由此知道自己拥有一个专属代号"},{"label":"D","content":"这实质上是一种条件反射的建立过程\nS四IHA海IGO公NGK考AO 练习题 2 5 套"}]','D','所填入语句在文末，可猜测其是对上文的概括总结。
文段先介绍了猫等动物能识别自己的名字，尾句分析其识别名字的方式：
与人类基本一致、反复经历特殊字符伴随自己的事件、建立字符与自己的关系。这些分析都相对具体，所填入语句应是对“识别名字方式”的总结，“反复经历特殊字符伴随自己的事件后建立字符与自己的关系”就是一种条件反射，对应 D选项，当选；
A选项的“互动模式”无中生有；B选项、C选项意思与前文的“建立起这个字符与自己的关系”相近，并非是对该种识别方式的总结，排除。','2020年国家公务员考试','进阶','published','{"globalNumber":487,"setNumber":25,"localNumber":7,"sourceLabel":"2020年国家公务员考试 69%","accuracy":69,"typeAndPassage":"语句填入类+说理类文段","stemRich":[{"text":"猫虽然平时可能对主人不理不睬，却能在众多声音中识别出主人的声音，并对其投入更多情感和注意。研究发现，猫不仅敏感于主人的声音(音频信息),还敏感于主人呼唤自己的名字(字符信息)。不只是猫，目前的研究发现，猿猴、海豚、狗甚至鹦鹉，都可以识别出自己的名字。它们识别名字的方式与人类基本一致，都是在反复经历某个特殊字符伴随自己的事件之后，才建立起这个字符与自己的关系， "},{"text":"                        ","underline":true},{"text":"\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"这揭示了人类与动物之间的互动模式"}],"B":[{"text":"名字成为与普通字符完全不同的存在"}],"C":[{"text":"它们由此知道自己拥有一个专属代号"}],"D":[{"text":"这实质上是一种条件反射的建立过程\nS四IHA海IGO公NGK考AO 练习题 2 5 套"}]},"annotatedStemRich":[{"text":"猫虽然平时可能对主人不理不睬，却能在众多声音中识别出主人的声音，\n并对其投入更多情感和注意。研究发现，猫不仅敏感于主人的声音(音频信息), 还敏感于主人呼唤自己的名字(字符信息)。不只是猫，目前的研究发现，猿猴、海豚、狗甚至鹦鹉，都可以识别出自己的名字(介绍猫等动物能识别自己名字)。它们识别名字的方式与人类基本一致，都是在反复经历某个特殊字符伴随自己的事件之后，才建立起这个字符与自己的关系，"},{"text":"                         ","underline":true},{"text":" ( 介绍猫等动物识别名字的方式)。\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"这揭示了人类与动物之间的互动模式"}],"B":[{"text":"名字成为与普通字符完全不同的存在"}],"C":[{"text":"它们由此知道自己拥有一个专属代号"}],"D":[{"text":"这实质上是一种条件反射的建立过程"}]},"practicalAnalysis":"所填入语句在文末，可猜测其是对上文的概括总结。\n文段先介绍了猫等动物能识别自己的名字，尾句分析其识别名字的方式：\n与人类基本一致、反复经历特殊字符伴随自己的事件、建立字符与自己的关系。这些分析都相对具体，所填入语句应是对“识别名字方式”的总结，“反复经历特殊字符伴随自己的事件后建立字符与自己的关系”就是一种条件反射，对应 D选项，当选；\nA选项的“互动模式”无中生有；B选项、C选项意思与前文的“建立起这个字符与自己的关系”相近，并非是对该种识别方式的总结，排除。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300488,3,'中心理解题','大国经济的重要特征，就是必须实现内部可循环，并且提供巨大国内市场，提高供给能力，支撑并带动外循环。我国拥有14亿多人口的全球最大最有潜力市场，随着向高收入国家行列迈进，规模巨大的国内市场不断扩张。新形势下，构建以国内大循环为主体、国内国际双循环相互促进的新发展格局，是把握未来发展主动权的战略性布局和先手棋，是贯彻新发展理念、促进大国经济发展的重大举措。
这段文字旨在强调：','[{"label":"A","content":"构建新发展格局的重大意义"},{"label":"B","content":"把握未来主动权必须扩大国际市场"},{"label":"C","content":"强大的国内国际市场是高收入国家的特征"},{"label":"D","content":"提高供给能力是发展大国经济的重要抓手"}]','A','文段分析见批注。
文段先介绍背景，大国经济中国内市场非常重要，我国国内市场潜力巨大且不断扩张；后文强调在这样的新形势下我国构建新发展格局的重要意义；只有A选项提到了“新发展格局及其意义”,当选；
其他选项均未提到“新发展格局”,可简单排除。

花生批注：
⑭ 行文结构：二层结构之背景
+正文。
先介绍背景(即下文的新形势 ):
我国国内市场潜力巨大且不断扩张；
再介绍在新形势下构建新发展格局的意义：
1. 是把握未来发展主动权的战略性布局和先手棋；
2.是贯彻新发展理念、促进大国经济发展的重大举措。','2024年广东省事业单位','基础','published','{"globalNumber":488,"setNumber":25,"localNumber":8,"sourceLabel":"2024年广东省事业单位 74%","accuracy":74,"typeAndPassage":"中心理解题+说理类文段","stemRich":[{"text":"大国经济的重要特征，就是必须实现内部可循环，并且提供巨大国内市场，提高供给能力，支撑并带动外循环。我国拥有14亿多人口的全球最大最有潜力市场，随着向高收入国家行列迈进，规模巨大的国内市场不断扩张。新形势下，构建以国内大循环为主体、国内国际双循环相互促进的新发展格局，是把握未来发展主动权的战略性布局和先手棋，是贯彻新发展理念、促进大国经济发展的重大举措。\n这段文字旨在强调："}],"optionRich":{"A":[{"text":"构建新发展格局的重大意义"}],"B":[{"text":"把握未来主动权必须扩大国际市场"}],"C":[{"text":"强大的国内国际市场是高收入国家的特征"}],"D":[{"text":"提高供给能力是发展大国经济的重要抓手"}]},"annotatedStemRich":[{"text":"大国经济的重要特征，就是必须实现内部可循环，并且提供巨大国内市场，提高供给能力，支撑并带动外循环。我国拥有14亿多人口的全球最大最有潜力市场，随着向高收入国家行列迈进，规模巨大的国内市场不断扩张(背景介绍 ) 。新形势下，构建以国内大循环为主体、国内国际双循环相互促进的新发展格局，是把握未来发展主动权的战略性布局和先手棋，是贯彻新发展理念、促进大国经济发展的重大举措(正文)。⑩\n这段文字旨在强调："}],"annotatedOptionRich":{"A":[{"text":"构建新发展格局的重大意义(具体类)"}],"B":[{"text":"把握未来主动权必须扩大国际市场(对策有误)"}],"C":[{"text":"强大的国内国际市场是高收入国家的特征(无中生有)"}],"D":[{"text":"提高供给能力是发展大国经济的重要抓手(出处有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍背景，大国经济中国内市场非常重要，我国国内市场潜力巨大且不断扩张；后文强调在这样的新形势下我国构建新发展格局的重要意义；只有A选项提到了“新发展格局及其意义”,当选；\n其他选项均未提到“新发展格局”,可简单排除。","notes":[{"marker":"⑭","content":"行文结构：二层结构之背景\n+正文。\n先介绍背景(即下文的新形势 ):\n我国国内市场潜力巨大且不断扩张；\n再介绍在新形势下构建新发展格局的意义：\n1. 是把握未来发展主动权的战略性布局和先手棋；\n2.是贯彻新发展理念、促进大国经济发展的重大举措。","matchScore":0.9739,"pairingMode":"content-similarity","order":13}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300489,3,'语句排序题','①凡是具有人文精神的作品，便是很好的教科书
②能培育人的认知能力和审美能力，提高人的精神素养，净化人的灵魂，给人以力量、智慧和愉悦
③早先在先秦时代就有《诗经》的四言体和《楚辞》的骚体，尔后不断发展出各种体裁，到五四时期出现自由诗
④我国有“诗国”的美称，诗歌起源之早，数量之多，内容之丰富，艺术之精湛，对社会生活影响之大，在世界文化史上都是罕见的
⑤无论是山水诗、田园诗、边塞诗，还是言志诗、爱情诗、哲理诗
⑥诗歌是我国文化艺术的瑰宝
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"⑥①⑤②④③"},{"label":"B","content":"④③⑥⑤①②⑯"},{"label":"C","content":"④③⑤②( ⑥①"},{"label":"D","content":"⑥③④①⑤②"}]','B','本题首句不好判断，可从缺少主语的②句入手；观察选项可知， ②可能接①或⑤,若⑤②捆绑，“无论”没有搭配的逻辑关联词；若⑤①②捆绑，“无论……凡是……便是”衔接得当①,且解决②没主语的问题，锁定B选项；
验证B选项，④③⑥可看作背景引出话题“诗歌”,⑤①②介绍“有人文精神的诗歌就是很好的教材书，就有积极意义”,逻辑正确，当选。

花生批注：
⑮ “诗歌”为全文论述话题
⑰ 无论是什么体裁的诗歌，凡
有人文精神，就是很好的教材，(就)能培育人、提高人。','2019年公务员联考','进阶','published','{"globalNumber":489,"setNumber":25,"localNumber":9,"sourceLabel":"2019年公务员联考 65%","accuracy":65,"typeAndPassage":"语句排序题+说理类文章","stemRich":[{"text":"①凡是具有人文精神的作品，便是很好的教科书\n②能培育人的认知能力和审美能力，提高人的精神素养，净化人的灵魂，给人以力量、智慧和愉悦\n③早先在先秦时代就有《诗经》的四言体和《楚辞》的骚体，尔后不断发展出各种体裁，到五四时期出现自由诗\n④我国有“诗国”的美称，诗歌起源之早，数量之多，内容之丰富，艺术之精湛，对社会生活影响之大，在世界文化史上都是罕见的\n⑤无论是山水诗、田园诗、边塞诗，还是言志诗、爱情诗、哲理诗\n⑥诗歌是我国文化艺术的瑰宝\n将以上6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"⑥①⑤②④③"}],"B":[{"text":"④③⑥⑤①②⑯"}],"C":[{"text":"④③⑤②( ⑥①"}],"D":[{"text":"⑥③④①⑤②"}]},"annotatedStemRich":[{"text":"①凡是具有人文精神的作品，便是很好的教科书\n②能培育人的认知能力和审美能力，提高人的精神素养，净化人的灵魂，给人以力量、智慧和愉悦\n③早先在先秦时代就有《诗经》的四言体和《楚辞》的骚体，尔后不断发展出各种体裁，到五四时期出现自由诗\n④我国有“诗国”的美称，诗歌起源之早，数量之多，内容之丰富，艺术之精湛，对社会生活影响之大，在世界文化史上都是罕见的\n⑤无论是山水诗、田园诗、边塞诗，还是言志诗、爱情诗、哲理诗\n⑥"},{"text":"诗歌","underline":true},{"text":"⑤是我国文化艺术的瑰宝\n将以上6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"⑥①⑤②④③"}],"B":[{"text":"④③⑥⑤①②⑯"}],"C":[{"text":"④③⑤②( ⑥①"}],"D":[{"text":"⑥③④①⑤②"}]},"practicalAnalysis":"本题首句不好判断，可从缺少主语的②句入手；观察选项可知， ②可能接①或⑤,若⑤②捆绑，“无论”没有搭配的逻辑关联词；若⑤①②捆绑，“无论……凡是……便是”衔接得当①,且解决②没主语的问题，锁定B选项；\n验证B选项，④③⑥可看作背景引出话题“诗歌”,⑤①②介绍“有人文精神的诗歌就是很好的教材书，就有积极意义”,逻辑正确，当选。","notes":[{"marker":"⑮","content":"“诗歌”为全文论述话题","matchScore":0.2724,"pairingMode":"content-similarity","order":14},{"marker":"⑰","content":"无论是什么体裁的诗歌，凡\n有人文精神，就是很好的教材，(就)能培育人、提高人。","matchScore":0.7421,"pairingMode":"content-similarity","order":16}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300490,3,'中心理解题','如果把“新市民”这个群体按照生命周期来划分，金融服务应贯穿新市民的整个生命周期，从最前端的到城市找工作，到后面的生活消费，再到结婚生子，以及未来孩子的教育和医疗保险。具体的金融产品应服务到每一个重要阶段：进城、落户期间租房买房需要的购房和装修贷款；安置生活购买家电产品需要的消费和车辆贷款；就业创业的启动和周转资金贷款；孩子助学贷款、自我提升的就业培训贷款；提升生活品质的消费分期贷款；赡养老人所需的医疗险等。
根据这段文字，作者最有可能赞同：','[{"label":"A","content":"应根据新市民生活工作阶段设计针对性强的金融服务产品"},{"label":"B","content":"金融服务应当在现阶段基础上进一步根据生命周期来细分"},{"label":"C","content":"就业生活、医疗教育应当成为当前阶段金融产品设计的重点"},{"label":"D","content":"应当进一步细分适用场景不同的新市民群体的金融服务产品\n片段阅读6 00 (下册)"}]','A','文段分析见批注。
文段为典型的前对策结构，首句开门见山提出对策，金融服务要贯穿新市民生命周期，金融产品要服务到每一个重要阶段；四个选项都是对策类选项，但只有A选项体现了“根据新市民的不同阶段提供有针对性的金融服务产品”, 当选；
B选项和C选项没体现金融服务的对象“新市民”,排除； D选项的“进一步细分适用场景”表述不如A选项的“生活工作阶段”具体，排除。

花生批注：
⑱ 新市民为全文论述主体。
⑲ 行文结构：前对策结构。
开门见山提出对策：
金融服务要贯穿新市民整个生命周期，具体的金融产品要服务到每一个阶段。
再举例论证。
20 不同适用场景，可能是同一时段的不同场景，未体现“生命周期的每一个时间阶段”。','2023年广东省事业单位','挑战','published','{"globalNumber":490,"setNumber":25,"localNumber":10,"sourceLabel":"2023年广东省事业单位39%","accuracy":39,"typeAndPassage":"中心理解题+说理类文段","stemRich":[{"text":"如果把“新市民”这个群体按照生命周期来划分，金融服务应贯穿新市民的整个生命周期，从最前端的到城市找工作，到后面的生活消费，再到结婚生子，以及未来孩子的教育和医疗保险。具体的金融产品应服务到每一个重要阶段：进城、落户期间租房买房需要的购房和装修贷款；安置生活购买家电产品需要的消费和车辆贷款；就业创业的启动和周转资金贷款；孩子助学贷款、自我提升的就业培训贷款；提升生活品质的消费分期贷款；赡养老人所需的医疗险等。\n根据这段文字，作者最有可能赞同："}],"optionRich":{"A":[{"text":"应根据新市民生活工作阶段设计针对性强的金融服务产品"}],"B":[{"text":"金融服务应当在现阶段基础上进一步根据生命周期来细分"}],"C":[{"text":"就业生活、医疗教育应当成为当前阶段金融产品设计的重点"}],"D":[{"text":"应当进一步细分适用场景不同的新市民群体的金融服务产品\n片段阅读6 00 (下册)"}]},"annotatedStemRich":[{"text":"如果把"},{"text":"“新市民”","underline":true},{"text":"⑱这个群体按照生命周期来划分，金融服务应贯穿新市民的整个生命周期，从最前端的到城市找工作，到后面的生活消费，再到结婚生子，以及未来孩子的教育和医疗保险。具体的金融产品应服务到每一个重要阶段(提出对策):进城、落户期间租房买房需要的购房和装修贷款；安置生活购买家电产品需要的消费和车辆贷款；就业创业的启动和周转资金贷款；孩子助学贷款、自我提升的就业培训贷款；提升生活品质的消费分期贷款；赡养老人所需的医疗险等(举例论证)。⑨\n根据这段文字，作者最有可能赞同："}],"annotatedOptionRich":{"A":[{"text":"应根据新市民生活工作阶段设计针对性强的金融服务产品"}],"B":[{"text":"金融服务应当在现阶段基础上进一步根据生命周期来细分(缺主体)"}],"C":[{"text":"就业生活、医疗教育应当成为当前阶段金融产品设计的重点(缺主体)"}],"D":[{"text":"应当进一步细分适用场景不同的新市民群体的金融服务产品"},{"text":"(宽泛)","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段为典型的前对策结构，首句开门见山提出对策，金融服务要贯穿新市民生命周期，金融产品要服务到每一个重要阶段；四个选项都是对策类选项，但只有A选项体现了“根据新市民的不同阶段提供有针对性的金融服务产品”, 当选；\nB选项和C选项没体现金融服务的对象“新市民”,排除； D选项的“进一步细分适用场景”表述不如A选项的“生活工作阶段”具体，排除。","notes":[{"marker":"⑱","content":"新市民为全文论述主体。","matchScore":0.2393,"pairingMode":"marker-and-content","order":17},{"marker":"⑲","content":"行文结构：前对策结构。\n开门见山提出对策：\n金融服务要贯穿新市民整个生命周期，具体的金融产品要服务到每一个阶段。\n再举例论证。","matchScore":0.9494,"pairingMode":"content-similarity","order":18},{"marker":"20","content":"不同适用场景，可能是同一时段的不同场景，未体现“生命周期的每一个时间阶段”。","matchScore":0.4923,"pairingMode":"content-similarity","order":19}],"pairingMode":"text-and-sequence"}');
