INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300492,3,'语句填入类','互联网新闻业颠覆了新闻媒介和职业记者是公众与消息来源和信息准确可靠性之间权威通道的传统理念。以往优秀的职业记者和强大公信力的媒介机构在获取消息来源、验证信息准确度方面具有得天独厚的资源和优势，这也是职业与非职业新闻业之间的分野所在。然而今天，除了各类消息来源都可以直接面对公众之外，遍布全球、专业高效的互联网用户，也使得信息的交叉验证变得比以往更为便捷。简而言之，媒介机构不再是新闻事件的权威阐释主体，新闻报道的价值和意义
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"已然掌握在互联网各类新媒体手中"},{"label":"B","content":"不再由传统的权威新闻媒体所定义"},{"label":"C","content":"由互联网用户的广泛参与而消解"},{"label":"D","content":"经由公众的集体参与而被重塑"}]','D','所填入语句在文末且由“简而言之”引出，可确定尾句是对上文内容的简略总结。
尾句“媒介机构不再是新闻事件的权威阐释主体”是对上文“以往优秀的职业记者和强大公信力的媒介机构……这也是职业与非职业新闻业之间的分野所在”的“简而言之”,那么后文“然而今天，除了各类消息来源都可以直接面对公众之外，遍布全球、专业高效的互联网用户，也使得信息的交叉验证变得比以往更为便捷”的主要意思应被所填入语句概括，即“公众可广泛参与新闻的获得与验证”;

花生批注：
2 消解指的是消释与消除，新闻报道的价值不会因为公众参与而消失，该表述有悖常识。
观察选项，A选项、B选项②未体现“公众参与新闻产生”这一意思，排除； C选项的“新闻报道价值和意义被消解”本身有误；
D选项的“经由公众集体参与”对应上文“然而”后内容，“新闻报道的价值和意义被重塑”指的是新闻报道因公众参与而与以往不同，完美体现全文意思，当选。','2022江苏省考','挑战','published','{"globalNumber":492,"setNumber":25,"localNumber":12,"sourceLabel":"2022江苏省考36%","accuracy":36,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"互联网新闻业颠覆了新闻媒介和职业记者是公众与消息来源和信息准确可靠性之间权威通道的传统理念。以往优秀的职业记者和强大公信力的媒介机构在获取消息来源、验证信息准确度方面具有得天独厚的资源和优势，这也是职业与非职业新闻业之间的分野所在。然而今天，除了各类消息来源都可以直接面对公众之外，遍布全球、专业高效的互联网用户，也使得信息的交叉验证变得比以往更为便捷。简而言之，媒介机构不再是新闻事件的权威阐释主体，新闻报道的价值和意义\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"已然掌握在互联网各类新媒体手中"}],"B":[{"text":"不再由传统的权威新闻媒体所定义"}],"C":[{"text":"由互联网用户的广泛参与而消解"}],"D":[{"text":"经由公众的集体参与而被重塑"}]},"annotatedStemRich":[{"text":"互联网新闻业颠覆了新闻媒介和职业记者是公众与消息来源和信息准确可靠性之间权威通道的传统理念。以往优秀的职业记者和强大公信力的媒介机构在获取消息来源、验证信息准确度方面具有得天独厚的资源和优势，这也是职业与非职业新闻业之间的分野所在。然而今天，除了各类消息来源都可以直接面对公众之外，遍布全球、专业高效的互联网用户，也使得信息的交叉验证变得比以往更为便捷。简而言之，媒介机构不再是新闻事件的权威阐释主体，新\n闻报道的价值和意义 "},{"text":"                        ","underline":true},{"text":"\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"已然掌握在互联网各类新媒体手中"}],"B":[{"text":"不再由传统的权威新闻媒体所定义"}],"C":[{"text":"由互联网用户的广泛参与而消解"}],"D":[{"text":"经由公众的集体参与而被重塑"}]},"practicalAnalysis":"所填入语句在文末且由“简而言之”引出，可确定尾句是对上文内容的简略总结。\n尾句“媒介机构不再是新闻事件的权威阐释主体”是对上文“以往优秀的职业记者和强大公信力的媒介机构……这也是职业与非职业新闻业之间的分野所在”的“简而言之”,那么后文“然而今天，除了各类消息来源都可以直接面对公众之外，遍布全球、专业高效的互联网用户，也使得信息的交叉验证变得比以往更为便捷”的主要意思应被所填入语句概括，即“公众可广泛参与新闻的获得与验证”;","notes":[{"marker":"2","content":"消解指的是消释与消除，新闻报道的价值不会因为公众参与而消失，该表述有悖常识。\n观察选项，A选项、B选项②未体现“公众参与新闻产生”这一意思，排除； C选项的“新闻报道价值和意义被消解”本身有误；\nD选项的“经由公众集体参与”对应上文“然而”后内容，“新闻报道的价值和意义被重塑”指的是新闻报道因公众参与而与以往不同，完美体现全文意思，当选。","matchScore":0.2712,"pairingMode":"content-similarity","order":21}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300493,3,'中心理解题','互联网的唯一性让安全风险变得更集中，一旦发生问题，建立在其上的体系都会崩塌。对中国而言，现有网络基础设施的核心技术受制于人，这是最大的隐患。要从根本上抵御安全风险，敢于跳出已有框架，从“0”到“1”打造独创、独有的网络、不再让互联网一网独大。可以预测，现有网络体系正酝酿着一场根本变革，未来将出现关键网络技术体系更新。中国只要抓住机遇、提前筹划，完全可能在新的网络发展模式上获得引领地位，掌握网络技术发展的主导权。
这段文字意在说明：','[{"label":"A","content":"未来网络技术体系将有颠覆性更新"},{"label":"B","content":"中国有望掌握网络技术发展主导权"},{"label":"C","content":"精细化应用场景对网络安全性提出全面要求"},{"label":"D","content":"互联网原始设计缺陷导致安全风险不可避免"}]','B','文段分析见批注。
文段先指出“我国网络基础设施核心技术受制于人是隐患”的问题，再给出对策“我国只要抓住机遇提前筹划，就可能掌握网络技术发展的主导权”, 对策是重点，且要体现主体“我国”,只有B选项符合，当选；
其他选项均未提及“我国”,均可简单排除。

花生批注：
② 有的同学可能会认为B选项的“不再”与上文的“不再”构成排比句，读着通顺；
但如填入B选项，则文末的“简而言之”总结句未能体现上文的全部意思，显然并不合适。
④ 行文结构：后对策结构。
先提出问题：
互联网使安全风险集中，我国网络基础设施核心技术受制于人是隐患；
再分析问题；
最后给出对策：
我国只要抓住机遇提前筹划，就可能掌握网络技术发展的主导权。','23年事业单位联考','基础','published','{"globalNumber":493,"setNumber":25,"localNumber":13,"sourceLabel":"23年事业单位联考72%","accuracy":72,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"互联网的唯一性让安全风险变得更集中，一旦发生问题，建立在其上的体系都会崩塌。对中国而言，现有网络基础设施的核心技术受制于人，这是最大的隐患。要从根本上抵御安全风险，敢于跳出已有框架，从“0”到“1”打造独创、独有的网络、不再让互联网一网独大。可以预测，现有网络体系正酝酿着一场根本变革，未来将出现关键网络技术体系更新。中国只要抓住机遇、提前筹划，完全可能在新的网络发展模式上获得引领地位，掌握网络技术发展的主导权。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"未来网络技术体系将有颠覆性更新"}],"B":[{"text":"中国有望掌握网络技术发展主导权"}],"C":[{"text":"精细化应用场景对网络安全性提出全面要求"}],"D":[{"text":"互联网原始设计缺陷导致安全风险不可避免"}]},"annotatedStemRich":[{"text":"互联网的唯一性让安全风险变得更集中，一旦发生问题，建立在其上的体系都会崩塌。对"},{"text":"中国","underline":true},{"text":"而言，现有网络基础设施的核心技术受制于人，这是最大的隐患(提出问题)。要从根本上抵御安全风险，敢于跳出已有框架，从“0”到“1”打造独创、独有的网络、不再让互联网一网独大。可以预测，现有网络体系正酝酿着一场根本变革，未来将出现关键网络技术体系更新(分析问题)。中国只要抓住机遇、提前筹划，完全可能在新的网络发展模式上获得引领地位，掌握网络技术发展的主导权(后对策)。②\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"未来网络技术体系将有颠覆性更新"}],"B":[{"text":"中国有望掌握网络技术发展主导权"}],"C":[{"text":"精细化应用场景对网络安全性提出全面要求"}],"D":[{"text":"互联网原始设计缺陷导致安全风险不可避免"}]},"practicalAnalysis":"文段分析见批注。\n文段先指出“我国网络基础设施核心技术受制于人是隐患”的问题，再给出对策“我国只要抓住机遇提前筹划，就可能掌握网络技术发展的主导权”, 对策是重点，且要体现主体“我国”,只有B选项符合，当选；\n其他选项均未提及“我国”,均可简单排除。","notes":[{"marker":"②","content":"有的同学可能会认为B选项的“不再”与上文的“不再”构成排比句，读着通顺；\n但如填入B选项，则文末的“简而言之”总结句未能体现上文的全部意思，显然并不合适。","matchScore":0.1658,"pairingMode":"marker-and-content","order":20},{"marker":"④","content":"行文结构：后对策结构。\n先提出问题：\n互联网使安全风险集中，我国网络基础设施核心技术受制于人是隐患；\n再分析问题；\n最后给出对策：\n我国只要抓住机遇提前筹划，就可能掌握网络技术发展的主导权。","matchScore":0.9797,"pairingMode":"content-similarity","order":23}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300494,3,'细节判断类','红树植物之“红”不在于树叶，而在于树干、枝杈，其断裂面露出的单宁物质非常容易氧化，从而呈现红色，这就是其名称的由来。红树生长在海边潮水涨落的污泥滩涂环境，必有高超的生存之道—— 其拒盐、泌盐的功能就是一种“妙招”。红树林组成树种之一——蜡烛果，又名桐花树。与大多数红树植物一样，蜡烛果的根系具有超级的“拒盐”本领，长期的海洋环境适应性演化使其发展出极具特色的“半透膜”构造，不仅可以将海水之中的盐质拒于体外，而且有能力从高盐海水中汲取生命活动所需要的淡水。俗话说“常在河边走，哪能不湿鞋”,蜡烛果等红树类植物的根系也难以完全阻止盐分入体，而其解决问题的方式是分泌盐分。分泌结构是植物(体表或体内)的一些特殊细胞或细胞群，可产生一些次生代谢物质并分泌出去。这些次生代谢物包括挥发油、生物碱、有机酸、树脂、杀菌素和蜜汁等。蜡烛果具有分泌无机盐的结构——盐腺。
根据这段文字，下列说法正确的是：','[{"label":"A","content":"红树植物得名于其树干、树权的表面呈现红色，其树叶并不为红色"},{"label":"B","content":"海边潮水涨落的污泥滩涂环境属于高盐环境，不利于普通植物的生长"},{"label":"C","content":"红树植物通过“半透膜”构造，可以将海水完全过滤成其需要的淡水"},{"label":"D","content":"蜡烛果等红树植物区别于其他植物的特点在于具有产生次生代谢物质的分泌结构"}]','B','B选项，根据文段第②句的“红树生长在海边潮水涨落的污泥滩

花生批注：
25 根据①句可知，红树植物得名于树干、树权的断裂面呈红色，而非树干和树权的表面，错误。
26 根据⑤句可知，红树类植物也难以完全阻止盐分入体，“将海水完全过滤成需要的淡水”表述过于绝对化，错误。
考场思维：这类绝对化且有悖常识的选项，可直接排除。
28 根据常识可知，海水含盐量较高；
后文也介绍了红树植物需要将水中的盐质拒于体外，进入植物内部的盐也需要分泌出去；
都可得出含盐量较高的结论。
注：较难的细节判断经常存在这样的选项设置，一个选项犯了严重的、违背常规逻辑的错误，一个选项稍有“过度”推断但符合常理，此时一定“抓大放小”。
涂环境，必有高超的生存之道”可知，没有“高超的生存之道就不能生长在海边潮水涨落的污泥滩涂环境”,并结合后文和常识可知②,污泥滩涂含盐量较高，正确，当选。
