INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300498,3,'标题拟定题','仔细研究各地那些消失的地方特色美食、知名老店，我们会发现很多美味不是消失于“市场的选择”, 而是在动迁中无法接续。对城市来说，不能只有看得见的光鲜和便于量化的经济增长指标，更需要有市井的味道、城市的记忆、百姓的情感。如何避免“改造对城市文化记忆的打断”,是摆在中国众多城市治理者面前的一个共同课题。在两难中谋取两全，兼顾城市繁华与人间烟火味，更需要制度的温情和治理的智慧。
最适合做这段文字标题的是：','[{"label":"A","content":"城市管理两难，还需争取两全"},{"label":"B","content":"市场选择与城市文化的传承"},{"label":"C","content":"市井的味道，城市的记忆"},{"label":"D","content":"城市变迁中的地方美食"}]','A','文段结构见批注。
