INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300501,3,'中心理解题','1971年10月，联合国第26届大会上，中国恢复了在联合国的合法席位。1972年2月，尼克松总统访华，在上海签订了《中美联合公报》。1978年底，中美两国发表《中美建交公报》,中美两国于1979年正式建立外交关系，两国关系开始走向正常化。1972年秋，田中角荣首相访华，1973年，中日建交。中美、中日建交的影响，符合三个国家的利益，有利于亚太地区的和平与稳定，有利于世界的和平与稳定。中国参与地区性国际组织：1991年开始，中国外交部长每年都作为特邀贵宾出席东盟会议。对这段文字的主题思想，概括正确是：','[{"label":"A","content":"维护世界和平，促进共同发展"},{"label":"B","content":"中国重返联合国"},{"label":"C","content":"中国的外交政策是独立自主的和平外交政策"},{"label":"D","content":"中国外交打开新局面"}]','D','文段分析见批注。
文段属于大并列结构，依次介绍中国自1971年开始的各种外交行为，D选项是全文的概括，当选；
A选项缺少主题词外交，且缺少主语“中国”;B选项仅对应第一句，片面； C选项无中生有，全文并未提及中国的外交政策是怎样的，均可简单排除。

花生批注：
①① 行文结构：大并列结构。
对这段文字的主题思想，概括正确是：文段依次介绍：
A. 维护世界和平，促进共同发展(缺主题词) ①1971年10月中国恢复了
在联合国的合法席位；
B. 中国重返联合国(片面) ②1972年2月，尼克松总
C. 中国的外交政策是独立自主的和平外交政策(无中生有) 年；中美建交；
D. 中国外交打开新局面公考最新资料、更新进度微信SKA674 ④1973年中日建交；','23年天津市事业单位','基础','published','{"globalNumber":501,"setNumber":26,"localNumber":1,"sourceLabel":"23年天津市事业单位77%","accuracy":77,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"1971年10月，联合国第26届大会上，中国恢复了在联合国的合法席位。1972年2月，尼克松总统访华，在上海签订了《中美联合公报》。1978年底，中美两国发表《中美建交公报》,中美两国于1979年正式建立外交关系，两国关系开始走向正常化。1972年秋，田中角荣首相访华，1973年，中日建交。中美、中日建交的影响，符合三个国家的利益，有利于亚太地区的和平与稳定，有利于世界的和平与稳定。中国参与地区性国际组织：1991年开始，中国外交部长每年都作为特邀贵宾出席东盟会议。对这段文字的主题思想，概括正确是："}],"optionRich":{"A":[{"text":"维护世界和平，促进共同发展"}],"B":[{"text":"中国重返联合国"}],"C":[{"text":"中国的外交政策是独立自主的和平外交政策"}],"D":[{"text":"中国外交打开新局面"}]},"annotatedStemRich":[{"text":"①1971年10月，联合国第26届大会上，中国恢复了在联合国的合法席位。\n②1972年2月，尼克松总统访华，在上海签订了《中美联合公报》。③1978 年底，中美两国发表《中美建交公报》,中美两国于1979年正式建立外交关系，两国关系开始走向正常化。④1972年秋，田中角荣首相访华，1973年，中日建交。中美、中日建交的影响，符合三个国家的利益，有利于亚太地区的和平\n与稳定，有利于世界的和平与稳定。⑤中国参与地区性国际组织：1991年开始，\n中国外交部长每年都作为特邀贵宾出席东盟会议。① ①"},{"text":"花生批注：","bold":true},{"text":"\n"},{"text":"行文结构：","bold":true},{"text":"大并列结构。\n对这段文字的主题思想，概括正确是：文段依次介绍："}],"annotatedOptionRich":{"A":[{"text":"维护世界和平，促进共同发展"},{"text":"(缺主题词)","bold":true},{"text":" ①1971年10月中国恢复了\n在联合国的合法席位；"}],"B":[{"text":"中国重返联合国(片面) ②1972年2月，尼克松总"}],"C":[{"text":"中国的外交政策是独立自主的和平外交政策(无中生有) 年；中美建交；"}],"D":[{"text":"中国外交打开新局面","bold":true},{"text":" \n⑤1991年开始中国参与"}]},"practicalAnalysis":"文段分析见批注。\n文段属于大并列结构，依次介绍中国自1971年开始的各种外交行为，D选项是全文的概括，当选；\nA选项缺少主题词外交，且缺少主语“中国”;B选项仅对应第一句，片面； C选项无中生有，全文并未提及中国的外交政策是怎样的，均可简单排除。","notes":[{"marker":"①①","content":"行文结构：大并列结构。\n对这段文字的主题思想，概括正确是：文段依次介绍：\nA. 维护世界和平，促进共同发展(缺主题词) ①1971年10月中国恢复了\n在联合国的合法席位；\nB. 中国重返联合国(片面) ②1972年2月，尼克松总\nC. 中国的外交政策是独立自主的和平外交政策(无中生有) 年；中美建交；\nD. 中国外交打开新局面公考最新资料、更新进度微信SKA674 ④1973年中日建交；","matchScore":0.8141,"pairingMode":"content-similarity","order":5}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300502,3,'标题拟定类','国家的制度变革和治理现代化与每个人息息相关。从“管理”到“治理”,一字之变，其内涵与外延都发生了巨大变化。“管理”更多强调的是自上而下的维度，而“治理”则具有更多平等和共治的意味，是公共事务相关主体对于国家和社会事务的有序参与，是各类主体围绕国家和社会事务的协商互动。“治理”理念的提出，本身就是一种现代化的转型，有利于促进社会参与、激发社会活力，更好吸纳群众有序政治参与。
下列选项最适合作为这一文段标题的是：','[{"label":"A","content":"国家治理现代化的内涵与外延"},{"label":"B","content":"“管理”和“治理”的一字之变"},{"label":"C","content":"国家治理现代化，人人都是参与者"},{"label":"D","content":"国家制度完善和发展，我们都是受益人"}]','C','文段分析见批注。
文段可看作是前观点结构，而且尾句重复了观点：即国家治理现代化转型和每个人相关，有利于促进社会群众广泛参与；观点正对应 C选项，当选。
A选项出处有误，出自分析说明部分，适合科普介绍类文段，排除； D选项的“我们都是受益人”无中生有，排除；
B选项为强干扰项，可看作是区别比较联系类选项，但原文只是用“管理”引出“治理”,首句和尾句均重点介绍现在的“治理”,而且B选项未体现“一字之变”后“治理”的内涵与意义，不如 C选项具体，排除。

花生批注：
② 行文结构：前观点结构。
开门见山提出观点：
国家制度变革和治理现代化与每个人有关；
中间介绍“管理”与“治理”的含义：
管理强调“自上而下”,治理强调“平等共治、广泛参与互动”;
尾句重复观点：
治理是现代化转型，有利于社会群众广泛参与。','2021年广东省考','挑战','published','{"globalNumber":502,"setNumber":26,"localNumber":2,"sourceLabel":"2021年广东省考 41%","accuracy":41,"typeAndPassage":"标题拟定类+说理类文章","stemRich":[{"text":"国家的制度变革和治理现代化与每个人息息相关。从“管理”到“治理”,一字之变，其内涵与外延都发生了巨大变化。“管理”更多强调的是自上而下的维度，而“治理”则具有更多平等和共治的意味，是公共事务相关主体对于国家和社会事务的有序参与，是各类主体围绕国家和社会事务的协商互动。“治理”理念的提出，本身就是一种现代化的转型，有利于促进社会参与、激发社会活力，更好吸纳群众有序政治参与。\n下列选项最适合作为这一文段标题的是："}],"optionRich":{"A":[{"text":"国家治理现代化的内涵与外延"}],"B":[{"text":"“管理”和“治理”的一字之变"}],"C":[{"text":"国家治理现代化，人人都是参与者"}],"D":[{"text":"国家制度完善和发展，我们都是受益人"}]},"annotatedStemRich":[{"text":"国家的制度变革和治理现代化与每个人息息相关(前观点)。从“管理”到“治理”,一字之变，其内涵与外延都发生了巨大变化。“管理”更多强调的是自上而下的维度，而“治理”则具有更多平等和共治的意味，是公共事务相关主体对于国家和社会事务的有序参与，是各类主体围绕国家和社会事务的协商互"},{"text":"动(分析说明)。","bold":true},{"text":"“治理”理念的提出，本身就是一种现代化的转型，有利于促进社会参与、激发社会活力，更好吸纳群众有序政治参与"},{"text":"(重复观点)。②","bold":true},{"text":"\n下列选项最适合作为这一文段标题的是："}],"annotatedOptionRich":{"A":[{"text":"国家治理现代化的内涵与外延(出处有误)"}],"B":[{"text":"“管理”和“治理”的一字之变(区别比较联系类)"}],"C":[{"text":"国家治理现代化，人人都是参与者"}],"D":[{"text":"国家制度完善和发展，我们都是受益人(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段可看作是前观点结构，而且尾句重复了观点：即国家治理现代化转型和每个人相关，有利于促进社会群众广泛参与；观点正对应 C选项，当选。\nA选项出处有误，出自分析说明部分，适合科普介绍类文段，排除； D选项的“我们都是受益人”无中生有，排除；\nB选项为强干扰项，可看作是区别比较联系类选项，但原文只是用“管理”引出“治理”,首句和尾句均重点介绍现在的“治理”,而且B选项未体现“一字之变”后“治理”的内涵与意义，不如 C选项具体，排除。","notes":[{"marker":"②","content":"行文结构：前观点结构。\n开门见山提出观点：\n国家制度变革和治理现代化与每个人有关；\n中间介绍“管理”与“治理”的含义：\n管理强调“自上而下”,治理强调“平等共治、广泛参与互动”;\n尾句重复观点：\n治理是现代化转型，有利于社会群众广泛参与。","matchScore":0.7594,"pairingMode":"marker-and-content","order":6}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300503,3,'语句排序类','①人文关怀是一所大学最可爱的地方
②正直的情操、完满的人格，勇于担当责任，敢于坚守真理……到底该成为什么样的人，是远比学习具体知识更为重要的大学课程
③大学不仅要教书，更要育人，最高远的渴求除却知识，更应有智慧
④于细微处流露的真情与责任背后，是一所大学所秉持的价值观和所追求的精神气象
⑤虽然无形，却充盈各处，虽然柔软，却无比坚韧
⑥舆论场里热议的“清华温度”恰恰说明了今天人们对于“大学之道，在明明德”的向往与共识将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"②⑤⑥③①④"},{"label":"B","content":"①⑤④⑥③②③"},{"label":"C","content":"③②⑥④⑤①"},{"label":"D","content":"⑥②①③⑤④\n片段阅读6 00 (下册)"}]','B','文段分析见批注。
观察选项可知，①②③⑥可能做首句，①是引出大学最可爱的地方且可看作下定义，②③具体介绍大学育人更重要，⑥是证明观点的论证，所以，①做首句最为可能；
验证B选项：①引出人文关怀，⑤是对人文关怀的评价(和①句共用主语人文关怀),④⑥是对人文关怀的进一步评价和解释，③②给出观点：大学更应该育人。全文可看作是后观点结构，逻辑正确，当选。

