INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300505,3,'中心理解题','减轻学生作业负担和校外培训负担(“双减”),是教育战线贯彻新发展理念、构建新发展格局、推进高质量发展、促进学生健康成长的重大举措。学校教育是由国家设立的专门教育机构承担的培养和教育下一代的公共职责，而校外教育则是学校教育的有益补充。把学科专业教育还给学校，并不是要消灭校外培训教育机构，而是要发挥校外教育实践化、差别化、个性化教育的优势，与学校教育形成互相支持、互相补充、相得益彰的新格局。像课外阅读、体育、音乐、美术、舞蹈、书法等方面的兴趣爱好教育，研学旅行、科技教育、心理拓展、军事、环保、劳动、志愿服务等社会实践活动，或组织学生就近到社区、企事业单位开展社会实践活动，让学生在实践中了解社会、认识国情，等等，更适合由校外培训教育机构提供。
对这段文字的主旨概括最准确的是：','[{"label":"A","content":"“双减”改革必须依法规范学校教育和校外教育办学行为"},{"label":"B","content":"“双减”改革必须厘清学校教育与校外教育的职能边界"},{"label":"C","content":"“双减”改革必须发挥学校教育与校外教育各自的优势"},{"label":"D","content":"“双减”改革必须实施源头治理规范校外培训教育机构准入"}]','C','文段分析见批注。
文段为前观点结构，观点可理解为：学校教育与校外教育有不同作用，二者应发挥各自优势，形成互相支持、互相补充、相得益彰的新格局；对应C选项，当选；
其它选项：A选项的“依法规范办学行为”、 B选项的“厘清职能边界”、 D选项的“治理规范校外培训机构准入”,均属无中生有，对策有误，排除。

花生批注：
36 行文结构：分总结构。
分1: 降低疫情处置影响要坚持精准防控；
分2:降低疫情处置影响要做好精心服务；
总：疫情防控要提升城市精细化、智能化管理水平。
⑦ 行文结构：前观点结构。
开篇引出话题：
“双减”是什么;
再给出观点：
学校教育与校外教育有不同作用，二者应发挥各自优势，形成互相支持、互相补充、相得益彰的新格局；
最后分析论证：
介绍适合校外教育的培训内容。
A “双减”改革必须依法规范学校教育和校外教育办学行为(无中生有) B “双减”改革必须厘清学校教育与校外教育的职能边界(无中生有)
C “双减”改革必须发挥学校教育与校外教育各自的优势','2022年建设银行秋招','基础','published','{"globalNumber":505,"setNumber":26,"localNumber":5,"sourceLabel":"2022年建设银行秋招73%","accuracy":73,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"减轻学生作业负担和校外培训负担(“双减”),是教育战线贯彻新发展理念、构建新发展格局、推进高质量发展、促进学生健康成长的重大举措。学校教育是由国家设立的专门教育机构承担的培养和教育下一代的公共职责，而校外教育则是学校教育的有益补充。把学科专业教育还给学校，并不是要消灭校外培训教育机构，而是要发挥校外教育实践化、差别化、个性化教育的优势，与学校教育形成互相支持、互相补充、相得益彰的新格局。像课外阅读、体育、音乐、美术、舞蹈、书法等方面的兴趣爱好教育，研学旅行、科技教育、心理拓展、军事、环保、劳动、志愿服务等社会实践活动，或组织学生就近到社区、企事业单位开展社会实践活动，让学生在实践中了解社会、认识国情，等等，更适合由校外培训教育机构提供。\n对这段文字的主旨概括最准确的是："}],"optionRich":{"A":[{"text":"“双减”改革必须依法规范学校教育和校外教育办学行为"}],"B":[{"text":"“双减”改革必须厘清学校教育与校外教育的职能边界"}],"C":[{"text":"“双减”改革必须发挥学校教育与校外教育各自的优势"}],"D":[{"text":"“双减”改革必须实施源头治理规范校外培训教育机构准入"}]},"annotatedStemRich":[{"text":"减轻学生作业负担和校外培训负担(“双减”),是教育战线贯彻新发展理念、构建新发展格局、推进高质量发展、促进学生健康成长的重大举措( 引出话题)。学校教育是由国家设立的专门教育机构承担的培养和教育下一代的公共职责，而校外教育则是学校教育的有益补充。把学科专业教育还给学校，并不是要消灭校外培训教育机构，而是要发挥校外教育实践化、差别化、个性化教育的优势，与学校教育形成互相支持、互相补充、相得益彰的新格局( 前观点)。像课外阅读、体育、音乐、美术、舞蹈、书法等方面的兴趣爱好教育，研学旅行、科技教育、心理拓展、军事、环保、劳动、志愿服务等社会实践活动，或组织学生就近到社区、企事业单位开展社会实践活动，让学生在实践中了解社会、认识国情，等等，更适合由校外培训教育机构提供"},{"text":"(分析论证)。②","bold":true},{"text":"\n"},{"text":"行文结构：","bold":true},{"text":"前观点结构。\n对这段文字的主旨概括最准确的是："}],"annotatedOptionRich":{"A":[{"text":"“双减”改革必须依法规范学校教育和校外教育办学行为(无中生有) B “双减”改革必须厘清学校教育与校外教育的职能边界(无中生有)"}],"C":[{"text":"“双减”改革必须发挥学校教育与校外教育各自的优势\nD“双减”改革必须实施源头治理规范校外培训教育机构准入(无中生有) 【参考答案】C\n【题型与文段类型】中心理解题+说理类文章\n【实战解析】文段分析见批注。\n文段为前观点结构，观点可理解为：学校教育与校外教育有不同作用，二者应发挥各自优势，形成互相支持、互相补充、相得益彰的新格局；对应C 选项，当选；\n其它选项：A 选项的“依法规范办学行为”、 B 选项的“厘清职能边界”、 D 选项的“治理规范校外培训机构准入”,均属无中生有，对策有误，排除。"}]},"practicalAnalysis":"文段分析见批注。\n文段为前观点结构，观点可理解为：学校教育与校外教育有不同作用，二者应发挥各自优势，形成互相支持、互相补充、相得益彰的新格局；对应C选项，当选；\n其它选项：A选项的“依法规范办学行为”、 B选项的“厘清职能边界”、 D选项的“治理规范校外培训机构准入”,均属无中生有，对策有误，排除。","notes":[{"marker":"36","content":"行文结构：分总结构。\n分1: 降低疫情处置影响要坚持精准防控；\n分2:降低疫情处置影响要做好精心服务；\n总：疫情防控要提升城市精细化、智能化管理水平。","matchScore":0.121,"pairingMode":"content-similarity","order":4},{"marker":"⑦","content":"行文结构：前观点结构。\n开篇引出话题：\n“双减”