INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300507,3,'中心理解题','当前，由于政府决策、施策的事项纷繁复杂，各类矛盾交织、各种变量融合的情况比比皆是。缺乏数据支撑的决策特别是凭经验做出的决策，往往顾此失彼，科学性、前瞻性不够。政府应借助大数据手段，利用数据关联分析、数学建模、虚拟仿真乃至人工智能等技术，在基于广泛、大量数据的基础上进行模块化分析和政策模拟，为决策提供更为系统、准确、科学的参考依据，为决策实施提供更为全面、可靠的实时跟踪，推动政府决策由过去的经验型、估计型向数据分析型转变，最终实现政府决策机制再造。
这段文字意在强调：','[{"label":"A","content":"大数据在政府治理方面应用前景广阔"},{"label":"B","content":"当前政府决策施策事项问题从生"},{"label":"C","content":"以大数据助推政府决策科学化"},{"label":"D","content":"以大数据助推政务管理精准化"}]','C','文段分析见批注。
文段为后对策结构，先提出问题并分析问题：政府决策存在种种问题，决策缺乏数据支撑往往科学性、前瞻性不够；再给出对策：政府应借助大数据手段实现政府决策机制再造。C选项既体现对策“大数据助推”,也体现问题“决策科学化不够”,完美选项，当选；
A选项、D选项缺少问题主题词“决策”,B选项缺少对策主题词“大数据”且非对策表述，排除。

花生批注：
③④ 行文结构：后对策结构。
文段先提出并分析问题：
城市改造打断了城市文化记忆；
尾句给出对策：
城市治理要在两难中求两全，要兼顾城市繁华和人间烟火。
⑨ 行文结构：后对策结构。
开篇提出问题：
