INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300508,3,'中心理解题','大量疾病与蛋白质的折叠形状有千丝万缕的联系。例如新冠病毒的棘突蛋白 ( S 蛋白)的折叠形式决定了它入侵人体细胞的速度和致病能力。遗憾的是，截至目前，只有约10万个蛋白质的结构已经用实验方法得到了解析。从理论上看，一个蛋白质从一维到三维有无数的折叠方式，认识和精确测定蛋白质的构型既要耗费大量的时间和精力，同时也不一定能测得准，也造成了药物、疫苗研发和疾病治疗的举步维艰。如新冠病毒的蛋白质频繁变异，如果不能及时，准确地认知其变异结构，就难以研发新的疫苗。
这段文字主要介绍了：','[{"label":"A","content":"测定蛋白质结构的意义与困境"},{"label":"B","content":"新冠病毒的蛋白质结构及变异"},{"label":"C","content":"新冠病毒给医学界带来的挑战"},{"label":"D","content":"疾病与蛋白质折叠形状的关系"}]','A','本题可在简略阅读文段后，根据选项确定结构及选择答案。
B选项、C选项论述主体为新冠病毒，但“新冠病毒”是例子，证明蛋白质的折叠形状与疾病有联系，排除；
D选项为具体类选项，原文并未介绍疾病与蛋白质折叠形状的关系是什么, 只是说二者有关系，排除；
A选项为“A 且B 类”选项，逆推文段，可将“大量疾病与蛋白质的折叠形状有千丝万缕的联系”看作测定蛋白质结构的意义，可将后文看作测定蛋白质结构的困境，完美选项，当选。

花生批注：
⑩ 蛋白质的折叠形状与疾病有关，根据蛋白质的折叠形状可了解疾病相关情况，即意义。
⑪ 困境①:结构已解析的蛋白质数量少；
困境②:折叠方式多，认识和精确测定蛋白质构型耗时耗力、不一定测得准；
困境③:根据蛋白质结构研发药物和疫苗、治疗疾病举步维艰。
⑫ 行文逻辑如下：
⑤引出话题，什么是计算；
③⑥对比引出大数分解；
②④介绍因为大数分解难度很大，成为现代密码学基础；
①介绍量子计算机让大数分解变快。
大量疾病与蛋白质的折叠形状有千丝万缕的联系。例如新冠病毒的棘突蛋白(S 蛋白)的折叠形式决定了它入侵人体细胞的速度和致病能力(测定蛋白质结构的意义)。遗憾的是，截至目前，只有约10万个蛋白质的结构已经用实验方法得到了解析。从理论上看，一个蛋白质从一维到三维有无数的折叠方式，认识和精确测定蛋白质的构型既要耗费大量的时间和精力，同时也不一定能测得准，也造成了药物、疫苗研发和疾病治疗的举步维艰。如新冠病毒的蛋白质频繁变异，如果不能及时，准确地认知其变异结构，就难以研发新的疫苗(测定蛋白质结构的困境)。
