INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300509,3,'语句排序类','①1994年，贝尔实验室的科学家肖尔发现，使用量子计算机可以让大数分解变得很快
