INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300510,3,'细节判断类','很多人都有过“睡眠惊跳”的体验。睡着睡着，肢体一侧或双侧突然发生短促抽动，有的还会累及上肢、颈部和躯干，同时我们的意识还在朦胧状态。这种情况叫作睡眠惊跳，也称睡初抽动。睡眠惊跳是一个正常而又普遍的现象，各年龄层均可发生，尤以小孩为多见。小朋友白天兴奋性的活动比较多，入睡时指挥运动的神经细胞不容易完全抑制，剩余的兴奋信息反射至大脑皮质，干扰睡眠抑制，因此产生睡眠惊跳。成年人的睡眠惊跳，大多与白天过分疲劳、兴奋、紧张、焦虑、惊恐，或临睡前饮用刺激性饮料等因素有关。
这段文字没有介绍的是：','[{"label":"A","content":"睡眠惊跳的多发人群"},{"label":"B","content":"睡眠惊跳的最大诱因"},{"label":"C","content":"睡眠惊跳的临床表现"},{"label":"D","content":"睡眠惊跳的发生机制"}]','B','B选项表述绝对化，应重点关注。虽然文段分别提及小朋友、成年人两群体“睡眠惊跳”的诱因，但并未指出“最大诱因”,本题为选非题，当选。

花生批注：
⑭ 根据③句“睡眠惊跳是一个正常而又普遍的现象，各年龄层均可发生，尤以小孩为多见”可知，文中已谈到“多发人群”。
⑮ 根据②句的“睡着睡着，肢体一侧或双侧突然发生短促抽动，有的还会累及上肢、颈部和躯干，同时我们的意识还在朦胧状态”可知，文中已谈到“临床表现(临床表现可理解为症状)”。
⑯ ⑤⑥句依次介绍了小朋友和成年人的发生机制，发生机制可理解为发病的原因和内在过程。','2023年辽宁省考','进阶','published','{"globalNumber":510,"setNumber":26,"localNumber":10,"sourceLabel":"2023年辽宁省考47%","accuracy":47,"typeAndPassage":"细节判断类","stemRich":[{"text":"很多人都有过“睡眠惊跳”的体验。睡着睡着，肢体一侧或双侧突然发生短促抽动，有的还会累及上肢、颈部和躯干，同时我们的意识还在朦胧状态。这种情况叫作睡眠惊跳，也称睡初抽动。睡眠惊跳是一个正常而又普遍的现象，各年龄层均可发生，尤以小孩为多见。小朋友白天兴奋性的活动比较多，入睡时指挥运动的神经细胞不容易完全抑制，剩余的兴奋信息反射至大脑皮质，干扰睡眠抑制，因此产生睡眠惊跳。成年人的睡眠惊跳，大多与白天过分疲劳、兴奋、紧张、焦虑、惊恐，或临睡前饮用刺激性饮料等因素有关。\n这段文字没有介绍的是："}],"optionRich":{"A":[{"text":"睡眠惊跳的多发人群"}],"B":[{"text":"睡眠惊跳的最大诱因"}],"C":[{"text":"睡眠惊跳的临床表现"}],"D":[{"text":"睡眠惊跳的发生机制"}]},"annotatedStemRich":[{"text":"①很多人都有过“睡眠惊跳”的体验。②睡着睡着，肢体一侧或双侧突然发生短促抽动，有的还会累及上肢、颈部和躯干，同时我们的意识还在朦胧状态( C 选项)。③这种情况叫作睡眠惊跳，也称睡初抽动。④睡眠惊跳是一个正常而又普遍的现象，各年龄层均可发生，尤以小孩为多见( A 选项)。⑤小朋友白天兴奋性的活动比较多，入睡时指挥运动的神经细胞不容易完全抑制，剩余的兴奋信息反射至大脑皮质，干扰睡眠抑制，因此产生睡眠惊跳。⑥成年人的睡眠惊跳，大多与白天过分疲劳、兴奋、紧张、焦虑、惊恐，或临睡前饮用刺激性饮料等因素有关( D 选项)。\n这段文字"},{"text":"没有","bold":true},{"text":"介绍的是："}],"annotatedOptionRich":{"A":[{"text":"睡眠惊跳的多发人群⑭"}],"B":[{"text":"睡眠惊跳的最大诱因"}],"C":[{"text":"睡眠惊跳的临床表现⑮"}],"D":[{"text":"睡眠惊跳的发生机制"}]},"practicalAnalysis":"B选项表述绝对化，应重点关注。虽然文段分别提及小朋友、成年人两群体“睡眠惊跳”的诱因，但并未指出“最大诱因”,本题为选非题，当选。","notes":[{"marker":"⑭","content":"根据③句“睡眠惊跳是一个正常而又普遍的现象，各年龄层均可发生，尤以小孩为多见”可知，文中已谈到“多发人群”。","matchScore":0.8025,"pairingMode":"marker-and-content","order":18},{"marker":"⑮","content":"根据②句的“睡着睡着，肢体一侧或双侧突然发生短促抽动，有的还会累及上肢、颈部和躯干，同时我们的意识还在朦胧状态”可知，文中已谈到“临床表现(临床表现可理解为症状)”。","matchScore":0.8483,"pairingMode":"marker-and-content","order":19},{"marker":"⑯","content":"⑤⑥句依次介绍了小朋友和成年人的发生机制，发生机制可理解为发病的原因和内在过程。","matchScore":0.2745,"pairingMode":"content-similarity","order":20}],"pairingMode":"text-and-sequence"}');
