INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300512,3,'中心理解题','近几年，漆艺的发展渐有起色，不仅展览频繁，并且形式和特点也呈现出从平面、器具、装饰性、实用性的传统范畴向立体、装置、影像、艺术叙事和张扬个性的广阔空间迈进的趋势。漆艺不再止于实用性的漆器，也不再止于装饰性的漆画，而是呈现出多元的发展态势。然而在漆艺从形式到内涵都发生巨大变化的同时，漆艺审美和批评却并未同步。由于人们习惯于传统漆艺平、光、润的审美和装饰性、实用性的功能定位，所以当漆艺呈现出陌生化的表征之时，常常会面临行业内的质疑。这让漆艺创作者对于自身探索性的尝试充满不确定性，无益于后续发展。
这段文字意在说明：','[{"label":"A","content":"应重新建构漆艺审美的价值体系"},{"label":"B","content":"行业内的封闭观念制约了漆艺的发展"},{"label":"C","content":"漆艺传承和发展面对的难题尚难以突破"},{"label":"D","content":"对漆艺发展的多元态势应给予更多包容"}]','D','文段分析见批注。
文段可视为转折结构，先介绍漆艺发展已呈多元化，再提出问题：“漆艺审美与批评不同步，多元化发展呈现陌生化表征时时常常面临质疑。”,说理类文段原文有问题可针对问题提出对策也可体现问题；D选项的“对漆艺发展的多元态势”对应“转折前”,“应给予更多包容”对应“转折后的问题(即“漆艺多元发展呈现陌生化表征时，常常面临质疑”)⑩,完美选项，当选；
A选项对策有误⑧,原文问题为“漆艺多元化发展呈现陌生化表征时面临质疑”, 与漆艺审美的价值体系无关，应从面对漆艺多元化问题上秉持什么样的态度去解决问题，排除；B选项、C选项无中生有，原文问题为“漆艺多元化发展呈现陌生化表征时面临质疑”,并非封闭观念制约了发展或存在难题难以突破，排除。

花生批注：
⑱ 行文结构：二层结构之转折。
转折前：
介绍漆艺的多元发展态势；转折后：
指出问题：漆艺审美与批评不同步，多元化发展呈现陌生化表征时时常常面临质疑。
⑲ 文段问题可概括为：人们习惯传统的功能定位，漆艺多元发展时会呈现出人们陌生的表征，这时就会有质疑声音；
那针对这一问题，应给出的对策应是“宽容且接受这种新变化，不要阻碍漆艺多元化发展”,对应D选项。
2 若A选项当选，文段问题应为“漆艺审美的价值体系”存在问题。
近几年，漆艺的发展渐有起色，不仅展览频繁，并且形式和特点也呈现出从平面、器具、装饰性、实用性的传统范畴向立体、装置、影像、艺术叙事和张扬个性的广阔空间迈进的趋势。漆艺不再止于实用性的漆器，也不再止于装饰性的漆画，而是呈现出多元的发展态势(介绍漆艺的多元化发展态势)。然而在漆艺从形式到内涵都发生巨大变化的同时，漆艺审美和批评却并未同步。由于人们习惯于传统漆艺平、光、润的审美和装饰性、实用性的功能定位，所以当漆艺呈现出陌生化的表征之时，常常会面临行业内的质疑。这让漆艺创作者对于自身探索性的尝试充满不确定性，无益于后续发展(提出问题)。⑩
这段文字意在说明：
A. 应重新建构漆艺审美的价值体系(对策有误)
B. 行业内的封闭观念制约了漆艺的发展 (无中生有)
C. 漆艺传承和发展面对的难题尚难以突破(无中生有)
D. 对漆艺发展的多元态势应给予更多包容','2023年事业单位联考','进阶','published','{"globalNumber":512,"setNumber":26,"localNumber":12,"sourceLabel":"2023年事业单位联考47%","accuracy":47,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"近几年，漆艺的发展渐有起色，不仅展览频繁，并且形式和特点也呈现出从平面、器具、装饰性、实用性的传统范畴向立体、装置、影像、艺术叙事和张扬个性的广阔空间迈进的趋势。漆艺不再止于实用性的漆器，也不再止于装饰性的漆画，而是呈现出多元的发展态势。然而在漆艺从形式到内涵都发生巨大变化的同时，漆艺审美和批评却并未同步。由于人们习惯于传统漆艺平、光、润的审美和装饰性、实用性的功能定位，所以当漆艺呈现出陌生化的表征之时，常常会面临行业内的质疑。这让漆艺创作者对于自身探索性的尝试充满不确定性，无益于后续发展。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"应重新建构漆艺审美的价值体系"}],"B":[{"text":"行业内的封闭观念制约了漆艺的发展"}],"C":[{"text":"漆艺传承和发展面对的难题尚难以突破"}],"D":[{"text":"对漆艺发展的多元态势应给予更多包容"}]},"annotatedStemRich":[{"text":"⑱花生批注：\n行文结构：二层结构之转折。\n转折前：\n介绍漆艺的多元发展态势；转折后：\n指出问题：漆艺审美与批评不同步，多元化发展呈现陌生化表征时时常常面临质疑。\n⑲花生批注：\n"},{"text":"文段问题可概括为：","bold":true},{"text":"人们习惯传统的功能定位，漆艺多元发展时会呈现出人们陌生的表征，这时就会有质疑声音；\n那针对这一问题，应给出的对策应是“宽容且接受这种新变化，不要阻碍漆艺多元化发展”,对应D 选项。\n2花生批注：\n若A 选项当选，文段问题应为“漆艺审美的价值体系”存在问题。\n近几年，漆艺的发展渐有起色，不仅展览频繁，并且形式和特点也呈现出从平面、器具、装饰性、实用性的传统范畴向立体、装置、影像、艺术叙事和张扬个性的广阔空间迈进的趋势。漆艺不再止于实用性的漆器，也不再止于装饰性的漆画，而是呈现出多元的发展态势(介绍漆艺的多元化发展态势)。然而在漆艺从形式到内涵都发生巨大变化的同时，漆艺审美和批评却并未同步。由于人们习惯于传统漆艺平、光、润的审美和装饰性、实用性的功能定位，所以当漆艺呈现出陌生化的表征之时，常常会面临行业内的质疑。这让漆艺创作者对于自身探索性的尝试充满不确定性，无益于后续发展(提出问题)。⑩\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"应重新建构漆艺审美的价值体系(对策有误)"}],"B":[{"text":"行业内的封闭观念制约了漆艺的发展 (无中生有)"}],"C":[{"text":"漆艺传承和发展面对的难题尚难以突破(无中生有)"}],"D":[{"text":"对漆艺发展的多元态势应给予更多包容"}]},"practicalAnalysis":"文段分析见批注。\n文段可视为转折结构，先介绍漆艺发展已呈多元化，再提出问题：“漆艺审美与批评不同步，多元化发展呈现陌生化表征时时常常面临质疑。”,说理类文段原文有问题可针对问题提出对策也可体现问题；D选项的“对漆艺发展的多元态势”对应“转折前”,“应给予更多包容”对应“转折后的问题(即“漆艺多元发展呈现陌生化表征时，常常面临质疑”)⑩,完美选项，当选；\nA选项对策有误⑧,原文问题为“漆艺多元化发展呈现陌生化表征时面临质疑”, 与漆艺审美的价值体系无关，应从面对漆艺多元化问题上秉持什么样的态度去解决问题，排除；B选项、C选项无中生有，原文问题为“漆艺多元化发展呈现陌生化表征时面临质疑”,并非封闭观念制约了发展或存在难题难以突破，排除。","notes":[{"marker":"⑱","content":"行文结构：二层结构之转折。\n转折前：\n介绍漆艺的多元发展态势；转折后：\n指出问题：漆艺审美与批评不同步，多元化发展呈现陌生化表征时时常常面临质疑。","matchScore":1.122,"pairingMode":"marker-and-content","order":22},{"marker":"⑲","content":"文段问题可概括为：人们习惯传统的功能定位，漆艺多元发展时会呈现出人们陌生的表征，这时就会有质疑声音；\n那针对这一问题，应给出的对策应是“宽容且接受这种新变化，不要阻碍漆艺多元化发展”,对应D选项。","matchScore":1.1671,"pairingMode":"marker-and-content","order":23},{"marker":"2","content":"若A选项当选，文段问题应为“漆艺审美的价值体系”存在问题。\n近几年，漆艺的发展渐有起色，不仅展览频繁，并且形式和特点也呈现出从平面、器具、装饰性、实用性的传统范畴向立体、装置、影像、艺术叙事和张扬个性的广阔空间迈进的趋势。漆艺不再止于实用性的漆器，也不再止于装饰性的漆画，而是呈现出多元的发展态势(介绍漆艺的多元化发展态势)。然而在漆艺从形式到内涵都发生巨大变化的同时，漆艺审美和批评却并未同步。由于人们习惯于传统漆艺平、光、润的审美和装饰性、实用性的功能定位，所以当漆艺呈现出陌生化的表征之时，常常会面临行业内的质疑。这让漆艺创作者对于自身探索性的尝试充满不确定性，无益于后续发展(提出问题)。⑩\n这段文字意在说明：\nA. 应重新建构漆艺审美的价值体系(对策有误)\nB. 行业内的封闭观念制约了漆艺的发展 (无中生有)\nC. 漆艺传承和发展面对的难题尚难以突破(无中生有)\nD. 对漆艺发展的多元态势应给予更多包容","matchScore":1.402,"pairingMode":"content-similarity","order":24}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300513,3,'语句排序类','①改革开放以来，按照现行贫困标准计算，我国7.7亿农村贫困人口摆脱贫困，按照世界银行国际贫困标准，我国减贫人口占同期全球减贫人口70%以上。
②放眼世界，没有哪一个国家能在这么短的时间内实现几亿人脱贫。
③联合国秘书长古特雷斯表示，精准扶贫方略是帮助贫困人口、实现2030年可持续发展议程设定的宏伟目标的唯一途径，中国的经验可以为其他发展中国家提供有益借鉴。
④中国减贫奇迹，得到国际社会广泛赞誉，为推动构建人类命运共同体贡献了中国力量。
⑤从世界范围看，摆脱贫困一直是困扰全球发展和治理的突出难题。
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"①②⑤③④"},{"label":"B","content":"②⑤①③④"},{"label":"C","content":"⑤①②④③⑧"},{"label":"D","content":"④⑤②①③"}]','C','本题首句不好判断，可从②句的“指代”入手解题：“没有哪一个国家能在这么短时间内脱贫”,前文应介绍我国的脱贫情况，①②捆绑，排除B选项、D选项；
2

