INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300514,3,'细节判断类','研究者认为，巨量的基性溢流玄武岩喷发至地表、火山喷发造成的温室气体浓度急剧升高等为全球性陆地风化作用增强提供了必要的条件。大陆风化作用将地表巨量的离子和营养盐输送至海洋，引发海水的富营养化和海洋酸化，进而导致海水缺氧、透光带降低等危及当时海洋中生命生存的环境系统，这一效应积累到阈值后，最终引发海洋生态系统的崩溃并造成二叠纪末生命大量灭绝。
根据这段文字，以下说法正确的是：','[{"label":"A","content":"火山爆发是二叠纪末生命灭绝的重要原因"},{"label":"B","content":"海洋酸化的直接原因是温室气体浓度急剧升高"},{"label":"C","content":"陆地风化作用的增强使得二叠纪末火山大规模爆发"},{"label":"D","content":"海水富营养化带来的海洋缺氧直接导致海洋生物的灭绝"}]','A','本文段属于顺承结构，逻辑性较强，由火山喷发造成温室气体浓度升高从而引发大陆风化，然后导致海水的富营养化和海洋酸化，最终使海洋生态系统的崩溃并造成二叠纪末生命大量灭绝。故火山喷发是二叠纪末生命大量灭绝的根本原因，A选项当选。

花生批注：
2 根据文段第②句的“大陆风化作用将地表巨量的离子和营养盐输送至海洋，引发海水的富营养化和海洋酸化”可知，海洋酸化的直接原因是大陆风化，错误。
3 因果倒置，根据文段第①句的“火山喷发造成的温室气体浓度急剧升高等为全球性陆地风化作用增强提供了必要的条件”可知，火山喷发导致陆地风化，错误。
④ 根据文段第②句的“海水的富营养化和海洋酸化，进而导致海水缺氧、透光带降低等危及当时海洋中生命生存的环境系统，这一效应积累到阈值后，最终引发海洋生态系统的崩溃并造成二叠纪末生命大量灭绝”可知，海洋生物灭绝的直接原因不仅仅是海水富营养化导致的海洋缺氧，也包括海洋酸化、透光带降低、环境系统被破坏等等，错误。
④句引出“中国减贫奇迹受到国际广泛赞誉”,③具体介绍联合国秘书长对我国减贫奇迹的评价，④③捆绑；
