INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300515,3,'语句填入类','过去的犯罪真相难于查明，需要一场严肃的刑事诉讼对案情加以重构。这一过程与考古非常类似，都需要根据不断挖掘、打捞出的证据，逐步还原某个历史场景。不过，刑事诉讼与考古的不同其实多于相似：考古没有时间限制，挖掘一旦无法持续，可以等待；而刑事诉讼程序则必须遵守法定期限，不能让案件在期限之外悬而不决，狱羁冤人，必须有一套对真相不明的疑难案件的处置规则。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"所以在刑事治罪领域，特别强调以事实为依据"},{"label":"B","content":"为文明诉讼所公认的规则，那就是“疑罪从无”"},{"label":"C","content":"描述、回溯事实还是要取决于如何理解法条文义"},{"label":"D","content":"犯罪行为发生在过去，还原真相的过程也会出错"}]','B','文段分析见批注。
所填入语句是对前文的总体概括，上文通过将考古和刑事诉讼对比，引出二者不同之处：刑事诉讼程序有法定期限，若在期限之内未查清，必须有一套对真相不明的疑难案件的处置规则。尾句应介绍该规则，对应B选项，即在规定期限内未查明案件真相，要遵照“疑罪从无”的原则，B选项当选；
其他选项均未提及“针对真相不明的疑难案件的处置规则”,可简单排除。

