INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300516,3,'语句填入类','。然而，随着我国经济快速发展，人民生活水平日益提高，婚俗悄然“变味”。“辛辛苦苦几十年，一婚回到贫困线”不是段子，而是屡见不鲜的现实。动辄十几万到几十万不等的惊人“天价彩礼”,高攀不起的“份子钱”,一摆就是几十桌甚至上百桌的豪华婚宴，尽显低俗甚至触及法律底线的“婚闹”……凡此种种，不一而足，婚俗中的一些不正之风，打着传统文化的旗号，传播的却是不健康、不文明的文化气息。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"最令人深恶痛绝的是无底线的低俗乃至愚俗的“婚闹”"},{"label":"B","content":"文明的婚俗，是践行社会主义核心价值观的生动实现，是良好社会风尚的重要载体"},{"label":"C","content":"婚俗礼仪传承千年，全国各地已形成了各具特色的婚礼习俗，也成为传统文化的重要组成部分"},{"label":"D","content":"婚俗之“俗”,乃传统习俗、公序良俗之意，绝无半点庸俗、低俗的味道\n片段阅读600四(下册)"}]','D','文段先通过转折提出问题：婚俗悄然“变味”;后文具体介绍婚俗的“变味”,文末做了总结：婚俗中的不正之风打着传统文化旗号传播的却是不健康、不文明的文化气息。
所填入语句在转折前，应介绍原来的“婚俗(即传统的婚俗)”,与之后的“婚俗变了味”形成转折。只有D选项介绍的是“传统的婚俗”,为“传统习俗、公序良俗之意”,而且“味道”与后文的“变味”形成呼应，完美选项，当选；
A选项的主语为“婚闹”而非婚俗，B选项介绍的是“文明的婚俗”而非“传统的婚俗”,可简单排除；
C选项为强干扰项，介绍“婚俗传承千年，是传统文化重要组成部分”, 可与下文形成转折与呼应，但不如D选项的“味道”与下文“变味”衔接紧密，排除。
片段阅读6 00 ( 下册)

