INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300517,3,'下文推断类②','圆梦顶尖名校、欧洲文化探秘、国际学生领导力峰会……各色名目赚足了家长的眼球。随着人们收入水平的提高、教育理念的改变以及出国政策的优化，海外游学热的出现可谓应时当令。游与学，本身就包含了寓教于乐的期望。在不少家长心中，与其把假期改造成为“第三学期”,不如用游学让孩子得一闲暇、放松身心，独自体验国外教育、了解风土人情也有助于开拓视野、锻炼能力，其出发点是好的。
作为一篇文章的引言，作者接下来最有可能介绍的是：','[{"label":"A","content":"游学的价值"},{"label":"B","content":"游学的市场状况"},{"label":"C","content":"游学的内容"},{"label":"D","content":"游学的历史发展"}]','B','文段先介绍了海外游学热及家长的期待，且在尾句做出评价：“其出发点是好的”。出发点即做事的动机，出发点是好的，往往结果事与愿违。即家长的想法是好的，但是海外游学可能存在某些问题。
B选项的“游学的市场状况”可理解为“游学可能出现的不符合家长期待的实际状况”,与上文的“出发点是好的”构成转折，逻辑正确，当选；
A选项的“游学价值”、C选项的“游学内容”为上文介绍过的内容，不会重复介绍，排除；D选项的“历史发展”无中生有，历史发展与“出发点是好的”无法衔接，排除。

花生批注：
28 家长的出发点是家长的预期想法，游学的市场状况可理解为“实际的市场现状”, 想法与实际对应，即“理想很丰满，现实很骨感”。','2018年江西省考','挑战','published','{"globalNumber":517,"setNumber":26,"localNumber":17,"sourceLabel":"2018年江西省考 38%","accuracy":38,"typeAndPassage":"下文推断类② +转折","stemRich":[{"text":"圆梦顶尖名校、欧洲文化探秘、国际学生领导力峰会……各色名目赚足了家长的眼球。随着人们收入水平的提高、教育理念的改变以及出国政策的优化，海外游学热的出现可谓应时当令。游与学，本身就包含了寓教于乐的期望。在不少家长心中，与其把假期改造成为“第三学期”,不如用游学让孩子得一闲暇、放松身心，独自体验国外教育、了解风土人情也有助于开拓视野、锻炼能力，其出发点是好的。\n作为一篇文章的引言，作者接下来最有可能介绍的是："}],"optionRich":{"A":[{"text":"游学的价值"}],"B":[{"text":"游学的市场状况"}],"C":[{"text":"游学的内容"}],"D":[{"text":"游学的历史发展"}]},"annotatedStemRich":[{"text":"圆梦顶尖名校、欧洲文化探秘、国际学生领导力峰会……各色名目赚足了家长的眼球。随着人们收入水平的提高、教育理念的改变以及出国政策的优化，海外游学热的出现可谓应时当令。游与学，本身就包含了寓教于乐的期望。在不少家长心中，与其把假期改造成为“第三学期”,不如用游学让孩子得一闲暇、放松身心，独自体验国外教育、了解风土人情也有助于开拓视野、锻炼能力，其出发点是好的。\n作为一篇文章的引言，作者接下来最有可能介绍的是："}],"annotatedOptionRich":{"A":[{"text":"游学的价值"}],"B":[{"text":"游学的市场状况"}],"C":[{"text":"游学的内容"}],"D":[{"text":"游学的历史发展"}]},"practicalAnalysis":"文段先介绍了海外游学热及家长的期待，且在尾句做出评价：“其出发点是好的”。出发点即做事的动机，出发点是好的，往往结果事与愿违。即家长的想法是好的，但是海外游学可能存在某些问题。\nB选项的“游学的市场状况”可理解为“游学可能出现的不符合家长期待的实际状况”,与上文的“出发点是好的”构成转折，逻辑正确，当选；\nA选项的“游学价值”、C选项的“游学内容”为上文介绍过的内容，不会重复介绍，排除；D选项的“历史发展”无中生有，历史发展与“出发点是好的”无法衔接，排除。","notes":[{"marker":"28","content":"家长的出发点是家长的预期想法，游学的市场状况可理解为“实际的市场现状”, 想法与实际对应，即“理想很丰满，现实很骨感”。","matchScore":0.51,"pairingMode":"content-similarity","order":32}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300518,3,'中心理解题','在线教育驶入发展快车道，一点也不令人意外。一堂“慕课”,可容纳10万名学生注册学习；偏远山村，孩子们能够实时聆听千里之外的名师授课；遇到难题，扫一扫即可得到方法解析……信息技术在教育领域应用的普及，打破了时空限制，推倒了学校围墙，为教育开启了“魔法之门”。在这种背景下，在线教育日益为教育事业开拓着新的可能，前景十分广阔。
这段文字意在强调：','[{"label":"A","content":"在线教育发展迅速，前景无限"},{"label":"B","content":"在线教育打破了时空限制，会颠覆传统教育"},{"label":"C","content":"在线教育可以解决教育资源分配不均的问题"},{"label":"D","content":"传统教育须借力信息技术才有发展的空间"}]','A','文段分析见批注。
文段先介绍在线教育快速发展，结尾指出在线教育前景广阔；A选项可看做“A 且B 类”选项，“发展迅速”和“前景无限”分别对应“快速发展”和“前景广阔”,完美选项，当选。
B选项的“会颠覆传统教育”、C选项的“解决教育资源分配不均”均无中生有，D选项主体有误(应为在线教育),均可简单排除。

花生批注：
9 在线教育是全文论述主体。
③0 行文结构：分总结构。
前文介绍在线教育快速发展；
尾句给出总结：在线教育前景广阔。','2019年江西省事业单位','基础','published','{"globalNumber":518,"setNumber":26,"localNumber":18,"sourceLabel":"2019年江西省事业单位83%","accuracy":83,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"在线教育驶入发展快车道，一点也不令人意外。一堂“慕课”,可容纳10万名学生注册学习；偏远山村，孩子们能够实时聆听千里之外的名师授课；遇到难题，扫一扫即可得到方法解析……信息技术在教育领域应用的普及，打破了时空限制，推倒了学校围墙，为教育开启了“魔法之门”。在这种背景下，在线教育日益为教育事业开拓着新的可能，前景十分广阔。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"在线教育发展迅速，前景无限"}],"B":[{"text":"在线教育打破了时空限制，会颠覆传统教育"}],"C":[{"text":"在线教育可以解决教育资源分配不均的问题"}],"D":[{"text":"传统教育须借力信息技术才有发展的空间"}]},"annotatedStemRich":[{"text":"在线教育","underline":true},{"text":"驶入发展快车道，一点也不令人意外。一堂“慕课”,可容纳 10万名学生注册学习；偏远山村，孩子们能够实时聆听千里之外的名师授课；遇到难题，扫一扫即可得到方法解析……信息技术在教育领域应用的普及，打破了时空限制，推倒了学校围墙，为教育开启了“魔法之门”(分)。在这种背景下，在线教育日益为教育事业开拓着新的可能，前景十分广阔(总)。⑩\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"在线教育发展迅速，前景无限"}],"B":[{"text":"在线教育打破了时空限制，会颠覆传统教育"}],"C":[{"text":"在线教育可以解决教育资源分配不均的问题"}],"D":[{"text":"传统教育须借力信息技术才有发展的空间"}]},"practicalAnalysis":"文段分析见批注。\n文段先介绍在线教育快速发展，结尾指出在线教育前景广阔；A选项可看做“A 且B 类”选项，“发展迅速”和“前景无限”分别对应“快速发展”和“前景广阔”,完美选项，当选。\nB选项的“会颠覆传统教育”、C选项的“解决教育资源分配不均”均无中生有，D选项主体有误(应为在线教育),均可简单排除。","notes":[{"marker":"9","content":"在线教育是全文论述主体。","matchScore":0.4317,"pairingMode":"content-similarity","order":33},{"marker":"③0","content":"行文结构：分总结构。\n前文介绍在线教育快速发展；\n尾句给出总结：在线教育前景广阔。","matchScore":0.5632,"pairingMode":"content-similarity","order":34}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300519,3,'中心理解题','目前，我国“三农”工作重心已历史性转向全面推进乡村振兴。其中，保障粮食和重要农副产品有效供给是重中之重。大力发展农业保险，有助于应对农业领域的重大风险挑战，提升粮食和重要农产品供给保障能力，为乡村全面振兴保驾护航。通过发展农业保险对农业进行支持保护是国际惯例，也是许多国家农业支持保护政策的支柱。大力发展和运用农业保险工具，既是促进我国农业支持政策向国际看齐、更好适应世界贸易组织规则的现实选择，也是保障我国农业产业稳定发展、维护粮食安全、保护农民利益的长远需要。
这段文字意在说明：','[{"label":"A","content":"乡村振兴需要健全的农业支持保护政策"},{"label":"B","content":"农业保险有助于“三农”工作顺利推进"},{"label":"C","content":"农业政策既要立足国内也要有国际视野"},{"label":"D","content":"发展农业保险是保障粮食安全的必选项"}]','B','文段分析见批注。
文段为前对策结构，对策句可翻译为“发展农业保险有助于应对农业领域重大挑战、提升保障能力、推进乡村振兴”,B选项为对策的同义替换⑬,当选；

花生批注：
③ 三农工作是全文论述话题。三农，指农业、农村和农民。所谓“三农”问题，就是指农业、农村、农民这三个问题。
③2 行文结构：前对策结构。
开篇引出话题：
“三农”工作重心已经转向；再给出对策：
大力发展农业保险有助于应对农业领域重大挑战、提升保障能力、推进乡村振兴；后文通过国际与我国对比进行分析论证。
这段文字意在说明：
A. 乡村振兴需要健全的农业支持保护政策
B. 农业保险有助于“三农”工作顺利推进
C. 农业政策既要立足国内也要有国际视野
D. 发展农业保险是保障粮食安全的必选项
33 原文以并列方式指出，发展农业保险能应对风险，发展农业保险能提升保障能力，发展农业保险能助力乡村振兴；这三句话都在强调农业保险对三农工作的重要意义，B选项是对上述观点的概括，且能回应首句话题。
其它选项：A选项、C选项均缺少关键词“农业保险”,可简单排除； D选项片面，文段指出发展农业保险可应对农业领域重大挑战、提升保障能力、推进乡村振兴，作用是三方面的，该选项仅能对应粮食安全，排除。
片段阅读600','2023年国家公务员考试','进阶','published','{"globalNumber":519,"setNumber":26,"localNumber":19,"sourceLabel":"2023年国家公务员考试59%","accuracy":59,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"目前，我国“三农”工作重心已历史性转向全面推进乡村振兴。其中，保障粮食和重要农副产品有效供给是重中之重。大力发展农业保险，有助于应对农业领域的重大风险挑战，提升粮食和重要农产品供给保障能力，为乡村全面振兴保驾护航。通过发展农业保险对农业进行支持保护是国际惯例，也是许多国家农业支持保护政策的支柱。大力发展和运用农业保险工具，既是促进我国农业支持政策向国际看齐、更好适应世界贸易组织规则的现实选择，也是保障我国农业产业稳定发展、维护粮食安全、保护农民利益的长远需要。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"乡村振兴需要健全的农业支持保护政策"}],"B":[{"text":"农业保险有助于“三农”工作顺利推进"}],"C":[{"text":"农业政策既要立足国内也要有国际视野"}],"D":[{"text":"发展农业保险是保障粮食安全的必选项"}]},"annotatedStemRich":[{"text":"目前，我国“三农”工作③重心已历史性转向全面推进乡村振兴。其中，保障粮食和重要农副产品有效供给是重中之重(引出话题)。大力发展农业保险，有助于应对农业领域的重大风险挑战，提升粮食和重要农产品供给保障能力，为乡村全面振兴保驾护航(前对策)。通过发展农业保险对农业进行支持保护是国际惯例，也是许多国家农业支持保护政策的支柱。大力发展和运用农业保险工具，既是促进我国农业支持政策向国际看齐、更好适应世界贸易组织规则的现实选择，也是保障我国农业产业稳定发展、维护粮食安全、保护农民利益\n的长远需要(分析论证)。③\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"乡村振兴需要健全的农业支持保护政策"}],"B":[{"text":"农业保险有助于“三农”工作顺利推进"}],"C":[{"text":"农业政策既要立足国内也要有国际视野"}],"D":[{"text":"发展农业保险是保障粮食安全的必选项"}]},"practicalAnalysis":"文段分析见批注。\n文段为前对策结构，对策句可翻译为“发展农业保险有助于应对农业领域重大挑战、提升保障能力、推进乡村振兴”,B选项为对策的同义替换⑬,当选；","notes":[{"marker":"③","content":"三农工作是全文论述话题。三农，指农业、农村和农民。所谓“三农”问题，就是指农业、农村、农民这三个问题。","matchScore":0.2469,"pairingMode":"marker-and-content","order":35},{"marker":"③2","content":"行文结构：前对策结构。\n开篇引出话题：\n“三农”工作重心已经转向；再给出对策：\n大力发展农业保险有助于应对农业领域重大挑战、提升保障能力、推进乡村振兴；后文通过国际与我国对比进行分析论证。\n这段文字意在说明：\nA. 乡村振兴需要健全的农业支持保护政策\nB. 农业保险有助于“三农”工作顺利推进\nC. 农业政策既要立足国内也要有国际视野\nD. 发展农业保险是保障粮食安全的必选项","matchScore":0.7386,"pairingMode":"content-similarity","order":36},{"marker":"33","content":"原文以并列方式指出，发展农业保险能应对风险，发展农业保险能提升保障能力，发展农业保险能助力乡村振兴；这三句话都在强调农业保险对三农工作的重要意义，B选项是对上述观点的概括，且能回应首句话题。\n其它选项：A选项、C选项均缺少关键词“农业保险”,可简单排除； D选项片面，文段指出发展农业保险可应对农业领域重大挑战、提升保障能力、推进乡村振兴，作用是三方面的，该选项仅能对应粮食安全，排除。\n片段阅读600","matchScore":0.4593,"pairingMode":"content-similarity","order":37}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300520,3,'语句填入类','针对外来入侵物种问题，我国管理制度在不断完善，《外来入侵物种管理办法》已于2022年8月1 日起施行。办法明确，农业农村部会同有关部门建立外来入侵物种普查制度，每十年组织开展一次全国普查；建立外来入侵物种监测制度，构建全国外来入侵物种监测网络；建立外来入侵物种信息发布制度。 ,防范外来物种入侵，人人有责。《中华人民共和国生物安全法》规定：任何单位和个人未经批准，不得擅自引进、释放或者丢弃外来物种。千万不要觉得外来物种和自己没有多大关系。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"外来入侵物种可能会对生态环境造成严重破坏"},{"label":"B","content":"生物安全防线是总体国家安全观的重要环节"},{"label":"C","content":"这一问题的解决也要依靠社会和个人的努力"},{"label":"D","content":"每位公民的心中更应该保有对自然和法律的敬畏"}]','C','文段分析见批注。
文段可看作并列结构，先后介绍解决外来入侵物种问题的两种措施：一是管理制度，二是公众参与。所填入语句引出第二种措施，应体现“人人参与”。
A选项、B选项均未体现“人人参与”,可简单排除；
D选项虽然提及“每位公民”,但“保有对自然和法律的敬畏”无中生有，未体现“外来物种入侵”这一问题，排除；
C选项的“这一问题”指代首句的“外来入侵物种问题”,“要依靠社会和个人努力”对应下文对策，而且句式和首句相似，可看作“相同句式表并列”, 完美选项，当选。
