INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300521,3,'中心理解题','距今大约八千年前，随着地球明显回暖，原始农业先后在中东、东亚和中南美地区出现。4200年前，干冷气候突变，造成粮食减产和苏美尔、埃及、印度河与中国良渚等古文化崩溃。中国历代王朝兴衰，很大程度上与气候变化和粮食产量密切相关。粮食增产和国力强盛的秦汉、隋唐都处于相对暖期，而游牧民族大举南侵的南北朝、北宋末期及明末清初，大都伴随气候变冷、干旱频繁和粮食歉收。清朝所谓“康乾盛世”,也与气候回暖、降水增多有关，清朝后期再度变冷，灾害与饥荒又频繁发生。对这段文字概括最准确的一项是：','[{"label":"A","content":"回顾历史上的气候变迁过程"},{"label":"B","content":"强调气候对粮食生产的意义"},{"label":"C","content":"揭示气候变化对人类社会的影响"},{"label":"D","content":"说明气候是影响王朝兴衰的因素"}]','C','文段分析见批注。
文段可看作大并列结构，依次介绍气候变化对8000年前中东等地区、 4200年前苏美尔等地区、中国历代王朝的影响。关键词为“气候变化”和“人类社会”,对应C选项，当选；
A选项、B选项均未提及“人类社会”,D选项只对应“分3”部分，均可简单排除。

花生批注：
① 行文结构：大并列结构。
分1:八千年前的地球回暖，为中东、东亚和中南美地区带来原始农业；
分2:4200年前，干冷气候造成粮食减产和苏美尔、埃及、印度河与中国良渚等古文化崩溃；
分3:气候变化和粮食产量变化，影响中国历代王朝的兴衰。
