INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300523,3,'细节判断类','恒星中心迅速的聚合反应在经历数百万年后，逐渐耗尽自身的氢元素。此时，恒星的中心坍缩产生更高的温度，直到氦原子开始聚合，产生更复杂的元素，比如碳。经历一系列这样的剧烈坍缩，新的元素不断诞生，直至出现原子核中拥有26个质子的铁元素。产生含有更多质子的元素需要更高的温度。没有恒星(无论其体积大小)能达到如此高的温度。当一颗体型巨大的恒星坍缩时，它会在巨大的爆炸中走向消亡，成为一颗“超新星”。正是在此过程中产生了各种重元素，直到最重的元素铀，其原子核中含有92个质子。超新星使得化学反应成为可能，没有它们，人类就不会存在，地球也不会存在。第一批超新星很可能是在大爆炸发生10亿年内消亡的。从那时起，超新星就一直将更复杂的化学元素抛撒到星际空间。尽管氢和氦仍是宇宙中占绝对优势的主导元素，但是其他元素的储量也有了显著的积累和提高。这些元素可以通过各种复杂的方式合成化合物。
根据这段文字推论正确的是：','[{"label":"A","content":"足够高的温度是星际空间产生新元素的必要条件之一"},{"label":"B","content":"碳、铁、铀等元素都是在恒星的聚合坍缩中产生的"},{"label":"C","content":"超新星时期，宇宙中占优势的化学元素不再是氢和氦"},{"label":"D","content":"超新星的消亡使宇宙中更加复杂的物质化合成人类"}]','A','A选项，根据②③④句可知“恒星的中心坍缩产生更高的温度……产生含有更多质子的元素需要更高的温度”,即足够高的温度是宇宙产生新元素的必要条件之一，表述正确，当选。

花生批注：
④ 根据⑦句可知，铀元素是在恒星走向消亡、成为一颗超新星过程中产生的，错误。
⑤ 根据⑪句可知，超新星时期，占绝对优势的主导元素依然是氢和氦，错误。
⑥ 根据⑧句可知，超新星使得化学反应成为可能，也让人类成为可能；根据⑫句可知，各种元素可以通过各种复杂的方式合成化合物；
“超新星消亡”、“化合成人类”均无中生有，错误。','2021年黑龙江省考','进阶','published','{"globalNumber":523,"setNumber":27,"localNumber":3,"sourceLabel":"2021年黑龙江省考 48%","accuracy":48,"typeAndPassage":"细节判断类","stemRich":[{"text":"恒星中心迅速的聚合反应在经历数百万年后，逐渐耗尽自身的氢元素。此时，恒星的中心坍缩产生更高的温度，直到氦原子开始聚合，产生更复杂的元素，比如碳。经历一系列这样的剧烈坍缩，新的元素不断诞生，直至出现原子核中拥有26个质子的铁元素。产生含有更多质子的元素需要更高的温度。没有恒星(无论其体积大小)能达到如此高的温度。当一颗体型巨大的恒星坍缩时，它会在巨大的爆炸中走向消亡，成为一颗“超新星”。正是在此过程中产生了各种重元素，直到最重的元素铀，其原子核中含有92个质子。超新星使得化学反应成为可能，没有它们，人类就不会存在，地球也不会存在。第一批超新星很可能是在大爆炸发生10亿年内消亡的。从那时起，超新星就一直将更复杂的化学元素抛撒到星际空间。尽管氢和氦仍是宇宙中占绝对优势的主导元素，但是其他元素的储量也有了显著的积累和提高。这些元素可以通过各种复杂的方式合成化合物。\n根据这段文字推论正确的是："}],"optionRich":{"A":[{"text":"足够高的温度是星际空间产生新元素的必要条件之一"}],"B":[{"text":"碳、铁、铀等元素都是在恒星的聚合坍缩中产生的"}],"C":[{"text":"超新星时期，宇宙中占优势的化学元素不再是氢和氦"}],"D":[{"text":"超新星的消亡使宇宙中更加复杂的物质化合成人类"}]},"annotatedStemRich":[{"text":"①恒星中心迅速的聚合反应在经历数百万年后，逐渐耗尽自身的氢元素。\n②此时，恒星的中心坍缩产生更高的温度，直到氦原子开始聚合，产生更复杂的元素，比如碳。③经历一系列这样的剧烈坍缩，新的元素不断诞生，直至出现原子核中拥有26个质子的铁元素。④产生含有更多质子的元素需要更高的温度( A 选项)。⑤没有恒星(无论其体积大小)能达到如此高的温度。⑥当一颗体型巨大的恒星坍缩时，它会在巨大的爆炸中走向消亡，成为一颗“超新星”。⑦正是在此过程中产生了各种重元素，直到最重的元素铀，其原子核中含有92个质子 ( B 选项 ) 。⑧超新星使得化学反应成为可能，没有它们，人类就不会存在，地球也不会存在。⑨第一批超新星很可能是在大爆炸发生10亿年内消亡的。⑩从那时起，超新星就一直将更复杂的化学元素抛撒到星际空间。⑪尽管氢和氦仍是宇宙中占绝对优势的主导元素，但是其他元素的储量也有了显著的积累和提高(C 选项)。⑫这些元素可以通过各种复杂的方式合成化合物( D 选项)。\n根据这段文字推论正确的是："}],"annotatedOptionRich":{"A":[{"text":"足够高的温度是星际空间产生新元素的必要条件之一"}],"B":[{"text":"碳、铁、铀等元素都是在恒星的聚合坍缩中产生的④"}],"C":[{"text":"超新星时期，宇宙中占优势的化学元素不再是氢和氦⑤"}],"D":[{"text":"超新星的消亡使宇宙中更加复杂的物质化合成人类⑥"}]},"practicalAnalysis":"A选项，根据②③④句可知“恒星的中心坍缩产生更高的温度……产生含有更多质子的元素需要更高的温度”,即足够高的温度是宇宙产生新元素的必要条件之一，表述正确，当选。","notes":[{"marker":"④","content":"根据⑦句可知，铀元素是在恒星走向消亡、成为一颗超新星过程中产生的，错误。","matchScore":0.7499,"pairingMode":"marker-and-content","order":3},{"marker":"⑤","content":"根据⑪句可知，超新星时期，占绝对优势的主导元素依然是氢和氦，错误。","matchScore":0.6725,"pairingMode":"marker-and-content","order":4},{"marker":"⑥","content":"根据⑧句可知，超新星使得化学反应成为可能，也让人类成为可能；根据⑫句可知，各种元素可以通过各种复杂的方式合成化合物；\n“超新星消亡”、“化合成人类”均无中生有，错误。","matchScore":0.746,"pairingMode":"marker-and-content","order":5}],"pairingMode"