INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300528,3,'语句填入类','采取项目储备、招标悬赏等主动布局方式，围绕大规模天线阵列、新型多址、新空口多载波、网络切片、中高频器件、光芯片、信息安全等重点方向，组织实施5G关键核心技术攻关项目，力争实现 5G 领域一批核心技术的重大突破，建立重大科技联合攻关和产量协同发展机制，推进产业关键共性技术合作研发和成果产业化，鼓励企业、高校和科研机构建设重点实验室、工程研究中心、企业技术中心等创新载体。
