INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300530,3,'语句填入类','在史前夏商时期，以鼎、觚、爵为代表的大型青铜礼器，以璧、圭、琮、璋等为代表的精美玉器，一般应为国王、贵族或最高统治者所拥有的“重器”,可作为判断遗址性质的参考标准。一个大型遗址一旦发现有使用此类物品的迹象，那么其性质很可能与都邑有密切关系。但由于青铜器、玉器具有可移动性和流动性，特定情况下可分散到都邑以外的地方，致使非都邑遗址也可能见到高规格的精美遗物。故高规格的遗物只能作为都邑遗址主要物化标准的补充，或作为主要物化标准有缺项情况下的重要参考。如果遗址不具备主要物化标志，
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"就难以断定高规格遗物的使用地点是否发生改变"},{"label":"B","content":"则需以此类“重器”为切入点来构建其它证据链"},{"label":"C","content":"单独的高规格遗物不能贸然作为都邑遗址的标志"},{"label":"D","content":"可从铸铜以及制玉手工作坊的存在推断都邑遗址"}]','C','文段分析见批注。
文段为转折结构，转折前介绍“大型遗址若发现‘重器’,就可能和都邑有关”,转折后介绍“‘重器’可移动和流动，非都邑也可能有，故‘重器’只能作为主要物化标准的补充或参考”,如果遗址不具备主要物化标志，那么不要贸然判定为都邑遗址，与转折前呼应；对应C选项，当选；
A选项未提及“是否是都邑遗址”,排除； B选项的“以‘重器’为切入点构建其他证据链”无中生有，无法和上文呼应，排除；D选项“可从铸铜以及制玉手工作坊”无中生有，排除。

花生批注：
② 行文结构：二层结构之转折。
转折前：
大型遗址若发现“重器”, 就可能和都邑有关。
转折后：
但“重器”可能移动和流动，非都邑也可能有，故“重器”只能作为主要物化标准的补充或参考。
22 转折前：
大型遗址若发现“重器”, 就可能和都邑有关。
转折后：
大型遗址若无主要物化标志，不要仅凭“重器”判定其是都邑遗址。
前后句式相似，当选。
片段阅读6 00 (下册)','2019年事业单位联考','进阶','published','{"globalNumber":530,"setNumber":27,"localNumber":10,"sourceLabel":"2019年事业单位联考 49%","accuracy":49,"typeAndPassage":"语句填入类+说理类文章","stemRich":[{"text":"在史前夏商时期，以鼎、觚、爵为代表的大型青铜礼器，以璧、圭、琮、璋等为代表的精美玉器，一般应为国王、贵族或最高统治者所拥有的“重器”,可作为判断遗址性质的参考标准。一个大型遗址一旦发现有使用此类物品的迹象，那么其性质很可能与都邑有密切关系。但由于青铜器、玉器具有可移动性和流动性，特定情况下可分散到都邑以外的地方，致使非都邑遗址也可能见到高规格的精美遗物。故高规格的遗物只能作为都邑遗址主要物化标准的补充，或作为主要物化标准有缺项情况下的重要参考。如果遗址不具备主要物化标志，"},{"text":"                        ","underline":true},{"text":"\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"就难以断定高规格遗物的使用地点是否发生改变"}],"B":[{"text":"则需以此类“重器”为切入点来构建其它证据链"}],"C":[{"text":"单独的高规格遗物不能贸然作为都邑遗址的标志"}],"D":[{"text":"可从铸铜以及制玉手工作坊的存在推断都邑遗址"}]},"annotatedStemRich":[{"text":"在史前夏商时期，以鼎、觚、爵为代表的大型青铜礼器，以璧、圭、琮、璋等为代表的精美玉器，一般应为国王、贵族或最高统治者所拥有的“重器”, 可作为判断遗址性质的参考标准。一个大型遗址一旦发现有使用此类物品的迹象，那么其性质很可能与都邑有密切关系。但由于青铜器、玉器具有可移动性和流动性，特定情况下可分散到都邑以外的地方，致使非都邑遗址也可能见到高规格的精美遗物。故高规格的遗物只能作为都邑遗址主要物化标准的补充，或作为主要物化标准有缺项情况下的重要参考。如果遗址不具备主要物化标志，\n㉑\n"},{"text":" ","underline":true},{"text":" o\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"就难以断定高规格遗物的使用地点是否发生改变"}],"B":[{"text":"则需以此类“重器”为切入点来构建其它证据链"}],"C":[{"text":"单独的高规格遗物不能贸然作为都邑遗址的标志"}],"D":[{"text":"可从铸铜以及制玉手工作坊的存在推断都邑遗址"}]},"practicalAnalysis":"文段分析见批注。\n文段为转折结构，转折前介绍“大型遗址若发现‘重器’,就可能和都邑有关”,转折后介绍“‘重器’可移动和流动，非都邑也可能有，故‘重器’只能作为主要物化标准的补充或参考”,如果遗址不具备主要物化标志，那么不要贸然判定为都邑遗址，与转折前呼应；对应C选项，当选；\nA选项未提及“是否是都邑遗址”,排除； B选项的“以‘重器’为切入点构建其他证据链”无中生有，无法和上文呼应，排除；D选项“可从铸铜以及制玉手工作坊”无中生有，排除。","notes":[{"marker":"②","content":"行文结构：二层结构之转折。\n转折前：\n大型遗址若发现“重器”, 就可能和都邑有关。\n转折后：\n但“重器”可能移动和流动，非都邑也可能有，故“重器”只能作为主要物化标准的补充或参考。","matchScore":0.9686,"pairingMode":"content-similarity","order":20},{"marker":"22","content":"转折前：\n大型遗址若发现“重器”, 就可能和都邑有关。\n转折后：\n大型遗址若无主要物化标志，不要仅凭“重器”判定其是都邑遗址。\n前后句式相似，当选。\n片段阅读6 00 (下册)","matchScore":0.6427,"pairingMode":"content-similarity","order":21}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300531,3,'细节判断类','棕色脂肪组织是一种功能特化为产热的组织，低温时动物通过激活棕色脂肪组织和促进白色脂肪棕色化的方式增加产热，以维持体温。团队科研人员利用不同的抗生素配方处理小鼠以清除小鼠的肠道菌群，发现缺失肠道菌群的小鼠体温调控机制受到破坏，研究发现肠道菌群的缺失减弱了棕色脂肪组织中UCP-1 蛋白表达量的增加，降低了白色脂肪组织的棕色化水平。科研人员认为，产生这种作用的原因可能是在寒冷条件下，肠道菌群被破坏后，动物不能消化足够数量的食物，以满足寒冷条件下的热量需求。
根据这段文字，下列说法正确的是：','[{"label":"A","content":"拥有肠道菌群的动物能够抵御寒冷"},{"label":"B","content":"小鼠的体温控制机制和人类类似"},{"label":"C","content":"动物只能依靠棕色脂肪组织维持体温"},{"label":"D","content":"UCP-1 蛋白的表达量与肠道菌群的数量成正比"}]','A','本题可使用排除法解题。
B选项，文段并未提及人类体温控制机制，“与人类类似”无中生有，错误；
C选项，“只能依靠棕色脂肪组织维持体温”表述过于绝对，错误；

花生批注：
3 根据第③句的“肠道菌群被D选项，根据文段第②句的“研究发现肠道菌群的缺失减弱了棕色脂肪组
破坏后，动物不能消化足够织中UCP-1 蛋白表达量的增加”可知，肠道菌群数量减少的同时UCP-1 蛋数量的食物，以满足寒冷条
件下的热量需求”可知，肠白表达量增长放缓，即前者减少的同时后者依然在增加(只是增速放缓),二道菌群有助于帮助动物抵御者并非成正比关系，错误；
寒冷，与A选项意思接近，
正确。虽然A选项表述不十分严谨，但大体符合文段且不违背常识，当选。','2022年天津市考','挑战','published','{"globalNumber":531,"setNumber":27,"localNumber":11,"sourceLabel":"2022年天津市考 39%","accuracy":39,"typeAndPassage":"细节判断类","stemRich":[{"text":"棕色脂肪组织是一种功能特化为产热的组织，低温时动物通过激活棕色脂肪组织和促进白色脂肪棕色化的方式增加产热，以维持体温。团队科研人员利用不同的抗生素配方处理小鼠以清除小鼠的肠道菌群，发现缺失肠道菌群的小鼠体温调控机制受到破坏，研究发现肠道菌群的缺失减弱了棕色脂肪组织中UCP-1 蛋白表达量的增加，降低了白色脂肪组织的棕色化水平。科研人员认为，产生这种作用的原因可能是在寒冷条件下，肠道菌群被破坏后，动物不能消化足够数量的食物，以满足寒冷条件下的热量需求。\n根据这段文字，下列说法正确的是："}],"optionRich":{"A":[{"text":"拥有肠道菌群的动物能够抵御寒冷"}],"B":[{"text":"小鼠的体温控制机制和人类类似"}],"C":[{"text":"动物只能依靠棕色脂肪组织维持体温"}],"D":[{"text":"UCP-1 蛋白的表达量与肠道菌群的数量成正比"}]},"annotatedStemRich":[{"text":"①棕色脂肪组织是一种功能特化为产热的组织，低温时动物通过激活棕色脂肪组织和促进白色脂肪棕色化的方式增加产热，以维持体温。②团队科研人员利用不同的抗生素配方处理小鼠以清除小鼠的肠道菌群，发现缺失肠道菌群的小鼠体温调控机制受到破坏，研究发现肠道菌群的缺失减弱了棕色脂肪组织中 UCP-1蛋白表达量的增加，降低了白色脂肪组织的棕色化水平。③科研人员认为，产生这种作用的原因可能是在寒冷条件下，肠道菌群被破坏后，动物不能消化足够数量的食物，以满足寒冷条件下的热量需求。\n根据这段文字，下列说法正确的是："}],"annotatedOptionRich":{"A":[{"text":"拥有肠道菌群的动物能够抵御寒冷"}],"B":[{"text":"小鼠的体温控制机制和人类类似"}],"C":[{"text":"动物只能依靠棕色脂肪组织维持体温"}],"D":[{"text":"UCP-1 蛋白的表达量与肠道菌群的数量成正比"}]},"practicalAnalysis":"本题可使用排除法解题。\nB选项，文段并未提及人类体温控制机制，“与人类类似”无中生有，错误；\nC选项，“只能依靠棕色脂肪组织维持体温”表述过于绝对，错误；","notes":[{"marker":"3","content":"根据第③句的“肠道菌群被D选项，根据文段第②句的“研究发现肠道菌群的缺失减弱了棕色脂肪组\n破坏后，动物不能消化足够织中UCP-1 蛋白表达量的增加”可知，肠道菌群数量减少的同时UCP-1 蛋数量的食物，以满足寒冷条\n件下的热量需求”可知，肠白表达量增长放缓，即前者减少的同时后者依然在增加(只是增速放缓),二道菌群有助于帮助动物抵御者并非成正比关系，错误；\n寒冷，与A选项意思接近，\n正确。虽然A选项表述不十分严谨，但大体符合文段且不违背常识，当选。","matchScore":0.6351,"pairingMode":"marker-and-content","order":22}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300532,3,'语句排序类','①粗细不均、长短不一、弯直各异的线条，经土著“大师”们的巧妙组合、排布，再配合上平涂的点、面，一幅幅形象生动的绘画便跃然于树皮之上
②在取材用料上，20世纪的澳洲树皮画创作，依然保持了土著艺术的“原汁原味”一以桉树皮为画布，以赭石等矿物质为颜料
③正是这种特殊的画笔，使得树皮画在艺术形式上呈现出以线条表现为主的特色
④得益于延续几千年的历史和人文传统，澳大利亚树皮画带有强烈的原始艺术趣味
⑤绘画工具简单便利，多是在细木棒一端固定上细长毛发制作而成
⑥每一笔线条都好似岁月留痕，勾勒出古老部落的传说、崇拜乃至先民的视野与思想所及将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"④②⑤③①⑥⁴"},{"label":"B","content":"①⑥④⑤③②\n162"},{"label":"C","content":"④⑤⑥ ②③①"},{"label":"D","content":"①④⑥⑤②③"}]','A','本题首句在④①中选择，④引出澳大利亚树皮画这一话题， ①具体介绍树皮画的特点，应先④引出话题后①展开论述，排除B选项、D选项；
⑤③都在讨论“绘画工具”,⑤介绍绘画工具是什么,③的“这种特殊画笔”指代⑤的绘画工具，⑤③应绑定，排除C选项；
综上，A选项当选。

花生批注：
④ ⑤绘画工具简单便利，多是在细木棒一端固定上细长毛发制作而成
行文逻辑如下：
④引出澳大利亚树皮画； ⑥每一笔线条都好似岁月留痕，勾勒出古老部落的传说、崇拜乃至先民的
②⑤介绍此画的画布、颜料、视野与思想所及绘画工具；
③①⑥介绍画作的特点。将以上6个句子重新排列，语序正确的是：
A.④②⑤③①⑥⁴ B.①⑥④⑤③②
162 C.④⑤⑥ ②③① D.①④⑥⑤②③','2020年天津市事业单位','基础','published','{"globalNumber":532,"setNumber":27,"localNumber":12,"sourceLabel":"2020年天津市事业单位 76%","accuracy":76,"typeAndPassage":"语句排序类+科普介绍文章","stemRich":[{"text":"①粗细不均、长短不一、弯直各异的线条，经土著“大师”们的巧妙组合、排布，再配合上平涂的点、面，一幅幅形象生动的绘画便跃然于树皮之上\n②在取材用料上，20世纪的澳洲树皮画创作，依然保持了土著艺术的“原汁原味”一以桉树皮为画布，以赭石等矿物质为颜料\n③正是这种特殊的画笔，使得树皮画在艺术形式上呈现出以线条表现为主的特色\n④得益于延续几千年的历史和人文传统，澳大利亚树皮画带有强烈的原始艺术趣味\n⑤绘画工具简单便利，多是在细木棒一端固定上细长毛发制作而成\n⑥每一笔线条都好似岁月留痕，勾勒出古老部落的传说、崇拜乃至先民的视野与思想所及将以上6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"④②⑤③①⑥⁴"}],"B":[{"text":"①⑥④⑤③②\n162"}],"C":[{"text":"④⑤⑥ ②③①"}],"D":[{"text":"①④⑥⑤②③"}]},"annotatedStemRich":[{"text":"①粗细不均、长短不一、弯直各异的线条，经土著“大师”们的巧妙组合、排布，再配合上平涂的点、面，一幅幅形象生动的绘画便跃然于树皮之上\n②在取材用料上，20世纪的澳洲树皮画创作，依然保持了土著艺术的“原\n汁原味”一以桉树皮为画布，以赭石等矿物质为颜料\n③正是这种特殊的画笔，使得树皮画在艺术形式上呈现出以线条表现为主的特色 ④得益于延续几千年的历史和人文传统，澳大利亚树皮画带有强烈的原始艺术趣味\n④花生批注： ⑤绘画工具简单便利，多是在细木棒一端固定上细长毛发制作而成\n行文逻辑如下：\n④引出澳大利亚树皮画； ⑥每一笔线条都好似岁月留痕，勾勒出古老部落的传说、崇拜乃至先民的\n②⑤介绍此画的画布、颜料、视野与思想所及绘画工具；\n③①⑥介绍画作的特点。将以上6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"④②⑤③①⑥⁴"}],"B":[{"text":"①⑥④⑤③②\n162"}],"C":[{"text":"④⑤⑥ ②③①"}],"D":[{"text":"①④⑥⑤②③"}]},"practicalAnalysis":"本题首句在④①中选择，④引出澳大利亚树皮画这一话题， ①具体介绍树皮画的特点，应先④引出话题后①展开论述，排除B选项、D选项；\n⑤③都在讨论“绘画工具”,⑤介绍绘画工具是什么,③的“这种特殊画笔”指代⑤的绘画工具，⑤③应绑定，排除C选项；\n综上，A选项当选。","notes":[{"marker":"④","content":"⑤绘画工具简单便利，多是在细木棒一端固定上细长毛发制作而成\n行文逻辑如下：\n④引出澳大利亚树皮画； ⑥每一笔线条都好似岁月留痕，勾勒出古老部落的传说、崇拜乃至先民的\n②⑤介绍此画的画布、颜料、视野与思想所及绘画工具；\n③①⑥介绍画作的特点。将以上6个句子重新排列，语序正确的是：\nA.④②⑤③①⑥⁴ B.①⑥④⑤③②\n162 C.④⑤⑥ ②③① D.①④⑥⑤②③","matchScore":1.2433,"pairingMode":"marker-and-content","order":23}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300533,3,'中心理解题','群众的眼睛是雪亮的，但如果缺乏足够的引导和约束，这种“雪亮”有可能变成一种“偏执”,一种没有方向的自负。而建立在“多数人”压过“少数人”基础上的制度安排，很可能走进片面和偏狭的陷阱中。“上级”评议，官员面对的是“一个人”,“公众”评议，官员面对的是“一群人”, 只有在“顶天”的压力和“立地”的责任互相补充下才能真正起到足够的监督作用。自上而下与自下而上的监督力量有机地结合，才可能在博弈中避免“一个人”的片面和“一群人”的片面。
这段文字的主旨是：','[{"label":"A","content":"质疑群众评议的合理性"},{"label":"B","content":"群众的意志要得到合理的引导和约束"},{"label":"C","content":"如何对官员进行有效的监督"},{"label":"D","content":"怎样在群众和上级间达到平衡"}]','C','文段分析见批注。
文段为后对策结构，文段对策为：“官员监督需要自上而下与自下而上的监督力量有机地结合”,谈论的是对官员的监督措施。 C选项是对对策的概括，文段谈论的是如何对官员进行有效监督，当选；
其他选项未提及“对官员的监督”,均可简单排除。

花生批注：
25 官员是对策的主体
6 行文结构：后对策结构。
开篇提出问题：
群众监督缺乏引导和约束也会走进片面和狭隘；
之后给出对策：
官员监督需要自上而下与自下而上的监督力量有机地结合。','2020年建设银行秋招','挑战','published','{"globalNumber":533,"setNumber":27,"localNumber":13,"sourceLabel":"2020年建设银行秋招32%","accuracy":32,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"群众的眼睛是雪亮的，但如果缺乏足够的引导和约束，这种“雪亮”有可能变成一种“偏执”,一种没有方向的自负。而建立在“多数人”压过“少数人”基础上的制度安排，很可能走进片面和偏狭的陷阱中。“上级”评议，官员面对的是“一个人”,“公众”评议，官员面对的是“一群人”, 只有在“顶天”的压力和“立地”的责任互相补充下才能真正起到足够的监督作用。自上而下与自下而上的监督力量有机地结合，才可能在博弈中避免“一个人”的片面和“一群人”的片面。\n这段文字的主旨是："}],"optionRich":{"A":[{"text":"质疑群众评议的合理性"}],"B":[{"text":"群众的意志要得到合理的引导和约束"}],"C":[{"text":"如何对官员进行有效的监督"}],"D":[{"text":"怎样在群众和上级间达到平衡"}]},"annotatedStemRich":[{"text":"群众的眼睛是雪亮的，但如果缺乏足够的引导和约束，这种“雪亮”有可能变成一种“偏执”,一种没有方向的自负。而建立在“多数人”压过“少数人”基础上的制度安排，很可能走进片面和偏狭的陷阱中(提出问题)。“上级”评议，"},{"text":"官员","underline":true},{"text":"面对的是“一个人”,“公众”评议，官员面对的是“一群人”, 只有在“顶天”的压力和“立地”的责任互相补充下才能真正起到足够的监督作用。自上而下与自下而上的监督力量有机地结合，才可能在博弈中避免“一个人”的片面和“一群人”的片面(后对策)。②\n这段文字的主旨是："}],"annotatedOptionRich":{"A":[{"text":"质疑群众评议的合理性"},{"text":"(","bold":true},{"text":" "},{"text":"缺主体","bold":true},{"text":" "},{"text":")","bold":true}],"B":[{"text":"群众的意志要得到合理的引导和约束( 缺主体 )"}],"C":[{"text":"如何对官员进行有效的监督"}],"D":[{"text":"怎样在群众和上级间达到平衡(缺主体)"}]},"practicalAnalysis":"文段分析见批注。\n文段为后对策结构，文段对策为：“官员监督需要自上而下与自下而上的监督力量有机地结合”,谈论的是对官员的监督措施。 C选项是对对策的概括，文段谈论的是如何对官员进行有效监督，当选；\n其他选项未提及“对官员的监督”,均可简单排除。","notes":[{"marker":"25","content":"官员是对策的主体","matchScore":0.7423,"pairingMode":"content-similarity","order":24},{"marker":"6","content":"行文结构：后对策结构。\n开篇提出问题：\n群众监督缺乏引导和约束也会走进片面和狭隘；\n之后给出对策：\n官员监督需要自上而下与自下而上的监督力量有机地结合。","matchScore":0.774,"pairingMode":"content-similarity","order":25}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300534,3,'中心理解题','失去对自然声音感悟的人是最可悲的，当有人说“风景美得像一幅画”时，境界便低了，因为画是静的，自然的风景是活的、动的；而除了目视，自然还提供了各种声音，这种双重的组合才使自然超拔出人所能创造的境界。世上有无数艺术家，全是从自然中吸取灵感，但再好的艺术家，总无法完全捕捉自然的魂魄，因为自然是有声音有画面的，还是活的，时刻都在变化的。
这段文字意在说明：','[{"label":"A","content":"欣赏自然需要视觉、听觉的全方位体验"},{"label":"B","content":"大自然为艺术家提供了取之不尽的材料"},{"label":"C","content":"自然风景超出了人所能创造的境界"},{"label":"D","content":"取法自然才能创造出杰出的作品"}]','A','文段分析见批注。
文段为前观点结构，开篇和末尾都给出观点：自然是有声音的。“声音”是全文的关键词，只有A选项提及声音，而且“欣赏自然需要听觉”是解决“失去对自然声音感悟的人是可悲的”的对策，当选⑧;
其他选项均未提及“自然的声音”,均可简单排除。

花生批注：
② 行文结构：前观点结构。
开门见山给出观点：
失去对自然声音感悟的人是可悲的；
然后分析论证：
画面和声音的双重的组合才使自然超拔出人所能创造的境界；
最后重复观点：
自然是有声音有画面的，还是活的，时刻都在变化的。
28 实战秒杀：
文段全文都在强调自然的声音，故抓住高频词“声音”即可直接秒杀A选项。
⑨ “失去对自然声音感悟的人是最可悲的”可理解为问题，针对问题的对策是“要感悟自然的声音”,即欣赏自然需要视觉和听觉的全方位体验。','2022年辽宁省事业单位','进阶','published','{"globalNumber":534,"setNumber":27,"localNumber":14,"sourceLabel":"2022年辽宁省事业单位56%","accuracy":56,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"失去对自然声音感悟的人是最可悲的，当有人说“风景美得像一幅画”时，境界便低了，因为画是静的，自然的风景是活的、动的；而除了目视，自然还提供了各种声音，这种双重的组合才使自然超拔出人所能创造的境界。世上有无数艺术家，全是从自然中吸取灵感，但再好的艺术家，总无法完全捕捉自然的魂魄，因为自然是有声音有画面的，还是活的，时刻都在变化的。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"欣赏自然需要视觉、听觉的全方位体验"}],"B":[{"text":"大自然为艺术家提供了取之不尽的材料"}],"C":[{"text":"自然风景超出了人所能创造的境界"}],"D":[{"text":"取法自然才能创造出杰出的作品"}]},"annotatedStemRich":[{"text":"失去对自然声音感悟的人是最可悲的"},{"text":"(","bold":true},{"text":" "},{"text":"前观点","bold":true},{"text":" "},{"text":")","bold":true},{"text":" "},{"text":",","bold":true},{"text":"当有人说“风景美得像一幅画”时，境界便低了，因为画是静的，自然的风景是活的、动的；而除了目视，自然还提供了各种声音，这种双重的组合才使自然超拔出人所能创造的境"},{"text":"界(分析论证)。","bold":true},{"text":"世上有无数艺术家，全是从自然中吸取灵感，但再好的艺术家，总无法完全捕捉自然的魂魄，因为自然是有声音有画面的，\n还是活的，时刻都在变化的"},{"text":"(重复观点)。②","bold":true},{"text":"\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"欣赏自然需要视觉、听觉的全方位体验"}],"B":[{"text":"大自然为艺术家提供了取之不尽的材料"},{"text":"(缺主题词)","bold":true}],"C":[{"text":"自然风景超出了人所能创造的境界("},{"text":"缺主题词)","bold":true}],"D":[{"text":"取法自然才能创造出杰出的作品 "},{"text":"(缺主题词)","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段为前观点结构，开篇和末尾都给出观点：自然是有声音的。“声音”是全文的关键词，只有A选项提及声音，而且“欣赏自然需要听觉”是解决“失去对自然声音感悟的人是可悲的”的对策，当选⑧;\n其他选项均未提及“自然的声音”,均可简单排除。","notes":[{"marker":"②","content":"行文结构：前观点结构。\n开门见山给出观点：\n失去对自然声音感悟的人是可悲的；\n然后分析论证：\n画面和声音的双重的组合才使自然超拔出人所能创造的境界；\n最后重复观点：\n自然是有声音有画面的，还是活的，时刻都在变化的。","matchScore":1.0057,"pairingMode":"marker-and-content","order":26},{"marker":"28","content":"实战秒杀：\n文段全文都在强调自然的声音，故抓住高频词“声音”即可直接秒杀A选项。","matchScore":0.3417,"pairingMode":"content-similarity","order":27},{"marker":"⑨","content":"“失去对自然声音感悟的人是最可悲的”可理解为问题，针对问题的对策是“要感悟自然的声音”,即欣赏自然需要视觉和听觉的全方位体验。","matchScore":0.635,"pairingMode":"content-similarity","order":28}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300535,3,'语句排序类','①在众多化学元素当中，放射性元素因其神奇的特质，令众多科学家痴迷
②相比核裂变，这种核聚变能源更加清洁安全
③比如放射性元素氚可与氘发生核聚变反应，产生大量能量
④再比如氡，作为一种天然放射性气体，无处不在，甚至包括我们居住的房间
⑤这些元素往往字眼生僻，特别难念，但又与人们的生活息息相关
⑥科学家对放射性元素的研究不断加深，普通公众对这些元素的认知也要跟上脚步将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"⑥④③②①⑤"},{"label":"B","content":"⑥②①⑤③④"},{"label":"C","content":"①③④⑤②⑥"},{"label":"D","content":"①⑤③②④⑥\n四SIHA海IGO公NGK考AO 练习题27套"}]','D','观察首句，①句引出放射性元素，⑥是关于放射性元素的对策，应先引出再讨论，①在⑥前，排除A选项、B选项；
再从②③句入手，②句的“这种核聚变”只能接在③句后⑧,其他句子均未提及“核聚变”,排除C选项；
综上，正确答案为D选项。

花生批注：
③0 行文结构：后对策结构。
①⑤引出话题：放射性元素； ③②④举例说明：放射性元素与生活息息相关；
⑥提出对策：普通公众要提高对这些放射性元素的认识。
③ 部分同学可能认为③④“比如……,再比如”适合捆绑，但是，根据句式我们只能确定③在前，④在后，二者未必紧邻。','2023年北京市考','基础','published','{"globalNumber":535,"setNumber":27,"localNumber":15,"sourceLabel":"2023年北京市考72%","accuracy":72,"typeAndPassage":"语句排序类+科普介绍文章","stemRich":[{"text":"①在众多化学元素当中，放射性元素因其神奇的特质，令众多科学家痴迷\n②相比核裂变，这种核聚变能源更加清洁安全\n③比如放射性元素氚可与氘发生核聚变反应，产生大量能量\n④再比如氡，作为一种天然放射性气体，无处不在，甚至包括我们居住的房间\n⑤这些元素往往字眼生僻，特别难念，但又与人们的生活息息相关\n⑥科学家对放射性元素的研究不断加深，普通公众对这些元素的认知也要跟上脚步将以上6个句子重新排列，语序正确的是："}],"optionRich":{"A":[{"text":"⑥④③②①⑤"}],"B":[{"text":"⑥②①⑤③④"}],"C":[{"text":"①③④⑤②⑥"}],"D":[{"text":"①⑤③②④⑥\n四SIHA海IGO公NGK考AO 练习题27套"}]},"annotatedStemRich":[{"text":"①在众多化学元素当中，放射性元素因其神奇的特质，令众多科学家痴迷\n②相比核裂变，这种核聚变能源更加清洁安全\n③比如放射性元素氚可与氘发生核聚变反应，产生大量能量\n④再比如氡，作为一种天然放射性气体，无处不在，甚至包括我们居住的房间\n⑤这些元素往往字眼生僻，特别难念，但又与人们的生活息息相关\n⑥科学家对放射性元素的研究不断加深，普通公众对这些元素的认知也要跟上脚步\n将以上6个句子重新排列，语序正确的是："}],"annotatedOptionRich":{"A":[{"text":"⑥④③②①⑤"}],"B":[{"text":"⑥②①⑤③④"}],"C":[{"text":"①③④⑤②⑥"}],"D":[{"text":"①⑤③②④⑥\n"},{"text":"四SIHA海IGO公NGK考AO ","bold":true},{"text":"练习题27套"}]},"practicalAnalysis":"观察首句，①句引出放射性元素，⑥是关于放射性元素的对策，应先引出再讨论，①在⑥前，排除A选项、B选项；\n再从②③句入手，②句的“这种核聚变”只能接在③句后⑧,其他句子均未提及“核聚变”,排除C选项；\n综上，正确答案为D选项。","notes":[{"marker":"③0","content":"行文结构：后对策结构。\n①⑤引出话题：放射性元素； ③②④举例说明：放射性元素与生活息息相关；\n⑥提出对策：普通公众要提高对这些放射性元素的认识。","matchScore":0.4986,"pairingMode":"content-similarity","order":29},{"marker":"③","content":"部分同学可能认为③④“比如……,再比如”适合捆绑，但是，根据句式我们只能确定③在前，④在后，二者未必紧邻。","matchScore":0.1923,"pairingMode":"marker-and-content","order":30}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300536,3,'语句填入类','提到一座城市，人们往往会想到具有代表性的文化地标：600岁的紫禁城见证着北京城的过往，拓荒牛雕塑标记着深圳的开拓进取……城市文化地标 ,成为一个城市的精神和文化象征，与人们产生紧密的情感连接、文化认同。文化地标是一个地方的文化名片，在传播城市形象方面有巨大的流量效应。近年来，文化旅游市场持续升温，各类文化地标成为热门参观地、网红打卡地。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"大都强调人文景观与自然环境和谐共生，以形神兼备的呈现方式"},{"label":"B","content":"或深植于历史文化，或投射着时代风貌，以鲜明独特的符号形象"},{"label":"C","content":"不是凭借炫目奇特的视觉效果，或各类时髦文化元素的简单堆砌"},{"label":"D","content":"承载着无法替代的人文价值，满足着公众的审美旨趣和美好期待"}]','B','所填入语句是对前文的概括，且选项均为“A 且B 类”选项，依次考察选项即可。
B选项的“深植于历史文化”对应前文例子“600岁的紫禁城见证着北京城的过往”,“投射着时代风貌”对应前文例子“拓荒牛雕塑标记着深圳的开拓进取”,完美选项，当选；
其他选项均无法与上文两个例子一一对应，均可简单排除。
