INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300538,3,'中心理解题','春节期间，潮汕特色民俗英歌舞火爆，不仅为当地百姓增添了节日气氛，吸引众多游客前来观赏，更通过网络平台让更多人了解这一融舞蹈、武术、戏曲于一体的民俗运动项目。许多传统体育和民俗运动项目，蕴含着丰富历史文化内涵，是折射当地生活习俗、中华优秀传统文化的一个窗口。英歌舞的走红，得益于借助新媒体平台拓展传播途径，充分展现了文化吸引力。
