INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300539,3,'中心理解题','远在战国时就有“高枕而卧，国必无忧”的记载。古人的枕头大多既高且硬，选用的材料多为竹子、木头、石块、陶瓷，考古人员还发现了青铜枕、金枕等。这种睡硬枕头的习惯至今在我国一些地区还保留着，如有名的“关中百怪”中就有一怪是“枕头砖来代”,因为古人认为睡硬枕可以使人睿智。虽然叫“枕头”,但古代的一些硬枕其实是垫到脖子下面的，如果能贴合使用者颈椎的生理弧度，不但能给颈椎提供支撑，而且还能让颈部放松，睡得更舒服。
上述文字意在强调：','[{"label":"A","content":"“枕头砖来代”"},{"label":"B","content":"古人偏爱高枕硬枕"},{"label":"C","content":"硬枕使人睿智"},{"label":"D","content":"“高枕而卧，国必无忧”"}]','B','文段分析见批注。
文段为果因类结构，文段先介绍了古人的枕头大多既高且硬并且这种睡硬枕头的习惯至今在我国一些地区还保留着，后文具体介绍为什么古人的枕头既高且硬。
文段重点介绍古人爱睡高枕硬枕及其原因， B选项对应“果”,即因为高枕硬枕有好处，所以古人对其有所偏爱，当选；
A选项、D选项分别出自举例和引出话题部分，出处有误，C选项只是高枕硬枕的一个好处，片面，均可简单排除。

花生批注：
36 行文结构：二层结构之果因。果：古人的枕头大多既高且硬；
因：
①古人认为睡硬枕可以使人睿智；
②能给颈椎提供支撑，而且还能让颈部放松，睡得更舒服。','2023年福建省事业单位','基础','published','{"globalNumber":539,"setNumber":27,"localNumber":19,"sourceLabel":"2023年福建省事业单位 78%","accuracy":78,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"远在战国时就有“高枕而卧，国必无忧”的记载。古人的枕头大多既高且硬，选用的材料多为竹子、木头、石块、陶瓷，考古人员还发现了青铜枕、金枕等。这种睡硬枕头的习惯至今在我国一些地区还保留着，如有名的“关中百怪”中就有一怪是“枕头砖来代”,因为古人认为睡硬枕可以使人睿智。虽然叫“枕头”,但古代的一些硬枕其实是垫到脖子下面的，如果能贴合使用者颈椎的生理弧度，不但能给颈椎提供支撑，而且还能让颈部放松，睡得更舒服。\n上述文字意在强调："}],"optionRich":{"A":[{"text":"“枕头砖来代”"}],"B":[{"text":"古人偏爱高枕硬枕"}],"C":[{"text":"硬枕使人睿智"}],"D":[{"text":"“高枕而卧，国必无忧”"}]},"annotatedStemRich":[{"text":"远在战国时就有“高枕而卧，国必无忧”的记载。古人的枕头大多既高且硬，选用的材料多为竹子、木头、石块、陶瓷，考古人员还发现了青铜枕、金枕等(果)。这种睡硬枕头的习惯至今在我国一些地区还保留着，如有名的“关中百怪”中就有一怪是“枕头砖来代”,因为古人认为睡硬枕可以使人睿智。虽然叫“枕头”, 但古代的一些硬枕其实是垫到脖子下面的，如果能贴合使用者颈椎的生理弧度，不但能给颈椎提供支撑，而且还能让颈部放松，睡得更舒服( 因 ) 。\n上述文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"“枕头砖来代”(出处有误)"}],"B":[{"text":"古人偏爱高枕硬枕"}],"C":[{"text":"硬枕使人睿智(片面)"}],"D":[{"text":"“高枕而卧，国必无忧”(出处有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段为果因类结构，文段先介绍了古人的枕头大多既高且硬并且这种睡硬枕头的习惯至今在我国一些地区还保留着，后文具体介绍为什么古人的枕头既高且硬。\n文段重点介绍古人爱睡高枕硬枕及其原因， B选项对应“果”,即因为高枕硬枕有好处，所以古人对其有所偏爱，当选；\nA选项、D选项分别出自举例和引出话题部分，出处有误，C选项只是高枕硬枕的一个好处，片面，均可简单排除。","notes":[{"marker":"36","content":"行文结构：二层结构之果因。果：古人的枕头大多既高且硬；\n因：\n①古人认为睡硬枕可以使人睿智；\n②能给颈椎提供支撑，而且还能让颈部放松，睡得更舒服。","matchScore":0.9411,"pairingMode":"content-similarity","order":35}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300540,3,'中心理解题','乡村教师犹如点点烛光，为农村孩子点亮梦想，为乡村发展注入力量。农村孩子的未来，需要乡村教师的坚守；乡村教师的成长，也需要制度的护航。无论是提高薪酬待遇，还是在职称评审上给予政策倾斜，抑或是关注乡村教师的婚姻和居住等诉求，尊重和善待乡村教师需要更多换位思考的体谅和将心比心的成全。
上述文段旨在说明：','[{"label":"A","content":"要为乡村教师打造和提供能展现与提升自我的平台"},{"label":"B","content":"乡村教师为教育教学注入了更多的“源头活水”"},{"label":"C","content":"要满足乡村教师的精神诉求和情感需要"},{"label":"D","content":"留住乡村教师要设身处地留心留人"}]','D','文段分析见批注。
文段可看作后对策结构，对策为“尊重和善待乡村教师需要更多换位思考的体谅和将心比心的成全”,D选项为对策句的同义替换，当选；
A选项的“打造平台”和 C选项的“精神诉求和情感需要”无中生有， B选项非对策表述，均可简单排除。
