INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300543,3,'标题拟定类','横跨江河的大桥两端接岸处，通常被称为桥头，在桥头位置建造的建筑物就是桥头堡。桥头堡最初的建造目的是出于军事防御的需要。由于最初的桥头堡只是一座地堡或堡垒，因此而得名。现在有些大桥修建的桥头堡不再出于军事目的，而是作为一种建筑标志，如著名的南京长江大桥，两端桥头都建有高达70米的桥头堡，并配合雕塑群像，形成宏伟壮观的建筑群体，使大桥更具气势。桥头堡内部还安装了观光电梯，方便游人登桥眺望壮丽的长江风光。除此之外，设置桥头堡还具有利于大桥的交通管理，方便对其进行日常养护等作用。
最适合做这段文字标题的是：','[{"label":"A","content":"建造大桥桥头堡的初衷"},{"label":"B","content":"桥头堡名字的由来"},{"label":"C","content":"建造桥头堡的意义"},{"label":"D","content":"为什么大桥要造桥头堡"}]','D','文段结构见批注。
文段依次介绍建筑桥头堡的三个目的，即三个原因，对应D选项；
A选项只对应最初目的，片面； B选项出自最初目的的解释部门，非重点； C选项对应“除此之外”,非重点⑤,均可排除。

花生批注：
④ 行文结构：果因结构。
开篇引出“桥头堡”;
之后依次介绍桥头堡建造原因(即目的):
①出于军事需要目的；
②出于建筑标志目的；
③出于方便大桥管理目的。
⑤ 有同学因为“除此之外”之后的“作用”选择了C选项，我认为D选项优于C选项的原因有三点：
①原文先介绍了最初的目的、现在的目的(不再出于军事目的，而是xx 目的), 只是在“除此之外”后提及作用，“除此之外”起补充作用，重要程度显然不如前文；
②该题目为标题拟定题，标题应起到吸引人的作用，就像儿童科普读物《十万个为什么》一样，“为什么”的表述显然比“xx 的意义”更吸引读者；
③目的、原因表达的是“出于什么理由”建造了桥头堡，意义、作用侧重的是“建造了桥头堡有什么好处”,文段更侧重表达为什么要修建桥头堡。','2019年辽宁省考','进阶','published','{"globalNumber":543,"setNumber":28,"localNumber":3,"sourceLabel":"2019年辽宁省考 45%","accuracy":45,"typeAndPassage":"标题拟定类+说理类文段","stemRich":[{"text":"横跨江河的大桥两端接岸处，通常被称为桥头，在桥头位置建造的建筑物就是桥头堡。桥头堡最初的建造目的是出于军事防御的需要。由于最初的桥头堡只是一座地堡或堡垒，因此而得名。现在有些大桥修建的桥头堡不再出于军事目的，而是作为一种建筑标志，如著名的南京长江大桥，两端桥头都建有高达70米的桥头堡，并配合雕塑群像，形成宏伟壮观的建筑群体，使大桥更具气势。桥头堡内部还安装了观光电梯，方便游人登桥眺望壮丽的长江风光。除此之外，设置桥头堡还具有利于大桥的交通管理，方便对其进行日常养护等作用。\n最适合做这段文字标题的是："}],"optionRich":{"A":[{"text":"建造大桥桥头堡的初衷"}],"B":[{"text":"桥头堡名字的由来"}],"C":[{"text":"建造桥头堡的意义"}],"D":[{"text":"为什么大桥要造桥头堡"}]},"annotatedStemRich":[{"text":"横跨江河的大桥两端接岸处，通常被称为桥头，在桥头位置建造的建筑物就是桥头堡"},{"text":"(","bold":true},{"text":" "},{"text":"果","bold":true},{"text":" "},{"text":")","bold":true},{"text":" "},{"text":"。","bold":true},{"text":"桥头堡最初的建造目的是出于军事防御的需要。由于最初的桥头堡只是一座地堡或堡垒，因此而得名(原因1)。现在有些大桥修建的桥头堡不再出于军事目的，而是作为一种建筑标志，如著名的南京长江大桥，两端桥头都建有高达70米的桥头堡，并配合雕塑群像，形成宏伟壮观的建筑群体，使大桥更具气势。桥头堡内部还安装了观光电梯，方便游人登桥眺望壮丽的长江风光(原因2)。除此之外，设置桥头堡还具有利于大桥的交通管理，\n方便对其进行日常养护等作用"},{"text":"(原因3)。④","bold":true},{"text":" 最适合做这段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"建造大桥桥头堡的初衷(片面)"}],"B":[{"text":"桥头堡名字的由来( 片面 )"}],"C":[{"text":"建造桥头堡的意义(片面 )"}],"D":[{"text":"为什么大桥要造桥头堡"}]},"practicalAnalysis":"文段结构见批注。\n文段依次介绍建筑桥头堡的三个目的，即三个原因，对应D选项；\nA选项只对应最初目的，片面； B选项出自最初目的的解释部门，非重点； C选项对应“除此之外”,非重点⑤,均可排除。","notes":[{"marker":"④","content":"行文结构：果因结构。\n开篇引出“桥头堡”;\n之后依次介绍桥头堡建造原因(即目的):\n①出于军事需要目的；\n②出于建筑标志目的；\n③出于方便大桥管理目的。","matchScore":0.5261,"pairingMode":"marker-and-content","order":3},{"marker":"⑤","content":"有同学因为“除此之外”之后的“作用”选择了C选项，我认为D选项优于C选项的原因有三点：\n①原文先介绍了最初的目的、现在的目的(不再出于军事目的，而是xx 目的), 只是在“除此之外”后提及作用，“除此之外”起补充作用，重要程度显然不如前文；\n②该题目为标题拟定题，标题应起到吸引人的作用，就像儿童科普读物《十万个为什么》一样，“为什么”的表述显然比“xx 的意义”更吸引读者；\n③目的、原因表达的是“出于什么理由”建造了桥头堡，意义、作用侧重的是“建造了桥头堡有什么好处”,文段更侧重表达为什么要修建桥头堡。","matchScore":0.3042,"pairingMode":"marker-and-content","order":4}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300544,3,'下文推断类⑥','天气干燥，很多人都有这样的困扰——手指边缘会起倒刺。在临床研究中，尽管已证实维生素对于皮肤健康和皮肤黏膜的修复有一定的辅助作用，但并没有任何证据可以证明产生倒刺是因为体内缺乏某类维生素。目前临床上普遍认为，手指出现倒刺主要还是和皮肤干燥、化学刺激有直接关系。有很多人一看到倒刺，就想撕掉它，但这个操作是非常错误的。
这段文字接下来最有可能讲述的是：','[{"label":"A","content":"倒刺的形成原因"},{"label":"B","content":"随意拔倒刺会造成什么样的后果"},{"label":"C","content":"怎么处理倒刺才是正确的"},{"label":"D","content":"我们该如何避免长倒刺"}]','B','文段先介绍手指出现倒刺的原因；文末指出问题：看到倒刺就想撕掉的做法是错误的；上文提出问题，下文应分析问题或者提出针对性对策。
A选项上文已有论述，D选项的“避免长倒刺”和“如何处理倒刺”无关，可简单排除；
B选项和C选项需要辨析：B选项属于分析问题，即分析随意拔倒刺的危害，而 C选项属于解决问题，即“怎样正确处理倒刺”。根据行文逻辑，应当先分析问题危害，再提出对策解决问题，所以B选项是正确答案。

花生批注：
⑥ 下文推断的常见结构：
①上文文末提出新内容→下文解释新内容
②上文提出问题→下文分析问题、解决问题
③上文给出宏观对策、原因等→下文具体展开
④时间对比：过去不行→现在有了新突破
⑤总分：上文是总+分→下文补充另一“分”
