INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300545,3,'下文推断类②','人类学与社会学在国际社会科学领域作为独立学科早已为世界各国学者所公认，也在不同国度里经历了各自的发展历程。然而，在中国人类学发展的早期阶段，即20世纪前半期，民族学、人类学却与社会学有着纠缠不清的关系，在学科发展史讨论中是一个难以回避的话题。
文章接下来最有可能讲述的是：','[{"label":"A","content":"中国文化语境下，民族学、人类学、社会学的内涵"},{"label":"B","content":"中国民族学、人类学与社会学的代表学者及观点"},{"label":"C","content":"20 世纪前民族学、人类学与社会学研究的分歧"},{"label":"D","content":"中国民族学、人类学与社会学关系的学科发展史"}]','D','文段先介绍国际上公认人类学与社会学为独立学科，文末提出宏观问题：我国学科发展过程中，民族学、人类学与社会学的关系纠缠不清；下文可以具体介绍我国学科发展过程中民族学、人类学与社会学的关系是什么。
D选项具体介绍中国民族学、人类学与社会学关系的学科发展史，符合行文逻辑“宏观问题→下文具体展开”,当选；
A选项未提及三个学科的“关系”,内涵并非文段重点，排除； B选项，文末问题围绕三个学科的关系展开，则下文应为学科本身，无需介绍“代表学者及观点”,排除；C选项未提及“我国”,且文末介绍三者关系而非存在分歧，排除。','2016年福建省事业单位','进阶','published','{"globalNumber":545,"setNumber":28,"localNumber":5,"sourceLabel":"2016年福建省事业单位55%","accuracy":55,"typeAndPassage":"下文推断类②+宏观问题→下文具体展开","stemRich":[{"text":"人类学与社会学在国际社会科学领域作为独立学科早已为世界各国学者所公认，也在不同国度里经历了各自的发展历程。然而，在中国人类学发展的早期阶段，即20世纪前半期，民族学、人类学却与社会学有着纠缠不清的关系，在学科发展史讨论中是一个难以回避的话题。\n文章接下来最有可能讲述的是："}],"optionRich":{"A":[{"text":"中国文化语境下，民族学、人类学、社会学的内涵"}],"B":[{"text":"中国民族学、人类学与社会学的代表学者及观点"}],"C":[{"text":"20 世纪前民族学、人类学与社会学研究的分歧"}],"D":[{"text":"中国民族学、人类学与社会学关系的学科发展史"}]},"annotatedStemRich":[{"text":"人类学与社会学在国际社会科学领域作为独立学科早已为世界各国学者所公认，也在不同国度里经历了各自的发展历程。然而，在中国人类学发展的早期阶段，即20世纪前半期，民族学、人类学却与社会学有着纠缠不清的关系，在学科发展史讨论中是一个难以回避的话题 "},{"text":"(转折引出宏观问题)。","bold":true},{"text":"\n文章接下来最有可能讲述的是："}],"annotatedOptionRich":{"A":[{"text":"中国文化语境下，民族学、人类学、社会学的内涵"}],"B":[{"text":"中国民族学、人类学与社会学的代表学者及观点"}],"C":[{"text":"20 世纪前民族学、人类学与社会学研究的分歧"}],"D":[{"text":"中国民族学、人类学与社会学关系的学科发展史"}]},"practicalAnalysis":"文段先介绍国际上公认人类学与社会学为独立学科，文末提出宏观问题：我国学科发展过程中，民族学、人类学与社会学的关系纠缠不清；下文可以具体介绍我国学科发展过程中民族学、人类学与社会学的关系是什么。\nD选项具体介绍中国民族学、人类学与社会学关系的学科发展史，符合行文逻辑“宏观问题→下文具体展开”,当选；\nA选项未提及三个学科的“关系”,内涵并非文段重点，排除； B选项，文末问题围绕三个学科的关系展开，则下文应为学科本身，无需介绍“代表学者及观点”,排除；C选项未提及“我国”,且文末介绍三者关系而非存在分歧，排除。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300546,3,'中心理解题','在大数据时代，数据变得越来越敏感。而数据之所以变得越来越敏感，就是因为此所谓数据，从某种角度而言，正是由无数个人的小隐私组合而成的大数据。可以肯定地说，在公众个人隐私和便捷性之间，确有一定关联。但是，若问有多少人知道这其中的关联，再问有多少人愿意以自己的隐私来交换这种便捷性，恐怕并不能得出“很多情况下他们是愿意的”的结论。公众对上述说法的反馈，至少说明有相当多的人是不愿意进行这种交换，或者起码是在知情、有法定条件下进行这种交换。
这段文字主要表述的是：','[{"label":"A","content":"制定保护隐私的相关法规是当务之急"},{"label":"B","content":"公众个人隐私和便捷性相关联"},{"label":"C","content":"便捷性必须以隐私交换为条件"},{"label":"D","content":"大数据时代更应保护公众隐私"}]','D','文段分析见批注。
文段转折后提出“大数据时代，公众并不愿意用自己的隐私来交换便捷性”这一问题；
B选项出自文段背景介绍部分，C选项“必须”属绝对化表述⑨,均可简单排除；
A选项和D选项均属于对策选项，需要仔细辨析，A选项对策侧重于“建立相关法规”,但原文并未指出“相关法规缺位”的问题0;D选项对策侧重于“保护公众隐私”,该对策更贴合“公众不愿意用隐私交换便捷性”这一问题，“因为不愿意，所以要保护”,而且D选项的“大数据时代”对应首句；
综上，D选项是正确答案。

花生批注：
⑧ 行文结构：二层结构之转折。
转折前：
大数据时代公众个人隐私和便捷性间存在关联；
转折后：
指出相当多的人是不愿意用隐私交换便捷性的。
⑨ 文段只说了隐私和便捷性间存在关联，但并未提及“必须”用隐私交换便捷性。
⑩ A选项属于典型的对策无中生有(或过度推断);
原文指出“公众不愿意用隐私交换便捷性”这一问题，有针对性的给出“要保护公众数据隐私”这一对策即可；“继续制定保护隐私的相关法规”属于无中生有。','2023年江西省三支一扶','进阶','published','{"globalNumber":546,"setNumber":28,"localNumber":6,"sourceLabel":"2023年江西省三支一扶54%","accuracy":54,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"在大数据时代，数据变得越来越敏感。而数据之所以变得越来越敏感，就是因为此所谓数据，从某种角度而言，正是由无数个人的小隐私组合而成的大数据。可以肯定地说，在公众个人隐私和便捷性之间，确有一定关联。但是，若问有多少人知道这其中的关联，再问有多少人愿意以自己的隐私来交换这种便捷性，恐怕并不能得出“很多情况下他们是愿意的”的结论。公众对上述说法的反馈，至少说明有相当多的人是不愿意进行这种交换，或者起码是在知情、有法定条件下进行这种交换。\n这段文字主要表述的是："}],"optionRich":{"A":[{"text":"制定保护隐私的相关法规是当务之急"}],"B":[{"text":"公众个人隐私和便捷性相关联"}],"C":[{"text":"便捷性必须以隐私交换为条件"}],"D":[{"text":"大数据时代更应保护公众隐私"}]},"annotatedStemRich":[{"text":"在大数据时代，数据变得越来越敏感。而数据之所以变得越来越敏感，就是因为此所谓数据，从某种角度而言，正是由无数个人的小隐私组合而成的大数据。可以肯定地说，在公众个人隐私和便捷性之间，确有一定关联(背景介绍)。但是，若问有多少人知道这其中的关联，再问有多少人愿意以自己的隐私来交换这种便捷性，恐怕并不能得出“很多情况下他们是愿意的”的结论。公众对上述说法的反馈，至少说明有相当多的人是不愿意进行这种交换，或者起码是在知情、有法定条件下进行这种交换(提出问题)。⑧\n这段文字主要表述的是："}],"annotatedOptionRich":{"A":[{"text":"制定保护隐私的相关法规是当务之急(无中生有)"}],"B":[{"text":"公众个人隐私和便捷性相关联(出处有误)"}],"C":[{"text":"便捷性必须以隐私交换为条件(绝对化表述)"}],"D":[{"text":"大数据时代更应保护公众隐私"}]},"practicalAnalysis":"文段分析见批注。\n文段转折后提出“大数据时代，公众并不愿意用自己的隐私来交换便捷性”这一问题；\nB选项出自文段背景介绍部分，C选项“必须”属绝对化表述⑨,均可简单排除；\nA选项和D选项均属于对策选项，需要仔细辨析，A选项对策侧重于“建立相关法规”,但原文并未指出“相关法规缺位”的问题0;D选项对策侧重于“保护公众隐私”,该对策更贴合“公众不愿意用隐私交换便捷性”这一问题，“因为不愿意，所以要保护”,而且D选项的“大数据时代”对应首句；\n综上，D选项是正确答案。","notes":[{"marker":"⑧","content":"行文结构：二层结构之转折。\n转折前：\n大数据时代公众个人隐私和便捷性间存在关联；\n转折后：\n指出相当多的人是不愿意用隐私交换便捷性的。","matchScore":0.7483,"pairingMode":"marker-and-content","order":7},{"marker":"⑨","content":"文段只说了隐私和便捷性间存在关联，但并未提及“必须”用隐私交换便捷性。","matchScore":0.5824,"pairingMode":"marker-and-content","order":8},{"marker":"⑩","content":"A选项属于典型的对策无中生有(或过度推断);\n原文指出“公众不愿意用隐私交换便捷性”这一问题，有针对性的给出“要保护公众数据隐私”这一对策即可；“继续制定保护隐私的相关法规”属于无中生有。","matchScore":0.5331,"pairingMode":"content-similarity","order":9}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300547,3,'语句填入题','口服脊髓灰质炎疫苗自投入使用以来，使无数儿童免于瘫痪。但也有极小概率的健康人群服用这种疫苗后反而会瘫痪，1962年，这种情况就已经很明确了，然而口服脊髓灰质炎疫苗还是被继续使用了半个世纪。近年来，由于脊髓灰质炎的发病率在全世界范围内已降到极低水平，由口服疫苗引起的负面作用就超过了病毒本身的危害。改变了防疫方式的选择，比如美国在2000年取消了口服脊髓灰质炎疫苗，全部改用注射疫苗。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"风险收益比例的变化"},{"label":"B","content":"药物风险意识的提高"},{"label":"C","content":"防疫技术水平的提升"},{"label":"D","content":"疫苗致瘫风险的累积"}]','A','文段分析见批注。
文段可看做分总结构，先分析介绍以往的“口服脊髓灰质炎疫苗”,并介绍现状“脊髓灰质炎发病率极低，口服疫苗的危害反而大过病毒本身”;尾句应总结上文。“脊髓灰质炎疫苗的收益变小”和“疫苗带来的风险加大”①使得防疫方式出现改变，即“风险收益比例的变化改变了防疫方式的选择”,对应 A选项，当选；
其他选项均未体现这种“风险和收益比例的变化”,均可简单排除。

花生批注：
⑪ 原来脊髓灰质炎疫苗能使无数儿童免于瘫痪，虽然有极小概率使健康人群瘫痪，但疫苗的收益大于风险；
但现在脊髓灰质炎本身的发病率极低，疫苗能带来的收益变小，但是依然存在让健康人群瘫痪的风险，此时疫苗的收益就不一定大于其本身的风险；
即风险和收益的比例发生变化。','2019年江苏省事业单位','挑战','published','{"globalNumber":547,"setNumber":28,"localNumber":7,"sourceLabel":"2019年江苏省事业单位37%","accuracy":37,"typeAndPassage":"语句填入题+说理类文章","stemRich":[{"text":"口服脊髓灰质炎疫苗自投入使用以来，使无数儿童免于瘫痪。但也有极小概率的健康人群服用这种疫苗后反而会瘫痪，1962年，这种情况就已经很明确了，然而口服脊髓灰质炎疫苗还是被继续使用了半个世纪。近年来，由于脊髓灰质炎的发病率在全世界范围内已降到极低水平，由口服疫苗引起的负面作用就超过了病毒本身的危害。"},{"text":"                       ","underline":true},{"text":" 改变了防疫方式的选择，比如美国在2000年取消了口服脊髓灰质炎疫苗，全部改用注射疫苗。\n填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"风险收益比例的变化"}],"B":[{"text":"药物风险意识的提高"}],"C":[{"text":"防疫技术水平的提升"}],"D":[{"text":"疫苗致瘫风险的累积"}]},"annotatedStemRich":[{"text":"口服脊髓灰质炎疫苗自投入使用以来，使无数儿童免于瘫痪。但也有极小概率的健康人群服用这种疫苗后反而会瘫痪，1962年，这种情况就已经很明确了，然而口服脊髓灰质炎疫苗还是被继续使用了半个世纪。近年来，由于脊髓灰质炎的发病率在全世界范围内已降到极低水平，由口服疫苗引起的负面作用就超过了病毒本身的危害"},{"text":"(","bold":true},{"text":" "},{"text":"分","bold":true},{"text":" "},{"text":")","bold":true},{"text":" "},{"text":"。","bold":true},{"text":"                        ","underline":true},{"text":" 改变了防疫方式的选择，比如美国在2000年取消了口服脊髓灰质炎疫苗，全部改用注射疫苗 "},{"text":"(","bold":true},{"text":" "},{"text":"总","bold":true},{"text":" "},{"text":")","bold":true},{"text":"。\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"风险收益比例的变化"}],"B":[{"text":"药物风险意识的提高"}],"C":[{"text":"防疫技术水平的提升"}],"D":[{"text":"疫苗致瘫风险的累积"}]},"practicalAnalysis":"文段分析见批注。\n文段可看做分总结构，先分析介绍以往的“口服脊髓灰质炎疫苗”,并介绍现状“脊髓灰质炎发病率极低，口服疫苗的危害反而大过病毒本身”;尾句应总结上文。“脊髓灰质炎疫苗的收益变小”和“疫苗带来的风险加大”①使得防疫方式出现改变，即“风险收益比例的变化改变了防疫方式的选择”,对应 A选项，当选；\n其他选项均未体现这种“风险和收益比例的变化”,均可简单排除。","notes":[{"marker":"⑪","content":"原来脊髓灰质炎疫苗能使无数儿童免于瘫痪，虽然有极小概率使健康人群瘫痪，但疫苗的收益大于风险；\n但现在脊髓灰质炎本身的发病率极低，疫苗能带来的收益变小，但是依然存在让健康人群瘫痪的风险，此时疫苗的收益就不一定大于其本身的风险；\n即风险和收益的比例发生变化。","matchScore":0.6464,"pairingMode":"content-similarity","order":10}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300548,3,'标题拟定题','人们常常对创新过程中遭遇的失败缺少宽容。大家崇拜的往往是光鲜的成功者，而较少认识到创新过程的曲折、肯定失败的价值。当然，追求成功、崇拜强者没有错，但倘若一味忽略过程、只许成功不许失败，就可能无形中束缚科技人员的手脚、影响他们的创新积极性。在企业中，因为担心失败，就会让技术人员畏首畏尾，不敢研发新工艺、新产品；在科研院所，则可能导致科研人员只做“短平快”的浅层次研究。
最适合做这段文字标题的是：','[{"label":"A","content":"科研人员勇于创新"},{"label":"B","content":"创新不能够“成王败寇”"},{"label":"C","content":"要客观看待创新中的失败"},{"label":"D","content":"创新中的失败比成功更可贵"}]','B','文段结构见批注。
文段可看作前对策结构，先提出问题：对创新失败缺少宽容，接着用逻辑关联词“倘若……就”给出对策：对创新不能忽略过程，不能“只许成功不许失败。B选项是对策的同义替换，“成王”对应“只许成功”,“败寇”对应“不许失败”,完美选项，当选；
A选项未体现问题， D选项无中生有，可简单排除； C选项虽然也是对策表述，但“客观看待”不如B选项更贴合文段对策，而且不如B选项作为标题有吸引力，排除。

花生批注：
⑫ 行文结构：前对策结构。
文段先提出问题：
对创新失败缺少宽容；
转折后用“倘若..…就”给出对策：
对创新不能忽略过程，不能“只许成功不许失败”;
之后进行论证。
最适合做这段文字标题的是：
A. 科研人员勇于创新
B. 创新不能够“成王败寇”
C. 要客观看待创新中的失败
D. 创新中的失败比成功更可贵
⑬ “客观看待”强调要客观，要根据客观实际对失败采取合适态度，可能批评、可能宽容；
但文段表达的是“要对创新失败宽容”,不如“不能成王败寇”合适。
成王败寇：指在争夺政权斗争中，成功了的就是合法的，称帝称王；失败了的就是非法的，被称为寇贼；含有成功者权势在手，无人敢责难，失败者却有口难辩的意思。','2022年四川省事业单位','挑战','published','{"globalNumber":548,"setNumber":28,"localNumber":8,"sourceLabel":"2022年四川省事业单位41%","accuracy":41,"typeAndPassage":"标题拟定题+说理类文段","stemRich":[{"text":"人们常常对创新过程中遭遇的失败缺少宽容。大家崇拜的往往是光鲜的成功者，而较少认识到创新过程的曲折、肯定失败的价值。当然，追求成功、崇拜强者没有错，但倘若一味忽略过程、只许成功不许失败，就可能无形中束缚科技人员的手脚、影响他们的创新积极性。在企业中，因为担心失败，就会让技术人员畏首畏尾，不敢研发新工艺、新产品；在科研院所，则可能导致科研人员只做“短平快”的浅层次研究。\n最适合做这段文字标题的是："}],"optionRich":{"A":[{"text":"科研人员勇于创新"}],"B":[{"text":"创新不能够“成王败寇”"}],"C":[{"text":"要客观看待创新中的失败"}],"D":[{"text":"创新中的失败比成功更可贵"}]},"annotatedStemRich":[{"text":"人们常常对创新过程中遭遇的失败缺少宽容(提出问题)。大家崇拜的往往是光鲜的成功者，而较少认识到创新过程的曲折、肯定失败的价值。当然，追求成功、崇拜强者没有错，但倘若一味忽略过程、只许成功不许失败，就可能无形中束缚科技人员的手脚、影响他们的创新积极性(转折提出对策)。在企业中，因为担心失败，就会让技术人员畏首畏尾，不敢研发新工艺、新产品；在科研院所，则可能导致科研人员只做“短平快”的浅层次研究("},{"text":"论证)。②","bold":true},{"text":"\n最适合做这段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"科研人员勇于创新"}],"B":[{"text":"创新不能够“成王败寇”"}],"C":[{"text":"要客观看待创新中的失败"}],"D":[{"text":"创新中的失败比成功更可贵\n⑬"},{"text":"花生批注：","bold":true},{"text":"\n“客观看待”强调要客观，要根据客观实际对失败采取合适态度，可能批评、可能宽容；\n但文段表达的是“要对创新失败宽容”,不如“不能成王败寇”合适。\n成王败寇：指在争夺政权斗争中，成功了的就是合法的，称帝称王；失败了的就是非法的，被称为寇贼；含有成功者权势在手，无人敢责难，失败者却有口难辩的意思。\n"},{"text":"⑭花生批注：","bold":true},{"text":"\n"},{"text":"行文结构：","bold":true},{"text":"果因结构。\n先提出“网络文学版权维护难”这一问题(果);\n再分析这一问题产生的原"},{"text":"因：","bold":true},{"text":"\n①数字内容产业本身存在侵权盗版问题；\n②作品本身的版权也存在不少漏洞；\n③网络作家不得不签订带有霸王条款的合约，版权被拿走。"}]},"practicalAnalysis":"文段结构见批注。\n文段可看作前对策结构，先提出问题：对创新失败缺少宽容，接着用逻辑关联词“倘若……就”给出对策：对创新不能忽略过程，不能“只许成功不许失败。B选项是对策的同义替换，“成王”对应“只许成功”,“败寇”对应“不许失败”,完美选项，当选；\nA选项未体现问题， D选项无中生有，可简单排除； C选项虽然也是对策表述，但“客观看待”不如B选项更贴合文段对策，而且不如B选项作为标题有吸引力，排除。","notes":[{"marker":"⑫","content":"行文结构：前对策结构。\n文段先提出问题：\n对创新失败缺少宽容；\n转折后用“倘若..…就”给出对策：\n对创新不能忽略过程，不能“只许成功不许失败”;\n之后进行论证。\n最适合做这段文字标题的是：\nA. 科研人员勇于创新\nB. 创新不能够“成王败寇”\nC. 要客观看待创新中的失败\nD. 创新中的失败比成功更可贵","matchScore":0.809,"pairingMode":"content-similarity","order":11},{"marker":"⑬","content":"“客观看待”强调要客观，要根据客观实际对失败采取合适态度，可能批评、可能宽容；\n但文段表达的是“要对创新失败宽容”,不如“不能成王败寇”合适。\n成王败寇：指在争夺政权斗争中，成功了的就是合法的，称帝称王；失败了的就是非法的，被称为寇贼；含有成功者权势在手，无人敢责难，失败者却有口难辩的意思。","matchScore":0.2634,"pairingMode":"marker-and-content","order":12}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300549,3,'中心理解题','有关数据显示，移动端盗版带来的损失逐年上升，而版权难维护的问题，也已经从出版读物延伸到网络文学。这不仅因为数字内容产业本身存在侵权盗版问题，其作品本身的版权也存在不少漏洞。网络作家为了能让作品上架销售，不得不依赖特定的阅读平台，与之签订带有霸王条款的合约。很多阅读平台在与作者签约后，并不能保障有足够的资源推荐，但却将作品的几乎所有版权全部拿走。这段文字主要介绍：','[{"label":"A","content":"移动端盗版的发展趋势"},{"label":"B","content":"网络作家与阅读平台的关系"},{"label":"C","content":"网络文学版权维护艰难的原因"},{"label":"D","content":"数字内容产业版权的特殊性"}]','C','文段分析见批注。
文段为典型的果因结构，先介绍“网络文学版权维护难”这一“果”,接下来再分析原因。C选项是原因类选项，完美对应，当选；
A选项的“发展趋势”、D选项的“特殊性”无中生有，排除；B选项为区别比较联系类选项，但二者并非原文重点介绍的“双主体”,排除。

花生批注：
⑭ 行文结构：果因结构。
先提出“网络文学版权维护难”这一问题(果);
再分析这一问题产生的原因：
①数字内容产业本身存在侵权盗版问题；
②作品本身的版权也存在不少漏洞；
③网络作家不得不签订带有霸王条款的合约，版权被拿走。','2023年四川省三支一扶','基础','published','{"globalNumber":549,"setNumber":28,"localNumber":9,"sourceLabel":"2023年四川省三支一扶81%","accuracy":81,"typeAndPassage":"中心理解题+说理类文段","stemRich":[{"text":"有关数据显示，移动端盗版带来的损失逐年上升，而版权难维护的问题，也已经从出版读物延伸到网络文学。这不仅因为数字内容产业本身存在侵权盗版问题，其作品本身的版权也存在不少漏洞。网络作家为了能让作品上架销售，不得不依赖特定的阅读平台，与之签订带有霸王条款的合约。很多阅读平台在与作者签约后，并不能保障有足够的资源推荐，但却将作品的几乎所有版权全部拿走。这段文字主要介绍："}],"optionRich":{"A":[{"text":"移动端盗版的发展趋势"}],"B":[{"text":"网络作家与阅读平台的关系"}],"C":[{"text":"网络文学版权维护艰难的原因"}],"D":[{"text":"数字内容产业版权的特殊性"}]},"annotatedStemRich":[{"text":"有关数据显示，移动端盗版带来的损失逐年上升，而版权难维护的问题，也已经从出版读物延伸到网络文学(果 ) 。这不仅因为数字内容产业本身存在侵权盗版问题，其作品本身的版权也存在不少漏洞。网络作家为了能让作品上架销售，不得不依赖特定的阅读平台，与之签订带有霸王条款的合约。很多阅读平台在与作者签约后，并不能保障有足够的资源推荐，但却将作品的几乎所\n有版权全部拿走(因)。⑩\n这段文字主要介绍："}],"annotatedOptionRich":{"A":[{"text":"移动端盗版的发展趋势(无中生有)"}],"B":[{"text":"网络作家与阅读平台的关系(区别比较联系类)"}],"C":[{"text":"网络文学版权维护艰难的原因"}],"D":[{"text":"数字内容产业版权的特殊性(无中生有)\n"},{"text":"S四IHA海IGO公NGK考AO 练习题28套","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段为典型的果因结构，先介绍“网络文学版权维护难”这一“果”,接下来再分析原因。C选项是原因类选项，完美对应，当选；\nA选项的“发展趋势”、D选项的“特殊性”无中生有，排除；B选项为区别比较联系类选项，但二者并非原文重点介绍的“双主体”,排除。","notes":[{"marker":"⑭","content":"行文结构：果因结构。\n先提出“网络文学版权维护难”这一问题(果);\n再分析这一问题产生的原因：\n①数字内容产业本身存在侵权盗版问题；\n②作品本身的版权也存在不少漏洞；\n③网络作家不得不签订带有霸王条款的合约，版权被拿走。","matchScore":0.9503,"pairingMode":"content-similarity","order":13}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300550,3,'中心理解题','中华传统民俗文化既是社会意识形态之一，又是一种历史悠久的文化遗产，不仅丰富人们的生活，更能增强中华民族共同体意识。传统乡规民约自发于民间，具有乡土性和区域性，紧紧围绕着乡土社会人们的生产和生活事务、人情往来、婚丧嫁娶、节日喜庆等方面，约定俗成，共同遵守。传统乡规民约虽然各具特色，但普遍包含孝敬父母、尊敬长上、和睦乡里、各安其生、调节矛盾、整肃秩序的内容和功能，集中体现了中国传统美德观念，是中华美育精神的实践体现。对其深入挖掘，对于弘扬中华美育精神、培育祖国青年一代，具有深远的意义。
这段文字意在强调：','[{"label":"A","content":"要深入挖掘优秀传统文化之美，领悟中华美育精神的精髓"},{"label":"B","content":"传统民俗乡规文化几千年来深深地积淀在中华民族的精神意识中"},{"label":"C","content":"要深入挖掘传统器物文化之美，传承中华美育精神的艺术形式和技艺"},{"label":"D","content":"要深入挖掘传统民俗乡规文化之美，发扬光大中华美育精神的实践价值"}]','D','文段分析见批注。
文段为典型后对策结构，尾句提出对策：深入挖掘传统乡规民约，对于弘扬中华美育精神、培育祖国青年一代具有深远的意义。可理解为：应深入挖掘传统乡规民约，弘扬中华美育精神，对应D选项，当选；
A选项“传统文化”过于宽泛，未提及“传统乡规民约”,B选项为中性表达，文段有对策应选择对策，C选项“传统器物文化之美”无中生有，均可简单排除。

花生批注：
⑮ 传统乡规民约为全文论述主体。
⑯ 行文结构：后对策结构。
先引出话题：传统乡规民约；再分析介绍：传统乡规民约的重要价值；
最后提出对策：应深入挖掘传统乡规民约，弘扬中华美育精神。
片段阅读6 00
(下册)','2023年四川省三支一扶66%) 公考最新资料、更新进度微信SKA674','进阶','published','{"globalNumber":550,"setNumber":28,"localNumber":10,"sourceLabel":"2023年四川省三支一扶66%) 公考最新资料、更新进度微信SKA674","accuracy":66,"typeAndPassage":"中心理解题+说理类文段","stemRich":[{"text":"中华传统民俗文化既是社会意识形态之一，又是一种历史悠久的文化遗产，不仅丰富人们的生活，更能增强中华民族共同体意识。传统乡规民约自发于民间，具有乡土性和区域性，紧紧围绕着乡土社会人们的生产和生活事务、人情往来、婚丧嫁娶、节日喜庆等方面，约定俗成，共同遵守。传统乡规民约虽然各具特色，但普遍包含孝敬父母、尊敬长上、和睦乡里、各安其生、调节矛盾、整肃秩序的内容和功能，集中体现了中国传统美德观念，是中华美育精神的实践体现。对其深入挖掘，对于弘扬中华美育精神、培育祖国青年一代，具有深远的意义。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"要深入挖掘优秀传统文化之美，领悟中华美育精神的精髓"}],"B":[{"text":"传统民俗乡规文化几千年来深深地积淀在中华民族的精神意识中"}],"C":[{"text":"要深入挖掘传统器物文化之美，传承中华美育精神的艺术形式和技艺"}],"D":[{"text":"要深入挖掘传统民俗乡规文化之美，发扬光大中华美育精神的实践价值"}]},"annotatedStemRich":[{"text":"中华传统民俗文化既是社会意识形态之一，又是一种历史悠久的文化遗产，不仅丰富人们的生活，更能增强中华民族共同体意识。"},{"text":"传统乡规民约","underline":true},{"text":"⑤自发于民间，具有乡土性和区域性，紧紧围绕着乡土社会人们的生产和生活事务、人情往来、婚丧嫁娶、节日喜庆等方面，约定俗成，共同遵守(引出话题)。传统乡规民约虽然各具特色，但普遍包含孝敬父母、尊敬长上、和睦乡里、各安其生、调节矛盾、整肃秩序的内容和功能，集中体现了中国传统美德观念，是中华美育精神的实践体现(分析介绍)。对其深入挖掘，对于弘扬中华美育精神、培育祖国青年一代，具有深远的意义(后对策)。⑩\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"要深入挖掘优秀传统文化之美，领悟中华美育精神的精髓(宽泛)"}],"B":[{"text":"传统民俗乡规文化几千年来深深地积淀在中华民族的精神意识中 (中性表达)"}],"C":[{"text":"要深入挖掘传统器物文化之美，传承中华美育精神的艺术形式和技艺 (无中生有)"}],"D":[{"text":"要深入挖掘传统民俗乡规文化之美，发扬光大中华美育精神的实践价值"}]},"practicalAnalysis":"文段分析见批注。\n文段为典型后对策结构，尾句提出对策：深入挖掘传统乡规民约，对于弘扬中华美育精神、培育祖国青年一代具有深远的意义。可理解为：应深入挖掘传统乡规民约，弘扬中华美育精神，对应D选项，当选；\nA选项“传统文化”过于宽泛，未提及“传统乡规民约”,B选项为中性表达，文段有对策应选择对策，C选项“传统器物文化之美”无中生有，均可简单排除。","notes":[{"marker":"⑮","content":"传统乡规民约为全文论述主体。","matchScore":0.4451,"pairingMode":"content-similarity","order":14},{"marker":"⑯","content":"行文结构：后对策结构。\n先引出话题：传统乡规民约；再分析介绍：传统乡规民约的重要价值；\n最后提出对策：应深入挖掘传统乡规民约，弘扬中华美育精神。\n片段阅读6 00\n(下册)","matchScore":0.6831,"pairingMode":"content-similarity","order":15}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300551,3,'语句排序类','① H7N9 禽流感病毒在人与人之间不能持续有效传播，通过消化道传播的可能性更低
②一种病毒只能寄生在一种(类)动物、植物或细菌真菌中，即具有特异性
③病毒是高度专性寄生的非细胞型生物，必须在活细胞内寄生并以复制方式增殖，分为植物病毒、动物病毒和细菌病毒
④人感染H7N9 禽流感病毒主要是经呼吸道传播，也可通过密切接触感染的禽类分泌物、排泄物或直接接触病毒感染
⑤也就是说，不会有哪种病毒可以同时感染动物和植物，因此禽流感病毒不会感染西瓜、香蕉、青菜等
⑥目前没有见到人因为食用西瓜等水果而感染H7N9 禽流感病毒的实例，也未发现该病毒具有在人群中持续传播的能力
将以上6个句子重新排列，语序正确的是：','[{"label":"A","content":"③②⑤④①⑥"},{"label":"B","content":"④⑥⑤③①②"},{"label":"C","content":"①④( ⑥(②⑤③"},{"label":"D","content":"②⑤⑥④③①"}]','A','观察首句，③句介绍什么是病毒及其种类，①和④的话题是 H7N9 禽流感病毒，②句介绍病毒的特异性，应先介绍什么是病毒，再介绍其特异性及具体介绍H7N9病毒，①锁定A选项；
验证A选项：③②⑤介绍病毒的定义、种类和特异性，①④⑥具体介绍某一种病毒( H7N9 禽流感病毒),先介绍大概念再介绍其中某一具体概念，逻辑正确，当选。

花生批注：
⑪ 病毒是个大概念，H7N9 病毒属于病毒的一种，应该先介绍大概念，再介绍其中具体的事项。
⑱ 行文结构：后对策结构。
开篇引出话题：科学家正在培养“大脑类器官”;
再提出问题：这类研究可能引发伦理问题；
最后给出对策：人类脑实验研究现在必须制定伦理框架。
① H7N9 禽流感病毒在人与人之间不能持续有效传播，通过消化道传播的可能性更低
②一种病毒只能寄生在一种(类)动物、植物或细菌真菌中，即具有特异性
③病毒是高度专性寄生的非细胞型生物，必须在活细胞内寄生并以复制方式增殖，分为植物病毒、动物病毒和细菌病毒
④人感染H7N9禽流感病毒主要是经呼吸道传播，也可通过密切接触感染的禽类分泌物、排泄物或直接接触病毒感染
⑤也就是说，不会有哪种病毒可以同时感染动物和植物，因此禽流感病毒不会感染西瓜、香蕉、青菜等
⑥目前没有见到人因为食用西瓜等水果而感染H7N9 禽流感病毒的实例，也未发现该病毒具有在人群中持续传播的能力
将以上6个句子重新排列，语序正确的是：
A.③②⑤④①⑥ B.④⑥⑤③①②
