INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300552,3,'中心理解题','为了在培育人体器官的道路上向前迈进，同时也为了研究帕金森病和精神分裂症等脑疾病，科研人员正在利用干细胞培养小型简化版人脑组织——大脑类器官。人类大脑高度发达且结构复杂，但长期以来我们对它知之甚少，因此这些研究可能具有无穷的价值。不过，有学者认为：“大脑类器官离功能性人脑越近，伦理问题就越严重。”科学家们总结称，人类脑实验模型或有助于解开精神疾病和神经疾病的谜题。但他们强调，为了确保这类研究可以在长期范围内取得成功，并为社会所接受，现在必须制定伦理框架。
这段文字意在说明：','[{"label":"A","content":"培育人体器官切不可急功近利"},{"label":"B","content":"体外培养人脑组织需作伦理考量"},{"label":"C","content":"对人类大脑的研究具有重要的价值"},{"label":"D","content":"人体干细胞研究应考虑社会的接受度"}]','B','文段分析见批注。
文段为典型的后对策结构，对策为“人类脑实验研究必须制定伦理框架”。 B选项为原文对策同义替换，当选；
A选项未提及“人脑”,C选项、D选项未提及对策重点“制定伦理框架”, 均可简单排除。','2019年四川省三支一扶','基础','published','{"globalNumber":552,"setNumber":28,"localNumber":12,"sourceLabel":"2019年四川省三支一扶74%","accuracy":74,"typeAndPassage":"中心理解题+说理类文段","stemRich":[{"text":"为了在培育人体器官的道路上向前迈进，同时也为了研究帕金森病和精神分裂症等脑疾病，科研人员正在利用干细胞培养小型简化版人脑组织——大脑类器官。人类大脑高度发达且结构复杂，但长期以来我们对它知之甚少，因此这些研究可能具有无穷的价值。不过，有学者认为：“大脑类器官离功能性人脑越近，伦理问题就越严重。”科学家们总结称，人类脑实验模型或有助于解开精神疾病和神经疾病的谜题。但他们强调，为了确保这类研究可以在长期范围内取得成功，并为社会所接受，现在必须制定伦理框架。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"培育人体器官切不可急功近利"}],"B":[{"text":"体外培养人脑组织需作伦理考量"}],"C":[{"text":"对人类大脑的研究具有重要的价值"}],"D":[{"text":"人体干细胞研究应考虑社会的接受度"}]},"annotatedStemRich":[{"text":"为了在培育人体器官的道路上向前迈进，同时也为了研究帕金森病和精神分裂症等脑疾病，科研人员正在利用干细胞培养小型简化版人脑组织——大脑类器官( 引出话题)。人类大脑高度发达且结构复杂，但长期以来我们对它知之甚少，因此这些研究可能具有无穷的价值。不过，有学者认为：“大脑类器官离功能性人脑越近，伦理问题就越严重(提出问题)。”科学家们总结称，人类脑实验模型或有助于解开精神疾病和神经疾病的谜题。但他们强调，为了确保这类研究可以在长期范围内取得成功，并为社会所接受，现在必须制定伦理框架"},{"text":"(后对策)。⑩","bold":true},{"text":"\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"培育人体器官切不可急功近利(缺主体)"}],"B":[{"text":"体外培养人脑组织需作伦理考量"}],"C":[{"text":"对人类大脑的研究具有重要的价值(非对策表述)"}],"D":[{"text":"人体干细胞研究应考虑社会的接受度(对策有误)"}]},"practicalAnalysis":"文段分析见批注。\n文段为典型的后对策结构，对策为“人类脑实验研究必须制定伦理框架”。 B选项为原文对策同义替换，当选；\nA选项未提及“人脑”,C选项、D选项未提及对策重点“制定伦理框架”, 均可简单排除。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300553,3,'细节判断类','一般来说，高速公路扩容改造方案主要有两种：一种是改扩建，即通过对既有高速公路进行拼宽或分离增建车道，提高通行能力；另一种是在既有高速公路通道内另建新线。在无特殊条件制约情况下，扩容改造项目应优先利用既有高速公路改扩建。因为既有高速公路一般占据了通道内较为理想的线位，周边相关路网及配套产业设施已基本形成，另建新线，往往难以取代既有公路承担的交通功能，若选择新线，工程、征拆、投资等规模都较大。
关于优先利用既有高速公路改扩建的理由，文段未涉及的是：','[{"label":"A","content":"工程造价征拆投资等投入相对较低"},{"label":"B","content":"既有高速公路线的线位已充分论证"},{"label":"C","content":"可以大大减少设计周期以缩短工期"},{"label":"D","content":"与现有路网和经济带的适应性最佳"}]','C','文段尾句介绍了优先利用既有高速公路改扩建的理由，和选项一一对应即可。
A选项对应“另建新线，工程、征拆、投资等规模都较大”,B选项对应“既有高速公路一般占据了通道内较为理想的线位”,D选项对应“周边相关路网及配套产业设施已基本形成”, ⑨均有所涉及；
C选项的“减少设计周期以缩短周期”并未提及，当选。

花生批注：
⑲ 有同学可能会认为“最佳”有绝对化之嫌，但文段是两种选择的比较，相对较好的一种选择即可称为“最佳”。
