INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300554,3,'语句排序类','①而网络提速降费将有利于进一步提高网络、信息的可及性，缩小不同人群之间的数字鸿沟
②数字鸿沟，指的是在信息时代，拥有电脑、网络等信息工具与没有的人之间，在信息可及性上存在明显的差距，犹如一条鸿沟横亘在他们之间
③换句话说，在信息技术可及性问题变得不那么凸显后，信息技术使用目的和方式的人群差异成为了新的数字鸿沟，即所谓的“数字鸿沟2.0”
④随着电脑价格的大幅下降，特别是智能手机、宽带网络的普及，信息技术、互联网的可及性已大幅提高
⑤近年来，随着信息技术快速发展和广泛应用，网络成为人们工作和生活的基础性工具，人们可以通过它获得知识、提高工作效率，也可以沉迷于网络游戏当中
⑥虽然目前“数字鸿沟2.0”定义还没有统一，但很多研究者都在努力识别不同社会群体在信息技术使用中产生的显著差异，并试图搞清楚它们的形成机制
将以上6个句子重新排序，语序正确的是：','[{"label":"A","content":"④①②③⑥⑤"},{"label":"B","content":"②④①⑤③⑥"},{"label":"C","content":"⑤④②③⑥①"},{"label":"D","content":"⑥②①⑤④③"}]','B','观察各语句可发现，①②③⑥提及数字鸿沟。其中， ②句是介绍数字鸿沟是什么②,①句介绍的是数字鸿沟的变化，③引出“数字鸿沟2.0”, ⑥句介绍并分析数字鸿沟2.0。根据逻辑，这四句的顺序应是②①③ ⑥,只有 B选项符合，当选。

花生批注：
20 行文逻辑如下：
②句下定义引出数字鸿沟 (信息可及性带来的数字鸿沟 ) ;
