INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300558,3,'语句填入题','“。”英雄的智慧来自人民，英雄的胆略也来自人民。在与困难作斗争的物质角力和精神对垒中，人民英雄的英雄力量、英雄行动和英雄精神，充分展现了生命至上举国同心、舍生忘死、尊重科学、命运与共的伟大抗疫精神，再次证明了中国共产党无比坚强的领导力、中国人民不屈不挠的意志力、中国特色社会主义制度的显著优势、新中国成立以来的坚实国力、社会主义核心价值观和中华优秀传统文化的强大精神动力、构建人类命运共同体的广泛感召力。在这个已经诞生
并将继续诞生英雄的时代，人民的英雄和英雄的人民必将在新时代的新征程上创造新的历史伟业! 填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"聪明秀出，谓之英；胆力过人，谓之雄"},{"label":"B","content":"时势造英雄，英雄亦造时势"},{"label":"C","content":"英雄不伏蛮夷死，更筑高台望故乡"},{"label":"D","content":"出师未捷身先死，长使英雄泪满襟"}]','A','文段分析见批注。
文段主要介绍人民英雄和英雄人民，依次分析选项即可：
B选项谈论英雄和时势的关系⑧,但文段并未提及“时势”,排除；

