INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300559,3,'中心理解类','土司制度是元明清三朝推行的一种地方行政管理制度，体现了中央王朝对边疆民族地区的治理。它是秦汉以来历代中央王朝经营边疆、开发边疆、治理边疆的一个重要发展阶段，有其产生、发展的历史原因。它也是边疆少数民族地区从“化外”到内属的一个重要发展阶段，体现了边疆地区与内地一体化的进程。土司制度中有着突出的、明显的“因俗而治”的思想，这在历代治边思想中也是一脉相承的。因此，研究土司制度必须紧扣历代中央王朝对边疆的治理模式，这样才能看出土司制度在西南边疆形成与巩固中的历史作用及其价值。
对这段文字的主旨概括最准确的是：','[{"label":"A","content":"土司制度的产生发展有其历史背景"},{"label":"B","content":"我国历代的治边思想是一脉相承的"},{"label":"C","content":"对土司制度的研究应有历史大视野"},{"label":"D","content":"土司制度具有稳定西南边疆的作用"}]','C','文段分析见批注。
文段为后对策结构，尾句对策可翻译为“研究土司制度必须紧扣历代的边疆治理模式”,C选项为原文观点的同义替换，当选；
其他选项均非对策表述，而且A选项、B选项出处有误，D选项的“稳定西南边疆”无中生有，均可简单排除。

花生批注：
③2 “土司制度”是全文论述主题。
33 行文结构：后对策结构。
开篇引出话题：“土司制度”; 之后分析介绍：
土司制度代表的发展阶段、包含的思想等；
最后通过“必须”给出对策：研究土司制度必须紧扣历代中央王朝对边疆的治理模式。
③④ 历史大视野，即不能仅拘泥于一个朝代或只研究土司制度本身，而是要紧扣历代边疆治理模式，来研究土司制度的历史作用和价值。','2021年安徽省三支一扶','进阶','published','{"globalNumber":559,"setNumber":28,"localNumber":19,"sourceLabel":"2021年安徽省三支一扶62%","accuracy":62,"typeAndPassage":"中心理解类+说理类文段","stemRich":[{"text":"土司制度是元明清三朝推行的一种地方行政管理制度，体现了中央王朝对边疆民族地区的治理。它是秦汉以来历代中央王朝经营边疆、开发边疆、治理边疆的一个重要发展阶段，有其产生、发展的历史原因。它也是边疆少数民族地区从“化外”到内属的一个重要发展阶段，体现了边疆地区与内地一体化的进程。土司制度中有着突出的、明显的“因俗而治”的思想，这在历代治边思想中也是一脉相承的。因此，研究土司制度必须紧扣历代中央王朝对边疆的治理模式，这样才能看出土司制度在西南边疆形成与巩固中的历史作用及其价值。\n对这段文字的主旨概括最准确的是："}],"optionRich":{"A":[{"text":"土司制度的产生发展有其历史背景"}],"B":[{"text":"我国历代的治边思想是一脉相承的"}],"C":[{"text":"对土司制度的研究应有历史大视野"}],"D":[{"text":"土司制度具有稳定西南边疆的作用"}]},"annotatedStemRich":[{"text":"土司制度","underline":true},{"text":"是元明清三朝推行的一种地方行政管理制度，体现了中央王朝对边疆民族地区的治理"},{"text":"(引出话题)。","bold":true},{"text":"它是秦汉以来历代中央王朝经营边疆、开发边疆、治理边疆的一个重要发展阶段，有其产生、发展的历史原因。它也是边疆少数民族地区从“化外”到内属的一个重要发展阶段，体现了边疆地区与内地一体化的进程。土司制度中有着突出的、明显的“因俗而治”的思想，这在历代治边思想中也是一脉相承的(分析介绍)。因此，研究土司制度必须紧扣历代中央王朝对边疆的治理模式，这样才能看出土司制度在西南边疆形成与巩固中的历史作用及其价值(后对策)。④\n对这段文字的主旨概括最准确的是："}],"annotatedOptionRich":{"A":[{"text":"土司制度的产生发展有其历史背景(非对策表述)"}],"B":[{"text":"我国历代的治边思想是一脉相承的(非对策表述)"}],"C":[{"text":"对土司制度的研究应有历史大视野"}],"D":[{"text":"土司制度具有稳定西南边疆的作用(无中生有)"}]},"practicalAnalysis":"文段分析见批注。\n文段为后对策结构，尾句对策可翻译为“研究土司制度必须紧扣历代的边疆治理模式”,C选项为原文观点的同义替换，当选；\n其他选项均非对策表述，而且A选项、B选项出处有误，D选项的“稳定西南边疆”无中生有，均可简单排除。","notes":[{"marker":"③2","content":"“土司制度”是全文论述主题。","matchScore":0.4268,"pairingMode":"content-similarity","order":31},{"marker":"33","content":"行文结构：后对策结构。\n开篇引出话题：“土司制度”; 之后分析介绍：\n土司制度代表的发展阶段、包含的思想等；\n最后通过“必须”给出对策：研究土司制度必须紧扣历代中央王朝对边疆的治理模式。","matchScore":0.6906,"pairingMode":"content-similarity","order":32},{"marker":"③④","content":"历史大视野，即不能仅拘泥于一个朝代或只研究土司制度本身，而是要紧扣历代边疆治理模式，来研究土司制度的历史作用和价值。","matchScore":0.5136,"pairingMode":"content-similarity","order":33}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300560,3,'中心理解题','汉服不是静态的出土文物，而是活态的社会习俗。如果说传统汉服是汉民族的服饰，新时代汉服则是以传统汉服为基本规范，吸收其他民族服饰元素，适合当代人着装需要，承载中华民族共同体的文化基因、象征整个中华民族共同符号的服饰。当前，汉服穿戴还属于在特定文化空间展示艺术美的范畴。要加强汉服研究阐释工作，着力构建有中国底蕴、中国特色的汉服理论体系和话语体系，将汉服作为礼服向国家、社会、人生仪式，以及文化、教育、科技等方面推广，最后推向人民群众的日常生活起居。这段文字意在说明：','[{"label":"A","content":"当前应加强汉服理论研究和推广"},{"label":"B","content":"新时代汉服设计应体现时代精神"},{"label":"C","content":"汉服是体现中国传统文化的典型符号"},{"label":"D","content":"汉服理论研究要形成自己的话语体系"}]','A','文段分析见批注。
文段为后对策结构，对策可概括为：要加强汉服研究以构建汉服理论体系和话语体系，并将汉服作为礼服进行推广。A选项可看做“A 且B 类”选项，“加强汉服理论研究”对应“要加强汉服研究阐释工作，着力构建有中国底蕴、中国特色的汉服理论体系和话语体系”,“加强汉服推广”对应“将汉服作为礼服向国家、社会、人生仪式，以及文化、教育、科技等方面推广，最后推向人民群众的日常生活起居”,完美选项，当选。
其他选项：B选项的“应体现时代精神”无中生有； C选项非对策表述； D选项主语错误并且片面，均可简单排除。
