INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300572,3,'语句填入类','激发科学兴趣应从娃娃抓起，科学的种子茁壮成长，离不开悉心呵护，持续培养，。目前，我国在中小学已经开设了科学课程，但能够承担科学课程教育的专业老师相对不足，一方面，需要通过加强科学教师培训等方式，提升科学教育整体水平；另一方面，还可以借助各类科技馆资源，开展馆校合作，推出公益科学课等，在教育“双减”中做好科学教育加法。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"然而拥有科学常识和科学思维能力至关重要"},{"label":"B","content":"提升公民科学素质，引导多方力量共同参与"},{"label":"C","content":"提升科普能力，满足人们多元化的科普需求"},{"label":"D","content":"因此，有必要推动科普与学校教育深度融合"}]','D','文段分析见批注。
所填入语句在文段中间，前文讲“科学”,后文讲“学校中的科普”。只有D选项包含二者，若填入D选项，可将所填入语句看作“前对策”,且D选项既承上又启下，下文对策体现了“科普与学校的合作”,当选；
A选项，文段前后均未谈论“科学常识和科学思维”,且该选项内容无法与上文形成转折，排除；
B选项的“多方力量共同参与”、C选项的“提升科普能力”,下文均未提及，且无法与下文的“学校中的科普”形成对应，排除。

