INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300573,3,'中心理解题','有许多长寿的人，你问他们常吃什么食品，他们回答说：“什么都吃，并无特殊的禁忌。”但有许多东西他们只尝一口，就敏锐地判断出成色。读书也是一样，好的书，是人参燕窝熊掌，人生若不大快朵颐，岂不白在世上潇洒走过一回?坏的书，是腐肉砒霜氰化物，浪费了时间贻误了性命。名著一般多是经过了许多年代的考验，是被大师们的智慧研磨了无数遭的精品。读的时候，像烈火烹油的满汉全席，为大享乐。
这段文字旨在说明：','[{"label":"A","content":"读书要有所选择"},{"label":"B","content":"名著如美食般余味无穷"},{"label":"C","content":"物质和精神食粮同样重要"},{"label":"D","content":"鉴别书籍比鉴别美食更困难\nS四IHA海IGO公NGK考AO 练习题29套"}]','A','文段分析见批注。
文段观点句可翻译为“读书要和吃饭一样，有所判断和选择”,A选项为原文观点句的对策表述，当选；
B选项出自分析论证部分，“名著如美食”用于论证前文观点“书有好有坏”,非文段重点，排除； C选项、D选项同质，均为区别比较联系类，但原文只是用鉴别美食引出读书，而非将二者对比，排除。

花生批注：
② 行文结构：前观点结构。
对比引出观点：
长寿的人可以对美食有所判断，读书也是一样；
后面进行论证：
好的书是人参燕窝熊掌，应该“大快朵颐”;
坏的书是腐肉砒霜氰化物，浪费时间贻误性命；
名著如满汉全席，读起来为大享乐。
