INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300577,3,'中心理解题','牛顿提出了著名的运动定律，为我们理解太阳系，乃至一切物体质量与施加于其上的力之间的关系奠定了基础。在用这些定律描述行星绕太阳如何运动后，牛顿又开始思索：如果有第三个天体(如月球)闯入其间会发生什么呢?当两个(或三个大小和距离差别很大的物体)绕一个中心点旋转时，用牛顿运动定律很容易计算出它们的运动轨道。但如果这三个物体的大小和与中心点的距离均相当，则整个系统将陷入混沌。而一旦混沌发生，就不可能用常规数学方法研究物体的运动，困扰科学家数百年的“三体问题”也由此浮出水面。
这段文字主要讲的是：','[{"label":"A","content":"“三体问题”带来的影响"},{"label":"B","content":"“三体问题”产生的原因"},{"label":"C","content":"牛顿运动定律自身的局限性"},{"label":"D","content":"科学界对“三体问题”的探索"}]','B','文段可看做因果结构。先介绍牛顿的一系列思考，再由此引出“三体问题”。即文段重点介绍的是“三体问题”产生的原因，对应B选项，当选。
A选项“三体问题”带来的影响，无中生有，C选项出自文段分析论证部分，非重点，D选项为具体类选项，文段并未具体说明科学界所做的探索，均可简单排除。
IG

花生批注：
③0 文段分析论证部分阐述三个物体的大小和与中心点的距离均相当的天体闯入运动轨道后，整个系统将陷入混沌，从而引发三体问题，而非论述“三体问题”带来的影响。','2022年天津市考','基础','published','{"globalNumber":577,"setNumber":29,"localNumber":17,"sourceLabel":"2022年天津市考 74%","accuracy":74,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"牛顿提出了著名的运动定律，为我们理解太阳系，乃至一切物体质量与施加于其上的力之间的关系奠定了基础。在用这些定律描述行星绕太阳如何运动后，牛顿又开始思索：如果有第三个天体(如月球)闯入其间会发生什么呢?当两个(或三个大小和距离差别很大的物体)绕一个中心点旋转时，用牛顿运动定律很容易计算出它们的运动轨道。但如果这三个物体的大小和与中心点的距离均相当，则整个系统将陷入混沌。而一旦混沌发生，就不可能用常规数学方法研究物体的运动，困扰科学家数百年的“三体问题”也由此浮出水面。\n这段文字主要讲的是："}],"optionRich":{"A":[{"text":"“三体问题”带来的影响"}],"B":[{"text":"“三体问题”产生的原因"}],"C":[{"text":"牛顿运动定律自身的局限性"}],"D":[{"text":"科学界对“三体问题”的探索"}]},"annotatedStemRich":[{"text":"牛顿提出了著名的运动定律，为我们理解太阳系，乃至一切物体质量与施加于其上的力之间的关系奠定了基础。在用这些定律描述行星绕太阳如何运动后，牛顿又开始思索：如果有第三个天体(如月球)闯入其间会发生什么呢?当两个(或三个大小和距离差别很大的物体)绕一个中心点旋转时，用牛顿运动定律很容易计算出它们的运动轨道。但如果这三个物体的大小和与中心点的距离均相当，则整个系统将陷入混沌。而一旦混沌发生，就不可能用常规数学方法研究物体的运动 ( 因 ) ,困扰科学家数百年的“三体问题”也由此浮出水面( 果 ) 。\n这段文字主要讲的是："}],"annotatedOptionRich":{"A":[{"text":"“三体问题”带来的影响(无中生有)"}],"B":[{"text":"“三体问题”产生的原因"}],"C":[{"text":"牛顿运动定律自身的局限性(出处有误)"}],"D":[{"text":"科学界对“三体问题”的探索(具体类选项)"}]},"practicalAnalysis":"文段可看做因果结构。先介绍牛顿的一系列思考，再由此引出“三体问题”。即文段重点介绍的是“三体问题”产生的原因，对应B选项，当选。\nA选项“三体问题”带来的影响，无中生有，C选项出自文段分析论证部分，非重点，D选项为具体类选项，文段并未具体说明科学界所做的探索，均可简单排除。\nIG","notes":[{"marker":"③0","content":"文段分析论证部分阐述三个物体的大小和与中心点的距离均相当的天体闯入运动轨道后，整个系统将陷入混沌，从而引发三体问题，而非论述“三体问题”带来的影响。","matchScore":0.8468,"pairingMode":"content-similarity","order":29}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300578,3,'标题拟定类','匾额悬挂于门屏上作为装饰，可以表示建筑物的名称和性质，同时表达人们的义理和情感。匾额习俗的形成源于古人对门的重视。在古代，门被称为“衡门”,是一种领地的标识，我国一些少数民族至今仍保留着在衡门上放置猎物作为其领地的风俗。我国第二个奴隶制王朝国号为商，“商”字的甲骨文写法极像衡门之上放置的鸟牲。周文王建台礼天，榜名“灵台”,可以说是我国历史上匾额的雏形。
这段文字最适合的标题是：','[{"label":"A","content":"匾额与衡门"},{"label":"B","content":"匾额的早期形态"},{"label":"C","content":"匾额的文化意义"},{"label":"D","content":"匾额的起源"}]','D','文段首句引出匾额并介绍其作用，②句指出匾额起源于古人对门的重视，③④句具体介绍“古人对门的重视”,尾句介绍我国最早的匾额(也和匾额起源有关)。首句引出匾额后，后四句均为对匾额习俗起源的相关介绍。
A选项为区别比较联系类，但“衡门”并非双主体之一，只是匾额的起源和“衡门”有关，文段讨论主体为“匾额”,排除；
B选项的“早期形态”和C选项的“文化意义”无中生有，且二者均属具体类选项，但文段无具体介绍，排除；
D选项，匾额起源对应原文后四句话，为文段重点介绍内容，当选。','2019年江苏省事业单位','进阶','published','{"globalNumber":578,"setNumber":29,"localNumber":18,"sourceLabel":"2019年江苏省事业单位56%","accuracy":56,"typeAndPassage":"标题拟定类+科普介绍文章","stemRich":[{"text":"匾额悬挂于门屏上作为装饰，可以表示建筑物的名称和性质，同时表达人们的义理和情感。匾额习俗的形成源于古人对门的重视。在古代，门被称为“衡门”,是一种领地的标识，我国一些少数民族至今仍保留着在衡门上放置猎物作为其领地的风俗。我国第二个奴隶制王朝国号为商，“商”字的甲骨文写法极像衡门之上放置的鸟牲。周文王建台礼天，榜名“灵台”,可以说是我国历史上匾额的雏形。\n这段文字最适合的标题是："}],"optionRich":{"A":[{"text":"匾额与衡门"}],"B":[{"text":"匾额的早期形态"}],"C":[{"text":"匾额的文化意义"}],"D":[{"text":"匾额的起源"}]},"annotatedStemRich":[{"text":"①匾额悬挂于门屏上作为装饰，可以表示建筑物的名称和性质，同时表达人们的义理和情感(引出话题)。②匾额习俗的形成源于古人对门的重视。③ 在古代，门被称为“衡门”,是一种领地的标识，我国一些少数民族至今仍保留着在衡门上放置猎物作为其领地的风俗。④我国第二个奴隶制王朝国号为商，“商”字的甲骨文写法极像衡门之上放置的鸟牲。⑤周文王建台礼天，榜名“灵台”,可以说是我国历史上匾额的雏形"},{"text":"(介绍起源)。","bold":true},{"text":"\n这段文字最适合的标题是："}],"annotatedOptionRich":{"A":[{"text":"匾额与衡门("},{"text":"区别比较联系类)","bold":true}],"B":[{"text":"匾额的早期形态(无中生有)"}],"C":[{"text":"匾额的文化意义(无中生有)"}],"D":[{"text":"匾额的起源"}]},"practicalAnalysis":"文段首句引出匾额并介绍其作用，②句指出匾额起源于古人对门的重视，③④句具体介绍“古人对门的重视”,尾句介绍我国最早的匾额(也和匾额起源有关)。首句引出匾额后，后四句均为对匾额习俗起源的相关介绍。\nA选项为区别比较联系类，但“衡门”并非双主体之一，只是匾额的起源和“衡门”有关，文段讨论主体为“匾额”,排除；\nB选项的“早期形态”和C选项的“文化意义”无中生有，且二者均属具体类选项，但文段无具体介绍，排除；\nD选项，匾额起源对应原文后四句话，为文段重点介绍内容，当选。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300579,3,'中心理解题','当我们将文人画奉为中国传统艺术之经典、沉浸在笔墨趣味的窠臼之时，我们是否遗忘了宋代山水画家们基于对宇宙自然的敬畏，以“致广大，尽精微”的艺术虔诚，努力描绘出的“无我之境”? 范宽所画山水的稳厚气阔尽显北方山势之雄浑；郭熙将山水分为“平远、高远、深远”,强调山水四季之不同气韵皆源自对自然的深刻体会；李唐早晚期创作风格从苍劲转为温润是因其由北方迁至南方所见地貌差异而致。张彦远在公元9世纪即提出“外师造化，中得心源”的艺术主张，强调艺术创作首先来源于对大自然的师法，但更需要艺术家通过自我转化提炼后加以呈现。
这段文字意在说明：','[{"label":"A","content":"山水画应重视对自然的体会"},{"label":"B","content":"艺术创作源于对自然的师法"},{"label":"C","content":"山水画应是对大自然的描摹"},{"label":"D","content":"大自然决定了山水画的创作"}]','A','文段分析见批注。
文段观点可概括为：山水画艺术创作应来源于大自然的师法，但更需要艺术家的自我感悟。 A选项是观点的同义替换，当选；
其他选项均对应尾句转折前部分，均强调“对自然的师法” , 而未提及更重要的“艺术家通过自我转化提炼(即对自然的体会)”,均可排除。','2024年湖北省选调','基础','published','{"globalNumber":579,"setNumber":29,"localNumber":19,"sourceLabel":"2024年湖北省选调 77%","accuracy":77,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"当我们将文人画奉为中国传统艺术之经典、沉浸在笔墨趣味的窠臼之时，我们是否遗忘了宋代山水画家们基于对宇宙自然的敬畏，以“致广大，尽精微”的艺术虔诚，努力描绘出的“无我之境”? 范宽所画山水的稳厚气阔尽显北方山势之雄浑；郭熙将山水分为“平远、高远、深远”,强调山水四季之不同气韵皆源自对自然的深刻体会；李唐早晚期创作风格从苍劲转为温润是因其由北方迁至南方所见地貌差异而致。张彦远在公元9世纪即提出“外师造化，中得心源”的艺术主张，强调艺术创作首先来源于对大自然的师法，但更需要艺术家通过自我转化提炼后加以呈现。\n这段文字意在说明："}],"optionRich":{"A":[{"text":"山水画应重视对自然的体会"}],"B":[{"text":"艺术创作源于对自然的师法"}],"C":[{"text":"山水画应是对大自然的描摹"}],"D":[{"text":"大自然决定了山水画的创作"}]},"annotatedStemRich":[{"text":"当我们将文人画奉为中国传统艺术之经典、沉浸在笔墨趣味的窠臼之时，\n我们是否遗忘了宋代山水画家们基于对宇宙自然的敬畏，以“致广大，尽精微”的艺术虔诚，努力描绘出的“无我之境”(转折引出话题)?范宽所画山水的稳厚气阔尽显北方山势之雄浑；郭熙将山水分为“平远、高远、深远”,强调山水四季之不同气韵皆源自对自然的深刻体会；李唐早晚期创作风格从苍劲转为温润是因其由北方迁至南方所见地貌差异而致"},{"text":"(举例分析)。","bold":true},{"text":"张彦远在公元 9世纪即提出“外师造化，中得心源”的艺术主张，强调艺术创作首先来源于对大自然的师法，但更需要艺术家通过自我转化提炼后加以呈现(后观点)。⑨\n这段文字意在说明："}],"annotatedOptionRich":{"A":[{"text":"山水画应重视对自然的体会"}],"B":[{"text":"艺术创作源于对自然的师法(出处有误)"}],"C":[{"text":"山水画应是对大自然的描摹(出处有误)"}],"D":[{"text":"大自然决定了山水画的创作(出处有误)\n③2"},{"text":"花生批注：","bold":true},{"text":"\n师法指老师传授的学问和技术。\n"},{"text":"33花生批注：","bold":true},{"text":"\n"},{"text":"行文结构","bold":true},{"text":"：二层结构之对比；\n过去：\n介绍过去一段时间一些大城市进行汽车限购，暂缓了矛盾堆积，为政策跟进留下了时间；\n现在：\n近两年，汽车限购逐步取消，转向引导使用和支持新能源汽车购置。"}]},"practicalAnalysis":"文段分析见批注。\n文段观点可概括为：山水画艺术创作应来源于大自然的师法，但更需要艺术家的自我感悟。 A选项是观点的同义替换，当选；\n其他选项均对应尾句转折前部分，均强调“对自然的师法” , 而未提及更重要的“艺术家通过自我转化提炼(即对自然的体会)”,均可排除。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300580,3,'语句填入类','一个时期以来，全国许多地方特别是一些大城市通过摇号或竞价的方式发放车辆号牌，限制消费者进行消费，。大城市汽车保有量快速增长，容易造成严重的交通拥堵、环境污染。严格的购买管理暂缓了矛盾堆积，为政策跟进留下了时间。从产业政策看，近两年相关部委先后出台政策，提出破除乘用车消费障碍、由限制购买转向引导使用、完善新能源汽车购置支持政策等。当前我们已经有条件通过减少城市限购、加强使用管理来合理引导居民汽车消费，同时解决好交通拥堵等问题。填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"主要是考虑到道路承载力问题"},{"label":"B","content":"用以呼应相关产业政策的调整"},{"label":"C","content":"其实是一种特定阶段的特定举措"},{"label":"D","content":"不失为疏解交通拥堵的良策之一"}]','C','文段分析见批注。
文段可看做时间对比结构，先介绍过去的“限购政策”,再介绍近年的“引导使用、完善新能源汽车购置支持政策”。
所填入语句是对过去限购政策的评价，由后文的“暂缓了矛盾堆积，为政策跟进留下了时间”、“由限制购买转向引导使用、完善新能源汽车购置支持政策”可知，“汽车限购政策”只是一段特定时期的特定政策，正对应C选项，当选；
A选项的“道路承载力”下文并未提及，排除；B选项，“政策调整”是近两年顺应时代变化的改变，当时的限购政策是特定阶段的政策，并非“呼应相关产业政策的调整”,排除； D选项，“良策”不如“特定阶段的特定举措”评价准确，更能体现限购政策的阶段性，排除。
