INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300581,3,'中心理解题','在自然状态下，大气中的二氧化碳通过植物光合作用形成有机碳储存于植物体内，植物枯死后在沼泽的特殊环境下堆积形成泥炭。因此，碳被长久地固定在泥炭湿地中，使泥炭湿地成为重要的碳汇。据研究，泥炭湿地是陆地各类生态系统中单位面积碳堆积量最大、碳积累速率最快的生态系统。全球泥炭湿地面积仅占陆域面积的2.66%,但碳储量却为全球土壤碳库量的16%～17%。然而，由于排水疏干、泥炭开采、火灾等因素，泥炭湿地不断遭到破坏，千百年来储存在泥炭湿地中的碳释放到大气中，泥炭湿地也因此从碳汇转化成碳源。
这段文字主要介绍了泥炭湿地：','[{"label":"A","content":"形成碳汇的地理条件"},{"label":"B","content":"在生态系统中的特殊地位"},{"label":"C","content":"遭到破坏的自然人文因素"},{"label":"D","content":"碳储存与碳释放的发生机制"}]','D','文段分析见批注。
文段转折前介绍泥炭湿地是重要碳汇，转折后指出因泥炭湿地被破坏，其从碳汇变成将碳释放到大气的碳源。
观察选项，D选项为典型的“A 且B 类”选项，“碳存储发生机制”对应转折前，“碳释放发生机制”对应转折后，完美选项，当选；
A选项只谈及“碳存储”、 C选项只谈及“碳释放”,均片面，排除； B选项的“特殊地位”无中生有，排除。
片段阅读6 00 四(下册)

