INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300590,3,'语句排序类','①清醒前释放高水平的糖皮质激素，会促使人体将脂肪酸和糖转化为能量。
②如果昼夜节律紊乱，例如由于轮班工作或时差原因，会引起糖皮质激素水平的改变，可能会发生严重的代谢异常。
③在一个健康的系统中，肾上腺每天早晨都会产生糖皮质激素。
④人体中的每个细胞都由内部生物钟驱动。
⑤该生物钟遵循24小时的昼夜节律，与白天和黑夜的自然周期同步运行，主要受阳光控制，也受社交习惯控制。
