INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300591,3,'语句填入类','现在主流计算机实质上是二维的，它们的芯片需要在超净室中生产，因为任何微小缺陷都是致命的，芯片一旦损坏，无法修复。人脑则完全不同，它们是三维的，是在杂乱而控制松散的环境下生长的，可以容忍缺陷或损伤。 ,新型计算机不但能够媲美现代半导体技术的集成密度、速度和规模，而且具有人脑的上述优点。没有明显的障碍阻止我们做到这点，强大的三维、容错、自修复计算机将会出现。在实现这些功能的过程中，我们也将获得许多与脑神经科学有关的知识。
填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"人类的感知能力其实有着极大的发展空间"},{"label":"B","content":"未来的计算机设计将借鉴生物世界的概念"},{"label":"C","content":"我们有理由和动力去发展新一代计算机技术"},{"label":"D","content":"模拟人脑的人工智能将带来翻天覆地的变化"}]','C','文段分析见批注。
所填入语句在文段中间，且前文指出“现今主流计算机的不足”,下文指出“新型计算机的优点”,可猜测所填入语句可能为前对策。下文论证重点为“新型计算机”,则对策应提及“新型计算机的研发”,锁定C选项。“有理由和动力”对应问题“现今主流计算机不足”,“发展新一代计算机技术”对应后文论证(新型计算机的优势和作用);而且符合“现今主流计算机不行，所以要开发新型计算机”的逻辑，完美选项，当选；
A选项未提及“新型计算机”,排除； B选项的“借鉴生物世界概念”无中生有，下文并未展开论证，排除；D选项的“模拟人脑的人工智能”不等于“新型计算机”,排除。

花生批注：
