INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300592,3,'语句填入类','黑土地是肥力最高、最适宜农耕和最具生产潜力的土壤，被誉为“地中的大熊猫”。我国东北地区作为北半球仅有的三大黑土区之一，是我国重要的粮食生产优势区、最大的商品粮生产基地。。近年来，由于长期高强度开发利用、地下水超采严重等原因，我国黑土区耕地出现退化，肥沃的黑土变得越来越“瘦”、越来越“薄”、越来越“硬”,打赢黑土地“保卫战”势在必行。填入文中画横线部分最恰当的一项是：','[{"label":"A","content":"确保黑土地不减少，是保障粮食生产和粮食安全的必然要求"},{"label":"B","content":"加强东北黑土地保护是促进农业可持续发展的基础支撑作用"},{"label":"C","content":"然而，维护国家粮食安全需加强东北黑土地保护和地力恢复"},{"label":"D","content":"但是，黑土高产丰产的同时，也面临着土地肥力透支的问题"}]','D','文段分析见批注。
文段可看做并列结构，先介绍我国黑土地的肥沃，再指出近年肥力下降的问题；
所填入语句在并列结构的文段中间，可能起到承上启下作用，正对应D选项，D选项的“黑土高产丰产”对应上文，“面临土地肥力透支的问题”引起下文，前后文形成转折关系，当选；
其他选项均与后文无法对应，可简单排除。

花生批注：
⑲ 行文结构：并列结构。
文段前半段：
介绍我国东北地区黑土地的肥沃；
文段后半段：
介绍我国黑土地出现退化，变瘦变薄，需要“保卫”。','2022年重庆市事业单位','基础','published','{"globalNumber":592,"setNumber":30,"localNumber":12,"sourceLabel":"2022年重庆市事业单位77%","accuracy":77,"typeAndPassage":"语句填入类+科普介绍文章","stemRich":[{"text":"黑土地是肥力最高、最适宜农耕和最具生产潜力的土壤，被誉为“地中的大熊猫”。我国东北地区作为北半球仅有的三大黑土区之一，是我国重要的粮食生产优势区、最大的商品粮生产基地。 "},{"text":" ","underline":true},{"text":"。近年来，由于长期高强度开发利用、地下水超采严重等原因，我国黑土区耕地出现退化，肥沃的黑土变得越来越“瘦”、越来越“薄”、越来越“硬”,打赢黑土地“保卫战”势在必行。填入文中画横线部分最恰当的一项是："}],"optionRich":{"A":[{"text":"确保黑土地不减少，是保障粮食生产和粮食安全的必然要求"}],"B":[{"text":"加强东北黑土地保护是促进农业可持续发展的基础支撑作用"}],"C":[{"text":"然而，维护国家粮食安全需加强东北黑土地保护和地力恢复"}],"D":[{"text":"但是，黑土高产丰产的同时，也面临着土地肥力透支的问题"}]},"annotatedStemRich":[{"text":"黑土地是肥力最高、最适宜农耕和最具生产潜力的土壤，被誉为“地中的大熊猫”。我国东北地区作为北半球仅有的三大黑土区之一，是我国重要的粮食生产优势区、最大的商品粮生产基地 ( 分 1 ) 。"},{"text":"                                                  ","underline":true},{"text":"。近年来，由于长期高强度开发利用、地下水超采严重等原因，我国黑土区耕地出现退化，肥沃的黑土变得越来越“瘦”、越来越“薄”、越来越“硬”,打赢黑土地“保卫战”势在必行(分2)。⑧\n填入文中画横线部分最恰当的一项是："}],"annotatedOptionRich":{"A":[{"text":"确保黑土地不减少，是保障粮食生产和粮食安全的必然要求"}],"B":[{"text":"加强东北黑土地保护是促进农业可持续发展的基础支撑作用"}],"C":[{"text":"然而，维护国家粮食安全需加强东北黑土地保护和地力恢复"}],"D":[{"text":"但是，黑土高产丰产的同时，也面临着土地肥力透支的问题"}]},"practicalAnalysis":"文段分析见批注。\n文段可看做并列结构，先介绍我国黑土地的肥沃，再指出近年肥力下降的问题；\n所填入语句在并列结构的文段中间，可能起到承上启下作用，正对应D选项，D选项的“黑土高产丰产”对应上文，“面临土地肥力透支的问题”引起下文，前后文形成转折关系，当选；\n其他选项均与后文无法对应，可简单排除。","notes":[{"marker":"⑲","content":"行文结构：并列结构。\n文段前半段：\n介绍我国东北地区黑土地的肥沃；\n文段后半段：\n介绍我国黑土地出现退化，变瘦变薄，需要“保卫”。","matchScore":0.6505,"pairingMode":"content-similarity","order":20}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300593,3,'中心理解题','老年衰弱已被视为一个重大的公共卫生问题，相对于大规模筛查老年衰弱的量表类工具而言，生物标志物可以更早、更客观地识别衰弱高危人群。与衰弱相关的炎症、内分泌、氧化应激标志物等传统生物标志物存在局限性，对蛋白质生物标志物、表观遗传标记、神经元标志物、细胞外水分率比值等新兴标志物的潜在性进行探讨，通过标志物与功能参数结合、建立衰弱核心标志物小组、针对衰弱的过程状态选择不同的标志物等评估衰弱的新方法，探索有价值的衰弱生物标志物补充到已有的研究中，有利于阐明衰弱的发病机制，对衰弱的预防、诊断及预后具有重要作用。
下列对该文段总结最准确的是：','[{"label":"A","content":"公共卫生问题大规模筛查"},{"label":"B","content":"老年衰弱新兴标志物研究"},{"label":"C","content":"传统生物标志物的局限性"},{"label":"D","content":"衰弱生物标志物的重要性"}]','B','文段分析见批注。
文段是典型的“背景+新”结构，研究的新进展和新发现是重点；文段在引出生物标志物和介绍传统标志物有局限后，重点介绍探索新兴标志物对衰老预防和诊断有重要作用，只有B选项提到了“新兴标志物”,当选；
其他选项均未提及“新兴标志物”,可简单排除。

花生批注：
20 行文结构：二层结构之背景
+ 新。
先介绍背景知识：
生物标志物有助于识别衰弱高危人群；
再介绍新进展：
介绍新兴标志物的研究现状及方法、作用等。
下列对该文段总结最准确的是：公考最新资料、更新进度微信SKA674
A. 公共卫生问题大规模筛查(缺关键词)
B. 老年衰弱新兴标志物研究
C. 传统生物标志物的局限性(缺关键词)
D. 衰弱生物标志物的重要性(缺关键词)','2022年四川省事业单位','进阶','published','{"globalNumber":593,"setNumber":30,"localNumber":13,"sourceLabel":"2022年四川省事业单位53%","accuracy":53,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"老年衰弱已被视为一个重大的公共卫生问题，相对于大规模筛查老年衰弱的量表类工具而言，生物标志物可以更早、更客观地识别衰弱高危人群。与衰弱相关的炎症、内分泌、氧化应激标志物等传统生物标志物存在局限性，对蛋白质生物标志物、表观遗传标记、神经元标志物、细胞外水分率比值等新兴标志物的潜在性进行探讨，通过标志物与功能参数结合、建立衰弱核心标志物小组、针对衰弱的过程状态选择不同的标志物等评估衰弱的新方法，探索有价值的衰弱生物标志物补充到已有的研究中，有利于阐明衰弱的发病机制，对衰弱的预防、诊断及预后具有重要作用。\n下列对该文段总结最准确的是："}],"optionRich":{"A":[{"text":"公共卫生问题大规模筛查"}],"B":[{"text":"老年衰弱新兴标志物研究"}],"C":[{"text":"传统生物标志物的局限性"}],"D":[{"text":"衰弱生物标志物的重要性"}]},"annotatedStemRich":[{"text":"老年衰弱已被视为一个重大的公共卫生问题，相对于大规模筛查老年衰弱的量表类工具而言，生物标志物可以更早、更客观地识别衰弱高危人群"},{"text":"(背景知识","bold":true},{"text":")。与衰弱相关的炎症、内分泌、氧化应激标志物等传统生物标志物存在局限性，对蛋白质生物标志物、表观遗传标记、神经元标志物、细胞外水分率比值等新兴标志物的潜在性进行探讨，通过标志物与功能参数结合、建立衰弱核心标志物小组、针对衰弱的过程状态选择不同的标志物等评估衰弱的新方法，探索有价值的衰弱生物标志物补充到已有的研究中，有利于阐明衰弱的发病机制，对衰弱的预防、诊断及预后具有重要作用"},{"text":"(研究新进展)。②","bold":true},{"text":"\n下列对该文段总结最准确的是："}],"annotatedOptionRich":{"A":[{"text":"公共卫生问题大规模筛查"},{"text":"(缺关键词)","bold":true}],"B":[{"text":"老年衰弱新兴标志物研究","bold":true}],"C":[{"text":"传统生物标志物的局限性"},{"text":"(缺关键词)","bold":true}],"D":[{"text":"衰弱生物标志物的重要性"},{"text":"(缺关键词)","bold":true}]},"practicalAnalysis":"文段分析见批注。\n文段是典型的“背景+新”结构，研究的新进展和新发现是重点；文段在引出生物标志物和介绍传统标志物有局限后，重点介绍探索新兴标志物对衰老预防和诊断有重要作用，只有B选项提到了“新兴标志物”,当选；\n其他选项均未提及“新兴标志物”,可简单排除。","notes":[{"marker":"20","content":"行文结构：二层结构之背景\n+ 新。\n先介绍背景知识：\n生物标志物有助于识别衰弱高危人群；\n再介绍新进展：\n介绍新兴标志物的研究现状及方法、作用等。\n下列对该文段总结最准确的是：公考最新资料、更新进度微信SKA674\nA. 公共卫生问题大规模筛查(缺关键词)\nB. 老年衰弱新兴标志物研究\nC. 传统生物标志物的局限性(缺关键词)\nD. 衰弱生物标志物的重要性(缺关键词)","matchScore":0.6802,"pairingMode":"content-similarity","order":21}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300594,3,'标题拟定类','潜艇要在冰下发射导弹，自然要破冰上浮。潜艇专家从海里畅游的鲸鱼身上受到了启发。众所周知，鲸鱼每隔几十分钟必须破冰吸一次气。巨大的鲸鱼背就像海中的一个小岛，又像一座小山，当鲸鱼上浮换气时，不仅会产生巨大的上浮压力，坚硬的鲸鱼背还能像一把利剑般使厚厚的冰层破裂。这一过程气势雄伟，潜艇破冰执行任务与之很相似。
最适合作这段文字标题的是：','[{"label":"A","content":"鲸鱼与潜艇"},{"label":"B","content":"鲸鱼与仿生学"},{"label":"C","content":"冰下发射导弹原理"},{"label":"D","content":"鲸背效应与潜艇导弹发射"}]','D','文段前两句介绍潜艇冰下发射导弹需要破冰，这一过程从鲸鱼身上得到启发；之后介绍鲸鱼破冰主要和鲸鱼背有关；尾句做出总结：二者相似。文段关键词应是“鲸鱼”和“潜艇发射导弹”。
观察选项：B选项未提及“潜艇”、 C选项未提及“鲸鱼”和“潜艇”, 可简单排除；
对比A选项、D选项，D选项的“鲸背效应”正对应“鲸鱼利用鲸鱼背破冰”、“潜艇导弹发射”也对应“潜艇冰下发射导弹”,较A选项更具体，A选项过于宽泛；
综上，答案为D选项。','2019年福建省事业单位','基础','published','{"globalNumber":594,"setNumber":30,"localNumber":14,"sourceLabel":"2019年福建省事业单位71%","accuracy":71,"typeAndPassage":"标题拟定类+科普介绍文章","stemRich":[{"text":"潜艇要在冰下发射导弹，自然要破冰上浮。潜艇专家从海里畅游的鲸鱼身上受到了启发。众所周知，鲸鱼每隔几十分钟必须破冰吸一次气。巨大的鲸鱼背就像海中的一个小岛，又像一座小山，当鲸鱼上浮换气时，不仅会产生巨大的上浮压力，坚硬的鲸鱼背还能像一把利剑般使厚厚的冰层破裂。这一过程气势雄伟，潜艇破冰执行任务与之很相似。\n最适合作这段文字标题的是："}],"optionRich":{"A":[{"text":"鲸鱼与潜艇"}],"B":[{"text":"鲸鱼与仿生学"}],"C":[{"text":"冰下发射导弹原理"}],"D":[{"text":"鲸背效应与潜艇导弹发射"}]},"annotatedStemRich":[{"text":"潜艇要在冰下发射导弹，自然要破冰上浮。潜艇专家从海里畅游的鲸鱼身上受到了启发。众所周知，鲸鱼每隔几十分钟必须破冰吸一次气。巨大的鲸鱼背就像海中的一个小岛，又像一座小山，当鲸鱼上浮换气时，不仅会产生巨大的上浮压力，坚硬的鲸鱼背还能像一把利剑般使厚厚的冰层破裂。这一过程气势雄伟，潜艇破冰执行任务与之很相似。\n最适合作这段文字标题的是："}],"annotatedOptionRich":{"A":[{"text":"鲸鱼与潜艇"}],"B":[{"text":"鲸鱼与仿生学"}],"C":[{"text":"冰下发射导弹原理"}],"D":[{"text":"鲸背效应与潜艇导弹发射\n②"},{"text":"花生批注：","bold":true},{"text":"\n原文并未提到药物治疗在细胞中是否可以发生作用，无中生有。\n2 "},{"text":"花生批注：","bold":true},{"text":"\n原文并无“主要受益者”的相关表述，无中生有。\n"},{"text":"3花生批注：","bold":true},{"text":"\n“只需一次就能彻底根治”表述过于绝对化，也明显不符合常识。"}]},"practicalAnalysis":"文段前两句介绍潜艇冰下发射导弹需要破冰，这一过程从鲸鱼身上得到启发；之后介绍鲸鱼破冰主要和鲸鱼背有关；尾句做出总结：二者相似。文段关键词应是“鲸鱼”和“潜艇发射导弹”。\n观察选项：B选项未提及“潜艇”、 C选项未提及“鲸鱼”和“潜艇”, 可简单排除；\n对比A选项、D选项，D选项的“鲸背效应”正对应“鲸鱼利用鲸鱼背破冰”、“潜艇导弹发射”也对应“潜艇冰下发射导弹”,较A选项更具体，A选项过于宽泛；\n综上，答案为D选项。","notes":[],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300595,3,'细节判断类','迄今为止，基因治疗已经不断尝试了近三十年。其方法是将人为改变基因的细胞或是正常的基因输入人体内，用以治疗疾病。虽然这种方法并不是直接治疗出现问题的基因，但也有报道称，通过“补充”正常的基因使病情得到了快速改善。将这种基因治疗的概念再次发展延伸后，就是被称作终极治疗的基因组编辑治疗。基因组编辑是能够精确改写或替换某个特定基因的技术，通过灵活运用这一技术，就能对导致疾病的基因本身改写或替换，也就是通常所说的修复基因。这种治疗的操作方法类似口服药物或注射药物，而其得到的治疗效果与手术效果相近。
能够从上述文字推断出的是：','[{"label":"A","content":"基因组编辑治疗与药物治疗都能在细胞中发挥作用"},{"label":"B","content":"基因组编辑治疗与手术治疗可谓旗鼓相当"},{"label":"C","content":"基因组编辑治疗的主要受益者是无法通过药物或手术治疗的先天疾病患者"},{"label":"D","content":"被称作终极治疗，意味着患者只需一次基因组编辑治疗就能彻底根治"}]','B','根据⑥句的“这种治疗的操作方法(基因组编辑治疗)…… 得到的治疗效果与手术效果相近。”可知，基因组编辑治疗和手术治疗可谓旗鼓相当，B选项表述正确，当选。

花生批注：
③2 师法指老师传授的学问和技术。
3 “只需一次就能彻底根治”表述过于绝对化，也明显不符合常识。','2021年重庆市考','进阶','published','{"globalNumber":595,"setNumber":30,"localNumber":15,"sourceLabel":"2021年重庆市考62%","accuracy":62,"typeAndPassage":"细节判断类","stemRich":[{"text":"迄今为止，基因治疗已经不断尝试了近三十年。其方法是将人为改变基因的细胞或是正常的基因输入人体内，用以治疗疾病。虽然这种方法并不是直接治疗出现问题的基因，但也有报道称，通过“补充”正常的基因使病情得到了快速改善。将这种基因治疗的概念再次发展延伸后，就是被称作终极治疗的基因组编辑治疗。基因组编辑是能够精确改写或替换某个特定基因的技术，通过灵活运用这一技术，就能对导致疾病的基因本身改写或替换，也就是通常所说的修复基因。这种治疗的操作方法类似口服药物或注射药物，而其得到的治疗效果与手术效果相近。\n能够从上述文字推断出的是："}],"optionRich":{"A":[{"text":"基因组编辑治疗与药物治疗都能在细胞中发挥作用"}],"B":[{"text":"基因组编辑治疗与手术治疗可谓旗鼓相当"}],"C":[{"text":"基因组编辑治疗的主要受益者是无法通过药物或手术治疗的先天疾病患者"}],"D":[{"text":"被称作终极治疗，意味着患者只需一次基因组编辑治疗就能彻底根治"}]},"annotatedStemRich":[{"text":"①迄今为止，基因治疗已经不断尝试了近三十年。②其方法是将人为改变基因的细胞或是正常的基因输入人体内，用以治疗疾病。③虽然这种方法并不是直接治疗出现问题的基因，但也有报道称，通过“补充”正常的基因使病情得到了快速改善。④将这种基因治疗的概念再次发展延伸后，就是被称作终极治疗的基因组编辑治疗。⑤基因组编辑是能够精确改写或替换某个特定基因的技术，通过灵活运用这一技术，就能对导致疾病的基因本身改写或替换，也就是通常所说的修复基因。⑥这种治疗的操作方法类似口服药物或注射药物，而其得到的治疗效果与手术效果相近。\n能够从上述文字推断出的是："}],"annotatedOptionRich":{"A":[{"text":"基因组编辑治疗与药物治疗都能在细胞中发挥作用"},{"text":"(无中生有)②","bold":true}],"B":[{"text":"基因组编辑治疗与手术治疗可谓旗鼓相当"}],"C":[{"text":"基因组编辑治疗的主要受益者是无法通过药物或手术治疗的先天疾病患者"},{"text":"(无中生有)","bold":true},{"text":"②"}],"D":[{"text":"被称作终极治疗，意味着患者只需一次基因组编辑治疗就能彻底根治 "},{"text":"(绝对化)②","bold":true}]},"practicalAnalysis":"根据⑥句的“这种治疗的操作方法(基因组编辑治疗)…… 得到的治疗效果与手术效果相近。”可知，基因组编辑治疗和手术治疗可谓旗鼓相当，B选项表述正确，当选。","notes":[{"marker":"③2","content":"师法指老师传授的学问和技术。","matchScore":0.1011,"pairingMode":"content-similarity","order":1},{"marker":"3","content":"“只需一次就能彻底根治”表述过于绝对化，也明显不符合常识。","matchScore":0.1216,"pairingMode":"marker-and-content","order":24}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300596,3,'中心理解题','未来政府财政预算改革的基本取向是建立公共财政，预算资金安排要体现公共性、政策性的客观要求。由于节能具有鲜明的公益性特征，属于社会共同需要的范畴，因此，公共预算设立节能项目与公共预算的改革方向是吻合的。在我国财政经济实力不断增强的背景下，加之必要的预算结构调整，我国的财政经常性预算已具备支持节能支出的财力基础。为此，政府需要通过调整预算支出结构，保证财政用于节能预算的资金投入。
最适合这段文字的标题是：','[{"label":"A","content":"建立公共财政，推进实施政府财政预算改革"},{"label":"B","content":"加大政府公共财政预算，推进节能项目建设"},{"label":"C","content":"建立政府公共财政，设立节能项目公共预算"},{"label":"D","content":"推进政府财政改革，确保节能项目资金投入"}]','C','文段分析见批注。
文段可看作前对策结构，开篇指出“政府财政预算改革的方向是建立公共财政”,接下来指出“公共预算设立节能项目与政府财政预算改革方向一致”, 对策可概括为“政府财政预算改革，要建立公共财政，要设立节能项目公共预算”。C选项是政府财政预算改革的具体内容，当选；
A选项，没提及对策重点之一“节能项目”,排除； B选项的“加大政府公共预算”无中生有，并非“加大”而是“预算改革要建立公共财政”,排除； D选项出自论证部分，而且“政府财政改革”过于宽泛，未体现“财政预算改革”, 此外，D选项未提及“财政预算改革的方向：建立政府公共财政”,排除。

花生批注：
④ 行文结构：前对策结构。
开篇给出对策：
政府财政预算改革的方向是建立公共财政，公共预算设立节能项目与政府财政预算改革方向一致(即政府财政预算改革，要建立公共财政，要设立节能项目公共预算);
之后再分析论证：
目前我国已有支持上述改革的财力，要保证做到上述改革。
最适合这段文字的标题是：
A. 建立公共财政，推进实施政府财政预算改革(缺主题词)
B. 加大政府公共财政预算，推进节能项目建设(无中生有)
