INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300599,3,'中心理解题','准确判断风险隐患是保障金融安全的前提，必须坚持底线思维，提高风险预见预判能力，严密防范各种风险挑战。国有商业银行要坚持总体国家安全观，认清形势、把握大局、压实责任，对重大风险因素设置防线，对各类风险传导建立阻断机制，坚决守住不发生系统性风险底线。提前分析研判，及时梳理风险，做到早识别、早预警、早发现、早处置。做好金融基础设施自主化建设，助力维护金融稳定。
这段文字旨在强调：','[{"label":"A","content":"准确判断风险隐患是保障金融安全的前提"},{"label":"B","content":"国有商业银行要坚持总体国家安全观"},{"label":"C","content":"坚决守住不发生系统性风险底线"},{"label":"D","content":"做好金融工作增强忧患意识和底线思维"}]','D','文段分析见批注。
文段可看作是前对策结构，首句通过必要条件表对策，可翻译为“保障金融安全要准确判断风险隐患，要坚持底线思维”,后文给出一系列保障金融安全的具体对策②;D选项是A 且B 类选项，“增强忧患意识”体现了“预见风险”, “增强底线思维”体现了“坚持底线思维”,当选；
C选项缺主题词“金融”⑨, A选项没体现“底线思维”,表述片面，均可简单排除；
B选项易错，“坚持总体国家安全观”只是后文的具体对策之一，表述片面，排除；
综上，正确选项是D选项。

花生批注：
28 行文结构：前对策结构。
开门见山提出对策：
保障金融安全要提高风险预见预判能力，准确判断风险隐患，还要坚持底线思维。后文解释对策：
因此，国有商业银行保障金融安全要做到：
①坚持总体国家安全观；
②认清形势、把握大局、压实责任、设置防线、建立风险传导阻断机制，守住不发生系统性风险底线；
③提前分析研判，及时梳理风险，做好金融基础设施自主化建设。
9 此时从后文提炼的对策很容易犯片面的错误。
③0 若C选项正确，无法反推出原文讨论的话题是“金融”领域。
这段文字旨在强调：
A. 准确判断风险隐患是保障金融安全的前提(片面)
B. 国有商业银行要坚持总体国家安全观(片面)
C. 坚决守住不发生系统性风险底线(缺主题词)','2021年山西省事业单位','进阶','published','{"globalNumber":599,"setNumber":30,"localNumber":19,"sourceLabel":"2021年山西省事业单位65%","accuracy":65,"typeAndPassage":"中心理解题+说理类文章","stemRich":[{"text":"准确判断风险隐患是保障金融安全的前提，必须坚持底线思维，提高风险预见预判能力，严密防范各种风险挑战。国有商业银行要坚持总体国家安全观，认清形势、把握大局、压实责任，对重大风险因素设置防线，对各类风险传导建立阻断机制，坚决守住不发生系统性风险底线。提前分析研判，及时梳理风险，做到早识别、早预警、早发现、早处置。做好金融基础设施自主化建设，助力维护金融稳定。\n这段文字旨在强调："}],"optionRich":{"A":[{"text":"准确判断风险隐患是保障金融安全的前提"}],"B":[{"text":"国有商业银行要坚持总体国家安全观"}],"C":[{"text":"坚决守住不发生系统性风险底线"}],"D":[{"text":"做好金融工作增强忧患意识和底线思维"}]},"annotatedStemRich":[{"text":"准确判断风险隐患是保障"},{"text":"金融","underline":true},{"text":"安全的前提，必须坚持底线思维，提高风险预见预判能力，严密防范各种风险挑战(前对策)。国有商业银行要坚持总体国家安全观，认清形势、把握大局、压实责任，对重大风险因素设置防线，对各类风险传导建立阻断机制，坚决守住不发生系统性风险底线。提前分析研判，及时梳理风险，做到早识别、早预警、早发现、早处置。做好金融基础设施自主化建设，助力维护金融稳定"},{"text":"(解释分析)。②","bold":true},{"text":"\n这段文字旨在强调："}],"annotatedOptionRich":{"A":[{"text":"准确判断风险隐患是保障金融安全的前提(片面)"}],"B":[{"text":"国有商业银行要坚持总体国家安全观(片面)"}],"C":[{"text":"坚决守住不发生系统性风险底线"},{"text":"(缺主题词)","bold":true}],"D":[{"text":"做好金融工作增强忧患意识和底线思维( A 且B)"}]},"practicalAnalysis":"文段分析见批注。\n文段可看作是前对策结构，首句通过必要条件表对策，可翻译为“保障金融安全要准确判断风险隐患，要坚持底线思维”,后文给出一系列保障金融安全的具体对策②;D选项是A 且B 类选项，“增强忧患意识”体现了“预见风险”, “增强底线思维”体现了“坚持底线思维”,当选；\nC选项缺主题词“金融”⑨, A选项没体现“底线思维”,表述片面，均可简单排除；\nB选项易错，“坚持总体国家安全观”只是后文的具体对策之一，表述片面，排除；\n综上，正确选项是D选项。","notes":[{"marker":"28","content":"行文结构：前对策结构。\n开门见山提出对策：\n保障金融安全要提高风险预见预判能力，准确判断风险隐患，还要坚持底线思维。后文解释对策：\n因此，国有商业银行保障金融安全要做到：\n①坚持总体国家安全观；\n②认清形势、把握大局、压实责任、设置防线、建立风险传导阻断机制，守住不发生系统性风险底线；\n③提前分析研判，及时梳理风险，做好金融基础设施自主化建设。","matchScore":1.0652,"pairingMode":"content-similarity","order":29},{"marker":"9","content":"此时从后文提炼的对策很容易犯片面的错误。","matchScore":0.1992,"pairingMode":"marker-and-content","order":30},{"marker":"③0","content":"若C选项正确，无法反推出原文讨论的话题是“金融”领域。\n这段文字旨在强调：\nA. 准确判断风险隐患是保障金融安全的前提(片面)\nB. 国有商业银行要坚持总体国家安全观(片面)\nC. 坚决守住不发生系统性风险底线(缺主题词)","matchScore":0.8373,"pairingMode":"content-similarity","order":31}],"pairingMode":"text-and-sequence"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (300600,3,'中心理解题','20世纪90年代经济转机的主要模式，一种是激进式、休克式改革方案，即华盛顿共识，其核心是自由化、市场化、私有化以及财政政策稳定化。在一系列华盛顿共识实验失败后，世界的各方聚焦于经济高度增长的中国，与中欧、东欧的激进式改革不同，中国在坚持社会主义制度的前提下进行经济体制改革。中国的转轨方案是一种先易后难的渐进式增量改革，依据改革阻力越小越优先的原则安排各项经济改革的次序，从试点到推广、从农村到城市、从体制外到体制内，巩固了改革成果，降低了改革带来的不确定性。此外，中国的渐进式增量改革强化了改革在转轨中的作用，特别是地方政府推动了自下而上的制度创新。
这段文字意在强调：','[{"label":"A","content":"经济转轨的两种模式的差异"},{"label":"B","content":"中国经济体制改革的制度基础"},{"label":"C","content":"中国经济高速增长引发了全球关注"},{"label":"D","content":"中国渐进式增量改革的实施原则"}]','D','文段分析见批注。
文段介绍了欧洲与我国不同的经济改革方式，对比欧洲华盛顿共识的失败，我国渐进式增量改革则是获得了成功，文段重点介绍我国渐进式增量改革的具体实施，因此文段重点应包含“渐进式增量改革”及“实施原则”,对应D选项当选；
A选项为区别比较联系类，文段并未具体说明两种模式的差异，排除； B选项是强干扰项，原文提及“中国在坚持社会主义制度的前提下进行经济体制改革”,即中国经济体制改革的制度基础是社会主义制度，社会主义制度并非文段重点，排除； C选项未提及“经济体制改革”,排除。

花生批注：
③ 渐进式增量改革是全文论述话题。
③2 行文结构：二层结构之对比。
先介绍：
20世纪90年代经济转机的欧洲的激进式、休克式改革 (华盛顿共识),并且失败了；后介绍：
我国渐进式增量改革的具体实施：
①依据改革阻力越小越优先原则安排次序；
②强化改革在转轨中的作用。','2023年安徽省三支一扶','进阶','published','{"globalNumber":600,"setNumber":30,"localNumber":20,"sourceLabel":"2023年安徽省三支一扶51%","accuracy":51,"typeAndPassage":"中心理解题+科普介绍文章","stemRich":[{"text":"20世纪90年代经济转机的主要模式，一种是激进式、休克式改革方案，即华盛顿共识，其核心是自由化、市场化、私有化以及财政政策稳定化。在一系列华盛顿共识实验失败后，世界的各方聚焦于经济高度增长的中国，与中欧、东欧的激进式改革不同，中国在坚持社会主义制度的前提下进行经济体制改革。中国的转轨方案是一种先易后难的渐进式增量改革，依据改革阻力越小越优先的原则安排各项经济改革的次序，从试点到推广、从农村到城市、从体制外到体制内，巩固了改革成果，降低了改革带来的不确定性。此外，中国的渐进式增量改革强化了改革在转轨中的作用，特别是地方政府推动了自下而上的制度创新。\n这段文字意在强调："}],"optionRich":{"A":[{"text":"经济转轨的两种模式的差异"}],"B":[{"text":"中国经济体制改革的制度基础"}],"C":[{"text":"中国经济高速增长引发了全球关注"}],"D":[{"text":"中国渐进式增量改革的实施原则"}]},"annotatedStemRich":[{"text":"20世纪90年代经济转机的主要模式，一种是激进式、休克式改革方案，即华盛顿共识，其核心是自由化、市场化、私有化以及财政政策稳定化"},{"text":"(欧洲","bold":true},{"text":"的激进式、休克式改革)。在一系列华盛顿共识实验失败后，世界的各方聚焦于经济高度增长的中国，与中欧、东欧的激进式改革不同，中国在坚持社会主义制度的前提下进行经济体制改革。中国的转轨方案是一种先易后难的"},{"text":"渐进式增量改革","underline":true},{"text":"③,依据改革阻力越小越优先的原则安排各项经济改革的次序，从试点到推广、从农村到城市、从体制外到体制内，巩固了改革成果，降低了改革带来的不确定性。此外，中国的渐进式增量改革强化了改革在转轨中的作用，特别是地方政府推动了自下而上的制度创新(中国的渐进式增量改革)。③\n这段文字意在强调："}],"annotatedOptionRich":{"A":[{"text":"经济转轨的两种模式的差异 "},{"text":"(区别比较联系类)","bold":true}],"B":[{"text":"中国经济体制改革的制度基础(缺少主题词)"}],"C":[{"text":"中国经济高速增长引发了全球关注"},{"text":"(缺少主题词)","bold":true}],"D":[{"text":"中国渐进式增量改革的实施原则"}]},"practicalAnalysis":"文段分析见批注。\n文段介绍了欧洲与我国不同的经济改革方式，对比欧洲华盛顿共识的失败，我国渐进式增量改革则是获得了成功，文段重点介绍我国渐进式增量改革的具体实施，因此文段重点应包含“渐进式增量改革”及“实施原则”,对应D选项当选；\nA选项为区别比较联系类，文段并未具体说明两种模式的差异，排除； B选项是强干扰项，原文提及“中国在坚持社会主义制度的前提下进行经济体制改革”,即中国经济体制改革的制度基础是社会主义制度，社会主义制度并非文段重点，排除； C选项未提及“经济体制改革”,排除。","notes":[{"marker":"③","content":"渐进式增量改革是全文论述话题。","matchScore":0.487,"pairingMode":"marker-and-content","order":32},{"marker":"③2","content":"行文结构：二层结构之对比。\n先介绍：\n20世纪90年代经济转机的欧洲的激进式、休克式改革 (华盛顿共识),并且失败了；后介绍：\n我国渐进式增量改革的具体实施：\n①依据改革阻力越小越优先原则安排次序；\n②强化改革在转轨中的作用。","matchScore":0.8971,"pairingMode":"content-similarity","order":33}],"pairingMode":"text-and-sequence"}');
